/* Trigger: AA_PRODUTOCUSTO_DTHRALT_BU */
CREATE TRIGGER AA_PRODUTOCUSTO_DTHRALT_BU FOR PRODUTOCUSTO
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
    /* TRIGGER QUE CONTROLA AS ALTERACOES DE USUARIO, CRIADA SEPARADAMENTE PARA SER DESABILITADA
       QUANDO FOR EXECUTADA ATUALIZACAO DE VERSAO DO CHERP */

    IF (UPDATING) THEN BEGIN
        IF (NEW.PRECOCUSTO <> OLD.PRECOCUSTO) THEN
            NEW.PRECOCUSTOANT    = OLD.PRECOCUSTO;
        IF (NEW.PRECOMEDIO <> OLD.PRECOMEDIO) THEN
            NEW.PRECOMEDIOANT = OLD.PRECOMEDIO;
    END
    IF ((NEW.PRECOCUSTO <> OLD.PRECOCUSTO) OR (NEW.PRECOMEDIO <> OLD.PRECOMEDIO) OR (NEW.PRECOCUSTONFLANC <> OLD.PRECOCUSTONFLANC)) THEN
        NEW.DATAHORAALT = 'NOW';
END
^

