/* Trigger: AA_PRODUTOVENDA_DTHRALT_BU */
CREATE TRIGGER AA_PRODUTOVENDA_DTHRALT_BU FOR PRODUTOVENDA
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
    /* TRIGGER QUE CONTROLA AS ALTERACOES DE USUARIO, CRIADA SEPARADAMENTE PARA SER DESABILITADA
       QUANDO FOR EXECUTADA ATUALIZACAO DE VERSAO DO CHERP */

    IF (UPDATING) THEN BEGIN
        EXECUTE PROCEDURE GERARLOGPAFECF(1, NEW.CHAVE, 1);
        IF (NEW.PRECOVENDA <> OLD.PRECOVENDA) THEN
            NEW.PRECOVENDAANT = OLD.PRECOVENDA;
    END
    IF ((NEW.PRECOVENDAMINIMO <> OLD.PRECOVENDAMINIMO) OR (NEW.PRECOVENDA <> OLD.PRECOVENDA)) THEN
        NEW.DATAHORAALT = 'NOW';
END
^

/* Trigger: AA_PRODUTO_DTHRALT_BIU */
CREATE TRIGGER AA_PRODUTO_DTHRALT_BIU FOR PRODUTO
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
begin
    /* Trigger que controla as alteracoes de usuario, criada separadamente para ser desabilitada
       quando for executada atualizacao de versao do CHERP */

    IF (INSERTING) THEN BEGIN
        IF (NEW.DATAHORACAD IS NULL) THEN
            NEW.DATAHORACAD = 'NOW';
        EXECUTE PROCEDURE GERARLOGPAFECF(0, NEW.CHAVE, 0);
    END
    IF (UPDATING) THEN BEGIN
        NEW.DATAHORAALT = 'NOW';
        EXECUTE PROCEDURE GERARLOGPAFECF(0, NEW.CHAVE, 1);
    END
end
^

