        OLD.CHAVECLASSFISCAL <> NEW.CHAVECLASSFISCAL OR
        OLD.ALIQNAC <> NEW.ALIQNAC OR
        OLD.ALIQIMP <> NEW.ALIQIMP OR
        OLD.ALIQEST <> NEW.ALIQEST OR
