        OLD.CHAVEIBPT <> NEW.CHAVEIBPT OR
        OLD.VIGENCIAINI <> NEW.VIGENCIAINI OR
        OLD.VIGENCIAFIM <> NEW.VIGENCIAFIM OR
        OLD.VERSAO <> NEW.VERSAO OR
        OLD.FONTE <> NEW.FONTE OR
        OLD.IDENTIFICADOR <> NEW.IDENTIFICADOR OR
        OLD.ORIGEMOFF <> NEW.ORIGEMOFF) THEN
    BEGIN
      NEW.DATAHORAALT = 'NOW';
    END
END
