/* Trigger: CAIXAPDV_BI */
CREATE TRIGGER CAIXAPDV_BI FOR CAIXAPDV
ACTIVE BEFORE INSERT OR UPDATE OR DELETE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN
    NEW.CHAVE = GEN_ID(GEN_CAIXAPDV_ID,1);
  IF (INSERTING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(10, NEW.CHAVE, 0);
  IF (UPDATING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(10, NEW.CHAVE, 1);
  IF (DELETING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(10, OLD.CHAVE, 2);
END
^

/* Trigger: CAIXA_BI */
CREATE TRIGGER CAIXA_BI FOR CAIXA
ACTIVE BEFORE INSERT POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN
    NEW.CHAVE = GEN_ID(GEN_CAIXA_ID,1);
  IF (NEW.CHAVECHEQUE <= 0) THEN
    NEW.CHAVECHEQUE = NULL;
  IF ((NEW.CHAVECHEQUE IS NULL) OR (NEW.CHAVECHEQUE <= 0)) THEN 
    NEW.COMPENSADO = NEW.LANCAMENTO;
  ELSE BEGIN
     NEW.COMPENSADO = (SELECT COMPENSADO FROM CHEQUES
     WHERE CHAVE=NEW.CHAVECHEQUE);
  END
END
^

