/* Trigger: CLIFOR_BI */
CREATE TRIGGER CLIFOR_BI FOR CLIFOR
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
    IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (COALESCE(NEW.CHAVE,0) = 0) THEN
        NEW.CHAVE = GEN_ID(GEN_CLIFOR_ID,1);
    IF (NEW.CHAVEBDORIGEM = 0) THEN
        NEW.CHAVEBDORIGEM = NULL;
    IF (NEW.CHAVEEMPCONVENIO = 0) THEN
        NEW.CHAVEEMPCONVENIO = NULL;
    IF (NEW.CHAVEVENDEDOR = 0) THEN
        NEW.CHAVEVENDEDOR = NULL;
    IF (NEW.CHAVETABELADESCONTOS = 0) THEN
        NEW.CHAVETABELADESCONTOS = NULL;
    IF (NEW.CHAVEBANCO = 0) THEN
        NEW.CHAVEBANCO = NULL;
    IF (NEW.CHAVECIDADETRABALHO = 0) THEN
        NEW.CHAVECIDADETRABALHO = NULL;
    IF (NEW.CHAVECIDADEFILIACAO = 0) THEN
        NEW.CHAVECIDADEFILIACAO = NULL;
    IF (NEW.CHAVEECOMMERCE = 0) THEN
        NEW.CHAVEECOMMERCE = NULL;
    IF (NEW.CHAVEMOBILE = 0) THEN
        NEW.CHAVEMOBILE = NULL;
    IF (NEW.CHAVECLIFORMOBILE = 0) THEN
        NEW.CHAVECLIFORMOBILE = NULL;
    IF (NEW.CHAVECONDPGTO = 0) THEN
        NEW.CHAVECONDPGTO = NULL;
    IF (NEW.CHAVETABELAPRECO = 0) THEN
        NEW.CHAVETABELAPRECO = NULL;
    IF (COALESCE(NEW.SEXO, -1) < 0) THEN
        NEW.SEXO = 3;
END
^

