/* Trigger: CONDICIONAL_BI */
CREATE TRIGGER CONDICIONAL_BI FOR CONDICIONAL
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
    IF (INSERTING) THEN BEGIN
       IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
         NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
    END
    IF (NEW.CHAVE IS NULL) THEN
        NEW.CHAVE = GEN_ID(GEN_CONDICIONAL_ID,1);
    IF (COALESCE(NEW.SITUACAO, 0) = 0) THEN
        NEW.SITUACAO = 0;
    IF ((COALESCE(NEW.SITUACAO, 0) <> 0) AND (OLD.SITUACAO = 0)) THEN BEGIN
        NEW.DATAFECHA      = CURRENT_DATE;
        NEW.HORAFECHAMENTO = CURRENT_TIME;
    END
    --veio status aberta mas ja foi fechada
    IF ((NEW.SITUACAO = 0) AND (OLD.SITUACAO <> 0)) THEN
        EXCEPTION SITUACAO_CONDICIONAL;
    IF (NEW.CHAVELOTE <= 0) THEN
        NEW.CHAVELOTE = NULL;
END
^

