/* Trigger: COTACAO_BI */
CREATE TRIGGER COTACAO_BI FOR COTACAO
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (COALESCE(NEW.CHAVE,0) = 0) THEN
    NEW.CHAVE = GEN_ID(GEN_COTACAO_ID,1);
  IF (NEW.CHAVEVEICULO <= 0) THEN
    NEW.CHAVEVEICULO = NULL;
  --VEIO STATUS ABERTA MAS JA FOI FECHADA
  --(SOMENTE ORCAMENTO NORMAL POIS TEM OPCAO DE CANCELAR ORCAMENTO ENTREGA FUTURA ONDE VOLTA SITUACAO PARA ABERTA)
  IF ((NEW.SITUACAO = 0) AND (NOT (OLD.SITUACAO IN (0, 10))) AND (NEW.TIPOCOMPRA=0)) THEN
    EXCEPTION SITUACAO_COTACAO;
END
