  IF(NEW.CHAVEPRODUTO <= 0) THEN
    NEW.CHAVEPRODUTO = NULL;

  IF(NEW.CHAVEEMITENTE <= 0) THEN
    NEW.CHAVEEMITENTE = NULL;

  IF(NEW.CHAVETOMADOR <= 0) THEN
    NEW.CHAVETOMADOR = NULL;

  IF(NEW.CHAVEUSUARIOFECHOU <= 0) THEN
    NEW.CHAVEUSUARIOFECHOU = NULL;

  IF(NEW.CHAVEUSUARIOINICIOU <= 0) THEN
    NEW.CHAVEUSUARIOINICIOU = NULL;

