/* Trigger: CTRLATUALIZACOES_BI */
CREATE TRIGGER CTRLATUALIZACOES_BI FOR CTRLATUALIZACOES
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN
    NEW.CHAVE = GEN_ID(GEN_CTRLATUALIZACOES_ID,1);
  IF (NEW.TIPO = 1) THEN
    UPDATE SOFTWAREHOUSE SET HOTFIX = NEW.DESCRSCRIPT WHERE CHAVE = 1;
