/* Trigger: CUPOMFISCAL_BI */
CREATE TRIGGER CUPOMFISCAL_BI FOR CUPOMFISCAL
ACTIVE BEFORE INSERT OR UPDATE OR DELETE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN
    NEW.CHAVE = GEN_ID(GEN_CUPOMFISCAL_ID,1);
  IF (NEW.CHAVECLIFORENDERECOS <= 0) THEN
    NEW.CHAVECLIFORENDERECOS = NULL;
  IF (INSERTING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(7, NEW.CHAVE, 0);
  IF (UPDATING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(7, NEW.CHAVE, 1);
  IF (DELETING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(7, OLD.CHAVE, 2);
END
