/* Trigger: ESTOQUERESERVADO_BI */
CREATE TRIGGER ESTOQUERESERVADO_BI FOR ESTOQUERESERVADO
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
  IF (COALESCE(NEW.CHAVE,0)=0) THEN
    NEW.CHAVE = GEN_ID(GEN_ESTOQUERESERVADO_ID,1);
  IF (INSERTING) THEN
    NEW.DATAHORA = CURRENT_TIMESTAMP;
  IF (COALESCE(NEW.CHAVEDPTOESTOQUE,0) = 0) THEN
    NEW.CHAVEDPTOESTOQUE = NULL;
  IF (COALESCE(NEW.CHAVELOTEPRODUTO,0) = 0) THEN
    NEW.CHAVELOTEPRODUTO = NULL;
  -- PEDIDO SAIDA
  IF (COALESCE(NEW.CHAVEPEDSAIDA,0) = 0) THEN
    NEW.CHAVEPEDSAIDA = NULL;
  IF (COALESCE(NEW.CHAVEITEMPEDSAIDA,0) = 0) THEN
    NEW.CHAVEITEMPEDSAIDA = NULL;
  ELSE BEGIN
    UPDATE ITENSPEDSAIDA SET
    QTDEESTRESERVADO=CASE WHEN (NEW.QTDE<0) THEN (COALESCE(QTDEESTRESERVADO,0)+(NEW.QTDE)) ELSE NEW.QTDE END
    WHERE (CHAVE=NEW.CHAVEITEMPEDSAIDA);
  END
  -- NF SAIDA
  IF (COALESCE(NEW.CHAVENFSAIDA,0) = 0) THEN
    NEW.CHAVENFSAIDA = NULL;
  IF (COALESCE(NEW.CHAVEITEMNFSAIDA,0) = 0) THEN
    NEW.CHAVEITEMNFSAIDA = NULL;
  ELSE BEGIN
    UPDATE ITENSNFSAIDA SET
    QTDEESTRESERVADO=CASE WHEN (NEW.QTDE<0) THEN (COALESCE(QTDEESTRESERVADO,0)+(NEW.QTDE)) ELSE NEW.QTDE END
    WHERE (CHAVE=NEW.CHAVEITEMNFSAIDA);
  END
  -- CONDICIONAL
  IF (COALESCE(NEW.CHAVECONDICIONAL,0) = 0) THEN
    NEW.CHAVECONDICIONAL = NULL;
  IF (COALESCE(NEW.CHAVEITEMCONDICIONAL,0) = 0) THEN
    NEW.CHAVEITEMCONDICIONAL = NULL;
  ELSE BEGIN
    UPDATE ITENSCONDICIONALPROD SET
    QTDEESTRESERVADO=CASE WHEN (NEW.QTDE<0) THEN (COALESCE(QTDEESTRESERVADO,0)+(NEW.QTDE)) ELSE NEW.QTDE END
    WHERE (CHAVE=NEW.CHAVEITEMCONDICIONAL);
  END
  -- ORCAMENTO
  IF (COALESCE(NEW.CHAVECOTACAO,0) = 0) THEN
    NEW.CHAVECOTACAO = NULL;
  IF (COALESCE(NEW.CHAVEITEMCOTACAO,0) = 0) THEN
    NEW.CHAVEITEMCOTACAO = NULL;
  ELSE BEGIN
    UPDATE ITENSCOTACAOPROD SET
    QTDEESTRESERVADO=CASE WHEN (NEW.QTDE<0) THEN (COALESCE(QTDEESTRESERVADO,0)+(NEW.QTDE)) ELSE NEW.QTDE END
    WHERE (CHAVE=NEW.CHAVEITEMCOTACAO);
  END
  -- DAV OS
  IF (COALESCE(NEW.CHAVEORDEMSERVICO,0) = 0) THEN
    NEW.CHAVEORDEMSERVICO = NULL;
  IF (COALESCE(NEW.CHAVEITEMORDEMSERVICO,0) = 0) THEN
    NEW.CHAVEITEMORDEMSERVICO = NULL;
  ELSE BEGIN
    UPDATE ITENSORDEMSERVICOPROD SET
    QTDEESTRESERVADO=CASE WHEN (NEW.QTDE<0) THEN (COALESCE(QTDEESTRESERVADO,0)+(NEW.QTDE)) ELSE NEW.QTDE END
    WHERE (CHAVE=NEW.CHAVEITEMORDEMSERVICO);
  END
  -- PRE VENDA
  IF (COALESCE(NEW.CHAVEPREVENDA,0) = 0) THEN
    NEW.CHAVEPREVENDA = NULL;
  IF (COALESCE(NEW.CHAVEITEMPREVENDA,0) = 0) THEN
    NEW.CHAVEITEMPREVENDA = NULL;
  ELSE BEGIN
    UPDATE ITENSPREVENDA SET
    QTDEESTRESERVADO=CASE WHEN (NEW.QTDE<0) THEN (COALESCE(QTDEESTRESERVADO,0)+(NEW.QTDE)) ELSE NEW.QTDE END
    WHERE (CHAVE=NEW.CHAVEITEMPREVENDA);
  END
  -- CHAVE USUARIO
  IF (COALESCE(NEW.CHAVEUSUARIO,0) = 0) THEN
    NEW.CHAVEUSUARIO = NULL;
  -- SETA SALDO POR DPTOEST
  UPDATE PRODUTODPTOESTOQUE SET
  SALDORESERVADO=CASE WHEN ((COALESCE(SALDORESERVADO,0)+(NEW.QTDE)) >= 0) THEN COALESCE(SALDORESERVADO,0)+(NEW.QTDE) ELSE 0 END
  WHERE (CHAVEEMPRESA=NEW.CHAVEEMPRESA)
  AND (CHAVEPRODUTO=NEW.CHAVEPRODUTO)
  AND (CHAVEDPTOESTOQUE=NEW.CHAVEDPTOESTOQUE);
  -- SETA SALDO GERAL
  UPDATE PRODUTOESTOQUE SET
  SALDORESERVADO=CASE WHEN ((COALESCE(SALDORESERVADO,0)+(NEW.QTDE)) >= 0) THEN COALESCE(SALDORESERVADO,0)+(NEW.QTDE) ELSE 0 END
  WHERE (CHAVEEMPRESA=NEW.CHAVEEMPRESA)
  AND (CHAVEPRODUTO=NEW.CHAVEPRODUTO);

END
^

/* Trigger: ESTOQUE_BI */
CREATE TRIGGER ESTOQUE_BI FOR ESTOQUE
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
    IF (INSERTING) THEN BEGIN
        IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
            NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
      IF (NEW.CHAVE IS NULL) THEN
            NEW.CHAVE = GEN_ID(GEN_ESTOQUE_ID, 1);
        IF (NEW.HORA IS NULL) THEN
            NEW.HORA = 'NOW';
        IF (NEW.ATIVO=1) THEN BEGIN
            /* EXECUTA PROCEDURE PARA ATUALIZAR O PRODUTOESTOQUE QUANDO INSERE REG NO ESTOQUE*/
            EXECUTE PROCEDURE ESTATUALIZARSALDOESTOQUE('NOW', NEW.CHAVEPRODUTO, NEW.CHAVEEMPRESA,
            CASE NEW.ORIGEM WHEN 98 THEN 0 ELSE NEW.SALDO END,
            CASE NEW.ORIGEM WHEN 8 THEN NEW.SALDO ELSE 0 END,
            NEW.TIPOMOVIMENTACAO, NEW.CHAVEDPTOESTOQUE);
            IF (NEW.CHAVELOTEPROD > 0) THEN BEGIN
                EXECUTE PROCEDURE ESTATUALIZARSALDOLOTEESTOQUE('N', NEW.CHAVEEMPRESA, NEW.CHAVEPRODUTO, NEW.CHAVELOTEPROD, NEW.QTDEENTRADA, NEW.QTDESAIDA);
                UPDATE LOTEPRODUTOS SET
                QTDESAIDA= COALESCE(QTDESAIDA,0) + NEW.QTDESAIDA,
                SALDO= COALESCE(SALDO,0) - NEW.QTDESAIDA
                WHERE CHAVE=NEW.CHAVELOTEPROD;
                UPDATE LOTEPRODUTOS SET
                QTDEENTRADA=COALESCE(QTDEENTRADA,0) + NEW.QTDEENTRADA,
                SALDO = COALESCE(SALDO,0) + NEW.QTDEENTRADA
                WHERE CHAVE= NEW.CHAVELOTEPROD;
            END
        END
    END ELSE BEGIN
        IF ((OLD.ATIVO=1) AND (NEW.ATIVO <> 1)) THEN BEGIN
            /* EXECUTA PROCEDURE PARA ATUALIZAR O PRODUTOESTOQUE QUANDO ALTERAR REG NO ESTOQUE*/
            EXECUTE PROCEDURE ESTATUALIZARSALDOESTOQUE('NOW', OLD.CHAVEPRODUTO,
            OLD.CHAVEEMPRESA, OLD.SALDO*(-1),
            CASE OLD.ORIGEM WHEN 8 THEN OLD.SALDO*(-1) ELSE 0 END,
            OLD.TIPOMOVIMENTACAO, OLD.CHAVEDPTOESTOQUE);
            IF (OLD.CHAVELOTEPROD > 0) THEN BEGIN
                EXECUTE PROCEDURE ESTATUALIZARSALDOLOTEESTOQUE('S', NEW.CHAVEEMPRESA, NEW.CHAVEPRODUTO, NEW.CHAVELOTEPROD, NEW.QTDEENTRADA, NEW.QTDESAIDA);
                UPDATE LOTEPRODUTOS SET
                QTDESAIDA= COALESCE(QTDESAIDA,0) - OLD.QTDESAIDA,
                SALDO= COALESCE(SALDO,0) + OLD.QTDESAIDA
                WHERE CHAVE=NEW.CHAVELOTEPROD;
                UPDATE LOTEPRODUTOS SET
                QTDEENTRADA=COALESCE(QTDEENTRADA,0) - OLD.QTDEENTRADA,
                SALDO = COALESCE(SALDO,0) - OLD.QTDEENTRADA
                WHERE CHAVE= OLD.CHAVELOTEPROD;
            END
        END
        IF ((OLD.ATIVO<>1) AND (NEW.ATIVO = 1)) THEN BEGIN
            /* EXECUTA PROCEDURE PARA ATUALIZAR O PRODUTOESTOQUE QUANDO ALTERAR REG NO ESTOQUE*/
            EXECUTE PROCEDURE ESTATUALIZARSALDOESTOQUE('NOW', NEW.CHAVEPRODUTO, NEW.CHAVEEMPRESA,
            CASE NEW.ORIGEM WHEN 98 THEN 0 ELSE NEW.SALDO END,
            CASE NEW.ORIGEM WHEN 8 THEN NEW.SALDO ELSE 0 END,
            NEW.TIPOMOVIMENTACAO, NEW.CHAVEDPTOESTOQUE);
            IF (NEW.CHAVELOTEPROD > 0) THEN BEGIN
                EXECUTE PROCEDURE ESTATUALIZARSALDOLOTEESTOQUE('N', NEW.CHAVEEMPRESA, NEW.CHAVEPRODUTO, NEW.CHAVELOTEPROD, NEW.QTDEENTRADA, NEW.QTDESAIDA);
                UPDATE LOTEPRODUTOS SET
                QTDESAIDA= COALESCE(QTDESAIDA,0) + NEW.QTDESAIDA,
                SALDO= COALESCE(SALDO,0) - NEW.QTDESAIDA
                WHERE CHAVE=NEW.CHAVELOTEPROD;
                UPDATE LOTEPRODUTOS SET
                QTDEENTRADA=COALESCE(QTDEENTRADA,0) + NEW.QTDEENTRADA,
                SALDO = COALESCE(SALDO,0) + NEW.QTDEENTRADA
                WHERE CHAVE= NEW.CHAVELOTEPROD;
            END
        END
    END
    IF (COALESCE(NEW.CHAVEDPTOESTOQUE,0) <= 0) THEN
       EXCEPTION DPTOESTOQUEZERADO_ESTOQUE;
END
^

