/* Trigger: ITENSORDEMSERVICOPROD_BI */
CREATE TRIGGER ITENSORDEMSERVICOPROD_BI FOR ITENSORDEMSERVICOPROD
ACTIVE BEFORE INSERT OR UPDATE OR DELETE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN
    NEW.CHAVE = GEN_ID(GEN_ITENSORDEMSERVICOPROD_ID,1);
  IF (NEW.CHAVEREGRAFISCAL <= 0) THEN
    NEW.CHAVEREGRAFISCAL = NULL;
  IF (INSERTING) THEN BEGIN
    EXECUTE PROCEDURE GERARLOGPAFECF(12, NEW.CHAVE, 0);
    EXECUTE PROCEDURE GERARLOGPAFITENSDAV(NEW.ATIVO, NEW.CHAVEEMPRESA, NEW.CHAVE, NEW.CHAVEPRODUTO, NEW.CHAVEUNIDADE, NEW.CHAVETRIBUTACAO,
                                        0, NEW.QTDE, NEW.VLRUNIT, NEW.DESCVLR, NEW.VLRACRESCGLOBAL, NEW.VLRTOTAL, 0, NEW.NRODAV, NEW.CHAVEOS, 'I');
  END
  IF (UPDATING) THEN BEGIN
    EXECUTE PROCEDURE GERARLOGPAFECF(12, NEW.CHAVE, 1);
    IF (OLD.QTDE <> NEW.QTDE) THEN BEGIN
        EXECUTE PROCEDURE GERARLOGPAFITENSDAV(OLD.ATIVO, OLD.CHAVEEMPRESA, OLD.CHAVE, OLD.CHAVEPRODUTO, OLD.CHAVEUNIDADE, OLD.CHAVETRIBUTACAO,
                                        0, OLD.QTDE, OLD.VLRUNIT, OLD.DESCVLR, OLD.VLRACRESCGLOBAL, OLD.VLRTOTAL, 0, OLD.NRODAV, OLD.CHAVEOS, 'A');
    END
    IF ((OLD.ATIVO=1) AND (NEW.ATIVO<>1)) THEN BEGIN
        EXECUTE PROCEDURE GERARLOGPAFITENSDAV(NEW.ATIVO, NEW.CHAVEEMPRESA, NEW.CHAVE, NEW.CHAVEPRODUTO, NEW.CHAVEUNIDADE, NEW.CHAVETRIBUTACAO,
                                        0, NEW.QTDE, NEW.VLRUNIT, NEW.DESCVLR, NEW.VLRACRESCGLOBAL, NEW.VLRTOTAL, 0, NEW.NRODAV, NEW.CHAVEOS, 'E');
    END
  END
  IF (DELETING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(12, OLD.CHAVE, 2);
END
^

