/* Trigger: ITENSPREVENDA_BI */
CREATE TRIGGER ITENSPREVENDA_BI FOR ITENSPREVENDA
ACTIVE BEFORE INSERT OR UPDATE OR DELETE POSITION 0
AS
BEGIN
  IF (UPDATING) THEN BEGIN
    IF ((COALESCE(NEW.IDENTIFICADOR, '') = '') AND (COALESCE(OLD.IDENTIFICADOR, '') <> ''))  THEN
     NEW.IDENTIFICADOR = OLD.IDENTIFICADOR;
  END
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
       NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
    IF (COALESCE(NEW.DATAITEMPV, '') = '') THEN
       NEW.DATAITEMPV = CURRENT_DATE;
    IF (COALESCE(NEW.HORAITEMPV, '') = '') THEN
       NEW.HORAITEMPV = CURRENT_TIME;
  END
  IF (NEW.CHAVE IS NULL) THEN
    NEW.CHAVE = GEN_ID(GEN_ITENSPREVENDA_ID,1);
   
  IF (NEW.CHAVECLASSFISCAL <= 0) THEN
    NEW.CHAVECLASSFISCAL = NULL;
  IF (INSERTING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(17, NEW.CHAVE, 0);
  IF (UPDATING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(17, NEW.CHAVE, 1);
  IF (DELETING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(17, OLD.CHAVE, 2);
END
