/* Trigger: LOTEPRODUTOS_BI */
CREATE TRIGGER LOTEPRODUTOS_BI FOR LOTEPRODUTOS
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (COALESCE(NEW.CHAVE,0) = 0) THEN
    NEW.CHAVE = GEN_ID(GEN_LOTEPRODUTOS_ID,1);
  IF (COALESCE(NEW.CHAVEGRADELINHA,0) <= 0) THEN
    NEW.CHAVEGRADELINHA = NULL;
  IF (COALESCE(NEW.CHAVEGRADECOLUNA,0) <= 0) THEN
    NEW.CHAVEGRADECOLUNA = NULL;
  IF (INSERTING) THEN BEGIN
     IF ((COALESCE(NEW.CHAVEGRADELINHA,0) > 0) OR (COALESCE(NEW.CHAVEGRADECOLUNA,0) > 0)) THEN BEGIN
        NEW.SEQGRADE = (SELECT FIRST 1 SEQGRADE
            FROM LOTEPRODUTOS
            WHERE (ATIVO<>1) AND (CHAVEEMPRESA=NEW.CHAVEEMPRESA) AND (CHAVEPRODUTO=NEW.CHAVEPRODUTO)
            AND (CHAVEGRADELINHA=NEW.CHAVEGRADELINHA) AND (CHAVEGRADECOLUNA=NEW.CHAVEGRADECOLUNA)
            ORDER BY CHAVE DESC);
        IF (COALESCE(NEW.SEQGRADE,0) = 0) THEN BEGIN
            NEW.SEQGRADE = (SELECT COALESCE(MAX(SEQGRADE),0)+1
                FROM LOTEPRODUTOS
                WHERE (CHAVEEMPRESA=NEW.CHAVEEMPRESA) AND (CHAVEPRODUTO=NEW.CHAVEPRODUTO)
                AND ((COALESCE(NEW.CHAVEGRADELINHA,0) > 0) OR (COALESCE(NEW.CHAVEGRADECOLUNA,0) > 0)));
        END
     END
  END
END
^

