CREATE TRIGGER NFENTRADA_BI FOR NFENTRADA
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
    IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN BEGIN
        NEW.CHAVE = GEN_ID(GEN_NFENTRADA_ID,1);
        NEW.DATALANCAMENTO = 'NOW';
    END
    IF ((OLD.STATUS = 1) AND (NEW.STATUS = 0)) THEN
        EXCEPTION SITUACAO_NFENTRADA;
    IF (UPDATING) THEN BEGIN
        /* TRATAMENTO PARA QUANDO EXCLUIR OU STATUS DIFERENTE DE ABERTA LIMPAR CAMPO JSON IMP XML */
        IF ((NEW.ATIVO<>1) OR (NEW.STATUS <> 0)) THEN
            NEW.JSONIMPXML = NULL;
    END

END
