/* Trigger: PAGAR_BI */
CREATE TRIGGER PAGAR_BI FOR PAGAR
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
    IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN
        NEW.CHAVE = GEN_ID(GEN_PAGAR_ID,1);
    IF (NEW.STATUS = 1) THEN
        NEW.REMANESCENTE = COALESCE(NEW.VALOR, 0) - COALESCE(NEW.RECEBPARCIALSEMJUROS, 0);
    ELSE
        NEW.REMANESCENTE = 0;
    IF (NEW.STATUS IN (0, 1)) THEN
        NEW.TOTALCONTA = COALESCE(NEW.REMANESCENTE, 0) + COALESCE(NEW.RECEBPARCIAL, 0);
    ELSE
        NEW.TOTALCONTA = 0;
END
