/* Trigger: PDVOFF_ECFSAUTORIZADOS */
CREATE TRIGGER PDVOFF_ECFSAUTORIZADOS FOR ECFSAUTORIZADOS
ACTIVE AFTER INSERT OR UPDATE POSITION 0
as
begin
    if ((updating) and (coalesce(new.DATAESTOQUE, current_date) <> coalesce(old.DATAESTOQUE, current_date))) then begin
     update or insert into SINCRONIZACAOPDVOFF(ATIVO, CHAVEEMPRESA, STATUS, OBS, CHAVEECFAUTORIZADO)
     values (1, new.CHAVEEMPRESA, 3, '', new.CHAVE)
     matching(CHAVEECFAUTORIZADO, STATUS);
   end
end
^

/* Trigger: PEDIDOSAIDA_BI */
CREATE TRIGGER PEDIDOSAIDA_BI FOR PEDIDOSAIDA
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (COALESCE(NEW.CHAVE,0) = 0) THEN
        NEW.CHAVE = GEN_ID(GEN_PEDIDOSAIDA_ID,1);
    IF (NEW.DATAHORAPEDIDO IS NULL) THEN
        NEW.DATAHORAPEDIDO = 'NOW';
    IF (NEW.CHAVEVEICULO <= 0) THEN
        NEW.CHAVEVEICULO = NULL;
    IF (NEW.STATUS IS NULL) THEN
        NEW.STATUS = 0; --ABERTO
    IF ((NEW.STATUS = 0) AND (OLD.FINALIZADO = 'N') AND (NEW.FINALIZADO = 'S')) THEN
        NEW.STATUS = 1; --FINALIZADO
    IF (NEW.TIPO='NF') THEN
        NEW.STATUS = 2; --GRADO NF
    IF (NEW.TIPO='CF') THEN
        NEW.STATUS = 3; --GERADO CF
    IF (NEW.TIPO='NP') THEN
        NEW.STATUS = 4; --IMPORTADO CHPDV (NFCe/NFe/NF)
    IF ((NEW.STATUS >= 2) AND (NEW.FINALIZADO = 'N')) THEN
        NEW.FINALIZADO = 'S';
    IF (NEW.CHAVESITENTREGA <= 0) THEN
        NEW.CHAVESITENTREGA = NULL;
END
^

