/* Trigger: PREVENDACONF_BI */
CREATE TRIGGER PREVENDACONF_BI FOR PREVENDACONF
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN
    NEW.CHAVE = GEN_ID(GEN_PREVENDACONF_ID,1);

  IF (INSERTING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(19, NEW.CHAVE, 0);

  IF (UPDATING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(19, NEW.CHAVE, 1);

  IF (DELETING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(19, OLD.CHAVE, 2);

END
^

/* Trigger: PREVENDA_BI */
CREATE TRIGGER PREVENDA_BI FOR PREVENDA
ACTIVE BEFORE INSERT OR UPDATE OR DELETE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF ((INSERTING) AND (NEW.CHAVE IS NULL)) THEN
    NEW.CHAVE = GEN_ID(GEN_PREVENDA_ID,1);
    IF (NEW.CHAVECLIFORENDERECOS <= 0) THEN
    NEW.CHAVECLIFORENDERECOS = NULL;
    IF (NEW.CHAVEBRSPEDIDOIFOOD <= 0) THEN
    NEW.CHAVEBRSPEDIDOIFOOD = NULL;

  IF (INSERTING) THEN
    NEW.HORA = 'NOW';
  IF ((UPDATING) AND (NEW.ENTREGA<>OLD.ENTREGA)) THEN BEGIN
    IF (NEW.ENTREGA=1) THEN
      NEW.DATAHORAENTREGANDO = CURRENT_TIMESTAMP;
    IF (NEW.ENTREGA=2) THEN BEGIN
      NEW.DATAHORAENTREGUE = CURRENT_TIMESTAMP;
      IF (COALESCE(NEW.DATAHORAENTREGANDO, '')='') THEN
        NEW.DATAHORAENTREGANDO = CURRENT_TIMESTAMP;
    END
  END
  IF ((COALESCE(NEW.TIPODOCDESTINO,0) <> 0) AND (NEW.DATAHORAFECHAMENTO IS NULL)) THEN
    NEW.DATAHORAFECHAMENTO = CURRENT_TIMESTAMP;
  IF (NEW.DATAHORAULTCONSUMACAO IS NULL) THEN
      NEW.DATAHORAULTCONSUMACAO = CURRENT_TIMESTAMP;
  IF (INSERTING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(16, NEW.CHAVE, 0);
  IF (UPDATING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(16, NEW.CHAVE, 1);
  IF (DELETING) THEN
    EXECUTE PROCEDURE GERARLOGPAFECF(16, OLD.CHAVE, 2);
END
^

