ACTIVE BEFORE INSERT OR UPDATE OR DELETE POSITION 0
AS
        BEGIN
            IF (INSERTING) THEN BEGIN
            IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
             NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
          END
          IF (NEW.CHAVE IS NULL) THEN
                NEW.CHAVE = GEN_ID(GEN_PRODUTO_ID,1);
            IF (DELETING) THEN
                EXECUTE PROCEDURE GERARLOGPAFECF(0, OLD.CHAVE, 2);
            IF (NEW.CHAVEUNFUNDMED <= 0) THEN
                NEW.CHAVEUNFUNDMED = NULL;
            IF (COALESCE(NEW.CHAVEGRADE,0) <= 0) THEN
                NEW.CHAVEGRADE = NULL;
            IF (NEW.CHAVECLASSFISCAL <= 0) THEN
                NEW.CHAVECLASSFISCAL = NULL;
            IF (OLD.IDERISSTATUS = 'S') THEN
                NEW.IDERISSTATUS = 'N';
            if (OLD.TRAYSTATUS = 'S') THEN
                NEW.TRAYSTATUS = 'N';
            if (OLD.LOJAINTSTATUS = 'S') THEN
                NEW.LOJAINTSTATUS = 'N';
            IF (OLD.MAGAZORDSTATUS = 'S') THEN
                NEW.MAGAZORDSTATUS = 'N';
        END
