/* Trigger: RECEBER_BI */
CREATE TRIGGER RECEBER_BI FOR RECEBER
ACTIVE BEFORE INSERT OR UPDATE POSITION 0
AS
BEGIN
  IF (INSERTING) THEN
    NEW.VENCIMENTOORIGINAL = NEW.VENCIMENTO;
  IF (INSERTING) THEN BEGIN
    IF (COALESCE(NEW.IDENTIFICADOR, '') = '') THEN
     NEW.IDENTIFICADOR = (SELECT UUID_TO_CHAR(GEN_UUID()) FROM RDB$DATABASE);
  END
  IF (NEW.CHAVE IS NULL) THEN BEGIN
    NEW.CHAVE = GEN_ID(GEN_RECEBER_ID,1);
  END
  IF (NEW.CHAVEMOEDAFATOR <= 0) THEN
    NEW.CHAVEMOEDAFATOR = NULL;
  --LIBERAR PONTUACAO AO BAIXAR TITULO
  IF ((NEW.STATUS = 0) AND (OLD.STATUS<>0)) THEN
    EXECUTE PROCEDURE GERARPONTUACAOCLIENTE(0, COALESCE(NEW.CHAVEDOC,0), NEW.NL, NEW.CHAVE);
  --CANCELAR PONTUACAO E GERAR BLOQUEADO AO ESTORNAR TITULO
  IF ((NEW.STATUS = 1) AND (OLD.STATUS=0)) THEN
    EXECUTE PROCEDURE GERARPONTUACAOCLIENTE(2, COALESCE(NEW.CHAVEDOC,0), NEW.NL, NEW.CHAVE);
  --CANCELAR PONTUACAO NA EXCLUSAO/AGRUPAMENTO DO TITULO
  IF ((NEW.ATIVO NOT IN (1,9)) AND (OLD.ATIVO IN (1,9))) THEN
    EXECUTE PROCEDURE GERARPONTUACAOCLIENTE(3, COALESCE(NEW.CHAVEDOC,0), NEW.NL, NEW.CHAVE);
  --CANCELAR PONTUACAO NO CANCELAMENTO DO TITULO
  IF ((NEW.STATUS=2) AND (OLD.STATUS<>2)) THEN
    EXECUTE PROCEDURE GERARPONTUACAOCLIENTE(3, COALESCE(NEW.CHAVEDOC,0), NEW.NL, NEW.CHAVE);
  --GERAR PONTUACAO NA REATIVACAO DO TITULO (DESAG. CONTA)
  IF ((NEW.ATIVO = 1) AND (OLD.ATIVO <> 1) AND (OLD.ATIVO > 0)) THEN
    EXECUTE PROCEDURE GERARPONTUACAOCLIENTE(4, COALESCE(NEW.CHAVEDOC,0), NEW.NL, NEW.CHAVE);
END
^

