ALTER PROCEDURE DUPLICANFENTRADA (
    CHAVENF INTEGER,
    CHAVEEMP INTEGER,
    ENLATUAL DOUBLE PRECISION)
RETURNS (
    CHAVEFINAL INTEGER)
AS
DECLARE VARIABLE CHAVENFENTRADA INTEGER;
DECLARE VARIABLE TOTALICMS NUMERIC(18,6);
DECLARE VARIABLE PERCREDIPI NUMERIC(18,6);
DECLARE VARIABLE VALIQIBSMUN NUMERIC(7,2);
DECLARE VARIABLE VALIQCBS NUMERIC(7,2);
DECLARE VARIABLE VALIQIBSUF NUMERIC(7,2);
DECLARE VARIABLE BCIPI NUMERIC(18,6);
DECLARE VARIABLE VCHAVECLASSTRIB INTEGER;
DECLARE VARIABLE VVLRIBSDIFUF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSDIFMUN NUMERIC(18,6);
DECLARE VARIABLE VVLRCBSDIF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSMUN NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSUF NUMERIC(18,6);
DECLARE VARIABLE VVLRCBS NUMERIC(18,6);
DECLARE VARIABLE VBASEIVA NUMERIC(18,6);
DECLARE VARIABLE VCONVTRIB NUMERIC(18,6);
DECLARE VARIABLE VVLRUNTRIB NUMERIC(18,6);
DECLARE VARIABLE VQTDETRIB NUMERIC(18,6);
DECLARE VARIABLE VUNTRIB VARCHAR(6);
DECLARE VARIABLE VQTDEESTOQUE NUMERIC(18,6);
DECLARE VARIABLE CHAVEDPTOESTOQUE INTEGER;
DECLARE VARIABLE COMPORTOTALNF INTEGER;
DECLARE VARIABLE ORIGEMDEVOLV INTEGER;
DECLARE VARIABLE VLRCOFINSTRIB NUMERIC(18,6);
DECLARE VARIABLE VLRPISTRIB NUMERIC(18,6);
DECLARE VARIABLE VLRIPITRIB NUMERIC(18,6);
DECLARE VARIABLE CHAVEDOCDEVOLV INTEGER;
DECLARE VARIABLE CHAVEITEMDEVOLV INTEGER;
DECLARE VARIABLE BASEICMS NUMERIC(18,6);
DECLARE VARIABLE TOTALPRODUTOS NUMERIC(18,6);
DECLARE VARIABLE TOTALIPI NUMERIC(18,4);
DECLARE VARIABLE BASEICMSSERV NUMERIC(18,4);
DECLARE VARIABLE TOTALICMSSERV NUMERIC(18,4);
DECLARE VARIABLE CHAVEPRODUTO INTEGER;
DECLARE VARIABLE CODPRODUTO VARCHAR(6);
DECLARE VARIABLE PRODUTO VARCHAR(100);
DECLARE VARIABLE CHAVEUNIDADE INTEGER;
DECLARE VARIABLE UN VARCHAR(6);
DECLARE VARIABLE QTDE NUMERIC(18,6);
DECLARE VARIABLE VLRLANC NUMERIC(18,6);
DECLARE VARIABLE VLRUNIT NUMERIC(18,6);
DECLARE VARIABLE DESCPORC NUMERIC(7,2);
DECLARE VARIABLE DESCVLR NUMERIC(18,6);
DECLARE VARIABLE VLRUNITCOMDESC NUMERIC(18,6);
DECLARE VARIABLE CHAVETRIBUTACAO INTEGER;
DECLARE VARIABLE CST VARCHAR(6);
DECLARE VARIABLE VLRSUBTOTAL NUMERIC(18,6);
DECLARE VARIABLE VLRTOTAL NUMERIC(18,6);
DECLARE VARIABLE ICMS NUMERIC(7,2);
DECLARE VARIABLE VLRICMS NUMERIC(18,6);
DECLARE VARIABLE CHAVECLASSFISCAL INTEGER;
DECLARE VARIABLE CSTIPI CHAR(2);
DECLARE VARIABLE IPI NUMERIC(7,2);
DECLARE VARIABLE BASECALCIPI NUMERIC(18,6);
DECLARE VARIABLE VLRIPI NUMERIC(18,6);
DECLARE VARIABLE BASEICMSSUBSTTRIB NUMERIC(18,6);
DECLARE VARIABLE VLRICMSSUBSTTRIB NUMERIC(18,6);
DECLARE VARIABLE BASEICMSSUBSTTRIBDESTAC NUMERIC(18,6);
DECLARE VARIABLE VLRICMSSUBSTTRIBDESTAC NUMERIC(18,6);
DECLARE VARIABLE PRECOCUSTO NUMERIC(18,6);
DECLARE VARIABLE PRECOVENDA NUMERIC(18,6);
DECLARE VARIABLE CUSTOFRETE NUMERIC(18,6);
DECLARE VARIABLE CUSTOSEGURO NUMERIC(18,6);
DECLARE VARIABLE CUSTODESPACESSORIAS NUMERIC(18,6);
DECLARE VARIABLE CUSTOPISCOFINS NUMERIC(18,6);
DECLARE VARIABLE ALIQUOTAPISCOFINS NUMERIC(7,2);
DECLARE VARIABLE CHAVEFATORMARKUP INTEGER;
DECLARE VARIABLE CHAVECFOP INTEGER;
DECLARE VARIABLE ALIQUOTAINTRA NUMERIC(7,2);
DECLARE VARIABLE MVA NUMERIC(7,2);
DECLARE VARIABLE CHAVECFOPOPERFISCAIS INTEGER;
DECLARE VARIABLE MOVESTOQUE SMALLINT;
DECLARE VARIABLE CSTPIS CHAR(2);
DECLARE VARIABLE ALIQPIS NUMERIC(18,6);
DECLARE VARIABLE BCPIS NUMERIC(18,6);
DECLARE VARIABLE VLRPIS NUMERIC(18,6);
DECLARE VARIABLE CSTCOFINS CHAR(2);
DECLARE VARIABLE ALIQCOFINS NUMERIC(18,6);
DECLARE VARIABLE BCCOFINS NUMERIC(18,6);
DECLARE VARIABLE VLRCOFINS NUMERIC(18,6);
DECLARE VARIABLE IPITRIB VARCHAR(2);
DECLARE VARIABLE CHAVELOTEPROD INTEGER;
DECLARE VARIABLE CHAVEITEMOLD INTEGER;
DECLARE VARIABLE CHAVEITEMNEW INTEGER;
DECLARE VARIABLE DESCRCOMPLEMENTPROD VARCHAR(1000);
DECLARE VARIABLE VCODENQIPI VARCHAR(6);
DECLARE VARIABLE VVLRICMSFCPST NUMERIC(18,6);
DECLARE VARIABLE VTOTALICMSFCPST NUMERIC(18,6);
DECLARE VARIABLE VVLRICMSDESONERADO NUMERIC(18,6);
DECLARE VARIABLE VTOTALICMSDESONERADO NUMERIC(18,6);
BEGIN
    CHAVENFENTRADA = GEN_ID(GEN_NFENTRADA_ID,1);
    INSERT INTO NFENTRADA (CHAVE, CHAVEEMPRESA, DATALANCAMENTO,
        NUMEROPED, DATAPED, CHAVECOTACAO, NUMERONF,
        EMISSAO,
        ENTRADA,
        VALORNF, BASECALCULOICMS, VLRICMS, BASECALCICMSSUBST, VLRICMSSUBST, FRETE,
        FATURA, VLRSEGURO, DESPACESSORIA, TOTALIPI, BCIPI, DESCONTOPORC, DESCONTOVLR,
        TOTALPRODUTO, DESCPORCSERVICO, DESCVLRSERVICO, TOTALSERVICO, TOTALNF,
        FRETEPORCONTA, QTDEVOLUME, ESPECIE, MARCA, NUMERO, PESOBRUTO, PESOLIQUIDO,
        OBS, CHAVECFOPPROD, CHAVECFOPSERV,
        CHAVECLIFOR, CHAVECONDPGTO, CHAVESERIENF, CHAVETRANSP,
        CHAVEMACROES, DATACANCELAMENTO, BASECALCICMSSUBSTDESTAC, VLRCALCICMSSUBSTDESTAC,
        SERIENF, INDICADOR, IDVEICULO, BASEISS, ALIQUOTAISS, TOTALISS,NL, STATUS,
        CHAVECFOPOPERFISCAIS, MODELONF, TIPOPAGAMENTO, BCPISCOFINS, VLRPIS, VLRCOFINS,
        BASEIRRF, VLRIRRF, BASEINSS, VLRINSS, BASECSLL, VLRCSLL,
        CHAVEACESSONFE, BCPISCOFINSSERV, VLRPISSERV, VLRCOFINSSERV, CHAVECENTROCUSTO, CHAVEPLANOCONTA,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CLASSECONSUMOENERGIAGAS,
        CLASSECONSUMOAGUA, TIPOLIGACAO, GRUPOTENSAO, TIPOASSINANTE, VLRPAGOTERCEIROS, SUBSERIE, ORIGEMNF, FORMAPGTO,
        FATURAXML, VLRICMSFCPST, VLRICMSDESONERADO, BASEIVA, VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFMUN,
        VLRIBSDIFUF)
    SELECT :CHAVENFENTRADA, :CHAVEEMP, 'NOW',
        NUMEROPED, DATAPED, CHAVECOTACAO, NUMERONF,
        CASE WHEN COALESCE(CHAVESERIENF,0) = 0 THEN EMISSAO ELSE CURRENT_DATE END,
        CASE WHEN COALESCE(CHAVESERIENF,0) = 0 THEN ENTRADA ELSE CURRENT_DATE END,
        VALORNF, BASECALCULOICMS, VLRICMS, BASECALCICMSSUBST, VLRICMSSUBST, FRETE,
        FATURA, VLRSEGURO, DESPACESSORIA, TOTALIPI, BCIPI, DESCONTOPORC, DESCONTOVLR,
        TOTALPRODUTO, DESCPORCSERVICO, DESCVLRSERVICO, TOTALSERVICO, TOTALNF,
        FRETEPORCONTA, QTDEVOLUME, ESPECIE, MARCA, NUMERO, PESOBRUTO, PESOLIQUIDO,
        OBS, CHAVECFOPPROD, CHAVECFOPSERV,
        CHAVECLIFOR, CHAVECONDPGTO, CHAVESERIENF, CHAVETRANSP,
        CHAVEMACROES, DATACANCELAMENTO, BASECALCICMSSUBSTDESTAC, VLRCALCICMSSUBSTDESTAC,
        SERIENF, 0, IDVEICULO, BASEISS, ALIQUOTAISS, TOTALISS, :ENLATUAL, 0,
        CHAVECFOPOPERFISCAIS, MODELONF, TIPOPAGAMENTO, BCPISCOFINS, VLRPIS, VLRCOFINS,
        BASEIRRF, VLRIRRF, BASEINSS, VLRINSS, BASECSLL, VLRCSLL,
        CASE WHEN COALESCE(CHAVESERIENF,0) = 0 THEN  CHAVEACESSONFE ELSE NULL END, BCPISCOFINSSERV, VLRPISSERV, VLRCOFINSSERV, CHAVECENTROCUSTO, CHAVEPLANOCONTA,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CLASSECONSUMOENERGIAGAS,
        CLASSECONSUMOAGUA, TIPOLIGACAO, GRUPOTENSAO, TIPOASSINANTE, VLRPAGOTERCEIROS, SUBSERIE, ORIGEMNF, FORMAPGTO,
        FATURAXML, VLRICMSFCPST, VLRICMSDESONERADO, BASEIVA, VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFMUN,
        VLRIBSDIFUF
    FROM NFENTRADA WHERE CHAVE=:CHAVENF;

    FOR SELECT CHAVE, CHAVEPRODUTO, CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE,
    VLRLANC, VLRUNIT, DESCPORC, DESCVLR, VLRUNITCOMDESC, CHAVETRIBUTACAO, CST, VLRSUBTOTAL, VLRTOTAL, ICMS,
    VLRICMS, BASEICMS, CHAVECLASSFISCAL, CSTIPI, IPI,
    BASECALCIPI, VLRIPI ,BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB, BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, PRECOCUSTO,
    PRECOVENDA, CUSTOFRETE, CUSTOSEGURO, CUSTODESPACESSORIAS, CUSTOPISCOFINS, ALIQUOTAPISCOFINS, CHAVEFATORMARKUP,
    CHAVECFOP, ALIQUOTAINTRA, MVA, CHAVECFOPOPERFISCAIS, MOVESTOQUE, COMPORTOTALNF, CSTPIS, ALIQPIS, BCPIS, VLRPIS, CSTCOFINS,
    ALIQCOFINS, BCCOFINS, VLRCOFINS, IPITRIB, CHAVELOTEPROD, CHAVEITEMDEVOLV, CHAVEDOCDEVOLV, ORIGEMDEVOLV, VLRIPITRIB, VLRPISTRIB,
    VLRCOFINSTRIB, DESCRCOMPLEMENT, CHAVEDPTOESTOQUE, CODENQIPI, QTDEESTOQUE, UNTRIB, QTDETRIB, CONVTRIB, VLRUNTRIB,
    VLRICMSFCPST, VLRICMSDESONERADO, PERCREDIPI, CHAVECLASSTRIB, BASEIVA, ALIQCBS, ALIQIBSUF, ALIQIBSMUN, VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFMUN,
    VLRIBSDIFUF
    FROM ITENSNFENTRADAPROD WHERE ATIVO=1 AND CHAVENFENTRADA=:CHAVENF ORDER BY CHAVE INTO
    :CHAVEITEMOLD, :CHAVEPRODUTO, :CODPRODUTO, :PRODUTO, :CHAVEUNIDADE, :UN, :QTDE,
    :VLRLANC, :VLRUNIT, :DESCPORC, :DESCVLR, :VLRUNITCOMDESC, :CHAVETRIBUTACAO, :CST, :VLRSUBTOTAL, :VLRTOTAL, :ICMS,
    :VLRICMS, :BASEICMS, :CHAVECLASSFISCAL, :CSTIPI, :IPI,
    :BASECALCIPI,
    :VLRIPI,
    :BASEICMSSUBSTTRIB, :VLRICMSSUBSTTRIB, :BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC, :PRECOCUSTO,
    :PRECOVENDA, :CUSTOFRETE, :CUSTOSEGURO, :CUSTODESPACESSORIAS, :CUSTOPISCOFINS, :ALIQUOTAPISCOFINS, :CHAVEFATORMARKUP,
    :CHAVECFOP, :ALIQUOTAINTRA, :MVA, :CHAVECFOPOPERFISCAIS, :MOVESTOQUE, :COMPORTOTALNF, :CSTPIS, :ALIQPIS, :BCPIS, :VLRPIS, :CSTCOFINS,
    :ALIQCOFINS, :BCCOFINS, :VLRCOFINS, :IPITRIB, :CHAVELOTEPROD, :CHAVEITEMDEVOLV, :CHAVEDOCDEVOLV, :ORIGEMDEVOLV, :VLRIPITRIB,
    :VLRPISTRIB, :VLRCOFINSTRIB, :DESCRCOMPLEMENTPROD, :CHAVEDPTOESTOQUE, :VCODENQIPI, :VQTDEESTOQUE, :VUNTRIB, :VQTDETRIB, :VCONVTRIB, :VVLRUNTRIB,
    :VVLRICMSFCPST, :VVLRICMSDESONERADO, :PERCREDIPI, :VCHAVECLASSTRIB, :VBASEIVA, :VALIQCBS, :VALIQIBSUF, :VALIQIBSMUN, :VVLRCBS, :VVLRIBSUF, :VVLRIBSMUN, :VVLRCBSDIF, :VVLRIBSDIFMUN,
    :VVLRIBSDIFUF
    DO BEGIN
        CHAVEITEMNEW = GEN_ID(GEN_ITENSNFENTRADAPROD_ID,1);
        INSERT INTO ITENSNFENTRADAPROD
            (CHAVE, CHAVEEMPRESA, CHAVENFENTRADA, CHAVEPRODUTO, CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE,
            VLRLANC, VLRUNIT, DESCPORC, DESCVLR, VLRUNITCOMDESC, CHAVETRIBUTACAO, CST, VLRSUBTOTAL, VLRTOTAL, ICMS, 
            VLRICMS, BASEICMS, CHAVECLASSFISCAL, CSTIPI, IPI, BASECALCIPI, VLRIPI,
            BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB, BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, PRECOCUSTO, PRECOVENDA, 
            CUSTOFRETE, CUSTOSEGURO, CUSTODESPACESSORIAS, CUSTOPISCOFINS, ALIQUOTAPISCOFINS, CHAVEFATORMARKUP, CHAVECFOP, 
            ALIQUOTAINTRA, MVA, NL, CHAVECFOPOPERFISCAIS, MOVESTOQUE, COMPORTOTALNF, CSTPIS, ALIQPIS, BCPIS, VLRPIS, CSTCOFINS,
            ALIQCOFINS, BCCOFINS, VLRCOFINS, IPITRIB, CHAVELOTEPROD, CHAVEITEMDEVOLV, CHAVEDOCDEVOLV, ORIGEMDEVOLV, VLRIPITRIB, VLRPISTRIB, VLRCOFINSTRIB,
            DESCRCOMPLEMENT, CHAVEDPTOESTOQUE, CODENQIPI, QTDEESTOQUE, UNTRIB, QTDETRIB, CONVTRIB, VLRUNTRIB, VLRICMSFCPST,
            VLRICMSDESONERADO, PERCREDIPI, CHAVECLASSTRIB, BASEIVA, ALIQCBS, ALIQIBSUF, ALIQIBSMUN, VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFMUN,
            VLRIBSDIFUF)
        VALUES
            (:CHAVEITEMNEW, :CHAVEEMP, :CHAVENFENTRADA, :CHAVEPRODUTO, :CODPRODUTO, :PRODUTO, :CHAVEUNIDADE, :UN, :QTDE,
            :VLRLANC, :VLRUNIT, :DESCPORC, :DESCVLR, :VLRUNITCOMDESC, :CHAVETRIBUTACAO, :CST, :VLRSUBTOTAL, :VLRTOTAL, :ICMS,
            :VLRICMS, :BASEICMS, :CHAVECLASSFISCAL, :CSTIPI, :IPI, :BASECALCIPI, :VLRIPI,
            :BASEICMSSUBSTTRIB, :VLRICMSSUBSTTRIB, :BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC, :PRECOCUSTO, :PRECOVENDA,
            :CUSTOFRETE, :CUSTOSEGURO, :CUSTODESPACESSORIAS, :CUSTOPISCOFINS, :ALIQUOTAPISCOFINS, :CHAVEFATORMARKUP, :CHAVECFOP,
            :ALIQUOTAINTRA, :MVA, :ENLATUAL, :CHAVECFOPOPERFISCAIS, :MOVESTOQUE, :COMPORTOTALNF, :CSTPIS, :ALIQPIS, :BCPIS, :VLRPIS, :CSTCOFINS,
            :ALIQCOFINS, :BCCOFINS, :VLRCOFINS, :IPITRIB, :CHAVELOTEPROD, :CHAVEITEMDEVOLV, :CHAVEDOCDEVOLV, :ORIGEMDEVOLV, :VLRIPITRIB, :VLRPISTRIB, :VLRCOFINSTRIB,
            :DESCRCOMPLEMENTPROD, :CHAVEDPTOESTOQUE, :VCODENQIPI, :VQTDEESTOQUE, :VUNTRIB, :VQTDETRIB, :VCONVTRIB, :VVLRUNTRIB, :VVLRICMSFCPST,
            :VVLRICMSDESONERADO, :PERCREDIPI, :VCHAVECLASSTRIB, :VBASEIVA, :VALIQCBS, :VALIQIBSUF, :VALIQIBSMUN, :VVLRCBS, :VVLRIBSUF, :VVLRIBSMUN, :VVLRCBSDIF, :VVLRIBSDIFMUN,
            :VVLRIBSDIFUF);

        INSERT INTO ITENSNFENTRADALOTEPROD(CHAVEEMPRESA, CHAVEITEMNF, CHAVEPRODUTO, CHAVELOTEPROD, QTDE)
        SELECT CHAVEEMPRESA, :CHAVEITEMNEW, CHAVEPRODUTO, CHAVELOTEPROD, QTDE FROM ITENSNFENTRADALOTEPROD
        WHERE ATIVO=1 AND CHAVEITEMNF = :CHAVEITEMOLD AND CHAVEEMPRESA = :CHAVEEMP AND CHAVEPRODUTO = :CHAVEPRODUTO;
    END

    INSERT INTO ITENSNFENTRADASERV (CHAVEEMPRESA, CHAVENFENTRADA,
        CHAVEPRODUTO, CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE,
        VLRLANC, VLRUNIT, VLRUNITORIGINALSERV, DESCPORC, DESCVLR,
        ISS, VLRISS, VLRUNITCOMDESC, VLRSUBTOTAL, VLRTOTAL, PRECOCUSTO,
        PRECOVENDA, CHAVECFOP, NL, CHAVECFOPOPERFISCAIS, CHAVETRIBUTACAO,
        BASEICMS, VLRICMS, BASEISS, CSTPISCOFINS, BASEPISCOFINS, ALIQPIS,
        ALIQCOFINS, VLRPIS, VLRCOFINS, DESCRCOMPLEMENT, CHAVECLASSTRIB, BASEIVA,
        ALIQCBS, ALIQIBSUF, ALIQIBSMUN, 
        VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFMUN, VLRIBSDIFUF)
    SELECT CHAVEEMPRESA, :CHAVENFENTRADA,
        CHAVEPRODUTO, CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE,
        VLRLANC, VLRUNIT, VLRUNITORIGINALSERV, DESCPORC, DESCVLR,
        ISS, VLRISS, VLRUNITCOMDESC, VLRSUBTOTAL, VLRTOTAL, PRECOCUSTO,
        PRECOVENDA, CHAVECFOP, :ENLATUAL, CHAVECFOPOPERFISCAIS, CHAVETRIBUTACAO,
        BASEICMS, VLRICMS, BASEISS, CSTPISCOFINS, BASEPISCOFINS, ALIQPIS,
        ALIQCOFINS, VLRPIS, VLRCOFINS, DESCRCOMPLEMENT, CHAVECLASSTRIB, BASEIVA,
        ALIQCBS, ALIQIBSUF, ALIQIBSMUN, 
        VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFMUN, VLRIBSDIFUF
    FROM ITENSNFENTRADASERV WHERE ATIVO=1 AND CHAVENFENTRADA=:CHAVENF
    ORDER BY CHAVE;

    SELECT SUM(VLRICMS), SUM(BASEICMS), SUM(VLRTOTAL), SUM(COALESCE(VLRIPI,0)), SUM(COALESCE(BASECALCIPI, 0)), SUM(COALESCE(VLRICMSFCPST, 0)), SUM(COALESCE(VLRICMSDESONERADO, 0))
    FROM ITENSNFENTRADAPROD
    WHERE CHAVENFENTRADA=:CHAVENFENTRADA
    INTO :TOTALICMS, :BASEICMS, :TOTALPRODUTOS, :TOTALIPI, :BCIPI, :VTOTALICMSFCPST, :VTOTALICMSDESONERADO;

    SELECT SUM(BASEICMS), SUM(VLRICMS)
    FROM ITENSNFENTRADASERV
    WHERE CHAVENFENTRADA=:CHAVENFENTRADA
    INTO :BASEICMSSERV, :TOTALICMSSERV;

    UPDATE NFENTRADA SET
        VLRICMS= COALESCE(:TOTALICMS,0)+COALESCE(:TOTALICMSSERV,0),
        BASECALCULOICMS= COALESCE(:BASEICMS,0)+COALESCE(:BASEICMSSERV,0),
        TOTALPRODUTO=COALESCE(:TOTALPRODUTOS,0),
        TOTALNF=COALESCE(:TOTALPRODUTOS,0) + COALESCE(TOTALSERVICO,0),
        TOTALIPI=COALESCE(:TOTALIPI,0),
        BCIPI   = COALESCE(:BCIPI,0),
        VLRICMSFCPST = COALESCE(:VTOTALICMSFCPST,0),
        VLRICMSDESONERADO = COALESCE(:VTOTALICMSDESONERADO,0)
    WHERE CHAVE=:CHAVENFENTRADA;

    EXECUTE PROCEDURE DUPLICAROBSLIVROFISCCOMPLDOCFIS(:CHAVENF, 0, :CHAVEEMP, :CHAVENFENTRADA, :ENLATUAL, 'N');

    INSERT INTO IMPOSTOSIMPORTACAO (
    ATIVO, CHAVEEMPRESA, CHAVENF, NL,
    TIPODOCIMPORTACAO, NUMERODOC, VLRPIS, VLRCOFINS, NUMEROACDRAW,
    DATADOC, LOCALDESEMBARACO, UFDESEMBARACO, DATADESEMBARACO, VLRII,
    VLRDESPADU, VLRIOF, TPVIATRANSP, VLRAFRMM, TPINTERMEDIO,
    CNPJADQUIRENTE, UFADQUIRENTE, NUMEROADICAO, NUMEROSEQADICAO,
    PESOLIQADICAO)
    SELECT 
    ATIVO, CHAVEEMPRESA, :CHAVENFENTRADA, :ENLATUAL,
    TIPODOCIMPORTACAO, NUMERODOC, VLRPIS, VLRCOFINS, NUMEROACDRAW,
    DATADOC, LOCALDESEMBARACO, UFDESEMBARACO, DATADESEMBARACO, VLRII,
    VLRDESPADU, VLRIOF, TPVIATRANSP, VLRAFRMM, TPINTERMEDIO,
    CNPJADQUIRENTE, UFADQUIRENTE, NUMEROADICAO, NUMEROSEQADICAO,
    PESOLIQADICAO FROM IMPOSTOSIMPORTACAO
    WHERE ATIVO=1 AND CHAVENF = :CHAVENF;


    CHAVEFINAL=:CHAVENFENTRADA;
    SUSPEND;
    /*
        CHAMADAS:
            - FUNCOESPROC : NESTA UNIT TEM A FUNCAO DE DUPLICAR A NF DE ENTRADA QUE FAZ A CHAMADA DA PROCEDURE
            - FRMNFENTRADA;
   */
END^


ALTER PROCEDURE DUPLICARCONDICIONAL (
    ECHAVEEMPRESA INTEGER,
    ECHAVECOND INTEGER,
    ECHAVEEMPCUSTO INTEGER,
    ECHAVEEMPEST INTEGER,
    ECHAVEUSUARIOLOG INTEGER,
    ENLATUAL DOUBLE PRECISION,
    ECHAVETABELAPRECO INTEGER)
RETURNS (
    SCHAVEFINAL INTEGER)
AS
declare variable VCONDAUTMAN integer;
declare variable VULTIMACOND integer;
declare variable VCODIGOCOND varchar(9);
declare variable VCHAVELOTEPROD integer;
declare variable VCODPRODUTO varchar(10);
declare variable VCHAVEPRODUTO integer;
declare variable VCHAVEITEM integer;
declare variable VVLRUNITCOMDESC numeric(18,6);
declare variable VCHAVEDPTOESTOQUE integer;
declare variable VTIPOMOVIMENTACAO integer;
declare variable VPRECOMEDIO numeric(18,6);
declare variable VCONVERSAO numeric(18,6);
declare variable VAGRUPADOCOMPOSTO integer;
declare variable VQTDE numeric(18,6);
declare variable VCHAVECLIFOR integer;
declare variable VAUTOINC integer;
declare variable VTOTALICMS numeric(18,6);
declare variable VBASEICMS numeric(18,6);
declare variable VTOTALPRODUTOS numeric(18,6);
declare variable VBASEICMSSUBSTTTRIB numeric(18,6);
declare variable VVLRICMSSUBSTTRIB numeric(18,6);
declare variable VBASEICMSSUBSTDESTAC numeric(18,6);
declare variable VVLRICMSSUBSTDESTAC numeric(18,6);
declare variable VTOTALSERVICO numeric(18,6);
declare variable VMOVESTOQUE integer;
declare variable VNEWCHAVEITEM integer;
declare variable VDESCACUMULADO numeric(18,6);
BEGIN
    VDESCACUMULADO =0;
    SELECT ULTIMACOND FROM CONFIGCONDICIONAL
    WHERE (ATIVO=1) AND (CHAVEEMPRESA=:ECHAVEEMPRESA)
    INTO :VULTIMACOND;
    SELECT CONDAUTMAN FROM CONFIGCONDICIONAL
    WHERE (ATIVO=1) AND (CHAVEEMPRESA=:ECHAVEEMPRESA)
    INTO :VCONDAUTMAN;
    IF (:VCONDAUTMAN=0) THEN BEGIN
        VULTIMACOND=:VULTIMACOND+1;
        VCODIGOCOND= '';
        VCODIGOCOND= LPAD(CAST(VULTIMACOND AS INTEGER),9,0);
        UPDATE CONFIGCONDICIONAL SET ULTIMACOND=:VULTIMACOND
        WHERE (ATIVO=1) AND (CHAVEEMPRESA=:ECHAVEEMPRESA);
    END ELSE
        VCODIGOCOND = '';
    VAUTOINC = GEN_ID(GEN_CONDICIONAL_ID,1);
    INSERT INTO CONDICIONAL (CHAVE, ATIVO, CHAVEEMPRESA, NROCONDICIONAL, CHAVECLIFOR, CHAVECONDPGTO,
        FRETE, TOTALIPI,
        BCIPI, DESCPORCPROD, DESCVLRPROD, TOTALPRODUTO, TOTALCONDICIONAL, TOTALSERVICO,
        OBS, DATAABERT, DESCPORCSERVICO, DESCVLRSERVICO,
        BASECALCULOICMS, VLRICMS, BASECALCICMSSUBST, VLRICMSSUBST,
        BASECALCICMSSUBSTDESTAC, VLRICMSSUBSTDESTAC, SITUACAO,
        NL, FATURA,
        CHAVECTABANCARIA, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD, CHAVECFOPSERV,
        CHAVETABELADESCONTOS, CONTATO, TIPOPAGAMENTO,
        TIPOSENHADESCPROD, CHAVEUSUARIOAUTORDESCPROD, TIPOSENHADESCSERV, CHAVEUSUARIOAUTORDESCSERV,
        CHAVEPLANOCONTA, CHAVECENTROCUSTO, FORMAPGTO, STATUSENTREGA)
    SELECT :VAUTOINC, 1, :ECHAVEEMPRESA, :VCODIGOCOND, CHAVECLIFOR, CHAVECONDPGTO,
        FRETE, TOTALIPI,
        BCIPI, DESCPORCPROD, DESCVLRPROD, TOTALPRODUTO, TOTALCONDICIONAL, TOTALSERVICO,
        OBS, 'NOW', DESCPORCSERVICO, DESCVLRSERVICO,
        BASECALCULOICMS, VLRICMS, BASECALCICMSSUBST, VLRICMSSUBST,
        BASECALCICMSSUBSTDESTAC, VLRICMSSUBSTDESTAC, 0,
        :ENLATUAL, FATURA,
        CHAVECTABANCARIA, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD, CHAVECFOPSERV,
        CHAVETABELADESCONTOS, CONTATO, TIPOPAGAMENTO,
        TIPOSENHADESCPROD, CHAVEUSUARIOAUTORDESCPROD, TIPOSENHADESCSERV, CHAVEUSUARIOAUTORDESCSERV,
        CHAVEPLANOCONTA, CHAVECENTROCUSTO, FORMAPGTO, 0
    FROM CONDICIONAL
    WHERE (CHAVE=:ECHAVECOND);
    SELECT
        CHAVE
    FROM DPTOESTOQUE
    WHERE (ATIVO=1)
    AND (CODIGO='001')
    AND (CHAVEEMPRESA=:ECHAVEEMPEST)
    AND (CHAVEEMPPROD=(SELECT CC.CHAVEEMPRESAREF FROM CONFIGCOMPART CC WHERE (CC.CHAVEEMPRESA=:ECHAVEEMPRESA) AND (CC.TABELA='PRODUTO')))
    INTO :VCHAVEDPTOESTOQUE;
    FOR SELECT IC.CHAVE
    FROM ITENSCONDICIONALPROD IC
    INNER JOIN PRODUTO P ON IC.CHAVEPRODUTO=P.CHAVE
    INNER JOIN TRIBUTACAO T ON IC.CHAVETRIBUTACAO=T.CHAVE
    LEFT JOIN CLASSFISCAL CL ON P.CHAVECLASSFISCAL=CL.CHAVE
    WHERE IC.ATIVO=1 AND IC.CHAVECONDICIONAL=:ECHAVECOND
    INTO :VCHAVEITEM DO BEGIN
        VNEWCHAVEITEM = GEN_ID(GEN_ITENSCONDICIONALPROD_ID,1);
        INSERT INTO ITENSCONDICIONALPROD
            (CHAVE, CHAVEEMPRESA, CHAVECONDICIONAL, CHAVEPRODUTO, CHAVECFOPOPERFISCAIS, CHAVECFOP,
            PRODUTO, CHAVEUNIDADE, UN, QTDE, VLRUNIT, DESCPORC, DESCVLR,
            CHAVETRIBUTACAO, VLRSUBTOTAL, VLRTOTAL, BASEICMS, ICMS, VLRICMS,
            IPI, CST, CSTIPI, VLRIPI, BASECALCIPI,
            BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB,
            BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, NL,
            DESCRCOMPLEMENT, INDICE, VLRVENDAMINIMO,
            VLRUNITORIGINAL, VLRUNITCOMDESC, VLRUNITTABELA,
            PRECOCUSTO,
            MVA, MVACALC,
            TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, CHAVELOTEPROD, IPITRIB,
            VLRIPITRIB, CHAVEDPTOESTOQUE, ALIQICMSINTRA, MOVESTOQUE, CHAVETABELAPRECO,
            CHAVEREGRAFISCAL, TIPOPROMOCAO, CHAVESPRODPROMO, NROORDEMCOMPRA, NROITEMORDEMCOMPRA)
        SELECT :VNEWCHAVEITEM, :ECHAVEEMPRESA, :VAUTOINC, CHAVEPRODUTO, CHAVECFOPOPERFISCAIS, CHAVECFOP,
            PRODUTO, CHAVEUNIDADE, UN, QTDE, VLRUNIT,
            DESCPORC, DESCVLR, CHAVETRIBUTACAO, VLRSUBTOTAL, VLRTOTAL,
            BASEICMS, ICMS, VLRICMS,
            IPI, CST, CSTIPI, VLRIPI, BASECALCIPI, BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB,
            BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, :ENLATUAL,
            DESCRCOMPLEMENT, 0, VLRVENDAMINIMO,
            VLRUNITORIGINAL, VLRUNITCOMDESC, VLRUNITTABELA,
            PRECOCUSTO,
            MVA, MVACALC,
            TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, CHAVELOTEPROD, IPITRIB,
            VLRIPITRIB, :VCHAVEDPTOESTOQUE, ALIQICMSINTRA, MOVESTOQUE, CASE :ECHAVETABELAPRECO WHEN 0 THEN CHAVETABELAPRECO ELSE :ECHAVETABELAPRECO END AS CHAVETABELAPRECO,
            CHAVEREGRAFISCAL, TIPOPROMOCAO, CHAVESPRODPROMO, NROORDEMCOMPRA, NROITEMORDEMCOMPRA
        FROM ITENSCONDICIONALPROD
        WHERE (ATIVO=1) AND (CHAVE=:VCHAVEITEM)
        ORDER BY CHAVE;
        INSERT INTO PRODUTOVENDAPROMOHIST (ATIVO, CHAVEEMPRESA, CHAVEITEMCOND, TIPOPROMOCAO, VALOR)
        SELECT ATIVO, CHAVEEMPRESA, :VNEWCHAVEITEM, TIPOPROMOCAO, VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMCOND=:VCHAVEITEM);
        VDESCACUMULADO = :VDESCACUMULADO + COALESCE((SELECT VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMCOND=:VCHAVEITEM)),0);
    END
    INSERT INTO ITENSCONDICIONALSERV
        (CHAVEEMPRESA, CHAVECONDICIONAL, CHAVEPRODUTO, CHAVECFOPOPERFISCAIS, CHAVECFOP,
        CHAVEUNIDADE, DESCPORC, DESCVLR, ISS, PRODUTO, QTDE,
        UN, VLRSUBTOTAL, TOTALSERVICO, VLRUNIT, NL, DESCRCOMPLEMENT,
        PRECOCUSTO, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, VLRUNITTABELA, CHAVETABELAPRECO)
    SELECT :ECHAVEEMPRESA, :VAUTOINC, CHAVEPRODUTO, CHAVECFOPOPERFISCAIS, CHAVECFOP,
        CHAVEUNIDADE, DESCPORC, DESCVLR, ISS, PRODUTO, QTDE, UN,
        VLRSUBTOTAL, TOTALSERVICO, VLRUNIT, :ENLATUAL, DESCRCOMPLEMENT,
        PRECOCUSTO, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, VLRUNITTABELA, CASE :ECHAVETABELAPRECO WHEN 0 THEN CHAVETABELAPRECO ELSE :ECHAVETABELAPRECO END AS CHAVETABELAPRECO
    FROM ITENSCONDICIONALSERV
    WHERE (ATIVO=1) AND (CHAVECONDICIONAL=:ECHAVECOND)
    ORDER BY CHAVE;
    INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
    SELECT CHAVEEMPRESA, :VAUTOINC, CHAVEVENDEDOR, ORIGEM, :ENLATUAL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA
    FROM COMISSAO
    WHERE (ATIVO=1) AND (ORIGEM=3) AND (CHAVEDOC=:ECHAVECOND);
    SELECT SUM(COALESCE(VLRICMS,0)), SUM(COALESCE(BASEICMS,0))
    FROM ITENSCONDICIONALPROD
    WHERE (ATIVO=1) AND (CHAVECONDICIONAL=:VAUTOINC)
    INTO :VTOTALICMS, :VBASEICMS;
    SELECT SUM(COALESCE(I.BASEICMSSUBSTTRIB,0)), SUM(COALESCE(I.VLRICMSSUBSTTRIB,0))
    FROM ITENSCONDICIONALPROD I
    INNER JOIN TRIBUTACAO T ON T.CHAVE=I.CHAVETRIBUTACAO
    WHERE (I.ATIVO=1) AND (I.CHAVECONDICIONAL=:VAUTOINC)
    INTO :VBASEICMSSUBSTTTRIB, :VVLRICMSSUBSTTRIB;
    SELECT SUM(COALESCE(BASEICMSSUBSTTRIBDESTAC,0)), SUM(COALESCE(VLRICMSSUBSTTRIBDESTAC,0))
    FROM ITENSCONDICIONALPROD
    WHERE (ATIVO=1) AND (CHAVECONDICIONAL=:VAUTOINC)
    INTO :VBASEICMSSUBSTDESTAC, :VVLRICMSSUBSTDESTAC;
    SELECT COALESCE(SUM(VLRTOTAL),0)
    FROM ITENSCONDICIONALPROD
    WHERE (ATIVO=1) AND (CHAVECONDICIONAL=:VAUTOINC)
    INTO :VTOTALPRODUTOS;
    SELECT COALESCE(SUM(TOTALSERVICO),0)
    FROM ITENSCONDICIONALSERV
    WHERE (ATIVO=1) AND (CHAVECONDICIONAL=:VAUTOINC)
    INTO :VTOTALSERVICO;
    UPDATE CONDICIONAL C SET
        VLRICMS= :VTOTALICMS,
        BASECALCULOICMS= :VBASEICMS,
        TOTALPRODUTO=:VTOTALPRODUTOS,
        TOTALSERVICO=:VTOTALSERVICO,
        BASECALCICMSSUBST=:VBASEICMSSUBSTTTRIB,
        VLRICMSSUBST=:VVLRICMSSUBSTTRIB,
        TOTALCONDICIONAL =:VTOTALPRODUTOS + :VTOTALSERVICO,
        BASECALCICMSSUBSTDESTAC=:VBASEICMSSUBSTDESTAC,
        VLRICMSSUBSTDESTAC=:VVLRICMSSUBSTDESTAC
    WHERE (CHAVE=:VAUTOINC);
    IF (:VDESCACUMULADO > 0) THEN BEGIN
        UPDATE CONDICIONAL C SET
            C.DESCVLRPROD=0,
            C.DESCPORCPROD=0
        WHERE (CHAVE=:VAUTOINC);
    END
    FOR SELECT I.CHAVE, I.CHAVEPRODUTO, P.CODIGO, I.CHAVELOTEPROD, I.QTDE,
        P.AGRUPADOCOMPOSTO, U.CONVERSAO, PC.PRECOMEDIO,
        CF.TIPOMOVIMENTACAO, I.CHAVEDPTOESTOQUE, I.VLRUNITCOMDESC, C.CHAVECLIFOR,
        I.MOVESTOQUE
        FROM ITENSCONDICIONALPROD I
        INNER JOIN CONDICIONAL C ON (C.CHAVE=I.CHAVECONDICIONAL)
        INNER JOIN PRODUTO P ON (I.CHAVEPRODUTO=P.CHAVE)
        INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=I.CHAVEPRODUTO) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
        INNER JOIN UNIDADE U ON (I.CHAVEUNIDADE=U.CHAVE)
        INNER JOIN CFOPOPERFISCAIS CF ON (I.CHAVECFOPOPERFISCAIS=CF.CHAVE)
        WHERE (I.ATIVO=1) AND (I.CHAVECONDICIONAL=:VAUTOINC)
    INTO :VCHAVEITEM, :VCHAVEPRODUTO, :VCODPRODUTO, :VCHAVELOTEPROD, :VQTDE,
        :VAGRUPADOCOMPOSTO, :VCONVERSAO, :VPRECOMEDIO,
        :VTIPOMOVIMENTACAO, :VCHAVEDPTOESTOQUE, :VVLRUNITCOMDESC, :VCHAVECLIFOR,
        :VMOVESTOQUE
    DO BEGIN
        IF (VMOVESTOQUE=0) THEN BEGIN
            EXECUTE PROCEDURE ESTENTRADASAIDAESTOQUE(:VCHAVEPRODUTO, :VCHAVELOTEPROD,
                :VQTDE*(-1), 0, :VAGRUPADOCOMPOSTO, :ECHAVEEMPEST, :ECHAVEEMPCUSTO,
                :ECHAVEUSUARIOLOG, :VAUTOINC, :ENLATUAL, :VCODIGOCOND, 8,
                '', :VCODPRODUTO, :VCONVERSAO, CURRENT_DATE, :VPRECOMEDIO, :VCHAVEITEM,
                :VCHAVECLIFOR, :VTIPOMOVIMENTACAO, 0, :VCHAVEDPTOESTOQUE, :VVLRUNITCOMDESC);
        END
    END
    SCHAVEFINAL=:VAUTOINC;
    SUSPEND;
    /*
        CHAMADAS:
            - funcoesProc : Nesta unit tem a funcao DuplicarCondicional que faz a chamada da procedure
                            Telas que chamam a funcao DuplicarCondicional
            - frmcondicional;
   */
END^


ALTER PROCEDURE DUPLICARCTRC (
    CHAVECTRC INTEGER,
    CHAVEEMPRESA INTEGER,
    ENLATUAL DOUBLE PRECISION)
RETURNS (
    CHAVEFINAL INTEGER)
AS
declare variable TIPOCTRC integer;
declare variable CHAVEGENCTRC integer;
BEGIN
    SELECT TIPOCTRC FROM CTRC
    WHERE CHAVE=:CHAVECTRC
    INTO :TIPOCTRC;
    CHAVEGENCTRC = GEN_ID(GEN_CTRC_ID,1);
    IF (:TIPOCTRC=0) THEN BEGIN
        INSERT INTO CTRC (CHAVE, ATIVO, CHAVEEMPRESA, NUMCTRC, EMISSAO, ENTRADA, VENCIMENTOCTRC,
            CHAVETRANSPORTADOR, FRETEPESO, FRETEVALOR, REEMBOLSO, SUBTOTAL, PEDAGIO, GRIS,
            REDESPACHO, TOTALFRETE, BASECALCICMS, ALIQICMS, VALORICMS, NL, OBS, CHAVESERIECTRC,
            SERIECTRC, CHAVECFOP, CHAVEREMETENTE, CHAVEDESTINATARIO, CHAVECIDCOLETA, CHAVECIDENTREGA,
            REDESPACHONUMCTRC, SITUACAO, SEGURO, OUTROS, TIPOCTRC, TIPONFSCTRC, SECCAT, DESPACHO,
            TIPOFRETEREDESPACHO, TIPOFRETE, SUBSERIE, CHAVETRIBUTACAO, CHAVECFOPOPERFISCAIS,
            CHAVECLIFORREDESP, CHAVECLIFORCONSIG, CHAVEACESSOCTE, TIPOEMISSAOCTE, DTHORAEMISSAOCTE,
            NRORECIBOCTE, NROPROTOCOLOCTE, DATAHORAPROTOCOLOCTE, STATUS, FORMAPGTO, TIPOPGTO, TOMADORSERVICO,
            MOTIVOINUTCANCCTE, VLRMERCADORIA, OUTRASINFCARGA, PRODPREDOMINANTE,
            PROCESSANDOCTE, MAQLOGADA, CHAVECLIFOROUTROS, TIPOSERV, FINALIDADE, MODELO, CHAVEMOTORISTA,
            VLRRECIBO, CHAVEVEICULO, CHAVEVEICULOSVINC1, CHAVEVEICULOSVINC2, CHAVEVEICULOSVINC3, SOMARICMSTOTFRETE,
            RESPONSAVELSEGURO, NOMESEGURADORA, NUMAPOLICE, VLRAVERBACAO, DIVISORICMS,
            PESOBRUTONFS, PESOLIQUIDONFS, CIOT,
            INSS, IRRF, SESTSENAT, VLRRECFRETE, VLRLIQRECFRETE, OUTROSVLRSOMAR, OUTROSVLRSUB, 
            VLRADIANTAMENTO, ALIQDESCCOMIS, VLRBRUTORECFRETE, VLRTOTTRIB, CTEGLOBALIZADO, TOTALRECEBER, REGIMETRIBUT,
