            REDESPACHONUMCTRC, 'ABERTO', SEGURO, OUTROS, TIPOCTRC, TIPONFSCTRC, SECCAT, DESPACHO,
            TIPOFRETEREDESPACHO, TIPOFRETE, SUBSERIE, CHAVETRIBUTACAO, CHAVECFOPOPERFISCAIS,
            CHAVECLIFORREDESP, CHAVECLIFORCONSIG, CHAVEACESSOCTE, TIPOEMISSAOCTE, '',
            '', '', '', 0, FORMAPGTO, TIPOPGTO, TOMADORSERVICO,
            MOTIVOINUTCANCCTE, VLRMERCADORIA, OUTRASINFCARGA, PRODPREDOMINANTE,
            PROCESSANDOCTE, MAQLOGADA, CHAVECLIFOROUTROS, TIPOSERV, FINALIDADE, MODELO, CHAVEMOTORISTA,
            VLRRECIBO, CHAVEVEICULO, CHAVEVEICULOSVINC1, CHAVEVEICULOSVINC2, CHAVEVEICULOSVINC3, SOMARICMSTOTFRETE,
            RESPONSAVELSEGURO, NOMESEGURADORA, NUMAPOLICE, VLRAVERBACAO, DIVISORICMS,
            PESOBRUTONFS, PESOLIQUIDONFS, CIOT,
            INSS, IRRF, SESTSENAT, VLRRECFRETE, VLRLIQRECFRETE, OUTROSVLRSOMAR, OUTROSVLRSUB,
            VLRADIANTAMENTO, ALIQDESCCOMIS, VLRBRUTORECFRETE, VLRTOTTRIB, CTEGLOBALIZADO, TOTALRECEBER, REGIMETRIBUT,
            NROMINUTA, NROOCA, DATAENTREGA, DIMENSAOCARGA, CLASSETARIFA, CODIGOTARIFA, VLRTARIFA, MODAL, REGNACTRANSPROD,
            CHAVECLASSTRIB, BASEIVA, VLRIBSMUN, VLRIBSUF, VLRCBS, ALIQIBSMUN, ALIQIBSUF, ALIQCBS, VLRIBSDIFMUN, VLRIBSDIFUF, VLRCBSDIF
        FROM CTRC WHERE CHAVE=:CHAVECTRC;
    END ELSE BEGIN
        INSERT INTO CTRC (CHAVE, ATIVO, CHAVEEMPRESA, NUMCTRC, EMISSAO, ENTRADA, VENCIMENTOCTRC,
            CHAVETRANSPORTADOR, FRETEPESO, FRETEVALOR, REEMBOLSO, SUBTOTAL, PEDAGIO, GRIS,
            REDESPACHO, TOTALFRETE, BASECALCICMS, ALIQICMS, VALORICMS, NL, OBS, CHAVESERIECTRC,
            SERIECTRC, CHAVECFOP, CHAVEREMETENTE, CHAVEDESTINATARIO, CHAVECIDCOLETA, CHAVECIDENTREGA,
            REDESPACHONUMCTRC, SITUACAO, SEGURO, OUTROS, TIPOCTRC, TIPONFSCTRC, SECCAT, DESPACHO,
            TIPOFRETEREDESPACHO, TIPOFRETE, SUBSERIE, CHAVETRIBUTACAO, CHAVECFOPOPERFISCAIS,
            CHAVECLIFORREDESP, CHAVECLIFORCONSIG, CHAVEACESSOCTE, TIPOEMISSAOCTE, DTHORAEMISSAOCTE,
            NRORECIBOCTE, NROPROTOCOLOCTE, DATAHORAPROTOCOLOCTE, STATUS, FORMAPGTO, TIPOPGTO, TOMADORSERVICO,
            MOTIVOINUTCANCCTE, VLRMERCADORIA, OUTRASINFCARGA, PRODPREDOMINANTE,
            PROCESSANDOCTE, MAQLOGADA, CHAVECLIFOROUTROS, TIPOSERV, FINALIDADE, MODELO, CHAVEMOTORISTA,
            VLRRECIBO, CHAVEVEICULO, CHAVEVEICULOSVINC1, CHAVEVEICULOSVINC2, CHAVEVEICULOSVINC3, SOMARICMSTOTFRETE,
            RESPONSAVELSEGURO, NOMESEGURADORA, NUMAPOLICE, VLRAVERBACAO,
            DIVISORICMS, PESOBRUTONFS, PESOLIQUIDONFS, SOMARQTDEUNMEDIDA, CIOT,
            INSS, IRRF, SESTSENAT, VLRRECFRETE, VLRLIQRECFRETE, OUTROSVLRSOMAR, OUTROSVLRSUB, VLRADIANTAMENTO,
            ALIQDESCCOMIS, VLRBRUTORECFRETE, VLRTOTTRIB, ALIQICMSUFFIM, ALIQICMSINTER, CTEGLOBALIZADO, TOTALRECEBER, REGIMETRIBUT, CUBAGEM,
            NROMINUTA, NROOCA, DATAENTREGA, DIMENSAOCARGA, CLASSETARIFA, CODIGOTARIFA, VLRTARIFA, MODAL, REGNACTRANSPROD,
            CHAVECLASSTRIB, BASEIVA, VLRIBSMUN, VLRIBSUF, VLRCBS, ALIQIBSMUN, ALIQIBSUF, ALIQCBS, VLRIBSDIFMUN, VLRIBSDIFUF, VLRCBSDIF)
        SELECT :CHAVEGENCTRC, 1, :CHAVEEMPRESA, '', CURRENT_DATE, CURRENT_DATE, CURRENT_DATE,
            CHAVETRANSPORTADOR, FRETEPESO, FRETEVALOR, REEMBOLSO, SUBTOTAL, PEDAGIO, GRIS,
            REDESPACHO, TOTALFRETE, BASECALCICMS, ALIQICMS, VALORICMS, :ENLATUAL, OBS, CHAVESERIECTRC,
            SERIECTRC, CHAVECFOP, CHAVEREMETENTE, CHAVEDESTINATARIO, CHAVECIDCOLETA, CHAVECIDENTREGA,
            REDESPACHONUMCTRC, 'ABERTO', SEGURO, OUTROS, TIPOCTRC, TIPONFSCTRC, SECCAT, DESPACHO,
            TIPOFRETEREDESPACHO, TIPOFRETE, SUBSERIE, CHAVETRIBUTACAO, CHAVECFOPOPERFISCAIS,
            CHAVECLIFORREDESP, CHAVECLIFORCONSIG, '', TIPOEMISSAOCTE, '',
            '', '', '', 0, FORMAPGTO, TIPOPGTO, TOMADORSERVICO,
            MOTIVOINUTCANCCTE, VLRMERCADORIA, OUTRASINFCARGA, PRODPREDOMINANTE,
            PROCESSANDOCTE, MAQLOGADA, CHAVECLIFOROUTROS, TIPOSERV, FINALIDADE, MODELO, CHAVEMOTORISTA,
            VLRRECIBO, CHAVEVEICULO, CHAVEVEICULOSVINC1, CHAVEVEICULOSVINC2, CHAVEVEICULOSVINC3, SOMARICMSTOTFRETE,
            RESPONSAVELSEGURO, NOMESEGURADORA, NUMAPOLICE, VLRAVERBACAO,
            DIVISORICMS, PESOBRUTONFS, PESOLIQUIDONFS, SOMARQTDEUNMEDIDA, CIOT,
            INSS, IRRF, SESTSENAT, VLRRECFRETE, VLRLIQRECFRETE, OUTROSVLRSOMAR, OUTROSVLRSUB, VLRADIANTAMENTO,
            ALIQDESCCOMIS, VLRBRUTORECFRETE, VLRTOTTRIB, ALIQICMSUFFIM, ALIQICMSINTER, CTEGLOBALIZADO, TOTALRECEBER, REGIMETRIBUT, CUBAGEM,
            NROMINUTA, NROOCA, DATAENTREGA, DIMENSAOCARGA, CLASSETARIFA, CODIGOTARIFA, VLRTARIFA, MODAL, REGNACTRANSPROD,
            CHAVECLASSTRIB, BASEIVA, VLRIBSMUN, VLRIBSUF, VLRCBS, ALIQIBSMUN, ALIQIBSUF, ALIQCBS, VLRIBSDIFMUN, VLRIBSDIFUF, VLRCBSDIF
        FROM CTRC WHERE CHAVE=:CHAVECTRC;
    END
    INSERT INTO CTRCNFS
        (ATIVO, CHAVEEMPRESA, CHAVECTRC, CHAVENF, NATUREZACARGA, NL, CODUNMEDIDA, TPMEDIDA, QTDEVOLUME, CHAVEACESSO, ORIGEM, TOTALPRODUTO, TOTALNF)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENCTRC, CHAVENF, NATUREZACARGA, :ENLATUAL, CODUNMEDIDA, TPMEDIDA, QTDEVOLUME, CHAVEACESSO, ORIGEM, TOTALPRODUTO, TOTALNF
    FROM CTRCNFS WHERE ATIVO=1 AND CHAVECTRC=:CHAVECTRC
    ORDER BY CHAVE;
    INSERT INTO CTRCOUTROSDOC
        (ATIVO, CHAVEEMPRESA, CHAVECTRC, DESCDOC, NUMERODOC, TIPOOUTRODOC, DTEMISSAODOC,
        VLRDOC, NL, CODUNMEDIDADOC, TPMEDIDA, QTDEVOLUME)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENCTRC, DESCDOC, NUMERODOC, TIPOOUTRODOC, DTEMISSAODOC,
        VLRDOC, :ENLATUAL, CODUNMEDIDADOC, TPMEDIDA, QTDEVOLUME
    FROM CTRCOUTROSDOC WHERE ATIVO=1 AND CHAVECTRC=:CHAVECTRC
    ORDER BY CHAVE;
    INSERT INTO CTRCDOCSANT
        (ATIVO, CHAVEEMPRESA, NUMERO, SERIE, EMISSAO, TIPODOC, CHAVEACESSO, SUBSERIE, CHAVECLIFOR, CHAVECTRC)
    SELECT 1, :CHAVEEMPRESA, NUMERO, SERIE, EMISSAO, TIPODOC, CHAVEACESSO, SUBSERIE, CHAVECLIFOR, :CHAVEGENCTRC
    FROM CTRCDOCSANT WHERE ATIVO=1 AND CHAVECTRC=:CHAVECTRC
    ORDER BY CHAVE;
    INSERT INTO CTRCPISCOFINS
        (ATIVO, CHAVEEMPRESA, CHAVECTRC, TIPOMOVIMENTO, VLRTOTAL, CSTPISCOFINS, BCPISCOFINS,
        ALIQPIS, ALIQCOFINS, VLRPIS, VLRCOFINS)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENCTRC, TIPOMOVIMENTO, VLRTOTAL, CSTPISCOFINS, BCPISCOFINS,
        ALIQPIS, ALIQCOFINS, VLRPIS, VLRCOFINS
    FROM CTRCPISCOFINS WHERE ATIVO=1 AND CHAVECTRC=:CHAVECTRC
    ORDER BY CHAVE;
    EXECUTE PROCEDURE DUPLICAROBSLIVROFISCCOMPLDOCFIS(:CHAVECTRC, 2, :CHAVEEMPRESA, :CHAVEGENCTRC, :ENLATUAL, 'N');
    CHAVEFINAL = :CHAVEGENCTRC;
    SUSPEND;
END^


ALTER PROCEDURE DUPLICAROBSLIVROFISCCOMPLDOCFIS (
    CHAVEDOC INTEGER,
    TIPODOC INTEGER,
    CHAVEEMP INTEGER,
    NOVACHAVEDOC INTEGER,
    NOVANL DOUBLE PRECISION,
    ETODOSCOMPL CHAR(1))
AS
declare variable CHAVEPAI integer;
declare variable AUTOINC integer;
declare variable VCHAVEOBSCOMPLFISCAL integer;
declare variable VUSAREM integer;
BEGIN
    FOR SELECT OBS.CHAVE, OBS.CHAVEOBSCOMPLFISCAL, OBSCOMPL.USAREM
    FROM OBSLIVROFISCCOMPLDOCFISC OBS
    INNER JOIN OBSCOMPLDOCFISCAL OBSCOMPL ON OBS.CHAVEOBSCOMPLFISCAL = OBSCOMPL.CHAVE
    WHERE OBS.ATIVO=1 AND OBS.TIPODOCFISCAL=:TIPODOC AND OBS.CHAVEDOCFISCAL = :CHAVEDOC
    ORDER BY OBS.CHAVE
    INTO :CHAVEPAI, :VCHAVEOBSCOMPLFISCAL, :VUSAREM DO BEGIN

        IF ((:ETODOSCOMPL = 'S') OR ((:VUSAREM <> 3) AND (:VCHAVEOBSCOMPLFISCAL <> 51))) THEN BEGIN
            AUTOINC = GEN_ID(GEN_OBSLIVROFISCCOMPLDOCFISC_ID,1);
            INSERT INTO OBSLIVROFISCCOMPLDOCFISC
                (CHAVE, CHAVEEMPRESA, CHAVEDOCFISCAL, NL, TIPODOCFISCAL, CHAVEOBSCOMPLFISCAL, DESCRICAOCOMPL, TIPO)
            SELECT :AUTOINC, :CHAVEEMP, :NOVACHAVEDOC, :NOVANL, TIPODOCFISCAL, CHAVEOBSCOMPLFISCAL, DESCRICAOCOMPL, TIPO
            FROM OBSLIVROFISCCOMPLDOCFISC
            WHERE CHAVE=:CHAVEPAI;
    
            INSERT INTO ITENSOBSLIVROFISCAL
                (CHAVEEMPRESA, CHAVEOBSLIVROFISCAL, CHAVECODAJUSTEICMS, DESCRICAOCOMPL, CHAVEPRODUTO,
                BASEICMS, ALIQICMS, VLRICMS, VLROUTROS, CFOPORIGINAL)
            SELECT :CHAVEEMP, :AUTOINC, CHAVECODAJUSTEICMS, DESCRICAOCOMPL, CHAVEPRODUTO,
                BASEICMS, ALIQICMS, VLRICMS, VLROUTROS, CFOPORIGINAL
            FROM ITENSOBSLIVROFISCAL
            WHERE (ATIVO=1) AND (CHAVEOBSLIVROFISCAL=:CHAVEPAI);
    
            INSERT INTO ITENSCOMPLPROCESSO
                (CHAVEEMPRESA, CHAVECOMPLDOCFISCAL, NUMERO, ORIGEM, CHAVEDETPROCESSO)
            SELECT :CHAVEEMP, :AUTOINC, NUMERO, ORIGEM, CHAVEDETPROCESSO
            FROM ITENSCOMPLPROCESSO
            WHERE (ATIVO=1) AND (CHAVECOMPLDOCFISCAL=:CHAVEPAI);
    
            INSERT INTO ITENSCOMPLDOCARREC
                (CHAVEEMPRESA, CHAVECOMPLDOCFISCAL, MODELO, UFBENEFICIADA, NUMERO, AUTENTBANCARIA, VLRTOTAL,
                VENCIMENTO, PAGAMENTO)
            SELECT :CHAVEEMP, :AUTOINC, MODELO, UFBENEFICIADA, NUMERO, AUTENTBANCARIA, VLRTOTAL,
                VENCIMENTO, PAGAMENTO
            FROM ITENSCOMPLDOCARREC
            WHERE (ATIVO=1) AND (CHAVECOMPLDOCFISCAL=:CHAVEPAI);
    
            INSERT INTO ITENSCOMPLDOCFISCAL
                (CHAVEEMPRESA, CHAVECOMPLDOCFISCAL, ORIGEMDOCFISCAL, CHAVECLIFOR, MODELO, CHAVESERIE, SERIE,
                SUBSERIE, CHAVENF, NUMERO, DATA, VLRTOTAL, CHAVEACESSONFE)
            SELECT :CHAVEEMP, :AUTOINC, ORIGEMDOCFISCAL, CHAVECLIFOR, MODELO, CHAVESERIE, SERIE,
                SUBSERIE, CHAVENF, NUMERO, DATA, VLRTOTAL, CHAVEACESSONFE
            FROM ITENSCOMPLDOCFISCAL
            WHERE (ATIVO=1) AND (CHAVECOMPLDOCFISCAL=:CHAVEPAI);
    
            INSERT INTO ITENSCOMPLCUPOMFISCAL
                (CHAVEEMPRESA, CHAVECOMPLDOCFISCAL, CHAVECUPOM, NLCUPOM)
            SELECT :CHAVEEMP, :AUTOINC, CHAVECUPOM, NLCUPOM
            FROM ITENSCOMPLCUPOMFISCAL
            WHERE (ATIVO=1) AND (CHAVECOMPLDOCFISCAL=:CHAVEPAI);
       END
    END
    /*
        CHAMADAS:
            - USADA SOMENTE NO BANCO DE DADOS, TEM A FUNCAO DE DUPLICAR AS OBSERVACOES E COMPLEMENTOS DE LIVROS FISCAIS
            PROCEDURES QUE CHAMAM A FUNCAO DUPLICAPEDIDOSAIDA
            - DUPLICANFENTRADA;
            - DUPLICAPEDIDOSAIDA;
   */
END^


ALTER PROCEDURE DUPLICAROS (
    CHAVEOS INTEGER,
    CHAVEEMPOS INTEGER,
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER,
    CHAVEUSUARIOINICIOU INTEGER,
    CHAVECLIFOR INTEGER,
    ENLATUAL DOUBLE PRECISION,
    ECHAVETABELAPRECO INTEGER)
RETURNS (
    CHAVEFINAL INTEGER)
AS
declare variable CHAVEGENOS integer;
declare variable NRODAV varchar(20);
declare variable PADRAO varchar(20);
declare variable TIPOOS integer;
declare variable CHAVEITEMSERV integer;
declare variable NOVACHAVEITEMSERV integer;
declare variable CHAVEITEMHORA integer;
declare variable CHAVEITEMPROD integer;
declare variable CHAVELOTEPROD integer;
declare variable QTDE numeric(18,6);
declare variable AGRUPADOCOMPOSTO integer;
declare variable CODPRODUTO varchar(6);
declare variable CONVERSAO numeric(18,6);
declare variable PRECOCUSTO numeric(18,6);
declare variable TIPOMOVIMENTACAO integer;
declare variable NOVACHAVEITEMPROD integer;
declare variable CHAVEPRODUTO integer;
declare variable NROORDEM varchar(6);
declare variable VLRUNIT numeric(18,6);
declare variable CHAVEDPTOESTOQUE integer;
declare variable VMOVESTOQUE smallint;
declare variable VDESCACUMULADO numeric(18,6);
BEGIN
    SELECT TIPO FROM ORDEMSERVICO
    WHERE CHAVE=:CHAVEOS
    INTO :TIPOOS;
    CHAVEGENOS = GEN_ID(GEN_ORDEMSERVICO_ID,1);
    NROORDEM= '';
    PADRAO  = '______';
    NROORDEM= CAST(:CHAVEGENOS AS INTEGER);
    WHILE (NOT :NROORDEM LIKE PADRAO) DO NROORDEM = '0' || :NROORDEM;
    SELECT LPAD(NUMERODAV, 13, 0) FROM ATUALIZARNUMERODAV(:CHAVEEMPOS)
    INTO :NRODAV;
    PADRAO  = '_____________';
    WHILE (NOT :NRODAV LIKE PADRAO) DO NRODAV = '0' || :NRODAV;
    INSERT INTO ORDEMSERVICO (CHAVE, ATIVO, CHAVEEMPRESA, ORDEM, DATA, DATAFECHA, TIPO,
        SITUACAO, CHAVECLIFOR, CHAVEEQUIPAMENTO, PROBLEMAABERTURAOS,
        OBS, TOTALPRODUTO, TOTALSERVICO, TOTALOS, NL, FRETE, KMATUAL, CHAVETABELADESCONTOS,
        TOTALIPI, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD, CHAVECFOPSERV, CHAVEDOCDESTINO, DOCDESTINO,
        NROCCF, NRODAV, KMFINAL, CHAVEUSUARIOINICIOU, CHAVEUSUARIOFECHOU, CONTATO, HORAFECHAMENTO, HORAABERTURA,
        NROCOO, CHAVEECFDOCNFISCAL, NROCAIXA, CHAVESITUACAOOS,
        CHAVETIPOATENDIMENTO, AGRUPADO, MARCAMODELO, NUMSERIE, DATAENTREGA, VLRACRESCIMO,
        CHAVERESPENTREGA, HORAENTREGA, CHAVESITENTREGA, CHAVEPLANOCONTA, CHAVECENTROCUSTO,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, TIPOPAGAMENTO, CHAVECONDPGTO, FATURA, DESCPORCPROD, DESCVLRPROD,
        DESCPORCSERVICO, DESCVLRSERVICO, ACRESCPORCPROD, ACRESCVLRPROD, CHAVEUSUARIOAUTORDESCPROD,
        CHAVEUSUARIOAUTORDESCSERV, TIPOSENHADESCPROD, TIPOSENHADESCSERV, ORIGEM, LAUDOTECNICO,
        ACESSORIOS, PATRIMONIO, FORMAPGTO)
    SELECT :CHAVEGENOS, 1, :CHAVEEMPOS, :NROORDEM, (SELECT CURRENT_DATE FROM RDB$DATABASE), NULL, TIPO,
        0, CHAVECLIFOR, CHAVEEQUIPAMENTO, PROBLEMAABERTURAOS,
        OBS, TOTALPRODUTO, TOTALSERVICO, TOTALOS, :ENLATUAL, FRETE, KMATUAL, CHAVETABELADESCONTOS,
        TOTALIPI, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD, CHAVECFOPSERV, CHAVEDOCDESTINO, DOCDESTINO,
        '', :NRODAV, KMFINAL, :CHAVEUSUARIOINICIOU, NULL, CONTATO, NULL, (SELECT CURRENT_TIME FROM RDB$DATABASE),
        '', NULL, '', NULL,
        CHAVETIPOATENDIMENTO, 'N', MARCAMODELO, NUMSERIE, DATAENTREGA, VLRACRESCIMO,
        CHAVERESPENTREGA, HORAENTREGA, NULL, CHAVEPLANOCONTA, CHAVECENTROCUSTO,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, TIPOPAGAMENTO, CHAVECONDPGTO, FATURA, DESCPORCPROD, DESCVLRPROD,
        DESCPORCSERVICO, DESCVLRSERVICO, ACRESCPORCPROD, ACRESCVLRPROD, CHAVEUSUARIOAUTORDESCPROD,
        CHAVEUSUARIOAUTORDESCSERV, TIPOSENHADESCPROD, TIPOSENHADESCSERV, 0, LAUDOTECNICO,
        ACESSORIOS, PATRIMONIO, FORMAPGTO
    FROM ORDEMSERVICO WHERE CHAVE=:CHAVEOS;
    INSERT INTO ORDEMSERVICOOTICA (CHAVE,  ATIVO, CHAVEEMPRESA, CHAVEORDEMSERVICO, NUMRECEITA,
        DATARECEITA, CHAVELENTETP, CHAVELENTEMAT, CHAVEARMACTP, CHAVEARMACMAT, LONGEESFOD,
        LONGEESFOE, LONGECILINDOD, LONGECILINDOE, LONGEEIXOOD, LONGEEIXOOE, PERTOESFOD, PERTOESFOE,
        PERTOCILINDOD, PERTOCILINDOE, PERTOEIXOOD, PERTOEIXOOE, MEDALTURAFACIALOD, MEDALTURAFACIALOE,
        LONGEDNPOD, LONGEDNPOE, PERTODNPOD, PERTODNPOE, MEDARMACDIAGMAIOR, MEDARMACHORIZ, MEDARMACPONTE, MEDARMACVERTICAL)
    SELECT NULL, ATIVO, :CHAVEEMPOS, :CHAVEGENOS, NUMRECEITA,
        DATARECEITA, CHAVELENTETP, CHAVELENTEMAT, CHAVEARMACTP, CHAVEARMACMAT, LONGEESFOD,
        LONGEESFOE, LONGECILINDOD, LONGECILINDOE, LONGEEIXOOD, LONGEEIXOOE, PERTOESFOD, PERTOESFOE,
        PERTOCILINDOD, PERTOCILINDOE, PERTOEIXOOD, PERTOEIXOOE, MEDALTURAFACIALOD, MEDALTURAFACIALOE,
        LONGEDNPOD, LONGEDNPOE, PERTODNPOD, PERTODNPOE, MEDARMACDIAGMAIOR, MEDARMACHORIZ, MEDARMACPONTE, MEDARMACVERTICAL
        FROM ORDEMSERVICOOTICA WHERE CHAVEORDEMSERVICO=:CHAVEOS AND ATIVO=1;
    VDESCACUMULADO = 0;
    FOR SELECT I.CHAVE, I.CHAVELOTEPROD, (I.QTDE*-1), P.AGRUPADOCOMPOSTO,
        P.CODIGO, U.CONVERSAO, I.PRECOCUSTO, CF.TIPOMOVIMENTACAO, I.CHAVEPRODUTO, I.VLRUNIT,
        I.CHAVEDPTOESTOQUE, I.MOVESTOQUE
    FROM ITENSORDEMSERVICOPROD I
    INNER JOIN PRODUTO P ON P.CHAVE=I.CHAVEPRODUTO
    INNER JOIN UNIDADE U ON U.CHAVE=I.CHAVEUNIDADE
    INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE=I.CHAVECFOPOPERFISCAIS
    WHERE I.ATIVO=1 AND I.CHAVEOS=:CHAVEOS
    INTO :CHAVEITEMPROD, :CHAVELOTEPROD, :QTDE, :AGRUPADOCOMPOSTO,
        :CODPRODUTO, :CONVERSAO, :PRECOCUSTO, :TIPOMOVIMENTACAO, :CHAVEPRODUTO, :VLRUNIT,
        :CHAVEDPTOESTOQUE, :VMOVESTOQUE
    DO BEGIN
        NOVACHAVEITEMPROD = GEN_ID(GEN_ITENSORDEMSERVICOPROD_ID,1);
        INSERT INTO ITENSORDEMSERVICOPROD
            (CHAVE, ATIVO, CHAVEEMPRESA, CHAVEOS, CHAVEPRODUTO, CHAVETRIBUTACAO, QTDE,
            VLRUNIT, DESCPORC, DESCVLR, DATA, CHAVEUNIDADE, UN, VLRSUBTOTAL, VLRTOTAL,
            NL, PRODUTO, IPI, VLRIPI, CHAVECFOP, CHAVECFOPOPERFISCAIS,
            DESCRCOMPLEMENT, PRECOCUSTO, CHAVEVENDEDOR, ALIQCOMISFAT, TIPOSENHADESC,
            CHAVEUSUARIOAUTORDESC, VLRUNITTABELA, VLRVENDAMINIMO, CHAVELOTEPROD, CODPRODUTO,
            NUMITEM, ACRESCVLR, CODVENDACF, CHAVEDPTOESTOQUE, VLRACRESCGLOBAL, NRODAV, ICMS, ALIQICMSINTRA,
            MOVESTOQUE, CHAVETABELAPRECO, CHAVEREGRAFISCAL, TIPOPROMOCAO, CHAVESPRODPROMO)
        SELECT :NOVACHAVEITEMPROD, 1, :CHAVEEMPOS, :CHAVEGENOS, I.CHAVEPRODUTO, I.CHAVETRIBUTACAO, I.QTDE,
            I.VLRUNIT, I.DESCPORC, I.DESCVLR, DATA, I.CHAVEUNIDADE, I.UN, I.VLRSUBTOTAL, I.VLRTOTAL,
            :ENLATUAL, I.PRODUTO, I.IPI, I.VLRIPI, I.CHAVECFOP, I.CHAVECFOPOPERFISCAIS,
            I.DESCRCOMPLEMENT, I.PRECOCUSTO, V.CHAVE AS CHAVEVENDEDOR, I.ALIQCOMISFAT, I.TIPOSENHADESC,
            I.CHAVEUSUARIOAUTORDESC, I.VLRUNITTABELA, I.VLRVENDAMINIMO, I.CHAVELOTEPROD, I.CODPRODUTO,
            I.NUMITEM, I.ACRESCVLR, I.CODVENDACF, I.CHAVEDPTOESTOQUE, I.VLRACRESCGLOBAL, :NRODAV, I.ICMS, I.ALIQICMSINTRA,
            I.MOVESTOQUE, I.CHAVETABELAPRECO, I.CHAVEREGRAFISCAL, I.TIPOPROMOCAO, I.CHAVESPRODPROMO
        FROM ITENSORDEMSERVICOPROD I
        LEFT JOIN CLIFOR V ON (V.CHAVE=I.CHAVEVENDEDOR) AND (V.ATIVO=1) AND (V.STATUS=0)
        WHERE I.ATIVO=1 AND I.CHAVE=:CHAVEITEMPROD
        ORDER BY I.CHAVE;
        INSERT INTO PRODUTOVENDAPROMOHIST (ATIVO, CHAVEEMPRESA, CHAVEITEMOS, TIPOPROMOCAO, VALOR)
        SELECT ATIVO, CHAVEEMPRESA, :NOVACHAVEITEMPROD, TIPOPROMOCAO, VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMOS=:CHAVEITEMPROD);
        VDESCACUMULADO = :VDESCACUMULADO + COALESCE((SELECT VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMOS=:CHAVEITEMPROD)),0);
        IF (:TIPOOS <> 2) THEN BEGIN
            IF (:VMOVESTOQUE = 0) THEN BEGIN
                EXECUTE PROCEDURE ESTENTRADASAIDAESTOQUE(:CHAVEPRODUTO, :CHAVELOTEPROD, :QTDE, 0, :AGRUPADOCOMPOSTO, :CHAVEEMPESTOQUE,
                CHAVEEMPCUSTO, :CHAVEUSUARIOINICIOU, :CHAVEGENOS, :ENLATUAL, :NROORDEM, 13, '',
                :CODPRODUTO, :CONVERSAO, (SELECT CURRENT_DATE FROM RDB$DATABASE), :PRECOCUSTO, :NOVACHAVEITEMPROD, :CHAVECLIFOR,
                :TIPOMOVIMENTACAO, 0, :CHAVEDPTOESTOQUE, :VLRUNIT);
            END
        END
    END
    FOR SELECT CHAVE FROM ITENSORDEMSERVICOSERV
    WHERE ATIVO=1 AND CHAVEOS=:CHAVEOS
    INTO :CHAVEITEMSERV
    DO BEGIN
        NOVACHAVEITEMSERV = GEN_ID(GEN_ITENSORDEMSERVICOSERV_ID,1);
        INSERT INTO ITENSORDEMSERVICOSERV
            (CHAVE, ATIVO, CHAVEEMPRESA, CHAVEOS, CHAVEPRODUTO, CODPRODUTO, PRODUTO,
            CHAVEUNIDADE, UN, QTDE, VLRUNIT, DESCPORC, DESCVLR, DATA, VLRSUBTOTAL,
            VLRTOTAL, ISS, NL, CHAVECFOP, CHAVECFOPOPERFISCAIS, DESCRCOMPLEMENT,
            PRECOCUSTO, CHAVEVENDEDOR, ALIQCOMISFAT, TIPOSENHADESC,
            CHAVEUSUARIOAUTORDESC, NUMITEM, ACRESCVLR, VLRUNITTABELA, NRODAV, CHAVETABELAPRECO)
        SELECT :NOVACHAVEITEMSERV, 1, :CHAVEEMPOS, :CHAVEGENOS, I.CHAVEPRODUTO, I.CODPRODUTO, I.PRODUTO,
            I.CHAVEUNIDADE, I.UN, I.QTDE, I.VLRUNIT, I.DESCPORC, I.DESCVLR, DATA, I.VLRSUBTOTAL,
            I.VLRTOTAL, I.ISS, :ENLATUAL, I.CHAVECFOP, I.CHAVECFOPOPERFISCAIS, I.DESCRCOMPLEMENT,
            I.PRECOCUSTO, V.CHAVE AS CHAVEVENDEDOR, I.ALIQCOMISFAT, I.TIPOSENHADESC,
            I.CHAVEUSUARIOAUTORDESC, I.NUMITEM, I.ACRESCVLR, I.VLRUNITTABELA, :NRODAV, I.CHAVETABELAPRECO
        FROM ITENSORDEMSERVICOSERV I
        LEFT JOIN CLIFOR V ON (V.CHAVE=I.CHAVEVENDEDOR) AND (V.ATIVO=1) AND (V.STATUS=0)
        WHERE I.ATIVO=1 AND I.CHAVE=:CHAVEITEMSERV;
        FOR SELECT CHAVE FROM ORDEMSERVICOHORAS
            WHERE ATIVO=1 AND CHAVEITEMOS=:CHAVEITEMSERV
        INTO :CHAVEITEMHORA
        DO BEGIN
             INSERT INTO ORDEMSERVICOHORAS
                 (ATIVO, CHAVEEMPRESA, CHAVEITEMOS, DATAINICIAL, HORAINICIAL,
                 DATAFINAL, HORAFINAL, RESPONSAVEL, OBS, TEMPOTOTAL, CHAVEVEICULO,
                 KMINI, KMFIM, KMROD)
             SELECT 1, :CHAVEEMPOS, :NOVACHAVEITEMSERV, DATAINICIAL, HORAINICIAL,
                 DATAFINAL, HORAFINAL, RESPONSAVEL, OBS, TEMPOTOTAL, CHAVEVEICULO,
                 KMINI, KMFIM, KMROD
             FROM ORDEMSERVICOHORAS WHERE ATIVO=1 AND CHAVE=:CHAVEITEMHORA;
        END
     END
    INSERT INTO ORDEMSERVICOIMG
        (ATIVO, CHAVEEMPRESA, DESCRICAO, IMG, CHAVEOS, NOMEARQUIVO, DATA)
    SELECT 1, :CHAVEEMPOS, DESCRICAO, IMG, :CHAVEGENOS, NOMEARQUIVO, DATA
    FROM ORDEMSERVICOIMG WHERE ATIVO=1 AND CHAVEOS=:CHAVEOS
    ORDER BY CHAVE;
    IF (:VDESCACUMULADO > 0) THEN BEGIN
        UPDATE ORDEMSERVICO SET
            DESCVLRPROD=0,
            DESCPORCPROD=0
        WHERE (CHAVE=:CHAVEGENOS);
    END
    INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
    SELECT C.CHAVEEMPRESA, :CHAVEGENOS, V.CHAVE AS CHAVEVENDEDOR, C.ORIGEM, :ENLATUAL, C.TIPOCOMISSAO,
    C.COMISSAOGERADA, C.COMISPRODUTO, C.COMISPRODEMISSAO, C.COMISPRODBAIXA,
    C.COMISSERVICO, C.COMISSERVEMISSAO, C.COMISSERVBAIXA, C.TIPOALIQUOTA
    FROM COMISSAO C
    INNER JOIN CLIFOR V ON (V.CHAVE=C.CHAVEVENDEDOR) AND (V.ATIVO=1) AND (V.STATUS=0)
    WHERE (C.ATIVO=1) AND (C.ORIGEM=4) AND (C.CHAVEDOC=:CHAVEOS);
    CHAVEFINAL = :CHAVEGENOS;
    SUSPEND;
END^


ALTER PROCEDURE ENTRADAESTOQUE (
    CHAVENF INTEGER,
    CHAVEEMPESTOQUE FLOAT,
    CHAVEEMPCUSTO INTEGER,
    PACHAVEEMP INTEGER,
    CHAVEUSUARIO INTEGER,
    DOCUMENTO VARCHAR(9),
    ATUALIZARPRECOVENDA CHAR(1),
    NFDECOMPRA CHAR(1),
    NAOATUALIZARCADPROD CHAR(1),
    ATUALIZARSOMENTECUSTOMEDIO CHAR(1),
    PRODUTOVENDACHAVEEMP SMALLINT,
    PRODUTOSALTERINDIVIDUAL CHAR(1),
    NFENTRADAINDIVIDUAL CHAR(1))
RETURNS (
    SPRODUTOCOMPPRINC VARCHAR(150))
AS
declare variable CHAVEPROD integer;
declare variable CASADECIMALCUSTO numeric(18,6);
declare variable CONTROLARLOTE char(1);
declare variable VVLRICMSDIFAL numeric(18,6);
declare variable VSOMARICMSDIFCUSTO varchar(1);
declare variable VPORCPVMINIMO numeric(18,4);
declare variable ALIQICMS numeric(7,2);
declare variable CHAVEDPTOESTOQUEITEM integer;
declare variable CSTSUBSTTRIB char(1);
declare variable CASADECIMALESTOQUE integer;
declare variable MOVESTPROPRIA smallint;
declare variable CUSTOPISCOFINS numeric(18,6);
declare variable CUSTOACESSORIA numeric(18,6);
declare variable CODPROD varchar(6);
declare variable CUSTOSAIDA numeric(18,6);
declare variable PRECOESTOQUE numeric(18,6);
declare variable QUANT numeric(18,6);
declare variable ANTSALDO numeric(18,6);
declare variable CUSTOMEDIOFINAL numeric(18,6);
declare variable CUSTOPROD numeric(18,6);
declare variable NLATUAL double precision;
declare variable RICMS char(1);
declare variable RIPI char(1);
declare variable AUMENTO numeric(18,6);
declare variable RDESP char(1);
declare variable RFRETE char(1);
declare variable RSEGURO char(1);
declare variable TOTALPRODUTO numeric(18,6);
declare variable CUSTOSEGURO numeric(18,6);
declare variable CUSTOFRETE numeric(18,6);
declare variable TOTALITENS numeric(18,6);
declare variable VLRICMS numeric(18,6);
declare variable CST varchar(6);
declare variable VLRICMSSUBSTTRIB numeric(18,6);
declare variable RICMSSUBST char(1);
declare variable AUX numeric(18,6);
declare variable AUX2 numeric(18,6);
declare variable FORMULACALCULOPROD integer;
declare variable ALTERAPRODUTODIRETO varchar(2);
declare variable NOVOCUSTOPROD numeric(18,6);
declare variable DATAENTRADA date;
declare variable SUBTRAIRATEIOICMS char(1);
declare variable SUBTRAIRATEIOPISCOFINS char(1);
declare variable CHAVELOTEPROD integer;
declare variable SALDO numeric(18,6);
declare variable AGRUPADOCOMPOSTO integer;
declare variable PERCFATORMARKUP numeric(7,4);
declare variable CHAVEFATORMARKUP integer;
declare variable UPRECOCUSTO numeric(18,6);
declare variable UPRECOVENDA numeric(18,6);
declare variable UPRECOMEDIO numeric(18,6);
declare variable UORIGEM integer;
declare variable ANTPRECOCUSTO numeric(18,6);
declare variable ANTPRECOMEDIO numeric(18,6);
declare variable ANTPRECOVENDA numeric(18,6);
declare variable LUCROMARKUP numeric(7,2);
declare variable CHAVEITEM integer;
declare variable TIPOFATORVENDA integer;
declare variable PERCSOBRECUSTO numeric(7,4);
declare variable MARGEMPORC numeric(18,4);
declare variable MARGEMVLR numeric(18,6);
declare variable XCHAVEEMP integer;
declare variable SALDOCONDICIONAL numeric(18,6);
declare variable COTACAO integer;
declare variable CHAVECOTACAO integer;
declare variable CLASSIFICACAO integer;
declare variable VLRICMSSUBSTTRIBITEM numeric(18,6);
declare variable ORIGEMDEVOLV integer;
declare variable VLRIPI numeric(18,6);
declare variable MOVESTOQUE smallint;
declare variable CHAVEITEMDEVOLV integer;
declare variable CHAVECLIFOR integer;
declare variable TIPOMOVIMENTACAO integer;
declare variable ANTPRECOCUSTOUPDATE numeric(18,6);
declare variable ANTPRECOMEDIOUPDATE numeric(18,6);
declare variable CHAVEREFCUSTO integer;
declare variable MOVESTOQUEITEM smallint;
declare variable VMODOPVMINIMO varchar(10);
declare variable VCASADECIMALESTCFG integer;
declare variable VCHAVETABELAPRECO integer;
declare variable VVLRICMSFCPSTITEM numeric(18,6);
declare variable VVLRICMSDESONERADO numeric(18,6);
declare variable VPRECOCUSTO numeric(18,6);
declare variable VPRECOMEDIO numeric(18,6);
declare variable VCHAVEEMPLOG integer;
BEGIN
    if (:NFENTRADAINDIVIDUAL = 'S') then BEGIN
       SELECT CHAVEEMPRESA FROM NFENTRADA WHERE CHAVE=:CHAVENF
       INTO :VCHAVEEMPLOG;
    END ELSE
        VCHAVEEMPLOG = :CHAVEEMPESTOQUE;
    SELECT C.RATEIAICMS, C.RATEIAIPI, C.RATEIADESPACESSORIA, C.RATEIAFRETE,
        C.RATEIASEGURO, C.RATEIAICMSSUBST, C.FORMULACALCMARGLUCPROD,
        C.ALTERAPRODUTODIRETO, C.SUBTRAIRATEIOICMS, C.SUBTRAIRATEIOPISCOFINS
    FROM CONFIG C
    WHERE C.CHAVEEMPRESA=:VCHAVEEMPLOG
    INTO :RICMS, :RIPI, :RDESP, :RFRETE,
        :RSEGURO, :RICMSSUBST, :FORMULACALCULOPROD, :ALTERAPRODUTODIRETO,
        :SUBTRAIRATEIOICMS, :SUBTRAIRATEIOPISCOFINS;
    SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=404 AND CHAVEEMPRESA=:VCHAVEEMPLOG
    INTO :VSOMARICMSDIFCUSTO;
        SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=184 AND CHAVEEMPRESA=:CHAVEEMPCUSTO
    INTO :VMODOPVMINIMO;
    SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=284 AND CHAVEEMPRESA=:CHAVEEMPESTOQUE
    INTO :CASADECIMALCUSTO;
    SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=198 AND CHAVEEMPRESA=:CHAVEEMPESTOQUE
    INTO :VCASADECIMALESTCFG;
    FOR SELECT I.CHAVE, I.CHAVEPRODUTO, I.CODPRODUTO, COALESCE(I.CHAVELOTEPROD,0),
        case UN.CONVERSAO
         when 0 then I.QTDE
         else case
                when UN.TIPOCONV=0 then cast(I.QTDE * UN.CONVERSAO as numeric(18,6))
                else cast(I.QTDE / UN.CONVERSAO as numeric(18,6))
              end
        end,
        I.VLRUNITCOMDESC, I.NL, NF.TOTALPRODUTO, NF.CHAVECOTACAO, CF.CLASSIFICACAO,
        I.VLRTOTAL, I.VLRICMS, CASE WHEN :VSOMARICMSDIFCUSTO = 'S' THEN COALESCE(I.VLRICMSDIFAL,0) ELSE 0 END, I.VLRIPI, ENTRADA,
        SUBSTRING(I.CST FROM 2 FOR 2), NF.VLRICMSSUBST,
        P.AGRUPADOCOMPOSTO, COALESCE(I.CHAVEFATORMARKUP,0), COALESCE(FM.LUCROLIQUIDOESPERADO,0),
        COALESCE(FM.CUSTOFIXO+FM.CUSTOVARIAVEL+FM.COMISSAOSOBREVENDA+FM.LUCROLIQUIDOESPERADO,0), FM.TIPOFATORVENDA, FM.PERCSOBRECUSTO,
        I.VLRICMSSUBSTTRIB, COF.MOVESTOQUE, I.MOVESTOQUE, I.ORIGEMDEVOLV, COALESCE(I.CHAVEITEMDEVOLV,0),
        COALESCE(I.CUSTODESPACESSORIAS,0),
        COALESCE(I.CUSTOFRETE,0), COALESCE(I.CUSTOSEGURO,0), COALESCE(I.CUSTOPISCOFINS,0),
        NF.CHAVECLIFOR, COF.TIPOMOVIMENTACAO, COALESCE(P.CONTROLARLOTE,'N'),
        CASE WHEN COF.MOVESTOQUEPROPRIA < 0 THEN 0 ELSE COALESCE(COF.MOVESTOQUEPROPRIA,0) END AS MOVESTOQUEPROPRIA, COALESCE(UN.CASADECUNMEDIDA,3),
        T.CSTSUBSTTRIB, I.ICMS, I.CHAVEDPTOESTOQUE, I.VLRICMSFCPST, I.VLRICMSDESONERADO
    FROM ITENSNFENTRADAPROD I
    INNER JOIN NFENTRADA NF ON (NF.CHAVE=I.CHAVENFENTRADA)
    INNER JOIN PRODUTO P ON (P.CHAVE=I.CHAVEPRODUTO)
    INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
    INNER JOIN CFOPOPERFISCAIS COF ON I.CHAVECFOPOPERFISCAIS=COF.CHAVE
    INNER JOIN TRIBUTACAO T ON T.CHAVE = I.CHAVETRIBUTACAO
    LEFT JOIN FATORMARKUP FM ON FM.CHAVE = I.CHAVEFATORMARKUP
    INNER JOIN CFOP CF ON CF.CHAVE = I.CHAVECFOP
    WHERE (NF.CHAVE=:CHAVENF) AND (I.ATIVO=1)
    AND (P.TIPO <> 9) -- LANCAR TODOS EXCETO SERVICO
    ORDER BY I.CHAVE
    INTO :CHAVEITEM, :CHAVEPROD, :CODPROD, :CHAVELOTEPROD, :QUANT,
        :CUSTOPROD, :NLATUAL, :TOTALPRODUTO, :COTACAO, :CLASSIFICACAO,
        :TOTALITENS, :VLRICMS, :VVLRICMSDIFAL, :VLRIPI, :DATAENTRADA,
        :CST, :VLRICMSSUBSTTRIB,
        :AGRUPADOCOMPOSTO,
        :CHAVEFATORMARKUP, :LUCROMARKUP, :PERCFATORMARKUP,
        :TIPOFATORVENDA, :PERCSOBRECUSTO,
        :VLRICMSSUBSTTRIBITEM, :MOVESTOQUE, :MOVESTOQUEITEM, :ORIGEMDEVOLV, :CHAVEITEMDEVOLV,
        :CUSTOACESSORIA, :CUSTOFRETE, :CUSTOSEGURO, :CUSTOPISCOFINS,
        :CHAVECLIFOR, :TIPOMOVIMENTACAO, :CONTROLARLOTE, :MOVESTPROPRIA, :CASADECIMALESTOQUE,
        :CSTSUBSTTRIB, :ALIQICMS, :CHAVEDPTOESTOQUEITEM, :VVLRICMSFCPSTITEM, :VVLRICMSDESONERADO
    DO BEGIN
        NOVOCUSTOPROD = 0;
        CUSTOMEDIOFINAL = 0;
        IF (:CASADECIMALESTOQUE > :VCASADECIMALESTCFG) THEN
           CASADECIMALESTOQUE = :VCASADECIMALESTCFG;
        QUANT = CASE CASADECIMALESTOQUE
        WHEN 4 THEN CAST(QUANT AS NUMERIC(14,4))
        WHEN 3 THEN CAST(QUANT AS NUMERIC(14,3))
        WHEN 2 THEN CAST(QUANT AS NUMERIC(14,2))
        WHEN 1 THEN CAST(QUANT AS NUMERIC(14,1))
        WHEN 0 THEN CAST(QUANT AS NUMERIC(14,0)) END;
        /* ESTOQUE */
        SELECT PE.SALDO, PE.SALDOCONDICIONAL, PC.PRECOCUSTO, COALESCE(PC.PRECOMEDIO,0)
        FROM PRODUTO P
        INNER JOIN PRODUTOESTOQUE PE ON P.CHAVE = PE.CHAVEPRODUTO
        INNER JOIN PRODUTOCUSTO PC ON P.CHAVE=PC.CHAVEPRODUTO AND PC.CHAVEEMPRESA=:CHAVEEMPCUSTO
        WHERE (P.CHAVE=:CHAVEPROD) AND (PE.CHAVEEMPRESA=:CHAVEEMPESTOQUE)
        INTO :SALDO, :SALDOCONDICIONAL, :ANTPRECOCUSTO, :ANTPRECOMEDIO;
        IF ((:CUSTOPROD = 0) OR (:CLASSIFICACAO = '5')) THEN
            CUSTOPROD = :ANTPRECOCUSTO;
        SELECT SMARGEMVLR, SMARGEMPORC, SAUMENTO, SANTSALDO
        FROM ENTRADAESTOQUECALCULOS(:QUANT, :CLASSIFICACAO, 0, :ANTPRECOCUSTO, :FORMULACALCULOPROD, :RICMS, :VSOMARICMSDIFCUSTO, :CST, :VLRICMS, :VVLRICMSDIFAL, :CSTSUBSTTRIB,
            :RICMSSUBST, :ALIQICMS, :VLRICMSSUBSTTRIBITEM, :VLRICMSSUBSTTRIB, :TOTALPRODUTO, :TOTALITENS, :RIPI, :VLRIPI, :RFRETE, :RSEGURO, :RDESP, :CUSTOFRETE,
            :CUSTOSEGURO, :CUSTOACESSORIA, :SUBTRAIRATEIOICMS, :SUBTRAIRATEIOPISCOFINS, :CUSTOPISCOFINS, :VVLRICMSFCPSTITEM, :VVLRICMSDESONERADO, :SALDO)
        INTO :MARGEMVLR, :MARGEMPORC, :AUMENTO, :ANTSALDO;
        IF (:MOVESTOQUE = 0) THEN BEGIN
            IF (:CLASSIFICACAO = 3)THEN BEGIN
                NOVOCUSTOPROD = :ANTPRECOMEDIO;
                CUSTOMEDIOFINAL = :ANTPRECOMEDIO;
            END ELSE BEGIN
                IF (:CLASSIFICACAO = 5 ) THEN BEGIN
                    NOVOCUSTOPROD = :CUSTOPROD;
                    IF (:ANTSALDO > 0) THEN BEGIN
                        CUSTOMEDIOFINAL = :ANTSALDO * :ANTPRECOMEDIO + (:QUANT * (0.01 + :AUMENTO));
                        CUSTOMEDIOFINAL = :CUSTOMEDIOFINAL / (:ANTSALDO+:QUANT);
                    END ELSE
                        CUSTOMEDIOFINAL = 0.01+:AUMENTO;
                    IF ((:CUSTOMEDIOFINAL <= 0) OR (:CUSTOMEDIOFINAL IS NULL)) THEN BEGIN
                        CUSTOMEDIOFINAL = 0.01;
                        NOVOCUSTOPROD = 0.01;
                    END
                END ELSE BEGIN
                    NOVOCUSTOPROD = :CUSTOPROD + :AUMENTO;
                    IF (:ANTSALDO > 0) THEN BEGIN
                        AUX = CAST(:ANTSALDO AS DOUBLE PRECISION) * CAST(:ANTPRECOMEDIO AS DOUBLE PRECISION);
                        AUX2 = :QUANT * :NOVOCUSTOPROD;
                        CUSTOMEDIOFINAL = :AUX + :AUX2;
                        CUSTOMEDIOFINAL = :CUSTOMEDIOFINAL / (:ANTSALDO+:QUANT);
                    END
                    IF ((:CUSTOMEDIOFINAL <= 0) OR (:CUSTOMEDIOFINAL IS NULL)) THEN
                        CUSTOMEDIOFINAL = :NOVOCUSTOPROD;
                END
            END
            PRECOESTOQUE = :NOVOCUSTOPROD;
            IF ((:CLASSIFICACAO=3) AND (:CHAVEITEMDEVOLV>0)) THEN BEGIN
               IF (:ORIGEMDEVOLV=0) THEN BEGIN
                  SELECT PRECOCUSTO FROM
                  ITENSNFSAIDA
                  WHERE CHAVE=:CHAVEITEMDEVOLV
                  INTO :CUSTOSAIDA;
               END ELSE BEGIN
                  SELECT PRECOCUSTO FROM
                  ITENSCUPOM
                  WHERE CHAVE=:CHAVEITEMDEVOLV
                  INTO :CUSTOSAIDA;
               END
               PRECOESTOQUE =:CUSTOSAIDA;
            END
            EXECUTE PROCEDURE ENTRADAESTOQUEINSERTEST(:CASADECIMALCUSTO, :PRECOESTOQUE, :CHAVELOTEPROD, :CONTROLARLOTE, :CHAVEITEM, :CHAVEPROD,
                :QUANT, :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO, :CHAVEUSUARIO, :CHAVENF, :NLATUAL, :DOCUMENTO, :CODPROD, :DATAENTRADA, :CHAVECLIFOR,
                :TIPOMOVIMENTACAO, :MOVESTPROPRIA, :CHAVEDPTOESTOQUEITEM, :AGRUPADOCOMPOSTO);
        END ELSE BEGIN
           NOVOCUSTOPROD = :CUSTOPROD + :AUMENTO;
           CUSTOMEDIOFINAL = :ANTPRECOMEDIO;
        END
        SELECT
        PC.PRECOCUSTO,
        COALESCE(PC.PRECOMEDIO,0)
        FROM PRODUTOCUSTO PC
        WHERE (PC.CHAVEPRODUTO=:CHAVEPROD)
        AND (PC.CHAVEEMPRESA=:CHAVEEMPCUSTO)
        INTO :VPRECOCUSTO, :VPRECOMEDIO;
        /* PRODUTOS ALTERADOS */
        FOR SELECT PE.SALDO, PE.SALDOCONDICIONAL, :VPRECOCUSTO,
            :VPRECOMEDIO, PV.PRECOVENDA,
            CASE WHEN :VMODOPVMINIMO = 0 THEN
                CASE WHEN PV.PRECOVENDAMINIMO > 0 THEN CAST(PV.PRECOVENDAMINIMO * 100 / :VPRECOCUSTO AS NUMERIC(18,4)) ELSE 0 END
            ELSE
                CASE WHEN PV.PRECOVENDAMINIMO > 0 THEN CAST(PV.PRECOVENDAMINIMO * 100 / PV.PRECOVENDA AS NUMERIC(18,4)) ELSE 0 END
            END AS PORCMINIMO, PV.CHAVETABELAPRECO
        FROM PRODUTO P
        INNER JOIN PRODUTOESTOQUE PE ON P.CHAVE = PE.CHAVEPRODUTO
        INNER JOIN PRODUTOVENDA PV ON (P.CHAVE=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.ATIVO=1)
        WHERE (P.CHAVE=:CHAVEPROD) AND (PE.CHAVEEMPRESA=:CHAVEEMPESTOQUE)
        INTO :SALDO, :SALDOCONDICIONAL, :ANTPRECOCUSTO,
            :ANTPRECOMEDIO, :ANTPRECOVENDA,
            :VPORCPVMINIMO, :VCHAVETABELAPRECO
        DO BEGIN
            AUX = 0; MARGEMVLR = 0; MARGEMPORC = 0;
            SELECT SMARGEMVLR, SMARGEMPORC, SAUMENTO, SANTSALDO
            FROM ENTRADAESTOQUECALCULOS(:QUANT, :CLASSIFICACAO, :ANTPRECOVENDA, :ANTPRECOCUSTO, :FORMULACALCULOPROD, :RICMS, :VSOMARICMSDIFCUSTO, :CST, :VLRICMS, :VVLRICMSDIFAL, :CSTSUBSTTRIB,
                :RICMSSUBST, :ALIQICMS, :VLRICMSSUBSTTRIBITEM, :VLRICMSSUBSTTRIB, :TOTALPRODUTO, :TOTALITENS, :RIPI, :VLRIPI, :RFRETE, :RSEGURO, :RDESP, :CUSTOFRETE,
                :CUSTOSEGURO, :CUSTOACESSORIA, :SUBTRAIRATEIOICMS, :SUBTRAIRATEIOPISCOFINS, :CUSTOPISCOFINS, :VVLRICMSFCPSTITEM, :VVLRICMSDESONERADO, :SALDO)
            INTO :MARGEMVLR, :MARGEMPORC, :AUMENTO, :ANTSALDO;
    
            IF (:SALDOCONDICIONAL < 0) THEN
                ANTSALDO=:ANTSALDO + (:SALDOCONDICIONAL * (-1));
            IF (:MOVESTOQUE <> :MOVESTOQUEITEM) THEN BEGIN
                UPDATE ITENSNFENTRADAPROD SET
                MOVESTOQUE=:MOVESTOQUE
                WHERE CHAVE=:CHAVEITEM;
            END
    
            IF (:NFDECOMPRA = 'S') THEN BEGIN
                UPRECOMEDIO = :CUSTOMEDIOFINAL;
                IF ((:NAOATUALIZARCADPROD = 'N') AND (:ATUALIZARSOMENTECUSTOMEDIO = 'N')) THEN BEGIN
                    UPRECOCUSTO = :NOVOCUSTOPROD;
                    IF ((:ATUALIZARPRECOVENDA = 'N') OR (:CLASSIFICACAO=5)) THEN BEGIN  -- BONIFICACAO NAO ALTERA VENDA
                        UORIGEM     = 1;
                        UPRECOVENDA = :ANTPRECOVENDA;
                    END ELSE BEGIN
                        IF (:CHAVEFATORMARKUP > 0) THEN BEGIN
                            IF (:TIPOFATORVENDA = 0) THEN BEGIN
                                AUX = 0;
                                AUX = (:PERCFATORMARKUP / 100);
                                AUX = 1 - :AUX;
                                UPRECOVENDA = :UPRECOCUSTO / :AUX;
                            END ELSE BEGIN
                                LUCROMARKUP = 0;
                                AUX         =  1 + :PERCSOBRECUSTO / 100;
                                UPRECOVENDA = :UPRECOCUSTO * AUX;
                            END
                            UORIGEM     = 2;
                        END ELSE BEGIN
                            UORIGEM     = 1;
                            IF (:FORMULACALCULOPROD = 0) THEN BEGIN
                                MARGEMVLR  = :UPRECOCUSTO * :MARGEMPORC / 100;
                                UPRECOVENDA = :UPRECOCUSTO + :MARGEMVLR;
                            END ELSE BEGIN
                                AUX = 1- (:MARGEMPORC / 100);
                                UPRECOVENDA = :UPRECOCUSTO / :AUX;
                            END
                        END
                    END
                    IF (:ALTERAPRODUTODIRETO = 'S') THEN BEGIN
                        IF (:CLASSIFICACAO IN (0,2)) THEN BEGIN
                            UPDATE PRODUTO SET
                                CHAVENFENTRADA = :CHAVENF,
                                CHAVEFATORMARKUP = :CHAVEFATORMARKUP,
                                CHAVEUSUARIOALT = :CHAVEUSUARIO
                            WHERE (CHAVE=:CHAVEPROD);
                            if ((:CLASSIFICACAO = 0) and (:CST IN ('10', '30', '70'))) then begin
                               UPDATE PRODUTOCUSTO SET
                               ALIQICMSPROPRIOCOMPRA = :ALIQICMS,
                               CHAVEUSUARIOALT=:CHAVEUSUARIO
                               WHERE CHAVEPRODUTO=:CHAVEPROD AND CHAVEEMPRESA=:CHAVEEMPCUSTO;
                            end
                            UPDATE PRODUTOCUSTO SET
                                PRECOCUSTO = :UPRECOCUSTO,
                                PRECOCUSTONFLANC = CASE WHEN :CLASSIFICACAO='5' THEN PRECOCUSTONFLANC ELSE :CUSTOPROD END,
                                PRECOMEDIO = :UPRECOMEDIO,
                                CHAVEUSUARIOALT=:CHAVEUSUARIO
                            WHERE (CHAVEPRODUTO=:CHAVEPROD) AND (CHAVEEMPRESA=:CHAVEEMPCUSTO);
                            UPDATE PRODUTOVENDA SET
                                PRECOVENDA = :UPRECOVENDA,
                                PRECOVENDAMINIMO =
                                CASE WHEN :VPORCPVMINIMO > 0 THEN
                                    CASE WHEN :VMODOPVMINIMO = 0 THEN
                                        (:UPRECOCUSTO*:VPORCPVMINIMO)/100
                                    ELSE
                                        (:UPRECOVENDA*:VPORCPVMINIMO)/100
                                    END
                                ELSE
                                    PRECOVENDAMINIMO
                                END,
                                CHAVEUSUARIOALT=:CHAVEUSUARIO
                            WHERE (CHAVEPRODUTO=:CHAVEPROD) AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO);
                        END ELSE BEGIN
                            IF (CLASSIFICACAO=5) THEN BEGIN
                                UPDATE PRODUTOCUSTO SET
                                    PRECOCUSTONFLANC = CASE WHEN :CLASSIFICACAO='5' THEN PRECOCUSTONFLANC ELSE :CUSTOPROD END,
                                    PRECOMEDIO = :uprecomedio, 
                                    CHAVEUSUARIOALT=:CHAVEUSUARIO
                                WHERE (CHAVEPRODUTO=:CHAVEPROD) AND (CHAVEEMPRESA=:CHAVEEMPCUSTO);
                            END
                            UPDATE PRODUTO SET
                                CHAVEFATORMARKUP = :CHAVEFATORMARKUP,
                                CHAVEUSUARIOALT  = :CHAVEUSUARIO
                             WHERE (CHAVE=:CHAVEPROD);
                        END
                    END ELSE BEGIN
                        IF (PRODUTOSALTERINDIVIDUAL = 'N') THEN BEGIN
                            IF (:CLASSIFICACAO IN (0,2,5)) THEN BEGIN
                                EXECUTE PROCEDURE ENTRADAESTOQUEALTCUSTOVENDAPROD(:CHAVENF, :CHAVEFATORMARKUP, :CHAVEUSUARIO, :CHAVEPROD, :UPRECOCUSTO, :UPRECOMEDIO,
                                    :CLASSIFICACAO, :CUSTOPROD, :CHAVEEMPCUSTO, :PRODUTOVENDACHAVEEMP, :VPORCPVMINIMO, :VMODOPVMINIMO, 'S', :VCHAVETABELAPRECO);
                                if ((:CLASSIFICACAO = 0) and (:CST = '10')) then begin
                                   UPDATE PRODUTOCUSTO SET
                                   ALIQICMSPROPRIOCOMPRA = :ALIQICMS,
                                   CHAVEUSUARIOALT=:CHAVEUSUARIO
                                   WHERE CHAVEPRODUTO=:CHAVEPROD AND CHAVEEMPRESA=:CHAVEEMPCUSTO;
                                end
                                EXECUTE PROCEDURE ENTRADAESTOQUEINSERTPRODALT(:CHAVEPROD, :COTACAO, :PACHAVEEMP, :CHAVENF, :CHAVECOTACAO, :NLATUAL, :UPRECOCUSTO,
                                    :CLASSIFICACAO, :UORIGEM, :CUSTOPROD, :ANTPRECOCUSTO, :UPRECOMEDIO, :ANTPRECOMEDIO, :UPRECOVENDA, :ANTPRECOVENDA, :LUCROMARKUP,
                                    :CHAVEITEM, :TIPOFATORVENDA, :PERCFATORMARKUP, :PERCSOBRECUSTO, :VPORCPVMINIMO, :VMODOPVMINIMO, :VCHAVETABELAPRECO);
                            END ELSE BEGIN
                                UPDATE PRODUTO SET
                                    CHAVEFATORMARKUP = :CHAVEFATORMARKUP,
                                    CHAVEUSUARIOALT  = :CHAVEUSUARIO
                                 WHERE (CHAVE=:CHAVEPROD);
                             END
                        END ELSE BEGIN
                            IF (:CLASSIFICACAO IN (0,2,5)) THEN BEGIN
                                EXECUTE PROCEDURE ENTRADAESTOQUEALTCUSTOVENDAPROD(:CHAVENF, :CHAVEFATORMARKUP, :CHAVEUSUARIO, :CHAVEPROD, :UPRECOCUSTO, :UPRECOMEDIO,
                                    :CLASSIFICACAO, :CUSTOPROD, :CHAVEEMPCUSTO, :PRODUTOVENDACHAVEEMP, :VPORCPVMINIMO, :VMODOPVMINIMO, 'S', :VCHAVETABELAPRECO);
                                IF (NFENTRADAINDIVIDUAL = 'S') THEN BEGIN
                                    EXECUTE PROCEDURE ENTRADAESTOQUEINSERTPRODALT(:CHAVEPROD, :COTACAO, :PACHAVEEMP, :CHAVENF, :CHAVECOTACAO, :NLATUAL, :UPRECOCUSTO,
                                        :CLASSIFICACAO, :UORIGEM, :CUSTOPROD, :ANTPRECOCUSTO, :UPRECOMEDIO, :ANTPRECOMEDIO, :UPRECOVENDA, :ANTPRECOVENDA, :LUCROMARKUP,
                                        :CHAVEITEM, :TIPOFATORVENDA, :PERCFATORMARKUP, :PERCSOBRECUSTO, :VPORCPVMINIMO, :VMODOPVMINIMO, :VCHAVETABELAPRECO);
                                END ELSE BEGIN
                                    FOR SELECT DISTINCT CP.CHAVEEMPRESAREF FROM CONFIGCOMPART CP
                                    INNER JOIN EMPRESA E ON CP.CHAVEEMPRESA=E.CHAVE AND E.ATIVO=1
                                    WHERE CP.ATIVO=1 AND CP.TABELA='PRODUTOSALTERADOS'
                                    INTO :XCHAVEEMP
                                    DO BEGIN
    
                                        SELECT CHAVEEMPRESAREF FROM CONFIGCOMPART
                                        WHERE ATIVO=1 AND CHAVEEMPRESA=:XCHAVEEMP AND TABELA='PRODUTOCUSTO'
                                        INTO :CHAVEREFCUSTO;
    
                                        IF (:CHAVEEMPCUSTO=:CHAVEREFCUSTO) THEN BEGIN
                                            ANTPRECOCUSTOUPDATE = :ANTPRECOCUSTO;
                                            ANTPRECOMEDIOUPDATE = :ANTPRECOMEDIO;
                                        END ELSE BEGIN
                                            SELECT PRECOCUSTO, PRECOMEDIO FROM PRODUTOCUSTO
                                            WHERE ATIVO=1 AND CHAVEPRODUTO=:CHAVEPROD
                                            AND CHAVEEMPRESA=(SELECT CHAVEEMPRESAREF FROM CONFIGCOMPART
                                            WHERE ATIVO=1 AND CHAVEEMPRESA=:XCHAVEEMP AND TABELA='PRODUTOCUSTO')
                                            INTO :ANTPRECOCUSTOUPDATE, :ANTPRECOMEDIOUPDATE;
                                        END
    
                                        SELECT PRECOVENDA FROM PRODUTOVENDA
                                        WHERE ATIVO=1 AND CHAVEPRODUTO=:CHAVEPROD
                                        AND CHAVEEMPRESA=(SELECT CHAVEEMPRESAREF FROM CONFIGCOMPART
                                        WHERE ATIVO=1 AND CHAVEEMPRESA=:XCHAVEEMP AND TABELA='PRODUTOVENDA')
                                        AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO)
                                        INTO :ANTPRECOVENDA;
    
                                        IF (:COTACAO IS NULL) THEN BEGIN
                                            EXECUTE PROCEDURE INSERIRREGPRODALTERADOS(:XCHAVEEMP, :CHAVEPROD, :UORIGEM,
                                                :CHAVENF, :NLATUAL, 'NOW',
                                                CASE WHEN :CLASSIFICACAO='5' THEN :CUSTOPROD ELSE :UPRECOCUSTO END,
                                                :ANTPRECOCUSTOUPDATE, :UPRECOMEDIO, :ANTPRECOMEDIOUPDATE,
                                                :UPRECOVENDA, :ANTPRECOVENDA, :LUCROMARKUP, :CHAVEITEM, CASE WHEN :TIPOFATORVENDA = 0 THEN :PERCFATORMARKUP ELSE :PERCSOBRECUSTO END,
                                                CASE WHEN :VPORCPVMINIMO > 0 THEN
                                                    CASE WHEN :VMODOPVMINIMO = 0 THEN
                                                        (:UPRECOCUSTO*:VPORCPVMINIMO)/100
                                                    ELSE
                                                        (:UPRECOVENDA*:VPORCPVMINIMO)/100
                                                    END
                                                ELSE 0 END, :VCHAVETABELAPRECO);
    
                                        END ELSE BEGIN
                                            CHAVECOTACAO = NULL;
                                            SELECT CHAVE FROM PRODUTOSALTERADOS
                                            WHERE ATIVO=1 AND CHAVEPRODUTO = :CHAVEPROD AND NL = :NLATUAL AND ORIGEM = 3
                                            INTO :CHAVECOTACAO;
                                            IF (:CHAVECOTACAO IS NOT NULL) THEN BEGIN
                                                UPDATE PRODUTOSALTERADOS SET
                                                    ORIGEM = :UORIGEM, CHAVEDOC = :CHAVENF,
                                                    PRECOCUSTO = :UPRECOCUSTO,
                                                    PRECOCUSTOANT = :ANTPRECOCUSTOUPDATE, PRECOCUSTOMEDIO = :UPRECOMEDIO,
                                                    PRECOCUSTOMEDIOANT = :ANTPRECOMEDIOUPDATE, CHAVEITEMDOC = :CHAVEITEM
                                                WHERE (CHAVEPRODUTO=:CHAVEPROD) AND (CHAVEEMPRESA=:XCHAVEEMP)
                                                AND (ORIGEM = 3) AND (NL = :NLATUAL);
                                             END ELSE BEGIN
                                                EXECUTE PROCEDURE INSERIRREGPRODALTERADOS(:XCHAVEEMP, :CHAVEPROD, :UORIGEM,
                                                    :CHAVENF, :NLATUAL, 'NOW',
                                                    CASE WHEN :CLASSIFICACAO='5' THEN :CUSTOPROD ELSE :UPRECOCUSTO END,
                                                    :ANTPRECOCUSTOUPDATE,:UPRECOMEDIO, :ANTPRECOMEDIOUPDATE,
                                                    :UPRECOVENDA, :ANTPRECOVENDA, :LUCROMARKUP, :CHAVEITEM, CASE WHEN :TIPOFATORVENDA = 0 THEN :PERCFATORMARKUP ELSE :PERCSOBRECUSTO END,
                                                    CASE WHEN :VPORCPVMINIMO > 0 THEN
                                                        CASE WHEN :VMODOPVMINIMO = 0 THEN
                                                            (:UPRECOCUSTO*:VPORCPVMINIMO)/100
                                                        ELSE
                                                            (:UPRECOVENDA*:VPORCPVMINIMO)/100
                                                        END
                                                    ELSE 0 END, :VCHAVETABELAPRECO);
                                             END
                                        END
                                    END
                                END
                            END ELSE BEGIN
                                UPDATE PRODUTO SET
                                    CHAVEFATORMARKUP = :CHAVEFATORMARKUP,
                                    CHAVEUSUARIOALT  = :CHAVEUSUARIO
                                 WHERE (CHAVE=:CHAVEPROD);
                            END
                        END
                    END
                END ELSE BEGIN
                    IF (:ATUALIZARSOMENTECUSTOMEDIO = 'N') THEN
                        UPRECOMEDIO = :ANTPRECOMEDIO;
                    IF (:CLASSIFICACAO IN (0,2,5)) THEN BEGIN
                        UPDATE PRODUTO SET
                            CHAVENFENTRADA   = :CHAVENF,
                            CHAVEFATORMARKUP = :CHAVEFATORMARKUP,
                            CHAVEUSUARIOALT  = :CHAVEUSUARIO
                         WHERE (CHAVE=:CHAVEPROD);
                        if ((:CLASSIFICACAO = 0) and (:CST = '10')) then begin
                           UPDATE PRODUTOCUSTO SET
                           ALIQICMSPROPRIOCOMPRA = :ALIQICMS,
                           CHAVEUSUARIOALT=:CHAVEUSUARIO
                           WHERE CHAVEPRODUTO=:CHAVEPROD AND CHAVEEMPRESA=:CHAVEEMPCUSTO;
                        end
                        UPDATE PRODUTOCUSTO SET
                            PRECOMEDIO= :UPRECOMEDIO,
                            PRECOCUSTONFLANC = CASE WHEN :CLASSIFICACAO='5' THEN PRECOCUSTONFLANC ELSE :CUSTOPROD END,
                            CHAVEUSUARIOALT=:CHAVEUSUARIO
                        WHERE (CHAVEPRODUTO=:CHAVEPROD) AND (CHAVEEMPRESA=:CHAVEEMPCUSTO);
                    END ELSE BEGIN
                        UPDATE PRODUTO SET
                            CHAVEFATORMARKUP = :CHAVEFATORMARKUP,
                            CHAVEUSUARIOALT  = :CHAVEUSUARIO
                         WHERE (CHAVE=:CHAVEPROD);
                    END
                END
            END
            UPDATE ITENSNFENTRADAPROD SET
                PRECOCUSTO = CASE WHEN :CLASSIFICACAO IN (0,2)
                        THEN :NOVOCUSTOPROD WHEN :CLASSIFICACAO = 5 THEN
                        CASE WHEN :AUMENTO > 0 THEN :AUMENTO ELSE 0.01 END
                        ELSE :ANTPRECOMEDIO END,
                       PRECOVENDA = :UPRECOVENDA
            WHERE CHAVE =:CHAVEITEM;
    
            SPRODUTOCOMPPRINC = 'N';
            IF (:AGRUPADOCOMPOSTO = 2) THEN BEGIN
                SPRODUTOCOMPPRINC = 'S';
                EXECUTE PROCEDURE ATUALIZARCUSTOCOMPOSTOPRINC(0, :CHAVEPROD, :CHAVEUSUARIO);
            END
        END
    END
    SUSPEND;
    /*
        CHAMADAS:
            FRMNFENTRADA : USADA PARA DAR ENTRADA DO ESTOQUE PELA NOTA DE ENTRADA
            FRMNFE : USADA NA PARA DAR ENTRADA DO ESTOQUE QUANDO E NF EMISSAO PROPRIA ELETRONICA
    */
END^


ALTER PROCEDURE ENTRADAESTOQUEALTCUSTOVENDAPROD (
    ECHAVENF INTEGER,
    ECHAVEFATORMARKUP INTEGER,
    ECHAVEUSUARIO INTEGER,
    ECHAVEPROD INTEGER,
    EPRECOCUSTO NUMERIC(18,6),
    EPRECOMEDIO NUMERIC(18,6),
    ECLASSIFICACAO INTEGER,
    ECUSTOPROD NUMERIC(18,6),
    ECHAVEEMPCUSTO INTEGER,
    ECHAVEEMPVENDA INTEGER,
    EPORCPVMINIMO NUMERIC(18,4),
    EMODOPVMINIMO VARCHAR(10),
    EVALIDARPERCMIN CHAR(1),
    ECHAVETABPRECO INTEGER)
AS
BEGIN
    UPDATE PRODUTO SET
        CHAVENFENTRADA   = :ECHAVENF,
        CHAVEFATORMARKUP = :ECHAVEFATORMARKUP,
        CHAVEUSUARIOALT  = :ECHAVEUSUARIO
    WHERE (CHAVE=:ECHAVEPROD);
    IF (:ECLASSIFICACAO IN (0,2)) THEN BEGIN
        UPDATE PRODUTOCUSTO SET
            PRECOCUSTO = :EPRECOCUSTO,
            PRECOMEDIO = :EPRECOMEDIO,
            PRECOCUSTONFLANC = CASE WHEN :ECLASSIFICACAO='5' THEN PRECOCUSTONFLANC ELSE :ECUSTOPROD END,
            CHAVEUSUARIOALT=:ECHAVEUSUARIO
        WHERE (CHAVEPRODUTO=:ECHAVEPROD) AND (CHAVEEMPRESA=:ECHAVEEMPCUSTO);
        IF (EVALIDARPERCMIN = 'S') THEN BEGIN
            IF ((:EMODOPVMINIMO=0) AND (:EPORCPVMINIMO>0)) THEN BEGIN
                UPDATE PRODUTOVENDA SET
                    PRECOVENDAMINIMO = (:EPRECOCUSTO*:EPORCPVMINIMO)/100,
                    CHAVEUSUARIOALT=:ECHAVEUSUARIO
                WHERE (CHAVEPRODUTO=:ECHAVEPROD) AND (CHAVEEMPRESA=:ECHAVEEMPVENDA) AND (CHAVETABELAPRECO=:ECHAVETABPRECO);
            END
        END
    END ELSE BEGIN
        UPDATE PRODUTOCUSTO SET
            PRECOCUSTONFLANC = :ECUSTOPROD,
            PRECOMEDIO = :EPRECOMEDIO,
            CHAVEUSUARIOALT=:ECHAVEUSUARIO
        WHERE (CHAVEPRODUTO=:ECHAVEPROD) AND (CHAVEEMPRESA=:ECHAVEEMPCUSTO);
    END
END^


ALTER PROCEDURE ENTRADAESTOQUECALCULOS (
    EQUANT NUMERIC(18,6),
    ECLASSIFICACAO INTEGER,
    EANTPRECOVENDA NUMERIC(18,6),
    EANTPRECOCUSTO NUMERIC(18,6),
    EFORMULACALCULOPROD INTEGER,
    ERICMS CHAR(1),
    ERICMSDIFAL CHAR(1),
    ECST VARCHAR(6),
    EVLRICMS NUMERIC(18,6),
    EVLRICMSDIFAL NUMERIC(18,6),
    ECSTSUBSTTRIB CHAR(1),
    ERICMSSUBST CHAR(1),
    EALIQICMS NUMERIC(7,2),
    EVLRICMSSUBSTTRIBITEM NUMERIC(18,6),
    EVLRICMSSUBSTTRIB NUMERIC(18,6),
    ETOTALPRODUTO NUMERIC(18,6),
    ETOTALITENS NUMERIC(18,6),
    ERIPI CHAR(1),
    EVLRIPI NUMERIC(18,6),
    ERFRETE CHAR(1),
    ERSEGURO CHAR(1),
    ERDESP CHAR(1),
    ECUSTOFRETE NUMERIC(18,6),
    ECUSTOSEGURO NUMERIC(18,6),
    ECUSTOACESSORIA NUMERIC(18,6),
    ESUBTRAIRATEIOICMS CHAR(1),
    ESUBTRAIRATEIOPISCOFINS CHAR(1),
    ECUSTOPISCOFINS NUMERIC(18,6),
    EVVLRICMSFCPSTITEM NUMERIC(18,6),
    EVVLRICMSDESONERADO NUMERIC(18,6),
    ESALDO NUMERIC(18,6))
RETURNS (
    SMARGEMVLR NUMERIC(18,6),
    SMARGEMPORC NUMERIC(18,4),
    SAUMENTO NUMERIC(18,6),
    SANTSALDO NUMERIC(18,6))
AS
declare variable VAUX numeric(18,6);
declare variable VAUX2 numeric(18,6);
BEGIN
  SAUMENTO=0;
    SANTSALDO   = CAST(:ESALDO AS DOUBLE PRECISION);
    SMARGEMVLR  = :EANTPRECOVENDA - :EANTPRECOCUSTO;
    IF (:EFORMULACALCULOPROD = 0) THEN BEGIN
        VAUX = CAST(:SMARGEMVLR / :EANTPRECOCUSTO AS NUMERIC(18,2));
        SMARGEMPORC = :VAUX * 100;
    END ELSE BEGIN
        IF (:EANTPRECOVENDA <> 0) THEN BEGIN
            VAUX = :EANTPRECOCUSTO / :EANTPRECOVENDA;
            VAUX = :VAUX * 100;
            SMARGEMPORC = 100 - :VAUX;
        END
    END
    IF (NOT :ECLASSIFICACAO IN (4,6)) THEN BEGIN
        SAUMENTO=0;
        IF ((:ERICMS='S') AND (:ECST NOT IN ('10','30','60','70'))) THEN BEGIN
            VAUX= 0;
            VAUX= :EVLRICMS/:EQUANT;
            SAUMENTO=:VAUX;
        END
        IF (:ERICMSDIFAL='S') THEN BEGIN
            VAUX= 0;
            VAUX= :EVLRICMSDIFAL/:EQUANT;
            SAUMENTO = :SAUMENTO + :VAUX;
        END
        IF ((:ERICMSSUBST='S') AND ((:ECST IN ('10','30','70')) OR ((:ECST = '90') AND (:ECSTSUBSTTRIB='S') AND (:EALIQICMS>0)))) THEN BEGIN
            IF (:EVLRICMSSUBSTTRIBITEM = 0) THEN BEGIN
                VAUX = 0;
                VAUX2= 0;
                VAUX = (:EVLRICMSSUBSTTRIB/100);
                VAUX2= (:ETOTALPRODUTO/100);
                VAUX2= (:ETOTALITENS/:VAUX2);
                VAUX = (:VAUX*:VAUX2);
                VAUX = :VAUX/:EQUANT;
                SAUMENTO= :SAUMENTO + :VAUX;
            END ELSE BEGIN
                VAUX = :EVLRICMSSUBSTTRIBITEM / :EQUANT;
                SAUMENTO = :SAUMENTO + :VAUX;
            END
            IF (EVVLRICMSFCPSTITEM>0) THEN BEGIN
                VAUX= 0;
                VAUX= (:EVVLRICMSFCPSTITEM);
                SAUMENTO= :SAUMENTO + (:VAUX/:EQUANT);
            END
        END
        IF (:ERIPI='S') THEN BEGIN
            VAUX= 0;
            VAUX= (:EVLRIPI);
            SAUMENTO= :SAUMENTO + (:VAUX/:EQUANT);
        END
        IF (:ERFRETE='S') THEN
            SAUMENTO= (:SAUMENTO + (:ECUSTOFRETE/:EQUANT));
        IF (:ERSEGURO='S') THEN
            SAUMENTO= (:SAUMENTO+(:ECUSTOSEGURO/:EQUANT));
        IF (:ERDESP='S') THEN
            SAUMENTO= (:SAUMENTO+(:ECUSTOACESSORIA/:EQUANT));
        IF ((:ESUBTRAIRATEIOICMS = 'S') AND (:ECST NOT IN ('10','30','60','70'))) THEN BEGIN
            VAUX= :EVLRICMS/:EQUANT;
            SAUMENTO= :SAUMENTO-:VAUX;
        END
        IF (EVVLRICMSDESONERADO>0) THEN BEGIN
            VAUX= 0;
            VAUX= (:EVVLRICMSDESONERADO);
            SAUMENTO= :SAUMENTO - (:VAUX/:EQUANT);
        END
        IF ((:ESUBTRAIRATEIOPISCOFINS = 'S') AND (:ECUSTOPISCOFINS>0))THEN
            SAUMENTO = :SAUMENTO - :ECUSTOPISCOFINS;
    END
    SUSPEND;
END^


ALTER PROCEDURE ENTRADAESTOQUEINSERTEST (
    ECASADECIMALCUSTO NUMERIC(18,6),
    EPRECOESTOQUE NUMERIC(18,6),
    ECHAVELOTEPROD INTEGER,
    ECONTROLARLOTE CHAR(1),
    ECHAVEITEM INTEGER,
    ECHAVEPROD INTEGER,
    EQUANT NUMERIC(18,6),
    ECHAVEEMPESTOQUE INTEGER,
    ECHAVEEMPCUSTO INTEGER,
    ECHAVEUSUARIO INTEGER,
    ECHAVENF INTEGER,
    ENLATUAL DOUBLE PRECISION,
    EDOCUMENTO VARCHAR(9),
    ECODPROD VARCHAR(6),
    EDATAENTRADA DATE,
    ECHAVECLIFOR INTEGER,
    ETIPOMOVIMENTACAO INTEGER,
    EMOVESTPROPRIA SMALLINT,
    ECHAVEDPTOESTOQUEITEM INTEGER,
    EAGRUPADOCOMPOSTO INTEGER)
AS
declare variable VCHAVELOTE integer;
declare variable VQUANTIDADE numeric(14,6);
BEGIN
    -- GRAVA CASAS DECIMAIS QUE ESTA NO CONFIG
    EPRECOESTOQUE = CASE :ECASADECIMALCUSTO
    WHEN 2 THEN CAST(:EPRECOESTOQUE AS NUMERIC(18,2))
    WHEN 3 THEN CAST(:EPRECOESTOQUE AS NUMERIC(18,3))
    WHEN 4 THEN CAST(:EPRECOESTOQUE AS NUMERIC(18,4)) END;
    IF ((:ECHAVELOTEPROD = 0) AND (:ECONTROLARLOTE = 'S')) THEN BEGIN
        -- VERIFICAR SE TEM REGISTRO NA TABELA ITENSNFENTRADALOTEPROD
        FOR SELECT CHAVELOTEPROD, QTDE
            FROM ITENSNFENTRADALOTEPROD
            WHERE ATIVO=1 AND
            CHAVEITEMNF=:ECHAVEITEM AND
            CHAVEPRODUTO=:ECHAVEPROD AND
            COALESCE(CHAVELOTEPROD,0) > 0
            UNION ALL
            SELECT 0, CAST(:EQUANT AS NUMERIC(14,6))-SUM(COALESCE(IL.QTDE,0))
            FROM ITENSNFENTRADAPROD I
            LEFT JOIN ITENSNFENTRADALOTEPROD IL ON IL.CHAVEITEMNF = I.CHAVE AND COALESCE(IL.CHAVELOTEPROD,0) > 0
            WHERE I.ATIVO=1 AND
            I.CHAVE=:ECHAVEITEM AND
            I.CHAVEPRODUTO=:ECHAVEPROD
            GROUP BY I.QTDE
            HAVING CAST(:EQUANT AS NUMERIC(14,6))-SUM(COALESCE(IL.QTDE,0)) > 0
            ORDER BY 1, 2
        INTO :VCHAVELOTE, :VQUANTIDADE DO BEGIN
            EXECUTE PROCEDURE ESTENTRADASAIDAESTOQUE(:ECHAVEPROD, :VCHAVELOTE, :VQUANTIDADE, 0, 0,
                :ECHAVEEMPESTOQUE, :ECHAVEEMPCUSTO, :ECHAVEUSUARIO, :ECHAVENF, :ENLATUAL, :EDOCUMENTO,
                2, NULL, :ECODPROD, 1, :EDATAENTRADA, :EPRECOESTOQUE, :ECHAVEITEM,
                :ECHAVECLIFOR, :ETIPOMOVIMENTACAO, :EMOVESTPROPRIA, :ECHAVEDPTOESTOQUEITEM, :EPRECOESTOQUE);
        END                
    END ELSE BEGIN
        EXECUTE PROCEDURE ESTENTRADASAIDAESTOQUE(:ECHAVEPROD, :ECHAVELOTEPROD, :EQUANT, 0, :EAGRUPADOCOMPOSTO,
           :ECHAVEEMPESTOQUE, :ECHAVEEMPCUSTO, :ECHAVEUSUARIO, :ECHAVENF, :ENLATUAL, :EDOCUMENTO,
           2, NULL, :ECODPROD, 1, :EDATAENTRADA, :EPRECOESTOQUE, :ECHAVEITEM,
           :ECHAVECLIFOR, :ETIPOMOVIMENTACAO, :EMOVESTPROPRIA, :ECHAVEDPTOESTOQUEITEM, :EPRECOESTOQUE);
    END
END^


ALTER PROCEDURE ENTRADAESTOQUEINSERTPRODALT (
    ECHAVEPROD INTEGER,
    ECOTACAO INTEGER,
    ECHAVEEMPPRODALT INTEGER,
    ECHAVENF INTEGER,
    ECHAVECOTACAO INTEGER,
    ENLATUAL DOUBLE PRECISION,
    EUPRECOCUSTO NUMERIC(18,6),
    ECLASSIFICACAO VARCHAR(10),
    EUORIGEM INTEGER,
    ECUSTOPROD NUMERIC(18,6),
    EANTPRECOCUSTO NUMERIC(18,6),
    EUPRECOMEDIO NUMERIC(18,6),
    EANTPRECOMEDIO NUMERIC(18,6),
    EUPRECOVENDA NUMERIC(18,6),
    EANTPRECOVENDA NUMERIC(18,6),
    ELUCROMARKUP NUMERIC(7,2),
    ECHAVEITEM INTEGER,
    ETIPOFATORVENDA INTEGER,
    EPERCFATORMARKUP NUMERIC(7,2),
    EPERCSOBRECUSTO NUMERIC(7,2),
    EVPORCPVMINIMO NUMERIC(18,4),
    EVMODOPVMINIMO VARCHAR(10),
    ECHAVETABELAPRECO INTEGER)
AS
BEGIN
    IF (:ECOTACAO IS NULL) THEN BEGIN
        EXECUTE PROCEDURE INSERIRREGPRODALTERADOS(:ECHAVEEMPPRODALT, :ECHAVEPROD, :EUORIGEM,
            :ECHAVENF, :ENLATUAL, 'NOW',
            CASE WHEN :ECLASSIFICACAO='5' THEN :ECUSTOPROD ELSE :EUPRECOCUSTO END,
            :EANTPRECOCUSTO, :EUPRECOMEDIO, :EANTPRECOMEDIO,
            :EUPRECOVENDA, :EANTPRECOVENDA, :ELUCROMARKUP, :ECHAVEITEM, CASE WHEN :ETIPOFATORVENDA = 0 THEN :EPERCFATORMARKUP ELSE :EPERCSOBRECUSTO END,
            CASE WHEN :EVPORCPVMINIMO > 0 THEN
                CASE WHEN :EVMODOPVMINIMO = 0 THEN
                    (:EUPRECOCUSTO*:EVPORCPVMINIMO)/100
                ELSE
                    (:EUPRECOVENDA*:EVPORCPVMINIMO)/100
                END
            ELSE 0 END, :ECHAVETABELAPRECO);

    END ELSE BEGIN
        ECHAVECOTACAO = NULL;
        SELECT CHAVE FROM PRODUTOSALTERADOS
        WHERE CHAVEPRODUTO = :ECHAVEPROD AND NL = :ENLATUAL AND ORIGEM = 3
        INTO :ECHAVECOTACAO;
        IF (:ECHAVECOTACAO IS NOT NULL) THEN BEGIN
            UPDATE PRODUTOSALTERADOS SET
                ORIGEM = :EUORIGEM, CHAVEDOC = :ECHAVENF,
                PRECOCUSTO = :EUPRECOCUSTO,
                PRECOCUSTOANT = :EANTPRECOCUSTO, PRECOCUSTOMEDIO = :EUPRECOMEDIO,
                PRECOCUSTOMEDIOANT = :EANTPRECOMEDIO, CHAVEITEMDOC = :ECHAVEITEM
            WHERE (CHAVEPRODUTO=:ECHAVEPROD) AND (CHAVEEMPRESA=:ECHAVEEMPPRODALT)
            AND (ORIGEM = 3) AND (NL = :ENLATUAL);
         END ELSE BEGIN
            EXECUTE PROCEDURE INSERIRREGPRODALTERADOS(:ECHAVEEMPPRODALT, :ECHAVEPROD, :EUORIGEM,
                :ECHAVENF, :ENLATUAL, 'NOW',
                CASE WHEN :ECLASSIFICACAO='5' THEN :ECUSTOPROD ELSE :EUPRECOCUSTO END,
                :EANTPRECOCUSTO, :EUPRECOMEDIO, :EANTPRECOMEDIO,
                :EUPRECOVENDA, :EANTPRECOVENDA, :ELUCROMARKUP, :ECHAVEITEM, CASE WHEN :ETIPOFATORVENDA = 0 THEN :EPERCFATORMARKUP ELSE :EPERCSOBRECUSTO END,
                CASE WHEN :EVPORCPVMINIMO > 0 THEN
                    CASE WHEN :EVMODOPVMINIMO = 0 THEN
                        (:EUPRECOCUSTO*:EVPORCPVMINIMO)/100
                    ELSE
                        (:EUPRECOVENDA*:EVPORCPVMINIMO)/100
                    END
                ELSE 0 END, :ECHAVETABELAPRECO);

         END
    END
END^


ALTER PROCEDURE ESTATUALIZARSALDODPTOESTOQUE (
    CHAVEDPTOESTOQUE INTEGER,
    CHAVEPROD INTEGER,
    QTDE NUMERIC(18,6),
    CHAVEEMPRESA INTEGER,
    ETIPOMOVIMENTACAO INTEGER)
AS
begin
    UPDATE PRODUTODPTOESTOQUE SET
        SALDO= COALESCE(SALDO,0)+:QTDE,
        SALDOEMTERCEIROS  = CASE WHEN :ETIPOMOVIMENTACAO = 1 THEN COALESCE(SALDOEMTERCEIROS,0)+:QTDE ELSE COALESCE(SALDOEMTERCEIROS,0) END,
        SALDODETERCEIROS  = CASE WHEN :ETIPOMOVIMENTACAO = 2 THEN COALESCE(SALDODETERCEIROS,0)+:QTDE ELSE COALESCE(SALDODETERCEIROS,0) END,
        SALDOPOSSEPROPRIA = CASE WHEN :ETIPOMOVIMENTACAO = 0 THEN COALESCE(SALDOPOSSEPROPRIA,0)+:QTDE ELSE COALESCE(SALDOPOSSEPROPRIA,0) END
    WHERE (CHAVEPRODUTO=:CHAVEPROD)
        AND (CHAVEEMPRESA=:CHAVEEMPRESA)
        AND (CHAVEDPTOESTOQUE=:CHAVEDPTOESTOQUE);
    /*
        CHAMADAS :
            - Chamada dentro da procedure ESTATUALIZARSALDOESTOQUE;
    */
end^


ALTER PROCEDURE ESTATUALIZARSALDOESTOQUE (
    DATA DATE,
    CHAVEPROD INTEGER,
    CHAVEEMPRESA INTEGER,
    QTDE NUMERIC(18,6),
    QTDECONDICIONAL NUMERIC(18,6),
    TIPOMOVIMENTACAO NUMERIC(18,6),
    CHAVEDPTOESTOQUE INTEGER)
AS
BEGIN
    UPDATE PRODUTOESTOQUE SET
        SALDO=COALESCE(SALDO,0)+:QTDE,
        SALDOCONDICIONAL= COALESCE(SALDOCONDICIONAL,0)+:QTDECONDICIONAL,
        DATA = :DATA,
        SALDOEMTERCEIROS  = CASE WHEN :TIPOMOVIMENTACAO = 1 THEN COALESCE(SALDOEMTERCEIROS,0)+:QTDE ELSE COALESCE(SALDOEMTERCEIROS,0) END,
        SALDODETERCEIROS  = CASE WHEN :TIPOMOVIMENTACAO = 2 THEN COALESCE(SALDODETERCEIROS,0)+:QTDE ELSE COALESCE(SALDODETERCEIROS,0) END,
        SALDOPOSSEPROPRIA = CASE WHEN :TIPOMOVIMENTACAO = 0 THEN COALESCE(SALDOPOSSEPROPRIA,0)+:QTDE ELSE COALESCE(SALDOPOSSEPROPRIA,0) END
    WHERE (CHAVEPRODUTO=:CHAVEPROD) AND (CHAVEEMPRESA=:CHAVEEMPRESA);

    if (:QTDE <> 0) then
        EXECUTE PROCEDURE ESTATUALIZARSALDODPTOESTOQUE(:CHAVEDPTOESTOQUE, :CHAVEPROD, :QTDE, :CHAVEEMPRESA, :TIPOMOVIMENTACAO);
    /*
        CHAMADAS :
            - Estoque_BI: Chamada dentro da trigger para sincronizar o estoque;
    */
END^


ALTER PROCEDURE ESTATUALIZARSALDOLOTEESTOQUE (
    ESTORNAR CHAR(1),
    CHAVEEMPRESA INTEGER,
    CHAVEPRODUTO INTEGER,
    CHAVELOTE INTEGER,
    QTDEENTRADA NUMERIC(18,6),
    QTDESAIDA NUMERIC(18,6))
AS
begin
    IF (ESTORNAR = 'S') THEN BEGIN
        UPDATE PRODUTOLOTEESTOQUE SET
        QTDESAIDA= QTDESAIDA - :QTDESAIDA,
        SALDO= SALDO + :QTDESAIDA
        WHERE CHAVELOTE=:CHAVELOTE AND CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;

        UPDATE PRODUTOLOTEESTOQUE SET
        QTDEENTRADA=QTDEENTRADA - :QTDEENTRADA,
        SALDO = SALDO - :QTDEENTRADA
        WHERE CHAVELOTE=:CHAVELOTE AND CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;
    END
    IF (ESTORNAR = 'N') THEN BEGIN
        UPDATE PRODUTOLOTEESTOQUE SET
        QTDESAIDA= QTDESAIDA + :QTDESAIDA,
        SALDO= SALDO - :QTDESAIDA
        WHERE CHAVELOTE=:CHAVELOTE AND CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;
        UPDATE PRODUTOLOTEESTOQUE SET
        QTDEENTRADA=QTDEENTRADA + :QTDEENTRADA,
        SALDO = SALDO + :QTDEENTRADA
        WHERE CHAVELOTE=:CHAVELOTE AND CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;
    END

end^


ALTER PROCEDURE ESTENTRADASAIDAESTOQUE (
    CHAVEPRODUTO INTEGER,
    CHAVELOTEPROD INTEGER,
    QTDE NUMERIC(18,6),
    QTDEEMPROD NUMERIC(18,6),
    AGRUPADOCOMPOSTO INTEGER,
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER,
    CHAVEUSUARIO INTEGER,
    CHAVEDOC INTEGER,
    NL DOUBLE PRECISION,
    DOCUMENTO VARCHAR(9),
    ORIGEM INTEGER,
    OBS VARCHAR(1000),
    CODPRODUTO VARCHAR(6),
    CONVERSAO NUMERIC(18,6),
    DATA DATE,
    PRECOCUSTO NUMERIC(18,6),
    CHAVEITEM INTEGER,
    CHAVECLIFOR INTEGER,
    TIPOMOVIMENTACAO INTEGER,
    MOVESTOQUEPROPRIA SMALLINT,
    CHAVEDPTOESTOQUE INTEGER,
    VLRMOVIMENTACAO NUMERIC(18,6))
AS
declare variable QTDEFINALEMPROD numeric(18,6);
declare variable QTDEFINAL numeric(18,6);
declare variable CHAVEPRODUTOFINAL integer;
declare variable QTDECOMPOSTO numeric(18,6);
declare variable PRECOMEDIO numeric(14,3);
BEGIN
    --Alterado em 26/07/2012 => Julio
    IF ((QTDEEMPROD > 0 ) AND (QTDE = 0)) THEN
        QTDE = QTDEEMPROD;
    --NEUTRO
    IF (:AGRUPADOCOMPOSTO = 0) THEN BEGIN
        QTDEFINAL = :QTDE;
        QTDEFINAL = :QTDEFINAL * CONVERSAO;
        -- MOVIMENTAR O CAMPO SALDOEMPROD E ORIGEM FOR LANC. ORDEM DE PRODUCAO
        IF (QTDEEMPROD > 0 ) THEN BEGIN
            QTDEFINALEMPROD = :QTDEFINAL;
            QTDEFINAL = 0;
        END ELSE
            QTDEFINALEMPROD = :QTDEEMPROD;
        EXECUTE PROCEDURE ESTINSERIRREGESTOQUE(:CHAVEEMPESTOQUE, :ORIGEM, :CHAVEDOC,
            :CHAVEUSUARIO, :CHAVEPRODUTO, :CODPRODUTO, :DOCUMENTO, :DATA, :PRECOCUSTO,
            :QTDEFINAL, :QTDEFINALEMPROD, :NL, :OBS, :CHAVELOTEPROD, :CHAVEITEM,
            :CHAVECLIFOR, :TIPOMOVIMENTACAO, :MOVESTOQUEPROPRIA, :CHAVEDPTOESTOQUE,
            :VLRMOVIMENTACAO, 0);
    END
    --AGRUPADO
    IF (:AGRUPADOCOMPOSTO = 1) THEN BEGIN
        QTDEFINAL = :QTDE;
        QTDEFINAL = :QTDEFINAL * CONVERSAO;
        -- MOVIMENTAR O CAMPO SALDOEMPROD E ORIGEM FOR LANC. ORDEM DE PRODUCAO
        IF (QTDEEMPROD > 0 ) THEN BEGIN
            QTDEFINALEMPROD = :QTDEFINAL;
            QTDEFINAL = 0;
        END ELSE
            QTDEFINALEMPROD = :QTDEEMPROD;

        SELECT CHAVE, PRECOMEDIO FROM ESTRETORNARAGRUPADOPRINCIPAL(:CHAVEPRODUTO, :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO)
        INTO :CHAVEPRODUTO, :PRECOMEDIO;

        EXECUTE PROCEDURE ESTINSERIRREGESTOQUE(:CHAVEEMPESTOQUE, :ORIGEM, :CHAVEDOC,
            :CHAVEUSUARIO, :CHAVEPRODUTO, :CODPRODUTO, :DOCUMENTO, :DATA, :PRECOMEDIO,
            :QTDEFINAL, :QTDEFINALEMPROD, :NL, :OBS, :CHAVELOTEPROD, :CHAVEITEM,
            :CHAVECLIFOR, :TIPOMOVIMENTACAO, :MOVESTOQUEPROPRIA, :CHAVEDPTOESTOQUE,
            :VLRMOVIMENTACAO, 0);
    END
    --COMPOSTO
    IF (:AGRUPADOCOMPOSTO = 2) THEN BEGIN
        QTDEFINAL = :QTDE;
        QTDEFINAL = :QTDEFINAL * CONVERSAO;
        -- MOVIMENTAR O CAMPO SALDOEMPROD E ORIGEM FOR LANC. ORDEM DE PRODUCAO
        IF (QTDEEMPROD > 0 ) THEN BEGIN
            QTDEFINALEMPROD = :QTDEFINAL;
            QTDEFINAL = 0;
        END ELSE
            QTDEFINALEMPROD = :QTDEEMPROD;

        EXECUTE PROCEDURE ESTINSERIRREGESTOQUE(:CHAVEEMPESTOQUE, :ORIGEM, :CHAVEDOC,
            :CHAVEUSUARIO, :CHAVEPRODUTO, :CODPRODUTO, :DOCUMENTO, :DATA, :PRECOCUSTO,
            :QTDEFINAL, :QTDEFINALEMPROD, :NL, :OBS, :CHAVELOTEPROD, :CHAVEITEM,
            :CHAVECLIFOR, :TIPOMOVIMENTACAO, :MOVESTOQUEPROPRIA, :CHAVEDPTOESTOQUE,
            :VLRMOVIMENTACAO, 0);
    END
    --AGRUPADO PRINCIPAL
    IF (:AGRUPADOCOMPOSTO = 3) THEN BEGIN
        QTDEFINAL = :QTDE;
        QTDEFINAL = :QTDEFINAL * CONVERSAO;
        -- MOVIMENTAR O CAMPO SALDOEMPROD E ORIGEM FOR LANC. ORDEM DE PRODUCAO
        IF (QTDEEMPROD > 0 ) THEN BEGIN
            QTDEFINALEMPROD = :QTDEFINAL;
            QTDEFINAL = 0;
        END ELSE
            QTDEFINALEMPROD = :QTDEEMPROD;

        EXECUTE PROCEDURE ESTINSERIRREGESTOQUE(:CHAVEEMPESTOQUE, :ORIGEM, :CHAVEDOC,
            :CHAVEUSUARIO, :CHAVEPRODUTO, :CODPRODUTO, :DOCUMENTO, :DATA, :PRECOCUSTO,
            :QTDEFINAL, :QTDEFINALEMPROD, :NL, :OBS, :CHAVELOTEPROD, :CHAVEITEM,
            :CHAVECLIFOR, :TIPOMOVIMENTACAO, :MOVESTOQUEPROPRIA, :CHAVEDPTOESTOQUE,
            :VLRMOVIMENTACAO, 0);
    END
    --COMPOSTO PRINCIPAL
    IF (:AGRUPADOCOMPOSTO = 4) THEN BEGIN
        QTDEFINAL = :QTDE;
        QTDEFINAL = :QTDEFINAL * CONVERSAO;
        FOR SELECT CHAVE, QTDEBAIXAR, CONVERSAO, PRECOMEDIO
        FROM ESTRETORNARCOMPOSTOS(0,:CHAVEPRODUTO, :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO, 0)
        INTO :CHAVEPRODUTOFINAL, :QTDECOMPOSTO, :CONVERSAO, :PRECOMEDIO DO BEGIN
            QTDECOMPOSTO = :QTDECOMPOSTO * CONVERSAO;
            QTDECOMPOSTO = :QTDEFINAL * :QTDECOMPOSTO;
            -- MOVIMENTAR O CAMPO SALDOEMPROD E ORIGEM FOR LANC. ORDEM DE PRODUCAO
            IF (QTDEEMPROD > 0 ) THEN BEGIN
                QTDEFINALEMPROD = :QTDECOMPOSTO;
                QTDECOMPOSTO = 0;
            END ELSE
                QTDEFINALEMPROD = :QTDEEMPROD;
            EXECUTE PROCEDURE ESTINSERIRREGESTOQUE(:CHAVEEMPESTOQUE, :ORIGEM, :CHAVEDOC,
                :CHAVEUSUARIO, :CHAVEPRODUTOFINAL, :CODPRODUTO, :DOCUMENTO, :DATA, :PRECOMEDIO,
                :QTDECOMPOSTO, :QTDEFINALEMPROD, :NL, :OBS, :CHAVELOTEPROD, :CHAVEITEM,
                :CHAVECLIFOR, :TIPOMOVIMENTACAO, :MOVESTOQUEPROPRIA, :CHAVEDPTOESTOQUE,
                :VLRMOVIMENTACAO, 0);
        END
    END
    /*
        CHAMADAS:
            classPreVenda : Usada para estornar o estoque reservado da pre-venda que gerou CF
            frmPreVenda : Usada para reservar o estoque da pre-venda
            frmAjustesDeEstoque : Usada para movimentar o estoque no ajuste
            frmCondicional : Usada para baixar estoque
            frmTransfSaldoEstoque : Usada para transferir o saldo de estoque entre produtos
            frmOrdemDeServico : Usada para baixar o estoque dos itens da OS
    */
END^


ALTER PROCEDURE ESTINSERIRREGESTOQUE (
    CHAVEEMPRESA INTEGER,
    ORIGEM INTEGER,
    CHAVEDOC INTEGER,
    CHAVEUSUARIO INTEGER,
    CHAVEPRODUTO INTEGER,
    CODPRODUTO VARCHAR(6),
    DOCUMENTO VARCHAR(9),
    DATA DATE,
    PRECOCUSTO NUMERIC(18,6),
    QTDE NUMERIC(18,6),
    QTDEEMPROD NUMERIC(18,6),
    NL DOUBLE PRECISION,
    OBS VARCHAR(1000),
    CHAVELOTEPROD INTEGER,
    CHAVEITEM INTEGER,
    CHAVECLIFOR INTEGER,
    TIPOMOVIMENTACAO INTEGER,
    MOVESTOQUEPROPRIA SMALLINT,
    CHAVEDPTOESTOQUE INTEGER,
    VLRMOVIMENTACAO NUMERIC(18,6),
    CHAVEMOTAJUSTE NUMERIC(18,6))
AS
declare variable QTDEENTRADA numeric(18,6);
declare variable QTDESAIDA numeric(18,6);
declare variable TIPOMOV integer;
BEGIN
    IF (:QTDE < 0) THEN BEGIN
        QTDESAIDA   = :QTDE * (-1);
        QTDEENTRADA = 0;
    END ELSE BEGIN
        QTDEENTRADA = :QTDE;
        QTDESAIDA   = 0;
    END

    IF (:TIPOMOVIMENTACAO = 1) THEN BEGIN
        TIPOMOV = :TIPOMOVIMENTACAO;
        TIPOMOVIMENTACAO = 0;
    END

    -- MOVIMENTA SALDO EM POSSE PROPRIA
    IF (MOVESTOQUEPROPRIA = 0) THEN BEGIN
        INSERT INTO ESTOQUE
            (CHAVEEMPRESA, ORIGEM, CHAVEDOC, CHAVEUSUARIO, CHAVEPRODUTO, CODPRODUTO,
            DOCUMENTO, DATA, PRECOCUSTO, QTDEENTRADA, QTDESAIDA, SALDO, NL, OBS,
            CHAVELOTEPROD, CHAVEITEM, CHAVECLIFOR, TIPOMOVIMENTACAO, SALDOEMPROD,
            CHAVEDPTOESTOQUE, VLRMOVIMENTACAO, CHAVEMOTIVOAJUSTE)
        VALUES
            (:CHAVEEMPRESA, :ORIGEM, :CHAVEDOC, :CHAVEUSUARIO, :CHAVEPRODUTO, :CODPRODUTO,
            :DOCUMENTO, :DATA, :PRECOCUSTO, :QTDEENTRADA, :QTDESAIDA, :QTDE, :NL, :OBS,
            :CHAVELOTEPROD, :CHAVEITEM, :CHAVECLIFOR, :TIPOMOVIMENTACAO, :QTDEEMPROD,
            :CHAVEDPTOESTOQUE, :VLRMOVIMENTACAO, :CHAVEMOTAJUSTE);
    END

    /* SALDO EM PODER DE TERCEIROS */
    IF (:TIPOMOV = 1) THEN BEGIN
        IF (:QTDESAIDA > 0) THEN BEGIN
            QTDEENTRADA = :QTDESAIDA;
            QTDESAIDA = 0;
        END ELSE BEGIN
            QTDESAIDA = :QTDEENTRADA;
            QTDEENTRADA = 0;
        END
        QTDE = :QTDE * (-1);
        INSERT INTO ESTOQUE
            (CHAVEEMPRESA, ORIGEM, CHAVEDOC, CHAVEUSUARIO, CHAVEPRODUTO, CODPRODUTO,
            DOCUMENTO, DATA, PRECOCUSTO, QTDEENTRADA, QTDESAIDA, SALDO, NL, OBS,
            CHAVELOTEPROD, CHAVEITEM, CHAVECLIFOR, TIPOMOVIMENTACAO,
            CHAVEDPTOESTOQUE, VLRMOVIMENTACAO, CHAVEMOTIVOAJUSTE)
        VALUES
            (:CHAVEEMPRESA, :ORIGEM, :CHAVEDOC, :CHAVEUSUARIO, :CHAVEPRODUTO, :CODPRODUTO,
            :DOCUMENTO, :DATA, :PRECOCUSTO, :QTDEENTRADA, :QTDESAIDA, :QTDE, :NL, :OBS,
            :CHAVELOTEPROD, :CHAVEITEM, :CHAVECLIFOR, :TIPOMOV,
            :CHAVEDPTOESTOQUE, :VLRMOVIMENTACAO, :CHAVEMOTAJUSTE);
    END
    /*
        CHAMADAS:
            FRMMANUTENCAOLOTEPROD : USADA PARA INSERIR REGISTROS NO ESTOQUE REF. MOVIMENTACAO
            FRMPRODUTO : USADA QUANDO CADASTRA UM PRODUTO NOVO, INSERE OS REGISTRO ZERADOS NO ESTOQUE
            FRMLANCAMENTOORDEMPROD : USADA PARA LANCAR A PERDA DO PRODUTO PRODUZIDO/FABRICADO            
    */
END^


ALTER PROCEDURE ESTOQUEPDV (
    COMANDO VARCHAR(10),
    CHAVELOTEPROD INTEGER,
    CHAVEPROD INTEGER,
    CHAVECUPOM INTEGER,
    CODPROD VARCHAR(6),
    DOCUMENTO VARCHAR(9),
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER,
    CHAVEUSUARIO INTEGER,
    QTDE NUMERIC(18,6),
    NL DOUBLE PRECISION,
    ORIGEM SMALLINT,
    PRECOCUSTO NUMERIC(18,6),
    CHAVEITEM INTEGER,
    CHAVECLIFOR INTEGER,
    CHAVEDPTOESTOQUE INTEGER,
    VLRCONVERSAO NUMERIC(18,6),
    VLRUNITCOMDESC NUMERIC(18,6))
AS
declare variable AGRUPADOCOMPOSTO integer;
declare variable CHAVEITEMCANC integer;
declare variable VTEMCOMPOSICAO varchar(1);
BEGIN
    --ESSA PARTE BAIXA COMPOSICAO/COMPLEMENTO DO CHBRS
    IF (:COMANDO = 'BAIXABRS') THEN BEGIN
        SELECT STEMCOMPOSICAO
        FROM BAIXAESTCOMPOSCOMPLEMBRS(:CHAVEITEM, 0, :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO, :CHAVEUSUARIO,
        :CHAVECUPOM, :NL, :DOCUMENTO, :ORIGEM, CURRENT_DATE, :CHAVECLIFOR, :CHAVEDPTOESTOQUE, :CODPROD, :VLRUNITCOMDESC)
        INTO :VTEMCOMPOSICAO;
        
        --SE NAO ACHAR BAIXAR NORMAL
        IF (:VTEMCOMPOSICAO = 'N') THEN
            COMANDO = 'BAIXA';
    END
    -- ESSA PARTE BAIXA O ESTOQUE
    IF (:COMANDO = 'BAIXA') THEN BEGIN
        SELECT P.AGRUPADOCOMPOSTO
        FROM PRODUTO P
        WHERE P.CHAVE =:CHAVEPROD
        INTO :AGRUPADOCOMPOSTO;

        EXECUTE PROCEDURE ESTENTRADASAIDAESTOQUE(:CHAVEPROD, :CHAVELOTEPROD, :QTDE*(-1), 0, :AGRUPADOCOMPOSTO,
            :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO, :CHAVEUSUARIO, :CHAVECUPOM, :NL, :DOCUMENTO,
            :ORIGEM,  '', :CODPROD, :VLRCONVERSAO, CURRENT_DATE, :PRECOCUSTO, :CHAVEITEM,
            :CHAVECLIFOR, 0, 0, :CHAVEDPTOESTOQUE, :VLRUNITCOMDESC);
    END
    -- VOLTA ESTOQUE QDO CANCELA ALGUM ITEM
    IF (:COMANDO='ESTORNA') THEN BEGIN
        SELECT I.CHAVE, I.QTDE, P.CHAVE, P.AGRUPADOCOMPOSTO
        FROM ITENSCUPOM I
        INNER JOIN PRODUTO P ON P.CHAVE = I.CHAVEPRODUTO
        WHERE I.CHAVE=:CHAVEITEM
        INTO :CHAVEITEMCANC, :QTDE, :CHAVEPROD, :AGRUPADOCOMPOSTO;

        UPDATE ITENSCUPOM SET
        ATIVO=2, CHAVEUSUARIOCANC=:CHAVEUSUARIO
        WHERE CHAVE=:CHAVEITEMCANC;

        UPDATE ESTOQUE SET ATIVO=6, OBS='ITEM CUPOM CANCELADO'
        WHERE ATIVO=1 AND ORIGEM=4 AND NL=:NL AND CHAVEITEM=:CHAVEITEMCANC;
    END
    /*
        CHAMADAS:
            ClassCupomFiscalOnline, ClassCupomFiscalOffline : Usada para baixar e estornar estoque de cupom fiscal
            ClassSATCFeOnLine: Usada para baixar e estornar estoque de SAT-CFe
    */
END^


ALTER PROCEDURE ESTORNAR_ITENSVALETROCA (
    CHAVEDOC INTEGER,
    NL DOUBLE PRECISION)
AS
declare variable ORIGEMITEM integer;
declare variable CHAVEITEM integer;
declare variable CHAVEITENSVALETROCA integer;
declare variable QTDEVALETROCA numeric(18,6);
BEGIN
    FOR SELECT CHAVE, QTDEVALETROCA, CHAVEITEM, ORIGEMITEM
    FROM CAIXAPDVITENSVALETROCA
    WHERE (ATIVO in (1, -1)) AND (ORIGEMVALETROCA=0)
    AND (CHAVEORIGEM IN (SELECT CHAVE FROM CAIXAPDV WHERE (ATIVO IN (1, -1)) AND (NL=:NL) AND (TRANSACAO=7) AND (CHAVECUPOM=:CHAVEDOC)))
    INTO :CHAVEITENSVALETROCA, :QTDEVALETROCA, :CHAVEITEM, :ORIGEMITEM DO BEGIN
        IF (ORIGEMITEM=1) THEN BEGIN
            UPDATE ITENSCUPOM I SET
            I.QTDEVALETROCA = CASE WHEN (COALESCE(I.QTDEVALETROCA,0) - :QTDEVALETROCA) < 0 THEN 0 ELSE (COALESCE(I.QTDEVALETROCA,0) - :QTDEVALETROCA) END
            WHERE (CHAVE=:CHAVEITEM);
        END
        IF (ORIGEMITEM=2) THEN BEGIN
            UPDATE ITENSNFSAIDA I SET
            I.QTDEVALETROCA = CASE WHEN (COALESCE(I.QTDEVALETROCA,0) - :QTDEVALETROCA) < 0 THEN 0 ELSE (COALESCE(I.QTDEVALETROCA,0) - :QTDEVALETROCA) END
            WHERE (CHAVE=:CHAVEITEM);
        END
        UPDATE CAIXAPDVITENSVALETROCA SET ATIVO=6
        WHERE (CHAVE=:CHAVEITENSVALETROCA);
    END
END^


ALTER PROCEDURE ESTORNARESTOQUECOTADO (
    ECHAVECOTACAO INTEGER,
    ECHAVEEMPESTOQUE INTEGER,
    ECHAVEEMPCUSTO INTEGER)
AS
declare variable VSTATUSESTOQUECOTADO integer;
declare variable VCHAVEPRODUTO integer;
declare variable VQTDE numeric(18,6);
declare variable VAGRUPADOCOMPOSTO integer;
declare variable VCONVERSAO numeric(18,6);
declare variable VQTDEFINAL numeric(18,6);
declare variable VCHAVEPRODFINAL integer;
declare variable VQTDECOMPOSTO numeric(18,6);
begin

    SELECT STATUSESTOQUECOTADO FROM COTACAO
    WHERE (CHAVE=:ECHAVECOTACAO)
    INTO :VSTATUSESTOQUECOTADO;
    -- SE O ESTOQUE ESTIVER COTADO ENTAO DESFAZ
    if (:VSTATUSESTOQUECOTADO = 1) then BEGIN
        FOR SELECT I.CHAVEPRODUTO, I.QTDE, P.AGRUPADOCOMPOSTO, U.CONVERSAO
        FROM ITENSCOTACAOPROD I
        INNER JOIN PRODUTO P ON (I.CHAVEPRODUTO=P.CHAVE)
        INNER JOIN UNIDADE U ON (I.CHAVEUNIDADE=U.CHAVE)
        WHERE (I.ATIVO=1) AND (I.CHAVECOTACAO=:ECHAVECOTACAO)
        INTO :VCHAVEPRODUTO, :VQTDE, :VAGRUPADOCOMPOSTO, :VCONVERSAO
        DO BEGIN
            VQTDE = (:VQTDE * (-1));
            --  NEUTRO  ou ITEM COMPOSTO ou AGRUPADO PRINCIPAL
            IF ((:VAGRUPADOCOMPOSTO = 0) or (:VAGRUPADOCOMPOSTO = 2) or (:VAGRUPADOCOMPOSTO = 3))  THEN BEGIN
                VQTDEFINAL = :VQTDE;
                VQTDEFINAL = :VQTDEFINAL * :VCONVERSAO;

                UPDATE produtoestoque set
                SALDOCOTADO=SALDOCOTADO+:VQTDEFINAL
                WHERE (CHAVEPRODUTO=:VCHAVEPRODUTO) and (CHAVEEMPRESA=:ECHAVEEMPESTOQUE);
            END
            --  ITEM AGRUPADO
            IF (:VAGRUPADOCOMPOSTO = 1) THEN BEGIN
                VQTDEFINAL = :VQTDE;
                VQTDEFINAL = :VQTDEFINAL * :VCONVERSAO;

                SELECT CHAVE FROM ESTRETORNARAGRUPADOPRINCIPAL(:VCHAVEPRODUTO, :ECHAVEEMPESTOQUE, :ECHAVEEMPCUSTO)
                INTO :VCHAVEPRODFINAL;

                UPDATE produtoestoque set
                SALDOCOTADO=SALDOCOTADO+:VQTDEFINAL
                WHERE (CHAVEPRODUTO=:VCHAVEPRODFINAL) and (CHAVEEMPRESA=:ECHAVEEMPESTOQUE);
            END
            -- COMPOSTO
            if (:VAGRUPADOCOMPOSTO = 4) then BEGIN
                VQTDEFINAL = :VQTDE;
                VQTDEFINAL = :VQTDEFINAL * VCONVERSAO;

                FOR SELECT CHAVE, QTDEBAIXAR, CONVERSAO
                FROM ESTRETORNARCOMPOSTOS(0,:VCHAVEPRODUTO, :ECHAVEEMPESTOQUE, :ECHAVEEMPCUSTO, 0)
                INTO :VCHAVEPRODFINAL, :VQTDECOMPOSTO, :VCONVERSAO DO BEGIN
                    VQTDECOMPOSTO = :VQTDECOMPOSTO * :VCONVERSAO;
                    VQTDECOMPOSTO = :VQTDEFINAL * :VQTDECOMPOSTO;

                    UPDATE produtoestoque set
                    SALDOCOTADO=SALDOCOTADO+:VQTDECOMPOSTO
                    WHERE (CHAVEPRODUTO=:VCHAVEPRODFINAL) and (CHAVEEMPRESA=:ECHAVEEMPESTOQUE);
                END
            END
        END

        UPDATE COTACAO SET
        STATUSESTOQUECOTADO = 2
        WHERE (CHAVE=:ECHAVECOTACAO);
    END

    /*
        CHAMADAS:
            proc COTACAOGERAOS : Usada para estornar o estoque cotado do orcamento que gerou OS

    */


end^


ALTER PROCEDURE ESTORNOREQMATERIAIS (
    CHAVEREQUISICAO INTEGER,
    NLATUAL DOUBLE PRECISION)
AS
BEGIN
    --Alterado em 20/10/2011 => Sergio
    -- CANCELA ENTRADA NO ESTOQUE
    UPDATE ESTOQUE SET ATIVO=8
    WHERE ATIVO=1 AND NL=:NLATUAL;
    -- CANCELA REQUISICAO
    UPDATE REQUISICAOMATERIAIS SET SITUACAO='ESTORNADA'
    WHERE CHAVE=:CHAVEREQUISICAO;
    -- CANCELA ITENS
    UPDATE ITENSREQMATERIAIS SET ATIVO=2
    WHERE ATIVO=1 AND CHAVE=:CHAVEREQUISICAO;
    /*
        CHAMADAS:
            frmReqMatEst : Usada para estornar estoque de requisicao de material
   */
END^


ALTER PROCEDURE ESTRETORNARAGRUPADOPRINCIPAL (
    CHAVEPRODUTO INTEGER,
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER)
RETURNS (
    CHAVE INTEGER,
    CONVERSAO NUMERIC(18,6),
    CODIGO VARCHAR(6),
    SALDO INTEGER,
    PRECOCUSTO NUMERIC(14,3),
    PRECOMEDIO NUMERIC(14,3))
AS
BEGIN
    --Alterado em 28/06/2012 => Sergio
    CHAVE = 0;
    SELECT BEA.CHAVEPRODUTO, COALESCE(PE.SALDO,0),
    UN.CONVERSAO, P.CODIGO, PC.PRECOCUSTO, PC.PRECOMEDIO
    FROM BAIXAESTAGRUPADO BEA
    INNER JOIN PRODUTO P ON P.CHAVE = BEA.CHAVEPRODUTO
    INNER JOIN PRODUTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE AND PE.CHAVEEMPRESA=:CHAVEEMPESTOQUE
    INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO = P.CHAVE AND PC.CHAVEEMPRESA=:CHAVEEMPCUSTO
    INNER JOIN UNIDADE UN ON UN.CHAVE = P.CHAVEUNIDADE
    WHERE BEA.ATIVO=1 AND BEA.CHAVEPRODUTOAGRUP=:CHAVEPRODUTO
    INTO :CHAVE, :SALDO,
    :CONVERSAO, :CODIGO, :PRECOCUSTO, :PRECOMEDIO;

    SUSPEND;
END^


ALTER PROCEDURE ESTRETORNARCOMPOSTOS (
    TIPO INTEGER,
    CHAVEPRODUTO INTEGER,
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER,
    CHAVEITEM INTEGER)
RETURNS (
    STATUS INTEGER,
    CHAVEINDICE INTEGER,
    CHAVE INTEGER,
    QTDEBAIXAR NUMERIC(18,6),
    CONVERSAO NUMERIC(18,6),
    CODIGO VARCHAR(6),
    SALDO NUMERIC(14,3),
    PRECOCUSTO NUMERIC(14,3),
    DESCRICAO VARCHAR(100),
    PRECOMEDIO NUMERIC(14,3))
AS
BEGIN
    IF (:TIPO = 0) THEN BEGIN
        FOR SELECT BEC.CHAVE, COALESCE(PE.SALDO,0),
        BEC.CHAVEPRODUTOCOMP, BEC.QTDEBAIXAR, UN.CONVERSAO, P.CODIGO, PC.PRECOCUSTO,
        PC.PRECOMEDIO, P.STATUS, P.DESCRICAO
        FROM BAIXAESTCOMPOSTO BEC
        INNER JOIN PRODUTO P ON BEC.CHAVEPRODUTOCOMP=P.CHAVE
        INNER JOIN PRODUTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE AND (PE.CHAVEEMPRESA=:CHAVEEMPESTOQUE)
        INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO = P.CHAVE AND (PC.CHAVEEMPRESA=:CHAVEEMPCUSTO)
        INNER JOIN UNIDADE UN ON UN.CHAVE = P.CHAVEUNIDADE
        WHERE (BEC.ATIVO=1) AND (BEC.CHAVEPRODUTO=:CHAVEPRODUTO) AND (BEC.TIPO=0)
        INTO :CHAVEINDICE, :SALDO, :CHAVE, :QTDEBAIXAR, :CONVERSAO, :CODIGO, :PRECOCUSTO,
        :PRECOMEDIO, :STATUS, :DESCRICAO DO BEGIN
            SUSPEND;
        END
    END ELSE BEGIN
        FOR SELECT BEC.CHAVE, COALESCE(PE.SALDO,0),
        I.CHAVEPRODUTOMATPRIMA, I.QTDEBAIXAR, UN.CONVERSAO, P.CODIGO, PC.PRECOCUSTO,
        PC.PRECOMEDIO, P.STATUS, P.DESCRICAO
        FROM PCPFORMULAS BEC
        INNER JOIN PCPFORMULASITENS I ON I.CHAVEFORMULA=BEC.CHAVE AND (COALESCE(I.CHAVEITEM,0) = :CHAVEITEM) -- chave item quando origem do ordem de producao for orcamento
        INNER JOIN PRODUTO P ON I.CHAVEPRODUTOMATPRIMA=P.CHAVE
        INNER JOIN PRODUTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE AND (PE.CHAVEEMPRESA=:CHAVEEMPESTOQUE)
        INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO = P.CHAVE AND (PC.CHAVEEMPRESA=:CHAVEEMPCUSTO)
        INNER JOIN UNIDADE UN ON UN.CHAVE = P.CHAVEUNIDADE
        WHERE (BEC.ATIVO=1) AND (BEC.CHAVE=:CHAVEPRODUTO) AND (I.ATIVO=1)
        INTO :CHAVEINDICE, :SALDO, :CHAVE, :QTDEBAIXAR, :CONVERSAO, :CODIGO, :PRECOCUSTO,
        :PRECOMEDIO, :STATUS, :DESCRICAO DO BEGIN
            SUSPEND;
        END
    END
END^


ALTER PROCEDURE EXCLUIRNFEHOMLOGACAO
AS
declare variable NL double precision;
BEGIN
  -- Excluir nfse/nfe no ambiente de homologacao
    FOR SELECT NL FROM NFSAIDA
    WHERE ((TIPOEMISSAONFE=1) OR (TIPOEMISSAONFSE=1))  AND NL>0
    INTO :NL
    DO BEGIN
        UPDATE ITENSNFSAIDA SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;

        UPDATE ITENSNFSERVICO SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;

        UPDATE PEDIDOSAIDA SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;

        UPDATE ITENSPEDSAIDA SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;

        UPDATE ITENSPEDSAIDASERV SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;

        UPDATE NFSAIDA SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;
    END
    -- Excluir as nfs de entrada
    FOR SELECT NL FROM NFENTRADA
    WHERE (TIPOEMISSAONFE=1)  AND (NL>0)
    INTO :NL
    DO BEGIN
        UPDATE ITENSNFENTRADAPROD SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;

        UPDATE ITENSNFENTRADASERV SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;

        UPDATE NFENTRADA SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;
    END
   -- Excluir CTRCS Eletronicos no ambiente de homologacao
    FOR SELECT NL FROM CTRC
    WHERE TIPOEMISSAOCTE=1 AND NL>0
    INTO :NL
    DO BEGIN
        UPDATE CTRCNFS SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;


        UPDATE CTRC SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;
    END
   -- Excluir Manifestos Eletronicos no ambiente de homologacao
    FOR SELECT NL FROM TMSMANIFESTO
    WHERE TIPOEMISSAO=1 AND NL>0
    INTO :NL
    DO BEGIN
        UPDATE TMSMANIFESTOITENSCTRC SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;


        UPDATE TMSMANIFESTO SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;
    END

    -- Excluir CTEOS Eletronicos no ambiente de homologacao
    FOR SELECT NL FROM CTEOS
    WHERE TIPOEMISSAO=1 AND NL>0
    INTO :NL
    DO BEGIN
        UPDATE CTEOS SET
        ATIVO=3
        WHERE ATIVO=1 AND NL=:NL;
    END


    /*  
        CHAMADAS :
            - Config : Usada para excluir xml dos docs. eletronicos;
    */
END^


ALTER PROCEDURE GERA_CAIXA (
    CHAVELANCBCO INTEGER,
    CHAVEEMP INTEGER,
    GERARCAIXALANCBANCARIO CHAR(1),
    CHAVEUSUARIO INTEGER,
    CHAVECONTACAIXA INTEGER)
AS
declare variable LANCAMENTO date;
declare variable CHAVEPLANOCONTA integer;
declare variable CHAVECENTROCUSTO integer;
declare variable CHAVECLIFOR integer;
declare variable HISTORICO varchar(100);
declare variable DOCUMENTO varchar(20);
declare variable COMPETENCIA varchar(10);
declare variable VALOR numeric(18,4);
declare variable TIPO char(1);
declare variable NOVOPLANOCTA integer;
declare variable NLATUAL double precision;
declare variable CHEQUE integer;
declare variable CHAVECONTA integer;
declare variable CHAVEMOVFINANC integer;
declare variable LANCBANCARIOSIMPLES char(1);
declare variable CHAVEPCTRANSFCAIXABCO integer;
declare variable CHAVEPCTRANSFBCOCAIXA integer;
declare variable CHAVECONTABCO integer;
declare variable CHAVEPCDEPCHEQUETERCEIROS integer;
declare variable CHAVEOPERACOESTITULOS integer;
BEGIN
    LANCBANCARIOSIMPLES='S';
    NLATUAL = 0;
    SELECT COMPENSADO, CHAVEPLANOCTO, CHAVECENTROCTO,
           HISTORICO, NUMERODOC, COMPETENCIA, VALOR, CHAVECHEQUE, CHAVECONTABCO,
           CHAVECLIFOR, CHAVEOPERACOESTITULOS, NL
    FROM LANCBCO
    WHERE CHAVE=:CHAVELANCBCO
    INTO :LANCAMENTO, :CHAVEPLANOCONTA, :CHAVECENTROCUSTO,
         :HISTORICO, :DOCUMENTO, :COMPETENCIA, :VALOR, :CHEQUE, :CHAVECONTABCO,
         :CHAVECLIFOR, :CHAVEOPERACOESTITULOS, :NLATUAL;
    IF (:NLATUAL = 0) THEN BEGIN
        SELECT ULTIMANL FROM ATUALIZANL
        INTO :NLATUAL;
    
        UPDATE LANCBCO SET
        NL=:NLATUAL
        WHERE CHAVE=:CHAVELANCBCO;
    END
    IF (:CHEQUE IS NOT NULL) THEN BEGIN
        UPDATE CHEQUES SET
        NLSAIDA= :NLATUAL
        WHERE CHAVE=:CHEQUE;
        SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
        WHERE CHAVE=35
        INTO :CHAVEPCDEPCHEQUETERCEIROS; 
        IF (:GERARCAIXALANCBANCARIO = 'S') THEN BEGIN
            INSERT INTO CAIXA (CHAVEEMPRESA, CHAVEPLANOCTO, CHAVECENTROCTO,
                           LANCAMENTO, HISTORICO, DOCUMENTO, COMPETENCIA,
                           VALOR, NL, LANCBANCARIO, CHAVECONTABCO,
                           CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                           CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO)
            VALUES (:CHAVEEMP, :CHAVEPCDEPCHEQUETERCEIROS, 1,
                :LANCAMENTO, SUBSTRING('GERADO AUT. '||:HISTORICO FROM 1 FOR 100), :DOCUMENTO,
                :COMPETENCIA, :VALOR, :NLATUAL, 'S', :CHAVECONTABCO,
                :CHAVEUSUARIO, :CHAVEUSUARIO, :CHAVECLIFOR,
                :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, 1);
        END
    END ELSE BEGIN
        SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
        WHERE CHAVE=29
        INTO :CHAVEPCTRANSFCAIXABCO;
        SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
        WHERE CHAVE=30
        INTO :CHAVEPCTRANSFBCOCAIXA;
        SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
        WHERE CHAVE=31
        INTO :CHAVEPCDEPCHEQUETERCEIROS;
        IF (:GERARCAIXALANCBANCARIO = 'S') THEN BEGIN
            IF (:CHAVEPLANOCONTA IS NOT NULL) THEN BEGIN
                SELECT SUBSTRING(CONTA FROM 1 FOR 1)
                FROM PLANOCONTA
                WHERE (CHAVE=:CHAVEPLANOCONTA)
                INTO :TIPO;
                NOVOPLANOCTA=0;
                IF ((:TIPO = '1') AND (:CHAVEPLANOCONTA <> :CHAVEPCTRANSFBCOCAIXA)) THEN
                    NOVOPLANOCTA= :CHAVEPCTRANSFCAIXABCO;
                IF ((:TIPO = '2') AND (:CHAVEPLANOCONTA <> :CHAVEPCTRANSFCAIXABCO)
                    AND (:CHAVEPLANOCONTA <> :CHAVEPCDEPCHEQUETERCEIROS)) THEN
                    NOVOPLANOCTA= CHAVEPCTRANSFBCOCAIXA;
                IF (:NOVOPLANOCTA > 0) THEN BEGIN
                    FOR SELECT M.VALOR, M.CHAVECONTA, M.CHAVE
                    FROM MOVFINANCEIRAS M
                    WHERE (M.ATIVO=1) AND (M.CHAVELANCBCO=:CHAVELANCBCO)
                    INTO :VALOR, :CHAVECONTA, :CHAVEMOVFINANC DO BEGIN
                        IF (:TIPO = '1') THEN BEGIN
                            INSERT INTO CAIXA(CHAVEEMPRESA, CHAVEPLANOCTO, CHAVECENTROCTO,
                                          HISTORICO, CHAVECONTA, LANCAMENTO, DOCUMENTO,
                                          COMPETENCIA, VALOR,  NL, LANCBANCARIO, CHAVEMOVFINANCEIRA,
                                          CHAVECONTABCO, CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                                          CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO)
                            SELECT :CHAVEEMP, CHAVEPLANOCTO, 1,
                                DESCRICAO, :CHAVECONTA, :LANCAMENTO, DOCUMENTO||'/'||PARCELA,
                                :COMPETENCIA, :VALOR, :NLATUAL, 'S', :CHAVEMOVFINANC,
                                :CHAVECONTABCO, :CHAVEUSUARIO, :CHAVEUSUARIO,
                                CHAVECLIFOR, CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, 0
                            FROM RECEBER
                            WHERE CHAVE=:CHAVECONTA;
                        END
                        IF (:TIPO = '2') THEN BEGIN
                            INSERT INTO CAIXA(CHAVEEMPRESA, CHAVEPLANOCTO, CHAVECENTROCTO,
                                          HISTORICO, CHAVECONTA, LANCAMENTO, DOCUMENTO,
                                          COMPETENCIA, VALOR,  NL, LANCBANCARIO, CHAVEMOVFINANCEIRA,
                                          CHAVECONTABCO, CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                                          CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO)
                            SELECT :CHAVEEMP, CHAVEPLANOCTO, 1,
                                DESCRICAO, :CHAVECONTA, :LANCAMENTO, DOCUMENTO||'/'||PARCELA,
                                :COMPETENCIA, :VALOR,  :NLATUAL, 'S', :CHAVEMOVFINANC,
                                :CHAVECONTABCO, :CHAVEUSUARIO, :CHAVEUSUARIO,
                                CHAVECLIFOR, CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, 0
                            FROM PAGAR
                            WHERE CHAVE=:CHAVECONTA;
                        END
                        LANCBANCARIOSIMPLES='N';
                    END
                    INSERT INTO CAIXA (CHAVEEMPRESA, CHAVEPLANOCTO, CHAVECENTROCTO,
                                   LANCAMENTO, HISTORICO, DOCUMENTO,
                                   COMPETENCIA, VALOR,  NL, LANCBANCARIO, CHAVECONTABCO,
                                   CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                                   CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO)
                    SELECT :CHAVEEMP, :NOVOPLANOCTA, 1,
                        :LANCAMENTO, SUBSTRING('GERADO AUT. '||:HISTORICO FROM 1 FOR 100), :DOCUMENTO,
                        :COMPETENCIA, VALOR, :NLATUAL, 'S', :CHAVECONTABCO,
                        :CHAVEUSUARIO, :CHAVEUSUARIO,
                        CHAVECLIFOR, CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, 0
                    FROM LANCBCO
                    WHERE CHAVE=:CHAVELANCBCO;
                END
            END
    
            IF ((:CHAVEPLANOCONTA = :CHAVEPCTRANSFBCOCAIXA) AND (:CHAVEPLANOCONTA IS NOT NULL)) THEN BEGIN
                INSERT INTO CAIXA (CHAVEEMPRESA, CHAVEPLANOCTO, CHAVECENTROCTO,
                               LANCAMENTO, HISTORICO, DOCUMENTO,
                               VALOR, NL, LANCBANCARIO, CHAVECONTABCO,
                               CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                               CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO)
                VALUES (:CHAVEEMP, :CHAVEPLANOCONTA, 1,
                    :LANCAMENTO, SUBSTRING('GERADO AUT. '||:HISTORICO FROM 1 FOR 100), :DOCUMENTO,
                    :VALOR,  :NLATUAL, 'S', :CHAVECONTABCO,
                    :CHAVEUSUARIO, :CHAVEUSUARIO,
                    :CHAVECLIFOR, :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, 0);
            END
            IF ((:CHAVEPLANOCONTA <> :CHAVEPCTRANSFBCOCAIXA) AND
                (:CHAVEPLANOCONTA IS NOT NULL) AND (:LANCBANCARIOSIMPLES='S'))  THEN BEGIN
                INSERT INTO CAIXA (CHAVEEMPRESA, CHAVEPLANOCTO, CHAVECENTROCTO,
                               LANCAMENTO, HISTORICO, DOCUMENTO,
                               VALOR,  NL, LANCBANCARIO, CHAVECONTABCO,
                               CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                               CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO)
                VALUES (:CHAVEEMP, :CHAVEPLANOCONTA, :CHAVECENTROCUSTO,
                    :LANCAMENTO, :HISTORICO,  :DOCUMENTO,
                    :VALOR,  :NLATUAL, 'S', :CHAVECONTABCO,
                    :CHAVEUSUARIO, :CHAVEUSUARIO,
                    :CHAVECLIFOR, :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, 0);
            END
        END ELSE BEGIN
            IF ((:CHAVEPLANOCONTA = :CHAVEPCTRANSFBCOCAIXA) AND (:CHAVEPLANOCONTA IS NOT NULL)) THEN BEGIN
                INSERT INTO CAIXA (CHAVEEMPRESA, CHAVEPLANOCTO, CHAVECENTROCTO,
                               LANCAMENTO, HISTORICO, DOCUMENTO,
                               VALOR, NL, LANCBANCARIO, CHAVECONTABCO,
                               CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                               CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO)
                VALUES (:CHAVEEMP, :CHAVEPLANOCONTA, 1,
                    :LANCAMENTO, SUBSTRING('GERADO AUT. '||:HISTORICO FROM 1 FOR 100), :DOCUMENTO,
                    :VALOR, :NLATUAL, 'S', :CHAVECONTABCO,
                    :CHAVEUSUARIO, :CHAVEUSUARIO,
                    :CHAVECLIFOR, :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, 0);
            END
        END
    END
    /*
        CHAMADAS:
            - frmCompLctoBco: Usada para gerar caixa em lancamentos bancarios
    */
END^


ALTER PROCEDURE GERA_COMISSAOGRUPO (
    CHAVEDOC INTEGER,
    CHAVEEMP INTEGER,
    TIPO CHAR(3),
    CHAVEDOCDEV INTEGER,
    ATIVO INTEGER)
AS
declare variable CHAVECLIFOR integer;
declare variable CHAVEPRODUTO integer;
declare variable VLRTOTAL numeric(18,4);
declare variable NLNF double precision;
declare variable CHAVEGRUPO integer;
declare variable ALIQCOMISSAO numeric(18,4);
declare variable DOCUMENTO varchar(9);
declare variable NL double precision;
declare variable CHAVEVENDEDORAUX integer;
declare variable ORIGEMDOC integer;
declare variable ORIGEMDEVOLV integer;
declare variable VDATANF date;
begin
    IF (:TIPO='NF') THEN BEGIN
        FOR SELECT I.CHAVEPRODUTO, I.VLRTOTAL, NF.NUMERONF,
            NF.CHAVECLIFOR, I.NL, NF.DATANF FROM ITENSNFSAIDA I
            INNER JOIN NFSAIDA NF ON (NF.CHAVE=I.CHAVENFSAIDA) AND (NF.CHAVE=:CHAVEDOC)
            INNER JOIN CFOP C ON C.CHAVE = I.CHAVECFOP AND C.CLASSIFICACAO = 1
            INNER JOIN CFOPOPERFISCAIS CFOPER ON CFOPER.CHAVE = I.CHAVECFOPOPERFISCAIS AND CFOPER.GERARFINANCEIRO = 0
            WHERE (I.ATIVO=1)
            INTO :CHAVEPRODUTO, :VLRTOTAL, :DOCUMENTO,
                 :CHAVECLIFOR, :NL, :VDATANF
            DO BEGIN
                CHAVEGRUPO = NULL;
                SELECT P.CHAVEGRUPO  FROM  PRODUTO P
                WHERE (P.ATIVO=1) AND (:CHAVEPRODUTO=P.CHAVE)
                INTO :CHAVEGRUPO;
                IF (:CHAVEGRUPO IS NOT NULL) THEN BEGIN
                    FOR SELECT VSGP.ALIQCOMISSAO, VSGP.CHAVEVENDEDOR FROM VENDGRUPOSUBGRUPO VSGP
                        WHERE (ATIVO=1) AND (ORIGEM=0) AND (VSGP.CHAVEORIGEM=:CHAVEGRUPO) AND
                               VSGP.CHAVEVENDEDOR IN (SELECT CO.CHAVEVENDEDOR FROM COMISSAO CO
                                  WHERE (CO.ATIVO=1) AND (CO.ORIGEM=1) AND (CO.CHAVEDOC=:CHAVEDOC) AND (CO.NL=:NL))
                        INTO :ALIQCOMISSAO, :CHAVEVENDEDORAUX
                        DO BEGIN
                            IF (:ALIQCOMISSAO IS NOT NULL) THEN BEGIN
                                INSERT INTO COMISSAOGRUPO
                                    (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                                    CHAVEPRODUTO, CHAVEGRUPO, ORIGEMDOC, DOCUMENTO, DATA,
                                    ALIQCOMISSAO, VALORDOC, NL, CHAVEDOC)
                                VALUES
                                    (:ATIVO, :CHAVEEMP, :CHAVECLIFOR, :CHAVEVENDEDORAUX,
                                    :CHAVEPRODUTO, :CHAVEGRUPO, 2, :DOCUMENTO, :VDATANF,
                                    :ALIQCOMISSAO, :VLRTOTAL, :NL, :CHAVEDOC);
                            END
                        END
                END
        END
    END
    -- Estorno de comissao por grupo
    IF ((:TIPO='NFE') OR (:TIPO='CFE')) THEN BEGIN
        If (:TIPO='NFE') THEN BEGIN
            ORIGEMDOC = 2;
            ORIGEMDEVOLV = 0;
        END ELSE BEGIN
            ORIGEMDOC = 3;
            ORIGEMDEVOLV = 1;
        END

        FOR SELECT CHAVEPRODUTO, NL FROM ITENSNFENTRADAPROD
        WHERE (ATIVO=1) AND (CHAVENFENTRADA=:CHAVEDOC) AND (ORIGEMDEVOLV=:ORIGEMDEVOLV) AND (CHAVEDOCDEVOLV=:CHAVEDOCDEV)
        INTO :CHAVEPRODUTO, :NLNF
        DO BEGIN
            INSERT INTO COMISSAOGRUPO
                (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                CHAVEPRODUTO, CHAVEGRUPO, ORIGEMDOC, DOCUMENTO, DATA,
                ALIQCOMISSAO, VALORDOC, NL, CHAVEDOC)
            SELECT :ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                CHAVEPRODUTO, CHAVEGRUPO, ORIGEMDOC, DOCUMENTO, 'NOW',
                ALIQCOMISSAO, VALORDOC*-1, :NLNF, :CHAVEDOC
                FROM COMISSAOGRUPO
                WHERE (ATIVO=1) AND (CHAVEDOC=:CHAVEDOCDEV) AND (ORIGEMDOC=:ORIGEMDOC)
                AND CHAVEPRODUTO=:CHAVEPRODUTO;
        END
    END
    IF (:TIPO='PD') THEN BEGIN
        FOR SELECT I.CHAVEPRODUTO, I.VLRTOTAL, CF.NUMEROCOO,
            CF.CHAVECLIFOR, I.NL, I.DATA FROM ITENSCUPOM I
            INNER JOIN CUPOMFISCAL CF ON (CF.CHAVE=I.CHAVECUPOM)
            WHERE (CF.CHAVE=:CHAVEDOC) AND (CF.ATIVO=1) AND (I.ATIVO=1)
            INTO :CHAVEPRODUTO, :VLRTOTAL, :DOCUMENTO,
                :CHAVECLIFOR, :NL, :VDATANF
            DO BEGIN
                CHAVEGRUPO = NULL;
                SELECT P.CHAVEGRUPO  FROM  PRODUTO P
                WHERE (P.ATIVO=1) AND (:CHAVEPRODUTO=P.CHAVE)
                INTO :CHAVEGRUPO;
                IF (:CHAVEGRUPO IS NOT NULL) THEN BEGIN
                    FOR SELECT VSGP.ALIQCOMISSAO, VSGP.CHAVEVENDEDOR FROM VENDGRUPOSUBGRUPO VSGP
                        WHERE (ORIGEM=0) AND (VSGP.CHAVEORIGEM=:CHAVEGRUPO) AND (VSGP.ATIVO=1) AND
                               VSGP.CHAVEVENDEDOR IN (SELECT CO.CHAVEVENDEDOR FROM COMISSAO CO
                                  WHERE (CO.ATIVO=1) AND (CO.ORIGEM=6) AND (CO.CHAVEDOC=:CHAVEDOC) AND (CO.NL=:NL))
                        INTO :ALIQCOMISSAO, :CHAVEVENDEDORAUX
                        DO BEGIN
                            IF (:ALIQCOMISSAO IS NOT NULL) THEN BEGIN
                                INSERT INTO COMISSAOGRUPO
                                    (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                                    CHAVEPRODUTO, CHAVEGRUPO, ORIGEMDOC, DOCUMENTO, DATA,
                                    ALIQCOMISSAO, VALORDOC, NL, CHAVEDOC)
                                VALUES
                                    (:ATIVO, :CHAVEEMP, :CHAVECLIFOR, :CHAVEVENDEDORAUX,
                                    :CHAVEPRODUTO, :CHAVEGRUPO, 3, :DOCUMENTO, :VDATANF,
                                    :ALIQCOMISSAO, :VLRTOTAL, :NL, :CHAVEDOC);
                            END
                        END
                END
        END
    END
    /*
    CHAMADAS :
        - FRMDLGFATURAMENTO: USADA PARA GERAR COMISSAO NOTA FISCAL FORMULARIO
        - CHSERVER - USADA PARA GERAR COMISSAO NOTA FISCAL NFe
        - CHPDV - USADA PARA GERAR COMISSAO CUPOM FISCAL/NFCE/SAT-CFE
    */
end^


ALTER PROCEDURE GERA_COMISSAOSUBGRUPO (
    CHAVEDOC INTEGER,
    CHAVEEMP INTEGER,
    TIPO CHAR(3),
    CHAVEDOCDEV INTEGER,
    ATIVO INTEGER)
AS
declare variable CHAVECLIFOR integer;
declare variable CHAVEPRODUTO integer;
declare variable VLRTOTAL numeric(18,4);
declare variable NLDOC double precision;
declare variable CHAVESUBGRUPO integer;
declare variable ALIQCOMISSAO numeric(18,4);
declare variable DOCUMENTO varchar(9);
declare variable NL double precision;
declare variable CHAVEVENDEDORAUX integer;
declare variable ORIGEMDOC integer;
declare variable ORIGEMDEVOLV integer;
begin
    IF (:TIPO='NF') THEN BEGIN
        FOR SELECT I.CHAVEPRODUTO, I.VLRTOTAL, NF.NUMERONF,
            NF.CHAVECLIFOR, I.NL FROM ITENSNFSAIDA I
            INNER JOIN NFSAIDA NF ON (NF.CHAVE=I.CHAVENFSAIDA)
            INNER JOIN CFOP C ON C.CHAVE = I.CHAVECFOP AND C.CLASSIFICACAO = 1
            INNER JOIN CFOPOPERFISCAIS CFOPER ON CFOPER.CHAVE = I.CHAVECFOPOPERFISCAIS AND CFOPER.GERARFINANCEIRO = 0
            WHERE (NF.CHAVE=:CHAVEDOC) AND (I.ATIVO=1)
            INTO :CHAVEPRODUTO, :VLRTOTAL, :DOCUMENTO,
                 :CHAVECLIFOR, :NL
            DO BEGIN
                CHAVESUBGRUPO = NULL;
                SELECT P.CHAVESUBGRUPO FROM  PRODUTO P
                WHERE (P.ATIVO=1) AND (:CHAVEPRODUTO=P.CHAVE)
                INTO :CHAVESUBGRUPO;
                IF (:CHAVESUBGRUPO IS NOT NULL) THEN BEGIN
                    FOR SELECT VSGP.ALIQCOMISSAO, VSGP.CHAVEVENDEDOR FROM VENDGRUPOSUBGRUPO VSGP
                        WHERE (VSGP.ATIVO=1) AND (VSGP.ORIGEM=1) AND (VSGP.CHAVEORIGEM=:CHAVESUBGRUPO) AND
                               VSGP.CHAVEVENDEDOR IN (SELECT CO.CHAVEVENDEDOR FROM COMISSAO CO
                                  WHERE (CO.ATIVO=1) AND (CO.ORIGEM=1) AND (CO.CHAVEDOC=:CHAVEDOC) AND (CO.NL=:NL))
                        INTO :ALIQCOMISSAO, :CHAVEVENDEDORAUX
                        DO BEGIN
                            IF (:ALIQCOMISSAO IS NOT NULL) THEN BEGIN
                                INSERT INTO COMISSAOSUBGRUPO
                                    (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                                    CHAVEPRODUTO, CHAVESUBGRUPO, ORIGEMDOC, DOCUMENTO, DATA,
                                    ALIQCOMISSAO, VALORDOC, NL, CHAVEDOC)
                                VALUES
                                    (:ATIVO, :CHAVEEMP, :CHAVECLIFOR, :CHAVEVENDEDORAUX,
                                    :CHAVEPRODUTO, :CHAVESUBGRUPO, 2, :DOCUMENTO, 'NOW',
                                    :ALIQCOMISSAO, :VLRTOTAL, :NL, :CHAVEDOC);
                            END
                        END
                END
        END
    END
    -- Estorno de nota fiscal de saida e cupom, atraves da nf entrada
    IF ((:TIPO='NFE') OR (:TIPO='CFE')) THEN BEGIN
        If (:TIPO='NFE') THEN BEGIN
            ORIGEMDOC = 2;
            ORIGEMDEVOLV = 0;
        END ELSE BEGIN
            ORIGEMDOC = 3;
            ORIGEMDEVOLV = 1;
        END
        FOR SELECT CHAVEPRODUTO, NL FROM ITENSNFENTRADAPROD
        WHERE (ATIVO=1) AND (CHAVENFENTRADA=:CHAVEDOC) AND (ORIGEMDEVOLV=:ORIGEMDEVOLV)  AND (CHAVEDOCDEVOLV=:CHAVEDOCDEV)
        INTO :CHAVEPRODUTO, :NLDOC
        DO BEGIN
            INSERT INTO COMISSAOSUBGRUPO
                (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                CHAVEPRODUTO, CHAVESUBGRUPO, ORIGEMDOC, DOCUMENTO, DATA,
                ALIQCOMISSAO, VALORDOC, NL, CHAVEDOC)
            SELECT
                :ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                CHAVEPRODUTO, CHAVESUBGRUPO, ORIGEMDOC, DOCUMENTO, 'NOW',
                ALIQCOMISSAO, VALORDOC*-1, :NLDOC, :CHAVEDOC
            FROM COMISSAOSUBGRUPO
            WHERE ATIVO=1 AND CHAVEDOC=:CHAVEDOCDEV AND ORIGEMDOC=:ORIGEMDOC AND CHAVEPRODUTO=:CHAVEPRODUTO;
        END
    END
    IF (:TIPO='PD') THEN BEGIN
        FOR SELECT I.CHAVEPRODUTO, I.VLRTOTAL, CF.NUMEROCOO,
        CF.CHAVECLIFOR, I.NL
        FROM ITENSCUPOM I
        INNER JOIN CUPOMFISCAL CF ON (CF.CHAVE=I.CHAVECUPOM) AND (CF.ATIVO=1)
        WHERE (CF.CHAVE=:CHAVEDOC) AND (CF.ATIVO=1) AND (I.ATIVO=1)
        INTO :CHAVEPRODUTO, :VLRTOTAL, :DOCUMENTO,
        :CHAVECLIFOR, :NL
        DO BEGIN
            CHAVESUBGRUPO = NULL;
            SELECT P.CHAVESUBGRUPO FROM  PRODUTO P
            WHERE (P.ATIVO=1) AND (:CHAVEPRODUTO=P.CHAVE)
            INTO :CHAVESUBGRUPO;
            IF (:CHAVESUBGRUPO IS NOT NULL) THEN BEGIN
                FOR SELECT VSGP.ALIQCOMISSAO, VSGP.CHAVEVENDEDOR FROM VENDGRUPOSUBGRUPO VSGP
                    WHERE (VSGP.ATIVO=1) AND (VSGP.ORIGEM=1) AND (VSGP.CHAVEORIGEM=:CHAVESUBGRUPO) AND
                           VSGP.CHAVEVENDEDOR IN (SELECT CO.CHAVEVENDEDOR FROM COMISSAO CO
                              WHERE (CO.ATIVO=1) AND (CO.ORIGEM=6) AND (CO.CHAVEDOC=:CHAVEDOC) AND (CO.NL=:NL))
                INTO :ALIQCOMISSAO, :CHAVEVENDEDORAUX
                DO BEGIN

                    IF (:ALIQCOMISSAO IS NOT NULL) THEN BEGIN
                        INSERT INTO COMISSAOSUBGRUPO
                        (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, CHAVEVENDEDOR,
                        CHAVEPRODUTO, CHAVESUBGRUPO, ORIGEMDOC, DOCUMENTO, DATA,
                        ALIQCOMISSAO, VALORDOC, NL, CHAVEDOC)
                        VALUES
                        (:ATIVO, :CHAVEEMP, :CHAVECLIFOR, :CHAVEVENDEDORAUX,
                        :CHAVEPRODUTO, :CHAVESUBGRUPO, 3, :DOCUMENTO, CURRENT_DATE,
                        :ALIQCOMISSAO, :VLRTOTAL, :NL, :CHAVEDOC);
                    END
                END
            END
        END
    END
    /*
    CHAMADAS :
        - FRMDLGFATURAMENTO: USADA PARA GERAR COMISSAO NOTA FISCAL FORMULARIO
        - CHSERVER - USADA PARA GERAR COMISSAO NOTA FISCAL NFe
        - CHPDV - USADA PARA GERAR COMISSAO CUPOM FISCAL/NFCE/SAT-CFE
    */
end^


ALTER PROCEDURE GERA_CONTASPAGARCOT (
    CHAVECOT INTEGER,
    PARC INTEGER,
    DATAVENC DATE,
    VLR NUMERIC(18,4),
    CHAVEUSUARIO INTEGER,
    CHAVECONTACAIXA INTEGER,
    ECHAVEEMPCAIXA INTEGER,
    PCHAVEEMP INTEGER)
AS
declare variable "COT" varchar(6);
declare variable CHAVECENTROCUSTO integer;
declare variable CLI integer;
declare variable DATANF date;
declare variable NPARCELAS integer;
declare variable FORMAPGTO smallint;
declare variable NLATUAL double precision;
declare variable RAZAOSOCIAL varchar(100);
declare variable CHAVEPLANOCONTA integer;
declare variable CHAVEPAGAR integer;
declare variable CHAVECTABANCARIA integer;
declare variable CHAVEOPERTITULOS integer;
declare variable VENC1 integer;
declare variable ENTRADANF date;
declare variable TIPOPAGAMENTO smallint;
declare variable CODCLIFOR varchar(6);
BEGIN
    SELECT C.NUMEROCO, C.CHAVECLIFOR, C.DATA, C.DATA, CP.PARCELAS,
    CP.FORMA, C.NL, CLI.CODIGO, CLI.RAZAOSOCIAL, C.CHAVECTABANCARIA,
    C.CHAVEOPERACOESTITULOS, CP.VENC1, COALESCE(C.CHAVEPLANOCONTA,0),
    C.TIPOPAGAMENTO, COALESCE(C.CHAVECENTROCUSTO,0)
    FROM COTACAO C
    INNER JOIN CONDPGTO CP ON (C.CHAVECONDPGTO=CP.CHAVE)
    INNER JOIN CLIFOR CLI ON (C.CHAVECLIFOR=CLI.CHAVE)
    WHERE (C.CHAVE=:CHAVECOT)
    INTO :COT, :CLI, :DATANF, :ENTRADANF, :NPARCELAS,
    :FORMAPGTO, :NLATUAL, :CODCLIFOR, :RAZAOSOCIAL, :CHAVECTABANCARIA,
    :CHAVEOPERTITULOS, :VENC1, :CHAVEPLANOCONTA,
    :TIPOPAGAMENTO, :CHAVECENTROCUSTO;
    IF (:CHAVEPLANOCONTA = 0) THEN BEGIN
        IF (:TIPOPAGAMENTO = 0) THEN BEGIN
            SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
            WHERE (CHAVE=4)
            INTO :CHAVEPLANOCONTA;
        END
        IF (:TIPOPAGAMENTO = 1) THEN BEGIN
            SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
            WHERE (CHAVE=5)
            INTO :CHAVEPLANOCONTA;
        END
        UPDATE COTACAO SET
        CHAVEPLANOCONTA=:CHAVEPLANOCONTA
        WHERE (CHAVE=:CHAVECOT);
    END
    IF (:CHAVECENTROCUSTO = 0) THEN BEGIN
        CHAVECENTROCUSTO = 2;
        UPDATE COTACAO SET
        CHAVECENTROCUSTO=:CHAVECENTROCUSTO
        WHERE CHAVE=:CHAVECOT;
    END
    CHAVEPAGAR = GEN_ID(GEN_PAGAR_ID,1);
    INSERT INTO PAGAR
        (CHAVE, CHAVECLIFOR, DATACONTA, DATAENTRADA, DOCUMENTO, PARCELA, VALOR,
        VENCIMENTO, COMPETENCIA, TOTPARC, TIPO, STATUS, CHAVEPLANOCTO, CHAVECENTROCTO, CHAVEEMPRESA,
        NL, DESCRICAO, ORIGEM, ABATIMENTO, ACRESCIMO, VLRPAGO,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
    VALUES (:CHAVEPAGAR, :CLI, :DATANF, :ENTRADANF, :COT, :PARC, :VLR,
        :DATAVENC, SUBSTRING(CAST(:DATAVENC AS VARCHAR(10)) FROM 6 FOR 2)||'/'|| SUBSTRING(CAST(:DATAVENC AS VARCHAR(10)) FROM 1 FOR 4),
        :NPARCELAS, :FORMAPGTO, 1, :CHAVEPLANOCONTA, :CHAVECENTROCUSTO, :PCHAVEEMP,
        :NLATUAL, SUBSTRING('ORCAMENTO ENTREGA FUTURA '||:COT||' - FORN. '||:CODCLIFOR||' - '||:RAZAOSOCIAL FROM 1 FOR 100), 5, 0, 0, 0,
        :CHAVECTABANCARIA, :CHAVEOPERTITULOS, :CHAVEUSUARIO, :CHAVEUSUARIO);
    IF ((:VENC1 = 0) AND (:PARC=1)) THEN
       EXECUTE PROCEDURE BAIXAPAGRECAUTOMATICO(:NLATUAL, 'P', :CHAVEPAGAR, :CHAVEUSUARIO, :CHAVECONTACAIXA, :CHAVECTABANCARIA, :ECHAVEEMPCAIXA);
    /*
        CHAMADAS:
            - frmCotacao: Usada para gerar contas a pagar quando for orcamento de compra tipo entrega futura
    */
END^


ALTER PROCEDURE GERA_CONTASPAGARNF (
    CHAVENF INTEGER,
    PCHAVEEMP INTEGER,
    PARC INTEGER,
    DATAVENC DATE,
    VLR NUMERIC(18,4),
    CHAVEUSUARIO INTEGER,
    CHAVECONTACAIXA INTEGER,
    ECHAVEEMPCAIXA INTEGER)
AS
declare variable NF varchar(9);
declare variable CHAVECENTROCUSTO integer;
declare variable CLI integer;
declare variable DATANF date;
declare variable NPARCELAS integer;
declare variable FORMAPGTO smallint;
declare variable NLATUAL double precision;
declare variable RAZAOSOCIAL varchar(100);
declare variable CHAVEPLANOCONTA integer;
declare variable CHAVEPAGAR integer;
declare variable CHAVECTABANCARIA integer;
declare variable CHAVEOPERTITULOS integer;
declare variable VENC1 integer;
declare variable ENTRADANF date;
declare variable TIPOPAGAMENTO smallint;
declare variable CODCLIFOR varchar(6);
BEGIN
    /* ESTA PROC GERA UM REGISTRO NA TABELA DE CONTAS A PAGAR PELA TELA DE NF DE ENTRADA
    SELECIONA OS DADOS DA NF E DAS CONDPAGTO E GUARDA NAS VARIAVEIS */
    SELECT N.NUMERONF, N.CHAVECLIFOR, N.EMISSAO, N.ENTRADA, C.PARCELAS,
    N.FORMAPGTO, N.NL, CLIFOR.CODIGO, CLIFOR.RAZAOSOCIAL, N.CHAVECTABANCARIA,
    N.CHAVEOPERACOESTITULOS, C.VENC1, COALESCE(CHAVEPLANOCONTA,0),
    N.TIPOPAGAMENTO, COALESCE(CHAVECENTROCUSTO,0)
    FROM NFENTRADA N
    INNER JOIN CONDPGTO C ON (C.CHAVE=N.CHAVECONDPGTO)
    INNER JOIN CLIFOR ON (CLIFOR.CHAVE=N.CHAVECLIFOR)
    WHERE N.CHAVE=:CHAVENF
    INTO :NF, :CLI, :DATANF, :ENTRADANF, :NPARCELAS,
    :FORMAPGTO, :NLATUAL, :CODCLIFOR, :RAZAOSOCIAL, :CHAVECTABANCARIA,
    :CHAVEOPERTITULOS, :VENC1, :CHAVEPLANOCONTA,
    :TIPOPAGAMENTO, :CHAVECENTROCUSTO;
    IF (:CHAVEPLANOCONTA = 0) THEN BEGIN
        IF (:TIPOPAGAMENTO = 1) THEN BEGIN
            SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
            WHERE CHAVE = 4
            INTO :CHAVEPLANOCONTA;
        END
        IF (:TIPOPAGAMENTO = 0) THEN BEGIN
            SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
            WHERE CHAVE = 5
            INTO :CHAVEPLANOCONTA;
        END
        UPDATE NFENTRADA SET
            CHAVEPLANOCONTA=:CHAVEPLANOCONTA
        WHERE CHAVE=:CHAVENF;
    END
    IF (:CHAVECENTROCUSTO = 0 ) THEN BEGIN
        CHAVECENTROCUSTO = 2;
        UPDATE NFENTRADA SET
            CHAVECENTROCUSTO=:CHAVECENTROCUSTO
        WHERE CHAVE=:CHAVENF;
    END
    CHAVEPAGAR = GEN_ID(GEN_PAGAR_ID,1);
    INSERT INTO PAGAR
        (CHAVE, CHAVECLIFOR, DATACONTA, DATAENTRADA, DOCUMENTO, PARCELA, VALOR,
        VENCIMENTO, COMPETENCIA, TOTPARC, TIPO, STATUS, CHAVEPLANOCTO, CHAVECENTROCTO, CHAVEEMPRESA,
        NL, DESCRICAO, ORIGEM, ABATIMENTO, ACRESCIMO, VLRPAGO,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
    VALUES (:CHAVEPAGAR, :CLI, :DATANF, :ENTRADANF, :NF, :PARC, :VLR,
        :DATAVENC, SUBSTRING(CAST(:DATAVENC AS VARCHAR(10)) FROM 6 FOR 2)||'/'|| SUBSTRING(CAST(:DATAVENC AS VARCHAR(10)) FROM 1 FOR 4),
        :NPARCELAS, :FORMAPGTO, 1, :CHAVEPLANOCONTA, :CHAVECENTROCUSTO, :PCHAVEEMP,
        :NLATUAL, SUBSTRING('NF ENTRADA '||:NF||' - FORN. '||:CODCLIFOR||' - '||:RAZAOSOCIAL FROM 1 FOR 100), 0, 0, 0, 0,
        :CHAVECTABANCARIA, :CHAVEOPERTITULOS, :CHAVEUSUARIO, :CHAVEUSUARIO);
    IF ((:VENC1 = 0) AND (:PARC = 1)) THEN
       EXECUTE PROCEDURE BAIXAPAGRECAUTOMATICO(:NLATUAL, 'P', :CHAVEPAGAR, :CHAVEUSUARIO, :CHAVECONTACAIXA, :CHAVECTABANCARIA, :ECHAVEEMPCAIXA);
    /*
        CHAMADAS:
            - frmNFEntrada/CHMonitor: Usada para gerar contas a pagar quando for NF de compra
    */
END^


ALTER PROCEDURE GERA_CONTASRECCOT (
    CHAVECOT INTEGER,
    PCHAVEEMP INTEGER,
    PARC INTEGER,
    DATAVENC DATE,
    VLRSERVICO NUMERIC(18,6),
    VLRPRODUTO NUMERIC(18,6),
    VLR NUMERIC(18,6),
    CHAVEUSUARIO INTEGER,
    CHAVECONTACAIXA INTEGER,
    ECHAVEEMPCAIXA INTEGER)
AS
declare variable "COT" varchar(6);
declare variable CHAVECENTROCUSTO integer;
declare variable CHAVERECEBER integer;
declare variable CLI integer;
declare variable NPARCELAS integer;
declare variable FORMAPGTO smallint;
declare variable NLATUAL double precision;
declare variable RAZAOSOCIAL varchar(100);
declare variable CHAVEPLANOCONTA integer;
declare variable CHAVECTABANCARIA integer;
declare variable CHAVEOPERTITULOS integer;
declare variable VENC1 integer;
declare variable TIPOPAGAMENTO smallint;
declare variable DATACOT date;
declare variable CODCLIFOR varchar(6);
BEGIN
    -- SELECIONAR OS DADOS DO ORCAMENTO E DAS COND PGTO E GUARDAR NAS VARIAVEIS
    SELECT C.NUMEROCO, C.CHAVECLIFOR, C.DATA, CP.PARCELAS,
    CP.FORMA, C.NL, CLI.CODIGO, CLI.RAZAOSOCIAL, C.CHAVECTABANCARIA,
    C.CHAVEOPERACOESTITULOS, CP.VENC1, COALESCE(C.CHAVEPLANOCONTA,0),
    C.TIPOPAGAMENTO, COALESCE(C.CHAVECENTROCUSTO,0)
    FROM COTACAO C
    INNER JOIN CONDPGTO CP ON (C.CHAVECONDPGTO=CP.CHAVE)
    INNER JOIN CLIFOR CLI ON (C.CHAVECLIFOR=CLI.CHAVE)
    WHERE (C.CHAVE=:CHAVECOT)
    INTO :COT, :CLI, :DATACOT, :NPARCELAS,
    :FORMAPGTO, :NLATUAL, :CODCLIFOR, :RAZAOSOCIAL, :CHAVECTABANCARIA,
    :CHAVEOPERTITULOS, :VENC1, :CHAVEPLANOCONTA,
    :TIPOPAGAMENTO, :CHAVECENTROCUSTO;

    -- VERIFICAR PLANO DE CONTA
    IF (:CHAVEPLANOCONTA = 0) THEN BEGIN
        -- PLANO DE CONTA PARA VENDA A PRAZO
        IF (:TIPOPAGAMENTO = 0) THEN BEGIN
            SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
            WHERE (CHAVE=6)
            INTO :CHAVEPLANOCONTA;
        END
        -- PLANO DE CONTA PARA VENDA A VISTA
        IF (:TIPOPAGAMENTO = 1) THEN BEGIN
            SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
            WHERE (CHAVE=7)
            INTO :CHAVEPLANOCONTA;
        END
        UPDATE COTACAO SET
        CHAVEPLANOCONTA=:CHAVEPLANOCONTA
        WHERE (CHAVE=:CHAVECOT);
    END
    IF (:CHAVECENTROCUSTO = 0) THEN BEGIN
        CHAVECENTROCUSTO = 2;
        UPDATE COTACAO SET
        CHAVECENTROCUSTO=:CHAVECENTROCUSTO
        WHERE CHAVE=:CHAVECOT;
    END
    CHAVERECEBER = GEN_ID(GEN_RECEBER_ID,1);
    INSERT INTO RECEBER
        (CHAVE, CHAVECLIFOR, DATACONTA, DOCUMENTO, PARCELA, VALOR,
        VENCIMENTO, TOTPARC, TIPO, STATUS, CHAVEEMPRESA, RECEBPARCIAL,
        NL, CHAVEPLANOCTO, CHAVECENTROCTO, DESCRICAO, VALORPRODUTO, VALORSERVICO,
        ORIGEM, CHAVECTABANCARIA, CHAVEOPERACOESTITULOS,
        CHAVEDOC, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
    VALUES (:CHAVERECEBER, :CLI, :DATACOT, :COT, :PARC, :VLR,
        :DATAVENC, :NPARCELAS, :FORMAPGTO, 1, :PCHAVEEMP, 0,
        :NLATUAL, :CHAVEPLANOCONTA, :CHAVECENTROCUSTO, SUBSTRING('ORCAMENTO ENTREGA FUTURA '||:COT||' - CLIENTE '||:CODCLIFOR||' - '||:RAZAOSOCIAL FROM 1 FOR 100), :VLRPRODUTO, :VLRSERVICO,
        5, :CHAVECTABANCARIA, :CHAVEOPERTITULOS,
        :CHAVECOT, :CHAVEUSUARIO, :CHAVEUSUARIO);
    -- Se for a vista ou com entrada
    IF ((:VENC1 = 0) AND (:PARC=1)) THEN
       EXECUTE PROCEDURE BAIXAPAGRECAUTOMATICO(:NLATUAL, 'R', :CHAVERECEBER, :CHAVEUSUARIO, :CHAVECONTACAIXA, :CHAVECTABANCARIA, :ECHAVEEMPCAIXA);

    INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
    SELECT CHAVEEMPRESA, :CHAVERECEBER, CHAVEVENDEDOR, 7, :NLATUAL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA
    FROM COMISSAO
    WHERE (ATIVO=1) AND (ORIGEM=2) AND (CHAVEDOC=:CHAVECOT);

    /*
        CHAMADAS:
            - frmCotacao: Usada para gerar contas a receber quando for orcamento de venda tipo entrega futura
    */
END^


ALTER PROCEDURE GERA_FINANCEIRONF (
    CHAVENF INTEGER,
    PARC INTEGER,
    DATAVENC DATE,
    VLR NUMERIC(18,4),
    CHAVEEMP INTEGER,
    VLRPRODUTO NUMERIC(18,4),
    VLRSERVICO NUMERIC(18,4),
    CHAVEUSUARIO INTEGER,
    CHAVECONTACAIXA INTEGER,
    ECHAVEEMPCAIXA INTEGER,
    EGERARPONTUACAO CHAR(1),
    ECHAVEEMPPONTUACAO INTEGER)
AS
declare variable NF varchar(9);
declare variable CHAVEPEDIDO integer;
declare variable CODOPERFISC varchar(10);
declare variable MODELONF varchar(2);
declare variable VLRREFERENCIA numeric(18,2);
declare variable PONTOSBLOQ numeric(18,6);
declare variable AOBSPONT varchar(100);
declare variable PONTOSMOV numeric(18,6);
declare variable CLI integer;
declare variable CHAVECENTROCUSTO integer;
declare variable DATANF date;
declare variable NPARCELAS integer;
declare variable FORMAPGTO integer;
declare variable RAZAOSOCIAL varchar(100);
declare variable NLATUAL double precision;
declare variable CHAVECONDPGTO integer;
declare variable CHAVEPLANOCONTA integer;
declare variable CHAVERECEBER integer;
declare variable CHAVECTABANCARIA integer;
declare variable CHAVEOPERTITULOS integer;
declare variable VENC1 integer;
declare variable CODCLIFOR varchar(6);
BEGIN
    VLRREFERENCIA = 0;
    PONTOSMOV = 0;
    PONTOSBLOQ = 0;
    /* ESTA PROC GERA UM REGISTRO NA TABELA DE CONTAS A RECEBER PELA NF
      SELECIONA OS DADOS DA NF E DAS CONDPAGTO E GUARDA NAS VARIAVEIS */
    SELECT N.CHAVEPEDIDO, N.NUMERONF, N.CHAVECLIFOR, N.DATANF, C.PARCELAS, N.FORMAPGTO, N.CHAVECONDPGTO,
    N.NL, CLIFOR.CODIGO, CLIFOR.RAZAOSOCIAL, N.CHAVECTABANCARIA,
    N.CHAVEOPERACOESTITULOS, C.VENC1, COALESCE(N.CHAVEPLANOCONTA,0) , COALESCE(N.CHAVECENTROCUSTO,0), CF.CODIGO,
    S.MODELO
    FROM NFSAIDA N
    INNER JOIN CONDPGTO C ON (C.CHAVE=N.CHAVECONDPGTO)
    INNER JOIN CLIFOR ON (CLIFOR.CHAVE=N.CHAVECLIFOR)
    INNER JOIN CFOPOPERFISCAIS CF ON (CF.CHAVE=N.CHAVECFOPOPERFISCAIS)
    INNER JOIN SERIENF S ON S.CHAVE = N.CHAVESERIENF
    WHERE (N.CHAVE=:CHAVENF)
    INTO :CHAVEPEDIDO, :NF, :CLI, :DATANF, :NPARCELAS, :FORMAPGTO, :CHAVECONDPGTO,
    :NLATUAL, :CODCLIFOR, :RAZAOSOCIAL, :CHAVECTABANCARIA,
    :CHAVEOPERTITULOS, :VENC1, :CHAVEPLANOCONTA, :CHAVECENTROCUSTO, :CODOPERFISC,
    :MODELONF;
    IF (:CODOPERFISC <> '012') THEN BEGIN
        -- VERIFICAR SE NAO TEM PLANO DE CONTA ASSOCIADA
        IF (CHAVEPLANOCONTA = 0 ) THEN BEGIN
            -- Plano de conta para vendas a prazo
            IF (:CHAVECONDPGTO <> 1) THEN BEGIN
                SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
                WHERE CHAVE = 6
                INTO :CHAVEPLANOCONTA;
            END
            -- Plano de conta para vendas a vista
            IF (:CHAVECONDPGTO = 1) THEN BEGIN
                SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
                WHERE CHAVE = 7
                INTO :CHAVEPLANOCONTA;
            END
            UPDATE PEDIDOSAIDA SET
                CHAVEPLANOCONTA = :CHAVEPLANOCONTA
             WHERE ATIVO=1 AND CHAVE=:CHAVEPEDIDO;
            UPDATE NFSAIDA SET
                CHAVEPLANOCONTA = :CHAVEPLANOCONTA
             WHERE ATIVO=1 AND CHAVE=:CHAVENF;
        END
        -- VERIFICAR SE NAO TEM CHAVECENTROCUSTO
        IF (CHAVECENTROCUSTO = 0) THEN BEGIN
            CHAVECENTROCUSTO = 1;
            UPDATE PEDIDOSAIDA SET
                CHAVECENTROCUSTO = :CHAVECENTROCUSTO
            WHERE ATIVO=1 AND CHAVE=:CHAVEPEDIDO;
            UPDATE NFSAIDA SET
                CHAVECENTROCUSTO = :CHAVECENTROCUSTO
             WHERE CHAVE=:CHAVENF;
        END
        CHAVERECEBER = GEN_ID(GEN_RECEBER_ID,1);
        -- COMECA A INSERIR OS VALORES
        INSERT INTO RECEBER
            (CHAVE, CHAVECLIFOR, DATACONTA, DOCUMENTO, PARCELA, VALOR,
            VENCIMENTO, TOTPARC, TIPO, STATUS, CHAVEEMPRESA, RECEBPARCIAL,
            NL, CHAVEPLANOCTO, CHAVECENTROCTO, DESCRICAO, VALORPRODUTO, VALORSERVICO,
            ORIGEM, CHAVECTABANCARIA, CHAVEOPERACOESTITULOS,
            CHAVEDOC, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
        VALUES (:CHAVERECEBER, :CLI, :DATANF, :NF, :PARC, :VLR,
            :DATAVENC, :NPARCELAS, :FORMAPGTO, 1, :CHAVEEMP, 0,
            :NLATUAL, :CHAVEPLANOCONTA, :CHAVECENTROCUSTO, SUBSTRING('NF SAIDA '||:NF||' - CLI. '||:CODCLIFOR||' - '||:RAZAOSOCIAL FROM 1 FOR 100), :VLRPRODUTO, :VLRSERVICO,
            1, :CHAVECTABANCARIA, :CHAVEOPERTITULOS,
            :CHAVENF, :CHAVEUSUARIO, :CHAVEUSUARIO);
        -- Se for a vista ou com entrada
        IF ((:VENC1 = 0) AND (:PARC=1)) THEN
           EXECUTE PROCEDURE BAIXAPAGRECAUTOMATICO(:NLATUAL, 'R', :CHAVERECEBER, :CHAVEUSUARIO, :CHAVECONTACAIXA, :CHAVECTABANCARIA, :ECHAVEEMPCAIXA);

        -- INSERIR OS REGISTROS DE REPRESENTANTES X COMISSAO LIGADOS A CONTA A RECEBER
        INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
        COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
        COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
        SELECT CHAVEEMPRESA, :CHAVERECEBER, CHAVEVENDEDOR, 7, :NLATUAL, TIPOCOMISSAO,
        COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
        COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA
        FROM COMISSAO
        WHERE (ATIVO=1) AND (ORIGEM=1) AND (CHAVEDOC=:CHAVENF);
        -- GERAR PONTUACAO
        IF (EGERARPONTUACAO = 'S') THEN BEGIN
            IF ((:VENC1 = 0) AND (:PARC=1)) THEN BEGIN
                AOBSPONT = 'VENDA A VISTA NF '||:NF||' MODELO '||:MODELONF;
                SELECT COALESCE(CAST(VALOR AS NUMERIC(18,2)),0) FROM CONFIGCAMPOS WHERE INDICE = 129 AND CHAVEEMPRESA=:CHAVEEMP
                INTO :VLRREFERENCIA;
                IF (VLRREFERENCIA>0) THEN
                    PONTOSMOV = CAST(:VLR / :VLRREFERENCIA AS NUMERIC(18,2));
                PONTOSBLOQ = 0;
            END ELSE BEGIN
                SELECT COALESCE(CAST(VALOR AS NUMERIC(18,2)),0) FROM CONFIGCAMPOS WHERE INDICE = 130 AND CHAVEEMPRESA=:CHAVEEMP
                INTO :VLRREFERENCIA;
                AOBSPONT = 'VENDA A PRAZO (PARC. '||:PARC||'/'||:NPARCELAS||') NF '||:NF||' MODELO '||:MODELONF;
                PONTOSMOV = 0;
                IF (VLRREFERENCIA>0) THEN
                    PONTOSBLOQ = CAST(:VLR / :VLRREFERENCIA AS NUMERIC(18,2));
            END
            IF (VLRREFERENCIA>0) THEN BEGIN
                INSERT INTO PONTUACAO (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, DATA, VLRBASE, VLRREFERENCIA, PONTOSMOV, OBS, CHAVEDOC, NL, CHAVERECEBER, PONTOSBLOQ)
                VALUES(1, :ECHAVEEMPPONTUACAO, :CLI, :DATANF, :VLR, :VLRREFERENCIA, :PONTOSMOV, :AOBSPONT, :CHAVENF, :NLATUAL, :CHAVERECEBER, :PONTOSBLOQ);
            END
        END
    END
    /*
       CHAMADAS :
            - FRMDLGFATURAMENTO: USADA PARA GERAR FINANCEIRO DE NOTA FISCAL FORMULARIO
            - MODULO CHSERVER - USADA PARA GERAR FINANCEIRO DE NOTA FISCAL ELETRONICA
    */
END^


ALTER PROCEDURE GERA_NFSAIDA (
    HORASAIDA TIME,
    NUMNFMANUAL INTEGER,
    DATASAIDA DATE,
    CHAVEPEDIDO INTEGER,
    CHAVEEMPNF INTEGER,
    DATAFATURAMENTO DATE,
    CHAVESERIENF INTEGER,
    CHAVEEMPSERIENF INTEGER,
    CHAVEEMPCUSTO INTEGER,
    CHAVEUSUARIO INTEGER)
RETURNS (
    CHAVENF INTEGER,
    DOC VARCHAR(9))
AS
DECLARE VARIABLE NUMERO INTEGER;
DECLARE VARIABLE LANCARNUMDOCMANUAL CHAR(1);
DECLARE VARIABLE NUMRPSNFSE INTEGER;
DECLARE VARIABLE VFORMAEMISNFSE INTEGER;
DECLARE VARIABLE VCHAVEORDEMSERVICO INTEGER;
DECLARE VARIABLE VCHAVECONDICIONAL INTEGER;
DECLARE VARIABLE VCHAVECOTACAO INTEGER;
DECLARE VARIABLE VPROVEDORNFSE VARCHAR(100);
DECLARE VARIABLE VGERARNUMNFSE CHAR(1);
DECLARE VARIABLE NUMLOTENFSE INTEGER;
DECLARE VARIABLE STATUS INTEGER;
DECLARE VARIABLE NUMERONF VARCHAR(9);
DECLARE VARIABLE AUTOINCNOTA INTEGER;
DECLARE VARIABLE NSU INTEGER;
DECLARE VARIABLE TIPOEMISSAONFE INTEGER;
DECLARE VARIABLE TIPOEMISSAONFSE INTEGER;
DECLARE VARIABLE MODELO VARCHAR(10);
DECLARE VARIABLE MSGNSU VARCHAR(200);
DECLARE VARIABLE CHAVECFOPOPERFISC INTEGER;
DECLARE VARIABLE NL DOUBLE PRECISION;
DECLARE VARIABLE VTIPOPGTO SMALLINT;
DECLARE VARIABLE SERIE VARCHAR(3);
BEGIN
    VGERARNUMNFSE = 'N';
    VFORMAEMISNFSE = 0;
    SELECT VALOR FROM CONFIGCAMPOS WHERE ATIVO=1 AND CHAVEEMPRESA=:CHAVEEMPNF AND INDICE = 73
    INTO :VPROVEDORNFSE;
    IF ((UPPER(:VPROVEDORNFSE) = 'INFISC-V11') OR (UPPER(:VPROVEDORNFSE) = 'INFISC'))  THEN
        VGERARNUMNFSE = 'S';
    SELECT ULTIMANF, COALESCE(NSU,0)+1, MODELO, LANCARNUMDOCMANUAL, NUMRPSNFSE, NUMLOTENFSE, SERIE
    FROM SERIENF
    WHERE (ATIVO=1) AND (CHAVE=:CHAVESERIENF)
    INTO :NUMERO, :NSU, :MODELO, :LANCARNUMDOCMANUAL, :NUMRPSNFSE, :NUMLOTENFSE, :SERIE;
    IF ((:MODELO <> '98') OR ((:MODELO = '98') AND (:VGERARNUMNFSE = 'S')))  THEN BEGIN
        IF ((LANCARNUMDOCMANUAL =  'S') AND (:NUMNFMANUAL > 0)) THEN
            NUMERO=:NUMNFMANUAL;
        ELSE
            NUMERO=:NUMERO+1;
        UPDATE SERIENF SET ULTIMANF=:NUMERO
        WHERE (ATIVO=1) AND (CHAVE=:CHAVESERIENF);
        IF ((:MODELO = '01') OR (:MODELO = '1B') OR (:MODELO = '99')) THEN BEGIN
            UPDATE SERIENF SET NSU=:NSU
            WHERE (ATIVO=1) AND (CHAVEEMPRESA=:CHAVEEMPSERIENF);
            NUMERONF = LPAD(NUMERO,6,0);
        END ELSE BEGIN
           NSU = 0;
           NUMERONF = LPAD(NUMERO,9,0);
        END
    END ELSE BEGIN
        NUMERO=NULL;
        NSU = 0;
    END
    AUTOINCNOTA = GEN_ID(GEN_NFSAIDA_ID,1);
    SELECT CAST(VALOR AS INTEGER) FROM CONFIGCAMPOS
    WHERE (CHAVEEMPRESA=:CHAVEEMPNF) AND (CAMPO='TIPOEMISSAONFE')
    INTO :TIPOEMISSAONFE;
    SELECT CAST(VALOR AS INTEGER) FROM CONFIGCAMPOS
    WHERE (CHAVEEMPRESA=:CHAVEEMPNF) AND (CAMPO='TIPOEMISSAONFSE')
    INTO :TIPOEMISSAONFSE;
    SELECT CHAVECFOPOPERFISCAIS, NL, TIPOPAGAMENTO FROM PEDIDOSAIDA
    WHERE ATIVO=1 AND CHAVE=:CHAVEPEDIDO
    INTO :CHAVECFOPOPERFISC, :NL, :VTIPOPGTO;
    STATUS   = 1;
    IF (:CHAVECFOPOPERFISC = 12) THEN
        STATUS = 9;
    IF (((:TIPOEMISSAONFE IN (1,2)) AND (:MODELO = '55')) OR ((:TIPOEMISSAONFSE IN (1,2)) AND (:MODELO = '98'))) THEN BEGIN
       STATUS   = 3;
    END
    IF (:MODELO <> '55') THEN
        TIPOEMISSAONFE=0;
    IF (:MODELO <>'98') THEN
        TIPOEMISSAONFSE=0;
    INSERT INTO NFSAIDA (CHAVE, NUMERONF, CHAVEPEDIDO, CHAVECLIFOR, CHAVECFOPPROD,
        CHAVECFOPSERV, CHAVECONDPGTO, BASECALCULOICMS, VLRICMS,
        BASECALCICMSSUBST, VLRICMSSUBST, FRETE, VLRSEGURO, DESPACESSORIA,
        TOTALIPI, BCIPI, DESCPORCPROD, DESCVLRPROD, TOTALPRODUTO, TOTALNF, TOTALSERVICO,
        CHAVETRANSP, FRETEPORCONTA, QTDEVOLUME,
        ESPECIE, MARCA, NUMERO, PESOBRUTO, PESOLIQUIDO, OBS, FATURA,
        DATAPEDIDO, DATAHORAPEDIDO, BASEISS, ALIQUOTAISS, TOTALISS,
        DESCPORCSERVICO, DESCVLRSERVICO, DATANF, DATASAIDA, HORASAIDA,
        CHAVEEMPRESA, CHAVEMACROES,
        CHAVECOTACAO, AGRUPADO, BASECALCICMSSUBSTDESTAC,
        VLRICMSSUBSTDESTAC, CHAVECONDICIONAL, VLRACRESCIMO,
        CHAVESERIENF, NSU, DATAHORANSU, CHAVECTABANCARIA, CHAVEOPERACOESTITULOS,
        CHAVECFOPOPERFISCAIS, CHAVETABELADESCONTOS, ALIQICMSSIMPLESNACIONAL,
        BASEICMSSIMPLESNACIONAL, VLRICMSSIMPLESNACIONAL, TIPOEMISSAONFE, TIPOEMISSAONFSE, NL, TIPOPAGAMENTO,
        BASEINSS, VLRINSS, VLRABATFINANCSERV, VLRABATFINANCPROD, VLRFINANCEIRO,
        UFEMBARQUEMERC, LOCALEMBARQUEMERC, BCPISCOFINS, VLRPIS,  VLRCOFINS, ORIGEMNF, STATUS,
        BCPISCOFINSSERV, VLRPISSERV, VLRCOFINSSERV, CHAVEPLANOCONTA, CHAVECENTROCUSTO,
        TIPOSENHADESCPROD, CHAVEUSUARIOAUTORDESCPROD, TIPOSENHADESCSERV,
        CHAVEUSUARIOAUTORDESCSERV, IRRF, VLRCSLL, NRONOTAEMPENHO, NROCONTRATO,
        NROORDEMPEDCOMPRA, CHAVECIDPRESTSERVICO, NUMRPSNFSE, NUMLOTENFSE,
        CHAVEPEDORIGINAL, VLRTOTTRIB, ENTREGA, VLRICMSPARTDEST,
        VLRICMSPARTREMET, VLRICMSFCP, FORMAPGTO, TIPOTOMADORNFSE, CHAVEENDENTREGA, CHAVENFENTFUTURA,
        CHAVEUSUARIOGEROU, VLRICMSFCPST, VLRICMSFCPSTDEST, CHAVEVEICULO,
        DATAHORAFATURA,
        VLRICMSSTEFET, BASEICMSSTEFET, CHAVEMOBILE, CHAVEECOMMERCE, NROCARGAECOMMERCE, CHAVELOTEPEDSAIDA,
        CHAVESITENTREGA, CHAVELANCORDEMPROD, CHAVEORDEMSERVICO, ASSDIGITALCLI, ASSDIGITALREPR, HORAENTREGA,
        ACRESCPORCPROD, ACRESCVLRPROD, CHAVEENDCOLETA, VLRIPIDEVOLV, STATUSECOMMERCE, ECOMMERCEIDIDERIS,
        CHAVERECEBER, ECOMMERCEIDTRAY, VLRICMSDESON, MODELONF, SERIENF, CHAVEINTERMEDIADOR, FORMAEMISSAONFSE,
        BASEIVA, VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFUF, VLRIBSDIFMUN, CHAVEROMANEIO, CHAVEROTA,
        NRORECEITAGRO, CPFRESPTEC, NROGUIA, SERIEGUIA, TIPOGUIA, UFGUIA, VLRCREDPRESCBS, VLRCREDPRESIBS, TPNFDEBITO,
        NOMEEVENTO, DATAINIEVENTO, DATAFIMEVENTO, IDATVEVENTO, COMPAJUSTE, VLRPISRET, VLRCOFINSRET)
    SELECT :AUTOINCNOTA, :NUMERONF, CHAVE, CHAVECLIFOR, CHAVECFOPPROD, CHAVECFOPSERV,
        CHAVECONDPGTO, COALESCE(BASECALCULOICMS,0), COALESCE(VLRICMS,0),
        COALESCE(BASECALCICMSSUBST,0), COALESCE(VLRICMSSUBST,0), COALESCE(FRETE,0),
        COALESCE(VLRSEGURO,0), COALESCE(DESPACESSORIA,0), COALESCE(TOTALIPI,0),
        COALESCE(BCIPI,0), COALESCE(DESCPORCPROD,0), COALESCE(DESCVLRPROD,0), COALESCE(TOTALPRODUTO,0),
        COALESCE(TOTALPEDIDO,0),COALESCE(TOTALSERVICO,0),
        CHAVETRANSP, FRETEPORCONTA, COALESCE(QTDEVOLUME,' '), COALESCE(ESPECIE,' '),
        MARCA, NUMERO, PESOBRUTO, PESOLIQUIDO, CAST(SUBSTRING(COALESCE(OBS,' ') FROM 1 FOR 5000) AS VARCHAR(5000)), FATURA,
        DATAPEDIDO, DATAHORAPEDIDO, BASEISS, ALIQUOTAISS, TOTALISS, COALESCE(DESCPORCSERVICO,0),
        COALESCE(DESCVLRSERVICO,0), :DATAFATURAMENTO, :DATASAIDA, :HORASAIDA,
        :CHAVEEMPNF, CHAVEMACROES, CHAVECOTACAO,
        AGRUPADO, COALESCE(BASECALCICMSSUBSTDESTAC,0),
        COALESCE(VLRICMSSUBSTDESTAC,00), CHAVECONDICIONAL,
        VLRACRESCIMO, :CHAVESERIENF, :NSU, 'NOW', CHAVECTABANCARIA, CHAVEOPERACOESTITULOS,
        CHAVECFOPOPERFISCAIS, CHAVETABELADESCONTOS, ALIQICMSSIMPLESNACIONAL,
        BASEICMSSIMPLESNACIONAL, VLRICMSSIMPLESNACIONAL, :TIPOEMISSAONFE, :TIPOEMISSAONFSE, NL, TIPOPAGAMENTO,
        BASEINSS, VLRINSS, VLRABATFINANCSERV, VLRABATFINANCPROD, VLRFINANCEIRO,
        UFEMBARQUEMERC, LOCALEMBARQUEMERC, BCPISCOFINS, VLRPIS,  VLRCOFINS, ORIGEMPED, :STATUS,
        BCPISCOFINSSERV, VLRPISSERV, VLRCOFINSSERV, CHAVEPLANOCONTA, CHAVECENTROCUSTO,
        TIPOSENHADESCPROD, CHAVEUSUARIOAUTORDESCPROD, TIPOSENHADESCSERV,
        CHAVEUSUARIOAUTORDESCSERV, IRRF, VLRCSLL, NRONOTAEMPENHO, NROCONTRATO,
        NROORDEMPEDCOMPRA, CHAVECIDPRESTSERVICO, :NUMRPSNFSE, :NUMLOTENFSE,
        CHAVEPEDORIGINAL, VLRTOTTRIB, ENTREGA, VLRICMSPARTDEST,
        VLRICMSPARTREMET, VLRICMSFCP, FORMAPGTO, TIPOTOMADORNFSE, CHAVEENDENTREGA, CHAVENFENTFUTURA,
        :CHAVEUSUARIO, VLRICMSFCPST, VLRICMSFCPSTDEST, CHAVEVEICULO,
        CASE WHEN (:DATASAIDA = CURRENT_DATE) AND (:HORASAIDA < CURRENT_TIME) THEN CURRENT_DATE + :HORASAIDA ELSE CURRENT_TIMESTAMP END,
        VLRICMSSTEFET, BASEICMSSTEFET, CHAVEMOBILE, CHAVEECOMMERCE, NROCARGAECOMMERCE, CHAVELOTEPEDSAIDA,
        CHAVESITENTREGA, CHAVELANCORDEMPROD, CHAVEORDEMSERVICO, ASSDIGITALCLI, ASSDIGITALREPR, HORAENTREGA,
        ACRESCPORCPROD, ACRESCVLRPROD, CHAVEENDCOLETA, VLRIPIDEVOLV, STATUSECOMMERCE, ECOMMERCEIDIDERIS,
        CHAVERECEBER, ECOMMERCEIDTRAY, VLRICMSDESON, :MODELO, :SERIE, CHAVEINTERMEDIADOR, :VFORMAEMISNFSE,
        BASEIVA, VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFUF, VLRIBSDIFMUN, CHAVEROMANEIO, CHAVEROTA,
        NRORECEITAGRO, CPFRESPTEC, NROGUIA, SERIEGUIA, TIPOGUIA, UFGUIA, VLRCREDPRESCBS, VLRCREDPRESIBS, TPNFDEBITO,
        NOMEEVENTO, DATAINIEVENTO, DATAFIMEVENTO, IDATVEVENTO, COMPAJUSTE, VLRPISRET, VLRCOFINSRET
        FROM PEDIDOSAIDA WHERE ATIVO=1 AND CHAVE=:CHAVEPEDIDO;
    INSERT INTO ITENSNFSAIDA (CHAVEEMPRESA, CHAVENFSAIDA, CHAVEPRODUTO,
        CODPRODUTO, PRODUTO, CHAVEUNIDADE ,UN, QTDE, VLRUNIT, VLRUNITORIGINAL,
        PRECOCUSTO, PCVENDA, DESCPORC, DESCVLR, VLRUNITCOMDESC, CHAVETRIBUTACAO, CST,
        VLRSUBTOTAL, VLRTOTAL, ICMS, VLRICMS, BASEICMS,
        CHAVECLASSFISCAL, CSTIPI, IPI, BASECALCIPI, VLRIPI, BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB,
        BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC,
        ALIQCOMISPROD, DESCRCOMPLEMENT, CHAVELOTEPROD,
        CHAVECFOP, CHAVECFOPOPERFISCAIS, NL, MVA, MVACALC, MOVESTOQUE, OPERENTFUTURA,
        VLRDESCGLOBAL, QTDEESTOQUE, VLRFRETE, VLRSEGURO, VLRDESPACESSORIA, VLRICMSSIMPLESNACIONAL,
        CSTPIS, CSTCOFINS, ALIQPIS, ALIQCOFINS, VLRPIS, VLRCOFINS, BCPIS, BCCOFINS,
        TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, CSOSN, CHAVETABPISCOFINS, NROORDEMCOMPRA,
        NROITEMORDEMCOMPRA, IPITRIB, VLRIPITRIB, VLRPISTRIB, VLRCOFINSTRIB, COMPORTOTALNF,
        VLRTOTTRIB, VLRTOTTRIBEST, VLRTOTTRIBMUNIC, NROFCI, VLRPAUTA, CHAVEDPTOESTOQUE,
        CHAVECENTROCUSTO, CHAVEPLANOCONTA, CEST, ALIQICMSINTRA, VLRICMSPARTDEST,
        VLRICMSPARTREMET, ALIQICMSINTER, BCICMSUFDEST, VLRICMSFCP, CODENQIPI, PERCICMSPART, UNTRIB,
        QTDETRIB, CONVTRIB, VLRUNTRIB, PERCICMSFCP, CHAVEITEMDEVOLV, VLRICMSFCPST, VLRICMSFCPSTDEST,
        CHAVETABELAPRECO, VLRICMSSTEFET, BASEICMSSTEFET, ALIQICMSPROPRIOCOMPRA, VLRICMSPROPRIOCOMPRA,
        PERCICMSFCPST, VLRACRESCGLOBAL, VLRUNITTABELA, VLRVENDAMINIMO, CHAVEREGRAFISCAL,
        ACRESCPORC, ACRESCVLR, CHAVESPRODPROMO, TIPOPROMOCAO, VLRIPIDEVOLV, PERCIPIDEVOLV,
        VLRBASEFLEX, VLRCREDITOFLEX, VLRICMSDESON, CODBENEF, CHAVEITEMENTREGUE, INDIMPORTCOMB, UFORIGEMCOMB, PERCORIGUFCOMB,
        CHAVECLASSTRIB, BASEIVA, ALIQCBS, ALIQIBSUF, ALIQIBSMUN, VLRCBS, VLRIBSUF, VLRIBSMUN,
        VLRCBSDIF, VLRIBSDIFUF, VLRIBSDIFMUN, CHAVECREDPRES, PERCCREDPRES, VLRCREDPRESCBS, VLRCREDPRESIBS, BCCREDPRES, NITEMREF, CHAVEACESSOREF)
    SELECT :CHAVEEMPNF, :AUTOINCNOTA, I.CHAVEPRODUTO,
        CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE, VLRUNIT, VLRUNITORIGINAL,
        PC.PRECOMEDIO, PC.PRECOCUSTO, DESCPORC, DESCVLR, VLRUNITCOMDESC, I.CHAVETRIBUTACAO, CST,
        VLRSUBTOTAL, VLRTOTAL, ICMS, VLRICMS, BASEICMS,
        CHAVECLASSFISCAL, CSTIPI, IPI, BASECALCIPI, VLRIPI, BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB,
        BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC,
        ALIQCOMISPROD, DESCRCOMPLEMENT, CHAVELOTEPROD,
        CHAVECFOP, CHAVECFOPOPERFISCAIS, NL, MVA, MVACALC, COALESCE(I.MOVESTOQUE,CF.MOVESTOQUE), COALESCE(I.OPERENTFUTURA,CF.ENTREGAFUTURA),
        VLRDESCGLOBAL, QTDEESTOQUE, VLRFRETE, VLRSEGURO, VLRDESPACESSORIA, VLRICMSSIMPLESNACIONAL,
        CSTPIS, CSTCOFINS, ALIQPIS, ALIQCOFINS, VLRPIS, VLRCOFINS, BCPIS, BCCOFINS,
        TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, I.CSOSN, I.CHAVETABPISCOFINS, NROORDEMCOMPRA,
        NROITEMORDEMCOMPRA, IPITRIB, VLRIPITRIB, VLRPISTRIB, VLRCOFINSTRIB,
        COALESCE(I.COMPORTOTALNF, CF.COMPORTOTALNF),
        VLRTOTTRIB, VLRTOTTRIBEST, VLRTOTTRIBMUNIC, NROFCI, VLRPAUTA, I.CHAVEDPTOESTOQUE,
        I.CHAVECENTROCUSTO, I.CHAVEPLANOCONTA, I.CEST, I.ALIQICMSINTRA, I.VLRICMSPARTDEST,
        I.VLRICMSPARTREMET, I.ALIQICMSINTER, I.BCICMSUFDEST, I.VLRICMSFCP, I.CODENQIPI,  I.PERCICMSPART, I.UNTRIB,
        I.QTDETRIB, I.CONVTRIB, I.VLRUNTRIB, I.PERCICMSFCP, I.CHAVEITEMDEVOLV, I.VLRICMSFCPST, I.VLRICMSFCPSTDEST,
        I.CHAVETABELAPRECO, I.VLRICMSSTEFET, I.BASEICMSSTEFET, I.ALIQICMSPROPRIOCOMPRA, I.VLRICMSPROPRIOCOMPRA,
        I.PERCICMSFCPST, I.VLRACRESCGLOBAL, I.VLRUNITTABELA, I.VLRVENDAMINIMO, I.CHAVEREGRAFISCAL,
        I.ACRESCPORC, I.ACRESCVLR, I.CHAVESPRODPROMO, I.TIPOPROMOCAO, I.VLRIPIDEVOLV, I.PERCIPIDEVOLV,
        I.VLRBASEFLEX, I.VLRCREDITOFLEX, I.VLRICMSDESON, I.CODBENEF, I.CHAVEITEMENTREGUE, I.INDIMPORTCOMB, I.UFORIGEMCOMB, I.PERCORIGUFCOMB,
        I.CHAVECLASSTRIB, I.BASEIVA, I.ALIQCBS, I.ALIQIBSUF, I.ALIQIBSMUN, I.VLRCBS, I.VLRIBSUF, I.VLRIBSMUN,
        I.VLRCBSDIF, I.VLRIBSDIFUF, I.VLRIBSDIFMUN, I.CHAVECREDPRES, I.PERCCREDPRES, I.VLRCREDPRESCBS, I.VLRCREDPRESIBS, I.BCCREDPRES, I.NITEMREF,
        I.CHAVEACESSOREF
    FROM ITENSPEDSAIDA I
    INNER JOIN CFOPOPERFISCAIS CF ON I.CHAVECFOPOPERFISCAIS = CF.CHAVE
    INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO = I.CHAVEPRODUTO AND PC.CHAVEEMPRESA=:CHAVEEMPCUSTO
    WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDIDO
    ORDER BY I.CHAVE;
    INSERT INTO ITENSNFSERVICO (CHAVEEMPRESA, CHAVENFSAIDA, CHAVEPRODUTO,
        CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE, VLRUNIT, VLRUNITORIGINALSERVICO,
        PRECOCUSTO, DESCPORC, DESCVLR, VLRUNITCOMDESCSERVICO, ISS,
        VLRSUBTOTAL, VLRTOTAL, DESCRCOMPLEMENT,
        ALIQCOMISPROD, CHAVECFOP, CHAVECFOPOPERFISCAIS, NL,
        VLRDESCGLOBAL, BASEISS, VLRISS, CSTPISCOFINS, BASEPISCOFINS, VLRPIS, VLRCOFINS, ALIQPIS, ALIQCOFINS,
        TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, CHAVETABPISCOFINS, VLRPISTRIB, VLRCOFINSTRIB,
        VLRTOTTRIB, VLRTOTTRIBEST, VLRTOTTRIBMUNIC, CHAVECENTROCUSTO, CHAVEPLANOCONTA, CHAVETABELAPRECO,
        VLRUNITTABELA, CODIGOCNO, CHAVECLASSTRIB, BASEIVA, ALIQCBS, ALIQIBSUF, ALIQIBSMUN, VLRCBS, VLRIBSUF, VLRIBSMUN,
        VLRCBSDIF, VLRIBSDIFUF, VLRIBSDIFMUN, CHAVECLASSFISCAL, NITEMREF)
    SELECT :CHAVEEMPNF, :AUTOINCNOTA, CHAVEPRODUTO,
        CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE, VLRUNIT, VLRUNITORIGINALSERVICO,
        PRECOCUSTO, DESCPORC, DESCVLR, VLRUNITCOMDESCSERVICO, ISS,
        VLRSUBTOTAL, VLRTOTAL, DESCRCOMPLEMENT,
        ALIQCOMISPROD, CHAVECFOP, CHAVECFOPOPERFISCAIS, NL,
        VLRDESCGLOBAL, BASEISS, VLRISS, CSTPISCOFINS, BASEPISCOFINS, VLRPIS, VLRCOFINS, ALIQPIS, ALIQCOFINS,
        TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, CHAVETABPISCOFINS, VLRPISTRIB, VLRCOFINSTRIB,
        VLRTOTTRIB, VLRTOTTRIBEST, VLRTOTTRIBMUNIC, CHAVECENTROCUSTO, CHAVEPLANOCONTA, CHAVETABELAPRECO,
        VLRUNITTABELA, CODIGOCNO, CHAVECLASSTRIB, BASEIVA, ALIQCBS, ALIQIBSUF, ALIQIBSMUN, VLRCBS, VLRIBSUF, VLRIBSMUN,
        VLRCBSDIF, VLRIBSDIFUF, VLRIBSDIFMUN, CHAVECLASSFISCAL, NITEMREF
    FROM ITENSPEDSAIDASERV WHERE ATIVO=1 AND CHAVEPEDIDO=:CHAVEPEDIDO
    ORDER BY CHAVE;
    UPDATE PEDIDOSAIDA SET
    STATUS=2, CHAVESERIENF=:CHAVESERIENF
    WHERE CHAVE=:CHAVEPEDIDO;
    EXECUTE PROCEDURE ATUALIZARALIQCOMISSAO(:NL, :VTIPOPGTO, :CHAVEPEDIDO);
    INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
    SELECT CHAVEEMPRESA, :AUTOINCNOTA, CHAVEVENDEDOR, 1, NL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA
    FROM COMISSAO
    WHERE (ATIVO=1) AND (ORIGEM=0) AND (CHAVEDOC=:CHAVEPEDIDO);
    CHAVENF=:AUTOINCNOTA;
    DOC=:NUMERONF;
    IF ((:MODELO = '01') OR (:MODELO = '1B') OR (:MODELO = '99')) THEN BEGIN
        SELECT ': '||LPAD(COALESCE(NSU,0),10,0)||' - '
            ||'DATA/HORA GERACAO: '||
            LPAD(EXTRACT(DAY FROM DATAHORANSU),2,0)||'/'||
            LPAD(EXTRACT(MONTH FROM DATAHORANSU),2,0)||'/'||
            LPAD(EXTRACT(YEAR FROM DATAHORANSU),2,0)||'-'||
            LPAD(EXTRACT(HOUR FROM DATAHORANSU),2,0)||':'||
            LPAD(EXTRACT(MINUTE FROM DATAHORANSU),2,0)||'. '||
            'NF: '||LPAD(COALESCE(NUMERONF,0),6,0)||' - '||
            'DATA/HORA IMPRESSAO: '||
            LPAD(EXTRACT(DAY FROM DATAHORAFATURA),2,0)||'/'||
            LPAD(EXTRACT(MONTH FROM DATAHORAFATURA),2,0)||'/'||
            LPAD(EXTRACT(YEAR FROM DATAHORAFATURA),2,0)||'-'||
            LPAD(EXTRACT(HOUR FROM DATAHORAFATURA),2,0)||':'||
            LPAD(EXTRACT(MINUTE FROM DATAHORAFATURA),2,0)
            FROM NFSAIDA
            WHERE CHAVE=:AUTOINCNOTA
        INTO :MSGNSU;
        INSERT INTO OBSLIVROFISCCOMPLDOCFISC
            (CHAVEEMPRESA, CHAVEDOCFISCAL, NL, TIPODOCFISCAL,
            CHAVEOBSCOMPLFISCAL, DESCRICAOCOMPL, TIPO)
        SELECT
            CHAVEEMPRESA, CHAVEPEDIDO, NL, 1,
            1, :MSGNSU, 1
        FROM NFSAIDA
        WHERE CHAVE=:AUTOINCNOTA;
    END
    INSERT INTO RASTREARDOC(ATIVO, CHAVEEMPRESA, CHAVEPEDORIGEM, CHAVENFDESTINO, DATAHORA, CHAVEUSUARIO)
    VALUES(1,:CHAVEEMPNF, :CHAVEPEDIDO, :AUTOINCNOTA, CURRENT_TIMESTAMP, :CHAVEUSUARIO);
    SELECT CHAVECOTACAO, CHAVECONDICIONAL, CHAVEORDEMSERVICO
    FROM PEDIDOSAIDA WHERE ATIVO=1 AND CHAVE=:CHAVEPEDIDO
    INTO :VCHAVECOTACAO, :VCHAVECONDICIONAL, :VCHAVEORDEMSERVICO;
    IF (VCHAVECOTACAO > 0) THEN BEGIN
       UPDATE COTACAO SET SITUACAO = 7
       WHERE CHAVE= :VCHAVECOTACAO;
    END
    IF (VCHAVECONDICIONAL > 0) THEN BEGIN
       UPDATE CONDICIONAL SET SITUACAO = 3
       WHERE CHAVE= :VCHAVECONDICIONAL;
    END
    IF (VCHAVEORDEMSERVICO > 0) THEN BEGIN
       UPDATE ORDEMSERVICO SET SITUACAO = 3
       WHERE CHAVE= :VCHAVEORDEMSERVICO;
    END
    SUSPEND;
    /* CHAMADAS
        - DLGGERANFCUPOMFISCAL - GERA UMA NF DECORRENTE AO CUPOM FISCAL
        - DLGFATURAMENTO -  GERA UMA NF REFERENTE AO PEDIDO DE SAIDA
    */
END^


ALTER PROCEDURE GERACOMISAGRUPADOC (
    EMPCOMISSAO INTEGER,
    CHAVEPEDIDO INTEGER)
AS
declare variable CHAVEVENDEDOR integer;
declare variable CHAVECLIFOR integer;
declare variable DOCUMENTO varchar(6);
declare variable DATA date;
declare variable VLRPARCPROD numeric(18,4);
declare variable VLRPARCSERV numeric(18,4);
declare variable TIPOCOMISSAO integer;
declare variable ALIQCOMISPRODEMISSAO numeric(7,2);
declare variable ALIQCOMISPRODBAIXA numeric(15,2);
declare variable COMISSAOGERADA integer;
declare variable ALIQCOMISSERVEMISSAO numeric(7,2);
declare variable ALIQCOMISSERVBAIXA numeric(7,2);
declare variable CHAVERECEBER integer;
declare variable CVPRODUTO numeric(18,6);
declare variable TOTALSERVICO numeric(18,6);
declare variable TOTALPRODUTO numeric(18,6);
declare variable CVSERVICO numeric(18,6);
declare variable PORCPAGONAPARC numeric(18,6);
declare variable NL double precision;
BEGIN
    SELECT COALESCE(SUM(I.VLRTOTAL-COALESCE(I.VLRDESCGLOBAL,0)),0) AS TOTALPRODUTO  FROM ITENSPEDSAIDA I
    INNER JOIN CFOP C ON C.CHAVE = I.CHAVECFOP AND C.CLASSIFICACAO = 1
    INNER JOIN CFOPOPERFISCAIS CFOPER ON CFOPER.CHAVE = I.CHAVECFOPOPERFISCAIS AND CFOPER.GERARFINANCEIRO = 0
    WHERE I.CHAVEPEDIDO = :CHAVEPEDIDO AND I.ATIVO=1
    INTO :TOTALPRODUTO;

    SELECT COALESCE(SUM(I.VLRTOTAL-COALESCE(I.VLRDESCGLOBAL,0)),0) AS TOTALSERVICO FROM ITENSPEDSAIDASERV I
    INNER JOIN CFOP C ON C.CHAVE = I.CHAVECFOP AND C.CLASSIFICACAO = 1
    INNER JOIN CFOPOPERFISCAIS CFOPER ON CFOPER.CHAVE = I.CHAVECFOPOPERFISCAIS AND CFOPER.GERARFINANCEIRO = 0
    WHERE I.CHAVEPEDIDO = :CHAVEPEDIDO AND I.ATIVO=1
    INTO :TOTALSERVICO;

    SELECT NL FROM PEDIDOSAIDA
    WHERE CHAVE=:CHAVEPEDIDO
    INTO :NL;

    -- CALCULA O PERCENTUAL QUE GEROU COMISSAO PARA GERAR COMISSAO BASEADO NO VALOR GERADO ANTERIORMENTE
    FOR SELECT COALESCE(RE.VALORPRODUTO,0), COALESCE(RE.VALORSERVICO,0),
    RE.CHAVE FROM RECEBER RE
    WHERE (RE.ATIVO=1) AND (RE.NL=:NL)
    INTO :VLRPARCPROD, :VLRPARCSERV, :CHAVERECEBER DO BEGIN

        FOR SELECT SUM(CF.VLRPRODUTO), SUM(CF.VLRSERVICO), CF.CHAVEVENDEDOR,
        CF.chaveclifor, TIPOCOMISSAO, DOCUMENTO, DATA, ALIQCOMISPRODEMISSAO, ALIQCOMISPRODBAIXA,
        ALIQCOMISSERVEMISSAO, ALIQCOMISSERVBAIXA, COMISSAOGERADA
        FROM COMISSAOFATURAMENTO CF
        WHERE CF.ATIVO=11 AND CF.CHAVEPEDIDO=:CHAVEPEDIDO
        GROUP BY CF.CHAVEVENDEDOR, CF.CHAVECLIFOR,
        TIPOCOMISSAO, DOCUMENTO, DATA, ALIQCOMISPRODEMISSAO, ALIQCOMISPRODBAIXA,
        ALIQCOMISSERVEMISSAO, ALIQCOMISSERVBAIXA, COMISSAOGERADA
        INTO :CVPRODUTO, :CVSERVICO, :CHAVEVENDEDOR, :CHAVECLIFOR, :TIPOCOMISSAO,
        :DOCUMENTO, :DATA, :ALIQCOMISPRODEMISSAO, :ALIQCOMISPRODBAIXA,
        :ALIQCOMISSERVEMISSAO, :ALIQCOMISSERVBAIXA, :COMISSAOGERADA DO BEGIN
    
            -- CALCULA PORCENTAGEM DO VALOR Q ESTA SENDO PAGO
            PORCPAGONAPARC = ((:VLRPARCPROD + :VLRPARCSERV)*100)/(:TOTALPRODUTO+:TOTALSERVICO);
            IF (:CVPRODUTO <> 0) THEN
                CVPRODUTO = (:CVPRODUTO * :PORCPAGONAPARC)/100;
            IF (:CVSERVICO <> 0) THEN
                CVSERVICO = (:CVSERVICO * :PORCPAGONAPARC)/100;

            IF (:CHAVEVENDEDOR IS NOT NULL) then BEGIN
                INSERT INTO COMISSAOFATURAMENTO
                (CHAVEEMPRESA, CHAVEVENDEDOR, CHAVECLIFOR,
                TIPOCOMISSAO, DOCUMENTO, DATA, NL,
                ALIQCOMISPRODEMISSAO, VLRCOMISPRODEMISSAO,
                ALIQCOMISPRODBAIXA, VLRCOMISPRODBAIXA,
                ALIQCOMISSERVEMISSAO, VLRCOMISSERVEMISSAO,
                ALIQCOMISSERVBAIXA, VLRCOMISSERVBAIXA,
                COMISSAOGERADA, VLRPRODUTO, VLRSERVICO, CHAVERECEBER, CHAVEPEDIDO,
                SITCOMISEMISSAO, SITCOMISBAIXA, ORIGEM)
                VALUES
                (:EMPCOMISSAO, :CHAVEVENDEDOR, :CHAVECLIFOR, :TIPOCOMISSAO,
                :DOCUMENTO, :DATA, :NL,
                :ALIQCOMISPRODEMISSAO, :CVPRODUTO * :ALIQCOMISPRODEMISSAO / 100,
                :ALIQCOMISPRODBAIXA, :CVPRODUTO * :ALIQCOMISPRODBAIXA / 100,
                :ALIQCOMISSERVEMISSAO, :CVSERVICO * :ALIQCOMISSERVEMISSAO / 100,
                :ALIQCOMISSERVBAIXA, :CVSERVICO * :ALIQCOMISSERVBAIXA / 100,
                :COMISSAOGERADA, :CVPRODUTO, :CVSERVICO, :CHAVERECEBER, :CHAVEPEDIDO, 'A', 'A', 0);
            END
        END
    END
        /*
       CHAMADAS :
            - FRMPEDIDOSAIDA : USADA PARA GERAR COMISSAO PS
            - FRMDLGFATURAMENTO: USADA PARA GERAR COMISSAO NOTA FISCAL FORMULARIO
            - MODULO CHSERVER - USADA PARA GERAR COMISSAO NOTA FISCAL NFe

    */
END^


ALTER PROCEDURE GERACOMISSAO (
    ECHAVEPEDIDO INTEGER,
    EORIGEM SMALLINT,
    EDOCUMENTO VARCHAR(9),
    ENL DOUBLE PRECISION)
AS
declare variable VCHAVECLIFOR integer;
declare variable VCHAVERECEBER integer;
declare variable VCHAVEEMPRESA integer;
declare variable VCHAVEVENDEDOR integer;
declare variable VVLRPRODUTO numeric(18,6);
declare variable VVLRSERVICO numeric(18,6);
declare variable VTIPOCOMISSAO integer;
declare variable VCOMISSAOGERADA integer;
declare variable VALIQCOMISPRODEMISSAO numeric(7,2);
declare variable VALIQCOMISPRODBAIXA numeric(7,2);
declare variable VALIQCOMISSERVEMISSAO numeric(7,2);
declare variable VALIQCOMISSERVBAIXA numeric(7,2);
declare variable VDATANF date;
declare variable VORIGEMCOMISSAO smallint;
declare variable VVLRRECEBER numeric(18,6);
declare variable VVLRFINANCEIRO numeric(18,6);
declare variable VTIPOPGTO smallint;
declare variable VCHAVEORIGEM integer;
declare variable VAUX numeric(18,6);
BEGIN
    IF (:EORIGEM = 0) THEN
        VORIGEMCOMISSAO = 0; /* NF - MAS UTILIZA ZERO PORQUE BUSCA A REFERENCIA PELA CHAVEPEDIDO */

    VCHAVEORIGEM = GEN_ID(GEN_COMISSAOFATURAMENTO_ID,0) + 1; /* GERA A CHAVE DA PRIMEIRA COMISSAO GERADA */
    FOR SELECT DISTINCT PS.CHAVEEMPRESA, CO.CHAVEVENDEDOR, PS.CHAVECLIFOR, R.VALOR, PS.VLRFINANCEIRO,
    CAST(COALESCE((SELECT SUM(I.VLRTOTAL-COALESCE(I.VLRDESCGLOBAL,0)) FROM ITENSPEDSAIDA I INNER JOIN CFOP C ON C.CHAVE = I.CHAVECFOP AND C.CLASSIFICACAO = 1
    INNER JOIN CFOPOPERFISCAIS CFOPER ON CFOPER.CHAVE = I.CHAVECFOPOPERFISCAIS AND CFOPER.GERARFINANCEIRO = 0 AND I.CHAVEPEDIDO = PS.CHAVE AND I.ATIVO=1),0)
    AS NUMERIC(14,2)) AS TOTALPRODUTO,
    CASE COALESCE(R.TOTPARC,0) WHEN 0 THEN PS.TOTALSERVICO ELSE R.VALORSERVICO END AS TOTALSERVICO,
    CO.TIPOCOMISSAO, CO.COMISSAOGERADA, CO.COMISPRODEMISSAO, CO.COMISPRODBAIXA,
    CO.COMISSERVEMISSAO, CO.COMISSERVBAIXA, COALESCE(R.CHAVE,0),
    CASE :EORIGEM WHEN 0 THEN NF.DATANF ELSE CURRENT_DATE END,
    PS.TIPOPAGAMENTO
    FROM COMISSAO CO
    INNER JOIN PEDIDOSAIDA PS ON (PS.CHAVE=CO.CHAVEDOC) AND (PS.NL=CO.NL)
    LEFT JOIN NFSAIDA NF ON (NF.CHAVEPEDIDO=PS.CHAVE)
    LEFT JOIN RECEBER R ON (R.NL=PS.NL)
    WHERE (CO.ATIVO=1) AND (CO.CHAVEDOC=:ECHAVEPEDIDO)
    AND (CO.ORIGEM=:VORIGEMCOMISSAO) AND (CO.NL=:ENL)
    AND (COALESCE(PS.VLRFINANCEIRO,0) > 0)
    INTO :VCHAVEEMPRESA, :VCHAVEVENDEDOR, :VCHAVECLIFOR, :VVLRRECEBER, :VVLRFINANCEIRO,
    :VVLRPRODUTO, :VVLRSERVICO,
    :VTIPOCOMISSAO, :VCOMISSAOGERADA,
    :VALIQCOMISPRODEMISSAO, :VALIQCOMISPRODBAIXA, :VALIQCOMISSERVEMISSAO, :VALIQCOMISSERVBAIXA,
    :VCHAVERECEBER, :VDATANF,
    :VTIPOPGTO
    DO BEGIN
        VAUX = :VVLRRECEBER * 100;
        VAUX = :VAUX / :VVLRFINANCEIRO;
        VAUX = CAST(:VAUX / 100 AS NUMERIC(18,6));
        VVLRPRODUTO = CAST(:VVLRPRODUTO * :VAUX AS NUMERIC(18,2));
        IF ((:VVLRPRODUTO + :VVLRSERVICO) > 0)  THEN BEGIN
            -- COMISSAO POR EMISSAO
            if ((:VCOMISSAOGERADA=0) or (:VCOMISSAOGERADA=2)) then BEGIN
                INSERT INTO COMISSAOFATURAMENTO
                (CHAVEEMPRESA, ORIGEM, CHAVEVENDEDOR, CHAVECLIFOR,
                CHAVEPEDIDO, DOCUMENTO, DATA, NL, VLRPRODUTO, VLRSERVICO, CHAVERECEBER,
                TIPOCOMISSAO, COMISSAOGERADA, SITCOMISEMISSAO, SITCOMISBAIXA,
                ALIQCOMISPRODEMISSAO, VLRCOMISPRODEMISSAO,
                ALIQCOMISPRODBAIXA, VLRCOMISPRODBAIXA,
                ALIQCOMISSERVEMISSAO, VLRCOMISSERVEMISSAO,
                ALIQCOMISSERVBAIXA, VLRCOMISSERVBAIXA,
                TIPOPAGAMENTO, OBSCOMPLEMENTAR, CHAVECOMISFATORIGEM)
                VALUES
                (:VCHAVEEMPRESA, :EORIGEM, :VCHAVEVENDEDOR, :VCHAVECLIFOR, :ECHAVEPEDIDO,
                :EDOCUMENTO, :VDATANF, :ENL, :VVLRPRODUTO, :VVLRSERVICO, :VCHAVERECEBER,
                :VTIPOCOMISSAO, 0, 'A', 'A',
                :VALIQCOMISPRODEMISSAO, (:VVLRPRODUTO/100)  * :VALIQCOMISPRODEMISSAO,
                0, 0,
                :VALIQCOMISSERVEMISSAO, (:VVLRSERVICO/100) * :VALIQCOMISSERVEMISSAO,
                0, 0,
                :VTIPOPGTO, '', :VCHAVEORIGEM);
            END

            -- COMISSAO POR BAIXA
            if ((:VCOMISSAOGERADA = 1) or (:VCOMISSAOGERADA=2)) then BEGIN
                INSERT INTO COMISSAOFATURAMENTO
                (CHAVEEMPRESA, ORIGEM, CHAVEVENDEDOR, CHAVECLIFOR,
                CHAVEPEDIDO, DOCUMENTO, DATA, NL, VLRPRODUTO, VLRSERVICO, CHAVERECEBER,
                TIPOCOMISSAO, COMISSAOGERADA, SITCOMISEMISSAO, SITCOMISBAIXA,
                ALIQCOMISPRODEMISSAO, VLRCOMISPRODEMISSAO,
                ALIQCOMISPRODBAIXA, VLRCOMISPRODBAIXA,
                ALIQCOMISSERVEMISSAO, VLRCOMISSERVEMISSAO,
                ALIQCOMISSERVBAIXA, VLRCOMISSERVBAIXA,
                TIPOPAGAMENTO, OBSCOMPLEMENTAR, CHAVECOMISFATORIGEM)
                VALUES
                (:VCHAVEEMPRESA, :EORIGEM, :VCHAVEVENDEDOR, :VCHAVECLIFOR, :ECHAVEPEDIDO,
                :EDOCUMENTO, :VDATANF, :ENL, :VVLRPRODUTO, :VVLRSERVICO, :VCHAVERECEBER,
                :VTIPOCOMISSAO, 1, 'A', 'A',
                0, 0,
                :VALIQCOMISPRODBAIXA, (:VVLRPRODUTO/100) * :VALIQCOMISPRODBAIXA,
                0, 0,
                :VALIQCOMISSERVBAIXA, (:VVLRSERVICO/100) * :VALIQCOMISSERVBAIXA,
                :VTIPOPGTO, '', :VCHAVEORIGEM);
            END

            UPDATE RECEBER SET
            VALORPRODUTO=:VVLRPRODUTO,
            VALORSERVICO=:VVLRSERVICO
            WHERE (CHAVE=:VCHAVERECEBER) AND (NL=:ENL);
        END
    END

    IF (COALESCE(:VCHAVEEMPRESA,0) > 0) THEN
        EXECUTE PROCEDURE GERARCOMISSAOFATEMISSAO(:VCHAVEEMPRESA, :VCHAVECLIFOR, :VDATANF, :ENL, :EORIGEM);

    /*
       CHAMADAS :
            - FRMDLGFATURAMENTO: USADA PARA GERAR COMISSAO NOTA FISCAL FORMULARIO
            - MODULO CHSERVER - USADA PARA GERAR COMISSAO NOTA FISCAL NFe

    */
END^


ALTER PROCEDURE GERAMOVFINANCEIRAS (
    CHAVECONTA INTEGER,
    CHAVEEMPCAIXA INTEGER,
    TIPO CHAR(2),
    DATARECEBIMENTO DATE,
    FORMAPAGTO INTEGER,
    GERACAIXA CHAR(1),
    GERARCAIXALANCBANCARIO CHAR(1),
    DATACAIXA DATE,
    OBSBAIXA VARCHAR(1000),
    CHAVEUSUARIO INTEGER,
    CHAVECONTACAIXA INTEGER,
    ECHAVEEMPLANCBANCARIO INTEGER,
    ECHAVECONTABANCARIA INTEGER,
    ETIPOLANCBANCARIO INTEGER,
    ENUMERODOC VARCHAR(40),
    EFAVORECIDO VARCHAR(100),
    EPREDATADO CHAR(1),
    EBOMPARA DATE,
    ECHAVEPLANOCONTA INTEGER,
    ECHAVECENTROCUSTO INTEGER,
    ECHAVEPLANOCONTAJUROS INTEGER,
    ECHAVEPLANOCONTAMULTA INTEGER,
    ECHAVEPLANOCONTADESCTO INTEGER,
    ECHAVEEMPCREDITO INTEGER)
AS
declare variable VDESCONTOS numeric(18,6);
declare variable VCHAVECLIFOR integer;
declare variable OBSDINHEIRO varchar(100);
declare variable CHEQUE integer;
declare variable VCHAVEFORMA integer;
declare variable VCHAVELANCBCO integer;
declare variable NLATUAL double precision;
declare variable VCOMPETENCIA varchar(10);
declare variable VCHAVEPLANOCTA integer;
declare variable VCHAVECENTROCTO integer;
declare variable DESCRICAO varchar(5000);
declare variable VDOC varchar(20);
declare variable RECEBPARCIALSEMJUROS numeric(18,6);
declare variable RECEBPARCIAL numeric(18,6);
declare variable STATUS integer;
declare variable JUROS numeric(18,6);
declare variable PARCELA varchar(5);
declare variable LANCBANCARIO char(1);
declare variable CHAVEMOVFINANCEIRA integer;
declare variable ACRESCIMORENEGOCIADO numeric(18,6);
declare variable CHAVEPCTRANSFCAIXABCO integer;
declare variable CHAVEPCTRANSFBCOCAIXA integer;
declare variable VLRMULTA numeric(18,6);
declare variable VALOR numeric(18,6);
declare variable CHAVEOPERACOESTITULOS integer;
declare variable VFORMACONDPGTO integer;
declare variable VCHAVECONTABANCARIA integer;
declare variable VCHAVECHEQUE integer;
declare variable VCLIFOR varchar(110);
declare variable VOBSREC varchar(5000);
declare variable VOBSPAG varchar(5000);
declare variable VOBSRECCOMP varchar(5000);
declare variable VOBSPAGCOMP varchar(5000);
BEGIN
    /* FORMAS DE PAGTO                PA - CONTAS A PAGAR
    1= DINHEIRO                       RE - CONTAS A RECEBER
    2= CHEQUES                        P2 - CONTAS A PAGAR AGRUPADAS
    3= COBRANCA BANCARIA              R2 - CONTAS A RECEBER AGRUPADA
    4= CREDITO CLIENTE                P+ - PAGAR COMPLEMENTAR
                                      R+ - RECEBER COMPLEMENTAR
                                      RC - RECEBER COMPLETO
                                      PC - PAGAR COMPLETO
                                      RP - RECEBER PARCIAL
                                      PP - PAGAR PARCIAL
                                      PD - PDV
                                      CR - CREDITO CLIENTE
                                      CF - CREDITO FORNECEDOR
                                      FL - FLEX (REPR)*/
    IF ((:TIPO = 'RE') OR (:TIPO = 'R2') OR (:TIPO = 'R+') OR (:TIPO = 'RC') OR
        (:TIPO = 'RP') OR (:TIPO = 'PA') OR (:TIPO = 'P2') OR (:TIPO = 'PC') OR
        (:TIPO = 'PP') OR (:TIPO = 'P+') OR (:TIPO = 'CR') OR (:TIPO = 'CF') OR
        (:TIPO = 'FL')) THEN BEGIN
        CHAVEMOVFINANCEIRA =  GEN_ID(GEN_MOVFINANCEIRAS_ID, 0);
    END
    SELECT MAX(CASE WHEN CHAVE=29 THEN CHAVEPLANOCONTA END) AS CHAVEPCTRANSFCAIXABCO,
           MAX(CASE WHEN CHAVE=30 THEN CHAVEPLANOCONTA END) AS CHAVEPCTRANSFBCOCAIXA
    FROM CONFIGCAIXA
    INTO :CHAVEPCTRANSFCAIXABCO, :CHAVEPCTRANSFBCOCAIXA;
    LANCBANCARIO= 'N';
    IF (:TIPO = 'PA') THEN BEGIN
        VCHAVEPLANOCTA= :ECHAVEPLANOCONTA;
        VCHAVECENTROCTO= :ECHAVECENTROCUSTO;
        SELECT P.NL, P.COMPETENCIA,
        P.DESCRICAO, P.DOCUMENTO, P.STATUS, COALESCE(P.PARCELA, '1'),
        P.CHAVECLIFOR, P.CHAVEOPERACOESTITULOS, P.TIPO, OBS,
        C.CODIGO||' - '||C.RAZAOSOCIAL
        FROM PAGAR P
        LEFT JOIN CLIFOR C ON (P.CHAVECLIFOR=C.CHAVE)
        WHERE (P.CHAVE=:CHAVECONTA)
        INTO :NLATUAL, :VCOMPETENCIA,
        :DESCRICAO, :VDOC, :STATUS, :PARCELA,
        :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO,
        :VOBSPAG, :VCLIFOR;
        FOR SELECT CHAVECHEQUE, CHAVEFORMAPGTO, CHAVELANCBCO, VALOR, CHAVECONTABCO, OBSDINHEIRO
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='PA') AND (GERADONOCAIXA=0)
        ORDER BY CHAVEFORMAPGTO
        INTO :CHEQUE, :VCHAVEFORMA, :VCHAVELANCBCO, :VALOR, :VCHAVECONTABANCARIA, :OBSDINHEIRO DO BEGIN
            IF (COALESCE(:CHEQUE, 0) > 0) THEN BEGIN
                UPDATE CHEQUES SET
                UTILIZADO = 'S',
                NLSAIDA   = :NLATUAL,
                CHAVEPAGAR= :CHAVECONTA,
                DATAUTILIZADO = :DATARECEBIMENTO,
                OBS = CAST(SUBSTRING(COALESCE(OBS,'') ||
                    CASE WHEN COALESCE(OBS,'') <> '' THEN
                        ASCII_CHAR(13) || ASCII_CHAR(10)
                    ELSE
                        ''
                    END
                    || 'PGTO DOC: '||:VDOC||'/'||:PARCELA||' EM '||LPAD(EXTRACT(DAY FROM :DATARECEBIMENTO),2,0)||'/'||LPAD(EXTRACT(MONTH FROM :DATARECEBIMENTO),2,0)||'/'||EXTRACT(YEAR FROM :DATARECEBIMENTO)||' FORN.: '||:VCLIFOR FROM 1 FOR 500) AS VARCHAR(5000))
                WHERE CHAVE = :CHEQUE;
            END
            IF (:VCHAVEFORMA = 3) THEN BEGIN
                LANCBANCARIO= 'S';
                IF ((:GERACAIXA = 'S') AND (:GERARCAIXALANCBANCARIO='S')) THEN BEGIN
                    INSERT INTO CAIXA (CHAVECENTROCTO, CHAVEPLANOCTO, CHAVECONTA,
                        DOCUMENTO, HISTORICO, COMPETENCIA,
                        LANCAMENTO, VALOR, CHAVEEMPRESA, NL,
                        LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS, CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                        CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO)
                    VALUES (:VCHAVECENTROCTO, :CHAVEPCTRANSFBCOCAIXA, :CHAVECONTA,
                        :VDOC||'/'||:PARCELA, CAST(SUBSTRING('GERADO AUT. - LANC. BANC. '||:OBSDINHEIRO FROM 1 FOR 100) AS VARCHAR(1000)),
                        :VCOMPETENCIA, :DATACAIXA, :VALOR, :CHAVEEMPCAIXA, :NLATUAL,
                        'S', :CHAVEMOVFINANCEIRA, CAST (SUBSTRING (CASE WHEN (COALESCE(:OBSBAIXA, '') <> '') AND (COALESCE(:VOBSPAG, '') <> '') THEN :VOBSPAG || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('PAGAMENTO ' || :OBSBAIXA AS VARCHAR(5000))
                        WHEN (COALESCE(:VOBSPAG, '') = '') AND (COALESCE(:OBSBAIXA, '') <> '') THEN CAST('PAGAMENTO ' || :OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSPAG) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                        :CHAVEUSUARIO, :CHAVEUSUARIO,:VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, :VCHAVECONTABANCARIA, :VFORMACONDPGTO);
                END
            END
            IF (:VCHAVEFORMA = 4) THEN BEGIN
                INSERT INTO CREDITO(CHAVEEMPRESA, CHAVECLIFOR, DATA, DESCRICAO, VLRCREDITO, NLORIGEMLANC, TIPO)
                VALUES(:ECHAVEEMPCREDITO, :VCHAVECLIFOR, :DATARECEBIMENTO, CAST(SUBSTRING('BAIXA DE CREDITO DOC: '||:VDOC||'/'||:PARCELA||' '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)), :VALOR*(-1), :NLATUAL, 1);
            END
        END
        SELECT FIRST(1) CHAVECONTA, OBSDINHEIRO, COALESCE(VALOR,0), COALESCE(JUROS,0),
        COALESCE(DESCONTOS,0), COALESCE(VLRMULTA,0), COALESCE(CHAVECHEQUE,0)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='PA') AND (GERADONOCAIXA IN (0,1))
        ORDER BY CHAVE DESC
        INTO :CHAVECONTA, :OBSDINHEIRO, :VALOR, :JUROS,
        :VDESCONTOS, :VLRMULTA, :VCHAVECHEQUE;
        IF ((:GERACAIXA = 'S') AND (:FORMAPAGTO<>4)) THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASCAIXA(:VCHAVEFORMA,
                :GERARCAIXALANCBANCARIO,
                :CHAVEEMPCAIXA,
                :DATACAIXA,
                :VCHAVEPLANOCTA,
                :VCHAVECENTROCTO,
                :CHAVECONTA,
                :OBSDINHEIRO,
                :VDOC||'/'||:PARCELA,
                :VCOMPETENCIA,
                :VALOR,
                :JUROS,
                :VLRMULTA,
                :VDESCONTOS,
                :CHAVEUSUARIO,
                :VCHAVECLIFOR,
                :CHAVEOPERACOESTITULOS,
                CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSPAG,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') <> '') AND (COALESCE(:VOBSPAG,'') <> '')
                THEN :VOBSPAG || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSPAG) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                :NLATUAL,
                :LANCBANCARIO,
                :CHAVEMOVFINANCEIRA,
                :ECHAVEPLANOCONTAJUROS,
                :ECHAVEPLANOCONTAMULTA,
                :ECHAVEPLANOCONTADESCTO,
                :CHAVECONTACAIXA,
                :VFORMACONDPGTO,
                :VCHAVECHEQUE);
        END
        IF (:LANCBANCARIO = 'S') THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASLANCBCO(:ECHAVEEMPLANCBANCARIO,
                :DATARECEBIMENTO,
                :VCHAVEPLANOCTA,
                :VCHAVECENTROCTO,
                :CHAVECONTA,
                :OBSDINHEIRO,
                :VCOMPETENCIA,
                :VALOR,
                :JUROS,
                :VLRMULTA,
                :VDESCONTOS,
                :CHAVEUSUARIO,
                :VCHAVECLIFOR,
                :CHAVEOPERACOESTITULOS,
                :NLATUAL,
                :CHAVEMOVFINANCEIRA,
                :ECHAVEPLANOCONTAJUROS,
                :ECHAVEPLANOCONTAMULTA,
                :ECHAVEPLANOCONTADESCTO,
                :EPREDATADO,
                :DATACAIXA,
                :ECHAVECONTABANCARIA,
                :ETIPOLANCBANCARIO,
                :ENUMERODOC,
                :EFAVORECIDO,
                CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSPAG,'') = '') AND (COALESCE(:DESCRICAO,'') <> '') THEN CAST(:DESCRICAO AS VARCHAR(5000)) WHEN (COALESCE(:DESCRICAO,'') <> '') AND (COALESCE(:VOBSPAG,'') <> '')
                THEN :VOBSPAG || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST(:DESCRICAO AS VARCHAR(5000)) WHEN (COALESCE(:DESCRICAO,'') = '') THEN (:VOBSPAG) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                :EBOMPARA,
                :CHEQUE);
        END
        UPDATE MOVFINANCEIRAS SET
        GERADONOCAIXA = 1,
        NL = :NLATUAL,
        OBSDINHEIRO = CAST(SUBSTRING(:OBSBAIXA FROM 1 FOR 100) AS VARCHAR(1000))
        WHERE (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='PA') AND (GERADONOCAIXA=0);
        SELECT COALESCE(SUM(VALOR),0) - COALESCE(SUM(JUROS),0) - COALESCE(SUM(VLRMULTA),0), COALESCE(SUM(VALOR),0), COALESCE(SUM(JUROS),0),
        COALESCE(SUM(DESCONTOS),0), COALESCE(SUM(VLRMULTA),0) FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='PA')
        INTO :RECEBPARCIALSEMJUROS, :RECEBPARCIAL, :JUROS, :VDESCONTOS, :VLRMULTA;
        IF (:STATUS = 0) THEN BEGIN
            UPDATE PAGAR SET
                RECEBPARCIALSEMJUROS = :RECEBPARCIALSEMJUROS + :VDESCONTOS,
                RECEBPARCIAL         = :RECEBPARCIAL,
                ACRESCIMO            = :JUROS,
                VLRMULTA             = :VLRMULTA,
                ABATIMENTO           = :VDESCONTOS,
                VLRPAGO              = :RECEBPARCIAL,
                DATAPAGAMENTO        = :DATARECEBIMENTO,
                CHAVEUSUARIOALT      = :CHAVEUSUARIO
            WHERE CHAVE = :CHAVECONTA;
        END ELSE BEGIN
            UPDATE PAGAR SET
                RECEBPARCIALSEMJUROS = :RECEBPARCIALSEMJUROS  + :VDESCONTOS,
                RECEBPARCIAL         = :RECEBPARCIAL,
                CHAVEUSUARIOALT      = :CHAVEUSUARIO
            WHERE CHAVE = :CHAVECONTA;
        END
    END
    IF (:TIPO = 'RE') THEN BEGIN
        VCHAVEPLANOCTA= :ECHAVEPLANOCONTA;
        VCHAVECENTROCTO= :ECHAVECENTROCUSTO;
        SELECT NL,
        DESCRICAO, DOCUMENTO, STATUS, COALESCE(PARCELA, '1'), COALESCE(ACRESCIMORENEGOCIADO, 0),
        CHAVECLIFOR, CHAVEOPERACOESTITULOS, TIPO, OBS
        FROM RECEBER
        WHERE (CHAVE=:CHAVECONTA)
        INTO :NLATUAL,
        :DESCRICAO, :VDOC, :STATUS, :PARCELA, :ACRESCIMORENEGOCIADO,
        :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO, :VOBSREC;
        SELECT (COALESCE(SUM(VALOR),0) - COALESCE(SUM(JUROS),0) - COALESCE(SUM(VLRMULTA),0)),
        COALESCE(SUM(VALOR),0), COALESCE(SUM(JUROS),0),
        COALESCE(SUM(DESCONTOS),0), COALESCE(SUM(VLRMULTA),0) FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA IN ('RE','PD'))
        INTO :RECEBPARCIALSEMJUROS,
        :RECEBPARCIAL, :JUROS,
        :VDESCONTOS, :VLRMULTA;
        IF (:STATUS = 0) THEN BEGIN
            UPDATE RECEBER SET
                RECEBPARCIALSEMJUROS = :RECEBPARCIALSEMJUROS + :VDESCONTOS,
                RECEBPARCIAL         = :RECEBPARCIAL,
                ACRESCIMO            = :JUROS-:ACRESCIMORENEGOCIADO,
                VLRMULTA             = :VLRMULTA,
                ABATIMENTO           = :VDESCONTOS,
                VALORBAIXADO         = :RECEBPARCIAL,
                DATABAIXA            = :DATARECEBIMENTO,
                CHAVEUSUARIOALT      = :CHAVEUSUARIO
            WHERE CHAVE = :CHAVECONTA;
        END ELSE BEGIN
            UPDATE RECEBER SET
                RECEBPARCIALSEMJUROS = :RECEBPARCIALSEMJUROS + :VDESCONTOS,
                RECEBPARCIAL         = :RECEBPARCIAL,
                CHAVEUSUARIOALT      = :CHAVEUSUARIO
            WHERE CHAVE = :CHAVECONTA;
        END
        FOR SELECT CHAVECHEQUE, CHAVEFORMAPGTO, CHAVELANCBCO, VALOR, CHAVECONTABCO, OBSDINHEIRO
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (GERADONOCAIXA=0) AND (TIPOCONTA = 'RE')
        ORDER BY CHAVEFORMAPGTO
        INTO :CHEQUE, :VCHAVEFORMA, :VCHAVELANCBCO, :VALOR, :VCHAVECONTABANCARIA, :OBSDINHEIRO DO BEGIN
            IF (COALESCE(:CHEQUE, 0) > 0) THEN BEGIN
                UPDATE CHEQUES SET
                CHAVERECEBER = :CHAVECONTA,
                NLENTRADA = :NLATUAL,
                UTILIZADO = CASE WHEN :VCHAVEFORMA=3 THEN 'S' ELSE 'N' END, 
                DATAUTILIZADO = CASE WHEN :VCHAVEFORMA=3 THEN :DATARECEBIMENTO ELSE DATAUTILIZADO END,
                NLSAIDA = CASE WHEN :VCHAVEFORMA=3 THEN :NLATUAL ELSE NLSAIDA END
                WHERE (CHAVE=:CHEQUE);
            END
            IF (:VCHAVEFORMA = 3) THEN BEGIN
                LANCBANCARIO= 'S';
                IF ((:GERACAIXA = 'S') AND (:GERARCAIXALANCBANCARIO = 'S')) THEN BEGIN
                    INSERT INTO CAIXA (CHAVECENTROCTO, CHAVEPLANOCTO, CHAVECONTA,
                        DOCUMENTO, HISTORICO, COMPETENCIA,
                        LANCAMENTO, VALOR, CHAVEEMPRESA, NL,
                        LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS, CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                        CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO)
                    VALUES (:VCHAVECENTROCTO, :CHAVEPCTRANSFCAIXABCO, :CHAVECONTA,
                        :VDOC||'/'||:PARCELA, CAST(SUBSTRING('GERADO AUT. - LANC. BANC. '||:OBSDINHEIRO FROM 1 FOR 100)AS VARCHAR(1000)),
                        LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                        :DATACAIXA, :VALOR, :CHAVEEMPCAIXA, :NLATUAL,
                        'S', :CHAVEMOVFINANCEIRA, CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSREC,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:VOBSREC,'') <> '') AND (COALESCE(:OBSBAIXA,'') <> '')
                        THEN :VOBSREC || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSREC) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                        :CHAVEUSUARIO, :CHAVEUSUARIO, :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, :VCHAVECONTABANCARIA, :VFORMACONDPGTO);
                END
            END
            IF (:VCHAVEFORMA = 4) THEN BEGIN
                INSERT INTO CREDITO(CHAVEEMPRESA, CHAVECLIFOR, DATA, DESCRICAO, VLRCREDITO, NLORIGEMLANC, TIPO)
                VALUES(:ECHAVEEMPCREDITO, :VCHAVECLIFOR, :DATARECEBIMENTO, CAST(SUBSTRING('BAIXA DE CREDITO DOC: '||:VDOC||'/'||:PARCELA||' '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)), :VALOR*(-1), :NLATUAL, 0);
            END
        END
        SELECT FIRST(1) OBSDINHEIRO, COALESCE(VALOR,0), COALESCE(JUROS,0), COALESCE(DESCONTOS,0),  COALESCE(VLRMULTA,0), COALESCE(CHAVECHEQUE,0)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA = 'RE')
        ORDER BY CHAVE DESC
        INTO :OBSDINHEIRO, :VALOR, :JUROS, :VDESCONTOS, :VLRMULTA, :VCHAVECHEQUE;
        IF ((:GERACAIXA = 'S') AND (:FORMAPAGTO<>4)) THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASCAIXA(:VCHAVEFORMA,
                :GERARCAIXALANCBANCARIO,
                :CHAVEEMPCAIXA,
                :DATACAIXA,
                :VCHAVEPLANOCTA,
                :VCHAVECENTROCTO,
                :CHAVECONTA,
                :OBSDINHEIRO,
                :VDOC||'/'||:PARCELA,
                LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                :VALOR,
                :JUROS,
                :VLRMULTA,
                :VDESCONTOS,
                :CHAVEUSUARIO,
                :VCHAVECLIFOR,
                :CHAVEOPERACOESTITULOS,
                CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSREC,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:VOBSREC,'') <> '') AND (COALESCE(:OBSBAIXA,'') <> '')
                THEN :VOBSREC || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSREC) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                :NLATUAL,
                :LANCBANCARIO,
                :CHAVEMOVFINANCEIRA,
                :ECHAVEPLANOCONTAJUROS,
                :ECHAVEPLANOCONTAMULTA,
                :ECHAVEPLANOCONTADESCTO,
                :CHAVECONTACAIXA,
                :VFORMACONDPGTO,
                :VCHAVECHEQUE);
        END
        IF (:LANCBANCARIO = 'S') THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASLANCBCO(:ECHAVEEMPLANCBANCARIO,
                :DATARECEBIMENTO,
                :VCHAVEPLANOCTA,
                :VCHAVECENTROCTO,
                :CHAVECONTA,
                :OBSDINHEIRO,
                LPAD(SUBSTRING(:DATARECEBIMENTO FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATARECEBIMENTO FROM 1 FOR 4),
                :VALOR,
                :JUROS,
                :VLRMULTA,
                :VDESCONTOS,
                :CHAVEUSUARIO,
                :VCHAVECLIFOR,
                :CHAVEOPERACOESTITULOS,
                :NLATUAL,
                :CHAVEMOVFINANCEIRA,
                :ECHAVEPLANOCONTAJUROS,
                :ECHAVEPLANOCONTAMULTA,
                :ECHAVEPLANOCONTADESCTO,
                :EPREDATADO,
                :DATACAIXA,
                :ECHAVECONTABANCARIA,
                :ETIPOLANCBANCARIO,
                :ENUMERODOC,
                :EFAVORECIDO,
                CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSREC,'') = '') AND (COALESCE(:DESCRICAO,'') <> '') THEN CAST(:DESCRICAO AS VARCHAR (5000))
                WHEN (COALESCE(:VOBSREC,'') <> '') AND (COALESCE(:DESCRICAO,'') <> '') THEN :VOBSREC || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST(:DESCRICAO AS VARCHAR (5000)) WHEN (COALESCE(:DESCRICAO,'') = '') THEN (:VOBSREC) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                :EBOMPARA,
                :CHEQUE);
        END
        UPDATE MOVFINANCEIRAS SET
        GERADONOCAIXA = 1,
        NL=:NLATUAL,
        OBSDINHEIRO = CAST(SUBSTRING(:OBSBAIXA FROM 1 FOR 100) AS VARCHAR(1000))
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='RE') AND ((NL <> :NLATUAL) OR (GERADONOCAIXA <> 1));
    END
    IF ((:TIPO = 'P2') OR (:TIPO = 'R2') OR (:TIPO = 'RC') OR
        (:TIPO = 'RP') OR (:TIPO = 'PC') OR (:TIPO = 'PP') OR
        (:TIPO = 'P+') OR (:TIPO = 'R+') ) THEN BEGIN
        IF (:FORMAPAGTO = 3) THEN
            LANCBANCARIO = 'S';
        ELSE
            LANCBANCARIO = 'N';
    END
    IF (:TIPO = 'P+') THEN BEGIN
        SELECT P.NL, P.COMPETENCIA, COALESCE(P.CHAVEPLANOCTO,2), COALESCE(P.CHAVECENTROCTO,1),
        P.DESCRICAO, P.DOCUMENTO, P.STATUS, COALESCE(P.PARCELA, '1'),
        P.CHAVECLIFOR, P.CHAVEOPERACOESTITULOS, P.TIPO, OBS,
        C.CODIGO||' - '||C.RAZAOSOCIAL
        FROM PAGAR P
        LEFT JOIN CLIFOR C ON P.CHAVECLIFOR=C.CHAVE
        WHERE (P.CHAVE=:CHAVECONTA)
        INTO :NLATUAL, :VCOMPETENCIA, :VCHAVEPLANOCTA, :VCHAVECENTROCTO,
            :DESCRICAO, :VDOC, :STATUS, :PARCELA,
            :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO, :VOBSPAGCOMP,
            :VCLIFOR;
        FOR SELECT DISTINCT CHAVECHEQUE, CHAVEFORMAPGTO, CHAVELANCBCO, VALOR,
        CHAVECONTABCO, OBSDINHEIRO
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='P2')
        ORDER BY CHAVEFORMAPGTO
        INTO :CHEQUE, :VCHAVEFORMA, :VCHAVELANCBCO, :VALOR,
        :VCHAVECONTABANCARIA, :OBSDINHEIRO
        DO BEGIN
            IF (COALESCE(:CHEQUE, 0) > 0) THEN BEGIN
                UPDATE CHEQUES SET
                    CHAVEPAGAR    = :CHAVECONTA,
                    UTILIZADO     = 'S',
                    NLSAIDA       = :NLATUAL,
                    DATAUTILIZADO = :DATARECEBIMENTO,
                    OBS = CAST(SUBSTRING(COALESCE(OBS,'') ||
                        CASE WHEN COALESCE(OBS,'') <> '' THEN
                            ASCII_CHAR(13) || ASCII_CHAR(10)
                        ELSE
                            ''
                        END
                        || 'PGTO DOC: '||:VDOC||'/'||:PARCELA||' EM '||LPAD(EXTRACT(DAY FROM :DATARECEBIMENTO),2,0)||'/'||LPAD(EXTRACT(MONTH FROM :DATARECEBIMENTO),2,0)||'/'||EXTRACT(YEAR FROM :DATARECEBIMENTO)||' FORN.: '||:VCLIFOR FROM 1 FOR 500) AS VARCHAR(1000))
                WHERE (CHAVE=:CHEQUE);
            END
            IF (:VCHAVEFORMA=3) THEN BEGIN
                IF ((:GERACAIXA='S') AND (:GERARCAIXALANCBANCARIO='S')) THEN BEGIN
                    INSERT INTO CAIXA (CHAVECENTROCTO, CHAVEPLANOCTO, CHAVECONTA,
                        DOCUMENTO, HISTORICO, COMPETENCIA,
                        LANCAMENTO, VALOR, CHAVEEMPRESA, NL,
                        LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS, CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                        CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO)
                    VALUES (:VCHAVECENTROCTO, :CHAVEPCTRANSFBCOCAIXA, :CHAVECONTA,
                        :VDOC||'/'||:PARCELA, CAST(SUBSTRING('GERADO AUT. - LANC. BANC. '||COALESCE(:DESCRICAO,'') FROM 1 FOR 100) AS VARCHAR(1000)),
                        :VCOMPETENCIA, :DATACAIXA, :VALOR, :CHAVEEMPCAIXA, :NLATUAL,
                        'S', :CHAVEMOVFINANCEIRA,
                        CAST (SUBSTRING (CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') AND (COALESCE(:VOBSPAGCOMP,'') <> '') THEN :VOBSPAGCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000))
                    WHEN (COALESCE(:VOBSPAGCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSPAGCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                        :CHAVEUSUARIO, :CHAVEUSUARIO, :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, :VCHAVECONTABANCARIA, :VFORMACONDPGTO);
                END
            END
            IF (:VCHAVEFORMA = 4) THEN BEGIN
                INSERT INTO CREDITO(CHAVEEMPRESA, CHAVECLIFOR, DATA, DESCRICAO, VLRCREDITO, NLORIGEMLANC, TIPO)
                VALUES(:ECHAVEEMPCREDITO, :VCHAVECLIFOR, :DATARECEBIMENTO, CAST(SUBSTRING('BAIXA DE CREDITO AGRUPADA: '||:VDOC||'/'||:PARCELA||' '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)), :VALOR*(-1), :NLATUAL, 1);
            END
        END
        UPDATE MOVFINANCEIRAS SET
        TIPOCONTA='PA',
        OBSDINHEIRO = CAST(SUBSTRING(:OBSBAIXA FROM 1 FOR 100) AS VARCHAR(1000))
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (NL=:NLATUAL) AND (TIPOCONTA='P2');
        SELECT SUM(VALOR), SUM(JUROS), SUM(VLRMULTA), SUM(DESCONTOS)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='PA')
        INTO :RECEBPARCIAL, :JUROS, :VLRMULTA, :VDESCONTOS;
        IF (:STATUS=0) THEN BEGIN
            UPDATE PAGAR SET
            DATAPAGAMENTO = :DATARECEBIMENTO,
            VLRPAGO= :RECEBPARCIAL,
            RECEBPARCIAL= :RECEBPARCIAL,
            RECEBPARCIALSEMJUROS = :RECEBPARCIAL - :JUROS - :VLRMULTA + :VDESCONTOS,
            VLRMULTA= :VLRMULTA,
            ACRESCIMO= :JUROS,
            ABATIMENTO= :VDESCONTOS,
            CHAVEUSUARIOALT= :CHAVEUSUARIO
            WHERE CHAVE=:CHAVECONTA;
       END
    END
    /* RECEBER COMPLETO COMPOSTO */
    IF (:TIPO = 'RC') THEN BEGIN
        SELECT NL, COALESCE(CHAVEPLANOCTO,1), COALESCE(CHAVECENTROCTO,1),
        DESCRICAO, DOCUMENTO, STATUS, COALESCE(PARCELA, '1'), COALESCE(ACRESCIMORENEGOCIADO, 0),
        CHAVECLIFOR, CHAVEOPERACOESTITULOS, TIPO, OBS
        FROM RECEBER
        WHERE (CHAVE=:CHAVECONTA)
        INTO :NLATUAL, :VCHAVEPLANOCTA, :VCHAVECENTROCTO,
        :DESCRICAO, :VDOC, :STATUS, :PARCELA, :ACRESCIMORENEGOCIADO,
        :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO, :VOBSRECCOMP;
        UPDATE MOVFINANCEIRAS SET
        NL=:NLATUAL,
        GERADONOCAIXA=1
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='R2') AND (COALESCE(NL,0) <> :NLATUAL);
        SELECT FIRST(1) OBSDINHEIRO, COALESCE(VALOR,0), COALESCE(JUROS,0), COALESCE(DESCONTOS,0),  COALESCE(VLRMULTA,0),
        COALESCE(CHAVECHEQUE,0)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA = 'R2')
        ORDER BY CHAVE DESC
        INTO :OBSDINHEIRO, :VALOR, :JUROS, :VDESCONTOS, :VLRMULTA,
        :VCHAVECHEQUE;
        IF (:GERACAIXA = 'S') THEN BEGIN
            IF ((:FORMAPAGTO NOT IN (3,4)) OR ((:FORMAPAGTO=3) AND (:GERARCAIXALANCBANCARIO='S'))) THEN BEGIN
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                    NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, COALESCE(R.CHAVEPLANOCTO,1),
                    COALESCE(R.CHAVECENTROCTO,1), :CHAVECONTA, SUBSTRING('RECBTO '||R.DESCRICAO FROM 1 FOR 100),
                    R.DOCUMENTO||'/'||:PARCELA,
                    LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                    COALESCE(M.VALOR,0) - COALESCE(M.JUROS,0) - COALESCE(M.VLRMULTA,0) + COALESCE(M.DESCONTOS,0),
                    :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA,
                    CAST (SUBSTRING (CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') AND (COALESCE(:VOBSRECCOMP,'') <> '')
                    THEN :VOBSRECCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:VOBSRECCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000))
                    WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSRECCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                    :CHAVEUSUARIO, :CHAVEUSUARIO, R.CHAVECLIFOR,
                    R.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, R.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN RECEBER R ON (M.NL=R.NL) AND (M.CHAVECONTA=R.CHAVE)
                WHERE (M.ATIVO=1) AND (R.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA) AND (M.TIPOCONTA='R2');
        
                EXECUTE PROCEDURE GERARMOVFINANCEIRASCAIXAAGRUP(:CHAVEEMPCAIXA,
                    :DATACAIXA,
                    :ECHAVEPLANOCONTAJUROS,
                    :VCHAVECENTROCTO,
                    :CHAVECONTA,
                    CAST(SUBSTRING('RECBTO '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)),
                    :VDOC||'/'||:PARCELA,
                    LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                    :NLATUAL,
                    :LANCBANCARIO,
                    :CHAVEMOVFINANCEIRA,
                    :CHAVEUSUARIO,
                    :VCHAVECLIFOR,
                    :CHAVEOPERACOESTITULOS,
                    :ECHAVEPLANOCONTAMULTA,
                    :ECHAVEPLANOCONTADESCTO,
                    'R2',
                    :DESCRICAO,
                    CAST (SUBSTRING (CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') AND (COALESCE(:VOBSRECCOMP,'') <> '')
                    THEN :VOBSRECCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:VOBSRECCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000))
                    WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSRECCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                    :CHAVECONTACAIXA,
                    :VFORMACONDPGTO,
                    :VCHAVECHEQUE);
            END
        END
        IF (:LANCBANCARIO = 'S') THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASLANCBCO(:ECHAVEEMPLANCBANCARIO,
                    :DATARECEBIMENTO,
                    :VCHAVEPLANOCTA,
                    :VCHAVECENTROCTO,
                    :CHAVECONTA,
                    CAST(SUBSTRING('RECBTO '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)),
                    LPAD(SUBSTRING(:DATARECEBIMENTO FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATARECEBIMENTO FROM 1 FOR 4),
                    :VALOR,
                    :JUROS,
                    :VLRMULTA,
                    :VDESCONTOS,
                    :CHAVEUSUARIO,
                    :VCHAVECLIFOR,
                    :CHAVEOPERACOESTITULOS,
                    :NLATUAL,
                    :CHAVEMOVFINANCEIRA,
                    :ECHAVEPLANOCONTAJUROS,
                    :ECHAVEPLANOCONTAMULTA,
                    :ECHAVEPLANOCONTADESCTO,
                    :EPREDATADO,
                    :DATACAIXA,
                    :ECHAVECONTABANCARIA,
                    :ETIPOLANCBANCARIO,
                    :ENUMERODOC,
                    :EFAVORECIDO,
                    CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSRECCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:VOBSRECCOMP,'') <> '') AND (COALESCE(:OBSBAIXA,'') <> '')
                    THEN :VOBSRECCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSRECCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                    :EBOMPARA,
                    :CHEQUE);
        END
    END
    /* RECEBER PARCIAL DENTRO DO RECEBER COMPOSTO */
    IF (:TIPO = 'RP') THEN BEGIN
        SELECT NL, COALESCE(CHAVEPLANOCTO,1), COALESCE(CHAVECENTROCTO,1),
        DESCRICAO, DOCUMENTO, STATUS, COALESCE(PARCELA, '1'), COALESCE(ACRESCIMORENEGOCIADO, 0),
        CHAVECLIFOR, CHAVEOPERACOESTITULOS, TIPO
        FROM RECEBER
        WHERE (CHAVE=:CHAVECONTA)
        INTO :NLATUAL, :VCHAVEPLANOCTA, :VCHAVECENTROCTO,
        :DESCRICAO, :VDOC, :STATUS, :PARCELA, :ACRESCIMORENEGOCIADO,
        :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO;
        UPDATE MOVFINANCEIRAS SET
        NL= :NLATUAL,
        GERADONOCAIXA=1
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='R2');
        SELECT FIRST(1) OBSDINHEIRO, COALESCE(VALOR,0), COALESCE(JUROS,0), COALESCE(VLRMULTA,0), COALESCE(DESCONTOS,0),
        COALESCE(CHAVECHEQUE,0)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA = 'R2')
        ORDER BY CHAVE DESC
        INTO :OBSDINHEIRO, :VALOR, :JUROS, :VLRMULTA, :VDESCONTOS, :VCHAVECHEQUE;
        IF (:GERACAIXA = 'S') THEN BEGIN
            IF ((:FORMAPAGTO NOT IN (3,4)) OR ((:FORMAPAGTO=3) AND (:GERARCAIXALANCBANCARIO='S'))) THEN BEGIN
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                    NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, COALESCE(R.CHAVEPLANOCTO,1),
                    COALESCE(R.CHAVECENTROCTO,1), :CHAVECONTA, SUBSTRING('RECBTO '||R.DESCRICAO FROM 1 FOR 100),
                    :VDOC||'/'||:PARCELA,
                    LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                    COALESCE(M.VALOR,0) - COALESCE(M.JUROS,0) - COALESCE(M.VLRMULTA,0) + COALESCE(M.DESCONTOS,0),
                    :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) END,
                    :CHAVEUSUARIO, :CHAVEUSUARIO, R.CHAVECLIFOR,
                    R.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, R.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN RECEBER R ON (M.NL=R.NL) AND (M.CHAVECONTA=R.CHAVE)
                WHERE (M.ATIVO=1) AND (R.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA) AND (M.TIPOCONTA='R2');
    
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                    NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, :ECHAVEPLANOCONTAJUROS,
                    COALESCE(R.CHAVECENTROCTO,1), :CHAVECONTA, SUBSTRING('RECBTO '||R.DESCRICAO FROM 1 FOR 100),
                    R.DOCUMENTO||'/'||:PARCELA,
                    LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                    COALESCE(M.JUROS,0),
                    :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) END,
                    :CHAVEUSUARIO, :CHAVEUSUARIO, R.CHAVECLIFOR,
                    R.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, R.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN RECEBER R ON (M.NL=R.NL) AND (M.CHAVECONTA=R.CHAVE)
                WHERE (M.ATIVO=1) AND (R.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA)
                AND (M.TIPOCONTA='R2') AND (M.JUROS>0);
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                    NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, :ECHAVEPLANOCONTAMULTA,
                    COALESCE(R.CHAVECENTROCTO,1), :CHAVECONTA, SUBSTRING('RECBTO '||R.DESCRICAO FROM 1 FOR 100),
                    R.DOCUMENTO||'/'||:PARCELA,
                    LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                    COALESCE(M.VLRMULTA,0),
                    :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) END,
                    :CHAVEUSUARIO, :CHAVEUSUARIO, R.CHAVECLIFOR,
                    R.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, R.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN RECEBER R ON (M.NL=R.NL) AND (M.CHAVECONTA=R.CHAVE)
                WHERE (M.ATIVO=1) AND (R.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA)
                AND (M.TIPOCONTA='R2') AND (M.VLRMULTA>0);
            END
        END
        IF (:LANCBANCARIO = 'S') THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASLANCBCO(:ECHAVEEMPLANCBANCARIO,
                    :DATARECEBIMENTO,
                    :VCHAVEPLANOCTA,
                    :VCHAVECENTROCTO,
                    :CHAVECONTA,
                    CAST(SUBSTRING('RECBTO '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)),
                    LPAD(SUBSTRING(:DATARECEBIMENTO FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATARECEBIMENTO FROM 1 FOR 4),
                    :VALOR,
                    :JUROS,
                    :VLRMULTA,
                    :VDESCONTOS,
                    :CHAVEUSUARIO,
                    :VCHAVECLIFOR,
                    :CHAVEOPERACOESTITULOS,
                    :NLATUAL,
                    :CHAVEMOVFINANCEIRA,
                    :ECHAVEPLANOCONTAJUROS,
                    :ECHAVEPLANOCONTAMULTA,
                    :ECHAVEPLANOCONTADESCTO,
                    :EPREDATADO,
                    :DATACAIXA,
                    :ECHAVECONTABANCARIA,
                    :ETIPOLANCBANCARIO,
                    :ENUMERODOC,
                    :EFAVORECIDO,
                    :OBSDINHEIRO,
                    :EBOMPARA,
                    :CHEQUE);
        END
    END
    IF (:TIPO = 'R+') THEN BEGIN
        SELECT NL, COALESCE(CHAVEPLANOCTO,1), COALESCE(CHAVECENTROCTO,1),
        DESCRICAO, DOCUMENTO, STATUS, COALESCE(PARCELA, '1'), COALESCE(ACRESCIMORENEGOCIADO, 0),
        CHAVECLIFOR, CHAVEOPERACOESTITULOS, TIPO, OBS
        FROM RECEBER
        WHERE (CHAVE=:CHAVECONTA)
        INTO :NLATUAL, :VCHAVEPLANOCTA, :VCHAVECENTROCTO,
        :DESCRICAO, :VDOC, :STATUS, :PARCELA, :ACRESCIMORENEGOCIADO,
        :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO, :VOBSRECCOMP;
        FOR SELECT DISTINCT CHAVECHEQUE, CHAVEFORMAPGTO, CHAVELANCBCO, VALOR,
        CHAVECONTABCO, OBSDINHEIRO
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='R2')
        ORDER BY CHAVEFORMAPGTO
        INTO :CHEQUE, :VCHAVEFORMA, :VCHAVELANCBCO, :VALOR,
        :VCHAVECONTABANCARIA, :OBSDINHEIRO
        DO BEGIN
            IF (COALESCE(:CHEQUE, 0) > 0) THEN BEGIN
                UPDATE CHEQUES SET
                    CHAVERECEBER = :CHAVECONTA,
                    NLENTRADA = :NLATUAL,
                    UTILIZADO = CASE WHEN :VCHAVEFORMA=3 THEN 'S' ELSE 'N' END, 
                    DATAUTILIZADO = CASE WHEN :VCHAVEFORMA=3 THEN :DATARECEBIMENTO ELSE DATAUTILIZADO END,
                    NLSAIDA = CASE WHEN :VCHAVEFORMA=3 THEN :NLATUAL ELSE NLSAIDA END
                WHERE CHAVE=:CHEQUE;
            END
            IF (:VCHAVEFORMA = 3) THEN BEGIN
                IF ((:GERACAIXA = 'S') AND (:GERARCAIXALANCBANCARIO = 'S')) THEN BEGIN
                    INSERT INTO CAIXA (CHAVECENTROCTO, CHAVEPLANOCTO, CHAVECONTA,
                        DOCUMENTO, COMPETENCIA, HISTORICO,
                        LANCAMENTO, VALOR, CHAVEEMPRESA, NL,
                        LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS, CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
                        CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO)
                    VALUES (:VCHAVECENTROCTO, :CHAVEPCTRANSFCAIXABCO, :CHAVECONTA,
                        :VDOC||'/'||:PARCELA,
                        LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                        CAST(SUBSTRING('GERADO AUT. - LANC. BANC. '||COALESCE(:DESCRICAO,'') FROM 1 FOR 100) AS VARCHAR(1000)),
                        :DATACAIXA, :VALOR, :CHAVEEMPCAIXA, :NLATUAL,
                        'S', :CHAVEMOVFINANCEIRA,
                        CAST (SUBSTRING (CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') AND (COALESCE(:VOBSRECCOMP,'') <> '') THEN :VOBSRECCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000))
                        WHEN (COALESCE(:VOBSRECCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('RECEBIMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSRECCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                        :CHAVEUSUARIO, :CHAVEUSUARIO, :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, :VCHAVECONTABANCARIA, :VFORMACONDPGTO);
                END
            END
            IF (:VCHAVEFORMA = 4) THEN BEGIN
                INSERT INTO CREDITO(CHAVEEMPRESA, CHAVECLIFOR, DATA, DESCRICAO, VLRCREDITO, NLORIGEMLANC, TIPO)
                VALUES(:ECHAVEEMPCREDITO, :VCHAVECLIFOR, :DATARECEBIMENTO, CAST(SUBSTRING('BAIXA DE CREDITO AGRUPADA: '||:VDOC||'/'||:PARCELA||' '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)), :VALOR*(-1), :NLATUAL, 0);
            END
        END
        UPDATE MOVFINANCEIRAS SET
        TIPOCONTA = 'RE',
        OBSDINHEIRO = CAST(SUBSTRING(:OBSBAIXA FROM 1 FOR 100) AS VARCHAR(1000))
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (NL=:NLATUAL) AND (TIPOCONTA='R2');
        SELECT SUM(VALOR), SUM(JUROS), SUM(VLRMULTA), SUM(DESCONTOS)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='RE')
        INTO :RECEBPARCIAL, :JUROS, :VLRMULTA, :VDESCONTOS;
        IF (:STATUS=0) THEN BEGIN
            UPDATE RECEBER SET
            DATABAIXA = :DATARECEBIMENTO,
            VALORBAIXADO= :RECEBPARCIAL,
            RECEBPARCIAL= :RECEBPARCIAL,
            RECEBPARCIALSEMJUROS = :RECEBPARCIAL - :JUROS - :VLRMULTA + :VDESCONTOS,
            VLRMULTA= :VLRMULTA,
            ACRESCIMO= :JUROS,
            ABATIMENTO= :VDESCONTOS,
            CHAVEUSUARIOALT = :CHAVEUSUARIO
            WHERE CHAVE=:CHAVECONTA;
        END
    END
    IF (:TIPO = 'PC') THEN BEGIN
        SELECT NL, COALESCE(CHAVEPLANOCTO,2), COALESCE(CHAVECENTROCTO,1),
        DESCRICAO, DOCUMENTO, COMPETENCIA, STATUS, COALESCE(PARCELA, '1'),
        CHAVECLIFOR, CHAVEOPERACOESTITULOS, TIPO, OBS
        FROM PAGAR
        WHERE (CHAVE=:CHAVECONTA)
        INTO :NLATUAL, :VCHAVEPLANOCTA, :VCHAVECENTROCTO,
        :DESCRICAO, :VDOC, :VCOMPETENCIA, :STATUS, :PARCELA,
        :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO, :VOBSPAGCOMP;
        UPDATE MOVFINANCEIRAS SET
        NL=:NLATUAL,
        GERADONOCAIXA=1
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='P2');
        SELECT FIRST(1) OBSDINHEIRO, COALESCE(VALOR,0), COALESCE(JUROS,0), COALESCE(DESCONTOS,0),  COALESCE(VLRMULTA,0),
        COALESCE(CHAVECHEQUE,0)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA = 'P2')
        ORDER BY CHAVE DESC
        INTO :OBSDINHEIRO, :VALOR, :JUROS, :VDESCONTOS, :VLRMULTA,
        :VCHAVECHEQUE;
        IF (:GERACAIXA = 'S') THEN BEGIN
            IF ((:FORMAPAGTO NOT IN  (3,4)) OR ((:FORMAPAGTO=3) AND (:GERARCAIXALANCBANCARIO='S'))) THEN BEGIN
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR, NL,
                    LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, COALESCE(P.CHAVEPLANOCTO,2),
                    COALESCE(P.CHAVECENTROCTO,2), :CHAVECONTA, SUBSTRING('PAGTO '||P.DESCRICAO FROM 1 FOR 100),
                    P.DOCUMENTO||'/'||:PARCELA, :VCOMPETENCIA, COALESCE(M.VALOR,0) - COALESCE(M.JUROS,0) - COALESCE(M.VLRMULTA,0) + COALESCE(M.DESCONTOS,0),
                    :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA,
                    CAST (SUBSTRING (CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') AND (COALESCE(:VOBSPAGCOMP,'') <> '') THEN :VOBSPAGCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000))
                    WHEN (COALESCE(:VOBSPAGCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSPAGCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                    :CHAVEUSUARIO, :CHAVEUSUARIO, P.CHAVECLIFOR,
                    P.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, P.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN PAGAR P ON (M.NL=P.NL) AND (M.CHAVECONTA=P.CHAVE)
                WHERE (M.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA) AND (M.TIPOCONTA='P2');
                EXECUTE PROCEDURE GERARMOVFINANCEIRASCAIXAAGRUP(:CHAVEEMPCAIXA,
                    :DATACAIXA,
                    :ECHAVEPLANOCONTAJUROS,
                    :VCHAVECENTROCTO,
                    :CHAVECONTA,
                    CAST(SUBSTRING('PAGTO '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)),
                    :VDOC||'/'||:PARCELA,
                    :VCOMPETENCIA,
                    :NLATUAL,
                    :LANCBANCARIO,
                    :CHAVEMOVFINANCEIRA,
                    :CHAVEUSUARIO,
                    :VCHAVECLIFOR,
                    :CHAVEOPERACOESTITULOS,
                    :ECHAVEPLANOCONTAMULTA,
                    :ECHAVEPLANOCONTADESCTO,
                    'P2',
                    :OBSDINHEIRO,
                    CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSPAGCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:VOBSPAGCOMP,'') <> '') AND (COALESCE(:OBSBAIXA,'') <> '')
                    THEN :VOBSPAGCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSPAGCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                    :CHAVECONTACAIXA,
                    :VFORMACONDPGTO,
                    :VCHAVECHEQUE);
            END
        END
        IF (:LANCBANCARIO = 'S') THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASLANCBCO(:ECHAVEEMPLANCBANCARIO,
                    :DATARECEBIMENTO,
                    :VCHAVEPLANOCTA,
                    :VCHAVECENTROCTO,
                    :CHAVECONTA,
                    CAST(SUBSTRING('PAGTO '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)),
                    :VCOMPETENCIA,
                    :VALOR,
                    :JUROS,
                    :VLRMULTA,
                    :VDESCONTOS,
                    :CHAVEUSUARIO,
                    :VCHAVECLIFOR,
                    :CHAVEOPERACOESTITULOS,
                    :NLATUAL,
                    :CHAVEMOVFINANCEIRA,
                    :ECHAVEPLANOCONTAJUROS,
                    :ECHAVEPLANOCONTAMULTA,
                    :ECHAVEPLANOCONTADESCTO,
                    :EPREDATADO,
                    :DATACAIXA,
                    :ECHAVECONTABANCARIA,
                    :ETIPOLANCBANCARIO,
                    :ENUMERODOC,
                    :EFAVORECIDO,
                    CAST (SUBSTRING (CASE WHEN (COALESCE(:VOBSPAGCOMP,'') = '') AND (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:VOBSPAGCOMP,'') <> '') AND (COALESCE(:OBSBAIXA,'') <> '')
                    THEN :VOBSPAGCOMP || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) WHEN (COALESCE(:OBSBAIXA,'') = '') THEN (:VOBSPAGCOMP) END FROM 1 FOR 5000) AS VARCHAR(5000)),
                    :EBOMPARA,
                    :CHEQUE);
        END
    END
    IF (:TIPO = 'PP') THEN BEGIN
        SELECT NL, COALESCE(CHAVEPLANOCTO,1), COALESCE(CHAVECENTROCTO,1),
        DESCRICAO, DOCUMENTO, COMPETENCIA, STATUS, COALESCE(PARCELA, '1'),
        CHAVECLIFOR, CHAVEOPERACOESTITULOS, TIPO
        FROM PAGAR
        WHERE (CHAVE=:CHAVECONTA)
        INTO :NLATUAL, :VCHAVEPLANOCTA, :VCHAVECENTROCTO,
        :DESCRICAO, :VDOC, :VCOMPETENCIA, :STATUS, :PARCELA,
        :VCHAVECLIFOR, :CHAVEOPERACOESTITULOS, :VFORMACONDPGTO;
        UPDATE MOVFINANCEIRAS SET
        NL=:NLATUAL,
        GERADONOCAIXA=1
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA='P2');
        SELECT FIRST(1) OBSDINHEIRO, COALESCE(VALOR,0), COALESCE(JUROS,0), COALESCE(VLRMULTA,0), COALESCE(DESCONTOS,0),
        COALESCE(CHAVECHEQUE,0)
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA = 'P2')
        ORDER BY CHAVE DESC
        INTO :OBSDINHEIRO, :VALOR, :JUROS, :VLRMULTA, :VDESCONTOS,
        :VCHAVECHEQUE;
        IF (:GERACAIXA = 'S') THEN BEGIN
            IF ((:FORMAPAGTO NOT IN (3,4)) OR ((:FORMAPAGTO=3) AND (:GERARCAIXALANCBANCARIO='S'))) THEN BEGIN
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR, NL,
                    LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, COALESCE(P.CHAVEPLANOCTO,2),
                    COALESCE(P.CHAVECENTROCTO,2), :CHAVECONTA, SUBSTRING('PAGTO '||P.DESCRICAO FROM 1 FOR 100),
                    P.DOCUMENTO||'/'||:PARCELA, :VCOMPETENCIA, COALESCE(M.VALOR,0) - COALESCE(M.JUROS,0) - COALESCE(M.VLRMULTA,0)  + COALESCE(M.DESCONTOS,0), :NLATUAL,
                    :LANCBANCARIO, :CHAVEMOVFINANCEIRA, CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) END,
                    :CHAVEUSUARIO, :CHAVEUSUARIO, P.CHAVECLIFOR,
                    P.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, P.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN PAGAR P ON (M.NL=P.NL) AND (M.CHAVECONTA=P.CHAVE) AND (P.ATIVO=1)
                WHERE (M.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA) AND (M.TIPOCONTA='P2');
        
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                    NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, :ECHAVEPLANOCONTAJUROS,
                    COALESCE(P.CHAVECENTROCTO,1), :CHAVECONTA, SUBSTRING('PAGTO '||P.DESCRICAO FROM 1 FOR 100),
                    P.DOCUMENTO||'/'||:PARCELA, COMPETENCIA, COALESCE(M.JUROS,0),
                    :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) END,
                    :CHAVEUSUARIO,  :CHAVEUSUARIO, P.CHAVECLIFOR,
                    P.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, P.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN PAGAR P ON (M.NL=P.NL) AND (M.CHAVECONTA=P.CHAVE)
                WHERE (M.ATIVO=1) AND (P.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA)
                AND (M.TIPOCONTA='P2') AND (M.JUROS > 0);
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                    NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, :ECHAVEPLANOCONTAMULTA,
                    COALESCE(P.CHAVECENTROCTO,1), :CHAVECONTA, SUBSTRING('PAGTO '||P.DESCRICAO FROM 1 FOR 100),
                    P.DOCUMENTO||'/'||:PARCELA, :VCOMPETENCIA, COALESCE(M.VLRMULTA,0),
                    :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) END,
                    :CHAVEUSUARIO,  :CHAVEUSUARIO, P.CHAVECLIFOR,
                    P.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, P.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN PAGAR P ON (M.NL=P.NL) AND (M.CHAVECONTA=P.CHAVE)
                WHERE (M.ATIVO=1) AND (P.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA)
                AND (M.TIPOCONTA='P2') AND (M.VLRMULTA > 0);
                INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                    CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                    NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                    CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                    CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE)
                SELECT :CHAVEEMPCAIXA, :DATACAIXA, :ECHAVEPLANOCONTADESCTO,
                    COALESCE(P.CHAVECENTROCTO,1), :CHAVECONTA, SUBSTRING('PAGTO '||P.DESCRICAO FROM 1 FOR 100),
                    P.DOCUMENTO||'/'||:PARCELA, :VCOMPETENCIA, COALESCE(M.DESCONTOS,0),
                    :NLATUAL, :LANCBANCARIO,:CHAVEMOVFINANCEIRA, CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST('PAGAMENTO '||:OBSBAIXA AS VARCHAR(5000)) END,
                    :CHAVEUSUARIO, :CHAVEUSUARIO, P.CHAVECLIFOR,
                    P.CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, P.TIPO, :VCHAVECHEQUE
                FROM MOVFINANCEIRAS M
                INNER JOIN PAGAR P ON (M.NL=P.NL) AND (M.CHAVECONTA=P.CHAVE)
                WHERE (M.ATIVO=1) AND (P.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA)
                AND (M.TIPOCONTA='P2') AND (M.DESCONTOS>0);
            END
        END
        IF (:LANCBANCARIO = 'S') THEN BEGIN
            EXECUTE PROCEDURE GERARMOVFINANCEIRASLANCBCO(:ECHAVEEMPLANCBANCARIO,
                    :DATARECEBIMENTO,
                    :VCHAVEPLANOCTA,
                    :VCHAVECENTROCTO,
                    :CHAVECONTA,
                    CAST(SUBSTRING('PAGTO '||:DESCRICAO FROM 1 FOR 100) AS VARCHAR(1000)),
                    :VCOMPETENCIA,
                    :VALOR,
                    :JUROS,
                    :VLRMULTA,
                    :VDESCONTOS,
                    :CHAVEUSUARIO,
                    :VCHAVECLIFOR,
                    :CHAVEOPERACOESTITULOS,
                    :NLATUAL,
                    :CHAVEMOVFINANCEIRA,
                    :ECHAVEPLANOCONTAJUROS,
                    :ECHAVEPLANOCONTAMULTA,
                    :ECHAVEPLANOCONTADESCTO,
                    :EPREDATADO,
                    :DATACAIXA,
                    :ECHAVECONTABANCARIA,
                    :ETIPOLANCBANCARIO,
                    :ENUMERODOC,
                    :EFAVORECIDO,
                    :OBSDINHEIRO,
                    :EBOMPARA,
                    :CHEQUE);
        END
    END
    IF ((:TIPO = 'CR') OR (:TIPO = 'CF') OR (:TIPO = 'FL')) THEN BEGIN
        SELECT NLORIGEMLANC, CHAVECLIFOR FROM CREDITO     
        WHERE CHAVE=:CHAVECONTA
        INTO :NLATUAL, :VCHAVECLIFOR;
        UPDATE MOVFINANCEIRAS SET
        NL= :NLATUAL,
        GERADONOCAIXA=1
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA=:TIPO);
        FOR SELECT CHAVECHEQUE, CHAVEFORMAPGTO, CHAVELANCBCO, VALOR
        FROM MOVFINANCEIRAS
        WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA = :TIPO)
        ORDER BY CHAVEFORMAPGTO
        INTO :CHEQUE, :VCHAVEFORMA, :VCHAVELANCBCO, :VALOR DO BEGIN
            IF (COALESCE(:CHEQUE, 0) > 0) THEN BEGIN
                UPDATE CHEQUES SET
                NLENTRADA = :NLATUAL,
                OBS = OBS || 'CHEQUE RECEBIDO ATRAVES DE CREDITO NRO '||:CHAVECONTA,
                UTILIZADO = CASE WHEN :VCHAVEFORMA=3 THEN 'S' ELSE 'N' END, 
                DATAUTILIZADO = CASE WHEN :VCHAVEFORMA=3 THEN :DATARECEBIMENTO ELSE DATAUTILIZADO END,
                NLSAIDA = CASE WHEN :VCHAVEFORMA=3 THEN :NLATUAL ELSE NLSAIDA END
                WHERE (CHAVE=:CHEQUE);
            END
            IF (:VCHAVEFORMA = 3) THEN BEGIN
                LANCBANCARIO= 'S';
                IF ((:GERACAIXA = 'S') AND (:GERARCAIXALANCBANCARIO = 'S')) THEN BEGIN
                    IF (:TIPO = 'CR') THEN
                        VCHAVEPLANOCTA = :CHAVEPCTRANSFCAIXABCO;
                    ELSE
                        VCHAVEPLANOCTA = :CHAVEPCTRANSFBCOCAIXA;
                    EXECUTE PROCEDURE GERARMOVFINANCEIRASBANCO(:VCHAVEPLANOCTA,
                        :CHAVECONTA,
                        :DATACAIXA,
                        :CHAVEEMPCAIXA,
                        :NLATUAL,
                        :CHAVEMOVFINANCEIRA,
                        CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST(:OBSBAIXA AS VARCHAR(1000)) END,
                        :CHAVEUSUARIO,
                        :CHAVECONTACAIXA,
                        :VCHAVELANCBCO,
                        0);
                END
                UPDATE LANCBCO SET
                NL=:NLATUAL
                WHERE (CHAVE=:VCHAVELANCBCO);
            END
        END
        IF (:GERACAIXA = 'S') THEN BEGIN
            SELECT FIRST(1) CHAVECONTA, OBSDINHEIRO, COALESCE(VALOR,0), COALESCE(JUROS,0), COALESCE(DESCONTOS,0),
            COALESCE(VLRMULTA,0)
            FROM MOVFINANCEIRAS
            WHERE (ATIVO=1) AND (CHAVECONTA=:CHAVECONTA) AND (TIPOCONTA = :TIPO)
            ORDER BY CHAVE DESC
            INTO :CHAVECONTA, :OBSDINHEIRO, :VALOR, :JUROS, :VDESCONTOS,
            :VLRMULTA;
            EXECUTE PROCEDURE GERARMOVFINANCEIRASCAIXA(:VCHAVEFORMA,
                :GERARCAIXALANCBANCARIO,
                :CHAVEEMPCAIXA,
                :DATACAIXA,
                :ECHAVEPLANOCONTA,
                :ECHAVECENTROCUSTO,
                :CHAVECONTA,
                CAST(SUBSTRING(:OBSDINHEIRO FROM 1 FOR 100)AS VARCHAR(1000)),
                :CHAVECONTA,
                LPAD(SUBSTRING(:DATACAIXA FROM 6 FOR 2), 2, '0')||'/'||SUBSTRING(:DATACAIXA FROM 1 FOR 4),
                :VALOR,
                :JUROS,
                :VLRMULTA,
                :VDESCONTOS,
                :CHAVEUSUARIO,
                :VCHAVECLIFOR,
                :CHAVEOPERACOESTITULOS,
                CASE WHEN (COALESCE(:OBSBAIXA,'') <> '') THEN CAST(:OBSBAIXA AS VARCHAR(5000)) END,
                :NLATUAL,
                :LANCBANCARIO,
                :CHAVEMOVFINANCEIRA,
                :ECHAVEPLANOCONTAJUROS,
                :ECHAVEPLANOCONTAMULTA,
                :ECHAVEPLANOCONTADESCTO,
                :CHAVECONTACAIXA,
                0,
                0);
        END
    END
    /*
         CHAMADAS
           FRMMOVFINANCEIRAS - GERA OS MOVIMENTOS FINANCEIROS DE CADA CONTA
    */
END^


ALTER PROCEDURE GERAPEDSAIDACOMDESCDACOTCOND (
    CHAVEPEDIDO INTEGER,
    CHAVETABDESC INTEGER,
    EMPRESALOG INTEGER,
    CHAVEEMPPRODUTO INTEGER)
AS
declare variable CHAVEPRODUTO integer;
declare variable REGIMETRIB smallint;
declare variable CODTABPISCOFINS varchar(10);
declare variable SOMARVLRCOFINS numeric(18,6);
declare variable SOMARVLRCOFINSSERV numeric(18,6);
declare variable SOMARVLRPISSERV numeric(18,6);
declare variable SOMARBCPISCOFINSSERV numeric(18,6);
declare variable SOMARBCPISCOFINS numeric(18,6);
declare variable VLRCOFINS numeric(18,6);
declare variable SOMARVLRPIS numeric(18,6);
declare variable BASEPISCOFINS numeric(18,6);
declare variable VLRPIS numeric(18,6);
declare variable VLRCOFINSTRIB numeric(18,6);
declare variable VLRPISTRIB numeric(18,6);
declare variable TOTALSERVICOS numeric(18,6);
declare variable ALIQCOFINS numeric(18,6);
declare variable ALIQPIS numeric(18,6);
declare variable CSTPIS varchar(10);
declare variable SOMARBCIPI numeric(18,6);
declare variable PERCREDST numeric(18,6);
declare variable CHAVEITEM integer;
declare variable CHAVETABELADESCONTO integer;
declare variable PERC01 numeric(18,6);
declare variable CASADECIMALVLRUNIT integer;
declare variable PERC02 numeric(18,6);
declare variable PERC03 numeric(18,6);
declare variable PERC04 numeric(18,6);
declare variable CST varchar(5);
declare variable ICMSITEM numeric(7,2);
declare variable ICMSTRIB numeric(7,2);
declare variable SOMABASEICMS numeric(18,6);
declare variable SOMAVLRICMS numeric(18,6);
declare variable VLRICMSITEM numeric(18,6);
declare variable VLRTOTALITEM numeric(18,6);
declare variable BASEICMSITEM numeric(18,6);
declare variable PERCRED numeric(15,6);
declare variable TOTALPRODUTOS numeric(18,6);
declare variable PRECOVENDAORIGINAL numeric(18,6);
declare variable QTDE numeric(18,6);
declare variable BASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable BASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable UFEMP char(2);
declare variable UFCLI char(2);
declare variable IPI numeric(7,2);
declare variable REDUCAOMVA numeric(7,2);
declare variable MVA numeric(7,2);
declare variable VLRIPITRIB numeric(18,6);
declare variable CONVUNMEDIDA numeric(18,6);
declare variable SOMAIPI numeric(18,6);
declare variable VLRIPI numeric(18,6);
declare variable ITENSTOTAL numeric(18,6);
declare variable VLRRATEIO numeric(18,6);
declare variable PORC numeric(18,6);
declare variable VLRRATEIOITEM numeric(18,6);
declare variable BASECALCIPI numeric(18,6);
declare variable TOTALPRODUTO numeric(18,6);
declare variable VLRPAUTA numeric(18,6);
declare variable CHAVEUNIDADE integer;
BEGIN
    TOTALPRODUTOS=0; TOTALSERVICOS=0;
    SELECT VALOR
    FROM CONFIGCAMPOS
    WHERE CHAVEEMPRESA = :EMPRESALOG AND INDICE = 288
    INTO :CASADECIMALVLRUNIT;
    -- Zera as variaveis de soma
    BASECALCIPI = 0;
    VLRIPI = 0;
    SOMAIPI = 0;
    SOMARBCIPI=0;
    SOMABASEICMS = 0;
    SOMAVLRICMS  = 0;
    SOMABASEICMSSUBSTTRIBRETIDO = 0;
    SOMAVLRICMSSUBSTTRIBRETIDO  = 0;
    SOMABASEICMSSUBSTTRIBDESTAC = 0;
    SOMAVLRICMSSUBSTTRIBDESTAC  = 0;

    SELECT CID.UF, E.REGIMETRIBUT  FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE E.CHAVE= :CHAVEEMPPRODUTO
    INTO :UFEMP, :REGIMETRIB;
    
    SELECT CID.UF, C.REDUCAOMVA, PS.TOTALPRODUTO,
    COALESCE(FRETE,0)+COALESCE(DESPACESSORIA,0)+COALESCE(VLRSEGURO,0)
    FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN PEDIDOSAIDA PS ON C.CHAVE=PS.CHAVECLIFOR
    WHERE PS.CHAVE=:CHAVEPEDIDO
    INTO :UFCLI, :REDUCAOMVA, :TOTALPRODUTO, :VLRRATEIO;

    UPDATE PEDIDOSAIDA SET
        BASECALCULOICMS = 0,
        VLRICMS  = 0,
        BASECALCICMSSUBST = 0,
        VLRICMSSUBST      = 0,
        BASECALCICMSSUBSTDESTAC = 0,
        VLRICMSSUBSTDESTAC      = 0,
        BCIPI = 0,
        TOTALIPI = 0,
        TOTALPRODUTO = 0,
        TOTALSERVICO = 0,
        TOTALPEDIDO  = 0
    WHERE CHAVE=:CHAVEPEDIDO;

    FOR SELECT IPS.CHAVE, IPS.CHAVEPRODUTO, IPS.CST,
    T.ALIQUOTADE, T.PERCRED, IPS.VLRUNITCOMDESC,
    IPS.QTDE, IPS.ICMS, IPS.IPI, P.MVA, IPS.VLRIPI,
    COALESCE(IPS.VLRIPITRIB,0), COALESCE(UN.CONVUNMEDIDA,0),
    IPS.VLRTOTAL, T.PERCREDST,
    IPS.CSTPIS, TC.CODIGO, COALESCE(UN.CONVUNMEDIDA,0),
    IPS.VLRPAUTA,  IPS.CHAVEUNIDADE
    FROM ITENSPEDSAIDA IPS
    INNER JOIN TRIBUTACAO T ON IPS.CHAVETRIBUTACAO=T.CHAVE
    INNER JOIN PRODUTO P ON IPS.CHAVEPRODUTO=P.CHAVE
    LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = IPS.CHAVETABPISCOFINS
    INNER JOIN UNIDADE UN ON UN.CHAVE = IPS.CHAVEUNIDADE
    WHERE IPS.ATIVO=1 AND IPS.CHAVEPEDIDO=:CHAVEPEDIDO
    INTO :CHAVEITEM, :CHAVEPRODUTO, :CST,
    :ICMSTRIB, :PERCRED, :PRECOVENDAORIGINAL,
    :QTDE, :ICMSITEM, :IPI, :MVA, :VLRIPI,
    :VLRIPITRIB, :CONVUNMEDIDA,
    :ITENSTOTAL, :PERCREDST, :CSTPIS, :CODTABPISCOFINS, :CONVUNMEDIDA,
    :VLRPAUTA, :CHAVEUNIDADE
    DO BEGIN
        -- Se tem desconto por grupo/subgrupo
        CHAVETABELADESCONTO = 0;
        SELECT COUNT(CHAVETABELADESCONTOS) FROM TABELADESCGRUPOPROD
        WHERE ATIVO=1 AND CHAVETABELADESC=:CHAVETABDESC
        INTO :CHAVETABELADESCONTO;
        IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
            -- Grupo
            CHAVETABELADESCONTO = 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                PERC01=0;
                PERC02=0;
                PERC03=0;
                PERC04=0;
                SELECT COALESCE(PERC01,0), COALESCE(PERC02,0), COALESCE(PERC03,0),
                COALESCE(PERC04,0) FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABELADESCONTO)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
              --  VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            END ELSE BEGIN
                -- Senao pega os descontos da tabela principal
                SELECT PERC01, PERC02, PERC03, PERC04 FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABDESC)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
              --  VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            END
            -- Subgrupo
            CHAVETABELADESCONTO = 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                PERC01=0;
                PERC02=0;
                PERC03=0;
                PERC04=0;
                SELECT COALESCE(PERC01,0), COALESCE(PERC02,0), COALESCE(PERC03,0),
                COALESCE(PERC04,0) FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABELADESCONTO)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
              --  VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            END ELSE BEGIN
                -- Senao pega os descontos da tabela principal
                SELECT PERC01, PERC02, PERC03, PERC04 FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABDESC)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
            END
        END ELSE BEGIN
            -- Senao pega os descontos da tabela principal
            SELECT PERC01, PERC02, PERC03, PERC04 FROM TABELADESCONTOS
            WHERE (ATIVO=1) AND (CHAVE=:CHAVETABDESC)
            INTO :PERC01, :PERC02, :PERC03, :PERC04;
            -- Aplica os percentuais de descontos
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
        --    VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
        END

        PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT
        WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,2))
        WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,3))
        WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,4))
        WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,5))
        WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,6))
        ELSE CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,4)) END;

        VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;

        -- Calculos de ICMS
        SELECT BASEICMSITEM, CAST(VLRICMSITEM AS NUMERIC(18,2)) AS VLRICMSITEM,
        BASEICMSSUBSTTRIBRETIDO, CAST(VLRICMSSUBSTTRIBRETIDO AS NUMERIC(18,2)) AS VLRICMSSUBSTTRIBRETIDO,
        BASEICMSSUBSTTRIBDESTAC, CAST(VLRICMSSUBSTTRIBDESTAC AS NUMERIC(18,2)) AS VLRICMSSUBSTTRIBDESTAC
        FROM CALCULARICMS(:CST, :VLRTOTALITEM, :ICMSTRIB, :PERCRED, :PRECOVENDAORIGINAL,
        :QTDE, :ICMSITEM, :UFCLI, :UFEMP, :IPI, :REDUCAOMVA, :REGIMETRIB, :MVA, :PERCREDST,
        :VLRIPITRIB, :VLRPAUTA, :CHAVEUNIDADE)
        INTO :BASEICMSITEM, :VLRICMSITEM,
        :BASEICMSSUBSTTRIBRETIDO, :VLRICMSSUBSTTRIBRETIDO,
        :BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC;

        -- Calculos de IPI
        IF ((:IPI+:VLRIPITRIB) > 0)  THEN BEGIN
            PORC = ((:ITENSTOTAL)*100)/:TOTALPRODUTO;
            PORC = CAST(:PORC AS NUMERIC(7,2));
            VLRRATEIOITEM = CAST(:VLRRATEIO / 100 * :PORC AS NUMERIC(18,6));
            IF (:IPI > 0) THEN BEGIN
                BASECALCIPI = :ITENSTOTAL + :VLRRATEIOITEM;
                VLRIPI = CAST(:BASECALCIPI * :IPI / 100 AS NUMERIC(18,2));
            END ELSE BEGIN
                BASECALCIPI = 0;
                VLRIPI = ((:CONVUNMEDIDA  * :QTDE) * :VLRIPITRIB) + CAST(((:VLRRATEIOITEM*VLRIPI)/:ITENSTOTAL) AS NUMERIC(18,2));
            END
            SOMAIPI = :SOMAIPI + :VLRIPI;
            SOMARBCIPI = SOMARBCIPI + BASECALCIPI;
        END
        -- Acumula totais
        SOMABASEICMS = :SOMABASEICMS + :BASEICMSITEM;
        SOMAVLRICMS  = :SOMAVLRICMS + :VLRICMSITEM;
        SOMABASEICMSSUBSTTRIBRETIDO = :SOMABASEICMSSUBSTTRIBRETIDO + :BASEICMSSUBSTTRIBRETIDO;
        SOMAVLRICMSSUBSTTRIBRETIDO  = :SOMAVLRICMSSUBSTTRIBRETIDO + :VLRICMSSUBSTTRIBRETIDO;
        SOMABASEICMSSUBSTTRIBDESTAC = :SOMABASEICMSSUBSTTRIBDESTAC + :BASEICMSSUBSTTRIBDESTAC;
        SOMAVLRICMSSUBSTTRIBDESTAC  = :SOMAVLRICMSSUBSTTRIBDESTAC + :VLRICMSSUBSTTRIBDESTAC;

        SELECT ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB, BASE, VALORPIS, VALORCOFINS FROM CALCULARPISCOFINS(:CSTPIS, :VLRTOTALITEM, :CODTABPISCOFINS, :QTDE, :CONVUNMEDIDA)
        INTO :ALIQPIS, :ALIQCOFINS, :VLRPISTRIB, :VLRCOFINSTRIB, :BASEPISCOFINS, :VLRPIS, :VLRCOFINS;
        SOMARVLRPIS = :SOMARVLRPIS + :VLRPIS;
        SOMARVLRCOFINS= :SOMARVLRCOFINS + :VLRCOFINS;
        SOMARBCPISCOFINS = :SOMARBCPISCOFINS + :BASEPISCOFINS;

        -- Atualiza os valores de ICMS
        UPDATE ITENSPEDSAIDA SET
            VLRUNIT  = :PRECOVENDAORIGINAL,
            VLRUNITCOMDESC = :PRECOVENDAORIGINAL,
            DESCVLR  = 0,
            DESCPORC = 0,
            BASECALCIPI = :BASECALCIPI,
            VLRIPI =  :VLRIPI,
            BASEICMS = :BASEICMSITEM,
            VLRICMS  = :VLRICMSITEM,
            BASEICMSSUBSTTRIB = :BASEICMSSUBSTTRIBRETIDO,
            VLRICMSSUBSTTRIB  = :VLRICMSSUBSTTRIBRETIDO,
            BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC,
            VLRICMSSUBSTTRIBDESTAC  = :VLRICMSSUBSTTRIBDESTAC,
            VLRSUBTOTAL = :VLRTOTALITEM,
            VLRTOTAL    = :VLRTOTALITEM,
            ALIQPIS=:ALIQPIS,
            ALIQCOFINS=:ALIQCOFINS,
            VLRPISTRIB=:VLRPISTRIB,
            VLRCOFINSTRIB=:VLRCOFINSTRIB,
            BCPIS=:BASEPISCOFINS,
            BCCOFINS=:BASEPISCOFINS,
            VLRPIS=:VLRPIS,
            VLRCOFINS=:VLRCOFINS
        WHERE CHAVE=:CHAVEITEM;
    END
    FOR SELECT ITS.CHAVE, ITS.CHAVEPRODUTO, ITS.CSTPISCOFINS,
    ITS.VLRUNITCOMDESCSERVICO, ITS.QTDE, COALESCE(UN.CONVUNMEDIDA,0), ITS.VLRTOTAL
    FROM ITENSPEDSAIDASERV ITS
    INNER JOIN PRODUTO P ON ITS.CHAVEPRODUTO=P.CHAVE
    INNER JOIN UNIDADE UN ON UN.CHAVE = ITS.CHAVEUNIDADE
    LEFT JOIN TABELAPISCOFINS TP ON TP.CHAVE = ITS.CHAVETABPISCOFINS
    WHERE ITS.ATIVO=1 AND ITS.CHAVEPEDIDO=:CHAVEPEDIDO
    INTO :CHAVEITEM, :CHAVEPRODUTO, :CSTPIS,
    :PRECOVENDAORIGINAL, :QTDE, :CONVUNMEDIDA, :ITENSTOTAL
    DO BEGIN
        -- Se tem desconto por grupo/subgrupo
        CHAVETABELADESCONTO = 0;
        SELECT COUNT(CHAVETABELADESCONTOS) FROM TABELADESCGRUPOPROD
        WHERE ATIVO=1 AND CHAVETABELADESC=:CHAVETABDESC
        INTO :CHAVETABELADESCONTO;
        IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
            -- Grupo
            CHAVETABELADESCONTO = 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                PERC01=0;
                PERC02=0;
                PERC03=0;
                PERC04=0;
                SELECT COALESCE(PERC01,0), COALESCE(PERC02,0), COALESCE(PERC03,0),
                COALESCE(PERC04,0) FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABELADESCONTO)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
              --  VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            END ELSE BEGIN
                -- Senao pega os descontos da tabela principal
                SELECT PERC01, PERC02, PERC03, PERC04 FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABDESC)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
              --  VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            END
            -- Subgrupo
            CHAVETABELADESCONTO = 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                PERC01=0;
                PERC02=0;
                PERC03=0;
                PERC04=0;
                SELECT COALESCE(PERC01,0), COALESCE(PERC02,0), COALESCE(PERC03,0),
                COALESCE(PERC04,0) FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABELADESCONTO)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
              --  VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            END ELSE BEGIN
                -- Senao pega os descontos da tabela principal
                SELECT PERC01, PERC02, PERC03, PERC04 FROM TABELADESCONTOS
                WHERE (ATIVO=1) AND (CHAVE=:CHAVETABDESC)
                INTO :PERC01, :PERC02, :PERC03, :PERC04;
                -- Aplica os percentuais de descontos
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
                PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
            END
        END ELSE BEGIN
            -- Senao pega os descontos da tabela principal
            SELECT PERC01, PERC02, PERC03, PERC04 FROM TABELADESCONTOS
            WHERE (ATIVO=1) AND (CHAVE=:CHAVETABDESC)
            INTO :PERC01, :PERC02, :PERC03, :PERC04;
            -- Aplica os percentuais de descontos
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC01;
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC02;
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC03;
            PRECOVENDAORIGINAL = :PRECOVENDAORIGINAL - (:PRECOVENDAORIGINAL/100)*:PERC04;
        --    VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
        END

        PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT
        WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,2))
        WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,3))
        WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,4))
        WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,5))
        WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,6))
        ELSE CAST(:PRECOVENDAORIGINAL AS NUMERIC (18,4)) END;

        VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;

        SELECT ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB, BASE, VALORPIS, VALORCOFINS FROM CALCULARPISCOFINS(:CSTPIS, :VLRTOTALITEM, :CODTABPISCOFINS, :QTDE, :convunmedida)
        INTO :ALIQPIS, :ALIQCOFINS, :VLRPISTRIB, :VLRCOFINSTRIB, :BASEPISCOFINS, :VLRPIS, :VLRCOFINS;
        SOMARVLRPISSERV = :SOMARVLRPISSERV + :VLRPIS;
        SOMARVLRCOFINSSERV= :SOMARVLRCOFINSSERV + :VLRCOFINS;
        SOMARBCPISCOFINSSERV = :SOMARBCPISCOFINSSERV + :BASEPISCOFINS;

        UPDATE ITENSPEDSAIDASERV I SET
            VLRUNIT  = :PRECOVENDAORIGINAL,
            VLRUNITCOMDESCSERVICO = :PRECOVENDAORIGINAL,
            DESCVLR  = 0,
            DESCPORC = 0,
            VLRSUBTOTAL = :VLRTOTALITEM,
            VLRTOTAL    = :VLRTOTALITEM,
            ALIQPIS=:ALIQPIS, ALIQCOFINS=:ALIQCOFINS,
            VLRPISTRIB=:VLRPISTRIB, VLRCOFINSTRIB=:VLRCOFINSTRIB,
            BASEPISCOFINS=:BASEPISCOFINS, BASEISS=:VLRTOTALITEM,
            VLRISS=((:VLRTOTALITEM * COALESCE(ISS,0)) / 100)
        WHERE CHAVE=:CHAVEITEM;
    END

    SELECT COALESCE(SUM(CAST(VLRTOTAL AS NUMERIC(18,2))),0) FROM ITENSPEDSAIDA I
    INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS AND CF.COMPORTOTALNF = 0
    WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDIDO
    INTO :TOTALPRODUTOS;

    SELECT COALESCE(SUM(CAST(VLRTOTAL AS NUMERIC(18,2))),0) FROM ITENSPEDSAIDASERV I
    WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDIDO
    INTO :TOTALSERVICOS;

    UPDATE PEDIDOSAIDA SET
        TOTALIPI        = :SOMAIPI,
        BCIPI           = :SOMARBCIPI,
        BASECALCULOICMS = :SOMABASEICMS,
        VLRICMS         = :SOMAVLRICMS,
        BASECALCICMSSUBST = :SOMABASEICMSSUBSTTRIBRETIDO,
        VLRICMSSUBST      = :SOMAVLRICMSSUBSTTRIBRETIDO,
        BASECALCICMSSUBSTDESTAC = :SOMABASEICMSSUBSTTRIBDESTAC,
        VLRICMSSUBSTDESTAC      = :SOMAVLRICMSSUBSTTRIBDESTAC,
        TOTALPRODUTO    = :TOTALPRODUTOS,
        TOTALSERVICO    = :TOTALSERVICOS,
        TOTALPEDIDO     = :TOTALPRODUTOS + :TOTALSERVICOS,
        TOTALISS=((:TOTALSERVICOS*COALESCE(ALIQUOTAISS,0))/100), BASEISS=:TOTALSERVICOS,
        BCPISCOFINS=:SOMARBCPISCOFINS, VLRPIS=:SOMARVLRPIS, VLRCOFINS=:SOMARVLRCOFINS,
        BCPISCOFINSSERV=:SOMARBCPISCOFINSSERV, VLRPISSERV=:SOMARVLRPISSERV, VLRCOFINSSERV=:SOMARVLRCOFINSSERV
    WHERE CHAVE=:CHAVEPEDIDO;


    /*
        CHAMADAS:
            - frmPedidoSaida: Usada para aplicar a tabela de desconto que vem do orcamento/condicional
    */
END^


ALTER PROCEDURE GERAR_FINANCEIROCTEOS (
    CHAVECTEOS INTEGER,
    NUMCTEOS VARCHAR(20),
    CHAVECLIFOR INTEGER,
    TIPO VARCHAR(10),
    CHAVEEMPRESA INTEGER,
    CHAVEUSUARIO INTEGER)
AS
BEGIN
    --ENTRADA
    IF (TIPO = 'P') THEN BEGIN
        INSERT INTO PAGAR(CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
        DATACONTA, DATAENTRADA, DESCRICAO, DOCUMENTO,
        PARCELA, TIPO, TOTPARC, VALOR, VENCIMENTO, COMPETENCIA, STATUS, NL, ORIGEM, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
        SELECT :CHAVEEMPRESA, 2, :CHAVECLIFOR, (SELECT COALESCE(CHAVEPLANOCONTA,1) FROM CONFIGCAIXA WHERE (CHAVE=3)),
        CT.EMISSAO, CT.ENTRADA, substring('REF CTEOS NRO '||:NUMCTEOS||' - EMITENTE. '||C.RAZAOSOCIAL from 1 for 100), :NUMCTEOS,
        1, 1, 1, CT.TOTALSERVICO, CT.VENCIMENTO,
        substring(CAST(CT.VENCIMENTO AS VARCHAR(10))from 6 FOR 2)||'/'||substring(CAST(CT.VENCIMENTO AS VARCHAR(10)) FROM 1 FOR 4),
        1, CT.NL, 7, :CHAVEUSUARIO, :CHAVEUSUARIO
        FROM CTEOS CT                 
        INNER JOIN CLIFOR C ON C.CHAVE=CT.CHAVEEMITENTE
        WHERE CT.CHAVE = :CHAVECTEOS;
    END ELSE BEGIN
        INSERT INTO receber(CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
        DATACONTA, DESCRICAO, DOCUMENTO,
        PARCELA, TIPO, TOTPARC, VALOR, VENCIMENTO, STATUS, NL, ORIGEM, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
        SELECT :CHAVEEMPRESA, 1, :CHAVECLIFOR, (SELECT COALESCE(CHAVEPLANOCONTA,1) FROM CONFIGCAIXA WHERE (CHAVE=24)),
        CT.EMISSAO, substring('REF CTEOS NRO '||:NUMCTEOS||' - TOMADOR. '||C.RAZAOSOCIAL from 1 for 100), :NUMCTEOS,
        1, 1, 1, (CT.TOTALSERVICO - CT.VLRINSS) as TOTSERVICOABATINSS, CT.VENCIMENTO, 1, CT.NL, 13, :CHAVEUSUARIO, :CHAVEUSUARIO
        FROM CTEOS CT                 
        INNER JOIN CLIFOR C ON C.CHAVE=CT.chavetomador
        WHERE CT.CHAVE = :CHAVECTEOS;

    END
END^


ALTER PROCEDURE GERAR_FINANCEIROCTRC (
    CHAVECTRC INTEGER,
    NUMCTRC VARCHAR(20),
    TIPO VARCHAR(10),
    CHAVEEMPRESA INTEGER,
    CHAVEUSUARIO INTEGER)
AS
declare variable CHAVECLIFOR integer;
BEGIN
    IF (TIPO = 'R') THEN BEGIN
        INSERT INTO RECEBER(CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
        DATACONTA, DESCRICAO, DOCUMENTO, PARCELA, TIPO, TOTPARC, VALOR,
        VENCIMENTO, STATUS, NL, ORIGEM, CHAVEDOC, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
        SELECT :CHAVEEMPRESA, 1, CASE CT.TOMADORSERVICO WHEN 0 THEN CT.CHAVEREMETENTE WHEN 1 THEN CT.CHAVECLIFORREDESP WHEN 2 THEN CT.CHAVECLIFORCONSIG
        WHEN 3 THEN CT.CHAVEDESTINATARIO WHEN 4 THEN CT.CHAVECLIFOROUTROS END AS CHAVECLIFOR, (SELECT COALESCE(CHAVEPLANOCONTA,1) FROM CONFIGCAIXA WHERE (CHAVE=24)),
        CT.EMISSAO, SUBSTRING('REF CTE NRO '||:NUMCTRC||' - TRANSP. '||C.RAZAOSOCIAL FROM 1 FOR 100), :NUMCTRC, 1, CT.TIPOPGTO, 1, CT.TOTALRECEBER,
        CT.VENCIMENTOCTRC, 1, CT.NL, 11, :CHAVECTRC, :CHAVEUSUARIO, :CHAVEUSUARIO
        FROM CTRC CT
        INNER JOIN CLIFOR C ON C.CHAVE=CT.CHAVETRANSPORTADOR
        WHERE CT.CHAVE = :CHAVECTRC;
    END ELSE BEGIN
        IF (TIPO='RF') THEN BEGIN
            /* PARA ANEXAR O MOTORISTA NO CONTAS A PAGAR O MESMO DEVERA TER UM NOVO CADASTRO NO CHERP, CASO CONTRARIO IRA GRAVAR O PROPRIO TRANSPORTADOR */
            SELECT FIRST 1 COALESCE(CL.CHAVE,0)  FROM CTRC C
            INNER JOIN TMSMOTORISTA M ON M.CHAVE=C.CHAVEMOTORISTA
            INNER JOIN CLIFOR CL ON CL.CNPJCPF=M.CPF
            WHERE C.CHAVE =:CHAVECTRC
            INTO :CHAVECLIFOR;
            INSERT INTO PAGAR(CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
            DATACONTA, DATAENTRADA, DESCRICAO, DOCUMENTO,
            PARCELA, TIPO, TOTPARC, VALOR, VENCIMENTO, COMPETENCIA, STATUS, NL, ORIGEM, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
            SELECT :CHAVEEMPRESA, 2, CASE WHEN :CHAVECLIFOR> 0 THEN :CHAVECLIFOR ELSE CT.CHAVETRANSPORTADOR END , (SELECT COALESCE(CHAVEPLANOCONTA,1) FROM CONFIGCAIXA WHERE (CHAVE=3)),
            CT.EMISSAO, CT.ENTRADA, SUBSTRING('REF. AO PAGAMENTO DE FRETE AO MOTORISTA '||M.MOTORISTA||', CTRC NRO '||:NUMCTRC FROM 1 FOR 100), :NUMCTRC,
            1, CT.TIPOPGTO, 1, CT.VLRLIQRECFRETE, CT.VENCIMENTOCTRC,
            SUBSTRING(CAST(CT.VENCIMENTOCTRC AS VARCHAR(10)) FROM 6 FOR 2)||'/'|| SUBSTRING(CAST(CT.VENCIMENTOCTRC AS VARCHAR(10)) FROM 1 FOR 4),
            1, CT.NL, 1, :CHAVEUSUARIO, :CHAVEUSUARIO
            FROM CTRC CT
            INNER JOIN CLIFOR C ON C.CHAVE=CT.CHAVETRANSPORTADOR
            LEFT JOIN TMSMOTORISTA M ON M.CHAVE=CT.CHAVEMOTORISTA
            WHERE CT.CHAVE = :CHAVECTRC;
        END ELSE BEGIN
            INSERT INTO PAGAR(CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
            DATACONTA, DATAENTRADA, DESCRICAO, DOCUMENTO,
            PARCELA, TIPO, TOTPARC, VALOR, VENCIMENTO, COMPETENCIA, STATUS, NL, ORIGEM, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
            SELECT :CHAVEEMPRESA, 2, CT.CHAVETRANSPORTADOR, (SELECT COALESCE(CHAVEPLANOCONTA,1) FROM CONFIGCAIXA WHERE (CHAVE=3)),
            CT.EMISSAO, CT.ENTRADA, SUBSTRING('REF CTE NRO '||:NUMCTRC||' - TRANSP. '||C.RAZAOSOCIAL FROM 1 FOR 100), :NUMCTRC,
            1, CT.TIPOPGTO, 1, CT.TOTALRECEBER, CT.VENCIMENTOCTRC,
            SUBSTRING(CAST(CT.VENCIMENTOCTRC AS VARCHAR(10)) FROM 6 FOR 2)||'/'|| SUBSTRING(CAST(CT.VENCIMENTOCTRC AS VARCHAR(10)) FROM 1 FOR 4),
            1, CT.NL, 1, :CHAVEUSUARIO, :CHAVEUSUARIO
            FROM CTRC CT
            INNER JOIN CLIFOR C ON C.CHAVE=CT.CHAVETRANSPORTADOR
            WHERE CT.CHAVE = :CHAVECTRC;
        END
    END
    /*
    CHAMADAS:
    FRMNFe - Gerar financeiro de CTe
    FRMCTRC - Gerar financeiro de CTe no CHERP gerar pagar e no CHTMS gerar receber
    */
END^


ALTER PROCEDURE GERARCOMISSAOCONTASAGRUPADAS (
    BASEPROD NUMERIC(18,6),
    EMPCOMISSAO INTEGER,
    TOTALAGRUPADOSERV NUMERIC(18,6),
    TOTALAGRUPADOPROD NUMERIC(18,6),
    BASESERV NUMERIC(18,6),
    NLATUAL DOUBLE PRECISION)
AS
declare variable VLRSERV numeric(18,6);
declare variable VLRCOMISSERV numeric(18,6);
declare variable CHAVEVENDEDOR integer;
declare variable TIPOCOMISSAO integer;
declare variable ALIQSERVBAIXA numeric(7,2);
declare variable ALIQPRODBAIXA numeric(7,2);
declare variable VLRCOMISPROD numeric(18,6);
declare variable AUX04 numeric(7,2);
declare variable AUX03 numeric(7,2);
declare variable AUX02 numeric(7,2);
declare variable AUX01 numeric(7,2);
declare variable VLRPROD numeric(18,6);
declare variable CHAVECLIFOR integer;
declare variable DOCUMENTO varchar(20);
declare variable NLCOMIS double precision;
declare variable CHAVEREC integer;
declare variable VLRSERVFINAL numeric(18,6);
declare variable VLRPRODFINAL numeric(18,6);
declare variable DATA date;
declare variable CHAVERECEBER integer;
BEGIN
    VLRCOMISPROD = 0;
    VLRCOMISSERV = 0;
    VLRSERVFINAL = 0;
    VLRPRODFINAL = 0;
    FOR SELECT R.CHAVE, R.VALORPRODUTO, R.VALORSERVICO,
    R.CHAVECLIFOR, R.DOCUMENTO, R.DATACONTA
    FROM RECEBER R
    WHERE (ATIVO=1) AND (NL=:NLATUAL)
    INTO :CHAVERECEBER, :VLRPROD, :VLRSERV, :CHAVECLIFOR, :DOCUMENTO, :DATA
    DO BEGIN
        FOR SELECT COMISPRODBAIXA, COMISSERVBAIXA, CHAVEVENDEDOR, TIPOCOMISSAO FROM COMISSAO
        WHERE (ATIVO=1) AND (CHAVEDOC=:CHAVERECEBER) AND (ORIGEM=7) AND (NL=:NLATUAL)
        AND (COMISSAOGERADA>0) -- Somente comissao por baixa vai gerar no agrupamento
        INTO :ALIQPRODBAIXA, :ALIQSERVBAIXA, :CHAVEVENDEDOR, :TIPOCOMISSAO
        DO BEGIN
            IF ((VLRPROD > 0) AND (:ALIQPRODBAIXA>0)) THEN BEGIN
                AUX01 = BASEPROD*100/TOTALAGRUPADOPROD;
                AUX03 = (VLRPROD *AUX01)/100;
                VLRCOMISPROD = (AUX03*:ALIQPRODBAIXA)/100;
                VLRPRODFINAL = :AUX03;
            END
            IF ((VLRSERV > 0) AND (:ALIQSERVBAIXA>0)) THEN BEGIN
                AUX02 = BASESERV*100/TOTALAGRUPADOSERV;
                AUX04 = (VLRSERV *AUX02)/100;
                VLRCOMISSERV = (AUX04*:ALIQSERVBAIXA)/100;
                VLRSERVFINAL = :AUX04;
            END
            INSERT INTO COMISSAOFATURAMENTO
            (CHAVEEMPRESA, ORIGEM, CHAVEVENDEDOR, CHAVECLIFOR, DOCUMENTO,
            DATA, NL, VLRPRODUTO, VLRSERVICO, CHAVERECEBER, TIPOCOMISSAO, COMISSAOGERADA,
            SITCOMISEMISSAO, SITCOMISBAIXA, ALIQCOMISPRODEMISSAO, VLRCOMISPRODEMISSAO,
            ALIQCOMISPRODBAIXA, VLRCOMISPRODBAIXA, ALIQCOMISSERVEMISSAO,
            VLRCOMISSERVEMISSAO, ALIQCOMISSERVBAIXA, VLRCOMISSERVBAIXA, TIPOPAGAMENTO)
            VALUES
            (:EMPCOMISSAO, 7, :CHAVEVENDEDOR, :CHAVECLIFOR,
            :DOCUMENTO, :DATA, :NLATUAL, :VLRPRODFINAL, :VLRSERVFINAL,
            :CHAVERECEBER, :TIPOCOMISSAO, 1, 'A', 'A',
            0, 0, :ALIQPRODBAIXA, :VLRCOMISPROD,
            0, 0, :ALIQSERVBAIXA, :VLRCOMISSERV, 2);
        END
    END
    FOR SELECT CHAVE, NL FROM RECEBER
    WHERE NLAGRUPADO=:NLATUAL
    INTO :CHAVEREC, :NLCOMIS
    DO BEGIN
        UPDATE COMISSAOFATURAMENTO
        SET ATIVO = 8
        WHERE ATIVO=1 AND CHAVERECEBER=:CHAVEREC AND COMISSAOGERADA=1
        AND NL=:NLCOMIS;
    END
    /* CHAMADAS
       DlgAgrupaContasPagRec  - Usada para gerar comissoes quando as contas sao agrupadas
   */
END^


ALTER PROCEDURE GERARCOMISSAOFATEMISSAO (
    ECHAVEEMPCOMIS INTEGER,
    ECHAVECLIFOR INTEGER,
    EDATA DATE,
    ENL DOUBLE PRECISION,
    EORIGEM INTEGER)
AS
declare variable VCHAVEEMPRESA integer;
declare variable VORIGEM integer;
declare variable VCHAVEVENDEDOR integer;
declare variable VCHAVECLIFOR integer;
declare variable VCHAVEPEDIDO integer;
declare variable VDOCUMENTO varchar(9);
declare variable VDATA date;
declare variable VNL double precision;
declare variable VSITCOMISEMISSAO char(1);
declare variable VDATABAIXAEMISSAO date;
declare variable VTIPOCOMISSAO integer;
declare variable VALIQCOMISPRODEMISSAO numeric(7,2);
declare variable VALIQCOMISSERVEMISSAO numeric(7,2);
declare variable VVLRPRODUTO numeric(18,6);
declare variable VVLRSERVICO numeric(18,6);
declare variable VVLRCOMISPRODEMISSAO numeric(18,6);
declare variable VVLRCOMISSERVEMISSAO numeric(18,6);
begin
    -- Agrupar registros de comissao por emissao, que agora so tem 1 reg por documento
    FOR SELECT C.CHAVEEMPRESA, C.ORIGEM, C.CHAVEVENDEDOR, C.CHAVECLIFOR,
    C.CHAVEPEDIDO, C.DOCUMENTO, C.DATA, C.NL,
    C.SITCOMISEMISSAO, C.DATABAIXAEMISSAO, C.TIPOCOMISSAO,
    SUM(C.ALIQCOMISPRODEMISSAO)/COUNT(*) AS ALIQCOMISPRODEMISSAO, SUM(C.ALIQCOMISSERVEMISSAO)/COUNT(*) AS ALIQCOMISSERVEMISSAO,
    SUM(C.VLRPRODUTO), SUM(C.VLRSERVICO),
    SUM(C.VLRCOMISPRODEMISSAO), SUM(C.VLRCOMISSERVEMISSAO)
    FROM COMISSAOFATURAMENTO C
    WHERE (C.ATIVO=1) AND (C.COMISSAOGERADA=0) and (COALESCE(C.VLRPRODUTO,0)+COALESCE(C.VLRSERVICO,0)) > 0 AND
    CHAVEEMPRESA=:ECHAVEEMPCOMIS AND CHAVECLIFOR=:ECHAVECLIFOR AND
    DATA=:EDATA AND NL=:ENL AND ORIGEM=:EORIGEM
    GROUP BY CHAVEEMPRESA, ORIGEM, CHAVEVENDEDOR, CHAVECLIFOR,
    CHAVEPEDIDO, DOCUMENTO, DATA, NL,
    C.SITCOMISEMISSAO, C.DATABAIXAEMISSAO, C.TIPOCOMISSAO
    HAVING COUNT(*)>1
    INTO :VCHAVEEMPRESA, :VORIGEM, :VCHAVEVENDEDOR, :VCHAVECLIFOR,
    :VCHAVEPEDIDO, :VDOCUMENTO, :VDATA, :VNL,
    :VSITCOMISEMISSAO, :VDATABAIXAEMISSAO, :VTIPOCOMISSAO,
    :VALIQCOMISPRODEMISSAO, :VALIQCOMISSERVEMISSAO,
    :VVLRPRODUTO, :VVLRSERVICO,
    :VVLRCOMISPRODEMISSAO, :VVLRCOMISSERVEMISSAO
    DO BEGIN
    
        UPDATE COMISSAOFATURAMENTO SET
        ATIVO=4
        WHERE (ATIVO=1) AND (COMISSAOGERADA=0) and (ORIGEM=:VORIGEM)
        AND (CHAVECLIFOR=:VCHAVECLIFOR) AND (CHAVEVENDEDOR=:VCHAVEVENDEDOR)
        AND (NL=:VNL) AND (DATA=:VDATA) AND (DOCUMENTO=:VDOCUMENTO);

        -- Insert 1 reg de comissao por EMISSAO
        INSERT INTO COMISSAOFATURAMENTO(CHAVEEMPRESA, ORIGEM, CHAVEVENDEDOR, CHAVECLIFOR,
        CHAVEPEDIDO, DOCUMENTO, DATA, NL, VLRPRODUTO, VLRSERVICO, TIPOCOMISSAO, COMISSAOGERADA,
        ALIQCOMISPRODEMISSAO, VLRCOMISPRODEMISSAO,
        ALIQCOMISPRODBAIXA, VLRCOMISPRODBAIXA,
        ALIQCOMISSERVEMISSAO, VLRCOMISSERVEMISSAO,
        ALIQCOMISSERVBAIXA, VLRCOMISSERVBAIXA,
        SITCOMISEMISSAO, DATABAIXAEMISSAO, TIPOPAGAMENTO)
        VALUES (:VCHAVEEMPRESA, :VORIGEM, :VCHAVEVENDEDOR, :VCHAVECLIFOR,
        :VCHAVEPEDIDO, :VDOCUMENTO, :VDATA, :VNL, :VVLRPRODUTO, :VVLRSERVICO, :VTIPOCOMISSAO, 0,
        :VALIQCOMISPRODEMISSAO, :VVLRCOMISPRODEMISSAO,
        0,0,
        :VALIQCOMISSERVEMISSAO, :VVLRCOMISSERVEMISSAO,
        0,0,
        :VSITCOMISEMISSAO, :VDATABAIXAEMISSAO, 1);
    END
end^


ALTER PROCEDURE GERARCOMISSAOPROD (
    ECHAVEDOC INTEGER,
    EPESQPORFAIXA INTEGER,
    ECHAVEEMPCOMISPROD INTEGER,
    ECHAVEEMPPV INTEGER,
    EORIGEM INTEGER,
    EORIGEMPDV CHAR(1))
AS
declare variable VCHAVEPROD integer;
declare variable VVALOR numeric(18,6);
declare variable VCHAVEVEND integer;
declare variable VALIQ numeric(7,2);
declare variable VNL double precision;
declare variable VTIPOPAGTOPDV integer;
declare variable VTIPOPAGTO integer;
declare variable VTOTALITEM numeric(18,6);
declare variable VVLRTOTALCOMIS numeric(18,6);
declare variable VCHAVEITEM integer;
declare variable VCHAVEREC integer;
declare variable VVALORPARCELA numeric(18,6);
declare variable VTOTALDOC numeric(18,6);
declare variable VTIPO integer;
declare variable VCHAVEITEMDEVOLV integer;
declare variable VDOC varchar(20);
declare variable VCHAVECLIFOR integer;
declare variable VCHAVETABELAPRECO integer;
declare variable VDATACONTA date;
BEGIN
    FOR SELECT CHAVEVENDEDOR FROM COMISSAO
    WHERE (ATIVO=1) AND (CHAVEDOC=:ECHAVEDOC) AND (ORIGEM=:EORIGEM)
    INTO :VCHAVEVEND
    DO BEGIN
        IF (:EORIGEM = 0) THEN BEGIN
            FOR SELECT P.TIPOPAGAMENTO, I.CHAVE, I.CHAVEPRODUTO, CAST(I.VLRTOTAL/I.QTDE AS NUMERIC(18,6)), P.NL, CAST(I.VLRUNITCOMDESC * I.QTDE AS NUMERIC(18,6)), 0,
            I.CHAVETABELAPRECO
            FROM PEDIDOSAIDA P
            INNER JOIN ITENSPEDSAIDA I ON (P.CHAVE=I.CHAVEPEDIDO) AND (I.ATIVO=1)
            INNER JOIN CFOP C ON (I.CHAVECFOP=C.CHAVE) AND (C.CLASSIFICACAO = 1)
            WHERE (P.ATIVO=1) AND (P.CHAVE=:ECHAVEDOC)
            UNION ALL
            SELECT P.TIPOPAGAMENTO, ITS.CHAVE, ITS.CHAVEPRODUTO, CAST(ITS.VLRTOTAL/ITS.QTDE AS NUMERIC(18,6)), P.NL, CAST(ITS.VLRUNITCOMDESCSERVICO * ITS.QTDE AS NUMERIC(18,6)), 1,
            ITS.CHAVETABELAPRECO
            FROM PEDIDOSAIDA P
            INNER JOIN ITENSPEDSAIDASERV ITS ON (P.CHAVE=ITS.CHAVEPEDIDO) AND (ITS.ATIVO=1)
            INNER JOIN CFOP C ON (ITS.CHAVECFOP=C.CHAVE) AND (C.CLASSIFICACAO = 1)
            WHERE (P.ATIVO=1) AND (P.CHAVE=:ECHAVEDOC)
            INTO :VTIPOPAGTO, :VCHAVEITEM, :VCHAVEPROD, :VVALOR, :VNL, :VTOTALITEM, :VTIPO, :VCHAVETABELAPRECO
            DO BEGIN
                VALIQ = 0;
                IF (:EPESQPORFAIXA = 0) THEN BEGIN
                    SELECT FIRST 1 CASE :VTIPOPAGTO WHEN 0 THEN C.ALIQCOMISSAO WHEN 1 THEN C.ALIQCOMISPRAZO ELSE 0 END FROM COMISSAOPRODUTO C
                    WHERE (C.ATIVO=1) AND (C.CHAVEEMPRESA=:ECHAVEEMPCOMISPROD) AND (C.CHAVEVENDEDOR=:VCHAVEVEND) AND (C.CHAVEPRODUTO=:VCHAVEPROD)
                    AND (COALESCE(C.FAIXAVLRPERC,0)=0)
                    INTO :VALIQ;
                END ELSE BEGIN
                    SELECT FIRST 1 CASE :VTIPOPAGTO WHEN 0 THEN C.ALIQCOMISSAO WHEN 1 THEN C.ALIQCOMISPRAZO ELSE 0 END FROM COMISSAOPRODUTO C
                    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO = C.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:ECHAVEEMPPV) AND (PV.CHAVETABELAPRECO=:VCHAVETABELAPRECO) AND (PV.ATIVO=1)
                    WHERE (C.ATIVO=1) AND (C.CHAVEEMPRESA=:ECHAVEEMPCOMISPROD) AND (C.CHAVEVENDEDOR=:VCHAVEVEND) AND (C.CHAVEPRODUTO=:VCHAVEPROD)
                    AND (CASE WHEN C.TIPOFAIXAPRECO = 1 THEN
                        COALESCE(C.FAIXAVLRPERC,0)
                    ELSE
                       CASE WHEN COALESCE(C.FAIXAVLRPERC,0) > 0 THEN
                              CAST(PV.PRECOVENDA+(COALESCE(C.FAIXAVLRPERC,0)*PV.PRECOVENDA/100) AS NUMERIC (18,2))
                       ELSE
                              :VVALOR
                       END
                    END) >= :VVALOR
                    ORDER BY (CASE WHEN C.TIPOFAIXAPRECO = 1 THEN COALESCE(C.FAIXAVLRPERC,0) ELSE
                    CAST(PV.PRECOVENDA+(COALESCE(C.FAIXAVLRPERC,0)*PV.PRECOVENDA/100) AS NUMERIC (18,2)) END)
                    INTO :VALIQ;
                END
    
                INSERT INTO COMISSAOPRODUTODOC(CHAVEEMPRESA, CHAVEDOC, ORIGEM, NL, CHAVEITEM, CHAVEVENDEDOR, BASE, ALIQ, VALOR, TIPO)
                VALUES(:ECHAVEEMPCOMISPROD, :ECHAVEDOC, :EORIGEM, :VNL, :VCHAVEITEM, :VCHAVEVEND, :VTOTALITEM, :VALIQ, CAST(:VTOTALITEM*:VALIQ/100 AS NUMERIC(18,6)), :VTIPO);
            END
        END
        IF ((:EORIGEM = 1))  THEN BEGIN
            IF (EORIGEMPDV = 'S') THEN BEGIN
                SELECT FIRST 1 TIPOPGTO FROM (
                SELECT COUNT(CASE WHEN TRANSACAO IN (1,2,5) THEN 0 ELSE 1 END) AS QTDE,
                CASE WHEN TRANSACAO IN (1,2,5) THEN 0 ELSE 1 END TIPOPGTO FROM CAIXAPDV
                WHERE (ATIVO in(-1, 1)) AND (CHAVECUPOM=:ECHAVEDOC) AND (TRANSACAOMESTRE=7) -- O ativo -1 para pegar NFCE pois ainda esta como pendente no momento de gerar aliquota.
                AND TRANSACAO IN (1,2,3,4,5,8,9)
                GROUP BY 2
                )
                ORDER BY QTDE DESC
                INTO :VTIPOPAGTOPDV;
                SELECT CASE WHEN COALESCE(MIN(CHAVE),0) > 0 THEN 1 ELSE 0 END AS TEMCOMISFAIXAPRECO
                FROM COMISSAOPRODUTO
                WHERE (ATIVO=1) AND (CHAVEEMPRESA=:ECHAVEEMPCOMISPROD)
                AND (TIPOFAIXAPRECO<>0)
                INTO :EPESQPORFAIXA;
            END
            FOR SELECT N.TIPOPAGAMENTO, I.CHAVE, I.CHAVEPRODUTO, CAST(I.VLRTOTAL/I.QTDE AS NUMERIC(18,6)), N.NL, CAST(I.VLRUNITCOMDESC * I.QTDE AS NUMERIC(18,6)), 0,
            I.CHAVETABELAPRECO
            FROM NFSAIDA N
            INNER JOIN ITENSNFSAIDA I ON (N.CHAVE=I.CHAVENFSAIDA) AND (I.ATIVO=1)
            INNER JOIN CFOP C ON (I.CHAVECFOP=C.CHAVE) AND (C.CLASSIFICACAO=1)
            WHERE (N.ATIVO=1) AND (N.CHAVE=:ECHAVEDOC)
            UNION ALL
            SELECT N.TIPOPAGAMENTO, INFS.CHAVE, INFS.CHAVEPRODUTO, CAST(INFS.VLRTOTAL/INFS.QTDE AS NUMERIC(18,6)), N.NL, CAST(INFS.VLRUNITCOMDESCSERVICO * INFS.QTDE AS NUMERIC(18,6)), 1,
            INFS.CHAVETABELAPRECO
            FROM NFSAIDA N
            INNER JOIN ITENSNFSERVICO INFS ON (N.CHAVE=INFS.CHAVENFSAIDA) AND (INFS.ATIVO=1)
            INNER JOIN CFOP C ON (INFS.CHAVECFOP=C.CHAVE) AND (C.CLASSIFICACAO=1)
            WHERE (N.ATIVO=1) AND (N.CHAVE=:ECHAVEDOC)
            INTO :VTIPOPAGTO, :VCHAVEITEM, :VCHAVEPROD, :VVALOR, :VNL, :VTOTALITEM, :VTIPO, :VCHAVETABELAPRECO
            DO BEGIN
               IF (EORIGEMPDV = 'S') THEN
                    VTIPOPAGTO = :VTIPOPAGTOPDV;
                VALIQ = 0;
                IF (:EPESQPORFAIXA = 0) THEN BEGIN
                    SELECT FIRST 1 CASE :VTIPOPAGTO WHEN 0 THEN C.ALIQCOMISSAO WHEN 1 THEN C.ALIQCOMISPRAZO ELSE 0 END FROM COMISSAOPRODUTO C
                    WHERE (C.ATIVO=1) AND (C.CHAVEEMPRESA=:ECHAVEEMPCOMISPROD) AND (C.CHAVEVENDEDOR=:VCHAVEVEND) AND (C.CHAVEPRODUTO=:VCHAVEPROD)
                    AND (COALESCE(C.FAIXAVLRPERC,0)=0)
                    INTO :VALIQ;
                END ELSE BEGIN
                    SELECT FIRST 1 CASE :VTIPOPAGTO WHEN 0 THEN C.ALIQCOMISSAO WHEN 1 THEN C.ALIQCOMISPRAZO ELSE 0 END FROM COMISSAOPRODUTO C
                    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO = C.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:ECHAVEEMPPV) AND (PV.CHAVETABELAPRECO=:VCHAVETABELAPRECO) AND (PV.ATIVO=1)
                    WHERE (C.ATIVO=1) AND (C.CHAVEEMPRESA=:ECHAVEEMPCOMISPROD) AND (C.CHAVEVENDEDOR=:VCHAVEVEND) AND (C.CHAVEPRODUTO=:VCHAVEPROD)
                    AND (CASE WHEN C.TIPOFAIXAPRECO = 1 THEN
                        COALESCE(C.FAIXAVLRPERC,0)
                    ELSE
                       CASE WHEN COALESCE(C.FAIXAVLRPERC,0) > 0 THEN
                              CAST(PV.PRECOVENDA+(COALESCE(C.FAIXAVLRPERC,0)*PV.PRECOVENDA/100) AS NUMERIC (18,2))
                       ELSE
                              :VVALOR
                       END
                    END) >= :VVALOR
                    ORDER BY (CASE WHEN C.TIPOFAIXAPRECO = 1 THEN COALESCE(C.FAIXAVLRPERC,0) ELSE
                    CAST(PV.PRECOVENDA+(COALESCE(C.FAIXAVLRPERC,0)*PV.PRECOVENDA/100) AS NUMERIC (18,2)) END)
                    INTO :VALIQ;
                END
                INSERT INTO COMISSAOPRODUTODOC(CHAVEEMPRESA, CHAVEDOC, ORIGEM, NL, CHAVEITEM, CHAVEVENDEDOR, BASE, ALIQ, VALOR, TIPO)
                VALUES(:ECHAVEEMPCOMISPROD, :ECHAVEDOC, :EORIGEM, :VNL, :VCHAVEITEM, :VCHAVEVEND, :VTOTALITEM, :VALIQ, cast(:VTOTALITEM*:VALIQ as numeric(18,6))/100, :VTIPO);
            END
        END
        IF (:EORIGEM = 6) THEN BEGIN
            SELECT FIRST 1 TIPOPGTO FROM (
            SELECT COUNT(CASE WHEN TRANSACAO IN (1,2,5) THEN 0 ELSE 1 END) AS QTDE,
            CASE WHEN TRANSACAO IN (1,2,5) THEN 0 ELSE 1 END TIPOPGTO FROM CAIXAPDV
            WHERE (ATIVO=1) AND (CHAVECUPOM=:ECHAVEDOC) AND (TRANSACAOMESTRE=0)
            AND TRANSACAO IN (1,2,3,4,5,8,9)
            GROUP BY 2
            )
            ORDER BY QTDE DESC
            INTO :VTIPOPAGTO;
            SELECT CASE WHEN COALESCE(MIN(CHAVE),0) > 0 THEN 1 ELSE 0 END AS TEMCOMISFAIXAPRECO
            FROM COMISSAOPRODUTO
            WHERE (ATIVO=1) AND (CHAVEEMPRESA=:ECHAVEEMPCOMISPROD)
            AND (TIPOFAIXAPRECO<>0)
            INTO :EPESQPORFAIXA;
            FOR SELECT I.CHAVE, I.CHAVEPRODUTO, CAST(I.VLRTOTAL/I.QTDE AS NUMERIC(18,6)), CF.NL, I.VLRUNITCOMDESCACRESC, 0,
            I.CHAVETABELAPRECO
            FROM CUPOMFISCAL CF
            INNER JOIN ITENSCUPOM I ON (CF.CHAVE=I.CHAVECUPOM) AND (I.ATIVO=1)
            WHERE (CF.ATIVO=1) AND (CF.CHAVE=:ECHAVEDOC)
            INTO :VCHAVEITEM, :VCHAVEPROD, :VVALOR, :VNL, :VTOTALITEM, :VTIPO, :VCHAVETABELAPRECO
            DO BEGIN
                VALIQ = 0;
                IF (:EPESQPORFAIXA = 0) THEN BEGIN
                    SELECT FIRST 1 CASE :VTIPOPAGTO WHEN 0 THEN C.ALIQCOMISSAO WHEN 1 THEN C.ALIQCOMISPRAZO ELSE 0 END FROM COMISSAOPRODUTO C
                    WHERE (C.ATIVO=1) AND (C.CHAVEEMPRESA=:ECHAVEEMPCOMISPROD) AND (C.CHAVEVENDEDOR=:VCHAVEVEND) AND (C.CHAVEPRODUTO=:VCHAVEPROD)
                    AND (COALESCE(C.FAIXAVLRPERC,0)=0)
                    INTO :VALIQ;
                END ELSE BEGIN
                    SELECT FIRST 1 CASE :VTIPOPAGTO WHEN 0 THEN C.ALIQCOMISSAO WHEN 1 THEN C.ALIQCOMISPRAZO ELSE 0 END FROM COMISSAOPRODUTO C
                    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO = C.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:ECHAVEEMPPV) AND (PV.CHAVETABELAPRECO=:VCHAVETABELAPRECO) AND (PV.ATIVO=1)
                    WHERE (C.ATIVO=1) AND (C.CHAVEEMPRESA=:ECHAVEEMPCOMISPROD) AND (C.CHAVEVENDEDOR=:VCHAVEVEND) AND (C.CHAVEPRODUTO=:VCHAVEPROD)
                    AND (CASE WHEN C.TIPOFAIXAPRECO = 1 THEN
                        COALESCE(C.FAIXAVLRPERC,0)
                    ELSE
                       CASE WHEN COALESCE(C.FAIXAVLRPERC,0) > 0 THEN
                              CAST(PV.PRECOVENDA+(COALESCE(C.FAIXAVLRPERC,0)*PV.PRECOVENDA/100) AS NUMERIC (18,2))
                       ELSE
                              :VVALOR
                       END
                    END) >= :VVALOR
                    ORDER BY (CASE WHEN C.TIPOFAIXAPRECO = 1 THEN COALESCE(C.FAIXAVLRPERC,0) ELSE
                    CAST(PV.PRECOVENDA+(COALESCE(C.FAIXAVLRPERC,0)*PV.PRECOVENDA/100) AS NUMERIC (18,2)) END)
                    INTO :VALIQ;
                END
    
                INSERT INTO COMISSAOPRODUTODOC(CHAVEEMPRESA, CHAVEDOC, ORIGEM, NL, CHAVEITEM, CHAVEVENDEDOR, BASE, ALIQ, VALOR, TIPO)
                VALUES(:ECHAVEEMPCOMISPROD, :ECHAVEDOC, :EORIGEM, :VNL, :VCHAVEITEM, :VCHAVEVEND, :VTOTALITEM, :VALIQ, cast(:VTOTALITEM*:VALIQ as numeric(18,6))/100, :VTIPO);
            END
        END
    END
    IF (:EORIGEM = 8) THEN BEGIN
        FOR SELECT I.CHAVE, I.CHAVEPRODUTO, CAST(I.VLRTOTAL/I.QTDE AS NUMERIC(18,6)), N.NL, CAST(I.VLRUNITCOMDESC * I.QTDE AS NUMERIC(18,6)), 0, I.CHAVEITEMDEVOLV,
        N.NUMERONF, N.CHAVECLIFOR FROM NFENTRADA N
        INNER JOIN ITENSNFENTRADAPROD I ON (N.CHAVE=I.CHAVENFENTRADA) AND (I.ATIVO=1) AND (I.ORIGEMDEVOLV=0) AND (I.CHAVEITEMDEVOLV > 0)
        INNER JOIN CFOP C ON (I.CHAVECFOP=C.CHAVE) AND (C.CLASSIFICACAO=3)
        WHERE (N.ATIVO=1) AND (N.CHAVE=:ECHAVEDOC)
        INTO :VCHAVEITEM, :VCHAVEPROD, :VVALOR, :VNL, :VTOTALITEM, :VTIPO, :VCHAVEITEMDEVOLV,
        :VDOC, :VCHAVECLIFOR
        DO BEGIN
    
            INSERT INTO COMISSAOPRODUTODOC(CHAVEEMPRESA, CHAVEDOC, ORIGEM, NL, CHAVEITEM, CHAVEVENDEDOR, BASE, ALIQ, VALOR, TIPO)
            SELECT :ECHAVEEMPCOMISPROD, :ECHAVEDOC, :EORIGEM, :VNL, :VCHAVEITEM, CHAVEVENDEDOR, CAST(:VTOTALITEM*(-1) AS NUMERIC(18,6)), ALIQ, CAST((:VTOTALITEM*ALIQ/100)*(-1) AS NUMERIC(18,6)), :VTIPO
            FROM COMISSAOPRODUTODOC
            WHERE (ATIVO=1) AND (ORIGEM=1) AND (CHAVEITEM=:VCHAVEITEMDEVOLV);
    
        END
        INSERT INTO COMISSAOFATURAMENTOPROD(CHAVEEMPRESA, CHAVEDOC, ORIGEM, NL, CHAVEVENDEDOR, CHAVERECEBER, BASE, VALOR,
        TIPOPAGAMENTO, DATA, SITUACAO, ALIQ, CHAVECLIFOR, DOC)
        SELECT :ECHAVEEMPCOMISPROD, :ECHAVEDOC, :EORIGEM, :VNL,  CHAVEVENDEDOR, :VCHAVEREC, CAST(SUM(BASE) AS NUMERIC(18,6)), CAST(SUM(VALOR) AS NUMERIC(18,6)),
        0, CURRENT_DATE, 0, CAST((SUM(VALOR)*100)/SUM(BASE) AS NUMERIC(18,6)), :VCHAVECLIFOR, :VDOC
        FROM COMISSAOPRODUTODOC
        WHERE (ATIVO=1) AND (NL=:VNL)
        GROUP BY CHAVEVENDEDOR;
    END
    IF (:EORIGEM <> 8) THEN BEGIN
        FOR SELECT CHAVEVENDEDOR FROM COMISSAO
        WHERE (ATIVO=1) AND (CHAVEDOC=:ECHAVEDOC) AND (ORIGEM=:EORIGEM)
        INTO :VCHAVEVEND
        DO BEGIN
        
            SELECT CAST(SUM(VALOR) AS NUMERIC(18,6)) FROM COMISSAOPRODUTODOC
            WHERE (ATIVO=1) AND (CHAVEDOC=:ECHAVEDOC) AND (ORIGEM=:EORIGEM) AND (NL=:VNL) AND (CHAVEVENDEDOR=:VCHAVEVEND)
            INTO :VVLRTOTALCOMIS;
    
            SELECT CAST(SUM(COALESCE(R.VALORPRODUTO, 0) + COALESCE(R.VALORSERVICO, 0)) AS NUMERIC(18,6))
            FROM RECEBER R
            WHERE (ATIVO=1) AND (NL=:VNL) AND (CHAVEDOC=:ECHAVEDOC)
            INTO :VTOTALDOC;
    
            VALIQ = 0;
            IF (:VVLRTOTALCOMIS > 0 AND :VTOTALDOC > 0) THEN
                VALIQ= CAST((:VVLRTOTALCOMIS*100)/:VTOTALDOC AS NUMERIC(7,2));
    
            FOR SELECT R.CHAVE, R.DOCUMENTO, R.DATACONTA, R.CHAVECLIFOR, CAST(COALESCE(R.VALORPRODUTO, 0) + COALESCE(R.VALORSERVICO, 0) AS NUMERIC(18,6))
            FROM RECEBER R
            WHERE (R.ATIVO=1) AND (R.NL=:VNL)
            INTO :VCHAVEREC, :VDOC, :VDATACONTA, :VCHAVECLIFOR, :VVALORPARCELA
            DO BEGIN
                
                INSERT INTO COMISSAOFATURAMENTOPROD
                (CHAVEEMPRESA, CHAVEDOC, ORIGEM, NL, CHAVEVENDEDOR, CHAVERECEBER, BASE, VALOR,
                TIPOPAGAMENTO, DATA, SITUACAO, ALIQ, DOC, CHAVECLIFOR)
                VALUES
                (:ECHAVEEMPCOMISPROD, :ECHAVEDOC, :EORIGEM, :VNL,  :VCHAVEVEND, :VCHAVEREC, :VVALORPARCELA, CAST(:VVALORPARCELA*:VALIQ/100 AS NUMERIC(18,6)),
                :VTIPOPAGTO, :VDATACONTA, 0, :VALIQ, :VDOC, :VCHAVECLIFOR);
    
            END
        END
    END
END^


ALTER PROCEDURE GERARDIGVERIFEAN13 (
    ECODIGO VARCHAR(12))
RETURNS (
    SDIGITO INTEGER)
AS
declare variable VSOMA integer;
declare variable VDIGCOD integer;
declare variable VCONT integer;
BEGIN
    VCONT = 1;
    VSOMA = 0;
    WHILE (:VCONT <= CHAR_LENGTH(:ECODIGO)) DO BEGIN
        VDIGCOD = (CAST(SUBSTRING(:ECODIGO FROM :VCONT FOR 1) AS INTEGER));
        VSOMA = :VSOMA + (CASE WHEN (MOD(:VCONT, 2) = 0) then 3 else 1 end) * :VDIGCOD;
        VCONT = :VCONT + 1;
    END
    SDIGITO = ((TRUNC(:VSOMA / 10,0) + 1) * 10) - :VSOMA;
    IF (:SDIGITO > 9) THEN
       SDIGITO = 0;
    SUSPEND;
END^


ALTER PROCEDURE GERARFINANCEIROPAGAR (
    ECHAVE INTEGER,
    ECHAVEEMPRESA INTEGER,
    EORIGEM INTEGER,
    ESTATUS INTEGER,
    ETIPO SMALLINT,
    EDOCUMENTO VARCHAR(20),
    EDATACONTA DATE,
    EDATAENTRADA DATE,
    EDESCRICAO VARCHAR(100),
    EVENCIMENTO DATE,
    EPARCELA INTEGER,
    ETOTPARC INTEGER,
    EOBS VARCHAR(1000),
    EVALOR NUMERIC(18,6),
    EABATIMENTO NUMERIC(18,6),
    EACRESCIMO NUMERIC(18,6),
    EVLRPAGO NUMERIC(18,6),
    EDATAPAGAMENTO DATE,
    ECHAVEPLANOCTO INTEGER,
    ECHAVECENTROCTO INTEGER,
    ECHAVECLIFOR INTEGER,
    ENL DOUBLE PRECISION,
    ENLAGRUPADO DOUBLE PRECISION,
    EAGRUPADO INTEGER,
    ECHAVEUSUARIODESCTO INTEGER,
    ERECEBPARCIAL NUMERIC(18,6),
    ERECEBPARCIALSEMJUROS NUMERIC(18,6),
    ECHAVECTABANCARIA INTEGER,
    ECHAVEOPERACOESTITULOS INTEGER,
    EVLRMULTA NUMERIC(18,6),
    ECONTRAPARTIDA INTEGER,
    ECHAVEPROVISAO INTEGER,
    EDATAHORACAD TIMESTAMP,
    ECHAVEUSUARIOCAD INTEGER,
    EDATAHORAALT TIMESTAMP,
    ECHAVEUSUARIOALT INTEGER,
    ECOMPETENCIA VARCHAR(10))
AS
BEGIN
    INSERT INTO PAGAR (CHAVE, ATIVO, CHAVEEMPRESA, ORIGEM, TIPO, STATUS, DOCUMENTO, DATACONTA,
        DATAENTRADA, DESCRICAO, VENCIMENTO, PARCELA, TOTPARC, OBS, VALOR, ABATIMENTO, ACRESCIMO,
        VLRPAGO, DATAPAGAMENTO, CHAVEPLANOCTO, CHAVECENTROCTO, CHAVECLIFOR, NL,
        NLAGRUPADO, AGRUPADO,
        CHAVEUSUARIODESCTO, RECEBPARCIAL, RECEBPARCIALSEMJUROS,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS,
        VLRMULTA, CONTRAPARTIDA,
        CHAVEPROVISAO, DATAHORACAD,
        CHAVEUSUARIOCAD, DATAHORAALT, CHAVEUSUARIOALT, COMPETENCIA)
    VALUES (:ECHAVE, 1, :ECHAVEEMPRESA, :EORIGEM, :ETIPO, :ESTATUS, :EDOCUMENTO, :EDATACONTA,
        :EDATAENTRADA, :EDESCRICAO, :EVENCIMENTO, :EPARCELA, :ETOTPARC, :EOBS, :EVALOR, :EABATIMENTO, :EACRESCIMO,
        :EVLRPAGO, CASE WHEN :EDATAPAGAMENTO = '30.12.1899' THEN NULL ELSE :EDATAPAGAMENTO END, :ECHAVEPLANOCTO, :ECHAVECENTROCTO, :ECHAVECLIFOR, :ENL,
        CASE WHEN :ENLAGRUPADO = 0 THEN NULL ELSE :ENLAGRUPADO END, CASE WHEN :EAGRUPADO = 0 THEN NULL ELSE :EAGRUPADO END,
        CASE WHEN :ECHAVEUSUARIODESCTO = 0 THEN NULL ELSE :ECHAVEUSUARIODESCTO END, :ERECEBPARCIAL, :ERECEBPARCIALSEMJUROS,
        CASE WHEN :ECHAVECTABANCARIA = 0 THEN NULL ELSE :ECHAVECTABANCARIA END, CASE WHEN :ECHAVEOPERACOESTITULOS = 0 THEN NULL ELSE :ECHAVEOPERACOESTITULOS END,
        :EVLRMULTA, :ECONTRAPARTIDA,
        CASE WHEN :ECHAVEPROVISAO = 0 THEN NULL ELSE :ECHAVEPROVISAO END, :EDATAHORACAD,
        :ECHAVEUSUARIOCAD, :EDATAHORAALT, CASE WHEN :ECHAVEUSUARIOALT = 0 THEN NULL ELSE :ECHAVEUSUARIOALT END, :ECOMPETENCIA);
END^


