ALTER PROCEDURE GERARMOVFINANCEIRASBANCO (
    CHAVEPLANOCONTA INTEGER,
    CHAVECONTA INTEGER,
    LANCAMENTO DATE,
    CHAVEEMPCAIXA INTEGER,
    NLATUAL DOUBLE PRECISION,
    CHAVEMOVFINANCEIRA INTEGER,
    OBS VARCHAR(5000),
    CHAVEUSUARIO INTEGER,
    CHAVECONTACAIXA INTEGER,
    CHAVELANCBCO INTEGER,
    EFORMAPGTO INTEGER)
AS
begin
      INSERT INTO CAIXA (CHAVECENTROCTO, CHAVEPLANOCTO, CHAVECONTA,
            DOCUMENTO, HISTORICO, COMPETENCIA,
            LANCAMENTO, VALOR, CHAVEEMPRESA, NL,
            LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS, CHAVEUSUARIOLANC, CHAVEUSUARIOALT,
            CHAVECLIFOR, CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO)
      SELECT CHAVECENTROCTO, :CHAVEPLANOCONTA, :CHAVECONTA,
            NUMERODOC, SUBSTRING('GERADO AUT. - LANC. BANC. '||HISTORICO FROM 1 FOR 100),
            COMPETENCIA, :LANCAMENTO, COALESCE(VALOR,0), :CHAVEEMPCAIXA, :NLATUAL,
            'S', :CHAVEMOVFINANCEIRA, :OBS, :CHAVEUSUARIO, :CHAVEUSUARIO,
            CHAVECLIFOR, CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, CHAVECONTABCO, :EFORMAPGTO
      FROM LANCBCO
      WHERE (ATIVO=1) AND (CHAVE=:CHAVELANCBCO);
    /*
         CHAMADAS
           PROC GERAMOVFINANCEIRAS - GERA CAIXA DAS MOVIMENTACOES BANCARIAS
    */
end^


ALTER PROCEDURE GERARMOVFINANCEIRASCAIXA (
    CHAVEFORMA INTEGER,
    GERARCAIXALANCBANCARIO CHAR(1),
    CHAVEEMPCAIXA INTEGER,
    DATACAIXA DATE,
    CHAVEPLANOCTA INTEGER,
    CHAVECENTROCTO INTEGER,
    CHAVECONTA INTEGER,
    OBSDINHEIRO VARCHAR(100),
    DOC VARCHAR(40),
    COMPETENCIA VARCHAR(10),
    VALOR NUMERIC(18,6),
    JUROS NUMERIC(18,6),
    VLRMULTA NUMERIC(18,6),
    DESCONTOS NUMERIC(18,6),
    CHAVEUSUARIO INTEGER,
    CHAVECLIFOR INTEGER,
    CHAVEOPERACOESTITULOS INTEGER,
    OBSBAIXA VARCHAR(5000),
    NLATUAL DOUBLE PRECISION,
    LANCBANCARIO CHAR(1),
    CHAVEMOVFINANCEIRA INTEGER,
    CHAVEPLANOCONTAJUROS INTEGER,
    CHAVEPCMULTA INTEGER,
    CHAVEPLANOCONTADESC INTEGER,
    CHAVECONTACAIXA INTEGER,
    EFORMAPGTO INTEGER,
    ECHAVECHEQUE INTEGER)
AS
BEGIN
    IF ((:CHAVEFORMA <> 3) OR ((:GERARCAIXALANCBANCARIO = 'S') AND (:CHAVEFORMA = 3))) THEN BEGIN
        IF ((:JUROS > 0) OR (:VLRMULTA > 0) OR (:DESCONTOS > 0)) THEN BEGIN
            INSERT INTO CAIXA(ATIVO, CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR, CHAVEOPERACOESTITULOS,
                CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
            VALUES (10, :CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPLANOCTA,
            :CHAVECENTROCTO, :CHAVECONTA, :OBSDINHEIRO, :DOC, :COMPETENCIA, :VALOR,
            :NLATUAL, :LANCBANCARIO,:CHAVEMOVFINANCEIRA, :OBSBAIXA,
            :CHAVEUSUARIO, :CHAVEUSUARIO,:CHAVECLIFOR, :CHAVEOPERACOESTITULOS,
            :CHAVECONTACAIXA, :EFORMAPGTO, :ECHAVECHEQUE, 4);
        END
        INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
            CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
            NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
            CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR, CHAVEOPERACOESTITULOS,
            CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
        VALUES (:CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPLANOCTA,
        :CHAVECENTROCTO, :CHAVECONTA, :OBSDINHEIRO, :DOC, :COMPETENCIA, :VALOR - :JUROS - :VLRMULTA + :DESCONTOS,
        :NLATUAL, :LANCBANCARIO,:CHAVEMOVFINANCEIRA, :OBSBAIXA,
        :CHAVEUSUARIO, :CHAVEUSUARIO,:CHAVECLIFOR, :CHAVEOPERACOESTITULOS,
        :CHAVECONTACAIXA, :EFORMAPGTO, :ECHAVECHEQUE, 0);
        IF (:JUROS > 0) THEN BEGIN
            INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
            VALUES (:CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPLANOCONTAJUROS,
            :CHAVECENTROCTO, :CHAVECONTA, SUBSTRING('JUROS - '||:OBSDINHEIRO FROM 1 FOR 100), :DOC, :COMPETENCIA, :JUROS,
            :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, :OBSBAIXA,
            :CHAVEUSUARIO, :CHAVEUSUARIO, :CHAVECLIFOR,
            :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, :EFORMAPGTO, :ECHAVECHEQUE, 1);
        END
        IF (:VLRMULTA > 0) THEN BEGIN
            INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
            VALUES (:CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPCMULTA,
            :CHAVECENTROCTO, :CHAVECONTA, SUBSTRING('MULTA - '||:OBSDINHEIRO FROM 1 FOR 100), :DOC, :COMPETENCIA, :VLRMULTA,
            :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, :OBSBAIXA,
            :CHAVEUSUARIO, :CHAVEUSUARIO, :CHAVECLIFOR,
            :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, :EFORMAPGTO, :ECHAVECHEQUE, 2);
        END
        IF (:DESCONTOS > 0) THEN BEGIN
            INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
                CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
                NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
                CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
                CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
            VALUES (:CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPLANOCONTADESC,
                :CHAVECENTROCTO, :CHAVECONTA, SUBSTRING('DESCONTO - '||:OBSDINHEIRO FROM 1 FOR 100), :DOC, :COMPETENCIA, :DESCONTOS,
            :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, :OBSBAIXA,
            :CHAVEUSUARIO, :CHAVEUSUARIO, :CHAVECLIFOR,
            :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, :EFORMAPGTO, :ECHAVECHEQUE, 3);
        END
    END
    /*
         CHAMADAS
           PROC GERAMOVFINANCEIRAS - GERA CAIXA DAS MOVIMENTACOES
    */
END^


ALTER PROCEDURE GERARMOVFINANCEIRASCAIXAAGRUP (
    CHAVEEMPCAIXA INTEGER,
    DATACAIXA DATE,
    CHAVEPLANOCONTAJUROS INTEGER,
    CHAVECENTROCTO INTEGER,
    CHAVECONTA INTEGER,
    DESCRICAO VARCHAR(100),
    DOC VARCHAR(20),
    COMPETENCIA VARCHAR(10),
    NLATUAL DOUBLE PRECISION,
    LANCBANCARIO CHAR(1),
    CHAVEMOVFINANCEIRA INTEGER,
    CHAVEUSUARIO INTEGER,
    CHAVECLIFOR INTEGER,
    CHAVEOPERACOESTITULOS INTEGER,
    CHAVEPCMULTA INTEGER,
    CHAVEPLANOCONTADESC INTEGER,
    TIPOCONTA VARCHAR(2),
    OBSDINHEIRO VARCHAR(100),
    OBSBAIXA VARCHAR(5000),
    CHAVECONTACAIXA INTEGER,
    EFORMAPGTO INTEGER,
    ECHAVECHEQUE INTEGER)
AS
begin
    INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
        CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
        NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
        CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
        CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
    SELECT :CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPLANOCONTAJUROS,
        :CHAVECENTROCTO, :CHAVECONTA, SUBSTRING('JUROS - '||:DESCRICAO FROM 1 FOR 100),
        :DOC, :COMPETENCIA, COALESCE(M.JUROS,0),
        :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, :OBSBAIXA,
        :CHAVEUSUARIO, :CHAVEUSUARIO, :CHAVECLIFOR,
        :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, :EFORMAPGTO, :ECHAVECHEQUE, 1
        FROM MOVFINANCEIRAS M
        WHERE (M.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA) AND (M.TIPOCONTA=:TIPOCONTA) AND (M.JUROS>0);
    INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
        CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
        NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
        CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
        CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
    SELECT :CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPCMULTA,
        :CHAVECENTROCTO, :CHAVECONTA, SUBSTRING('MULTA - '||:DESCRICAO FROM 1 FOR 100), :DOC, :COMPETENCIA, COALESCE(M.VLRMULTA,0),
        :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, :OBSBAIXA,
        :CHAVEUSUARIO, :CHAVEUSUARIO, :CHAVECLIFOR,
        :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, :EFORMAPGTO, :ECHAVECHEQUE, 2
        FROM MOVFINANCEIRAS M
        WHERE (M.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA) AND (M.TIPOCONTA=:TIPOCONTA) AND (M.VLRMULTA>0);
    INSERT INTO CAIXA(CHAVEEMPRESA, LANCAMENTO, CHAVEPLANOCTO,
        CHAVECENTROCTO, CHAVECONTA, HISTORICO, DOCUMENTO, COMPETENCIA, VALOR,
        NL, LANCBANCARIO, CHAVEMOVFINANCEIRA, OBS,
        CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR,
        CHAVEOPERACOESTITULOS, CHAVECONTACAIXA, CHAVECONTABCO, FORMAPGTO, CHAVECHEQUE, IDCONTABIL)
    SELECT :CHAVEEMPCAIXA, :DATACAIXA, :CHAVEPLANOCONTADESC,
        :CHAVECENTROCTO, :CHAVECONTA, SUBSTRING('DESCONTO - '||:DESCRICAO FROM 1 FOR 100),
        :DOC, :COMPETENCIA, COALESCE(M.DESCONTOS,0),
        :NLATUAL, :LANCBANCARIO, :CHAVEMOVFINANCEIRA, :OBSBAIXA,
        :CHAVEUSUARIO, :CHAVEUSUARIO, :CHAVECLIFOR,
        :CHAVEOPERACOESTITULOS, :CHAVECONTACAIXA, M.CHAVECONTABCO, :EFORMAPGTO, :ECHAVECHEQUE, 3
        FROM MOVFINANCEIRAS M
        WHERE (M.ATIVO=1) AND (M.CHAVECONTA=:CHAVECONTA) AND (M.TIPOCONTA=:TIPOCONTA) AND (M.DESCONTOS>0);
    /*
         CHAMADAS
           PROC GERAMOVFINANCEIRAS - GERA CAIXA DAS MOVIMENTACOES
    */
end^


ALTER PROCEDURE GERARMOVFINANCEIRASLANCBCO (
    ECHAVEEMPLANCBANCARIO INTEGER,
    EDATACAIXA DATE,
    ECHAVEPLANOCTA INTEGER,
    ECHAVECENTROCTO INTEGER,
    ECHAVECONTA INTEGER,
    EHISTORICO VARCHAR(100),
    ECOMPETENCIA VARCHAR(10),
    EVALOR NUMERIC(18,6),
    EJUROS NUMERIC(18,6),
    EVLRMULTA NUMERIC(18,6),
    EDESCONTOS NUMERIC(18,6),
    ECHAVEUSUARIO INTEGER,
    ECHAVECLIFOR INTEGER,
    ECHAVEOPERACOESTITULOS INTEGER,
    ENLATUAL DOUBLE PRECISION,
    ECHAVEMOVFINANCEIRA INTEGER,
    ECHAVEPLANOCONTAJUROS INTEGER,
    ECHAVEPCMULTA INTEGER,
    ECHAVEPLANOCONTADESC INTEGER,
    EPREDATADO CHAR(1),
    ECOMPENSADO DATE,
    ECHAVECONTABANCARIA INTEGER,
    ETIPO INTEGER,
    ENUMERODOC VARCHAR(40),
    EFAVORECIDO VARCHAR(100),
    EOBS VARCHAR(5000),
    EBOMPARA DATE,
    ECHAVECHEQUE INTEGER)
AS
BEGIN
    IF ((:EJUROS > 0) OR (:EVLRMULTA > 0) OR (:EDESCONTOS > 0)) THEN BEGIN
        INSERT INTO LANCBCO(ATIVO, CHAVEEMPRESA, CHAVECONTABCO, TIPOCOBBCO, DATALANC, HISTORICO,
            NUMERODOC, PREDATADO, COMPETENCIA, VALOR, CHAVEMOVFINANCEIRA,
            CHAVEPLANOCTO, CHAVECENTROCTO, COMPENSADO, NL, CHAVECONTA,
            FAVORECIDO, CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR, CHAVEOPERACOESTITULOS,
            OBS, BOMPARA, SITUACAO, CHAVECHEQUE, IDCONTABIL)
        VALUES (10, :ECHAVEEMPLANCBANCARIO, :ECHAVECONTABANCARIA, :ETIPO, :EDATACAIXA, :EHISTORICO,
            :ENUMERODOC, :EPREDATADO, :ECOMPETENCIA, :EVALOR, :ECHAVEMOVFINANCEIRA,
            :ECHAVEPLANOCTA, :ECHAVECENTROCTO, CASE :EPREDATADO WHEN 'S' THEN NULL ELSE :ECOMPENSADO END, :ENLATUAL,  :ECHAVECONTA,
            :EFAVORECIDO, :ECHAVEUSUARIO, :ECHAVEUSUARIO, :ECHAVECLIFOR, :ECHAVEOPERACOESTITULOS,
            :EOBS, :EBOMPARA, CASE :EPREDATADO WHEN 'S' THEN 0 ELSE 1 END, :ECHAVECHEQUE, 4);
    END
    INSERT INTO LANCBCO(CHAVEEMPRESA, CHAVECONTABCO, TIPOCOBBCO, DATALANC, HISTORICO,
        NUMERODOC, PREDATADO, COMPETENCIA, VALOR, CHAVEMOVFINANCEIRA,
        CHAVEPLANOCTO, CHAVECENTROCTO, COMPENSADO, NL, CHAVECONTA,
        FAVORECIDO, CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR, CHAVEOPERACOESTITULOS,
        OBS, BOMPARA, SITUACAO, CHAVECHEQUE, IDCONTABIL)
    VALUES (:ECHAVEEMPLANCBANCARIO, :ECHAVECONTABANCARIA, :ETIPO, :EDATACAIXA, :EHISTORICO,
        :ENUMERODOC, :EPREDATADO, :ECOMPETENCIA, :EVALOR - :EJUROS - :EVLRMULTA + :EDESCONTOS, :ECHAVEMOVFINANCEIRA,
        :ECHAVEPLANOCTA, :ECHAVECENTROCTO, CASE :EPREDATADO WHEN 'S' THEN NULL ELSE :ECOMPENSADO END, :ENLATUAL,  :ECHAVECONTA,
        :EFAVORECIDO, :ECHAVEUSUARIO, :ECHAVEUSUARIO, :ECHAVECLIFOR, :ECHAVEOPERACOESTITULOS,
        :EOBS, :EBOMPARA, CASE :EPREDATADO WHEN 'S' THEN 0 ELSE 1 END, :ECHAVECHEQUE, 0);
    IF (:EJUROS > 0) THEN BEGIN
        INSERT INTO LANCBCO(CHAVEEMPRESA, CHAVECONTABCO, TIPOCOBBCO, DATALANC, HISTORICO,
            NUMERODOC, PREDATADO, COMPETENCIA, VALOR, CHAVEMOVFINANCEIRA,
            CHAVEPLANOCTO, CHAVECENTROCTO, COMPENSADO, NL, CHAVECONTA,
            FAVORECIDO, CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR, CHAVEOPERACOESTITULOS,
            OBS, BOMPARA, SITUACAO, CHAVECHEQUE, IDCONTABIL)
        VALUES (:ECHAVEEMPLANCBANCARIO, :ECHAVECONTABANCARIA, :ETIPO, :EDATACAIXA, :EHISTORICO,
            :ENUMERODOC, :EPREDATADO, :ECOMPETENCIA, :EJUROS, :ECHAVEMOVFINANCEIRA,
            :ECHAVEPLANOCONTAJUROS, :ECHAVECENTROCTO, CASE :EPREDATADO WHEN 'S' THEN NULL ELSE :ECOMPENSADO END, :ENLATUAL,  :ECHAVECONTA,
            :EFAVORECIDO, :ECHAVEUSUARIO, :ECHAVEUSUARIO, :ECHAVECLIFOR, :ECHAVEOPERACOESTITULOS,
            :EOBS, :EBOMPARA, CASE :EPREDATADO WHEN 'S' THEN 0 ELSE 1 END, :ECHAVECHEQUE, 1);
    END
    IF (:EVLRMULTA > 0) THEN BEGIN
        INSERT INTO LANCBCO(CHAVEEMPRESA, CHAVECONTABCO, TIPOCOBBCO, DATALANC, HISTORICO,
            NUMERODOC, PREDATADO, COMPETENCIA, VALOR, CHAVEMOVFINANCEIRA,
            CHAVEPLANOCTO, CHAVECENTROCTO, COMPENSADO, NL, CHAVECONTA,
            FAVORECIDO, CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR, CHAVEOPERACOESTITULOS,
            OBS, BOMPARA, SITUACAO, CHAVECHEQUE, IDCONTABIL)
        VALUES (:ECHAVEEMPLANCBANCARIO, :ECHAVECONTABANCARIA, :ETIPO, :EDATACAIXA, :EHISTORICO,
            :ENUMERODOC, :EPREDATADO, :ECOMPETENCIA, :EVLRMULTA, :ECHAVEMOVFINANCEIRA,
            :ECHAVEPCMULTA, :ECHAVECENTROCTO, CASE :EPREDATADO WHEN 'S' THEN NULL ELSE :ECOMPENSADO END, :ENLATUAL,  :ECHAVECONTA,
            :EFAVORECIDO, :ECHAVEUSUARIO, :ECHAVEUSUARIO, :ECHAVECLIFOR, :ECHAVEOPERACOESTITULOS,
            :EOBS, :EBOMPARA, CASE :EPREDATADO WHEN 'S' THEN 0 ELSE 1 END, :ECHAVECHEQUE, 2);
    END
    IF (:EDESCONTOS > 0) THEN BEGIN
        INSERT INTO LANCBCO(CHAVEEMPRESA, CHAVECONTABCO, TIPOCOBBCO, DATALANC, HISTORICO,
            NUMERODOC, PREDATADO, COMPETENCIA, VALOR, CHAVEMOVFINANCEIRA,
            CHAVEPLANOCTO, CHAVECENTROCTO, COMPENSADO, NL, CHAVECONTA,
            FAVORECIDO, CHAVEUSUARIOLANC, CHAVEUSUARIOALT, CHAVECLIFOR, CHAVEOPERACOESTITULOS,
            OBS, BOMPARA, SITUACAO, CHAVECHEQUE, IDCONTABIL)
        VALUES (:ECHAVEEMPLANCBANCARIO, :ECHAVECONTABANCARIA, CASE WHEN :ETIPO IN (1,2) THEN 0 ELSE 1 END, :EDATACAIXA, :EHISTORICO,
            :ENUMERODOC, :EPREDATADO, :ECOMPETENCIA, :EDESCONTOS, :ECHAVEMOVFINANCEIRA,
            :ECHAVEPLANOCONTADESC, :ECHAVECENTROCTO, CASE :EPREDATADO WHEN 'S' THEN NULL ELSE :ECOMPENSADO END, :ENLATUAL,  :ECHAVECONTA,
            :EFAVORECIDO, :ECHAVEUSUARIO, :ECHAVEUSUARIO, :ECHAVECLIFOR, :ECHAVEOPERACOESTITULOS,
            :EOBS, :EBOMPARA, CASE :EPREDATADO WHEN 'S' THEN 0 ELSE 1 END, :ECHAVECHEQUE, 3);
    END
    /*
        CHAMADAS
            PROC GERAMOVFINANCEIRAS - GERA LANCAMENTOS BANCARIOS DAS MOVIMENTACOES
    */
END^


ALTER PROCEDURE GERAROSAGENDAOS (
    ECHAVEAGENDA INTEGER,
    ECHAVEEMPOS INTEGER,
    ECHAVEUSUARIO INTEGER,
    ECHAVEEMPCUSTO INTEGER,
    EUFEMPRESALOG VARCHAR(2),
    ECHAVEEMPVENDA INTEGER,
    ECHAVEDPTOESTOQUE INTEGER,
    ENLATUAL DOUBLE PRECISION,
    ECHAVETABELAPRECO INTEGER)
RETURNS (
    SNROOSNOVO VARCHAR(10))
AS
declare variable VCHAVEGENOS integer;
declare variable VNROORDEM varchar(20);
declare variable VPADRAO varchar(20);
declare variable VULTIMONRODAV integer;
declare variable VNRODAV varchar(20);
declare variable VPESSOA integer;
declare variable VUFCLI char(2);
declare variable VCHAVEOPERPROD integer;
declare variable VCHAVEOPERSERV integer;
declare variable VCHAVEPRODUTO integer;
declare variable VCHAVETRIBUTACAO integer;
declare variable VPRECOVENDA numeric(18,6);
declare variable VPRECOCUSTO numeric(18,6);
declare variable VCHAVEUNIDADE integer;
declare variable VUNIDADE char(6);
declare variable VDESCRPROD varchar(100);
declare variable VIPI numeric(7,2);
declare variable VVLRIPITRIB numeric(18,6);
declare variable VCHAVECFOP integer;
declare variable VCOMISPRODUTO numeric(7,2);
declare variable VCODIGOPROD varchar(6);
declare variable VIERG varchar(20);
declare variable VTOTALPROD numeric(18,2);
declare variable VTOTALSERV numeric(18,2);
declare variable VCHAVEVENDEDOR integer;
BEGIN
    VCHAVEGENOS = GEN_ID(GEN_ORDEMSERVICO_ID,1);

    VNROORDEM= '';
    VPADRAO  = '______';
    VNROORDEM= CAST(:VCHAVEGENOS AS INTEGER);
    WHILE (NOT :VNROORDEM LIKE VPADRAO) DO VNROORDEM = '0' || :VNROORDEM;

    SELECT FIRST 1 CASE WHEN NRODAV='' THEN 0 ELSE NRODAV END FROM ORDEMSERVICO
    ORDER BY NRODAV DESC
    INTO :VULTIMONRODAV;

    VNRODAV= '';
    VPADRAO  = '_____________';
    VNRODAV= CAST((:VULTIMONRODAV+1) AS INTEGER);
    WHILE (NOT :VNRODAV LIKE VPADRAO) DO VNRODAV = '0' || :VNRODAV;
    -- INSERIR NA OS
    INSERT INTO ORDEMSERVICO (CHAVE, ATIVO, CHAVEEMPRESA, ORDEM, DATA, DATAFECHA, TIPO,
        SITUACAO, CHAVECLIFOR, CHAVEEQUIPAMENTO, PROBLEMAABERTURAOS,
        OBS,
        TOTALPRODUTO, TOTALSERVICO, TOTALOS, NL, FRETE, KMATUAL, CHAVETABELADESCONTOS,
        TOTALIPI, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD, CHAVECFOPSERV, CHAVEDOCDESTINO, DOCDESTINO,
        NROCCF, NRODAV, KMFINAL, CHAVEUSUARIOINICIOU, CHAVEUSUARIOFECHOU, CONTATO, HORAFECHAMENTO, HORAABERTURA,
        NROCOO, CHAVEECFDOCNFISCAL, NROCAIXA, CHAVESITUACAOOS,
        CHAVETIPOATENDIMENTO, AGRUPADO, MARCAMODELO, NUMSERIE, DATAENTREGA, VLRACRESCIMO,
        CHAVERESPENTREGA, HORAENTREGA, CHAVESITENTREGA, CHAVEPLANOCONTA, CHAVECENTROCUSTO,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, TIPOPAGAMENTO, CHAVECONDPGTO, FATURA, DESCPORCPROD, DESCVLRPROD,
        DESCPORCSERVICO, DESCVLRSERVICO, ACRESCPORCPROD, ACRESCVLRPROD, CHAVEUSUARIOAUTORDESCPROD,
        CHAVEUSUARIOAUTORDESCSERV, TIPOSENHADESCPROD, TIPOSENHADESCSERV, ORIGEM, CHAVEDOCORIGEM)
    SELECT :VCHAVEGENOS, 1, :ECHAVEEMPOS, :VNROORDEM, (SELECT CURRENT_DATE FROM RDB$DATABASE), NULL, 0,
        0, AG.CHAVECLIFOR, 0, AG.DESCRICAO,
        AG.OBS,
        0, 0, 0, :ENLATUAL, 0, 0, 0,
        0, 0, 0, 0, 0, NULL,
        '', :VNRODAV, 0, :ECHAVEUSUARIO, NULL, '', NULL, (SELECT CURRENT_TIME FROM RDB$DATABASE),
        '', NULL, '', (SELECT CHAVE FROM TABELAS WHERE (CHAVETABELA=15) AND (CODIGO='000001')),
        0, 'N', '', '', NULL, 0,
        0, NULL, (SELECT CHAVE FROM TABELAS WHERE (CHAVETABELA=20) AND (CODIGO='000001')), 0, 0,
        0, 0, 0, 0, '', 0, NULL,
        0, 0, 0, 0, NULL,
        NULL, NULL, NULL, 2, :ECHAVEAGENDA
    FROM OSAGENDA AG
    INNER JOIN CLIFOR C ON (C.CHAVE=AG.CHAVECLIFOR)
    WHERE (AG.CHAVE=:ECHAVEAGENDA);

    SELECT
        C.PESSOA,
        C.IERG,
        CID.UF
    FROM OSAGENDA AG
    INNER JOIN CLIFOR C ON (C.CHAVE=AG.CHAVECLIFOR)
    INNER JOIN CIDADE CID ON (C.CHAVECIDADE=CID.CHAVE)
    WHERE (AG.CHAVE=:ECHAVEAGENDA)
    INTO :VPESSOA, :VIERG, :VUFCLI;
    IF ((:VPESSOA = 0) AND (:VIERG IN ('ISENTO',''))) THEN BEGIN
        VPESSOA = 1;
        VUFCLI = :EUFEMPRESALOG;
    END

    -- INSERE PRODUTOS
    VTOTALPROD = 0;
    FOR SELECT P.CHAVE, GF.CHAVETRIBUTACAO, PV.PRECOVENDA,
        P.CHAVEUNIDADE, U.UNMAIOR, P.DESCRICAO, GF.IPI, GF.VLRIPITRIB,
        (SELECT FIRST 1 (CASE WHEN :VUFCLI=:EUFEMPRESALOG THEN OPE.CHAVECFOPPRODDE ELSE CASE WHEN :VUFCLI<>'EX' THEN OPE.CHAVECFOPPRODFE ELSE OPE.CHAVECFOPEXPIMP END END) FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='002')),
        PC.PRECOCUSTO, COALESCE(CF.COMISPRODUTO, 0), P.CODIGO, CF.CHAVECLIFOR
    FROM OSAGENDAITENS I
    INNER JOIN OSAGENDA AG ON (AG.CHAVE=I.CHAVEAGENDA)
    LEFT JOIN CLIFORCFGCOMISFAT CF ON (CF.CHAVECLIFOR=(SELECT FIRST 1 CASE WHEN COALESCE(COUNT(USU.CHAVEREPRCHMOB),0) = 1 THEN USU.CHAVEREPRCHMOB ELSE 0 END FROM OSAGENDAUSUARIOS OSUSU
                                                       INNER JOIN USUARIOS USU ON USU.CHAVE = OSUSU.CHAVEUSUARIO
                                                       WHERE (OSUSU.ATIVO=1) AND (OSUSU.CHAVEOSAGENDA=:ECHAVEAGENDA)
                                                       GROUP BY USU.CHAVEREPRCHMOB
                                                       HAVING USU.CHAVEREPRCHMOB > 0))
    INNER JOIN CLIFOR C ON (C.CHAVE=AG.CHAVECLIFOR)
    INNER JOIN PRODUTO P ON (P.CHAVE=I.CHAVEPRODUTO) AND (P.TIPO<>9)
    LEFT JOIN UNIDADE U ON (U.CHAVE=P.CHAVEUNIDADE)
    LEFT JOIN GRUPOFISCAL GF ON (GF.CHAVE=(CASE :VPESSOA WHEN 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END))
    LEFT JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
    LEFT JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:ECHAVEEMPVENDA) AND (PV.CHAVETABELAPRECO=:ECHAVETABELAPRECO) AND (PV.ATIVO=1)
    WHERE (I.ATIVO=1)
    AND (AG.CHAVE=:ECHAVEAGENDA)
    INTO :VCHAVEPRODUTO, :VCHAVETRIBUTACAO, :VPRECOVENDA,
        :VCHAVEUNIDADE, :VUNIDADE, :VDESCRPROD, :VIPI, :VVLRIPITRIB,
        :VCHAVECFOP,
        :VPRECOCUSTO, :VCOMISPRODUTO, :VCODIGOPROD, :VCHAVEVENDEDOR
    DO BEGIN
        VCHAVEOPERPROD = 0;
        SELECT FIRST 1 CF.CHAVE
        FROM CFOPOPERFISCAIS CF
        WHERE (CF.ATIVO=1)
        AND ((CF.CHAVECFOPPRODDE = :VCHAVECFOP) OR (CF.CHAVECFOPPRODFE = :VCHAVECFOP))
        AND (CF.CHAVECFOPSERVDE IS NULL) OR (CF.CHAVECFOPSERVFE IS NULL)
        ORDER BY CF.CHAVE
        INTO :VCHAVEOPERPROD;
        IF ((VCHAVEOPERPROD=0) OR (VCHAVEOPERPROD IS NULL))   THEN
            VCHAVEOPERPROD=:VCHAVEOPERPROD;
        INSERT INTO ITENSORDEMSERVICOPROD
            (ATIVO, CHAVEEMPRESA, CHAVEOS, CHAVEPRODUTO, CHAVETRIBUTACAO, QTDE, VLRUNIT,
            DESCPORC, DESCVLR, DATA, CHAVEUNIDADE, UN, VLRTOTAL, NL, PRODUTO, IPI, VLRIPI,
            CHAVECFOP, CHAVECFOPOPERFISCAIS, DESCRCOMPLEMENT, PRECOCUSTO, CHAVEVENDEDOR,
            ALIQCOMISFAT, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, VLRUNITTABELA, VLRVENDAMINIMO,
            CHAVELOTEPROD, CODPRODUTO, NUMITEM, ACRESCVLR, CODVENDACF, CHAVEDPTOESTOQUE,
            VLRACRESCGLOBAL, NRODAV, VLRSUBTOTAL, CHAVETABELAPRECO)
        VALUES
            (1, :ECHAVEEMPOS, :VCHAVEGENOS, :VCHAVEPRODUTO, :VCHAVETRIBUTACAO, 1, :VPRECOVENDA,
            0, 0, 'NOW', :VCHAVEUNIDADE, :VUNIDADE, :VPRECOVENDA, :ENLATUAL, :VDESCRPROD, :VIPI, :VVLRIPITRIB,
            :VCHAVECFOP, :VCHAVEOPERPROD, '', :VPRECOCUSTO, :VCHAVEVENDEDOR,
            :VCOMISPRODUTO, 0, NULL, :VPRECOVENDA, 0,
            0, :VCODIGOPROD, 1, 0, NULL, :ECHAVEDPTOESTOQUE,
            0, :VNRODAV, :VPRECOVENDA, :ECHAVETABELAPRECO);
        VTOTALPROD = :VTOTALPROD + :VPRECOVENDA;
    END

    VTOTALSERV = 0;
    -- INSERE SERVICOS
    FOR SELECT P.CHAVE, P.CODIGO, P.DESCRICAO,
        P.CHAVEUNIDADE, U.UNMAIOR, PV.PRECOVENDA,
        PC.PRECOCUSTO, COALESCE(CF.COMISSERVICO, 0),
        (SELECT FIRST 1 (CASE WHEN :VUFCLI=:EUFEMPRESALOG THEN OPE.CHAVECFOPSERVDE ELSE CASE WHEN :VUFCLI<>'EX' THEN OPE.CHAVECFOPSERVFE ELSE OPE.CHAVECFOPSERVEXPIMP END END) FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='004')),
        CF.CHAVECLIFOR
    FROM OSAGENDAITENS I
    INNER JOIN OSAGENDA AG ON (AG.CHAVE=I.CHAVEAGENDA)
    LEFT JOIN CLIFORCFGCOMISFAT CF ON (CF.CHAVECLIFOR=(SELECT FIRST 1 CASE WHEN COALESCE(COUNT(USU.CHAVEREPRCHMOB),0) = 1 THEN USU.CHAVEREPRCHMOB ELSE 0 END FROM OSAGENDAUSUARIOS OSUSU
                                                       INNER JOIN USUARIOS USU ON USU.CHAVE = OSUSU.CHAVEUSUARIO
                                                       WHERE (OSUSU.ATIVO=1) AND (OSUSU.CHAVEOSAGENDA=:ECHAVEAGENDA)
                                                       GROUP BY USU.CHAVEREPRCHMOB
                                                       HAVING USU.CHAVEREPRCHMOB > 0))
    INNER JOIN CLIFOR C ON (C.CHAVE=AG.CHAVECLIFOR)
    INNER JOIN PRODUTO P ON (P.CHAVE=I.CHAVEPRODUTO) AND (P.TIPO=9)
    LEFT JOIN UNIDADE U ON (U.CHAVE=P.CHAVEUNIDADE)
    LEFT JOIN GRUPOFISCAL GF ON (GF.CHAVE=(CASE :VPESSOA WHEN 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END))
    LEFT JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
    LEFT JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:ECHAVEEMPVENDA) AND (PV.CHAVETABELAPRECO=:ECHAVETABELAPRECO) AND (PV.ATIVO=1)
    WHERE (AG.ATIVO=1)
    AND (AG.CHAVE=:ECHAVEAGENDA)
    INTO :VCHAVEPRODUTO, :VCODIGOPROD, :VDESCRPROD,
        :VCHAVEUNIDADE, :VUNIDADE, :VPRECOVENDA,
        :VPRECOCUSTO, :VCOMISPRODUTO,
        :VCHAVECFOP,
        :VCHAVEVENDEDOR
    DO BEGIN
        VCHAVEOPERSERV = 0;
        SELECT FIRST 1
            CF.CHAVE
        FROM CFOPOPERFISCAIS CF
        WHERE (CF.ATIVO=1)
        AND (CF.CHAVECFOPSERVDE = :VCHAVECFOP) OR (CF.CHAVECFOPSERVFE = :VCHAVECFOP)
        AND (CF.CHAVECFOPPRODDE IS NULL) OR (CF.CHAVECFOPPRODFE IS NULL)
        ORDER BY CF.CHAVE
        INTO :VCHAVEOPERSERV;
        IF ((:VCHAVEOPERSERV=0) OR (:VCHAVEOPERSERV IS NULL))   THEN
            VCHAVEOPERSERV =:VCHAVEOPERSERV;

        INSERT INTO ITENSORDEMSERVICOSERV
            (ATIVO, CHAVEEMPRESA, CHAVEOS, CHAVEPRODUTO, CODPRODUTO, PRODUTO,
            CHAVEUNIDADE, UN, QTDE, VLRUNIT, DESCPORC, DESCVLR, DATA, VLRSUBTOTAL,
            VLRTOTAL, ISS, NL, CHAVECFOP,
            CHAVECFOPOPERFISCAIS, DESCRCOMPLEMENT, PRECOCUSTO, CHAVEVENDEDOR,
            ALIQCOMISFAT, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, NUMITEM,
            ACRESCVLR, VLRUNITTABELA, CHAVETABELAPRECO)
        VALUES
            (1, :ECHAVEEMPOS, :VCHAVEGENOS, :VCHAVEPRODUTO, :VCODIGOPROD, :VDESCRPROD,
            :VCHAVEUNIDADE, :VUNIDADE, 1, :VPRECOVENDA, 0, 0, 'NOW', :VPRECOVENDA,
            :VPRECOVENDA, 0, :ENLATUAL, :VCHAVECFOP,
            :VCHAVEOPERSERV, '', :VPRECOCUSTO, :VCHAVEVENDEDOR,
            :VCOMISPRODUTO, 0, NULL, 1,
            0, :VPRECOVENDA, :ECHAVETABELAPRECO);
        VTOTALSERV = :VTOTALSERV + :VPRECOVENDA;
    END

    -- INSERE SE TIVER APENAS UM REPRESENTANTE
    IF ((SELECT coalesce(COUNT(OU.CHAVE),0) FROM OSAGENDAUSUARIOS OU
        INNER JOIN USUARIOS U ON U.CHAVE = OU.CHAVEUSUARIO
        WHERE (OU.ATIVO=1) AND (OU.CHAVEOSAGENDA=:ECHAVEAGENDA) AND (COALESCE(U.CHAVEREPRCHMOB,0)>0)) = 1) THEN BEGIN
        INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
            COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
            COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
        SELECT AG.CHAVEEMPRESA, :VCHAVEGENOS, U.CHAVEREPRCHMOB, 4, :ENLATUAL, CF.TIPOCOMISSAO,
            CF.COMISSAOGERADA, CF.COMISPRODUTO, CF.COMISPRODEMISSAO, CF.COMISPRODBAIXA,
            CF.COMISSERVICO, CF.COMISSERVEMISSAO, CF.COMISSERVBAIXA, 0
        FROM OSAGENDA AG
        INNER JOIN OSAGENDAUSUARIOS OU ON (OU.CHAVEOSAGENDA=:ECHAVEAGENDA) AND (OU.ATIVO=1)
        INNER JOIN USUARIOS U ON U.CHAVE = OU.CHAVEUSUARIO
        LEFT JOIN CLIFORCFGCOMISFAT CF ON (CF.CHAVE=U.CHAVEREPRCHMOB) AND (CF.ATIVO=1)
        WHERE (AG.CHAVE=:ECHAVEAGENDA);
    END

    UPDATE ORDEMSERVICO SET
        TOTALPRODUTO=(:VTOTALPROD),
        TOTALSERVICO=(:VTOTALSERV),
        TOTALOS=(:VTOTALPROD + :VTOTALSERV)
    WHERE CHAVE=:VCHAVEGENOS;

    SNROOSNOVO = :VNROORDEM;
   SUSPEND;
END^


ALTER PROCEDURE GERAROSAGENDAPETSHOP (
    ECHAVEAGENDA INTEGER,
    ECHAVEEMPOS INTEGER,
    ECHAVEUSUARIO INTEGER,
    ECHAVEEMPCUSTO INTEGER,
    EUFEMPRESALOG VARCHAR(2),
    ENLATUAL DOUBLE PRECISION,
    ECHAVEDPTOESTOQUE INTEGER,
    ECHAVETABELAPRECO INTEGER)
RETURNS (
    SNROOSNOVO VARCHAR(10))
AS
declare variable VCHAVEGENOS integer;
declare variable VCHAVEDPTOESTOQUE integer;
declare variable VVLRMOVIMENTACAO numeric(18,6);
declare variable VMOVESTOQUE integer;
declare variable VNL double precision;
declare variable VCHAVEUSUARIO integer;
declare variable VCHAVEOS integer;
declare variable VTIPOMOVIMENTACAO integer;
declare variable VDATA date;
declare variable VCONVERSAO numeric(18,6);
declare variable VPRECOCUSTO numeric(18,6);
declare variable VCODPROD varchar(20);
declare variable VCHAVELOTEPROD integer;
declare variable VQUANT numeric(18,6);
declare variable VAGRUPADOCOMPOSTO integer;
declare variable VNROORDEM varchar(10);
declare variable VCHAVECLIFOR integer;
declare variable VCHAVEPROD integer;
declare variable VCHAVEITEM integer;
declare variable VPADRAO varchar(20);
declare variable VULTIMONRODAV varchar(20);
declare variable VNRODAV varchar(20);
declare variable VVACINACOMPROD char(1);
declare variable VCHAVEEMPCUSTO integer;
declare variable VTIPO integer;
declare variable VTIPOSERVANIMALERP integer;
BEGIN
    SNROOSNOVO = '';

    SELECT CASE WHEN COALESCE(P.CHAVEPRODUTO,0)>0 THEN 'S' ELSE 'N' END,
        AG.TIPO, AG.TIPOSERVANIMALERP
    FROM OSPETSHOPAGENDA AG
    LEFT JOIN OSPETSHOPPROCEDIMENTOS P ON (P.CHAVE=AG.CHAVEPROCEDIMENTO)
    WHERE
    (AG.ATIVO=1)
    AND (AG.CHAVE=:ECHAVEAGENDA)
    INTO :VVACINACOMPROD, :VTIPO, :VTIPOSERVANIMALERP;

    -- GERA DAV QUANDO (FOR VACINA E TIVER PRODUTO ASSOCIADO) OU (QUANDO DIFERENTE DE PROCEDIMENTO)
    IF (((:VTIPO = 3) AND (:VVACINACOMPROD='S')) OR ((:VTIPO <> 3))) THEN BEGIN
        VCHAVEGENOS = GEN_ID(GEN_ORDEMSERVICO_ID,1);
    
        VNROORDEM= '';
        VPADRAO  = '______';
        VNROORDEM= CAST(:VCHAVEGENOS AS INTEGER);
        WHILE (NOT :VNROORDEM LIKE VPADRAO) DO VNROORDEM = '0' || :VNROORDEM;
    
        VULTIMONRODAV = COALESCE((SELECT MAX(NRODAV) FROM ORDEMSERVICO),'0');
    
        IF (VULTIMONRODAV = '') THEN
            VULTIMONRODAV = '0';
        VNRODAV= '';
        VPADRAO  = '_____________';
        VNRODAV= (CAST(:VULTIMONRODAV AS INTEGER)+1) ;
        WHILE (NOT :VNRODAV LIKE VPADRAO) DO VNRODAV = '0' || :VNRODAV;
        -- INSERIR NA OS
        INSERT INTO ORDEMSERVICO (CHAVE, ATIVO, CHAVEEMPRESA, ORDEM, DATA, DATAFECHA, TIPO,
            SITUACAO, CHAVECLIFOR,
            OBS,
            TOTALPRODUTO, TOTALSERVICO, TOTALOS, NL, FRETE, KMATUAL, CHAVETABELADESCONTOS,
            TOTALIPI, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD, CHAVECFOPSERV, CHAVEDOCDESTINO, DOCDESTINO,
            NROCCF, NRODAV, KMFINAL, CHAVEUSUARIOINICIOU, CHAVEUSUARIOFECHOU, CONTATO, HORAFECHAMENTO, HORAABERTURA,
            NROCOO, CHAVEECFDOCNFISCAL, NROCAIXA, CHAVESITUACAOOS,
            CHAVETIPOATENDIMENTO, AGRUPADO, MARCAMODELO, NUMSERIE, DATAENTREGA, VLRACRESCIMO,
            CHAVERESPENTREGA, HORAENTREGA, CHAVESITENTREGA, CHAVEPLANOCONTA, CHAVECENTROCUSTO,
            CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, TIPOPAGAMENTO, CHAVECONDPGTO, FATURA, DESCPORCPROD, DESCVLRPROD,
            DESCPORCSERVICO, DESCVLRSERVICO, ACRESCPORCPROD, ACRESCVLRPROD,
            ORIGEM, CHAVEDOCORIGEM, FORMAPGTO, CHAVEEQUIPAMENTO, CHAVEANIMAL)
        SELECT :VCHAVEGENOS, 1, :ECHAVEEMPOS, :VNROORDEM, (SELECT CURRENT_DATE FROM RDB$DATABASE), NULL, 0,
            0, A.CHAVECLIFOR,
            CASE COALESCE(AG.OBS,'') WHEN '' THEN 'ANIMAL:'|| A.CODIGO||' - '||A.NOME ELSE SUBSTRING(AG.OBS FROM 1 FOR 880)||'   ANIMAL:'|| A.CODIGO||' - '||A.NOME END,
            0, AG.VLRUNIT, AG.VLRUNIT, :ENLATUAL, 0, 0, 0,
            0, 0, 0, 0, 0, NULL,
            '', :VNRODAV, 0, :ECHAVEUSUARIO, NULL, '', NULL, (SELECT CURRENT_TIME FROM RDB$DATABASE),
            '', NULL, '', (SELECT CHAVE FROM TABELAS WHERE (CHAVETABELA=15) AND (CODIGO='000001')),
            0, 'N', '', '', NULL, 0,
            0, NULL, (SELECT CHAVE FROM TABELAS WHERE (CHAVETABELA=20) AND (CODIGO='000001')), 0, 0,
            0, 0, 0, 0, '', 0, NULL,
            0, 0, 0, 0,
            1, :ECHAVEAGENDA,0, AG.CHAVEVETERINARIO, AG.chaveanimal
        FROM OSPETSHOPAGENDA AG
        INNER JOIN OSPETSHOPANIMAIS A ON (A.CHAVE=AG.CHAVEANIMAL)
        INNER JOIN CLIFOR C ON (C.CHAVE=A.CHAVECLIFOR)
        WHERE (AG.CHAVE=:ECHAVEAGENDA);
    
        IF (:VVACINACOMPROD = 'N') THEN BEGIN
            INSERT INTO ITENSORDEMSERVICOSERV
                (ATIVO, CHAVEEMPRESA, CHAVEOS, CHAVEPRODUTO, CODPRODUTO, PRODUTO,
                CHAVEUNIDADE, UN, QTDE, VLRUNIT, DESCPORC, DESCVLR, DATA, VLRSUBTOTAL,
                VLRTOTAL, ISS, NL, CHAVECFOP,
                CHAVECFOPOPERFISCAIS,
                DESCRCOMPLEMENT, PRECOCUSTO, CHAVEVENDEDOR, ALIQCOMISFAT, TIPOSENHADESC,
                CHAVEUSUARIOAUTORDESC, NUMITEM, ACRESCVLR, VLRUNITTABELA, CHAVETABELAPRECO)
            SELECT 1, :ECHAVEEMPOS, :VCHAVEGENOS, P.CHAVE, P.CODIGO, P.DESCRICAO,
                (SELECT FIRST 1 U.CHAVE FROM UNIDADE U WHERE (U.ATIVO=1) AND (U.UNMAIOR='UN')), 'UN', 1, AG.VLRUNIT, 0, 0, (SELECT CURRENT_DATE FROM RDB$DATABASE), AG.VLRUNIT,
                AG.VLRUNIT, 0, :ENLATUAL,
                (SELECT FIRST 1 (CASE WHEN CID.UF=:EUFEMPRESALOG THEN OPE.CHAVECFOPSERVDE ELSE CASE WHEN CID.UF<>'EX' THEN OPE.CHAVECFOPSERVFE ELSE OPE.CHAVECFOPSERVEXPIMP END END) FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='004')),
                (SELECT FIRST 1 CHAVE FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='004')),
                '', PC.PRECOCUSTO, AG.CHAVEVENDEDOR, V.COMISSERVICO, 0,
                0, 1, 0, AG.VLRUNIT, :ECHAVETABELAPRECO
            FROM OSPETSHOPAGENDA AG
            INNER JOIN CLIFOR C ON (C.CHAVE=AG.CHAVECLIFOR)
            INNER JOIN CIDADE CID ON (CID.CHAVE=C.CHAVECIDADE)
            LEFT JOIN OSPETSHOPSERVICOS OS ON (OS.CHAVE=AG.CHAVESERVICO)
            INNER JOIN PRODUTO P ON (P.CHAVE=(CASE :VTIPOSERVANIMALERP WHEN 0 THEN OS.CHAVEPRODUTO WHEN 1 THEN AG.CHAVESERVICO END))
            INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
            LEFT JOIN CLIFORCFGCOMISFAT V ON (V.CHAVECLIFOR=AG.CHAVEVENDEDOR)
            WHERE (AG.ATIVO=1)
            AND (AG.CHAVE=:ECHAVEAGENDA);
        END ELSE BEGIN
            VCHAVEITEM = GEN_ID(GEN_ITENSORDEMSERVICOPROD_ID,1);
            INSERT INTO ITENSORDEMSERVICOPROD
                (CHAVE, ATIVO, CHAVEEMPRESA, CHAVEOS, CHAVEPRODUTO, CHAVETRIBUTACAO,
                QTDE, VLRUNIT, DESCPORC, DESCVLR,
                DATA, CHAVEUNIDADE, UN,
                VLRSUBTOTAL, VLRTOTAL, NL, PRODUTO, IPI,
                VLRIPI,
                CHAVECFOP,
                CHAVECFOPOPERFISCAIS,
                DESCRCOMPLEMENT, PRECOCUSTO, CHAVEVENDEDOR, ALIQCOMISFAT,
                TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, VLRUNITTABELA, VLRVENDAMINIMO, CHAVELOTEPROD,
                CODPRODUTO, NUMITEM, ACRESCVLR, CHAVEDPTOESTOQUE, VLRACRESCGLOBAL,
                NRODAV,
                ALIQICMSINTRA,
                ICMS,
                QTDERETORNO,
                MOVESTOQUE,
                CHAVETABELAPRECO)
            SELECT :VCHAVEITEM, 1, :ECHAVEEMPOS, :VCHAVEGENOS, P.CHAVE, CASE WHEN C.PESSOA=0 THEN GF.CHAVETRIBUTACAO ELSE GF.CHAVETRIBUTACAO END,
                PR.QTDE, AG.VLRUNIT, 0, 0,
                CURRENT_DATE, UN.CHAVE, UN.UNMAIOR,
                (AG.VLRUNIT*PR.QTDE), (AG.VLRUNIT*PR.QTDE), :ENLATUAL, P.DESCRICAO, CASE WHEN C.PESSOA=0 THEN GF.IPI ELSE GF.IPI END,
                ((AG.VLRUNIT*PR.QTDE) * (CASE WHEN C.PESSOA=0 THEN GF.IPI ELSE GF.IPI END))/100,
                CASE WHEN COALESCE(GF.CHAVECFOPOPERFISCAIS,0) > 0 THEN
                ((SELECT FIRST 1 (CASE WHEN CID.UF=:EUFEMPRESALOG THEN OPE.CHAVECFOPPRODDE ELSE OPE.CHAVECFOPPRODFE END) FROM CFOPOPERFISCAIS OPE WHERE (OPE.CHAVE=GF.CHAVECFOPOPERFISCAIS)))
                ELSE (SELECT FIRST 1 (CASE WHEN CID.UF=:EUFEMPRESALOG THEN OPE.CHAVECFOPPRODDE ELSE OPE.CHAVECFOPPRODFE END) FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='001')) END,
                CASE WHEN COALESCE(GF.CHAVECFOPOPERFISCAIS,0) > 0 THEN GF.CHAVECFOPOPERFISCAIS
                ELSE (SELECT FIRST 1 CHAVE FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='001')) END,
                '', PC.PRECOCUSTO, AG.CHAVEVENDEDOR, V.COMISPRODUTO,
                0, 0, AG.VLRUNIT, 0, NULL,
                P.CODIGO, 1, 0, :ECHAVEDPTOESTOQUE, 0,
                NULL,
                T.ALIQUOTADE,
                CASE WHEN  (CID.UF=:EUFEMPRESALOG) OR (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('40','41','50','51','90','20')) THEN T.ALIQUOTADE ELSE
                CASE WHEN SUBSTRING(T.CODIGO FROM 1 FOR 1) IN ('1','2','3','8') THEN 4 ELSE (SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU WHERE TU.ORIGEM=:EUFEMPRESALOG AND TU.DESTINO=CID.UF)
                END END,
                1,
                CASE WHEN COALESCE(GF.CHAVECFOPOPERFISCAIS,0) > 0 THEN (SELECT FIRST 1 MOVESTOQUE FROM CFOPOPERFISCAIS OPE WHERE (OPE.CHAVE=COALESCE(GF.CHAVECFOPOPERFISCAIS,0)))
                ELSE (SELECT FIRST 1 MOVESTOQUE FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='001')) END,
                :ECHAVETABELAPRECO
            FROM OSPETSHOPAGENDA AG
            INNER JOIN CLIFOR C ON (C.CHAVE=AG.CHAVECLIFOR)
            INNER JOIN CIDADE CID ON (CID.CHAVE=C.CHAVECIDADE)
            INNER JOIN OSPETSHOPPROCEDIMENTOS PR ON (PR.CHAVE=AG.CHAVEPROCEDIMENTO)
            INNER JOIN PRODUTO P ON (P.CHAVE=PR.CHAVEPRODUTO)
            INNER JOIN UNIDADE UN ON (UN.CHAVE=P.CHAVEUNIDADE)
            INNER JOIN GRUPOFISCAL GF ON (GF.CHAVE=CASE WHEN C.PESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END)
            INNER JOIN TRIBUTACAO T ON (T.CHAVE=GF.CHAVETRIBUTACAO)
            INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
            LEFT JOIN CLIFORCFGCOMISFAT V ON (V.CHAVECLIFOR=AG.CHAVEVENDEDOR)
            WHERE (AG.ATIVO=1)
            AND (AG.CHAVE=:ECHAVEAGENDA);

            SELECT NF.CHAVECLIFOR, I.CHAVEPRODUTO, I.CODPRODUTO, I.QTDE, I.CHAVELOTEPROD,
            P.AGRUPADOCOMPOSTO, UN.CONVERSAO,
            I.PRECOCUSTO, NF.DATA, CF.TIPOMOVIMENTACAO,
            I.CHAVEDPTOESTOQUE, I.VLRUNIT, NF.CHAVE AS CHAVEOS, NF.CHAVEUSUARIOINICIOU,
            NF.NL AS NL, UN.CONVERSAO, PC.CHAVEEMPRESA, I.movestoque
            FROM ITENSORDEMSERVICOPROD I
            INNER JOIN CFOPOPERFISCAIS CF ON I.CHAVECFOPOPERFISCAIS=CF.CHAVE
            INNER JOIN PRODUTO P ON I.CHAVEPRODUTO=P.CHAVE
            INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO = P.CHAVE AND PC.CHAVEEMPRESA = :ECHAVEEMPCUSTO
            INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
            INNER JOIN ORDEMSERVICO NF ON NF.CHAVE=I.CHAVEOS
            WHERE (I.ATIVO=1) AND (I.CHAVE=:VCHAVEITEM)
            AND (P.TIPO<>9) -- BAIXAR ESTOQUE EXCETO SERVICO
            INTO :VCHAVECLIFOR, :VCHAVEPROD, :VCODPROD, :VQUANT, :VCHAVELOTEPROD,
            :VAGRUPADOCOMPOSTO, :VCONVERSAO,
            :VPRECOCUSTO, :VDATA, :VTIPOMOVIMENTACAO,
            :VCHAVEDPTOESTOQUE, :VVLRMOVIMENTACAO, :VCHAVEOS, :VCHAVEUSUARIO, :VNL, :VCONVERSAO, :VCHAVEEMPCUSTO, :VMOVESTOQUE;
            IF (:VMOVESTOQUE = 0) THEN BEGIN
                EXECUTE PROCEDURE ESTENTRADASAIDAESTOQUE(:VCHAVEPROD, :VCHAVELOTEPROD,
                    :VQUANT*(-1), 0, :VAGRUPADOCOMPOSTO,
                    (SELECT COALESCE(CHAVEEMPRESAREF,:ECHAVEEMPOS) FROM CONFIGCOMPART WHERE (TABELA = 'PRODUTOESTOQUE')
                    AND (ATIVO=1) AND (CHAVEEMPRESA=:ECHAVEEMPOS)), :VCHAVEEMPCUSTO,
                    :VCHAVEUSUARIO, :VCHAVEOS, :VNL, '', 13,
                    '', :VCODPROD, :VCONVERSAO, :VDATA, :VPRECOCUSTO, :VCHAVEITEM,
                    :VCHAVECLIFOR, :VTIPOMOVIMENTACAO, 0, :VCHAVEDPTOESTOQUE, :VVLRMOVIMENTACAO);


           END
        END
    
        INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
        COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
        COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
        SELECT AG.CHAVEEMPRESA, :VCHAVEGENOS, AG.CHAVEVENDEDOR, 4, :ENLATUAL, CF.TIPOCOMISSAO,
        CF.COMISSAOGERADA, CF.COMISPRODUTO, CF.COMISPRODEMISSAO, CF.COMISPRODBAIXA,
        CF.COMISSERVICO, CF.COMISSERVEMISSAO, CF.COMISSERVBAIXA, 0
        FROM OSPETSHOPAGENDA AG
        INNER JOIN CLIFOR V ON AG.CHAVEVENDEDOR=V.CHAVE
        LEFT JOIN CLIFORCFGCOMISFAT CF ON (V.CHAVE=AG.CHAVEVENDEDOR)
        WHERE (AG.CHAVE=:ECHAVEAGENDA);
    
        SNROOSNOVO = :VNROORDEM;
    END
   SUSPEND;
END^


ALTER PROCEDURE GERARPARCELASCONDPGTO (
    ECHAVEDOC INTEGER,
    ENL DOUBLE PRECISION,
    EORIGEM INTEGER,
    EFATURA VARCHAR(4000),
    ECHAVEEMPRESA INTEGER)
AS
declare variable VULTIMAPOS integer;
declare variable VPROXPOS integer;
declare variable VLINHA integer;
declare variable VTEMP varchar(1000);
declare variable VDOC varchar(10);
declare variable VPARC integer;
declare variable VVENC date;
declare variable VVALOR numeric(18,6);
begin
    if (:EFATURA <> '') then BEGIN
        EFATURA = :EFATURA || ASCII_CHAR(10);
        VULTIMAPOS = 1;
        VPROXPOS = position(ASCII_CHAR(10), :EFATURA, :VULTIMAPOS);
        VLINHA = 1;
        WHILE (:VPROXPOS > 1) do BEGIN
            VTEMP = substring(:EFATURA from :VULTIMAPOS for :VPROXPOS - :VULTIMAPOS);
            VTEMP = replace(:VTEMP, ASCII_CHAR(13), '');
            if ((:VLINHA > 1) AND (TRIM(:VTEMP) <> '')) then BEGIN
                VDOC = TRIM(substring(:VTEMP from 1 for 10));
                VPARC = CAST(TRIM(substring(:VTEMP from 16 for 4)) AS INTEGER);
                VVENC = CAST(TRIM(REPLACE(substring(:VTEMP from 27 for 12), '/', '.')) AS DATE);
                VVALOR = CAST(TRIM(REPLACE(REPLACE(substring(:VTEMP from 44 for 20), '.', ''), ',', '.')) AS NUMERIC(18,2));
                INSERT INTO CONDPGTODOCS(CHAVEEMPRESA, ORIGEM, CHAVEDOC, DOCUMENTO, PARCELA, VENCIMENTO, VALOR, NL)
                VALUES (:ECHAVEEMPRESA, :EORIGEM, :ECHAVEDOC, :VDOC, :VPARC, :VVENC, :VVALOR, :ENL);
            END
            VULTIMAPOS = :VPROXPOS + 1;
            VPROXPOS = position(ASCII_CHAR(10), :EFATURA, :VULTIMAPOS);
            VLINHA = :VLINHA + 1;
        end
    END
end^


ALTER PROCEDURE GERARPONTUACAOCLIENTE (
    ACAO SMALLINT,
    CHAVEDOC INTEGER,
    NLDOC DOUBLE PRECISION,
    CHAVERECEBER INTEGER)
AS
BEGIN
    --INSERIR REGISTROS DE LIBERACAO DOS PONTOS BLOQUEADOS PARA O TITULO
    IF (:ACAO = 0) THEN BEGIN
        INSERT INTO PONTUACAO
        (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, DATA, VLRBASE, VLRREFERENCIA,
        OBS, CHAVEDOC, NL, CHAVERECEBER, PONTOSBLOQ, PONTOSMOV)
        SELECT F.ATIVO, F.CHAVEEMPRESA, F.CHAVECLIFOR, CURRENT_DATE, F.VLRBASE, F.VLRREFERENCIA,
        SUBSTRING('LIBERACAO - '||F.OBS FROM 1 FOR 100), F.CHAVEDOC, F.NL, F.CHAVERECEBER, 0, F.PONTOSBLOQ
        FROM PONTUACAO F
        WHERE (F.ATIVO=1) AND (F.NL=:NLDOC) AND (F.PONTOSBLOQ>0)
        AND (F.CHAVEDOC=COALESCE(:CHAVEDOC, 0)) AND (F.CHAVERECEBER=:CHAVERECEBER);

        UPDATE PONTUACAO F SET
        ATIVO=4
        WHERE (F.ATIVO=1) AND (F.NL=:NLDOC) AND (F.PONTOSBLOQ>0)
        AND (F.CHAVEDOC=CASE WHEN (:CHAVEDOC>=0) THEN :CHAVEDOC ELSE F.CHAVEDOC END)
        AND (F.CHAVERECEBER=CASE WHEN (:CHAVERECEBER>=0) THEN :CHAVERECEBER ELSE F.CHAVERECEBER END);

        EXIT;
    END
    --INSERIR REGISTROS DE ESTORNO DOS PONTOS JA LIBERADOS PARA O DOC
    IF (:ACAO = 1) THEN BEGIN
        INSERT INTO PONTUACAO
        (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, DATA, VLRBASE, VLRREFERENCIA,
        OBS, CHAVEDOC, NL, CHAVERECEBER, PONTOSBLOQ, PONTOSMOV)
        SELECT F.ATIVO, F.CHAVEEMPRESA, F.CHAVECLIFOR, CURRENT_DATE, F.VLRBASE, F.VLRREFERENCIA,
        SUBSTRING('CANCELAMENTO - '||F.OBS FROM 1 FOR 100), F.CHAVEDOC, F.NL, F.CHAVERECEBER, 0, F.PONTOSMOV * (-1)
        FROM PONTUACAO F
        WHERE (F.ATIVO=1) AND (F.NL=:NLDOC) AND (F.PONTOSMOV>0) AND (F.CHAVEDOC=COALESCE(:CHAVEDOC, 0));

        UPDATE PONTUACAO F SET
        ATIVO=3
        WHERE (F.ATIVO=1) AND (F.NL=:NLDOC) AND (F.PONTOSBLOQ>0)
        AND (F.CHAVEDOC=CASE WHEN (:CHAVEDOC>=0) THEN :CHAVEDOC ELSE F.CHAVEDOC END)
        AND (F.CHAVERECEBER=CASE WHEN (:CHAVERECEBER>=0) THEN :CHAVERECEBER ELSE F.CHAVERECEBER END);

        EXIT;
    END
    --ESTORNO DE TITULO
    IF (:ACAO = 2) THEN BEGIN
        --INSERIR REGISTRO PARA ESTORNAR OS PONTOS LIBERADOS NA BAIXA
        INSERT INTO PONTUACAO
        (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, DATA, VLRBASE, VLRREFERENCIA,
        OBS, CHAVEDOC, NL, CHAVERECEBER, PONTOSBLOQ, PONTOSMOV)
        SELECT FIRST 1 F.ATIVO, F.CHAVEEMPRESA, F.CHAVECLIFOR, CURRENT_DATE, F.VLRBASE, F.VLRREFERENCIA,
        SUBSTRING('EST. BAIXA - '||F.OBS FROM 1 FOR 100), F.CHAVEDOC, F.NL, F.CHAVERECEBER, 0, F.PONTOSMOV * (-1)
        FROM PONTUACAO F
        WHERE (F.ATIVO=1) AND (F.NL=:NLDOC) AND (F.PONTOSMOV>0)
        AND (F.CHAVEDOC=COALESCE(:CHAVEDOC, 0)) AND (F.CHAVERECEBER=:CHAVERECEBER)
        ORDER BY CHAVE DESC;

        --INSERIR REGISTRO DE PONTOS BLOQUEADOS PARA SER LIBERADO NA NOVA BAIXA
        INSERT INTO PONTUACAO
        (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, DATA, VLRBASE, VLRREFERENCIA,
        OBS, CHAVEDOC, NL, CHAVERECEBER, PONTOSBLOQ, PONTOSMOV)
        SELECT FIRST 1 F.ATIVO, F.CHAVEEMPRESA, F.CHAVECLIFOR, CURRENT_DATE, F.VLRBASE, F.VLRREFERENCIA,
        SUBSTRING('EST. BAIXA - '||F.OBS FROM 1 FOR 100), F.CHAVEDOC, F.NL, F.CHAVERECEBER, F.PONTOSMOV, 0
        FROM PONTUACAO F
        WHERE (F.ATIVO=1) AND (F.NL=:NLDOC) AND (F.PONTOSMOV>0)
        AND (F.CHAVEDOC=COALESCE(:CHAVEDOC, 0)) AND (F.CHAVERECEBER=:CHAVERECEBER)
        ORDER BY CHAVE DESC;

        EXIT;
    END

    --EXCLUSAO/CANCELAMENTO/AGRUPAMENTO DO TITULO
    IF (:ACAO = 3) THEN BEGIN
        UPDATE PONTUACAO F SET
        ATIVO=5
        WHERE (F.ATIVO=1) AND (F.NL=:NLDOC) AND (F.PONTOSBLOQ>0)
        AND (F.CHAVEDOC=CASE WHEN (:CHAVEDOC>=0) THEN :CHAVEDOC ELSE F.CHAVEDOC END)
        AND (F.CHAVERECEBER=CASE WHEN (:CHAVERECEBER>=0) THEN :CHAVERECEBER ELSE F.CHAVERECEBER END);

        EXIT;
    END

    --DESAGRUPAMENTO DE CONTAS
    IF (:ACAO = 4) THEN BEGIN
        INSERT INTO PONTUACAO
        (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, DATA, VLRBASE, VLRREFERENCIA,
        OBS, CHAVEDOC, NL, CHAVERECEBER, PONTOSBLOQ, PONTOSMOV)
        SELECT FIRST 1 1, F.CHAVEEMPRESA, F.CHAVECLIFOR, CURRENT_DATE, F.VLRBASE, F.VLRREFERENCIA,
        SUBSTRING('CONTA DESAG. - '||F.OBS FROM 1 FOR 100), F.CHAVEDOC, F.NL, F.CHAVERECEBER, F.PONTOSBLOQ, 0
        FROM PONTUACAO F
        WHERE (F.ATIVO<>1) AND (F.NL=:NLDOC) AND (F.PONTOSBLOQ>0)
        AND (F.CHAVEDOC=COALESCE(:CHAVEDOC, 0)) AND (F.CHAVERECEBER=:CHAVERECEBER)
        ORDER BY CHAVE DESC;
    END

    /*  CHAMADAS:
            - PROCEDURE CANCELACUPOM: USADA PARA ESTORNAR PONTOS DE CUPONS FISCAIS CANCELADOS
            - TRIGGER RECEBER_BI: USADA PARA NA BAIXA, ESTORNO, CANCELAMENTO E EXCLUSAO DE TITULOS*/
END^


ALTER PROCEDURE GERARPONTUACAODESMCONTA (
    CHAVERECEBER INTEGER,
    NOVACHAVERECEBER INTEGER,
    VLRDESMEMBRADO NUMERIC(18,2))
AS
BEGIN
    --GERAR NOVO REGISTRO DO VALOR DESMEMBRADO (ABERTO)
    INSERT INTO PONTUACAO
    (ATIVO, CHAVEEMPRESA, CHAVECLIFOR, DATA, VLRBASE, VLRREFERENCIA,
    OBS, CHAVEDOC, NL, CHAVERECEBER, PONTOSMOV,
    PONTOSBLOQ)
    SELECT FIRST 1 P.ATIVO, P.CHAVEEMPRESA, P.CHAVECLIFOR, CURRENT_DATE, :VLRDESMEMBRADO, P.VLRREFERENCIA,
    SUBSTRING('DESM. CONTA - '||P.OBS FROM 1 FOR 100), P.CHAVEDOC, P.NL, :NOVACHAVERECEBER, 0,
    CAST(:VLRDESMEMBRADO / P.VLRREFERENCIA AS NUMERIC(18,2))
    FROM PONTUACAO P
    WHERE (P.ATIVO=1) AND (P.PONTOSMOV>0)
    AND (P.CHAVERECEBER=:CHAVERECEBER)
    ORDER BY P.CHAVE DESC;

    --ALTERAR BASE E PONTOS DO REGISTRO ORIGINAL (BAIXADO)
    UPDATE PONTUACAO P SET
    P.VLRBASE = P.VLRBASE - :VLRDESMEMBRADO,
    P.PONTOSMOV = CAST((P.VLRBASE - :VLRDESMEMBRADO) / P.VLRREFERENCIA AS NUMERIC(18,2))
    WHERE (P.CHAVE=(SELECT MAX(P2.CHAVE) FROM PONTUACAO P2 WHERE (P2.ATIVO=1) AND (P2.PONTOSMOV>0)
    AND (P2.CHAVERECEBER=:CHAVERECEBER)));

    /*  CHAMADAS:
            - CONTAS A RECEBER: USADA PARA GERAR CORRETAMENTE A PONTUACAO AO DESMEMBRAR O TITULO*/
END^


ALTER PROCEDURE GERARPVAGENDAPETSHOP (
    ECHAVEEMPPROD INTEGER,
    ECHAVEEMPVENDA INTEGER,
    ECHAVEEMPCUSTO INTEGER,
    ECHAVEEMPPV INTEGER,
    ECHAVEAGENDA INTEGER,
    EUFEMPRESALOG CHAR(2),
    ENLATUAL DOUBLE PRECISION,
    ECODIGOREST VARCHAR(10),
    ECHAVETABELAPRECO INTEGER)
RETURNS (
    SCODIGORESTNOVO VARCHAR(10))
AS
declare variable VCHAVEGENPV integer;
declare variable VCODIGORESTNOVO varchar(20);
declare variable VNUMEROPVNOVO varchar(20);
BEGIN
    VCHAVEGENPV = GEN_ID(GEN_ORDEMSERVICO_ID,1);
    VCODIGORESTNOVO = :ECODIGOREST;
    IF (:VCODIGORESTNOVO = '') THEN BEGIN  /* SE CODIGO REST NA ENTRADA FOR BRANCO, MONTA O CODIGO REST */
        VCODIGORESTNOVO = COALESCE(SUBSTRING((SELECT MAX(CODIGOREST) FROM PREVENDA WHERE (CHAVEEMPRESA=:ECHAVEEMPPV))FROM 5 FOR 6),0);
        VCODIGORESTNOVO = CAST(VCODIGORESTNOVO AS INTEGER) +1;
        VCODIGORESTNOVO = '8888'||LPAD(:VCODIGORESTNOVO, 6, 0);
    END
    VNUMEROPVNOVO = (SELECT NUMEROPV FROM ATUALIZARNUMEROPV(:ECHAVEEMPPV));
    VNUMEROPVNOVO = LPAD(CAST(:VNUMEROPVNOVO AS INTEGER), 10, 0);
    INSERT INTO PREVENDA (
        CHAVE, ATIVO, CHAVEEMPRESA, NUMEROPV, DATAPV, CHAVECLIFOR, CHAVEVENDEDOR,
        CHAVECFOPPROD,
        CHAVECFOPOPERFISCAIS,
        CHAVECONDPGTO, FATURA, OBS,
        DESCPORCPROD, DESCVLRPROD, VLRACRESCIMO, TOTALPRODUTO, TOTALPV, NL,
        CODIGOREST, CHAVETABELADESCONTOS, TIPOSENHADESCONTO, CHAVEUSUARIOAUTORDESCONTO,
        NOMECLIENTE, HORA, COO, CCF, TIPO, CHAVEDOCDESTINO, TIPODOCDESTINO,
        CHAVEPLANOCONTA, CHAVECENTROCUSTO, CHAVECTABANCARIA, CHAVEOPERTITULOS,
        BRSGORJETAGARCOMPERC, BRSGORJETAGARCOMVLR, BRSTAXAENTREGA, BRSTIPOPEDIDO,
        BRSCREDITO, CHAVEBRSENTREGADOR, ENTREGA, BRSTAXAENTREGADOR,
        DATAHORAENTREGANDO, DATAHORAENTREGUE, TROCOPARA, CHAVEFORMAPGTO, BRSQTDEPESSOAS,
        BRSTEMRECOMPENSA, DATAHORAULTCONSUMACAO, BRSTAXACOUVERT,
        BRSCONFIMPRESSA, BRSQTDEPESSOASREMANESC, CHAVEUSUARIOGEROU,
        LOCALMESA, FINALIZADO, FORMAPGTO)
    SELECT
        :VCHAVEGENPV, 1, :ECHAVEEMPPV, :VNUMEROPVNOVO, CURRENT_DATE, AG.CHAVECLIFOR, NULL,
        (SELECT FIRST 1 (CASE WHEN CID.UF=:EUFEMPRESALOG THEN OPE.CHAVECFOPPRODDE ELSE OPE.CHAVECFOPPRODFE END) FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='001')),
        (SELECT FIRST 1 CHAVE FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='001')),
        NULL, '', 'GERADO DO AGENDAMENTO DA VACINA '||V.CODIGO||' - '||V.DESCRICAO,
        NULL, 0, NULL, 0, 0, :ENLATUAL,
        :VCODIGORESTNOVO, NULL, NULL, NULL,
        NULL, CURRENT_TIME, NULL, NULL, 0, NULL, 0,
        NULL, NULL, NULL, NULL,
        0, 0, 0, 0,
        0, NULL, NULL, NULL,
        NULL, NULL, NULL, NULL, 0,
        'N', NULL, 0,
        'N', NULL, 1,
        NULL, 'N', 0
    FROM OSPETSHOPAGENDA AG
    INNER JOIN OSPETSHOPPROCEDIMENTOS V ON (V.CHAVE=AG.CHAVEPROCEDIMENTO) AND (V.TIPO=0) -- VACINA
    INNER JOIN CLIFOR C ON (C.CHAVE=AG.CHAVECLIFOR)
    LEFT JOIN CIDADE CID ON (CID.CHAVE=C.CHAVECIDADE)
    WHERE (AG.CHAVE=:ECHAVEAGENDA);
    INSERT INTO ITENSPREVENDA(
        ATIVO, CHAVEEMPRESA, CHAVEPREVENDA, CHAVEPRODUTO, QTDE, VLRUNIT,
        VLRUNITORIGINAL, DESCPORC, DESCVLR, VLRUNITCOMDESC, CHAVETRIBUTACAO,
        VLRSUBTOTAL, VLRTOTAL, NL, CHAVECLASSFISCAL, TIPOSENHADESC,
        CHAVEUSUARIOAUTORDESC, VLRUNITTABELA, VLRVENDAMINIMO, CHAVEORIGEMTRANSF,
        NUMMESACONTATRANSF, CHAVELOTEPROD, CHAVEVENDEDOR, ALIQCOMISFAT, INDICE,
        DATAITEMPV, HORAITEMPV, DESCRCOMPLEMENT, ORIGEMLANC, IMPRESSOAUTO,
        OBSIMPRESSAO, SITUACAOPREPARO, RECOMPENSA, CHAVEITEMRECOMPENSA,
        TIPOPRODUTO, TRANSFERIDO, CHAVETABELAPRECO)
    SELECT 1, 1, :VCHAVEGENPV, P.CHAVE, V.QTDE, PV.PRECOVENDA,
        PV.PRECOVENDA, 0, 0, PV.PRECOVENDA, 4,
        (PV.PRECOVENDA*V.QTDE), (PV.PRECOVENDA*V.QTDE), :ENLATUAL, NULL, NULL,
        NULL, 0, 0, NULL,
        NULL, NULL, 2, 0, 1,
        CURRENT_DATE, CURRENT_TIME, '', 0, 0,
        NULL, 0, NULL, NULL,
        0, 'N', :ECHAVETABELAPRECO
    FROM OSPETSHOPAGENDA AG
    INNER JOIN OSPETSHOPPROCEDIMENTOS V ON (V.CHAVE=AG.CHAVEPROCEDIMENTO) AND (V.TIPO=0) -- VACINA
    INNER JOIN PRODUTO P ON (P.CHAVE=V.CHAVEPRODUTO) AND (P.CHAVEEMPRESA=:ECHAVEEMPPROD)
    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:ECHAVEEMPVENDA) AND (PV.CHAVETABELAPRECO=:ECHAVETABELAPRECO) AND (PV.ATIVO=1)
    INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
    WHERE (AG.CHAVE=:ECHAVEAGENDA);
    UPDATE PREVENDA SET
    TOTALPV=(SELECT SUM(VLRTOTAL) FROM ITENSPREVENDA WHERE (CHAVEPREVENDA=:VCHAVEGENPV) AND (ATIVO=1)),
    TOTALPRODUTO=(SELECT SUM(VLRTOTAL) FROM ITENSPREVENDA WHERE (CHAVEPREVENDA=:VCHAVEGENPV) AND (ATIVO=1))
    WHERE CHAVE=:VCHAVEGENPV;
    SCODIGORESTNOVO = :VCODIGORESTNOVO;
  SUSPEND;
END^


ALTER PROCEDURE GERARREGSPRODUTO (
    ECHAVEPRODUTO INTEGER,
    EPRECOCUSTO NUMERIC(18,6),
    ECHAVETABELAPRECO INTEGER,
    EPRECOVENDA NUMERIC(18,6))
AS
declare variable VCHAVEPROD integer;
declare variable VCHAVEEMPPROD integer;
declare variable VCHAVEEMPESTOQUE integer;
declare variable VATIVO integer;
declare variable VCHAVEEMPRESA integer;
declare variable VCHAVEDPTOESTOQUE integer;
declare variable VSALDO numeric(18,3);
BEGIN
    --PRODUTOCUSTO
    FOR SELECT P.CHAVE
    FROM PRODUTO P
    LEFT JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE)
    WHERE (CASE WHEN :ECHAVEPRODUTO=0 THEN P.CHAVE ELSE :ECHAVEPRODUTO END = P.CHAVE)
    GROUP BY P.CHAVE, P.CODIGO
    HAVING (COUNT(PC.CHAVE) < (SELECT COUNT(CHAVE) FROM CONFIG WHERE (ATIVO=1)))
    INTO :VCHAVEPROD
    DO BEGIN

        INSERT INTO PRODUTOCUSTO
        (CHAVEEMPRESA, CHAVEPRODUTO, PRECOCUSTONFLANC, PRECOCUSTOANT, PRECOCUSTO, PRECOMEDIOANT, PRECOMEDIO, DATAHORAALT)
        SELECT C.CHAVEEMPRESA, :VCHAVEPROD, :EPRECOCUSTO, 0, :EPRECOCUSTO, 0, :EPRECOCUSTO, CURRENT_DATE
        FROM CONFIG C
        LEFT JOIN PRODUTOCUSTO PC ON (PC.CHAVEEMPRESA=C.CHAVEEMPRESA) AND (PC.CHAVEPRODUTO=:VCHAVEPROD)
        WHERE (C.ATIVO=1) AND (PC.CHAVE IS NULL);
    END

    --PRODUTOVENDA
    FOR SELECT P.CHAVE
    FROM PRODUTO P
    LEFT JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVETABELAPRECO=:ECHAVETABELAPRECO) AND (PV.ATIVO=1)
    WHERE (CASE WHEN :ECHAVEPRODUTO=0 THEN P.CHAVE ELSE :ECHAVEPRODUTO END = P.CHAVE)
    GROUP BY P.CHAVE, P.CODIGO
    HAVING (COUNT(PV.CHAVE)<(SELECT COUNT(CHAVE) FROM CONFIG WHERE (ATIVO=1)))
    INTO :VCHAVEPROD
    DO BEGIN

        INSERT INTO PRODUTOVENDA
        (CHAVEEMPRESA, CHAVEPRODUTO, PRECOVENDAMINIMO, PRECOVENDAANT, PRECOVENDA, DATAHORAALT, CHAVETABELAPRECO)
        SELECT C.CHAVEEMPRESA, :VCHAVEPROD, 0, 0, :EPRECOVENDA, CURRENT_DATE, :ECHAVETABELAPRECO
        FROM CONFIG C
        LEFT JOIN PRODUTOVENDA PV ON (PV.CHAVEEMPRESA=C.CHAVEEMPRESA) AND (PV.CHAVEPRODUTO=:VCHAVEPROD) AND (PV.ATIVO=1)
        WHERE (C.ATIVO=1) AND (PV.CHAVE IS NULL);
    END

    --PRODUTOESTOQUE
    FOR SELECT P.CHAVE
    FROM PRODUTO P
    LEFT JOIN PRODUTOESTOQUE PE ON (PE.CHAVEPRODUTO=P.CHAVE)
    WHERE (CASE WHEN :ECHAVEPRODUTO=0 THEN P.CHAVE ELSE :ECHAVEPRODUTO END = P.CHAVE)
    GROUP BY P.CHAVE, P.CODIGO
    HAVING (COUNT(PE.CHAVE)<(SELECT COUNT(CHAVE) FROM CONFIG WHERE (ATIVO=1)))
    INTO :VCHAVEPROD
    DO BEGIN

        INSERT INTO PRODUTOESTOQUE
        (CHAVEEMPRESA, SALDO, CHAVEPRODUTO, ESTOQUEMAXIMO, ESTOQUEMINIMO, SALDOCOTADO,
        SALDOCONDICIONAL, SALDOEMTERCEIROS, SALDODETERCEIROS, SALDOPOSSEPROPRIA)
        SELECT C.CHAVEEMPRESA, 0, :VCHAVEPROD, 0 , 0, 0, 0, 0, 0, 0
        FROM CONFIG C
        LEFT JOIN PRODUTOESTOQUE PE ON (PE.CHAVEEMPRESA=C.CHAVEEMPRESA) AND (PE.CHAVEPRODUTO=:VCHAVEPROD)
        WHERE (C.ATIVO=1) AND (PE.CHAVE IS NULL);
    END

    --GERAR DEPARTAMENTO GERAL
    FOR SELECT CC.CHAVE, CC2.CHAVE
    FROM EMPRESA CC
    INNER JOIN EMPRESA CC2 ON (CC2.CHAVE>0)
    ORDER BY CC.CHAVE, CC2.CHAVEEMPRESA
    INTO :VCHAVEEMPPROD, :VCHAVEEMPESTOQUE
    DO BEGIN

        UPDATE OR INSERT INTO DPTOESTOQUE
        (CHAVEEMPRESA, CHAVEEMPPROD, CODIGO, DESCRICAO)
        VALUES (:VCHAVEEMPESTOQUE, :VCHAVEEMPPROD, '001', 'GERAL')
        MATCHING (CHAVEEMPRESA, CHAVEEMPPROD, CODIGO, DESCRICAO);
    END

    --ESTOQUE
    INSERT INTO ESTOQUE
    (CHAVEEMPRESA, CHAVEUSUARIO, CHAVEPRODUTO, CODPRODUTO, DOCUMENTO,
    QTDEENTRADA,
    QTDESAIDA,
    SALDO, NL, ORIGEM, PRECOCUSTO, CHAVEDOC,
    DATA, HORA, CHAVECLIFOR, TIPOMOVIMENTACAO, SALDOEMPROD,
    CHAVEDPTOESTOQUE)
    SELECT PE.CHAVEEMPRESA, 1, PE.CHAVEPRODUTO, P.CODIGO, 'AJUSTE',
    CASE WHEN PE.SALDOPOSSEPROPRIA > 0 THEN PE.SALDOPOSSEPROPRIA ELSE 0 END,
    CASE WHEN PE.SALDOPOSSEPROPRIA < 0 THEN PE.SALDOPOSSEPROPRIA*(-1) ELSE 0 END,
    PE.SALDOPOSSEPROPRIA, 0, 5, PC.PRECOMEDIO, 0,
    CURRENT_DATE, CURRENT_TIME, 0, 0, 0,
    (SELECT CHAVE FROM DPTOESTOQUE D WHERE (D.CODIGO='001') AND (D.CHAVEEMPRESA=PE.CHAVEEMPRESA) AND (D.CHAVEEMPPROD=P.CHAVEEMPRESA))
    FROM PRODUTOESTOQUE PE
    INNER JOIN PRODUTO P ON (P.CHAVE=PE.CHAVEPRODUTO)
    INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=1)
    LEFT JOIN ESTOQUE E ON (E.CHAVEPRODUTO=PE.CHAVEPRODUTO) AND (PE.CHAVEEMPRESA=E.CHAVEEMPRESA)
    WHERE (E.CHAVE IS NULL)
    AND (CASE WHEN :ECHAVEPRODUTO=0 THEN P.CHAVE ELSE :ECHAVEPRODUTO END = P.CHAVE);

    --ATUALIZAR SALDO ESTOQUE
    EXECUTE PROCEDURE UPDATESALDOESTOQUE(:ECHAVEPRODUTO);

    --PRODUTODPTOESTOQUE
    FOR SELECT P.ATIVO, P.CHAVEEMPRESA, P.CHAVEPRODUTO, DE.CHAVE,
    CASE WHEN (DE.CODIGO='001') THEN P.SALDO ELSE 0 END AS SALDO
    FROM PRODUTO PROD
    INNER JOIN PRODUTOESTOQUE P ON (P.CHAVEPRODUTO=PROD.CHAVE)
    INNER JOIN DPTOESTOQUE DE ON (DE.CHAVEEMPPROD=PROD.CHAVEEMPRESA) AND (DE.CHAVEEMPRESA=P.CHAVEEMPRESA)
    LEFT JOIN PRODUTODPTOESTOQUE PD ON (PD.CHAVEDPTOESTOQUE=DE.CHAVE) AND (PD.CHAVEPRODUTO=PROD.CHAVE)
    WHERE (PD.CHAVE IS NULL)
    AND (CASE WHEN :ECHAVEPRODUTO=0 THEN PROD.CHAVE ELSE :ECHAVEPRODUTO END = PROD.CHAVE)
    ORDER BY P.CHAVEPRODUTO, DE.CHAVE
    INTO :VATIVO, :VCHAVEEMPRESA, :VCHAVEPROD, :VCHAVEDPTOESTOQUE, :VSALDO
    DO BEGIN

        INSERT INTO PRODUTODPTOESTOQUE
        (ATIVO, CHAVEEMPRESA, CHAVEPRODUTO, CHAVEDPTOESTOQUE, SALDO)
        VALUES
        (:VATIVO, :VCHAVEEMPRESA, :VCHAVEPROD, :VCHAVEDPTOESTOQUE, :VSALDO);
    END
END^


ALTER PROCEDURE GERARSERVICOLEIPAFECF (
    ECHAVEEMP INTEGER,
    ECODIGO VARCHAR(6),
    EDESCRICAO VARCHAR(100),
    ECHAVETABELAPRECO INTEGER)
RETURNS (
    SRESULTADO VARCHAR(100))
AS
declare variable VTIPOCOD varchar(2);
declare variable VCHAVENCM integer;
declare variable VCHAVEGENERO integer;
declare variable VCHAVEGRUPOFISCAL integer;
declare variable VCHAVE integer;
declare variable VCHAVETABELAPISCOFINS integer;
declare variable VCODIGOGP varchar(6);
declare variable VCSTPISVENDA varchar(2);
declare variable VCSTCOFINSVENDA varchar(2);
BEGIN
    SRESULTADO = '';
    SELECT CHAVE
    FROM PRODUTO P
    WHERE (P.ATIVO=1)
    AND (P.CHAVEEMPRESA=:ECHAVEEMP)
    AND (P.CODIGO=:ECODIGO)
    AND (P.DESCRICAO <> :EDESCRICAO)
    INTO :VCHAVE;
    IF (:VCHAVE IS NOT NULL) THEN BEGIN
        SRESULTADO = 'JA EXISTE PRODUTO CADASTRADO COM CODIGO "999999", EXCLUA OU ALTERE O CODIGO DO PRODUTO.';
        EXIT;
    END
    SELECT CHAVE
    FROM PRODUTO P
    WHERE (P.ATIVO=3)
    AND (P.CHAVEEMPRESA=:ECHAVEEMP)
    AND (P.CODIGO=:ECODIGO)
    AND (P.DESCRICAO=:EDESCRICAO)
    INTO :VCHAVE;
    IF (:VCHAVE IS NOT NULL) THEN BEGIN
        SRESULTADO = 'JA EXISTE PRODUTO CADASTRADO COM CODIGO "' || :ECODIGO || '" E DESCRICAO "' || :EDESCRICAO || '".';
        EXIT;
    END
    UPDATE OR INSERT INTO CLASSFISCAL
    (ATIVO, CHAVEEMPRESA, CODIGO, DESCRICAO, TIPO)
    VALUES
    (1, 1, '00000000', 'MERCADORIA OU OUTRA OPERACAO QUE NAO POSSA SER CLASSIFICADA SEGUNDO A TABELA DA NCM', 0)
    MATCHING (CODIGO);
    SELECT FIRST 1 PT.CODIGO, CF.CHAVE, PG.CHAVE, GF.CHAVE, GF.CHAVETABELAPISCOFINS, GF.CODIGO, GF.CSTPIS, GF.CSTCOFINS
    FROM PRODUTO P
    LEFT JOIN PRODUTOTIPO PT ON (PT.CODIGO='99') AND (PT.CHAVEEMPRESA=1)
    LEFT JOIN PRODGENERO PG ON (PG.CODIGO='99')
    LEFT JOIN TRIBUTACAO T ON (T.ATIVO=1) AND (T.CODIGO='04100')
    LEFT JOIN GRUPOFISCAL GF ON (GF.CHAVETRIBUTACAO=T.CHAVE) AND (GF.ATIVO=1)
    LEFT JOIN CLASSFISCAL CF ON (CF.CODIGO='00000000') AND (CF.ATIVO=1)
    INTO :VTIPOCOD, :VCHAVENCM, :VCHAVEGENERO, :VCHAVEGRUPOFISCAL, :VCHAVETABELAPISCOFINS, :VCODIGOGP, :VCSTPISVENDA, :VCSTCOFINSVENDA;
    IF (:VTIPOCOD IS NULL) THEN BEGIN
        SRESULTADO = 'TIPO DE PRODUTO "99" NAO FOI ENCONTRADO.';
        EXIT;
    END
    IF (:VCHAVEGENERO IS NULL) THEN BEGIN
        SRESULTADO = 'GENERO DE PRODUTO "99" NAO FOI ENCONTRADO.';
        EXIT;
    END
    IF (:VCHAVEGRUPOFISCAL IS NULL) THEN BEGIN
        VCHAVEGRUPOFISCAL = GEN_ID(GEN_GRUPOFISCAL_ID, 1);
        INSERT INTO GRUPOFISCAL
        (CHAVE, ATIVO, CHAVEEMPRESA, CODIGO, DESCRICAO,
        CHAVETRIBUTACAO, MODBCICMS, MODBCICMSST, CSTIPI, IPITRIB,
        IPI, VLRIPITRIB, CSTPIS, CSTCOFINS, CHAVETABELAPISCOFINS,
        CSTPISCOMPRA, CSTCOFINSCOMPRA, STATUS, CHAVEBDORIGEM, CODENQIPI,
        CHAVECFOPOPERFISCAIS, CHAVECFOPOPERFISCAISENT, VISIVEL, DATAHORAALT)
        VALUES
        (:VCHAVEGRUPOFISCAL, 1, 1, LPAD(:VCHAVEGRUPOFISCAL, 6, '0'), 'ICMS 041 - ALIQ. 0.00% (AUT.)',
        11, 0, 0, '53', '',
        0, 0, '08', '08', 697,
        '70', '70', 0, NULL, '999',
        1, 16, 0, CURRENT_TIMESTAMP);
    END
    IF (:VCHAVEGRUPOFISCAL IS NULL) THEN BEGIN
        SRESULTADO = 'CADASTRE UM GRUPO FISCAL COM CST ICMS "04100" NO CHERP EM FISCAIS / GRUPOS FISCAIS E TENTE NOVAMENTE.';
        EXIT;
    END
    IF (:VCHAVENCM IS NULL) THEN BEGIN
        SRESULTADO = 'CADASTRE UMA CLASSIFICACAO FISCAL (NCM) "00000000" NO CHERP EM FISCAIS / CLASSIFICACOES FISCAIS (NCM/NBS) E TENTE NOVAMENTE.';
        EXIT;
    END
    IF ((:VCSTPISVENDA = '08') AND (:VCSTCOFINSVENDA = '08') AND ((:VCHAVETABELAPISCOFINS IS NULL) or (:VCHAVETABELAPISCOFINS = 0)))  THEN BEGIN
        SRESULTADO = 'EM CHERP / FISCAIS / GRUPOS FISCAIS, ACESSE O GRUPO FISCAL: "' || :VCODIGOGP || '" E ASSOCIE UM DETALHAMENTO DE PIS/COFINS E TENTE NOVAMENTE.';
        EXIT;
    END
    VCHAVE = GEN_ID(GEN_PRODUTO_ID, 1);
    INSERT INTO PRODUTO
    (CHAVE, ATIVO, CHAVEEMPRESA, CODIGO, TIPO, CODBARRAS, CODIGOFABRICA,
    STATUS, DESCRICAO, CHAVECLASSFISCAL, CHAVEUNIDADE, CHAVEUSUARIOCAD,
    CHAVEUSUARIOALT, EXPORTABALANCA, AGRUPADOCOMPOSTO, MVA,
    IPPT, IAT, CHAVEPRODGENERO, OBS,
    VLRPAUTA, CHAVEGRUPOFISCAL, CHAVEGRUPOFISCALPF)
    VALUES
    (:VCHAVE, 3, :ECHAVEEMP, :ECODIGO, :VTIPOCOD, '9999999999999', '',
    1, :EDESCRICAO, :VCHAVENCM, 1, 1,
    1, 'N', 0, 0,
    'T', 'A', :VCHAVEGENERO, '',
    0, :VCHAVEGRUPOFISCAL, :VCHAVEGRUPOFISCAL);
    EXECUTE PROCEDURE GERARREGSPRODUTO(:VCHAVE, 1, 1, :ECHAVETABELAPRECO);
    SUSPEND;
END^


ALTER PROCEDURE GETULTIMOPEDIDO (
    CHAVEEMPRESA INTEGER)
RETURNS (
    PEDIDO VARCHAR(6))
AS
declare variable PEDAUTMAN integer;
declare variable ULTIMOPED integer;
declare variable ULTIMOPEDEMBRANCO integer;
declare variable ULTIMOPEDGRAVADO integer;
declare variable NUMERO integer;
BEGIN
    SELECT PEDAM, ULTIMOPED, ULTIMOPEDMANUALEMBRANCO FROM CONFIGPEDIDOSAIDA
    WHERE ATIVO=1 AND CHAVEEMPRESA=:CHAVEEMPRESA
    INTO :PEDAUTMAN, :ULTIMOPED, :ULTIMOPEDEMBRANCO;
    IF (:PEDAUTMAN=0) THEN BEGIN
        NUMERO=:ULTIMOPED+1;
        SELECT CASE PEDIDO WHEN '' THEN 0 ELSE PEDIDO END FROM PEDIDOSAIDA
        WHERE ATIVO=1 AND CHAVEEMPRESA = :CHAVEEMPRESA
        AND CHAVE = (SELECT GEN_ID(GEN_PEDIDOSAIDA_ID,0) FROM RDB$GENERATORS
        WHERE RDB$GENERATOR_NAME='GEN_PEDIDOSAIDA_ID')
        INTO :ULTIMOPEDGRAVADO;
        IF (:ULTIMOPEDGRAVADO >= :ULTIMOPED) THEN
            NUMERO= :ULTIMOPEDGRAVADO+1;
        UPDATE CONFIGPEDIDOSAIDA SET ULTIMOPED=:NUMERO
        WHERE CHAVEEMPRESA=:CHAVEEMPRESA;
    END
    IF (:PEDAUTMAN=1) THEN BEGIN
        NUMERO=:ULTIMOPEDEMBRANCO+1;
        UPDATE CONFIGPEDIDOSAIDA SET ULTIMOPEDMANUALEMBRANCO=:NUMERO
        WHERE CHAVEEMPRESA=:CHAVEEMPRESA;
    END
    PEDIDO= CAST(NUMERO AS INTEGER);
    PEDIDO= LPAD(:PEDIDO, 6, 0);
    SUSPEND;
    /*
        FUNCIONALIDADE: PASSA A CHAVEEMPRESA E A PROC RETORNA O NUMERO DO ULTIMO PEDIDO VALIDO PARA USAR
        CHAMADAS:
            - PROCEDURE FRACIONARPEDIDOS;
            - PROCEDURE AGRUPACOOS;
            - PROCEDURE AGRUPAPEDIDOSAIDA;
            - PROCEDURE CONDICIONALGERAPS;
            - PROCEDURE COTACAOGERAPS;
            - PROCEDURE DUPLICAPEDIDOSAIDA;
            - PROCEDURE GERANFREMESSA;
            - PROCEDURE GERA_PEDSAIDA;
            - PROCEDURE ORDEMSERVICOGERAPS;
    */
END^


ALTER PROCEDURE IMPCOTACAONFENTRADA (
    CHAVECOTACAO INTEGER,
    CHAVEEMPRESA INTEGER,
    CHAVENFENTRADA INTEGER)
AS
DECLARE VARIABLE NLATUAL DOUBLE PRECISION;
DECLARE VARIABLE NUMEROCOT VARCHAR(10);
BEGIN
    SELECT NL, NUMEROCO FROM COTACAO WHERE CHAVE=:CHAVECOTACAO
    INTO :NLATUAL, :NUMEROCOT;
    INSERT INTO NFENTRADA(CHAVE, CHAVEEMPRESA, DATALANCAMENTO, NUMEROPED,
        DATAPED, CHAVECOTACAO, NUMERONF, EMISSAO, ENTRADA, VALORNF,
        BASECALCULOICMS, VLRICMS, BASECALCICMSSUBST, VLRICMSSUBST,
        FRETE, FATURA, OBS, TOTALIPI, BCIPI, TOTALPRODUTO, TOTALNF,
        FRETEPORCONTA, CHAVECLIFOR, CHAVECONDPGTO,
        STATUS, QTDEVOLUME, NL, DESPACESSORIA,
        VLRSEGURO, DESCONTOPORC, DESCONTOVLR, DESCPORCSERVICO,
        DESCVLRSERVICO, INDICADOR, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD,
        TIPOPAGAMENTO, BASECALCICMSSUBSTDESTAC, VLRCALCICMSSUBSTDESTAC,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CHAVEPLANOCONTA, CHAVECENTROCUSTO)
        SELECT :CHAVENFENTRADA, :CHAVEEMPRESA, 'NOW', NUMEROCO,
        DATA, :CHAVECOTACAO, NULL, NULL, 'NOW', TOTALCOTACAO,
        BASECALCULOICMS, VLRICMS, BASECALCICMSSUBST, VLRICMSSUBST,
        FRETE, FATURA, OBS, TOTALIPI, BCIPI, TOTALPRODUTO, TOTALCOTACAO,
        1, CHAVECLIFOR, CHAVECONDPGTO,
        0, 0, NL, DESPACESSORIA,
        VLRSEGURO, DESCPORCPROD, DESCVLRPROD, DESCPORCSERVICO,
        DESCVLRSERVICO, 0, CHAVECFOPOPERFISCAIS, CHAVECFOPPROD,
        TIPOPAGAMENTO, BASECALCICMSSUBSTDESTAC, VLRICMSSUBSTDESTAC,
        CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CHAVEPLANOCONTA, CHAVECENTROCUSTO
    FROM COTACAO C
    WHERE CHAVE=:CHAVECOTACAO;
    INSERT INTO ITENSNFENTRADAPROD(CHAVEEMPRESA, CHAVENFENTRADA, CHAVEPRODUTO, CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE,
        VLRLANC, VLRUNIT, VLRUNITCOMDESC, DESCPORC, DESCVLR, CHAVETRIBUTACAO, CST, VLRSUBTOTAL, VLRTOTAL, ICMS, VLRICMS, BASEICMS,
        CHAVECLASSFISCAL, CSTIPI, IPI, BASECALCIPI, VLRIPI, BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB,
        BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, PRECOCUSTO, PRECOVENDA, NL, CHAVECFOP, CHAVECFOPOPERFISCAIS, MOVESTOQUE, COMPORTOTALNF, MVA,
        CSTPIS, BCPIS, ALIQPIS, VLRPIS, CSTCOFINS, BCCOFINS, ALIQCOFINS, VLRCOFINS, IPITRIB, ALIQUOTAINTRA,
        MVACALC, DESCRCOMPLEMENT, CHAVEDPTOESTOQUE, CODENQIPI)
    SELECT IP.CHAVEEMPRESA, :CHAVENFENTRADA, IP.CHAVEPRODUTO, IP.CODPRODUTO, IP.PRODUTO, IP.CHAVEUNIDADE, IP.UNIDADE, IP.QTDE,
        IP.VLRUNIT, IP.VLRUNIT, (IP.VLRUNIT - IP.DESCVLR), IP.DESCPORC, IP.DESCVLR, IP.CHAVETRIBUTACAO, IP.CST, IP.VLRSUBTOTAL, IP.VLRTOTAL, IP.ICMS, IP.VLRICMS, IP.BASEICMS,
        IP.CHAVECLASSFISCAL, IP.CSTIPI, IP.IPI, IP.BASECALCIPI, IP.VLRIPI, IP.BASEICMSSUBSTTRIB, IP.VLRICMSSUBSTTRIB,
        IP.BASEICMSSUBSTTRIBDESTAC, IP.VLRICMSSUBSTTRIBDESTAC, PC.PRECOCUSTO, PV.PRECOVENDA, NL, IP.CHAVECFOP, IP.CHAVECFOPOPERFISCAIS, C.MOVESTOQUE, IP.COMPORTOTALCOT, IP.MVA,
        IP.CSTPIS, IP.BCPIS, IP.ALIQPIS, IP.VLRPIS, IP.CSTCOFINS, IP.BCCOFINS, IP.ALIQCOFINS, IP.VLRCOFINS, '00', T.ALIQUOTADE,
        IP.MVACALC, DESCRCOMPLEMENT, IP.CHAVEDPTOESTOQUE, G.CODENQIPI
    FROM ITENSCOTACAOPROD IP
    INNER JOIN PRODUTO P ON (IP.CHAVEPRODUTO=P.CHAVE)
    INNER JOIN GRUPOFISCAL G ON (P.CHAVEGRUPOFISCAL=G.CHAVE)
    INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=IP.CHAVEPRODUTO) AND (PC.CHAVEEMPRESA=(SELECT CC.CHAVEEMPRESAREF FROM CONFIGCOMPART CC WHERE (CC.CHAVEEMPRESA=:CHAVEEMPRESA) AND (CC.TABELA='PRODUTOCUSTO')))
    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=IP.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=(SELECT CC.CHAVEEMPRESAREF FROM CONFIGCOMPART CC WHERE (CC.CHAVEEMPRESA=:CHAVEEMPRESA) AND (CC.TABELA='PRODUTOVENDA'))) AND (PV.CHAVETABELAPRECO=IP.CHAVETABELAPRECO) AND (PV.ATIVO=1)
    INNER JOIN CFOPOPERFISCAIS C ON (C.CHAVE = IP.CHAVECFOPOPERFISCAIS)
    INNER JOIN TRIBUTACAO T ON (T.CHAVE=IP.CHAVETRIBUTACAO)
    WHERE (IP.ATIVO=1) AND (IP.CHAVECOTACAO=:CHAVECOTACAO);
    INSERT INTO ITENSNFENTRADASERV(CHAVEEMPRESA, CHAVENFENTRADA, CHAVEPRODUTO, CODPRODUTO, PRODUTO, CHAVEUNIDADE, UN, QTDE,
        VLRLANC, VLRUNIT, VLRUNITORIGINALSERV, DESCPORC, DESCVLR, VLRUNITCOMDESC, VLRSUBTOTAL, VLRTOTAL, PRECOCUSTO, PRECOVENDA, CHAVECFOP,
        CHAVECFOPOPERFISCAIS, CHAVETRIBUTACAO, BASEISS, ISS, VLRISS,
        BASEICMS, VLRICMS, CSTPISCOFINS, BASEPISCOFINS, ALIQPIS,
        VLRPIS, ALIQCOFINS, VLRCOFINS, NL, DESCRCOMPLEMENT)
    SELECT I.CHAVEEMPRESA, :CHAVENFENTRADA, I.CHAVEPRODUTO, I.CODPRODUTO, I.PRODUTO, I.CHAVEUNIDADE, I.UN, I.QTDE,
        I.VLRUNIT, I.VLRUNIT, I.VLRUNIT, I.DESCPORC, I.DESCVLR, (I.VLRUNIT - I.DESCVLR), I.VLRSUBTOTAL, I.VLRTOTAL, PC.PRECOCUSTO, PV.PRECOVENDA, I.CHAVECFOP,
        I.CHAVECFOPOPERFISCAIS, NULL, CASE WHEN COALESCE(ISS,0) > 0 THEN I.VLRTOTAL ELSE 0 END, I.ISS, CASE WHEN COALESCE(ISS,0) > 0 THEN ((I.VLRTOTAL*I.ISS)/100) ELSE 0 END,
        0, 0, GF.CSTPISCOMPRA,
        (SELECT BASE FROM CALCULARPISCOFINS(GF.CSTPISCOMPRA, I.VLRTOTAL, '', I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT ALIQPIS FROM CALCULARPISCOFINS(GF.CSTPISCOMPRA, I.VLRTOTAL, '',I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORPIS FROM CALCULARPISCOFINS(GF.CSTPISCOMPRA, I.VLRTOTAL, '',I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT ALIQCOFINS FROM CALCULARPISCOFINS(GF.CSTPISCOMPRA, I.VLRTOTAL, '',I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORCOFINS FROM CALCULARPISCOFINS(GF.CSTPISCOMPRA, I.VLRTOTAL, '',I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        NL, DESCRCOMPLEMENT
    FROM ITENSCOTACAOSERV I
    INNER JOIN PRODUTO P ON (P.CHAVE=I.CHAVEPRODUTO) AND (P.CHAVEEMPRESA=:CHAVEEMPRESA)
    INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
    INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=I.CHAVEPRODUTO) AND (PC.CHAVEEMPRESA=(SELECT CC.CHAVEEMPRESAREF FROM CONFIGCOMPART CC WHERE (CC.CHAVEEMPRESA=:CHAVEEMPRESA) AND (CC.TABELA='PRODUTOCUSTO')))
    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=I.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=(SELECT CC.CHAVEEMPRESAREF FROM CONFIGCOMPART CC WHERE (CC.CHAVEEMPRESA=:CHAVEEMPRESA) AND (CC.TABELA='PRODUTOVENDA'))) AND (PV.CHAVETABELAPRECO=I.CHAVETABELAPRECO) AND (PV.ATIVO=1)
    INNER JOIN GRUPOFISCAL GF ON (P.CHAVEGRUPOFISCAL=GF.CHAVE)
    WHERE (I.ATIVO=1) AND (I.CHAVECOTACAO=:CHAVECOTACAO);
    INSERT INTO OBSLIVROFISCCOMPLDOCFISC
    (CHAVEEMPRESA, CHAVEDOCFISCAL, NL, TIPODOCFISCAL, CHAVEOBSCOMPLFISCAL, DESCRICAOCOMPL, TIPO)
    VALUES (:CHAVEEMPRESA, :CHAVENFENTRADA, :NLATUAL, 0, 42, :NUMEROCOT, 1);
    /*
       CHAMADAS :
            - frmCotacao : Usada para gerar uma NF Entrada de um orcamento de compra
    */
END^


ALTER PROCEDURE INSERIRREGDPTOESTOQUE (
    CHAVEDPTOESTOQUE INTEGER,
    CHAVEPRODUTO INTEGER,
    CHAVEEMPPROD INTEGER,
    CHAVEEMPDPTOEST INTEGER)
AS
BEGIN
    IF (:CHAVEDPTOESTOQUE = 0) THEN BEGIN
        INSERT INTO PRODUTODPTOESTOQUE (ATIVO, CHAVEEMPRESA, CHAVEPRODUTO, CHAVEDPTOESTOQUE, SALDO)
        SELECT 1, PE.CHAVEEMPRESA, :CHAVEPRODUTO, PE.CHAVE, 0 FROM DPTOESTOQUE PE WHERE PE.CHAVEEMPPROD=:CHAVEEMPPROD;
    END ELSE BEGIN
        INSERT INTO PRODUTODPTOESTOQUE (ATIVO, CHAVEEMPRESA, CHAVEPRODUTO, CHAVEDPTOESTOQUE, SALDO)
        SELECT 1, :CHAVEEMPDPTOEST, PE.CHAVE, :CHAVEDPTOESTOQUE, 0 FROM PRODUTO PE WHERE PE.CHAVEEMPRESA=:CHAVEEMPPROD;
    END
END^


ALTER PROCEDURE INSERIRREGLOTEESTOQUE (
    CHAVEEMPESTOQUE INTEGER,
    CHAVELOTE INTEGER)
AS
begin
    INSERT INTO PRODUTOLOTEESTOQUE (ATIVO, CHAVEEMPRESA, CHAVEPRODUTO, CHAVELOTE, QTDEENTRADA, QTDESAIDA, SALDO)
    SELECT 1, :CHAVEEMPESTOQUE, L.CHAVEPRODUTO, :CHAVELOTE, 0, 0, 0 FROM LOTEPRODUTOS L WHERE CHAVE=:CHAVELOTE;

end^


ALTER PROCEDURE INSERIRREGPRODALTERADOS (
    EPACHAVEEMP INTEGER,
    ECHAVEPRODUTO INTEGER,
    EORIGEM INTEGER,
    ECHAVEDOC INTEGER,
    ENL DOUBLE PRECISION,
    EDATAOPERACAO DATE,
    EPRECOCUSTO NUMERIC(18,6),
    EPRECOCUSTOANT NUMERIC(18,6),
    EPRECOCUSTOMEDIO NUMERIC(18,6),
    EPRECOCUSTOMEDIOANT NUMERIC(18,6),
    EPRECOVENDA NUMERIC(18,6),
    EPRECOVENDAANT NUMERIC(18,6),
    ELUCROPORC NUMERIC(7,2),
    ECHAVEITEMDOC INTEGER,
    EFATORMARKUP NUMERIC(7,2),
    EPRECOVENDAMINIMO NUMERIC(18,6),
    ECHAVETABELAPRECO INTEGER)
AS
declare variable VMARGEMPORC numeric(7,2);
declare variable VMARGEMVLR numeric(18,6);
declare variable VTIPOCALCLUCRO integer;
BEGIN
    -- EXCLUI SE JA EXISTE
    UPDATE PRODUTOSALTERADOS
        SET ATIVO=5
    WHERE (ATIVO=1)
    AND (ORIGEM=:EORIGEM)
    AND (CHAVEEMPRESA=:EPACHAVEEMP)
    AND (CHAVEPRODUTO=:ECHAVEPRODUTO)
    AND (CHAVETABELAPRECO=:ECHAVETABELAPRECO);

    SELECT
    FORMULACALCMARGLUCPROD
    FROM CONFIG
    WHERE CHAVEEMPRESA=:EPACHAVEEMP
    INTO :VTIPOCALCLUCRO;

    VMARGEMVLR = :EPRECOVENDA - :EPRECOCUSTO;
    IF (:EPRECOCUSTO > 0) THEN BEGIN
        IF (:VTIPOCALCLUCRO = 0) THEN
            VMARGEMPORC = (:VMARGEMVLR*100)/:EPRECOCUSTO; -- SIMPLES
        ELSE
            VMARGEMPORC = 100 - ((:EPRECOCUSTO/:EPRECOVENDA)*100); -- GM
    END ELSE
        VMARGEMPORC = 0;
    -- INSERE NOVO REGISTRO
    INSERT INTO PRODUTOSALTERADOS
        (CHAVEEMPRESA, CHAVEPRODUTO, ORIGEM,
        CHAVEDOC, NL, DATAOPERACAO,
        PRECOCUSTO, PRECOCUSTOANT, PRECOCUSTOMEDIO, PRECOCUSTOMEDIOANT,
        PRECOVENDA, PRECOVENDAANT, LUCROPORC, CHAVEITEMDOC, FATORMKP,
        PRECOVENDAMINIMO, CHAVETABELAPRECO, MARGEMPORC, MARGEMVLR)
    VALUES 
        (:EPACHAVEEMP, :ECHAVEPRODUTO, :EORIGEM,
        :ECHAVEDOC, :ENL, :EDATAOPERACAO,
        :EPRECOCUSTO, :EPRECOCUSTOANT, :EPRECOCUSTOMEDIO, :EPRECOCUSTOMEDIOANT,
        :EPRECOVENDA, :EPRECOVENDAANT, :ELUCROPORC, :ECHAVEITEMDOC, :EFATORMARKUP,
        :EPRECOVENDAMINIMO, :ECHAVETABELAPRECO, :VMARGEMPORC, :VMARGEMVLR);
END^


ALTER PROCEDURE LANCORDEMPRODGERARPS (
    ECHAVEEMPPS INTEGER,
    ECHAVEORDEMPROD INTEGER,
    ECHAVEPS INTEGER,
    ECHAVEEMPVENDA INTEGER,
    ECHAVEEMPCUSTO INTEGER)
AS
declare variable VCHAVECLIFOR integer;
declare variable VNUMORDEM varchar(10);
declare variable VPESSOA integer;
declare variable VUFEMP char(2);
declare variable VUFCLI char(2);
declare variable VCHAVECFOP integer;
declare variable VCHAVECFOPOPERFIS integer;
declare variable VMOVESTOQUE smallint;
declare variable VENTREGAFUTURA char(1);
declare variable VCOMPORTOTALNF smallint;
declare variable VCLIREDUCAOMVA numeric(7,2);
declare variable VREGIMETRIB smallint;
declare variable VTOTALPS numeric(18,6);
declare variable VSUMTOTALPS numeric(18,6);
declare variable VNLATUAL double precision;
BEGIN
    VSUMTOTALPS = 0;

    SELECT OP.CHAVECLIFOR, OP.NUMORDEM, C.PESSOA, CID.UF,
        C.REDUCAOMVA
    FROM LANCORDEMPROD OP
    INNER JOIN CLIFOR C ON (C.CHAVE=OP.CHAVECLIFOR)
    INNER JOIN CIDADE CID ON (CID.CHAVE=C.CHAVECIDADE)
    WHERE (OP.CHAVE=:ECHAVEORDEMPROD)
    INTO :VCHAVECLIFOR, :VNUMORDEM, :VPESSOA, :VUFCLI,
        :VCLIREDUCAOMVA;

    SELECT CID.UF, E.REGIMETRIBUT
    FROM EMPRESA E
    INNER JOIN CIDADE CID ON (E.CHAVECIDADE=CID.CHAVE)
    WHERE E.CHAVE= :ECHAVEEMPPS
    INTO :VUFEMP, :VREGIMETRIB;

    SELECT
    NL
    FROM PEDIDOSAIDA PS
    WHERE PS.CHAVE=:ECHAVEPS
    INTO :VNLATUAL;

    /* PS JA FOI GERADO NO MOMENTO QUE CONFIRMOU O COMPLEMENTO */
    SELECT FIRST 1
    (CASE WHEN :VUFCLI=:VUFEMP THEN OPE.CHAVECFOPPRODDE ELSE CASE WHEN :VUFCLI<>'EX' THEN OPE.CHAVECFOPPRODFE ELSE OPE.CHAVECFOPEXPIMP END END)
    FROM CFOPOPERFISCAIS OPE WHERE (OPE.CODIGO='002')
    INTO :VCHAVECFOP;

    SELECT FIRST 1
    CF.CHAVE, CF.MOVESTOQUE, CF.ENTREGAFUTURA, CF.COMPORTOTALNF
    FROM CFOPOPERFISCAIS CF
    WHERE (CF.ATIVO=1)
    AND ((CF.CHAVECFOPPRODDE = :VCHAVECFOP) OR (CF.CHAVECFOPPRODFE = :VCHAVECFOP))
    AND (CF.CHAVECFOPSERVDE IS NULL) OR (CF.CHAVECFOPSERVFE IS NULL)
    ORDER BY CF.CHAVE
    INTO :VCHAVECFOPOPERFIS, :VMOVESTOQUE, :VENTREGAFUTURA, :VCOMPORTOTALNF;

    INSERT INTO ITENSPEDSAIDA
        (CHAVEEMPRESA, CHAVEPEDIDO, CHAVEPRODUTO,
        CODPRODUTO, PRODUTO, DESCRCOMPLEMENT, CHAVEUNIDADE, UN, QTDE, VLRUNIT,
        CHAVETRIBUTACAO, CST,
        ICMS,
        ALIQICMSINTRA,
        ALIQICMSINTER,
        VLRSUBTOTAL, VLRTOTAL, BASEICMS, VLRICMS, DESCPORC, DESCVLR, VLRUNITCOMDESC,
        PRECOCUSTO, VLRUNITORIGINAL, NL,
        CSTIPI, IPI, BASECALCIPI, VLRIPI,
        CHAVECFOP,
        CHAVECFOPOPERFISCAIS, MOVESTOQUE, OPERENTFUTURA, COMPORTOTALNF,
        MVA, CSTPIS, CSTCOFINS,
        ALIQPIS,
        ALIQCOFINS,
        VLRPISTRIB,
        VLRCOFINSTRIB,
        BCPIS,
        BCCOFINS,
        VLRPIS,
        VLRCOFINS,
        CHAVECLASSFISCAL, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC,
        VLRUNITTABELA, VLRVENDAMINIMO, CSOSN,
        CHAVETABPISCOFINS,CHAVELOTEPROD, IPITRIB,
        CHAVEDPTOESTOQUE, VLRACRESCGLOBAL, CODENQIPI,
        CHAVETABELAPRECO)
    SELECT
        :ECHAVEEMPPS, :ECHAVEPS, I.CHAVEPRODUTO,
        P.CODIGO, P.DESCRICAO, P.DESCRCOMPLP, P.CHAVEUNIDADE, UN.UNMAIOR, I.QTDE, PV.PRECOVENDA,
        T.CHAVE,T.CODIGO,
        CASE WHEN  (:VUFCLI = :VUFEMP) OR (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('40','41','50','51','90','20')) THEN T.ALIQUOTADE ELSE
        CASE WHEN SUBSTRING(T.CODIGO FROM 1 FOR 1) IN ('1','2','3','8') THEN 4 ELSE (SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU WHERE TU.ORIGEM=:VUFEMP AND TU.DESTINO=:VUFCLI)
        END END,
        T.ALIQUOTADE,
        CASE WHEN  (:VUFCLI = :VUFEMP) OR (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('40','41','50','51','90','20')) THEN T.ALIQUOTADE ELSE
        CASE WHEN SUBSTRING(T.CODIGO FROM 1 FOR 1) IN ('1','2','3','8') THEN 4 ELSE (SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU WHERE TU.ORIGEM=:VUFEMP AND TU.DESTINO=:VUFCLI)
        END END,
        PV.PRECOVENDA*I.QTDE, PV.PRECOVENDA*I.QTDE, 0,0,0,0, PV.PRECOVENDA,
        PC.PRECOMEDIO, PV.PRECOVENDA, :VNLATUAL,
        '53',0,0,0,
        :VCHAVECFOP,
        CASE WHEN COALESCE(GF.CHAVECFOPOPERFISCAIS,0) = 0 THEN :VCHAVECFOPOPERFIS ELSE GF.CHAVECFOPOPERFISCAIS END,
        CASE WHEN COALESCE(GF.CHAVECFOPOPERFISCAIS,0) = 0 THEN :VMOVESTOQUE ELSE COPF.MOVESTOQUE END,
        CASE WHEN COALESCE(GF.CHAVECFOPOPERFISCAIS,0) = 0 THEN :VENTREGAFUTURA ELSE COPF.ENTREGAFUTURA END,
        CASE WHEN COALESCE(GF.CHAVECFOPOPERFISCAIS,0) = 0 THEN :VCOMPORTOTALNF ELSE COPF.COMPORTOTALNF END,
        P.MVA - (P.MVA * :VCLIREDUCAOMVA / 100), GF.CSTPIS, GF.CSTCOFINS,
        (SELECT ALIQPIS FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT ALIQCOFINS FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VLRPISTRIB FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VLRCOFINSTRIB FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT BASE FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT BASE FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORPIS FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORCOFINS FROM CALCULARPISCOFINS(GF.CSTPIS, PV.PRECOVENDA*I.QTDE, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GF.CHAVETABELAPISCOFINS),I.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        P.CHAVECLASSFISCAL, NULL, NULL,
        PV.PRECOVENDA, PV.PRECOVENDAMINIMO, CASE WHEN :VREGIMETRIB <> 2 THEN T.CODIGOSOSN ELSE NULL END,
        TC.CHAVE, I.CHAVELOTEPROD, '',
        I.CHAVEDPTOESTOQUE, 0, GF.CODENQIPI,
        I.CHAVETABELAPRECO
    FROM ITENSLANCORDEMPROD I
    INNER JOIN PRODUTO P ON (P.CHAVE=I.CHAVEPRODUTO)
    INNER JOIN UNIDADE UN ON (UN.CHAVE=P.CHAVEUNIDADE)
    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:ECHAVEEMPVENDA) AND (PV.CHAVETABELAPRECO=I.CHAVETABELAPRECO) AND (PV.ATIVO=1)
    INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
    INNER JOIN GRUPOFISCAL GF ON (GF.CHAVE=CASE WHEN :VPESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END)
    LEFT JOIN CFOPOPERFISCAIS COPF ON (COPF.CHAVE=GF.CHAVECFOPOPERFISCAIS)
    INNER JOIN TRIBUTACAO T ON (T.CHAVE=GF.CHAVETRIBUTACAO)
    LEFT JOIN PCPFORMULASESTAGIO ES ON (ES.CHAVE=I.CHAVEESTAGIOPRODUCAO)
    LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = GF.CHAVETABELAPISCOFINS
    WHERE
    (I.ATIVO=1)
    AND (I.TIPO=1)
    AND (I.CHAVELANCORDEMPROD=:ECHAVEORDEMPROD)
    AND ((ES.TIPOESTAGIO=1) OR (COALESCE(ES.TIPOESTAGIO,-1) = -1));-- ESTAGIO FINAl OU SEM ESTAGIO;

    FOR SELECT
        I.VLRTOTAL
    FROM ITENSPEDSAIDA I
    WHERE (I.CHAVEPEDIDO=:ECHAVEPS)
    INTO :VTOTALPS
    DO BEGIN
        VSUMTOTALPS = :VSUMTOTALPS + :VTOTALPS;
    END

    UPDATE PEDIDOSAIDA SET
    CHAVECLIFOR=:VCHAVECLIFOR,
    OBS = 'GERADO DA ORDEM DE PRODUCAO: '||:VNUMORDEM,
    TOTALPEDIDO = :VSUMTOTALPS,
    TOTALPRODUTO = :VSUMTOTALPS
    WHERE CHAVE=:ECHAVEPS;
END^


ALTER PROCEDURE NFCEGERANF (
    EREGIMETRIB INTEGER,
    ECHAVESIN VARCHAR(1000),
    EVENDANAOPRESENCIAL CHAR(1),
    EOBS VARCHAR(5000),
    ECHAVEUSUARIO INTEGER,
    ECHAVECLIFOR INTEGER,
    ECHAVESERIENF INTEGER,
    EAGRUPAITENS CHAR(1),
    EPCCHAVEEMP INTEGER,
    ECHAVEVEICULO INTEGER,
    ECHAVECFOPPROD INTEGER,
    ECHAVECFOPSERV INTEGER,
    EPVCHAVEEMP INTEGER,
    EFRETEPORCONTA INTEGER,
    ECHAVETRANSP INTEGER,
    ENL DOUBLE PRECISION,
    ECHAVEEMP INTEGER)
RETURNS (
    SNOVACHAVEPEDPROD INTEGER)
AS
DECLARE VARIABLE VCHAVETRIBOPERFISC INTEGER;
DECLARE VARIABLE VCHAVEEMPCOMISSAO INTEGER;
DECLARE VARIABLE VCOMISPRODUTO NUMERIC(7,2);
DECLARE VARIABLE VPDVSOMARVDAPROD44F INTEGER;
DECLARE VARIABLE VCOMISPRODEMISSAO NUMERIC(7,2);
DECLARE VARIABLE UFEMP CHAR(2);
DECLARE VARIABLE UFCLI CHAR(2);
DECLARE VARIABLE VCOMISSERVBAIXA NUMERIC(7,2);
DECLARE VARIABLE VTIPOALIQCOMIS SMALLINT;
DECLARE VARIABLE VCOMISSERVEMISSAO NUMERIC(7,2);
DECLARE VARIABLE VCOMISSERVICO NUMERIC(7,2);
DECLARE VARIABLE VIERG VARCHAR(20);
DECLARE VARIABLE VCOMISPRODBAIXA NUMERIC(7,2);
DECLARE VARIABLE VTIPOCOMISSAO INTEGER;
DECLARE VARIABLE VCOMISSAOGERADA INTEGER;
DECLARE VARIABLE VCHAVEDPTOESTOQUE INTEGER;
DECLARE VARIABLE PESSOA SMALLINT;
DECLARE VARIABLE VCHAVEVENDEDOR INTEGER;
DECLARE VARIABLE VPORCPRODNF NUMERIC(18,6);
DECLARE VARIABLE VTOTALICMS NUMERIC(18,6);
DECLARE VARIABLE VBASEICMS NUMERIC(18,6);
DECLARE VARIABLE VTOTALDESC NUMERIC(18,6);
DECLARE VARIABLE VTOTALACRESC NUMERIC(18,6);
DECLARE VARIABLE VTOTALNFSAIDA NUMERIC(18,6);
DECLARE VARIABLE VVLRTOTALPROD NUMERIC(18,6);
DECLARE VARIABLE VTOTALACRESCIMO NUMERIC(18,6);
DECLARE VARIABLE VCHAVENFSAIDA INTEGER;
DECLARE VARIABLE NUMEROPS VARCHAR(6);
DECLARE VARIABLE VVLRPRODUTO NUMERIC(18,6);
DECLARE VARIABLE VPORCDESCNF NUMERIC(18,6);
DECLARE VARIABLE VTIPOSENHADESCONTO SMALLINT;
DECLARE VARIABLE VCHAVEUSUARIOAUTORDESC INTEGER;
DECLARE VARIABLE VDESCONTO NUMERIC(18,6);
DECLARE VARIABLE VTOTALNF NUMERIC(18,6);
DECLARE VARIABLE AUTOINCPED INTEGER;
DECLARE VARIABLE VCODBENEF VARCHAR(20);
DECLARE VARIABLE VBASEIVA NUMERIC(18,6);
DECLARE VARIABLE VVLRCBS NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSUF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSMUN NUMERIC(18,6);
DECLARE VARIABLE VVLRCBSDIF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSDIFUF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSDIFMUN NUMERIC(18,6);
BEGIN
    VVLRTOTALPROD=0;VTOTALACRESC=0;
    VTOTALDESC=0; VTOTALNFSAIDA=0;
    VCHAVETRIBOPERFISC = 0;
    SELECT E.REGIMETRIBUT, CID.UF,
    (SELECT PEDIDO FROM GETULTIMOPEDIDO (:ECHAVEEMP))
    FROM CONFIG CO
    INNER JOIN EMPRESA E ON E.CHAVE = CO.CHAVEEMPRESA
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE CO.ATIVO=1 AND CO.CHAVEEMPRESA=:ECHAVEEMP
    INTO :EREGIMETRIB, :UFEMP, :NUMEROPS;
    SELECT CID.UF, C.PESSOA, C.IERG FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    WHERE C.CHAVE=:ECHAVECLIFOR
    INTO :UFCLI, :PESSOA, :VIERG;
    AUTOINCPED = GEN_ID(GEN_PEDIDOSAIDA_ID,1);
    SELECT CHAVETRIBUTACAO, CODBENEF FROM CFOPOPERFISCAIS WHERE (ATIVO=1) AND (CHAVE=12)
    INTO :VCHAVETRIBOPERFISC, :VCODBENEF;
    INSERT INTO PEDIDOSAIDA
            (CHAVE, CHAVEEMPRESA, PEDIDO, CHAVECLIFOR, QTDEVOLUME,
            CHAVECFOPPROD, CHAVECFOPSERV, TOTALPRODUTO, TOTALPEDIDO, OBS, DATAPEDIDO,
            STATUS, FRETEPORCONTA, CHAVETRANSP, CHAVEVEICULO,
            DESCVLRPROD, DESPACESSORIA, CHAVECFOPOPERFISCAIS, NL, TIPOPAGAMENTO, CHAVEUSUARIOINICIOU, CHAVESERIENF)
        VALUES(:AUTOINCPED, :ECHAVEEMP, :NUMEROPS, :ECHAVECLIFOR, 0,
            :ECHAVECFOPPROD, :ECHAVECFOPSERV, 0, 0, '', 'NOW',
            0, :EFRETEPORCONTA, :ECHAVETRANSP, :ECHAVEVEICULO, 0, 0, 12, :ENL, 2, :ECHAVEUSUARIO, :ECHAVESERIENF);
    FOR SELECT DISTINCT C.CHAVEEMPRESA, C.CHAVEVENDEDOR, C.TIPOCOMISSAO, C.COMISSAOGERADA, C.COMISPRODUTO,
    C.COMISPRODEMISSAO, C.COMISPRODBAIXA, C.COMISSERVICO, C.COMISSERVEMISSAO, C.COMISSERVBAIXA, C.TIPOALIQUOTA
    FROM COMISSAO C
    INNER JOIN QUEBRARSTRING(:ECHAVESIN) Q ON (Q.REGISTROINT=C.CHAVEDOC)
    WHERE (C.ATIVO=1) AND (C.ORIGEM=6)
    INTO :VCHAVEEMPCOMISSAO, :VCHAVEVENDEDOR, :VTIPOCOMISSAO, :VCOMISSAOGERADA, :VCOMISPRODUTO,
    :VCOMISPRODEMISSAO, :VCOMISPRODBAIXA, :VCOMISSERVICO, :VCOMISSERVEMISSAO, :VCOMISSERVBAIXA, :VTIPOALIQCOMIS
    DO BEGIN
        INSERT INTO COMISSAO
            (ATIVO, CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, TIPOCOMISSAO, COMISSAOGERADA, COMISPRODUTO,
            COMISPRODEMISSAO, COMISPRODBAIXA, COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA,
            NL, ORIGEM, TIPOALIQUOTA)
        VALUES(1, :VCHAVEEMPCOMISSAO, :AUTOINCPED, :VCHAVEVENDEDOR, :VTIPOCOMISSAO, :VCOMISSAOGERADA, :VCOMISPRODUTO,
            :VCOMISPRODEMISSAO, :VCOMISPRODBAIXA, :VCOMISSERVICO, :VCOMISSERVEMISSAO, :VCOMISSERVBAIXA,
            :ENL, 0, :VTIPOALIQCOMIS);
    END
    VCHAVEDPTOESTOQUE=0;
    SELECT CAST(VALOR AS INTEGER)
    FROM CONFIGCAMPOS C
    WHERE (C.CAMPO='CHAVEDPTOESTOQUESAIDA') AND (CHAVEEMPRESA=:ECHAVEEMP)
    INTO :VCHAVEDPTOESTOQUE;
    VPDVSOMARVDAPROD44F=0;
    SELECT CAST(VALOR AS INTEGER)
    FROM CONFIGCAMPOS C
    WHERE (C.CAMPO='PDVSOMARVDAPROD44F') AND (CHAVEEMPRESA=:ECHAVEEMP)
    INTO :VPDVSOMARVDAPROD44F;
    FOR SELECT NF.CHAVE, COALESCE(NF.DESPACESSORIA,0),
    NF.TOTALPRODUTO - CASE WHEN :VPDVSOMARVDAPROD44F = 0 THEN COALESCE(TOTALITEM999999,0) ELSE 0 END,
    NF.DESCVLRPROD,
    NF.TOTALNF - CASE WHEN :VPDVSOMARVDAPROD44F = 0 THEN COALESCE(TOTALITEM999999,0) ELSE 0 END,
    NF.TIPOSENHADESCPROD, NF.CHAVEUSUARIOAUTORDESCPROD, NF.DESCVLRPROD * 100 / ((NF.TOTALNF -
    CASE WHEN :VPDVSOMARVDAPROD44F = 0 THEN COALESCE(TOTALITEM999999,0) ELSE 0 END)
    + NF.DESCVLRPROD)
    FROM NFSAIDA NF
    INNER JOIN QUEBRARSTRING(:ECHAVESIN) Q ON (Q.REGISTROINT=NF.CHAVE)
    WHERE (NF.ATIVO=1)
    INTO :VCHAVENFSAIDA, :VTOTALACRESCIMO, :VVLRPRODUTO, :VDESCONTO, :VTOTALNF,
    :VTIPOSENHADESCONTO, :VCHAVEUSUARIOAUTORDESC, :VPORCDESCNF
    DO BEGIN
        VPORCPRODNF = 0;
        VPORCPRODNF = VPORCPRODNF + :VVLRPRODUTO * 100 / (:VTOTALNF);
        VVLRTOTALPROD = VVLRTOTALPROD + :VVLRPRODUTO;
        VTOTALDESC = VTOTALDESC + :VDESCONTO;
        VTOTALACRESC = VTOTALACRESC + :VTOTALACRESCIMO;
        VTOTALNFSAIDA = VTOTALNFSAIDA + :VTOTALNF;
         INSERT INTO ITENSPEDSAIDA
            (ATIVO, CHAVEEMPRESA, CHAVEPEDIDO, CHAVEPRODUTO,
            CODPRODUTO, PRODUTO, CHAVEUNIDADE, QTDE, VLRUNIT, DESCPORC, DESCVLR, VLRDESCGLOBAL,
            CHAVETRIBUTACAO, VLRTOTAL,
            VLRSUBTOTAL, 
            ICMS,
            ALIQICMSINTRA,
            ALIQICMSINTER,
            BASEICMS,
            VLRICMS,
            CST, UN, VLRUNITCOMDESC,
            CHAVECLASSFISCAL, VLRUNITORIGINAL,
            NL, CHAVECFOP, CHAVECFOPOPERFISCAIS, PRECOCUSTO,
            CSTIPI, IPI, BASECALCIPI, VLRIPI, MOVESTOQUE, OPERENTFUTURA, COMPORTOTALNF, CSTPIS,
            CSTCOFINS, ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB, BCPIS, BCCOFINS, VLRPIS, VLRCOFINS,
            TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, VLRUNITTABELA, VLRVENDAMINIMO,
            CSOSN, CHAVETABPISCOFINS, CHAVELOTEPROD, CHAVEDPTOESTOQUE, CODENQIPI, CHAVETABELAPRECO,
            TIPOPROMOCAO, CHAVESPRODPROMO, DESCRCOMPLEMENT, CODBENEF, BASEIVA, CHAVECLASSTRIB, ALIQCBS,
            ALIQIBSUF, ALIQIBSMUN, VLRCBS, VLRIBSUF, VLRIBSMUN, VLRCBSDIF, VLRIBSDIFUF, VLRIBSDIFMUN)
        SELECT 1, :ECHAVEEMP, :AUTOINCPED, I.CHAVEPRODUTO,
            I.CODPRODUTO, I.PRODUTO, I.CHAVEUNIDADE, I.QTDE, I.VLRUNIT,
            I.DESCPORC, I.DESCVLR, I.VLRDESCGLOBAL, I.CHAVETRIBUTACAO, I.VLRTOTAL, I.VLRSUBTOTAL,
            CASE WHEN :EVENDANAOPRESENCIAL = 'N' THEN T.ALIQUOTADE ELSE
            (SELECT TUF.ALIQUOTA FROM TRIBUTACAOPORUF TUF
            WHERE TUF.ORIGEM=:UFEMP AND TUF.DESTINO=:UFCLI) END,
            CASE WHEN :EVENDANAOPRESENCIAL = 'N' THEN T.ALIQUOTADE ELSE
            (SELECT TUF.ALIQUOTA FROM TRIBUTACAOPORUF TUF
            WHERE TUF.ORIGEM=:UFEMP AND TUF.DESTINO=:UFCLI) END,
            CASE WHEN :EVENDANAOPRESENCIAL = 'N' THEN T.ALIQUOTADE ELSE
            (SELECT TUF.ALIQUOTA FROM TRIBUTACAOPORUF TUF
            WHERE TUF.ORIGEM=:UFEMP AND TUF.DESTINO=:UFCLI) END,
            CASE WHEN (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('30','40','41','50','60')) OR (T.ALIQUOTADE=0) THEN 0 ELSE I.VLRTOTAL*((1-T.PERCRED/100)) END,
            CASE WHEN (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('30','40','41','50','60')) OR (T.ALIQUOTADE=0) THEN 0 ELSE I.VLRTOTAL*((T.ALIQUOTADE * (1-T.PERCRED/100))/100) END,
            T.CODIGO, I.UN, I.VLRUNITCOMDESC,
            I.CHAVECLASSFISCAL, I.VLRUNITORIGINAL, :ENL, :ECHAVECFOPPROD, 12, I.PRECOCUSTO, I.CSTIPI, I.IPI, I.BASECALCIPI, I.VLRIPI, I.MOVESTOQUE,
            I.OPERENTFUTURA, I.COMPORTOTALNF, I.CSTPIS, I.CSTCOFINS, I.ALIQPIS, I.ALIQCOFINS, I.VLRPISTRIB, I.VLRCOFINSTRIB, I.BCPIS, I.BCCOFINS,
            I.VLRPIS, I.VLRCOFINS, I.TIPOSENHADESC, I.CHAVEUSUARIOAUTORDESC, PV.PRECOVENDA, PV.PRECOVENDAMINIMO,
            CASE WHEN :EREGIMETRIB <> 2 THEN CASE WHEN :PESSOA=0 AND :VIERG NOT IN ('','ISENTO') THEN T.CODIGOSOSN ELSE CASE WHEN T.CODIGOSOSN = '101' THEN '102' ELSE T.CODIGOSOSN END END ELSE NULL END, I.CHAVETABPISCOFINS,
            I.CHAVELOTEPROD, :VCHAVEDPTOESTOQUE, GP.CODENQIPI, I.CHAVETABELAPRECO,
            I.TIPOPROMOCAO, I.CHAVESPRODPROMO, CASE WHEN (COALESCE(LP.CHAVE, 0) > 0) THEN 'LOTE(S)/NUM. SERIE:' || LP.LOTE ELSE '' END, CASE WHEN COALESCE(:VCODBENEF,'') = '' THEN P.CODBENEF ELSE :VCODBENEF END AS CODBENEF,
            I.BASEIVA, I.CHAVECLASSTRIB, I.ALIQCBS, I.ALIQIBSUF, I.ALIQIBSMUN, I.VLRCBS, I.VLRIBSUF, I.VLRIBSMUN, I.VLRCBSDIF, I.VLRIBSDIFUF, I.VLRIBSDIFMUN
        FROM ITENSNFSAIDA I
        INNER JOIN PRODUTO P ON (I.CHAVEPRODUTO=P.CHAVE) AND CASE WHEN :VPDVSOMARVDAPROD44F = 0 THEN (P.ATIVO <> 3) ELSE 1=1 END
        LEFT JOIN LOTEPRODUTOS LP ON (LP.CHAVE=I.CHAVELOTEPROD)
        INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO=I.CHAVEPRODUTO AND PC.CHAVEEMPRESA=:EPCCHAVEEMP
        INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=I.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:EPVCHAVEEMP) AND (PV.CHAVETABELAPRECO=I.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        INNER JOIN TRIBUTACAO T ON (CASE WHEN :VCHAVETRIBOPERFISC > 0 THEN :VCHAVETRIBOPERFISC ELSE I.CHAVETRIBUTACAO END = T.CHAVE)
        INNER JOIN UNIDADE U ON (I.CHAVEUNIDADE=U.CHAVE)
        INNER JOIN CONFIG C ON I.CHAVEEMPRESA=C.CHAVEEMPRESA
        INNER JOIN GRUPOFISCAL GP ON (CASE WHEN :PESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END = GP.CHAVE)
        WHERE (I.ATIVO=1) AND (CHAVENFSAIDA=:VCHAVENFSAIDA)
        ORDER BY I.CHAVE;
        UPDATE NFSAIDA SET NFVINCULADA='S'
        WHERE CHAVE IN (:VCHAVENFSAIDA);
   END
        INSERT INTO RASTREARDOC(ATIVO, CHAVEEMPRESA, CHAVENFORIGEM, CHAVEPEDDESTINO, DATAHORA, CHAVEUSUARIO)
        VALUES(1,:ECHAVEEMP, :VCHAVENFSAIDA, :AUTOINCPED, CURRENT_TIMESTAMP, :ECHAVEUSUARIO);
        UPDATE PEDIDOSAIDA SET
        DESCVLRPROD  = COALESCE(DESCVLRPROD,0) + CASE :VVLRTOTALPROD WHEN 0 THEN 0 ELSE :VTOTALDESC * :VPORCPRODNF / 100 END,
        DESCPORCPROD = COALESCE(DESCPORCPROD,0) + CASE :VVLRTOTALPROD WHEN 0 THEN 0 ELSE :VPORCDESCNF END,
        TOTALPRODUTO  = COALESCE(TOTALPRODUTO,0) + :VVLRTOTALPROD,
        DESPACESSORIA = DESPACESSORIA + :VTOTALACRESC,
        TIPOSENHADESCPROD = :VTIPOSENHADESCONTO,
        CHAVEUSUARIOAUTORDESCPROD = :VCHAVEUSUARIOAUTORDESC,
        CHAVEUSUARIOFECHOU = :ECHAVEUSUARIO,
        ALIQUOTAISS = CASE WHEN :EREGIMETRIB = 2 THEN
        (SELECT COALESCE(CID.ISS,0) FROM EMPRESA E
         INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
         WHERE E.CHAVE=:ECHAVEEMP) ELSE
        (SELECT COALESCE(ALIQISSSIMPLESNACIONAL,0) FROM EMPRESA WHERE CHAVE=:ECHAVEEMP) END
        WHERE CHAVE = :AUTOINCPED;
        EXECUTE PROCEDURE CARREGARMSGCOMPLDOCFISC (:AUTOINCPED);
   
   
       SELECT SUM(COALESCE(BASEICMS,0)), SUM(COALESCE(VLRICMS,0)), SUM(COALESCE(BASEIVA,0)),
       SUM(COALESCE(VLRCBS,0)), SUM(COALESCE(VLRIBSUF,0)), SUM(COALESCE(VLRIBSMUN,0)),
       SUM(COALESCE(VLRCBSDIF,0)), SUM(COALESCE(VLRIBSDIFUF,0)), SUM(COALESCE(VLRIBSDIFMUN,0))
       FROM ITENSPEDSAIDA
       WHERE CHAVEPEDIDO =:AUTOINCPED
       INTO :VBASEICMS, :VTOTALICMS, :VBASEIVA, :VVLRCBS, :VVLRIBSUF, :VVLRIBSMUN,
       :VVLRCBSDIF, :VVLRIBSDIFUF, :VVLRIBSDIFMUN;
    
       UPDATE PEDIDOSAIDA SET
           BASECALCULOICMS= :VBASEICMS,
           VLRICMS= :VTOTALICMS,
           BASEIVA = :VBASEIVA,
           VLRCBS = :VVLRCBS,
           VLRIBSUF = :VVLRIBSUF,
           VLRIBSMUN = :VVLRIBSMUN,
           VLRCBSDIF = :VVLRCBSDIF,
           VLRIBSDIFUF = :VVLRIBSDIFUF,
           VLRIBSDIFMUN = :VVLRIBSDIFMUN,
           TOTALPEDIDO= DESPACESSORIA + TOTALPRODUTO,
           OBS = :EOBS,
           AGRUPADO='S',
           DESCPORCPROD = CASE WHEN TOTALPRODUTO > 0 THEN (DESCVLRPROD * 100) / (TOTALPRODUTO+DESCVLRPROD) ELSE 0 END,
           DESCPORCSERVICO = CASE WHEN TOTALSERVICO > 0 THEN (DESCPORCSERVICO * 100) / (TOTALSERVICO+DESCPORCSERVICO) ELSE 0 END
       WHERE CHAVE=:AUTOINCPED;
       IF (:EAGRUPAITENS = 'S') THEN
            EXECUTE PROCEDURE AGRUPAITENSPEDSAIDA(:ECHAVEEMP, :AUTOINCPED, :EPCCHAVEEMP, :EPVCHAVEEMP);
       SNOVACHAVEPEDPROD = :AUTOINCPED;
END^


ALTER PROCEDURE ORDEMSERVICOGERAPS (
    CHAVEOS INTEGER,
    CHAVEEMPPS INTEGER,
    PRODUTOCUSTOCHAVEEMP INTEGER,
    PRODUTOVENDACHAVEEMP INTEGER,
    CHAVEUSUARIO INTEGER,
    GERARPEDPRODUTO CHAR(1),
    ENLATUALSERVICO DOUBLE PRECISION)
RETURNS (
    PEDIDOSERVICO VARCHAR(10),
    PEDIDOPRODUTO VARCHAR(10),
    SCHAVEPEDPROD INTEGER)
AS
declare variable ALIQISSFINAL numeric(18,4);
declare variable PERCREDST numeric(18,6);
declare variable CHAVESERIENFPADRAO integer;
declare variable NUMEROOS varchar(10);
declare variable CHAVESERIEEXTRA integer;
declare variable CTRLDPTOESTOQUE char(1);
declare variable PRECOUNITARIO numeric(18,6);
declare variable CHAVEOPERFISCSERV integer;
declare variable BASEIPI numeric(18,6);
declare variable SOMARBCPISCOFINSSERV numeric(18,6);
declare variable BCPISCOFINSSERV numeric(18,6);
declare variable BCPISCOFINSPROD numeric(18,6);
declare variable SOMARBCPISCOFINS numeric(18,6);
declare variable SOMARTOTCOFINS numeric(18,6);
declare variable SOMARTOTPIS numeric(18,6);
declare variable VLRCOFINSPROD numeric(18,6);
declare variable VLRPISPROD numeric(18,6);
declare variable SOMARVLRCOFINS numeric(18,6);
declare variable SOMARVLRPIS numeric(18,6);
declare variable VLRCOFINSSERV numeric(18,6);
declare variable VLRPISSERV numeric(18,6);
declare variable REGIMETRIB smallint;
declare variable CHAVEOPERFISCPROD integer;
declare variable CHAVEPEDSERV integer;
declare variable CHAVEPEDPROD integer;
declare variable NROPEDIDOSERV varchar(10);
declare variable NROPEDIDOPROD varchar(10);
declare variable GERAR2NFS smallint; /* 0-NAO, 1-SIM */
declare variable TIPONFSERIEPADRAO smallint;
declare variable CHAVEOPERFISCDOC integer;
declare variable PODEGERAR2NF smallint; /* 0-NAO, 1-SIM */
declare variable UFEMP char(2);
declare variable UFCLI char(2);
declare variable CHAVEITEMPROD integer;
declare variable SOMABASEICMS numeric(18,6);
declare variable SOMAVLRICMS numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable CHAVEITEM integer;
declare variable QTDE numeric(14,3);
declare variable ICMSTRIB numeric(7,2);
declare variable ICMSITEM numeric(7,2);
declare variable CST char(5);
declare variable PERCRED numeric(15,6);
declare variable VLRTOTALITEM numeric(18,6);
declare variable BASEICMSITEM numeric(18,6);
declare variable VLRICMSITEM numeric(18,6);
declare variable BASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable BASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable IPI numeric(7,2);
declare variable REDUCAOMVA numeric(7,2);
declare variable MVA numeric(7,2);
declare variable SOMARBCIPI numeric(18,6);
declare variable NLATUALSERVICO double precision;
declare variable PESSOA integer;
declare variable IERG varchar(20);
declare variable MVAAJUSTADO numeric(7,2);
declare variable VLRIPITRIB numeric(18,6);
declare variable VLRPAUTA numeric(18,6);
declare variable CHAVEUNIDADE integer;
declare variable NLATUAL float;
declare variable TOTALPRODUTO numeric(18,6);
declare variable TOTALSERVICO numeric(18,6);
declare variable SOMARTOTALSERVICO numeric(18,6);
declare variable SOMARTOTALPRODUTO numeric(18,6);
declare variable VTIPOPGTO smallint;
declare variable VNEWCHAVEITEM integer;
declare variable VDESCACUMULADO numeric(18,6);
DECLARE VARIABLE VSTREQUIP VARCHAR(20);
BEGIN
    SOMABASEICMS = 0;
    SOMAVLRICMS  = 0;
    SOMABASEICMSSUBSTTRIBRETIDO = 0;
    SOMAVLRICMSSUBSTTRIBRETIDO  = 0;
    SOMABASEICMSSUBSTTRIBDESTAC = 0;
    SOMAVLRICMSSUBSTTRIBDESTAC  = 0;
    SOMARVLRPIS =0;
    SOMARVLRCOFINS =0;
    SOMARTOTPIS =0;
    SOMARTOTCOFINS =0;
    SOMARBCPISCOFINS =0;
    SOMARBCPISCOFINSSERV =0;
    SOMARBCIPI  = 0;
    SOMARTOTALSERVICO = 0;
    SOMARTOTALPRODUTO = 0;
    CHAVESERIEEXTRA = 0;
    PEDIDOPRODUTO = '';
    PEDIDOSERVICO = '';
    CHAVEPEDPROD =0;
    SELECT VALOR FROM CONFIGCAMPOS WHERE ATIVO=1 AND CAMPO = 'CONTROLARDPTOESTOQUE' AND CHAVEEMPRESA=:CHAVEEMPPS
    INTO :CTRLDPTOESTOQUE;
    SELECT
    CASE VALOR
    WHEN 0 THEN 'EQUIP'
    WHEN 1 THEN 'VEICULO'
    WHEN 2 THEN 'OFTAMOLOGISTA'
    WHEN 3 THEN 'VETERINARIO'
    END
    FROM CONFIGCAMPOS WHERE ATIVO=1 AND CAMPO = 'OSSEGMENTO' AND CHAVEEMPRESA=:CHAVEEMPPS
    INTO :VSTREQUIP;
    SELECT CASE WHEN COALESCE(VALOR, '') = '' THEN NULL ELSE VALOR END FROM CONFIGCAMPOS WHERE ATIVO=1 AND INDICE = 307 AND CHAVEEMPRESA=:CHAVEEMPPS
    INTO :CHAVESERIENFPADRAO;
    SELECT CASE WHEN (COALESCE(OS.TOTALPRODUTO,0) > 0) AND COALESCE(OS.TOTALSERVICO,0) > 0 THEN 1 ELSE 0 END,
    OS.CHAVECFOPOPERFISCAIS, OS.NL, OS.ORDEM, OS.TIPOPAGAMENTO
    FROM ORDEMSERVICO OS
    WHERE OS.ATIVO=1 AND OS.CHAVE=:CHAVEOS
    INTO :PODEGERAR2NF, :CHAVEOPERFISCDOC, :NLATUAL, :NUMEROOS, :VTIPOPGTO;
    NLATUALSERVICO= :NLATUAL;
    SELECT S1.TIPONOTAFISCAL,
    CASE E.REGIMETRIBUT WHEN 2 THEN CID.ISS ELSE E.ALIQISSSIMPLESNACIONAL END, E.REGIMETRIBUT,
    (SELECT PEDIDO FROM GETULTIMOPEDIDO (:CHAVEEMPPS))
    FROM CONFIG CO
    LEFT JOIN SERIENF S1 ON S1.CHAVE = :CHAVESERIENFPADRAO AND S1.ATIVO=1
    INNER JOIN EMPRESA E ON E.CHAVE = CO.CHAVEEMPRESA
    INNER JOIN CIDADE CID ON E.CHAVECIDADE = CID.CHAVE
    WHERE CO.ATIVO=1 AND CO.CHAVEEMPRESA=:CHAVEEMPPS
    INTO :TIPONFSERIEPADRAO, :ALIQISSFINAL, :REGIMETRIB,
    :NROPEDIDOPROD;
    IF (:PODEGERAR2NF = 1) THEN BEGIN
       IF (:TIPONFSERIEPADRAO=0) THEN BEGIN
          SELECT FIRST 1 COALESCE(CHAVE,0) FROM SERIENF
          WHERE ATIVO=1 AND (TIPONOTAFISCAL=2)
          ORDER BY CHAVE DESC
          INTO :CHAVESERIEEXTRA;
       END
       IF (:TIPONFSERIEPADRAO=2) THEN BEGIN
          SELECT FIRST 1 COALESCE(CHAVE,0) FROM SERIENF
          WHERE ATIVO=1 AND TIPONOTAFISCAL = 0
          ORDER BY CHAVE DESC
          INTO :CHAVESERIEEXTRA;
       END
      IF ((CHAVESERIEEXTRA = 0) AND (:GERARPEDPRODUTO = 'N')) THEN BEGIN
          SELECT FIRST 1 COALESCE(CHAVE,0) FROM SERIENF
          WHERE ATIVO=1 AND (TIPONOTAFISCAL=1)
          ORDER BY CHAVE DESC
          INTO :CHAVESERIEEXTRA;
      END
       IF (CHAVESERIEEXTRA > 0) THEN BEGIN
        GERAR2NFS = 1;
        IF (:GERARPEDPRODUTO = 'N') THEN BEGIN
            NROPEDIDOSERV= :NROPEDIDOPROD;
        END ELSE BEGIN
            SELECT PEDIDO FROM GETULTIMOPEDIDO(:CHAVEEMPPS)
            INTO :NROPEDIDOSERV;
        END
        PEDIDOSERVICO= :NROPEDIDOSERV;
       END ELSE
        GERAR2NFS = 0;
    END ELSE
        GERAR2NFS = 0;
    /*--1 - VAI GERAR 2 NFS / 0 - VAI GERAR 1 NF
    IF ((:PODEGERAR2NF > 0) AND
       (((:TIPONFSERIEEXTRA=0) AND (:TIPONFSERIEPADRAO=2)) OR
       ( (:TIPONFSERIEEXTRA=2) AND (:TIPONFSERIEPADRAO=0)))) THEN BEGIN
        GERAR2NFS = 1;
        IF (:GERARPEDPRODUTO = 'N') THEN BEGIN
            NROPEDIDOSERV= :NROPEDIDOPROD;
        END ELSE BEGIN
            SELECT PEDIDO FROM GETULTIMOPEDIDO(:CHAVEEMPPS)
            INTO :NROPEDIDOSERV;
        END
        PEDIDOSERVICO= :NROPEDIDOSERV;
    END ELSE
        GERAR2NFS = 0; */
    SELECT CID.UF FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE E.CHAVE= :CHAVEEMPPS
    INTO :UFEMP;
    
    SELECT CID.UF, C.IERG, C.PESSOA, C.REDUCAOMVA FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN ORDEMSERVICO OS ON C.CHAVE=OS.CHAVECLIFOR
    WHERE OS.CHAVE=:CHAVEOS
    INTO :UFCLI, :IERG, :PESSOA, :REDUCAOMVA;
    IF ((:PESSOA = 0) AND (:IERG IN ('ISENTO',''))) THEN
        PESSOA = 1;
    IF (:GERARPEDPRODUTO = 'S') THEN BEGIN
        CHAVEPEDPROD = GEN_ID(GEN_PEDIDOSAIDA_ID,1);
        PEDIDOPRODUTO= :NROPEDIDOPROD;
        SCHAVEPEDPROD= :CHAVEPEDPROD;
    END
    IF (:GERAR2NFS =1) THEN BEGIN
        IF (:GERARPEDPRODUTO = 'S') THEN BEGIN
            CHAVEOPERFISCPROD = 0;
            SELECT FIRST 1 CF.CHAVE
            FROM ORDEMSERVICO OS
            INNER JOIN CFOPOPERFISCAIS CF ON (CF.CHAVECFOPPRODDE = OS.CHAVECFOPPROD) OR (CF.CHAVECFOPPRODFE = OS.CHAVECFOPPROD)
            WHERE (OS.CHAVE =:CHAVEOS) AND (CF.ATIVO=1)
            AND (COALESCE(OS.TOTALPRODUTO,0) > 0) AND (COALESCE(OS.TOTALSERVICO,0) > 0)
            AND (COALESCE(CF.CHAVECFOPSERVDE,0)=0) AND (COALESCE(CF.CHAVECFOPSERVFE,0) = 0)
            ORDER BY CF.CHAVE
            INTO :CHAVEOPERFISCPROD;
            IF ((CHAVEOPERFISCPROD=0) OR (CHAVEOPERFISCPROD IS NULL))   THEN
                CHAVEOPERFISCPROD =:CHAVEOPERFISCDOC;
         END
        CHAVEOPERFISCSERV = 0;
        SELECT FIRST 1 CF.CHAVE
        FROM ORDEMSERVICO OS
        INNER JOIN CFOPOPERFISCAIS CF ON (CF.CHAVECFOPSERVDE = OS.CHAVECFOPSERV) OR (CF.CHAVECFOPSERVFE = OS.CHAVECFOPSERV)
        WHERE (OS.CHAVE =:CHAVEOS) AND (CF.ATIVO=1)
        AND (COALESCE(OS.TOTALPRODUTO,0) > 0) AND (COALESCE(OS.TOTALSERVICO,0) > 0)
        AND (COALESCE(CF.CHAVECFOPPRODDE,0) = 0) AND (COALESCE(CF.CHAVECFOPPRODFE,0)=0)
        ORDER BY CF.CHAVE
        INTO :CHAVEOPERFISCSERV;
        IF ((CHAVEOPERFISCSERV=0) OR (CHAVEOPERFISCSERV IS NULL))   THEN
            CHAVEOPERFISCSERV =:CHAVEOPERFISCDOC;
        IF (:GERARPEDPRODUTO = 'S') THEN BEGIN
            /* GERA PEDIDO DE PRODUTO */
            INSERT INTO PEDIDOSAIDA
                (CHAVE, CHAVEEMPRESA, PEDIDO, CHAVECLIFOR, CHAVECFOPOPERFISCAIS,
                CHAVECFOPPROD, NL, QTDEVOLUME,
                OBS, DATAPEDIDO, HORAPEDIDO, STATUS, CHAVEORDEMSERVICO,
                FRETE, FRETEPORCONTA, TOTALIPI, TIPOPAGAMENTO, CHAVEUSUARIOINICIOU,
                CHAVEPLANOCONTA, CHAVECENTROCUSTO, CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CHAVETABELADESCONTOS,
                CHAVECONDPGTO, FATURA, DESCPORCPROD, DESCVLRPROD, ACRESCPORCPROD, ACRESCVLRPROD,
                CHAVEUSUARIOAUTORDESCPROD, TIPOSENHADESCPROD, FORMAPGTO)
            SELECT :CHAVEPEDPROD, :CHAVEEMPPS, :NROPEDIDOPROD, OS.CHAVECLIFOR, :CHAVEOPERFISCPROD,
                OS.CHAVECFOPPROD, :NLATUAL, 0,
                SUBSTRING(OS.OBS ||COALESCE(' ' || :VSTREQUIP || ': '||E.CODIGO||' - '||E.DESCRICAO||' ('||E.IDENTIFICACAO||')',' ')||
                CASE WHEN OS.KMATUAL <> 0 THEN ' KM INICIAL: '||CAST(OS.KMATUAL AS NUMERIC(18,1)) ELSE '' END||CASE WHEN OS.KMFINAL <> 0 THEN ' KM FINAL: '||CAST(OS.KMFINAL AS NUMERIC(18,1)) ELSE '' END FROM 1 FOR 1000),
                CURRENT_DATE, CURRENT_TIME, 0, OS.CHAVE,
                OS.FRETE, CASE WHEN OS.FRETE=0 THEN 0 ELSE 1 END AS FRETEPORCONTA, OS.TOTALIPI, CASE TIPOPAGAMENTO WHEN 2 THEN 0 ELSE TIPOPAGAMENTO END, :CHAVEUSUARIO,
                OS.CHAVEPLANOCONTA, OS.CHAVECENTROCUSTO, OS.CHAVECTABANCARIA, OS.CHAVEOPERACOESTITULOS, OS.CHAVETABELADESCONTOS,
                CASE TIPOPAGAMENTO WHEN 2 THEN NULL ELSE CHAVECONDPGTO END,
                CASE TIPOPAGAMENTO WHEN 2 THEN NULL ELSE FATURA END, OS.DESCPORCPROD, OS.DESCVLRPROD, 0, 0,
                OS.CHAVEUSUARIOAUTORDESCPROD, OS.TIPOSENHADESCPROD, OS.FORMAPGTO
            FROM ORDEMSERVICO OS
            LEFT JOIN EQUIPAMENTOS E ON E.CHAVE=OS.CHAVEEQUIPAMENTO AND E.ATIVO=1
            WHERE OS.CHAVE=:CHAVEOS;
        END
        /* GERA PEDIDO DE SERVICO */
        NLATUALSERVICO = :ENLATUALSERVICO;
        CHAVEPEDSERV = GEN_ID(GEN_PEDIDOSAIDA_ID,1);
        INSERT INTO PEDIDOSAIDA
            (CHAVE, CHAVEEMPRESA, PEDIDO, CHAVECLIFOR, CHAVECFOPOPERFISCAIS,
            CHAVECFOPSERV, NL, QTDEVOLUME,
            TOTALPEDIDO, TOTALSERVICO, TOTALPRODUTO, TOTALISS, ALIQUOTAISS,
            BASEISS, OBS, DATAPEDIDO, HORAPEDIDO, STATUS, CHAVEORDEMSERVICO,
            TIPOPAGAMENTO, FRETEPORCONTA, CHAVEUSUARIOINICIOU,
            CHAVEPLANOCONTA, CHAVECENTROCUSTO, CHAVETABELADESCONTOS,
            CHAVECONDPGTO, FATURA, DESCPORCSERVICO, DESCVLRSERVICO, CHAVEUSUARIOAUTORDESCSERV,
            TIPOSENHADESCSERV, FORMAPGTO)
        SELECT :CHAVEPEDSERV, :CHAVEEMPPS, :NROPEDIDOSERV, OS.CHAVECLIFOR, :CHAVEOPERFISCSERV,
            OS.CHAVECFOPSERV, :NLATUALSERVICO, 0,
            OS.TOTALSERVICO, OS.TOTALSERVICO, OS.TOTALPRODUTO, (OS.TOTALSERVICO * :ALIQISSFINAL)/100, :ALIQISSFINAL,
            OS.TOTALSERVICO,
            SUBSTRING(OS.OBS||COALESCE(' ' || :VSTREQUIP || ': '||E.CODIGO||' - '||E.DESCRICAO||' ('||E.IDENTIFICACAO||')',' ')||
            CASE WHEN OS.KMATUAL <> 0 THEN ' KM INICIAL: '||CAST(OS.KMATUAL AS NUMERIC(18,1)) ELSE '' END||CASE WHEN OS.KMFINAL <> 0 THEN ' KM FINAL: '||CAST(OS.KMFINAL AS NUMERIC(18,1)) ELSE '' END FROM 1 FOR 1000),
            CURRENT_DATE, CURRENT_TIME, 0, OS.CHAVE,
            CASE TIPOPAGAMENTO WHEN 2 THEN 0 ELSE TIPOPAGAMENTO END, 0, :CHAVEUSUARIO,
            OS.CHAVEPLANOCONTA, OS.CHAVECENTROCUSTO, OS.CHAVETABELADESCONTOS,
            CASE TIPOPAGAMENTO WHEN 2 THEN NULL ELSE CHAVECONDPGTO END,
            CASE TIPOPAGAMENTO WHEN 2 THEN NULL ELSE FATURA END, OS.DESCPORCSERVICO, OS.DESCVLRSERVICO, OS.CHAVEUSUARIOAUTORDESCSERV,
            OS.TIPOSENHADESCSERV, OS.FORMAPGTO
        FROM ORDEMSERVICO OS
        LEFT JOIN EQUIPAMENTOS E ON E.CHAVE=OS.CHAVEEQUIPAMENTO AND E.ATIVO=1
        WHERE OS.CHAVE=:CHAVEOS;
        INSERT INTO RASTREARDOC(ATIVO, CHAVEEMPRESA, CHAVEOSORIGEM, CHAVEPEDDESTINO, DATAHORA, CHAVEUSUARIO, OBS)
        VALUES(1,:CHAVEEMPPS, :CHAVEOS, :CHAVEPEDPROD, CURRENT_TIMESTAMP, :CHAVEUSUARIO, 'PEDIDO COM PRODUTO');
    
        INSERT INTO RASTREARDOC(ATIVO, CHAVEEMPRESA, CHAVEOSORIGEM, CHAVEPEDDESTINO, DATAHORA, CHAVEUSUARIO, OBS)
        VALUES(1,:CHAVEEMPPS, :CHAVEOS, :CHAVEPEDSERV, CURRENT_TIMESTAMP, :CHAVEUSUARIO, 'PEDIDO COM SERVICO');
    END ELSE BEGIN
        CHAVEPEDSERV =:CHAVEPEDPROD;
        INSERT INTO PEDIDOSAIDA
            (CHAVE, CHAVEEMPRESA, PEDIDO, CHAVECLIFOR, CHAVECFOPOPERFISCAIS,
            CHAVECFOPPROD, CHAVECFOPSERV, NL, QTDEVOLUME,
            TOTALPRODUTO, TOTALPEDIDO, TOTALSERVICO, TOTALISS, ALIQUOTAISS,
            BASEISS, OBS, DATAPEDIDO, HORAPEDIDO, STATUS, CHAVEORDEMSERVICO,
            FRETE, FRETEPORCONTA, TOTALIPI, TIPOPAGAMENTO, CHAVEUSUARIOINICIOU,
            CHAVEPLANOCONTA, CHAVECENTROCUSTO, CHAVECTABANCARIA, CHAVEOPERACOESTITULOS, CHAVETABELADESCONTOS,
            CHAVECONDPGTO, FATURA, DESCPORCPROD, DESCVLRPROD, DESCPORCSERVICO, DESCVLRSERVICO, ACRESCPORCPROD, ACRESCVLRPROD,
            CHAVEUSUARIOAUTORDESCPROD, TIPOSENHADESCPROD, CHAVEUSUARIOAUTORDESCSERV, TIPOSENHADESCSERV, FORMAPGTO)
        SELECT :CHAVEPEDPROD, :CHAVEEMPPS, :NROPEDIDOPROD, OS.CHAVECLIFOR, OS.CHAVECFOPOPERFISCAIS,
            OS.CHAVECFOPPROD, OS.CHAVECFOPSERV, :NLATUAL, 0,
            OS.TOTALPRODUTO, (OS.TOTALOS-OS.VLRACRESCIMO), OS.TOTALSERVICO, (OS.TOTALSERVICO * :ALIQISSFINAL)/100, :ALIQISSFINAL,
            OS.TOTALSERVICO,
            SUBSTRING(OS.OBS||COALESCE(' ' || :VSTREQUIP || ': '||E.CODIGO||' - '||E.DESCRICAO||' ('||E.IDENTIFICACAO||')',' ')||
            CASE WHEN OS.KMATUAL <> 0 THEN ' KM INICIAL: '||CAST(OS.KMATUAL AS NUMERIC(18,1)) ELSE '' END||CASE WHEN OS.KMFINAL <> 0 THEN ' KM FINAL: '||CAST(OS.KMFINAL AS NUMERIC(18,1)) ELSE '' END FROM 1 FOR 1000),
            CURRENT_DATE, CURRENT_TIME, 0, OS.CHAVE,
            OS.FRETE, CASE WHEN OS.FRETE=0 THEN 0 ELSE 1 END AS FRETEPORCONTA, OS.TOTALIPI,
            CASE TIPOPAGAMENTO WHEN 2 THEN 0 ELSE TIPOPAGAMENTO END, :CHAVEUSUARIO,
            OS.CHAVEPLANOCONTA, OS.CHAVECENTROCUSTO, OS.CHAVECTABANCARIA, OS.CHAVEOPERACOESTITULOS, OS.CHAVETABELADESCONTOS,
            CASE TIPOPAGAMENTO WHEN 2 THEN NULL ELSE CHAVECONDPGTO END,
            CASE TIPOPAGAMENTO WHEN 2 THEN NULL ELSE FATURA END, OS.DESCPORCPROD, OS.DESCVLRPROD, OS.DESCPORCSERVICO, OS.DESCVLRSERVICO, 0,0,
            OS.CHAVEUSUARIOAUTORDESCPROD, OS.TIPOSENHADESCPROD, OS.CHAVEUSUARIOAUTORDESCSERV, OS.TIPOSENHADESCSERV, OS.FORMAPGTO
        FROM ORDEMSERVICO OS
        LEFT JOIN EQUIPAMENTOS E ON E.CHAVE=OS.CHAVEEQUIPAMENTO AND E.ATIVO=1
        WHERE OS.CHAVE=:CHAVEOS;
        INSERT INTO RASTREARDOC(ATIVO, CHAVEEMPRESA, CHAVEOSORIGEM, CHAVEPEDDESTINO, DATAHORA, CHAVEUSUARIO)
        VALUES(1,:CHAVEEMPPS, :CHAVEOS, :CHAVEPEDPROD, CURRENT_TIMESTAMP, :CHAVEUSUARIO);
    END
    VDESCACUMULADO = 0;
    IF (:GERARPEDPRODUTO = 'S') THEN BEGIN
        IF (:UFCLI = :UFEMP) THEN BEGIN
            FOR SELECT IC.CHAVE FROM ITENSORDEMSERVICOPROD IC
            INNER JOIN PRODUTO P ON IC.CHAVEPRODUTO=P.CHAVE
            INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO=P.CHAVE AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
            INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=IC.CHAVETABELAPRECO) AND (PV.ATIVO=1)
            INNER JOIN CONFIG C ON IC.CHAVEEMPRESA=C.CHAVEEMPRESA
            INNER JOIN TRIBUTACAO T ON IC.CHAVETRIBUTACAO=T.CHAVE
            WHERE IC.ATIVO=1 AND IC.CHAVEOS=:CHAVEOS
            ORDER BY IC.CHAVE
            INTO :CHAVEITEMPROD
            DO BEGIN
                VNEWCHAVEITEM = GEN_ID(GEN_ITENSPEDSAIDA_ID,1);
                INSERT INTO ITENSPEDSAIDA
                    (CHAVE, CHAVEEMPRESA, CHAVEPEDIDO, CHAVEPRODUTO,
                    CODPRODUTO, PRODUTO,DESCRCOMPLEMENT, CHAVEUNIDADE, UN, QTDE, VLRUNIT,
                    CHAVETRIBUTACAO, CST, ICMS, ALIQICMSINTRA, ALIQICMSINTER, VLRSUBTOTAL, VLRTOTAL,
                    BASEICMS, VLRICMS,
                    DESCPORC, DESCVLR,
                    VLRUNITCOMDESC, PRECOCUSTO, VLRUNITORIGINAL, NL,
                    CSTIPI, IPI, BASECALCIPI,
                    VLRIPI, CHAVECFOP, CHAVECFOPOPERFISCAIS, MOVESTOQUE, OPERENTFUTURA, COMPORTOTALNF, MVA,
                    CSTPIS, CSTCOFINS, ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB,
                    BCPIS, BCCOFINS, VLRPIS, VLRCOFINS,
                    CHAVECLASSFISCAL, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC,
                    VLRUNITTABELA, VLRVENDAMINIMO, CSOSN, CHAVETABPISCOFINS, CHAVELOTEPROD, IPITRIB,
                    CHAVEDPTOESTOQUE, VLRACRESCGLOBAL, CODENQIPI, CHAVETABELAPRECO, CHAVEREGRAFISCAL,
                    TIPOPROMOCAO, CHAVESPRODPROMO, QTDEPROMOUSADAPROD, CHAVECLASSTRIB)
                SELECT :VNEWCHAVEITEM, :CHAVEEMPPS, :CHAVEPEDPROD, P.CHAVE,
                    P.CODIGO, IOS.PRODUTO, IOS.DESCRCOMPLEMENT, IOS.CHAVEUNIDADE, IOS.UN, IOS.QTDE, IOS.VLRUNIT,
                    IOS.CHAVETRIBUTACAO, T.CODIGO,
                    CASE WHEN COALESCE(IOS.ICMS,0) = 0 THEN
                    CASE WHEN  (:UFCLI = :UFEMP) OR (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('40','41','50','51','90','20')) THEN T.ALIQUOTADE ELSE
                    CASE WHEN SUBSTRING(T.CODIGO FROM 1 FOR 1) IN ('1','2','3','8') THEN 4 ELSE (SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU WHERE TU.ORIGEM=:UFEMP AND TU.DESTINO=:UFCLI)
                    END END ELSE IOS.ICMS END, CASE WHEN COALESCE(IOS.ALIQICMSINTRA,0) = 0 THEN T.ALIQUOTADE ELSE IOS.ALIQICMSINTRA END,
                    CASE WHEN  (:UFCLI = :UFEMP) OR (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('40','41','50','51','90','20')) THEN T.ALIQUOTADE ELSE
                    CASE WHEN SUBSTRING(T.CODIGO FROM 1 FOR 1) IN ('1','2','3','8') THEN 4 ELSE (SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU WHERE TU.ORIGEM=:UFEMP AND TU.DESTINO=:UFCLI)
                    END END,
                    IOS.VLRSUBTOTAL, IOS.VLRTOTAL,
                    0, 0,
                    IOS.DESCPORC, IOS.DESCVLR,
                    IOS.VLRUNIT - (IOS.VLRUNIT/100*IOS.DESCPORC),
                    PC.PRECOMEDIO, PV.PRECOVENDA, :NLATUAL,
                    CASE IOS.IPI WHEN 0 THEN '53' ELSE '50' END,
                    IOS.IPI, CASE IOS.IPI WHEN 0 THEN 0 ELSE IOS.VLRTOTAL END,
                    IOS.VLRIPI, IOS.CHAVECFOP, IOS.CHAVECFOPOPERFISCAIS, IOS.MOVESTOQUE, CF.ENTREGAFUTURA, CF.COMPORTOTALNF,
                    P.MVA - (P.MVA * CLI.REDUCAOMVA / 100), GP.CSTPIS, GP.CSTCOFINS,
                    (SELECT ALIQPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT ALIQCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VLRPISTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VLRCOFINSTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT BASE FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT BASE FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VALORPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VALORCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    P.CHAVECLASSFISCAL, IOS.TIPOSENHADESC, IOS.CHAVEUSUARIOAUTORDESC,
                    IOS.VLRUNITTABELA, IOS.VLRVENDAMINIMO, CASE WHEN :REGIMETRIB <> 2 THEN T.CODIGOSOSN ELSE NULL END, TC.CHAVE,
                    IOS.CHAVELOTEPROD, CASE WHEN IOS.IPI > 0 THEN '00' ELSE '' END,
                    CASE WHEN :CTRLDPTOESTOQUE = 'N' THEN COALESCE((SELECT VALOR FROM CONFIGCAMPOS WHERE INDICE = 134 AND CHAVEEMPRESA=:CHAVEEMPPS), IOS.CHAVEDPTOESTOQUE) ELSE  IOS.CHAVEDPTOESTOQUE END,
                    0, GP.CODENQIPI, IOS.CHAVETABELAPRECO, IOS.CHAVEREGRAFISCAL,
                    IOS.TIPOPROMOCAO, IOS.CHAVESPRODPROMO, IOS.QTDEPROMOUSADAPROD, CASE COALESCE(P.CHAVECLASSTRIB, 0) WHEN 0 THEN CFC.CHAVECLASSTRIB ELSE P.CHAVECLASSTRIB END AS CHAVECLASSTRIB
                FROM ITENSORDEMSERVICOPROD IOS
                INNER JOIN ORDEMSERVICO OS ON IOS.CHAVEOS = OS.CHAVE
                INNER JOIN CLIFOR CLI ON OS.CHAVECLIFOR = CLI.CHAVE
                INNER JOIN PRODUTO P ON IOS.CHAVEPRODUTO=P.CHAVE
                INNER JOIN UNIDADE UN ON UN.CHAVE = IOS.CHAVEUNIDADE
                INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO=P.CHAVE AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
                INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=IOS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
                INNER JOIN TRIBUTACAO T ON IOS.CHAVETRIBUTACAO=T.CHAVE
                INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = IOS.CHAVECFOPOPERFISCAIS
                INNER JOIN GRUPOFISCAL GP ON (CASE WHEN :PESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END = GP.CHAVE)
                LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = GP.CHAVETABELAPISCOFINS
                LEFT JOIN CLASSFISCAL CFC ON (P.CHAVECLASSFISCAL=CFC.CHAVE)
                WHERE IOS.CHAVE=:CHAVEITEMPROD AND IOS.ATIVO=1
                ORDER BY IOS.CHAVE;
                INSERT INTO PRODUTOVENDAPROMOHIST (ATIVO, CHAVEEMPRESA, CHAVEITEMPEDSAIDA, TIPOPROMOCAO, VALOR)
                SELECT ATIVO, CHAVEEMPRESA, :VNEWCHAVEITEM, TIPOPROMOCAO, VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMOS=:CHAVEITEMPROD);
                VDESCACUMULADO = :VDESCACUMULADO + COALESCE((SELECT VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMOS=:CHAVEITEMPROD)),0);
            END
        END ELSE BEGIN
            FOR SELECT IC.CHAVE FROM ITENSORDEMSERVICOPROD IC
            INNER JOIN PRODUTO P ON IC.CHAVEPRODUTO=P.CHAVE
            INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO=P.CHAVE AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
            INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=IC.CHAVETABELAPRECO) AND (PV.ATIVO=1)
            INNER JOIN CONFIG C ON IC.CHAVEEMPRESA=C.CHAVEEMPRESA
            INNER JOIN TRIBUTACAO T ON IC.CHAVETRIBUTACAO=T.CHAVE
            WHERE IC.ATIVO=1 AND IC.CHAVEOS=:CHAVEOS
            ORDER BY IC.CHAVE
            INTO :CHAVEITEMPROD DO BEGIN
                INSERT INTO ITENSPEDSAIDA
                    (CHAVE, CHAVEEMPRESA, CHAVEPEDIDO, CHAVEPRODUTO,
                    CODPRODUTO, PRODUTO, DESCRCOMPLEMENT, CHAVEUNIDADE, UN, QTDE, VLRUNIT,
                    CHAVETRIBUTACAO, CST, ICMS, ALIQICMSINTRA, ALIQICMSINTER, VLRSUBTOTAL, VLRTOTAL,
                    BASEICMS, VLRICMS,
                    DESCPORC, DESCVLR,
                    VLRUNITCOMDESC,
                    PRECOCUSTO, VLRUNITORIGINAL, NL,
                    CSTIPI, IPI, BASECALCIPI,
                    VLRIPI, CHAVECFOP, CHAVECFOPOPERFISCAIS, MOVESTOQUE, OPERENTFUTURA, COMPORTOTALNF, MVA, CSTPIS,
                    CSTCOFINS, ALIQPIS, ALIQCOFINS,VLRPISTRIB, VLRCOFINSTRIB,
                    BCPIS, BCCOFINS, VLRPIS, VLRCOFINS,
                    CHAVECLASSFISCAL, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC,
                    VLRUNITTABELA, VLRVENDAMINIMO, CSOSN, CHAVETABPISCOFINS,CHAVELOTEPROD, IPITRIB,
                    CHAVEDPTOESTOQUE, VLRACRESCGLOBAL, CODENQIPI, CHAVETABELAPRECO,CHAVEREGRAFISCAL,
                    TIPOPROMOCAO, CHAVESPRODPROMO, QTDEPROMOUSADAPROD, CHAVECLASSTRIB)
                SELECT :VNEWCHAVEITEM, :CHAVEEMPPS, :CHAVEPEDPROD, P.CHAVE,
                    P.CODIGO, IOS.PRODUTO,IOS.DESCRCOMPLEMENT, IOS.CHAVEUNIDADE, IOS.UN, IOS.QTDE, IOS.VLRUNIT,
                    IOS.CHAVETRIBUTACAO, T.CODIGO,
                    CASE WHEN COALESCE(IOS.ICMS,0) = 0 THEN
                    CASE WHEN  (:UFCLI = :UFEMP) OR (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('40','41','50','51','90','20')) THEN T.ALIQUOTADE ELSE
                    CASE WHEN SUBSTRING(T.CODIGO FROM 1 FOR 1) IN ('1','2','3','8') THEN 4 ELSE (SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU WHERE TU.ORIGEM=:UFEMP AND TU.DESTINO=:UFCLI)
                    END END ELSE IOS.ICMS END, CASE WHEN COALESCE(IOS.ALIQICMSINTRA,0) = 0 THEN T.ALIQUOTADE ELSE IOS.ALIQICMSINTRA END,
                    CASE WHEN COALESCE(IOS.ICMS,0) = 0 THEN
                    CASE WHEN  (:UFCLI = :UFEMP) OR (SUBSTRING(T.CODIGO FROM 2 FOR 2) IN ('40','41','50','51','90','20')) THEN T.ALIQUOTADE ELSE
                    CASE WHEN SUBSTRING(T.CODIGO FROM 1 FOR 1) IN ('1','2','3','8') THEN 4 ELSE (SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU WHERE TU.ORIGEM=:UFEMP AND TU.DESTINO=:UFCLI)
                    END END ELSE IOS.ICMS END,
                    IOS.VLRSUBTOTAL, IOS.VLRTOTAL,
                    0, 0,
                    IOS.DESCPORC, IOS.DESCVLR,
                    IOS.VLRUNIT - (IOS.VLRUNIT/100*IOS.DESCPORC),
                    PC.PRECOMEDIO, PV.PRECOVENDA, :NLATUAL,
                    CASE IOS.IPI WHEN 0 THEN '53' ELSE '50' END,
                    IOS.IPI, CASE IOS.IPI WHEN 0 THEN 0 ELSE IOS.VLRTOTAL END,
                    IOS.VLRIPI, IOS.CHAVECFOP, IOS.CHAVECFOPOPERFISCAIS, IOS.MOVESTOQUE, CF.ENTREGAFUTURA, CF.COMPORTOTALNF,
                    P.MVA - (P.MVA * CLI.REDUCAOMVA / 100), GP.CSTPIS, GP.CSTCOFINS,
                    (SELECT ALIQPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT ALIQCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VLRPISTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VLRCOFINSTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT BASE FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT BASE FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VALORPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    (SELECT VALORCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
                    P.CHAVECLASSFISCAL, IOS.TIPOSENHADESC, IOS.CHAVEUSUARIOAUTORDESC,
                    IOS.VLRUNITTABELA, IOS.VLRVENDAMINIMO, CASE WHEN :REGIMETRIB <> 2 THEN T.CODIGOSOSN ELSE NULL END, TC.CHAVE,
                    IOS.CHAVELOTEPROD, CASE WHEN IOS.IPI > 0 THEN '00' ELSE '' END,
                    IOS.CHAVEDPTOESTOQUE, 0, GP.CODENQIPI, IOS.CHAVETABELAPRECO, IOS.CHAVEREGRAFISCAL,
                    IOS.TIPOPROMOCAO, IOS.CHAVESPRODPROMO, IOS.QTDEPROMOUSADAPROD, CASE COALESCE(P.CHAVECLASSTRIB, 0) WHEN 0 THEN CFC.CHAVECLASSTRIB ELSE P.CHAVECLASSTRIB END AS CHAVECLASSTRIB
                FROM ITENSORDEMSERVICOPROD IOS
                INNER JOIN ORDEMSERVICO OS ON IOS.CHAVEOS = OS.CHAVE
                INNER JOIN CLIFOR CLI ON OS.CHAVECLIFOR = CLI.CHAVE
                INNER JOIN PRODUTO P ON IOS.CHAVEPRODUTO=P.CHAVE
                INNER JOIN UNIDADE UN ON UN.CHAVE = IOS.CHAVEUNIDADE
                INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO=P.CHAVE AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
                INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=IOS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
                INNER JOIN TRIBUTACAO T ON IOS.CHAVETRIBUTACAO=T.CHAVE
                INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = IOS.CHAVECFOPOPERFISCAIS
                INNER JOIN GRUPOFISCAL GP ON (CASE WHEN :PESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END = GP.CHAVE)
                LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = GP.CHAVETABELAPISCOFINS
                LEFT JOIN CLASSFISCAL CFC ON (P.CHAVECLASSFISCAL=CFC.CHAVE)
                WHERE IOS.CHAVE=:CHAVEITEMPROD AND IOS.ATIVO=1
                ORDER BY IOS.CHAVE;
                INSERT INTO PRODUTOVENDAPROMOHIST (ATIVO, CHAVEEMPRESA, CHAVEITEMPEDSAIDA, TIPOPROMOCAO, VALOR)
                SELECT ATIVO, CHAVEEMPRESA, :VNEWCHAVEITEM, TIPOPROMOCAO, VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMOS=:CHAVEITEMPROD);
                VDESCACUMULADO = :VDESCACUMULADO + COALESCE((SELECT VALOR FROM PRODUTOVENDAPROMOHIST WHERE (ATIVO=1) AND (CHAVEITEMOS=:CHAVEITEMPROD)),0);
            END
        END
    END
    /*  COMISSAO X REPRESENTANTE  PARA PRODUTO */
    EXECUTE PROCEDURE ATUALIZARALIQCOMISSAO(:NLATUAL, :VTIPOPGTO, :CHAVEOS);
    INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
    SELECT CHAVEEMPRESA, :CHAVEPEDPROD, CHAVEVENDEDOR, 0, :NLATUAL, TIPOCOMISSAO,
    COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
    COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA
    FROM COMISSAO
    WHERE (ATIVO=1) AND (ORIGEM=4) AND (CHAVEDOC=:CHAVEOS);
    /* SE GEROU 2 PEDIDOS UM PRODUO E UM SERVICO GERA OS REPRESENTANTES PARA O SEGUNDO PEDIDO */
    IF (:CHAVEPEDPROD<>:CHAVEPEDSERV) THEN BEGIN
        INSERT INTO COMISSAO(CHAVEEMPRESA, CHAVEDOC, CHAVEVENDEDOR, ORIGEM, NL, TIPOCOMISSAO,
        COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
        COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA)
        SELECT CHAVEEMPRESA, :CHAVEPEDSERV, CHAVEVENDEDOR, 0, :NLATUALSERVICO, TIPOCOMISSAO,
        COMISSAOGERADA, COMISPRODUTO, COMISPRODEMISSAO, COMISPRODBAIXA,
        COMISSERVICO, COMISSERVEMISSAO, COMISSERVBAIXA, TIPOALIQUOTA
        FROM COMISSAO
        WHERE (ATIVO=1) AND (ORIGEM=4) AND (CHAVEDOC=:CHAVEOS);
    END
    FOR SELECT I.CHAVE, I.QTDE, T.ALIQUOTADE, I.ICMS,
    I.CST, T.PERCRED, I.VLRTOTAL, I.IPI, P.MVA,
    CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2)='60' THEN CASE WHEN COALESCE(I.PRECOCUSTO,0) = 0 THEN I.VLRUNIT ELSE  I.PRECOCUSTO END ELSE I.VLRUNIT END,
    T.PERCREDST, I.VLRIPITRIB, I.VLRPAUTA, I.CHAVEUNIDADE
    FROM ITENSPEDSAIDA I
    INNER JOIN PRODUTO P ON P.CHAVE=I.CHAVEPRODUTO
    INNER JOIN TRIBUTACAO T ON I.CHAVETRIBUTACAO=T.CHAVE
    WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDPROD
    INTO :CHAVEITEM, :QTDE, :ICMSTRIB, :ICMSITEM,
    :CST, :PERCRED, :VLRTOTALITEM, :IPI, :MVA, :PRECOUNITARIO,
    :PERCREDST, :VLRIPITRIB, :VLRPAUTA, :CHAVEUNIDADE
    DO BEGIN
        SELECT BASEICMSITEM, VLRICMSITEM, MVAAJUSTADO,
        BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO,
        BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC
        FROM CALCULARICMS(:CST, :VLRTOTALITEM, :ICMSTRIB, :PERCRED, :PRECOUNITARIO,
        :QTDE, :ICMSITEM, :UFCLI, :UFEMP, :IPI, :REDUCAOMVA, :REGIMETRIB, :MVA, :PERCREDST,
        :VLRIPITRIB, :VLRPAUTA, :CHAVEUNIDADE)
        INTO :BASEICMSITEM, :VLRICMSITEM, :MVAAJUSTADO,
        :BASEICMSSUBSTTRIBRETIDO, :VLRICMSSUBSTTRIBRETIDO,
        :BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC;
        SOMABASEICMS = :SOMABASEICMS + :BASEICMSITEM;
        SOMAVLRICMS  = :SOMAVLRICMS  + :VLRICMSITEM;
        SOMABASEICMSSUBSTTRIBRETIDO = :SOMABASEICMSSUBSTTRIBRETIDO + :BASEICMSSUBSTTRIBRETIDO;
        SOMAVLRICMSSUBSTTRIBRETIDO  = :SOMAVLRICMSSUBSTTRIBRETIDO  + :VLRICMSSUBSTTRIBRETIDO;
        SOMABASEICMSSUBSTTRIBDESTAC = :SOMABASEICMSSUBSTTRIBDESTAC + :BASEICMSSUBSTTRIBDESTAC;
        SOMAVLRICMSSUBSTTRIBDESTAC  = :SOMAVLRICMSSUBSTTRIBDESTAC  + :VLRICMSSUBSTTRIBDESTAC;
        UPDATE ITENSPEDSAIDA SET
            BASEICMS = :BASEICMSITEM,
            VLRICMS  = :VLRICMSITEM,
            BASEICMSSUBSTTRIB = :BASEICMSSUBSTTRIBRETIDO,
            VLRICMSSUBSTTRIB  = :VLRICMSSUBSTTRIBRETIDO,
            MVACALC = :MVAAJUSTADO,
            BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC,
            VLRICMSSUBSTTRIBDESTAC  = :VLRICMSSUBSTTRIBDESTAC
        WHERE CHAVE=:CHAVEITEM;
    END
    INSERT INTO ITENSPEDSAIDASERV
        (CHAVEEMPRESA, CHAVEPEDIDO,
        CHAVEPRODUTO, CODPRODUTO, PRODUTO, DESCRCOMPLEMENT,CHAVEUNIDADE,
        UN, QTDE, VLRUNIT, VLRTOTAL,
        VLRSUBTOTAL, ISS, NL, PRECOCUSTO,
        VLRUNITCOMDESCSERVICO, VLRUNITORIGINALSERVICO,
        DESCPORC, DESCVLR, CHAVECFOP, CHAVECFOPOPERFISCAIS,
        BASEISS, VLRISS, CSTPISCOFINS, ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB,
        BASEPISCOFINS, VLRPIS, VLRCOFINS, TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, CHAVETABPISCOFINS, VLRUNITTABELA,
        CHAVETABELAPRECO, CHAVECLASSTRIB, CHAVECLASSFISCAL)
    SELECT :CHAVEEMPPS, :CHAVEPEDSERV,
        IOS.CHAVEPRODUTO, IOS.CODPRODUTO, IOS.PRODUTO, IOS.DESCRCOMPLEMENT, IOS.CHAVEUNIDADE,
        IOS.UN, IOS.QTDE, IOS.VLRUNIT, IOS.VLRTOTAL,
        IOS.VLRSUBTOTAL, :ALIQISSFINAL, :NLATUALSERVICO, PC.PRECOMEDIO,
        IOS.VLRUNIT - (IOS.VLRUNIT/100*IOS.DESCPORC), PV.PRECOVENDA,
        DESCPORC, DESCVLR, IOS.CHAVECFOP, IOS.CHAVECFOPOPERFISCAIS,
        IOS.VLRTOTAL, IOS.VLRTOTAL*:ALIQISSFINAL/100, GP.CSTPIS,
        (SELECT ALIQPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT ALIQCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VLRPISTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VLRCOFINSTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT BASE FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IOS.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS),IOS.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        IOS.TIPOSENHADESC, IOS.CHAVEUSUARIOAUTORDESC, TC.CHAVE, IOS.VLRUNITTABELA,
        IOS.CHAVETABELAPRECO, CASE COALESCE(P.CHAVECLASSTRIB, 0) WHEN 0 THEN CFC.CHAVECLASSTRIB ELSE P.CHAVECLASSTRIB END AS CHAVECLASSTRIB, P.CHAVECLASSFISCAL
    FROM ITENSORDEMSERVICOSERV IOS
    INNER JOIN PRODUTO P ON IOS.CHAVEPRODUTO=P.CHAVE
    INNER JOIN UNIDADE UN ON UN.CHAVE = IOS.CHAVEUNIDADE
    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=IOS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
    INNER JOIN PRODUTOCUSTO PC ON PC.CHAVEPRODUTO=P.CHAVE AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
    INNER JOIN GRUPOFISCAL GP ON (CASE WHEN :PESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END = GP.CHAVE)
    LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE  = GP.CHAVETABELAPISCOFINS
    LEFT JOIN CLASSFISCAL CFC ON (P.CHAVECLASSFISCAL=CFC.CHAVE)
    WHERE IOS.CHAVEOS=:CHAVEOS AND IOS.ATIVO=1
    ORDER BY IOS.CHAVE;
    /* ACUMULAR TOTAIS PIS/COFINS DE SERVICO */
    FOR SELECT VLRPIS, VLRCOFINS, BASEPISCOFINS, VLRTOTAL FROM ITENSPEDSAIDASERV
    WHERE ATIVO=1 AND CHAVEPEDIDO IN (:CHAVEPEDPROD,:CHAVEPEDSERV)
    INTO :VLRPISSERV, :VLRCOFINSSERV, :BCPISCOFINSSERV, :TOTALSERVICO
    DO BEGIN
        SOMARVLRPIS = :SOMARVLRPIS+:VLRPISSERV;
        SOMARVLRCOFINS = :SOMARVLRCOFINS+:VLRCOFINSSERV;
        SOMARBCPISCOFINSSERV = :SOMARBCPISCOFINSSERV +:BCPISCOFINSSERV;
        SOMARTOTALSERVICO = :SOMARTOTALSERVICO + :TOTALSERVICO;
    END
    /* ACUMULAR TOTAIS PIS/COFINS DE PRODUTO */
    FOR SELECT VLRPIS, VLRCOFINS, BCPIS, COALESCE(BASECALCIPI,0), VLRTOTAL FROM ITENSPEDSAIDA
    WHERE ATIVO=1 AND CHAVEPEDIDO=:CHAVEPEDPROD
    INTO :VLRPISPROD, :VLRCOFINSPROD, :BCPISCOFINSPROD, :BASEIPI, :TOTALPRODUTO
    DO BEGIN
        SOMARTOTPIS = :SOMARTOTPIS+:VLRPISPROD;
        SOMARTOTCOFINS = :SOMARTOTCOFINS+:VLRCOFINSPROD;
        SOMARBCPISCOFINS =:SOMARBCPISCOFINS+:BCPISCOFINSPROD;
        SOMARBCIPI = :SOMARBCIPI + BASEIPI;
        SOMARTOTALPRODUTO = :SOMARTOTALPRODUTO + :TOTALPRODUTO;
    END
    UPDATE PEDIDOSAIDA SET
        BASECALCULOICMS        = :SOMABASEICMS,
        VLRICMS                = :SOMAVLRICMS,
        BASECALCICMSSUBST      = :SOMABASEICMSSUBSTTRIBRETIDO,
        VLRICMSSUBST           = :SOMAVLRICMSSUBSTTRIBRETIDO,
        BASECALCICMSSUBSTDESTAC= :SOMABASEICMSSUBSTTRIBDESTAC,
        VLRICMSSUBSTDESTAC     = :SOMAVLRICMSSUBSTTRIBDESTAC,
        VLRPISSERV             = CASE WHEN :GERAR2NFS = 1 THEN 0 ELSE :SOMARVLRPIS END,
        VLRCOFINSSERV          = CASE WHEN :GERAR2NFS = 1 THEN 0 ELSE :SOMARVLRCOFINS END,
        VLRPIS                 = :SOMARTOTPIS,
        VLRCOFINS              = :SOMARTOTCOFINS,
        BCPISCOFINS            = :SOMARBCPISCOFINS,
        BCIPI                  = :SOMARBCIPI,
        BCPISCOFINSSERV        = CASE WHEN :GERAR2NFS = 1 THEN 0 ELSE :SOMARBCPISCOFINSSERV END,
        TOTALPRODUTO           = :SOMARTOTALPRODUTO,
        TOTALSERVICO           = CASE WHEN :GERAR2NFS = 1 THEN 0 ELSE :SOMARTOTALSERVICO END,
        TOTALPEDIDO            = :SOMARTOTALPRODUTO + CASE WHEN :GERAR2NFS = 1 THEN 0 ELSE :SOMARTOTALSERVICO END
    WHERE CHAVE=:CHAVEPEDPROD;
    IF (:VDESCACUMULADO > 0) THEN BEGIN
        UPDATE PEDIDOSAIDA SET
            DESCVLRPROD=0,
            DESCPORCPROD=0
        WHERE CHAVE=:CHAVEPEDPROD;
    END
    UPDATE ESTOQUE SET ATIVO=9
    WHERE (ATIVO=1) AND (NL=:NLATUAL) AND (ORIGEM=13) AND (CHAVEDOC=:CHAVEOS) AND (COALESCE(CHAVEBDORIGEM,0)=0);
    EXECUTE PROCEDURE CARREGARMSGCOMPLDOCFISC(:CHAVEPEDPROD);
    INSERT INTO OBSLIVROFISCCOMPLDOCFISC
    (CHAVEEMPRESA, CHAVEDOCFISCAL, NL, TIPODOCFISCAL, CHAVEOBSCOMPLFISCAL, DESCRICAOCOMPL, TIPO)
    VALUES (:CHAVEEMPPS, :CHAVEPEDPROD, :NLATUAL, 1, 36, :NUMEROOS, 1);
    IF (:GERAR2NFS =1) THEN BEGIN
        INSERT INTO OBSLIVROFISCCOMPLDOCFISC
        (CHAVEEMPRESA, CHAVEDOCFISCAL, NL, TIPODOCFISCAL, CHAVEOBSCOMPLFISCAL, DESCRICAOCOMPL, TIPO)
        VALUES (:CHAVEEMPPS, :CHAVEPEDSERV, :NLATUALSERVICO, 1, 36, :NUMEROOS, 1);
    END
    IF (:GERAR2NFS = 1) THEN BEGIN
        UPDATE PEDIDOSAIDA SET
            FATURA = NULL
        WHERE (CHAVE IN (:CHAVEPEDPROD, :CHAVEPEDSERV));
        UPDATE PEDIDOSAIDA SET
            TOTALPRODUTO = 0,
            TOTALSERVICO = :SOMARTOTALSERVICO,
            TOTALPEDIDO = :SOMARTOTALSERVICO
        WHERE (CHAVE = :CHAVEPEDSERV);
    END
    UPDATE ORDEMSERVICO O SET
    O.CHAVEDOCDESTINO = COALESCE(:CHAVEPEDPROD,:CHAVEPEDSERV),
    O.DOCDESTINO  =  COALESCE(:NROPEDIDOPROD,:NROPEDIDOSERV)
    WHERE CHAVE = :CHAVEOS;
    /* CHAMADAS
        - FRMORDEMSERVICO - GERAR UM PEDIDO DE SAIDA REFERENTE A ORDEM DE SERVICO
        - CHPDV - GERAR UM PEDIDO DE SAIDA DE SERVICO QUANDO NAO FOR PERMITIDA VENDA DE SERVICO NO CHPDV
    */
END^


ALTER PROCEDURE OSPETSHOPREAGENDARAGENDA (
    ECHAVEAGENDAANT INTEGER,
    EDATA DATE,
    EHORA TIME,
    EPERIODO INTEGER)
RETURNS (
    SCHAVEAGENDANOVA INTEGER)
AS
BEGIN
   SCHAVEAGENDANOVA = GEN_ID(GEN_OSPETSHOPAGENDA_ID,1);
   INSERT INTO OSPETSHOPAGENDA(CHAVE, ATIVO, CHAVEEMPRESA, CHAVEANIMAL, CHAVECLIFOR, CHAVESERVICO, BUSCARANIMAL,
      ENTREGARANIMAL, SITUACAO, PERIODO, OBS, CHAVEPROCEDIMENTO,
      TEMPO, DATA, TIPO, NRODOSES, CHAVEVENDEDOR, HORA, CHAVELOCALARMAZENAGEM, VLRUNIT, TEMPOEXECUCAO,
      ORIGEM, HORAENTREGA, CONCLUSAO, CHAVEVETERINARIO, CHAVELABORATORIO, PARTIDALOTE, TIPOSERVANIMALERP, CHAVEAGENDAGEROU,
      TEMPOBANHO, TEMPOTOSA, CHAVEPLANO, CHAVEREAGENDADO, SESSAOPLANO, CHAVESETOR)
   SELECT :SCHAVEAGENDANOVA, 1, CHAVEEMPRESA, CHAVEANIMAL, CHAVECLIFOR, CHAVESERVICO, BUSCARANIMAL,
      ENTREGARANIMAL, 0, :EPERIODO, OBS, CHAVEPROCEDIMENTO,
      TEMPO, :EDATA, TIPO,  NRODOSES, CHAVEVENDEDOR, :EHORA, CHAVELOCALARMAZENAGEM, VLRUNIT, TEMPOEXECUCAO,
      ORIGEM, HORAENTREGA, CONCLUSAO, CHAVEVETERINARIO, CHAVELABORATORIO, PARTIDALOTE, TIPOSERVANIMALERP, CHAVEAGENDAGEROU,
      TEMPOBANHO, TEMPOTOSA, CHAVEPLANO, :ECHAVEAGENDAANT, SESSAOPLANO, CHAVESETOR
   FROM OSPETSHOPAGENDA
   WHERE CHAVE=:ECHAVEAGENDAANT;
   UPDATE OSPETSHOPAGENDA SET
   SITUACAO=2,
   OBS=OBS||' MOTIVO DO CANCELAMENTO: REAGENDADO PARA O DIA '||SUBSTRING(CAST(:EDATA AS VARCHAR(10)) FROM 9 FOR 2)||'/'||SUBSTRING(CAST(:EDATA AS VARCHAR(10)) FROM 6 FOR 2)||'/'||SUBSTRING(CAST(:EDATA AS VARCHAR(10)) FROM 1 FOR 4)
   WHERE CHAVE=:ECHAVEAGENDAANT;
   SUSPEND;
END^


ALTER PROCEDURE PREVENDAGERAPS (
    CHAVEPREVENDA INTEGER,
    CHAVEEMPPS INTEGER,
    PRODUTOVENDACHAVEEMP INTEGER,
    PRODUTOCUSTOCHAVEEMP INTEGER,
    CHAVEUSUARIO INTEGER,
    ENLATUALSERVICO DOUBLE PRECISION,
    COBROUSERVPDV CHAR(1))
RETURNS (
    SPEDIDOSERVICO VARCHAR(6))
AS
declare variable CHAVEOPERFISCSERV integer;
declare variable DESCPORCSERVICO numeric(18,2);
declare variable NLATUAL double precision;
declare variable CHAVECFOPSERV integer;
declare variable CHAVESERIENFPADRAO integer;
declare variable NUMEROPV varchar(10);
declare variable CHAVESERIEEXTRA integer;
declare variable SOMARBCPISCOFINSSERV numeric(18,6);
declare variable BCPISCOFINSSERV numeric(18,6);
declare variable SOMARVLRCOFINS numeric(18,6);
declare variable VLRCOFINSSERV numeric(18,6);
declare variable VLRPISSERV numeric(18,6);
declare variable SOMARVLRPIS numeric(18,6);
declare variable ALIQISSFINAL numeric(7,2);
declare variable CHAVEPEDSERV integer;
declare variable TIPONFSERIEPADRAO smallint;
declare variable NROPEDIDOSERV varchar(10);
declare variable UFEMP char(2);
declare variable UFCLI char(2);
declare variable TOTALSERVICO numeric(18,2);
declare variable NLATUALSERVICO double precision;
declare variable PESSOA smallint;
declare variable IERG varchar(20);
declare variable TIPOPAGAMENTO smallint;
BEGIN
    -- ZERAR VARIAVEIS
    SOMARVLRPIS =0;
    SOMARVLRCOFINS =0;
    SOMARBCPISCOFINSSERV =0;
    CHAVESERIEEXTRA = 0;
    CHAVECFOPSERV = 0;
    CHAVEOPERFISCSERV = 0;
    SPEDIDOSERVICO = '';

    -- SELECT PARA PEGAR OS REGISTROS PADROES DA PREVENDA
    SELECT PV.NL, PV.NUMEROPV, PV.DESCPORCPROD
    FROM PREVENDA PV
    WHERE PV.CHAVE =:CHAVEPREVENDA AND PV.ATIVO = 1
    INTO :NLATUAL, :NUMEROPV, :DESCPORCSERVICO;

    SELECT SUM(IP.VLRSUBTOTAL) AS TOTALSERVICO FROM PREVENDA PV
    INNER JOIN ITENSPREVENDA IP ON (IP.CHAVEPREVENDA=PV.CHAVE) AND (IP.ATIVO=1)
    WHERE (PV.ATIVO=1) AND (PV.CHAVE=:CHAVEPREVENDA) AND (IP.TIPOPRODUTO=9)
    INTO :TOTALSERVICO;

    IF (COBROUSERVPDV = 'S') THEN BEGIN
        TIPOPAGAMENTO = 2;
        DESCPORCSERVICO = 0;
    END ELSE
        TIPOPAGAMENTO = 0;

    NLATUALSERVICO= :NLATUAL;

    SELECT CASE WHEN COALESCE(VALOR, '') = '' THEN NULL ELSE VALOR END FROM CONFIGCAMPOS WHERE ATIVO=1 AND INDICE = 307 AND CHAVEEMPRESA=:CHAVEEMPPS
    INTO :CHAVESERIENFPADRAO;

    SELECT S1.TIPONOTAFISCAL, CASE E.REGIMETRIBUT WHEN 2 THEN  CID.ISS ELSE E.ALIQISSSIMPLESNACIONAL END,
    (SELECT PEDIDO FROM GETULTIMOPEDIDO (:CHAVEEMPPS))
    FROM CONFIG CO
    LEFT JOIN SERIENF S1 ON S1.CHAVE = :CHAVESERIENFPADRAO AND S1.ATIVO=1
    INNER JOIN EMPRESA E ON E.CHAVE = CO.CHAVEEMPRESA
    INNER JOIN CIDADE CID ON E.CHAVEEMPRESA=CID.CHAVE
    WHERE CO.ATIVO=1 AND CO.CHAVEEMPRESA=:CHAVEEMPPS
    INTO :TIPONFSERIEPADRAO, :ALIQISSFINAL, :NROPEDIDOSERV;

    IF (:TIPONFSERIEPADRAO=0) THEN BEGIN
      -- BUSCAR SE EXISTE SERIE DE SERVICO
      SELECT FIRST 1 COALESCE(CHAVE,0) FROM SERIENF
      WHERE ATIVO=1 AND TIPONOTAFISCAL = 2
      ORDER BY CHAVE DESC
      INTO :CHAVESERIEEXTRA;
    END

    IF (CHAVESERIEEXTRA = 0) THEN BEGIN
      SELECT FIRST 1 COALESCE(CHAVE,0) FROM SERIENF
      WHERE ATIVO=1 AND (TIPONOTAFISCAL=1)
      ORDER BY CHAVE DESC
      INTO :CHAVESERIEEXTRA;
    END

    IF (CHAVESERIEEXTRA > 0) THEN BEGIN
        SPEDIDOSERVICO = :NROPEDIDOSERV;
    END

    SELECT CID.UF FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE E.CHAVE= :CHAVEEMPPS
    INTO :UFEMP;
    
    SELECT CID.UF, C.IERG, C.PESSOA FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN PREVENDA PV ON C.CHAVE=PV.CHAVECLIFOR
    WHERE PV.CHAVE=:CHAVEPREVENDA
    INTO :UFCLI, :IERG, :PESSOA;
    --CASO SEJA ISENTO FAZ TRATAMENTO COMO PESSOA FISICA
    IF ((:PESSOA = 0) AND (:IERG IN ('ISENTO',''))) THEN
        PESSOA = 1;    

    --VERIFICAR O CFOP QUE SERA USADO
    IF ((:PESSOA = 0) AND (NOT :IERG IN ('ISENTO', '')) AND (:UFCLI<>:UFEMP)) THEN BEGIN
        SELECT FIRST 1 CHAVE, CHAVECFOPSERVFE FROM CFOPOPERFISCAIS CF
        WHERE ATIVO=1 AND COALESCE(CF.CHAVECFOPSERVFE, 0) > 0
        ORDER BY CHAVE
        INTO :CHAVEOPERFISCSERV, :CHAVECFOPSERV;
    END ELSE BEGIN
        SELECT FIRST 1 CHAVE, CHAVECFOPSERVDE FROM CFOPOPERFISCAIS CF
        WHERE ATIVO=1 AND COALESCE(CF.CHAVECFOPSERVDE, 0) > 0
        ORDER BY CHAVE
        INTO :CHAVEOPERFISCSERV, :CHAVECFOPSERV;
    END

    --OPERACAO FISCAL DE SERVICO
    --GERAR A NF DE SERVICO
    NLATUALSERVICO= :ENLATUALSERVICO;
    CHAVEPEDSERV = GEN_ID(GEN_PEDIDOSAIDA_ID,1);
    INSERT INTO PEDIDOSAIDA
        (CHAVE, CHAVEEMPRESA, PEDIDO, CHAVECLIFOR,
        CHAVECFOPOPERFISCAIS, CHAVECFOPSERV,
        TOTALPEDIDO, TOTALSERVICO, FRETE,
        TOTALISS, ALIQUOTAISS, BASEISS,
        OBS, DATAPEDIDO, HORAPEDIDO, STATUS, FRETEPORCONTA,
        NL, QTDEVOLUME,
        CHAVEPLANOCONTA, CHAVECENTROCUSTO, CHAVECTABANCARIA, CHAVEOPERACOESTITULOS,
        TIPOPAGAMENTO, CHAVECONDPGTO, FATURA,
        CHAVETABELADESCONTOS, DESCPORCSERVICO, DESCVLRSERVICO, FORMAPGTO,
        VLRACRESCIMO, VLRFINANCEIRO)
    SELECT
        :CHAVEPEDSERV, :CHAVEEMPPS, :NROPEDIDOSERV, CHAVECLIFOR,
        :CHAVEOPERFISCSERV, :CHAVECFOPSERV,
        :TOTALSERVICO, :TOTALSERVICO, 0,
        (:TOTALSERVICO * :ALIQISSFINAL)/100, :ALIQISSFINAL, :TOTALSERVICO,
        OBS, DATAPV, CURRENT_TIME, 0, 0,
        :NLATUALSERVICO, 0,
        CHAVEPLANOCONTA, CHAVECENTROCUSTO, CHAVECTABANCARIA, CHAVEOPERTITULOS,
        :TIPOPAGAMENTO, CHAVECONDPGTO, '',
        CHAVETABELADESCONTOS, :DESCPORCSERVICO,
        CASE WHEN :DESCPORCSERVICO <> 0 THEN CAST((:DESCPORCSERVICO * :TOTALSERVICO)/100 AS NUMERIC(18,2)) ELSE 0 END, FORMAPGTO, VLRACRESCIMO, TOTALPV
    FROM PREVENDA WHERE CHAVE=:CHAVEPREVENDA;
    
    -- GERAR REGISTRO NA TEBELA RASTREAR DOC.
    INSERT INTO RASTREARDOC(ATIVO, CHAVEEMPRESA, CHAVEPVORIGEM, CHAVEPEDDESTINO, DATAHORA, CHAVEUSUARIO, OBS)
    VALUES(1,:CHAVEEMPPS, :CHAVEPREVENDA, :CHAVEPEDSERV, CURRENT_TIMESTAMP, :CHAVEUSUARIO, 'PEDIDO COM SERVICO');

    INSERT INTO ITENSPEDSAIDASERV
        (CHAVEEMPRESA, CHAVEPEDIDO,
        CHAVEPRODUTO, CODPRODUTO, PRODUTO, CHAVEUNIDADE,
        UN, QTDE, VLRUNIT, VLRTOTAL,
        VLRSUBTOTAL, ISS, NL, DESCRCOMPLEMENT,
        DESCPORC, DESCVLR, CHAVECFOP, CHAVECFOPOPERFISCAIS,
        PRECOCUSTO, VLRUNITORIGINALSERVICO, VLRUNITCOMDESCSERVICO,
        BASEISS, VLRISS,
        CSTPISCOFINS, ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB, BASEPISCOFINS, VLRPIS, VLRCOFINS,
        TIPOSENHADESC, CHAVEUSUARIOAUTORDESC, CHAVETABPISCOFINS, VLRUNITTABELA, CHAVETABELAPRECO)
    SELECT :CHAVEEMPPS, :CHAVEPEDSERV,
        IPV.CHAVEPRODUTO, P.CODIGO, P.DESCRICAO, P.CHAVEUNIDADE,
        UN.UNMAIOR, IPV.QTDE, IPV.VLRUNIT, IPV.VLRTOTAL,
        IPV.VLRSUBTOTAL, :ALIQISSFINAL, :NLATUALSERVICO, IPV.DESCRCOMPLEMENT,
        DESCPORC, DESCVLR, :CHAVECFOPSERV, :CHAVEOPERFISCSERV,
        PC.PRECOCUSTO, PV.PRECOVENDA, (IPV.VLRUNIT - (IPV.VLRUNIT/100*IPV.DESCPORC)),
        IPV.VLRTOTAL, IPV.VLRTOTAL*:ALIQISSFINAL/100, GP.CSTPIS,
        (SELECT ALIQPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IPV.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IPV.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT ALIQCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IPV.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IPV.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VLRPISTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IPV.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IPV.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VLRCOFINSTRIB FROM CALCULARPISCOFINS(GP.CSTPIS, IPV.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IPV.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT BASE FROM CALCULARPISCOFINS(GP.CSTPIS, IPV.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IPV.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORPIS FROM CALCULARPISCOFINS(GP.CSTPIS, IPV.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IPV.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        (SELECT VALORCOFINS FROM CALCULARPISCOFINS(GP.CSTPIS, IPV.VLRTOTAL, (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), IPV.QTDE, COALESCE(UN.CONVUNMEDIDA,0))),
        IPV.TIPOSENHADESC, IPV.CHAVEUSUARIOAUTORDESC, TC.CHAVE, IPV.VLRUNITTABELA, IPV.CHAVETABELAPRECO
    FROM ITENSPREVENDA IPV
    INNER JOIN PRODUTO P ON (IPV.CHAVEPRODUTO=P.CHAVE)
    INNER JOIN PRODUTOVENDA PV ON (PV.CHAVEPRODUTO=P.CHAVE) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=IPV.CHAVETABELAPRECO) AND (PV.ATIVO=1)
    INNER JOIN PRODUTOCUSTO PC ON (PC.CHAVEPRODUTO=P.CHAVE) AND (PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP) AND (PC.ATIVO=1)
    INNER JOIN UNIDADE UN ON (UN.CHAVE = P.CHAVEUNIDADE)
    INNER JOIN GRUPOFISCAL GP ON (CASE WHEN :PESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END = GP.CHAVE)
    LEFT JOIN TABELAPISCOFINS TC ON (TC.CHAVE = GP.CHAVETABELAPISCOFINS)
    WHERE (IPV.ATIVO=1) AND (IPV.CHAVEPREVENDA=:CHAVEPREVENDA) AND (IPV.TIPOPRODUTO = 9)
    ORDER BY IPV.CHAVE;

    --ACUMULAR TOTAIS PIS/COFINS DE SERVICO
    FOR SELECT VLRPIS, VLRCOFINS, BASEPISCOFINS FROM ITENSPEDSAIDASERV
    WHERE (ATIVO=1) AND (CHAVEPEDIDO=:CHAVEPEDSERV)
    INTO :VLRPISSERV, :VLRCOFINSSERV, :BCPISCOFINSSERV
    DO BEGIN
        SOMARVLRPIS = :SOMARVLRPIS+:VLRPISSERV;
        SOMARVLRCOFINS = :SOMARVLRCOFINS+:VLRCOFINSSERV;
        SOMARBCPISCOFINSSERV = :SOMARBCPISCOFINSSERV + :BCPISCOFINSSERV;
    END

    UPDATE PEDIDOSAIDA SET
        VLRPISSERV = :SOMARVLRPIS,
        VLRCOFINSSERV = :SOMARVLRCOFINS,
        BCPISCOFINSSERV = :SOMARBCPISCOFINSSERV
    WHERE CHAVE=:CHAVEPEDSERV;

    EXECUTE PROCEDURE CARREGARMSGCOMPLDOCFISC (:CHAVEPEDSERV);

    -- COMPLEMENTO QUE REFERENCIA QUAL PRE-VENDA ORIGINOU O PEDIDO DE SAIDA
    INSERT INTO OBSLIVROFISCCOMPLDOCFISC
    (CHAVEEMPRESA, CHAVEDOCFISCAL, NL, TIPODOCFISCAL, CHAVEOBSCOMPLFISCAL, DESCRICAOCOMPL, TIPO)
    VALUES (:CHAVEEMPPS, :CHAVEPEDSERV, :NLATUAL, 1, 37, :NUMEROPV, 1);

    SUSPEND;
END^


ALTER PROCEDURE PRODUTOESTOQUESALDO (
    CHAVEPROD INTEGER)
AS
BEGIN

    INSERT INTO PRODUTOESTOQUE(CHAVEEMPRESA, SALDO, CHAVEPRODUTO,
    ESTOQUEMAXIMO, ESTOQUEMINIMO, SALDOCOTADO, SALDOCONDICIONAL,
    SALDOEMTERCEIROS, SALDODETERCEIROS, SALDOPOSSEPROPRIA)
    SELECT C.CHAVEEMPRESA, 0, :CHAVEPROD, 0 , 0, 0, 0, 0, 0, 0
    FROM CONFIG C
    WHERE C.ATIVO=1;

    /*CHAMADAS:
            - frmProduto: Usada para inserir os registros na tabela ProdutoEstoque quando e cadastrado um produto novo*/
END^


ALTER PROCEDURE QUEBRARSTRING (
    ATEXTOIN VARCHAR(8192))
RETURNS (
    REGISTROINT INTEGER)
AS
declare variable ULTIMAPOS integer;
declare variable PROXIMAPOS integer;
declare variable TEMPSTR varchar(8192);
BEGIN
    IF (SUBSTRING(:ATEXTOIN FROM 1 FOR 1) = ';') THEN
        ATEXTOIN = SUBSTRING(:ATEXTOIN FROM 2 FOR 8192);

    ULTIMAPOS = 1;
    PROXIMAPOS = POSITION(';', :ATEXTOIN, ULTIMAPOS);
    WHILE (:PROXIMAPOS > 1) DO BEGIN
        TEMPSTR = SUBSTRING(:ATEXTOIN FROM :ULTIMAPOS FOR :PROXIMAPOS - :ULTIMAPOS);
        REGISTROINT = :TEMPSTR;
        ULTIMAPOS = :PROXIMAPOS + 1;
        PROXIMAPOS = POSITION(';', :ATEXTOIN, ULTIMAPOS);
        SUSPEND;
    END
END^


ALTER PROCEDURE QUEBRARSTRINGSTR (
    ATEXTOIN VARCHAR(8192))
RETURNS (
    SREGISTROSSTR VARCHAR(100))
AS
declare variable ULTIMAPOS integer;
declare variable PROXIMAPOS integer;
declare variable TEMPSTR varchar(8192);
BEGIN
    IF (SUBSTRING(:ATEXTOIN FROM 1 FOR 1) = ';') THEN
        ATEXTOIN = SUBSTRING(:ATEXTOIN FROM 2 FOR 8192);

    ULTIMAPOS = 1;
    PROXIMAPOS = POSITION(';', :ATEXTOIN, ULTIMAPOS);
    WHILE (:PROXIMAPOS > 1) DO BEGIN
        TEMPSTR = SUBSTRING(:ATEXTOIN FROM :ULTIMAPOS FOR :PROXIMAPOS - :ULTIMAPOS);
        SREGISTROSSTR = :TEMPSTR;
        ULTIMAPOS = :PROXIMAPOS + 1;
        PROXIMAPOS = POSITION(';', :ATEXTOIN, ULTIMAPOS);
        SUSPEND;
    END
END^


ALTER PROCEDURE QUEBRARVALOR (
    VQTDE NUMERIC(18,6))
RETURNS (
    SQTDE NUMERIC(18,6))
AS
begin
    WHILE (:VQTDE > 0) DO BEGIN
        IF (:VQTDE >= 1) THEN
            SQTDE  = 1;
        ELSE
            SQTDE  = :VQTDE;
        VQTDE = :VQTDE - 1;
        SUSPEND;
    END
/*USADO PARA CUSTOMIZADOS QUEBRAR QTDES CHAMADO DE EXEMPLO 64648 NAO EXCLUIR*/
end^


ALTER PROCEDURE RATEIOCONDICIONAL (
    CHAVECONDICIONAL INTEGER)
AS
declare variable VLRACRESCGLOBAL numeric(18,6);
declare variable ACRESCVLRCOND numeric(18,6);
declare variable VTOTALITEM numeric(18,4);
declare variable QTDE numeric(18,4);
declare variable VSOMARBCIPI numeric(18,6);
declare variable VBASEICMS numeric(18,6);
declare variable VIERG varchar(20);
declare variable VPESSOA integer;
declare variable VVLRIPI numeric(18,6);
declare variable VCONVUNMEDIDA numeric(18,6);
declare variable VMVA numeric(18,6);
declare variable VAUX numeric(18,6);
declare variable VPERCREDICMS numeric(18,6);
declare variable VVLRPAUTA numeric(18,6);
declare variable VCSTSUBSTTRIB char(1);
declare variable VPERCREDST numeric(18,6);
declare variable VVLRICMS numeric(18,6);
declare variable VALIQICMS numeric(7,2);
declare variable VCST2 varchar(2);
declare variable VPORC numeric(18,6);
declare variable VSOMAVLRSUBSTTRIBDEST numeric(18,6);
declare variable VSOMABASESUBSTTRIBDEST numeric(18,6);
declare variable VSOMAVLRSUBSTTRIB numeric(18,6);
declare variable VSOMABASESUBSTTRIB numeric(18,6);
declare variable VVLRUNITCOMDESC numeric(18,6);
declare variable VPRECOCUSTO numeric(18,6);
declare variable VCHAVEUNIDADE integer;
declare variable VREGIMETRIBUT integer;
declare variable VREDUCAOMVA numeric(18,6);
declare variable VUFCLI varchar(2);
declare variable VUFEMP varchar(2);
declare variable VMVACALC numeric(18,6);
declare variable VMVAORIGINAL numeric(18,6);
declare variable VCST varchar(10);
declare variable VSOMAVLRICMS numeric(18,6);
declare variable VVLRRATEIOITEM numeric(18,6);
declare variable VSOMABASEICMS numeric(18,6);
declare variable VVLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VBASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VVLRICMSSUBSTTRIB numeric(18,6);
declare variable VBASEICMSSUBSTTRIB numeric(18,6);
declare variable VAUX2 numeric(18,6);
declare variable VFRETE numeric(18,6);
declare variable VBASECALCIPI numeric(18,6);
declare variable VSOMARIPI numeric(18,6);
declare variable VVLRIPITRIB numeric(18,6);
declare variable VIPI numeric(7,2);
declare variable VLRTOTALITEM numeric(18,6);
declare variable ACRESCPORCPROD numeric(18,6);
declare variable CHAVEITEM integer;
declare variable TOTALPRODUTO numeric(18,6);
declare variable DESCPORCPROD numeric(7,2);
declare variable DESCVLRPROD numeric(18,6);
declare variable VCONVERSAO numeric(18,6);
declare variable VTOTALTABITENS numeric(18,6);
declare variable VNROITENS integer;
declare variable VITEMATUAL integer;
declare variable VLRACRESGLOBALACUM numeric(18,6);
declare variable VLRDESCGLOBAL numeric(18,4);
BEGIN
   VSOMARIPI = 0;
   VSOMARBCIPI = 0;
   VSOMABASEICMS = 0;
   VSOMAVLRICMS = 0;
   VSOMABASESUBSTTRIB = 0;
   VSOMAVLRSUBSTTRIB = 0;
   VSOMABASESUBSTTRIBDEST = 0;
   VSOMAVLRSUBSTTRIBDEST = 0;
   VPORC = 0;
   VLRACRESCGLOBAL = 0;
   VVLRUNITCOMDESC = 0;
   VITEMATUAL = 0;
   VLRACRESGLOBALACUM = 0;
   -- SELECIONAR VALORES COND.

   SELECT COALESCE(SUM(VLRTOTAL),0) FROM ITENSCONDICIONALPROD
   WHERE CHAVECONDICIONAL=:CHAVECONDICIONAL AND ATIVO=1 INTO :VTOTALTABITENS;

   SELECT COALESCE(COALESCE(SUM(I.VLRTOTAL),0) - SUM(COALESCE(I.VLRACRESCGLOBAL, 0)),0), COUNT(I.CHAVE)
   FROM ITENSCONDICIONALPROD I
   INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS AND CF.COMPORTOTALNF = 0
   WHERE I.CHAVECONDICIONAL=:CHAVECONDICIONAL AND I.ATIVO=1
   INTO :VTOTALTABITENS, :VNROITENS;

   SELECT COND.ACRESCVLRPROD, COND.ACRESCPORCPROD, COND.TOTALPRODUTO, COND.DESCPORCPROD, COND.DESCVLRPROD,
   COND.FRETE, C.PESSOA, C.IERG, CID.UF, CIDE.UF, C.REDUCAOMVA, C.REGIMETRIBUTARIO, COND.TOTALIPI
   FROM CONDICIONAL COND
   LEFT JOIN CLIFOR C ON C.CHAVE = COND.CHAVECLIFOR
   LEFT JOIN CIDADE CID ON CID.CHAVE = C.CHAVECIDADE
   INNER JOIN EMPRESA E ON E.CHAVE = COND.CHAVEEMPRESA
   INNER JOIN CIDADE CIDE ON CIDE.CHAVE = E.CHAVECIDADE
   WHERE (COND.CHAVE=:CHAVECONDICIONAL)
   INTO :ACRESCVLRCOND, :ACRESCPORCPROD, :TOTALPRODUTO,:DESCPORCPROD, :DESCVLRPROD,
   :VFRETE, :VPESSOA, :VIERG, VUFCLI, :VUFEMP, :VREDUCAOMVA, :VREGIMETRIBUT, :VSOMARIPI;

   IF ((:ACRESCVLRCOND > 0) AND (:DESCVLRPROD > 0)) THEN BEGIN
      VAUX = :DESCVLRPROD * 100;
      VAUX = :VAUX / (:VTOTALTABITENS + :ACRESCVLRCOND);
      VAUX = CAST(VAUX AS NUMERIC(18,4));
      DESCPORCPROD = :VAUX;
   END

   -- SELECIONAR VALORES ITENS COND.
   FOR SELECT I.CHAVE, I.QTDE, (I.VLRTOTAL/I.QTDE), I.IPI, I.VLRIPITRIB,
   COALESCE(UN.CONVUNMEDIDA,0), SUBSTRING(T.CODIGO FROM 2 FOR 2), I.ICMS, T.PERCREDST, T.CSTSUBSTTRIB, P.VLRPAUTA,
   T.PERCRED, I.MVA, I.CHAVEUNIDADE, COALESCE(I.PRECOCUSTO,0),
   T.CODIGO, I.BASEICMS, I.VLRIPI, I.VLRTOTAL, COALESCE(UN.CONVERSAO,0), COALESCE(I.VLRACRESCGLOBAL,0)
   FROM ITENSCONDICIONALPROD I
   INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
   INNER JOIN TRIBUTACAO T ON T.CHAVE = I.CHAVETRIBUTACAO
   INNER JOIN PRODUTO P ON P.CHAVE = I.CHAVEPRODUTO
   INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS
   WHERE (I.ATIVO=1) AND (I.CHAVECONDICIONAL=:CHAVECONDICIONAL)
   INTO :CHAVEITEM, :QTDE, :VLRTOTALITEM, :VIPI, :VVLRIPITRIB,
   :VCONVUNMEDIDA, :VCST2, :VALIQICMS, :VPERCREDST, :VCSTSUBSTTRIB, :VVLRPAUTA,
   :VPERCREDICMS, :VMVA, :VCHAVEUNIDADE, :VPRECOCUSTO,
   :VCST, :VBASEICMS, :VVLRIPI, :VTOTALITEM, :VCONVERSAO, :VLRACRESCGLOBAL
   DO BEGIN
        VITEMATUAL = :VITEMATUAL + 1;
        VVLRRATEIOITEM = CAST(:VFRETE / 100 * :VPORC AS NUMERIC(18,6));
        VPORC = (:VTOTALITEM*100)/:TOTALPRODUTO;
        VPORC = CAST(:VPORC AS NUMERIC(7,2));
        VMVAORIGINAL = VMVA;
        VVLRUNITCOMDESC = CAST(:VTOTALITEM / (:QTDE * :VCONVERSAO) AS NUMERIC(18,4));

      -- RATEIO DO ACRESC. NOS ITENS
      IF (:ACRESCVLRCOND <> 0) THEN BEGIN
          IF (:VITEMATUAL < :VNROITENS) THEN BEGIN
             VAUX = :VLRTOTALITEM - :VLRACRESCGLOBAL;
             VAUX = ((:VAUX/100) * :ACRESCPORCPROD);
             VAUX = CAST(:VAUX AS NUMERIC(18,2));
             --PREVENCAO PARA QTDES MAIORES QUE 1
             VAUX = CAST(VAUX / :QTDE AS NUMERIC(18,2));
             VAUX = VAUX * :QTDE;
          END ELSE
             VAUX = :ACRESCVLRCOND - :VLRACRESGLOBALACUM;
          VLRACRESGLOBALACUM = :VLRACRESGLOBALACUM + :VAUX;
          VLRACRESCGLOBAL = :VAUX - :VLRACRESCGLOBAL;
          VTOTALITEM = :VTOTALITEM + :VLRACRESCGLOBAL; --ACRESCIMO AUMENTA O TOTAL DO ITEM
      END ELSE
         VLRACRESCGLOBAL = :VLRACRESCGLOBAL * (-1); --ABATER VALOR SE JA FOI RATEADO NOS ITENS

      VLRTOTALITEM = :VTOTALITEM;
      IF (:DESCPORCPROD > 0) THEN
         VTOTALITEM = :VTOTALITEM - ((:VTOTALITEM/100)*:DESCPORCPROD);
      IF (:DESCVLRPROD <> 0) THEN BEGIN
          VLRDESCGLOBAL = 0;
          -- VALOR DESCONTO GLOBAL PRODUTO
          VLRDESCGLOBAL= (:VLRTOTALITEM*100)/(:VTOTALTABITENS);
          VLRDESCGLOBAL = CAST(:VLRDESCGLOBAL AS NUMERIC(7,2));
          VLRDESCGLOBAL = :VLRDESCGLOBAL * :DESCVLRPROD/100;
      END

      -- RATEIA DESCONTO NOS ITENS PROD
      IF (:DESCVLRPROD <> 0) THEN BEGIN
         VAUX = 0;
         VLRDESCGLOBAL = 0;
         VAUX = :VVLRUNITCOMDESC * 100 / :VTOTALTABITENS;
         VAUX = :VAUX * :DESCVLRPROD / 100;
         VVLRUNITCOMDESC = :VVLRUNITCOMDESC - :VAUX;
      END

      -- ATUALIZA VALORES NO ITEM
      UPDATE ITENSCONDICIONALPROD SET
         VLRUNIT = VLRUNIT + (:VLRACRESCGLOBAL / QTDE),
--         DESCPORC = :NOVODESCPORC,
         DESCPORC = CASE WHEN (:VLRACRESCGLOBAL = 0) THEN DESCPORC ELSE CAST((DESCVLR * 100) / (VLRSUBTOTAL + :VLRACRESCGLOBAL) AS NUMERIC(18,4)) END,
         VLRUNITCOMDESC = :VVLRUNITCOMDESC,
         VLRACRESCGLOBAL = COALESCE(VLRACRESCGLOBAL,0) + :VLRACRESCGLOBAL,
         VLRSUBTOTAL=(VLRSUBTOTAL+:VLRACRESCGLOBAL),
         VLRTOTAL=(VLRTOTAL+:VLRACRESCGLOBAL)
      WHERE (CHAVE=:CHAVEITEM);

      --VALOR DO IPI
      IF ((:VIPI+:VVLRIPITRIB) > 0) THEN BEGIN
        VSOMARIPI = VSOMARIPI - VVLRIPI;
        IF (:VIPI > 0) THEN BEGIN
            VBASECALCIPI = :VTOTALITEM + :VVLRRATEIOITEM;
            VVLRIPI  = CAST(:VBASECALCIPI * :VIPI / 100 AS NUMERIC(18,2));
        END ELSE BEGIN
            VBASECALCIPI = 0;
            VVLRIPI = ((:VCONVUNMEDIDA  * :QTDE) * :VVLRIPITRIB);
        END
        VSOMARBCIPI = VSOMARBCIPI + VBASECALCIPI;
        VSOMARIPI = :VSOMARIPI + :VVLRIPI;
        --SOMAR IPI NA BASE ICMS QDO NAO CONTRIBUINTE OU VENDA PARA USO E CONSUMO
        IF ((:VPESSOA=1) OR ((:VPESSOA =0) AND (:VIERG = 'ISENTO'))) THEN
            VBASEICMS = :VBASEICMS + :VVLRIPI;
     END
     IF ((:VCST2 IN ('00','10')) OR ((:VCST2 = '90') AND (:VCSTSUBSTTRIB='S') AND (:VALIQICMS>0) AND (:VPERCREDICMS=0))) THEN BEGIN
        VBASEICMS     = :VBASEICMS + :VVLRRATEIOITEM;
        VVLRICMS      = CAST(:VBASEICMS * :VALIQICMS / 100 AS NUMERIC(18,2));
     END
     IF ((:VCST2 IN ('20','70')) OR ((:VCST2 = '90') AND (:VPERCREDICMS>0) AND (:VALIQICMS>0))) THEN BEGIN
        VAUX = 0;
        VAUX = :VBASEICMS + :VVLRRATEIOITEM;
        VAUX = VAUX * ((100 - :VPERCREDICMS) / 100);
        VBASEICMS = CAST(:VAUX AS NUMERIC(18,2));
        VAUX = 0;
        VAUX = (:VBASEICMS/100)*:VALIQICMS;
        VVLRICMS = CAST(:VAUX AS NUMERIC(18,2));
     END
     IF (:VCST2 IN ('51')) THEN BEGIN
        IF (:VALIQICMS > 0) THEN BEGIN
            VBASEICMS     = :VBASEICMS + :VVLRRATEIOITEM;
            VVLRICMS      = CAST(:VBASEICMS * :VALIQICMS / 100 AS NUMERIC(18,2));
        END ELSE BEGIN
            VBASEICMS = 0;
            VVLRICMS  = 0;
        END
     END
     IF ((:VCST2 IN ('30','40','41','50','60')) OR ((:VCST2 = '90') AND (:VALIQICMS=0))) THEN BEGIN
        VBASEICMS = 0;
        VVLRICMS  = 0;
     END
     IF (((:VCST2 IN ('10','30','60','70')) OR ((:VCST2 = '90') AND (:VCSTSUBSTTRIB='S') AND (:VALIQICMS>0)))) THEN BEGIN
        VAUX  = 0;
        VAUX2 = 0;
        IF (:VCST2='60') THEN BEGIN
           SELECT BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, MVAAJUSTADO FROM
           CALCULARMVA(:VMVAORIGINAL, :VCST, :VALIQICMS,
           :VPRECOCUSTO, :QTDE, 0, 0, :VUFCLI, :VUFEMP, :VIPI, :VREDUCAOMVA, :VREGIMETRIBUT,0, :VVLRIPI, 0, 0)
           INTO :VAUX, :VAUX2, :VMVACALC;
        END ELSE BEGIN
           SELECT BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, MVAAJUSTADO FROM
           CALCULARMVA(:VMVAORIGINAL, :VCST, :VALIQICMS,
           :VVLRUNITCOMDESC + (:VVLRRATEIOITEM/:QTDE), :QTDE,
           :VPERCREDICMS, :VPERCREDST, :VUFCLI, :VUFEMP, :VIPI, :VREDUCAOMVA, :VREGIMETRIBUT, 0, :VVLRIPI, :VVLRPAUTA, :VCHAVEUNIDADE)
           INTO :VAUX, :VAUX2, :VMVACALC;
        END
        IF ((:VCST2 IN ('10','30','70')) OR ((:VCST2 = '90') AND (:VCSTSUBSTTRIB='S') AND (:VALIQICMS>0))) THEN BEGIN
            IF (CAST(:VAUX2 AS NUMERIC(18,2)) = 0) THEN BEGIN
                VBASEICMSSUBSTTRIB = 0;
                VVLRICMSSUBSTTRIB  = 0;
            END ELSE BEGIN
                VBASEICMSSUBSTTRIB = CAST(:VAUX AS NUMERIC(18,2));
                VVLRICMSSUBSTTRIB  = CAST(:VAUX2 AS NUMERIC(18,2));
            END
            VSOMABASESUBSTTRIB = :VSOMABASESUBSTTRIB + :VBASEICMSSUBSTTRIB;
            VSOMAVLRSUBSTTRIB = :VSOMAVLRSUBSTTRIB + :VVLRICMSSUBSTTRIB;
        END ELSE BEGIN
            IF (CAST(:VAUX2 AS NUMERIC(18,2)) = 0) THEN BEGIN
                VBASEICMSSUBSTTRIBDESTAC = 0;
                VVLRICMSSUBSTTRIBDESTAC  = 0;
            END ELSE BEGIN
                VBASEICMSSUBSTTRIBDESTAC = CAST(:VAUX AS NUMERIC(18,2));
                VVLRICMSSUBSTTRIBDESTAC  = CAST(:VAUX2 AS NUMERIC(18,2));
            END
            VSOMABASESUBSTTRIBDEST = :VSOMABASESUBSTTRIBDEST + :VBASEICMSSUBSTTRIBDESTAC;
            VSOMAVLRSUBSTTRIBDEST = :VSOMAVLRSUBSTTRIBDEST + :VVLRICMSSUBSTTRIBDESTAC;
        END
     END ELSE BEGIN
        VBASEICMSSUBSTTRIB       = 0;
        VVLRICMSSUBSTTRIB        = 0;
        VBASEICMSSUBSTTRIBDESTAC = 0;
        VVLRICMSSUBSTTRIBDESTAC  = 0;
     END
     VSOMABASEICMS = :VSOMABASEICMS + :VBASEICMS;
     VSOMAVLRICMS = :VSOMAVLRICMS + :VVLRICMS;

   END
   UPDATE ITENSCONDICIONALPROD SET
   BASEICMS=:VBASEICMS, VLRICMS=:VVLRICMS,
   BASECALCIPI=:VBASECALCIPI, VLRIPI=:VVLRIPI,
   BASEICMSSUBSTTRIB = :VBASEICMSSUBSTTRIB,
   VLRICMSSUBSTTRIB = :VVLRICMSSUBSTTRIB,
   MVACALC=:VMVACALC,
   BASEICMSSUBSTTRIBDESTAC = :VBASEICMSSUBSTTRIBDESTAC,
   VLRICMSSUBSTTRIBDESTAC = :VVLRICMSSUBSTTRIBDESTAC
   WHERE CHAVE=:CHAVEITEM;

   -- ATUALIZA VALORES NA COND.
   UPDATE CONDICIONAL SET
      TOTALCONDICIONAL = ((COALESCE(:VTOTALTABITENS,0) + COALESCE(TOTALSERVICO,0) + COALESCE(:ACRESCVLRCOND,0) + COALESCE(:VSOMARIPI,0) + COALESCE(:VSOMAVLRSUBSTTRIB,0) + COALESCE(VLRACRESCIMO,0)) - COALESCE(DESCVLRPROD,0)),
      TOTALPRODUTO = COALESCE(:VTOTALTABITENS,0) - COALESCE(:DESCVLRPROD,0) + COALESCE(:VLRACRESGLOBALACUM,0),
      TOTALSERVICO= COALESCE(TOTALSERVICO,0) - COALESCE(DESCVLRSERVICO,0),
      TOTALIPI = :VSOMARIPI,
      BCIPI = :VSOMARBCIPI,
      BASECALCULOICMS  = :VSOMABASEICMS,
      VLRICMS = :VSOMAVLRICMS,
      BASECALCICMSSUBST = :VSOMABASESUBSTTRIB,
      VLRICMSSUBST = :VSOMAVLRSUBSTTRIB,
      BASECALCICMSSUBSTDESTAC = :VSOMABASESUBSTTRIBDEST,
      VLRICMSSUBSTDESTAC = :VSOMAVLRSUBSTTRIBDEST
   WHERE (CHAVE=:CHAVECONDICIONAL);
END^


ALTER PROCEDURE RATEIOCOTACAO (
    CHAVECOTACAO INTEGER,
    EMPRESALOG INTEGER)
AS
declare variable ITENSTOTAL numeric(18,4);
declare variable QTDESERV numeric(14,3);
declare variable CONVUNMEDIDA numeric(18,6);
declare variable CSTSUBSTTRIB char(1);
declare variable PERCREDST numeric(18,6);
declare variable SOMARBCIPI numeric(18,6);
declare variable CONVUNMEDSERV numeric(18,6);
declare variable PRECOCUSTO numeric(18,6);
declare variable VLRIPITRIB numeric(18,6);
declare variable DESCPORCSERVICO numeric(7,2);
declare variable VALORTOTCOFINS numeric(18,6);
declare variable SOMARTOTBCPISCOFINSSERV numeric(18,6);
declare variable SOMARTOTCOFINSSERV numeric(18,6);
declare variable SOMARTOTPISSERV numeric(18,6);
declare variable BCPISCOFINSSERV numeric(18,6);
declare variable VLRCOFINSSERV numeric(18,6);
declare variable VLRPISSERV numeric(18,6);
declare variable VLRTOTSERV numeric(18,6);
declare variable CSTPISCOFINSSERV varchar(10);
declare variable VLRTOTBCPISCOFINS numeric(18,6);
declare variable REGIMETRIBUT smallint;
declare variable VALORTOTPIS numeric(18,6);
declare variable VALORPIS numeric(18,6);
declare variable VALORCOFINS numeric(18,6);
declare variable CSTCOFINS integer;
declare variable DESPACESS numeric(18,4);
declare variable BASECALCCOFINS numeric(18,6);
declare variable VLRFRETE numeric(18,4);
declare variable DESCONTO numeric(18,4);
declare variable VLRRATEIO numeric(18,4);
declare variable TOTALPRODUTO numeric(18,4);
declare variable PORC numeric(18,6);
declare variable ALIQICMS numeric(7,2);
declare variable BASEICMS numeric(18,4);
declare variable CST varchar(6);
declare variable DESCPORCPROD numeric(7,2);
declare variable SOMABASEICMS numeric(18,4);
declare variable SOMAVLRICMS numeric(18,4);
declare variable VLRSEGURO numeric(18,6);
declare variable AUX numeric(18,6);
declare variable PERCREDICMS numeric(18,6);
declare variable NROITENS integer;
declare variable ITEMATUAL integer;
declare variable MVAORIG numeric(7,2);
declare variable VLRTOTALITEM numeric(18,6);
declare variable VLRDESCGLOBAL numeric(18,4);
declare variable TOTALSERVICO numeric(18,6);
declare variable IPI numeric(7,2);
declare variable SOMAIPI numeric(18,6);
declare variable VLRIPI numeric(18,6);
declare variable VLRRATEIOITEM numeric(18,6);
declare variable VLRICMS numeric(18,6);
declare variable VLRUNITCOMDESC numeric(18,6);
declare variable MVA numeric(7,2);
declare variable AUX2 numeric(18,6);
declare variable QTDE numeric(15,3);
declare variable UFEMP char(2);
declare variable UFCLI char(2);
declare variable BASEICMSSUBSTTRIB numeric(18,6);
declare variable VLRICMSSUBSTTRIB numeric(18,6);
declare variable SOMABASESUBSTTRIB numeric(18,6);
declare variable SOMAVLRSUBSTTRIB numeric(18,6);
declare variable BASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMABASESUBSTTRIBDEST numeric(18,6);
declare variable SOMAVLRSUBSTTRIBDEST numeric(18,6);
declare variable CHAVEITEM integer;
declare variable DESCONTOSERVICO numeric(18,6);
declare variable CST2 char(2);
declare variable BASECALCIPI numeric(18,6);
declare variable REDUCAOMVA numeric(7,2);
declare variable PESSOA integer;
declare variable CODTABPISCOFINS varchar(10);
declare variable ACRESCVLRPROD numeric(18,6);
declare variable ACRESCPORCPROD numeric(18,6);
declare variable VLRACRESCGLOBAL numeric(18,6);
declare variable VLRPAUTA numeric(18,6);
declare variable VLRACRESGLOBALACUM numeric(18,6);
declare variable CHAVEUNIDADE integer;
declare variable IERG varchar(20);
declare variable VQTDEEST numeric(18,4);
declare variable VCONVERSAO numeric(18,6);
declare variable MVACALC numeric(7,2);
BEGIN
    -- Zera Variaveis
    PORC=0; SOMAVLRICMS=0; SOMABASEICMS=0; SOMAIPI=0; BASEICMSSUBSTTRIB = 0;
    VLRICMSSUBSTTRIB  = 0; SOMABASESUBSTTRIB = 0; SOMAVLRSUBSTTRIB  = 0;
    BASEICMSSUBSTTRIB = 0; VLRICMSSUBSTTRIB  = 0; SOMABASESUBSTTRIB = 0;
    SOMAVLRSUBSTTRIB  = 0; BASEICMSSUBSTTRIBDESTAC = 0;VLRICMSSUBSTTRIBDESTAC = 0;
    SOMABASESUBSTTRIBDEST = 0; SOMAVLRSUBSTTRIBDEST  = 0; VALORTOTCOFINS=0;
    VALORTOTPIS=0; VALORCOFINS=0; VALORPIS=0; BASECALCCOFINS=0; MVACALC=0;
    VLRTOTBCPISCOFINS=0; SOMARTOTPISSERV=0; SOMARTOTCOFINSSERV=0;
    SOMARTOTBCPISCOFINSSERV=0; SOMARBCIPI=0; VLRACRESGLOBALACUM=0;

    SELECT CID.UF, E.REGIMETRIBUT FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE E.CHAVE= :EMPRESALOG
    INTO :UFEMP, :REGIMETRIBUT;
    
    SELECT CID.UF, C.REDUCAOMVA, C.PESSOA, C.IERG FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN COTACAO COT ON C.CHAVE=COT.CHAVECLIFOR
    WHERE COT.CHAVE=:CHAVECOTACAO
    INTO :UFCLI, :REDUCAOMVA, :PESSOA, :IERG;

    --CASO SEJA ISENTO FAZ TRATAMENTO COMO PESSOA FISICA
    IF ((:PESSOA = 0) AND (:IERG IN ('ISENTO',''))) THEN BEGIN
        PESSOA = 1;
        UFCLI = :UFEMP;
    END

    SELECT COALESCE(SUM(VLRTOTAL),0) FROM ITENSCOTACAOPROD
    WHERE CHAVECOTACAO=:CHAVECOTACAO AND ATIVO=1 INTO :TOTALPRODUTO;

    SELECT COALESCE(SUM(VLRTOTAL),0) FROM ITENSCOTACAOSERV
    WHERE CHAVECOTACAO=:CHAVECOTACAO AND ATIVO=1 INTO :TOTALSERVICO;

    SELECT COALESCE(COALESCE(SUM(I.VLRTOTAL),0) - SUM(COALESCE(I.VLRACRESCGLOBAL, 0)),0), COUNT(I.CHAVE)
    FROM ITENSCOTACAOPROD I
    INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS AND CF.COMPORTOTALNF = 0
    WHERE I.CHAVECOTACAO=:CHAVECOTACAO AND I.ATIVO=1
    INTO :TOTALPRODUTO, :NROITENS;

    SELECT COALESCE(C.FRETE,0), COALESCE(C.DESCVLRPROD,0),
    COALESCE(C.DESPACESSORIA,0), COALESCE(C.DESCVLRSERVICO,0),
    COALESCE(C.DESCPORCPROD,0), COALESCE(C.VLRSEGURO,0),
    COALESCE(C.TOTALIPI,0), COALESCE(C.ACRESCVLRPROD,0), COALESCE(C.ACRESCPORCPROD,0)
    FROM COTACAO C
    LEFT JOIN CFOP  CF ON C.CHAVECFOPPROD = CF.CHAVE
    WHERE C.CHAVE=:CHAVECOTACAO
    INTO :VLRFRETE, :DESCONTO, :DESPACESS,
         :DESCONTOSERVICO, :DESCPORCPROD, :VLRSEGURO,
         :SOMAIPI, :ACRESCVLRPROD, :ACRESCPORCPROD;
    VLRRATEIO = :DESPACESS + :VLRFRETE + :VLRSEGURO;

    ITEMATUAL = 0;
    IF ((:ACRESCVLRPROD > 0) AND (:DESCONTO > 0)) THEN BEGIN
        AUX = :DESCONTO * 100;
        AUX = :AUX / (:TOTALPRODUTO + :ACRESCVLRPROD);
        AUX = CAST(AUX AS NUMERIC(18,4));
        DESCPORCPROD = :AUX;
    END

    FOR SELECT I.VLRTOTAL, I.ICMS, I.BASEICMS,
    I.CST, SUBSTRING(I.CST FROM 2 FOR 2), T.PERCRED,
    I.IPI, I.VLRIPI, I.QTDE, I.CHAVE, I.MVA,
    I.BASECALCIPI, I.CSTCOFINS,
    COALESCE(I.PRECOCUSTO,0), COALESCE(TPC.CODIGO,'99'), COALESCE(I.VLRIPITRIB,0), COALESCE(UN.CONVUNMEDIDA,0),
    T.PERCREDST, T.CSTSUBSTTRIB, P.VLRPAUTA, I.CHAVEUNIDADE, COALESCE(I.VLRACRESCGLOBAL,0),
    COALESCE(UN.CONVERSAO,0)
    FROM ITENSCOTACAOPROD I
    INNER JOIN PRODUTO P ON (I.CHAVEPRODUTO=P.CHAVE)
    INNER JOIN COTACAO CO ON (CO.CHAVE=I.CHAVECOTACAO)
    INNER JOIN CLIFOR C ON (C.CHAVE=CO.CHAVECLIFOR)
    INNER JOIN CFOPOPERFISCAIS COF ON COF.CHAVE = I.CHAVECFOPOPERFISCAIS
    INNER JOIN TRIBUTACAO T ON (T.CHAVE=I.CHAVETRIBUTACAO)
    INNER JOIN UNIDADE UN ON (UN.CHAVE=I.CHAVEUNIDADE)
    LEFT JOIN TABELAPISCOFINS TPC ON (TPC.CHAVE=I.CHAVETABPISCOFINS)
    WHERE (I.CHAVECOTACAO=:CHAVECOTACAO) AND (I.ATIVO=1)
    INTO :ITENSTOTAL, :ALIQICMS, :BASEICMS, :CST, :CST2, :PERCREDICMS,
    :IPI, :VLRIPI, :QTDE, :CHAVEITEM, :MVA,
    :BASECALCIPI, :CSTCOFINS,
    :PRECOCUSTO, :CODTABPISCOFINS, :VLRIPITRIB, :CONVUNMEDIDA,
    :PERCREDST, :CSTSUBSTTRIB, :VLRPAUTA, :CHAVEUNIDADE, :VLRACRESCGLOBAL,
    :VCONVERSAO
    DO BEGIN
        ITEMATUAL = :ITEMATUAL + 1;
        VQTDEEST = :QTDE*:VCONVERSAO;
        VLRUNITCOMDESC = :ITENSTOTAL / :VQTDEEST;

        IF (:ACRESCVLRPROD <> 0) THEN BEGIN
            IF (:ITEMATUAL < :NROITENS) THEN BEGIN
                AUX = :ITENSTOTAL - :VLRACRESCGLOBAL;
                AUX = ((:AUX/100) * :ACRESCPORCPROD);
                AUX = CAST(:AUX AS NUMERIC(18,2));
                --PREVENCAO PARA QTDES MAIORES QUE 1
                AUX = CAST(AUX / :QTDE AS NUMERIC(18,2));
                AUX = AUX * :QTDE;
            END ELSE
                AUX = :ACRESCVLRPROD - :VLRACRESGLOBALACUM;
            VLRACRESGLOBALACUM = :VLRACRESGLOBALACUM + :AUX;
            VLRACRESCGLOBAL = :AUX - :VLRACRESCGLOBAL;
            ITENSTOTAL = :ITENSTOTAL + :VLRACRESCGLOBAL; --ACRESCIMO AUMENTA O TOTAL DO ITEM
        END ELSE
            VLRACRESCGLOBAL = :VLRACRESCGLOBAL * (-1); --ABATER VALOR SE JA FOI RATEADO NOS ITENS
        VLRTOTALITEM = :ITENSTOTAL;
        BASEICMS = :ITENSTOTAL;
        MVAORIG = MVA;
        IF (:DESCPORCPROD > 0) THEN BEGIN
            BASEICMS = BASEICMS - ((:BASEICMS/100)*:DESCPORCPROD);
            ITENSTOTAL = :ITENSTOTAL - ((:ITENSTOTAL/100)*:DESCPORCPROD);
        END
        IF (:DESCONTO <> 0) THEN BEGIN
            VLRDESCGLOBAL = 0;
            -- VALOR DESCONTO GLOBAL PRODUTO
            VLRDESCGLOBAL= (:VLRTOTALITEM*100)/(:TOTALPRODUTO);
            VLRDESCGLOBAL = CAST(:VLRDESCGLOBAL AS NUMERIC(7,2));
            VLRDESCGLOBAL = :VLRDESCGLOBAL * :DESCONTO/100;
        END

        PORC = ((:ITENSTOTAL+COALESCE(VLRDESCGLOBAL,0))*100)/:TOTALPRODUTO;
        PORC = CAST(:PORC AS NUMERIC(7,2));

        VLRRATEIOITEM = CAST(:VLRRATEIO / 100 * :PORC AS NUMERIC(18,6));
        --VALOR DO IPI
        IF ((:IPI+:VLRIPITRIB) > 0) THEN BEGIN
            SOMAIPI = SOMAIPI - VLRIPI;
            IF (IPI > 0) THEN BEGIN
                BASECALCIPI = :ITENSTOTAL + :VLRRATEIOITEM;
                VLRIPI  = CAST(:BASECALCIPI * :IPI / 100 AS NUMERIC(18,2));
            END ELSE BEGIN
                BASECALCIPI = 0;
                VLRIPI = ((:CONVUNMEDIDA  * :QTDE) * :VLRIPITRIB);
            END
            SOMARBCIPI = SOMARBCIPI + BASECALCIPI;
            SOMAIPI = :SOMAIPI + :VLRIPI;
            --SOMAR IPI NA BASE ICMS QDO NAO CONTRIBUINTE OU VENDA PARA USO E CONSUMO
            IF ((:PESSOA=1) OR ((:PESSOA =0) AND (:IERG = 'ISENTO'))) THEN
                BASEICMS = :BASEICMS + :VLRIPI;
        END
        IF ((:CST2 IN ('00','10')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S') AND (:ALIQICMS>0) and (:PERCREDICMS=0))) THEN BEGIN
            BASEICMS     = :BASEICMS + :VLRRATEIOITEM;
            VLRICMS      = CAST(:BASEICMS * :ALIQICMS / 100 AS NUMERIC(18,2));
        END
        IF ((:CST2 IN ('20','70')) OR ((:CST2 = '90') AND (:PERCREDICMS>0) AND (:ALIQICMS>0))) THEN BEGIN
            AUX = 0;
            AUX = :BASEICMS + :VLRRATEIOITEM;
            AUX = AUX * ((100 - :PERCREDICMS) / 100);
            BASEICMS = CAST(:AUX AS NUMERIC(18,2));
            AUX = 0;
            AUX = (:BASEICMS/100)*:ALIQICMS;
            VLRICMS = CAST(:AUX AS NUMERIC(18,2));
        END
        IF (:CST2 IN ('51')) THEN BEGIN
            IF (:ALIQICMS > 0) THEN BEGIN
                BASEICMS     = :BASEICMS + :VLRRATEIOITEM;
                VLRICMS      = CAST(:BASEICMS * :ALIQICMS / 100 AS NUMERIC(18,2));
            END ELSE BEGIN
                BASEICMS = 0;
                VLRICMS  = 0;
            END
        END
        IF ((:CST2 IN ('30','40','41','50','60')) OR ((:CST2 = '90') AND (:ALIQICMS=0))) THEN BEGIN
            BASEICMS = 0;
            VLRICMS  = 0;
        END
        -- RATEIA DESCONTO NOS ITENS PROD
        IF (:DESCONTO <> 0) THEN BEGIN
            AUX = 0;
            AUX = :VLRUNITCOMDESC * 100 / :TOTALPRODUTO;
            AUX = :AUX * :DESCONTO / 100;
            VLRUNITCOMDESC = :VLRUNITCOMDESC - :AUX;
        END
        IF (((:CST2 IN ('10','30','60','70')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S') AND (:ALIQICMS>0)))) THEN BEGIN
            AUX  = 0;
            AUX2 = 0;
            IF (:CST2='60') THEN BEGIN
               IF (:MVA>0) THEN BEGIN
                   SELECT BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, MVAAJUSTADO FROM
                   CALCULARMVA(:MVAORIG, :CST, :ALIQICMS,
                   :PRECOCUSTO, :QTDE, 0, 0, :UFCLI, :UFEMP, :IPI, :REDUCAOMVA, :REGIMETRIBUT,0, :VLRIPI, 0, 0)
                   INTO :AUX, :AUX2, :MVACALC;
               END
            END ELSE BEGIN
               SELECT BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, MVAAJUSTADO FROM
               CALCULARMVA(:MVAORIG, :CST, :ALIQICMS,
               :VLRUNITCOMDESC + (:VLRRATEIOITEM/:QTDE), :QTDE,
               :PERCREDICMS, :PERCREDST, :UFCLI, :UFEMP, :IPI, :REDUCAOMVA, :REGIMETRIBUT, 0, :VLRIPI, :VLRPAUTA, :CHAVEUNIDADE)
               INTO :AUX, :AUX2, :MVACALC;
            END
            IF ((:CST2 IN ('10','30','70')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S') AND (:ALIQICMS>0))) THEN BEGIN
                IF (CAST(:AUX2 AS NUMERIC(18,2)) = 0) THEN BEGIN
                    BASEICMSSUBSTTRIB = 0;
                    VLRICMSSUBSTTRIB  = 0;
                END ELSE BEGIN
                    BASEICMSSUBSTTRIB = CAST(:AUX AS NUMERIC(18,2));
                    VLRICMSSUBSTTRIB  = CAST(:AUX2 AS NUMERIC(18,2));
                END
                SOMABASESUBSTTRIB = :SOMABASESUBSTTRIB + :BASEICMSSUBSTTRIB;
                SOMAVLRSUBSTTRIB = :SOMAVLRSUBSTTRIB + :VLRICMSSUBSTTRIB;
            END ELSE BEGIN
                IF (CAST(:AUX2 AS NUMERIC(18,2)) = 0) THEN BEGIN
                    BASEICMSSUBSTTRIBDESTAC = 0;
                    VLRICMSSUBSTTRIBDESTAC  = 0;
                END ELSE BEGIN
                    BASEICMSSUBSTTRIBDESTAC = CAST(:AUX AS NUMERIC(18,2));
                    VLRICMSSUBSTTRIBDESTAC  = CAST(:AUX2 AS NUMERIC(18,2));
                END
                SOMABASESUBSTTRIBDEST = :SOMABASESUBSTTRIBDEST + :BASEICMSSUBSTTRIBDESTAC;
                SOMAVLRSUBSTTRIBDEST = :SOMAVLRSUBSTTRIBDEST + :VLRICMSSUBSTTRIBDESTAC;
            END
        END ELSE BEGIN
            BASEICMSSUBSTTRIB       = 0;
            VLRICMSSUBSTTRIB        = 0;
            BASEICMSSUBSTTRIBDESTAC = 0;
            VLRICMSSUBSTTRIBDESTAC  = 0;
        END
        SOMABASEICMS = :SOMABASEICMS + :BASEICMS;
        SOMAVLRICMS = :SOMAVLRICMS + :VLRICMS;
        -- PIS/COFINS
        SELECT BASE, VALORPIS, VALORCOFINS FROM CALCULARPISCOFINS(:CSTCOFINS, :ITENSTOTAL+:VLRRATEIOITEM, :CODTABPISCOFINS, :QTDE, :CONVUNMEDIDA)
        INTO :BASECALCCOFINS, :VALORPIS, :VALORCOFINS;

        VLRTOTBCPISCOFINS = :VLRTOTBCPISCOFINS + BASECALCCOFINS;
        VALORTOTPIS = :VALORTOTPIS + :VALORPIS;
        VALORTOTCOFINS = :VALORTOTCOFINS + :VALORCOFINS;

        UPDATE ITENSCOTACAOPROD SET
        BASEICMS=:BASEICMS, VLRICMS=:VLRICMS,
        BASECALCIPI=:BASECALCIPI, VLRIPI=:VLRIPI,
        BASEICMSSUBSTTRIB = :BASEICMSSUBSTTRIB,
        VLRICMSSUBSTTRIB = :VLRICMSSUBSTTRIB,
        VLRDESCGLOBAL=:VLRDESCGLOBAL,
        MVACALC=:MVACALC,
        BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC,
        VLRICMSSUBSTTRIBDESTAC = :VLRICMSSUBSTTRIBDESTAC,
        BCPIS=:BASECALCCOFINS, BCCOFINS=:BASECALCCOFINS,
        VLRPIS= :VALORPIS, VLRCOFINS =:VALORCOFINS,
        DESCPORC = CASE WHEN (:VLRACRESCGLOBAL = 0) THEN DESCPORC ELSE CAST((DESCVLR * 100) / (VLRSUBTOTAL + :VLRACRESCGLOBAL) AS NUMERIC(18,4)) END,
        VLRACRESCGLOBAL = COALESCE(VLRACRESCGLOBAL,0) + :VLRACRESCGLOBAL,
        VLRUNIT = VLRUNIT + (:VLRACRESCGLOBAL / :QTDE),
        VLRSUBTOTAL = VLRSUBTOTAL + :VLRACRESCGLOBAL,
        VLRTOTAL = VLRTOTAL + :VLRACRESCGLOBAL,
        VLRUNITTABELA = VLRUNITTABELA + (:VLRACRESCGLOBAL / :QTDE),
        VLRUNITCOMDESC = :VLRUNITCOMDESC
        WHERE CHAVE=:CHAVEITEM;
    END
    -- PIS/COFINS SERVICO
    FOR SELECT GP.CSTPIS, I.VLRTOTAL, COALESCE(COT.DESCPORCSERVICO,0), TPC.CODIGO,
    COALESCE(UN.CONVUNMEDIDA,0), I.QTDE FROM ITENSCOTACAOSERV I
    INNER JOIN COTACAO COT ON COT.CHAVE = I.CHAVECOTACAO
    INNER JOIN PRODUTO P ON P.CHAVE = I.CHAVEPRODUTO
    INNER JOIN GRUPOFISCAL GP ON (CASE WHEN :PESSOA = 0 THEN P.CHAVEGRUPOFISCAL ELSE P.CHAVEGRUPOFISCALPF END = GP.CHAVE)
    INNER JOIN TABELAPISCOFINS TPC ON TPC.CHAVE = GP.CHAVETABELAPISCOFINS
    INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
    WHERE I.ATIVO=1 AND I.CHAVECOTACAO=:CHAVECOTACAO
    INTO :CSTPISCOFINSSERV, :VLRTOTSERV, :DESCPORCSERVICO,
    :CODTABPISCOFINS, :CONVUNMEDSERV, :QTDESERV
    DO BEGIN
        VLRTOTSERV = :VLRTOTSERV - ((:VLRTOTSERV/100)*:DESCPORCSERVICO);
        -- PIS/COFINS
        SELECT BASE, VALORPIS, VALORCOFINS FROM CALCULARPISCOFINS(:CSTPISCOFINSSERV,:VLRTOTSERV,:CODTABPISCOFINS, :QTDESERV, :CONVUNMEDSERV)
        INTO :BCPISCOFINSSERV, :VLRPISSERV, :VLRCOFINSSERV;
        -- ACUMULA TOTAIS DE PIS/COFINS DE SERVICO
        SOMARTOTPISSERV = :SOMARTOTPISSERV + :VLRPISSERV;
        SOMARTOTCOFINSSERV = :SOMARTOTCOFINSSERV + :VLRCOFINSSERV;
        SOMARTOTBCPISCOFINSSERV = :SOMARTOTBCPISCOFINSSERV+BCPISCOFINSSERV;
    END
    -- RATEIA DESC SERV
    IF (:TOTALSERVICO <> 0) THEN BEGIN
        FOR SELECT I.CHAVE, VLRTOTAL
        FROM ITENSCOTACAOSERV I
        INNER JOIN COTACAO COT ON COT.CHAVE=I.CHAVECOTACAO
        WHERE I.ATIVO=1 AND I.CHAVECOTACAO=:CHAVECOTACAO
        INTO :CHAVEITEM, :ITENSTOTAL
        DO BEGIN
            VLRDESCGLOBAL =0;
            -- VALOR DESCONTO GLOBAL SERVICO
            VLRDESCGLOBAL= (:ITENSTOTAL*100)/(:TOTALSERVICO);
            VLRDESCGLOBAL = CAST(:VLRDESCGLOBAL AS NUMERIC(7,2));
            VLRDESCGLOBAL = :VLRDESCGLOBAL * :DESCONTOSERVICO/100;

            UPDATE ITENSPEDSAIDASERV SET
            VLRDESCGLOBAL=:VLRDESCGLOBAL
            WHERE CHAVE=:CHAVEITEM;
        END
    END
    -- ATUALIZA A BASE DE CALCULO ICMS, O VLR DO ICMS E O TOTAL DO ORCAMENTO
    UPDATE COTACAO SET
        TOTALCOTACAO = (:TOTALPRODUTO + :VLRRATEIO  + :TOTALSERVICO + :SOMAIPI + :SOMAVLRSUBSTTRIB + :VLRACRESGLOBALACUM)-(:DESCONTO + :DESCONTOSERVICO),
        TOTALPRODUTO = :TOTALPRODUTO - :DESCONTO + :VLRACRESGLOBALACUM,
        TOTALSERVICO= TOTALSERVICO - :DESCONTOSERVICO,
        TOTALIPI = :SOMAIPI,
        BCIPI = :SOMARBCIPI,
        BASECALCULOICMS  = :SOMABASEICMS,
        VLRICMS = :SOMAVLRICMS,
        BASECALCICMSSUBST = :SOMABASESUBSTTRIB,
        VLRICMSSUBST = :SOMAVLRSUBSTTRIB,
        BASECALCICMSSUBSTDESTAC = :SOMABASESUBSTTRIBDEST,
        VLRICMSSUBSTDESTAC = :SOMAVLRSUBSTTRIBDEST,
        VLRPIS = :VALORTOTPIS, VLRCOFINS= :VALORTOTCOFINS,
        BCPISCOFINS = :VLRTOTBCPISCOFINS,
        VLRPISSERV =  :SOMARTOTPISSERV,
        VLRCOFINSSERV = :SOMARTOTCOFINSSERV,
        BCPISCOFINSSERV = :SOMARTOTBCPISCOFINSSERV
    WHERE (ATIVO=1) AND (CHAVE=:CHAVECOTACAO);
    /*
        CHAMADAS :
            FrmDescmembCot - Usada para refazer valores do novo orcamento desmembrado
            FrmCotacao - Usada para refazer valores do orcamento
    */
END^


ALTER PROCEDURE RATEIOCTRC (
    ECHAVEEMP INTEGER,
    CHAVECTRC INTEGER,
    SOMATOTALITENS NUMERIC(18,6),
    PRODUTOCUSTOCHAVEEMP INTEGER,
    PRODUTOVENDACHAVEEMP INTEGER,
    EPRODVENDAPROMOCHAVEEMP INTEGER,
    CHAVEUSUARIO INTEGER)
AS
declare variable TOTALFRETE numeric(18,6);
declare variable RATEIACUSTOPROD char(1);
declare variable VLRPISCOFINSNOTA numeric(18,6);
declare variable TIPOCONV integer;
declare variable VPORCPVMINIMO numeric(18,4);
declare variable CHAVEITEMPRODALT integer;
declare variable PRECOCUSTOITEMNF numeric(18,6);
declare variable CUSTOPISCOFINS numeric(18,6);
declare variable CUSTOICMS numeric(18,6);
declare variable SOMATOTNFS numeric(18,6);
declare variable VLRICMSNOTA numeric(18,6);
declare variable TOTALITENS numeric(18,6);
declare variable TOTALNF numeric(18,6);
declare variable CHAVEPRODUTO integer;
declare variable AUMENTO numeric(18,6);
declare variable QTDEITENS numeric(18,6);
declare variable VLRICMS numeric(18,6);
declare variable CUSTOUNITARIO numeric(18,6);
declare variable ANTSALDO numeric(15,3);
declare variable CUSTOMEDIOFINAL numeric(18,6);
declare variable PRECOCUSTO numeric(18,6);
declare variable PRECOVENDA numeric(18,6);
declare variable ALTERAPRODUTODIRETO varchar(2);
declare variable NOVOCUSTOPROD numeric(18,6);
declare variable NL double precision;
declare variable SALDOMULTIPLICADOR decimal(15,2);
declare variable CUSTOCTRC numeric(18,6);
declare variable ATUALIZAPRECOVENDA char(1);
declare variable FORMULACALCULOPROD integer;
declare variable CHAVENF integer;
declare variable CHAVEUNIDADE integer;
declare variable CONVERSAO numeric(18,6);
declare variable UPRECOMEDIO numeric(18,6);
declare variable UPRECOCUSTO numeric(18,6);
declare variable UPRECOVENDA numeric(18,6);
declare variable ANTPRECOVENDA numeric(18,6);
declare variable AUX numeric(18,6);
declare variable CHAVEITEM integer;
declare variable CUSTOMEDIOANT numeric(18,6);
declare variable MARGEMVLR numeric(18,6);
declare variable MARGEMPORC numeric(7,2);
declare variable SUBTRAIRRATEIOICMS char(1);
declare variable SALDOCONDICIONAL numeric(18,3);
declare variable TOTALPRODUTO numeric(18,6);
declare variable SUBTRAIRRATEIOPISCOFINS char(1);
declare variable PORC numeric(18,6);
declare variable VLRPIS numeric(18,6);
declare variable VLRCOFINS numeric(18,6);
declare variable AUX2 numeric(18,6);
declare variable VMODOPVMINIMO integer;
declare variable VCHAVETABELAPRECO integer;
declare variable VULTIMACHAVEITEM integer;
declare variable VCHAVEFATORMARKUP integer;
declare variable VPERCFATORMARKUP numeric(7,4);
declare variable VTIPOFATORVENDA integer;
declare variable VPERCSOBRECUSTO numeric(7,4);
BEGIN
    VLRPISCOFINSNOTA = 0;
    SELECT C.ALTERAPRODUTODIRETO, C.FORMULACALCMARGLUCPROD,
    C.CTRCSUBTRAIRATEIOICMS, C.CTRCSUBTRAIRATEIOPISCOFINS, C.CTRCRATEIANOCUSTOPROD
    FROM CONFIG C
    WHERE C.CHAVE = :ECHAVEEMP
    INTO :ALTERAPRODUTODIRETO, :FORMULACALCULOPROD,
    :SUBTRAIRRATEIOICMS, :SUBTRAIRRATEIOPISCOFINS, :RATEIACUSTOPROD;
    SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=184 AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
    INTO :VMODOPVMINIMO;
    SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=303 AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
    INTO :ATUALIZAPRECOVENDA;
    SELECT C.TOTALFRETE, C.VALORICMS, SUM(NF.TOTALNF) AS SOMATOTNF
    FROM CTRC C
    INNER JOIN CTRCNFS CT ON CT.CHAVECTRC = C.CHAVE AND CT.ATIVO=1
    INNER JOIN NFENTRADA NF ON NF.CHAVE = CT.CHAVENF AND NF.ATIVO=1
    WHERE C.CHAVE = :CHAVECTRC
    GROUP BY 1,2
    INTO :TOTALFRETE, :VLRICMS, :SOMATOTNFS;
    SELECT SUM(COALESCE(CPC.VLRCOFINS,0)) AS VLRCOFINS,
    SUM(COALESCE(CPC.VLRPIS,0)) AS VLRPIS
    FROM CTRC C
    INNER JOIN CTRCPISCOFINS CPC ON CPC.CHAVECTRC=C.CHAVE AND CPC.ATIVO=1
    WHERE C.CHAVE = :CHAVECTRC
    GROUP BY C.CHAVE
    INTO :VLRPIS, :VLRCOFINS;
    VULTIMACHAVEITEM= 0;
    FOR SELECT CT.CHAVENF, NF.TOTALNF  FROM CTRCNFS CT
    INNER JOIN NFENTRADA NF ON NF.CHAVE = CT.CHAVENF AND NF.ATIVO=1
    WHERE CT.ATIVO=1 AND CT.CHAVECTRC=:CHAVECTRC
    INTO :CHAVENF, :TOTALNF DO BEGIN
        FOR SELECT I.CHAVE, I.CHAVEPRODUTO,
        COALESCE(PALT.PRECOCUSTOMEDIOANT, PC.PRECOMEDIOANT),
        CASE WHEN COALESCE(PALT.PRECOVENDAANT,0) = 0 THEN COALESCE(PV.PRECOVENDA,0) ELSE COALESCE(PALT.PRECOVENDAANT,0) END,
        CASE WHEN (COALESCE(I.PRECOCUSTO,0) = 0) or (COALESCE(CF.CLASSIFICACAO,0) = 5) THEN COALESCE(PC.PRECOCUSTO,0) ELSE COALESCE(I.PRECOCUSTO,0) END,
        I.VLRTOTAL, NF.TOTALPRODUTO, CAST(I.QTDE AS NUMERIC (14,3)), I.NL,
        I.CHAVEUNIDADE,
        PALT.CHAVE, COALESCE(I.PRECOCUSTO,0),
        CASE WHEN :VMODOPVMINIMO = 0 THEN
            CASE WHEN PV.PRECOVENDAMINIMO > 0 THEN CAST(PV.PRECOVENDAMINIMO * 100 / PC.PRECOCUSTO AS NUMERIC(18,4)) ELSE 0 END
        ELSE
            CASE WHEN PV.PRECOVENDAMINIMO > 0 THEN CAST(PV.PRECOVENDAMINIMO * 100 / PV.PRECOVENDA AS NUMERIC(18,4)) ELSE 0 END
        END AS PORCMINIMO, PV.CHAVETABELAPRECO,
        COALESCE(I.CHAVEFATORMARKUP,0),
        COALESCE(FM.CUSTOFIXO+FM.CUSTOVARIAVEL+FM.COMISSAOSOBREVENDA+FM.LUCROLIQUIDOESPERADO,0), FM.TIPOFATORVENDA, FM.PERCSOBRECUSTO
        FROM ITENSNFENTRADAPROD I
        INNER JOIN NFENTRADA NF ON I.CHAVENFENTRADA=NF.CHAVE
        INNER JOIN CFOP CF ON I.CHAVECFOP=CF.CHAVE
        INNER JOIN PRODUTO P ON I.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOCUSTO PC ON P.CHAVE=PC.CHAVEPRODUTO AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
        INNER JOIN PRODUTOVENDA PV ON (P.CHAVE=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.ATIVO=1)
        LEFT JOIN PRODUTOVENDAPROMOCAO PVP ON (PVP.CHAVEPRODUTO=P.CHAVE) AND (PVP.CHAVEEMPRESA=:EPRODVENDAPROMOCHAVEEMP) AND (PVP.ATIVO=1)
        LEFT JOIN PRODUTOSALTERADOS PALT ON NF.NL = PALT.NL AND I.CHAVEPRODUTO=PALT.CHAVEPRODUTO AND PALT.ATIVO=1 AND PALT.CHAVETABELAPRECO=PV.CHAVETABELAPRECO
        LEFT JOIN FATORMARKUP FM ON FM.CHAVE = I.CHAVEFATORMARKUP
        WHERE NF.CHAVE=:CHAVENF AND I.ATIVO=1
        ORDER BY I.CHAVE
        INTO :CHAVEITEM, :CHAVEPRODUTO,
        :CUSTOMEDIOANT, :ANTPRECOVENDA, :CUSTOUNITARIO,
        :TOTALITENS, :TOTALPRODUTO, :QTDEITENS, :NL,
        :CHAVEUNIDADE, :CHAVEITEMPRODALT, :PRECOCUSTOITEMNF,
        :VPORCPVMINIMO, :VCHAVETABELAPRECO,
        :VCHAVEFATORMARKUP, :VPERCFATORMARKUP,
        :VTIPOFATORVENDA, :VPERCSOBRECUSTO
        DO BEGIN
            MARGEMVLR  = :ANTPRECOVENDA - :CUSTOUNITARIO;
            IF (:FORMULACALCULOPROD = 0) THEN BEGIN
                AUX = :MARGEMVLR / :CUSTOUNITARIO;
                MARGEMPORC = :AUX * 100;
            END ELSE BEGIN
                AUX = :CUSTOUNITARIO / :ANTPRECOVENDA;
                AUX = :AUX * 100;
                MARGEMPORC = 100 - :AUX;
            END
            SELECT COALESCE(SALDO,1), COALESCE(SALDOCONDICIONAL,0) FROM PRODUTOESTOQUE
            WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:ECHAVEEMP
            INTO :ANTSALDO, :SALDOCONDICIONAL;
            IF (:ANTSALDO < 1) THEN
                ANTSALDO= 1;
            SELECT COALESCE(CONVERSAO,0), TIPOCONV FROM UNIDADE
            WHERE CHAVE=:CHAVEUNIDADE
            INTO :CONVERSAO, :TIPOCONV;
            IF (:CONVERSAO > 0) THEN BEGIN
                IF (TIPOCONV = 0) THEN
                    QTDEITENS = :QTDEITENS * CONVERSAO;
                ELSE
                    QTDEITENS = :QTDEITENS / CONVERSAO;
            END
            AUX = (:TOTALFRETE/100);
            AUX2 = TOTALITENS;
            AUX2 = AUX2/(:SOMATOTALITENS/100);
            AUX = AUX * AUX2;
            AUMENTO = AUX / :QTDEITENS;
            NOVOCUSTOPROD  = 0;
            NOVOCUSTOPROD  = :CUSTOUNITARIO + :AUMENTO;
            CUSTOCTRC      = 0;
            CUSTOICMS      = 0;
            CUSTOPISCOFINS = 0;
            CUSTOCTRC     = :AUMENTO;
            IF (:SALDOCONDICIONAL < 0) THEN
                ANTSALDO= :ANTSALDO + (:SALDOCONDICIONAL * (-1));
            SALDOMULTIPLICADOR = :ANTSALDO-:QTDEITENS;
            IF (:SALDOMULTIPLICADOR <= 0) THEN
                SALDOMULTIPLICADOR = 0;
            AUX = (:CUSTOUNITARIO + :AUMENTO) * :QTDEITENS;
            AUX = :AUX + (:SALDOMULTIPLICADOR * :CUSTOMEDIOANT);
            IF ((:ANTSALDO - :QTDEITENS) < 0) THEN
                CUSTOMEDIOFINAL = :AUX / :QTDEITENS;
            ELSE
                CUSTOMEDIOFINAL = :AUX / :ANTSALDO;
            PORC = ((:TOTALNF*100)/:SOMATOTNFS);
            PORC = CAST(:PORC AS NUMERIC(7,2));
            VLRICMSNOTA =(:VLRICMS*:PORC)/100;
            PORC = ((:TOTALNF*100)/:SOMATOTNFS);
            PORC = CAST(:PORC AS NUMERIC(7,2));
            VLRPISCOFINSNOTA =((:VLRPIS+:VLRCOFINS) *:PORC)/100;
            IF (:SUBTRAIRRATEIOICMS = 'S') THEN BEGIN
                AUX= 0;
                PORC=0;
                PORC= (:TOTALITENS*100)/:TOTALPRODUTO;
                PORC = CAST(:PORC AS NUMERIC(7,2));
                AUX= (:VLRICMSNOTA*:PORC)/100;
                AUX=  :AUX/:QTDEITENS;
                CUSTOICMS= :AUX;
                CUSTOMEDIOFINAL= :CUSTOMEDIOFINAL-:AUX;
                NOVOCUSTOPROD = :NOVOCUSTOPROD -:AUX;
            END
            IF ((:SUBTRAIRRATEIOPISCOFINS = 'S') AND (:VLRPISCOFINSNOTA > 0)) THEN BEGIN
                 AUX= 0;
                 PORC=0;
                 PORC= (:TOTALITENS*100)/:TOTALPRODUTO;
                 PORC = CAST(:PORC AS NUMERIC(7,2));
                 AUX= ((:VLRPISCOFINSNOTA)*:PORC)/100;
                 AUX=  :AUX/:QTDEITENS;
                CUSTOMEDIOFINAL= :CUSTOMEDIOFINAL-:AUX;
                NOVOCUSTOPROD = :NOVOCUSTOPROD -:AUX;
                CUSTOPISCOFINS= :AUX;
            END
            IF (:ALTERAPRODUTODIRETO = 'S') THEN BEGIN
                if (:VULTIMACHAVEITEM <> :CHAVEITEM) then begin
                    UPDATE PRODUTOCUSTO SET
                    PRECOCUSTO= CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :NOVOCUSTOPROD ELSE PRECOCUSTO END,
                    PRECOMEDIO= :CUSTOMEDIOFINAL,
                    CHAVEUSUARIOALT=:CHAVEUSUARIO
                    WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP;
                end
                IF (:ATUALIZAPRECOVENDA='S') THEN BEGIN
                    IF (:VCHAVEFATORMARKUP > 0) THEN BEGIN
                        IF (:VTIPOFATORVENDA = 0) THEN BEGIN
                            AUX = 0;
                            AUX = (:VPERCFATORMARKUP / 100);
                            AUX = 1 - :AUX;
                            UPRECOVENDA = :NOVOCUSTOPROD / :AUX;
                        END ELSE BEGIN
                            AUX         =  1 + :VPERCSOBRECUSTO / 100;
                            UPRECOVENDA = :NOVOCUSTOPROD * AUX;
                        END
                    END ELSE
                       UPRECOVENDA = 0;
                    IF (:FORMULACALCULOPROD = 0) THEN BEGIN
                        UPDATE PRODUTOVENDA SET
                            PRECOVENDA = CASE when :VCHAVEFATORMARKUP > 0 THEN :UPRECOVENDA ELSE :NOVOCUSTOPROD + (((:NOVOCUSTOPROD)/100)*:MARGEMPORC) END,
                            PRECOVENDAMINIMO = CASE WHEN :VPORCPVMINIMO > 0 THEN
                                                    CASE WHEN :VMODOPVMINIMO = 0 THEN
                                                        (:NOVOCUSTOPROD*:VPORCPVMINIMO)/100
                                                    ELSE
                                                        ((:NOVOCUSTOPROD + (((:NOVOCUSTOPROD)/100)*:MARGEMPORC))*:VPORCPVMINIMO)/100
                                                    END
                                                ELSE PRECOVENDAMINIMO END,
                            CHAVEUSUARIOALT=:CHAVEUSUARIO
                        WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO);
                    END ELSE BEGIN
                        UPDATE PRODUTOVENDA SET
                            PRECOVENDAMINIMO = CASE WHEN :VPORCPVMINIMO > 0 THEN
                                                    CASE WHEN :VMODOPVMINIMO = 0 THEN
                                                        (:NOVOCUSTOPROD*:VPORCPVMINIMO)/100
                                                    ELSE
                                                        ((:NOVOCUSTOPROD/(1-(:MARGEMPORC/100)))*:VPORCPVMINIMO)/100
                                                    END
                                                ELSE PRECOVENDAMINIMO END,
                            PRECOVENDA= CASE when :VCHAVEFATORMARKUP > 0 THEN :UPRECOVENDA ELSE :NOVOCUSTOPROD/(1-(:MARGEMPORC/100)) END,
                            CHAVEUSUARIOALT=:CHAVEUSUARIO
                        WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO);
                    END
                END
                SELECT PRECOCUSTO FROM PRODUTOCUSTO
                WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
                INTO :PRECOCUSTO;
                SELECT PRECOVENDA FROM PRODUTOVENDA
                WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO) AND (ATIVO=1)
                INTO :PRECOVENDA;
                PRECOCUSTO =:NOVOCUSTOPROD;
            END ELSE BEGIN
                UPRECOMEDIO = :CUSTOMEDIOFINAL;
                UPRECOCUSTO = :NOVOCUSTOPROD;
                IF (:ATUALIZAPRECOVENDA = 'N') THEN
                    UPRECOVENDA = :ANTPRECOVENDA;
                ELSE BEGIN
                    IF (:PRECOCUSTOITEMNF=0) THEN
                        UPRECOCUSTO= :UPRECOCUSTO-:CUSTOUNITARIO;
                    IF (:VCHAVEFATORMARKUP > 0) THEN BEGIN
                        IF (:VTIPOFATORVENDA = 0) THEN BEGIN
                            AUX = 0;
                            AUX = (:VPERCFATORMARKUP / 100);
                            AUX = 1 - :AUX;
                            UPRECOVENDA = :NOVOCUSTOPROD / :AUX;
                        END ELSE BEGIN
                            AUX         =  1 + :VPERCSOBRECUSTO / 100;
                            UPRECOVENDA = :NOVOCUSTOPROD * AUX;
                        END
                    END ELSE BEGIN
                        IF (:FORMULACALCULOPROD = 0) THEN BEGIN
                            UPRECOVENDA = :UPRECOCUSTO + (:UPRECOCUSTO*:MARGEMPORC/100);
                        END ELSE BEGIN
                            AUX = 1 - (:MARGEMPORC / 100);
                            UPRECOVENDA = :UPRECOCUSTO / :AUX;
                        END
                    END
                END
                if (:VULTIMACHAVEITEM <> :CHAVEITEM) then begin
                        UPDATE PRODUTOCUSTO SET
                        PRECOMEDIO= :UPRECOMEDIO,
                        PRECOCUSTO = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :UPRECOCUSTO ELSE PRECOCUSTO END,
                        CHAVEUSUARIOALT=:CHAVEUSUARIO
                    WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP;
                end
                IF ((:VMODOPVMINIMO=0) AND (:VPORCPVMINIMO>0)) THEN BEGIN
                    UPDATE PRODUTOVENDA SET
                        PRECOVENDAMINIMO = (:UPRECOCUSTO*:VPORCPVMINIMO)/100,
                        CHAVEUSUARIOALT=:CHAVEUSUARIO
                    WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO) AND (ATIVO=1);
                END
                IF (:CHAVEITEMPRODALT > 0) THEN BEGIN
                    UPDATE PRODUTOSALTERADOS SET
                    PRECOCUSTO      = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :UPRECOCUSTO ELSE PRECOCUSTO END,
                    PRECOCUSTOMEDIO = :UPRECOMEDIO,
                    PRECOVENDA      = :UPRECOVENDA,
                    PRECOVENDAMINIMO = CASE WHEN :VPORCPVMINIMO > 0 THEN
                                            CASE WHEN :VMODOPVMINIMO = 0 THEN
                                                (CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :UPRECOCUSTO ELSE PRECOCUSTO END *:VPORCPVMINIMO)/100
                                            ELSE
                                                ((:NOVOCUSTOPROD + (((:NOVOCUSTOPROD)/100)*:MARGEMPORC))*:VPORCPVMINIMO)/100
                                            END
                                        ELSE PRECOVENDAMINIMO END
                    WHERE (CHAVE= :CHAVEITEMPRODALT);
                END
                PRECOCUSTO = :UPRECOCUSTO;
                PRECOVENDA = :UPRECOVENDA;
            END
            if (:VULTIMACHAVEITEM <> :CHAVEITEM) then begin
                IF ((RATEIACUSTOPROD='S') OR (:SUBTRAIRRATEIOICMS='S') OR (:SUBTRAIRRATEIOPISCOFINS='S')) THEN BEGIN
                    UPDATE ESTOQUE
                        SET PRECOCUSTO = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :PRECOCUSTO ELSE PRECOCUSTO END
                    WHERE (ORIGEM=2) AND (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP)
                    AND (CHAVEDOC=:CHAVENF) AND (NL=:NL) AND (CHAVEITEM=:CHAVEITEM);
                END
                UPDATE ITENSNFENTRADAPROD SET
                PRECOCUSTO = CASE WHEN (:PRECOCUSTOITEMNF>0) AND (:PRECOCUSTO=0) THEN PRECOCUSTO ELSE :PRECOCUSTO END,
                PRECOVENDA = :PRECOVENDA,
                CUSTOCTRC  = :CUSTOCTRC,
                CUSTOICMSCTRC = :CUSTOICMS,
                CUSTOPISCOFINSCTRC = :CUSTOPISCOFINS
                WHERE CHAVE = :CHAVEITEM;
            end
            VULTIMACHAVEITEM= :CHAVEITEM;
        END
    END
    /*
        CHAMADAS:
            - FRMCTRC : USADA PARA RATEAR O CTRC DE ENTRADA NO CUSTO DOS PRODUTOS DA NF DE ENTRADA
    */
END^


ALTER PROCEDURE RATEIODAVOS (
    CHAVEDAVOS INTEGER)
AS
declare variable VLRACRESCGLOBAL numeric(18,6);
declare variable NOVODESCPORC numeric(18,6);
declare variable ACRESCVLRDAVOS numeric(18,6);
declare variable QTDE numeric(18,4);
declare variable DESCVLR numeric(18,6);
declare variable VLRTOTALITEM numeric(18,6);
declare variable ACRESCPORCPROD numeric(18,6);
declare variable SUBTOTAL numeric(18,6);
declare variable CHAVEITEM integer;
declare variable TOTALPRODUTO numeric(18,6);
declare variable DESCPORCPROD numeric(18,4);
declare variable DESCVLRPROD numeric(18,6);
begin
   VLRACRESCGLOBAL = 0;
   NOVODESCPORC = 0;
   -- SELECIONAR VALORES DAV-OS.

   SELECT ACRESCVLRPROD, ACRESCPORCPROD, TOTALPRODUTO, DESCPORCPROD, DESCVLRPROD
   FROM ORDEMSERVICO
   WHERE (CHAVE=:CHAVEDAVOS)
   INTO :ACRESCVLRDAVOS, :ACRESCPORCPROD, :TOTALPRODUTO, :DESCPORCPROD, :DESCVLRPROD;

   -- SELECIONAR VALORES ITENS DAVO-OS.
   FOR SELECT CHAVE, QTDE, DESCVLR, VLRSUBTOTAL, (VLRTOTAL/QTDE)
   FROM ITENSORDEMSERVICOPROD
   WHERE (ATIVO=1) AND (CHAVEOS=:CHAVEDAVOS)
   INTO :CHAVEITEM, :QTDE, :DESCVLR, :SUBTOTAL, :VLRTOTALITEM
   DO BEGIN
      NOVODESCPORC = 0;
      IF (:ACRESCVLRDAVOS <> 0) THEN BEGIN
         VLRACRESCGLOBAL = ((:VLRTOTALITEM/100) * :ACRESCPORCPROD);
         VLRACRESCGLOBAL = :VLRACRESCGLOBAL * :QTDE;
         VLRACRESCGLOBAL = CAST(VLRACRESCGLOBAL AS NUMERIC(18,2));
         NOVODESCPORC = CAST((:DESCVLR*100) / (:SUBTOTAL + :VLRACRESCGLOBAL) AS NUMERIC(18,4));
         -- ATUALIZA VALORES NO ITEM
         UPDATE ITENSORDEMSERVICOPROD SET
            VLRACRESCGLOBAL=:VLRACRESCGLOBAL,
            VLRUNIT = VLRUNIT + (:VLRACRESCGLOBAL / QTDE),
            DESCPORC = :NOVODESCPORC,
            VLRSUBTOTAL=(VLRSUBTOTAL+:VLRACRESCGLOBAL),
            VLRTOTAL=(VLRTOTAL+:VLRACRESCGLOBAL)
         WHERE (CHAVE=:CHAVEITEM);
      END
   END
   NOVODESCPORC = 0;
   IF (:DESCPORCPROD > 0) THEN
      NOVODESCPORC = CAST((:DESCVLRPROD*100) / (:TOTALPRODUTO + :DESCVLRPROD + :ACRESCVLRDAVOS) AS NUMERIC(18,4));
   -- ATUALIZA VALORES NA DAV-OS.
   UPDATE ORDEMSERVICO SET
      TOTALPRODUTO = (TOTALPRODUTO + :ACRESCVLRDAVOS),
      DESCPORCPROD = :NOVODESCPORC
   WHERE (CHAVE=:CHAVEDAVOS);
end^


ALTER PROCEDURE RATEIOGNRE (
    QTDEITENSGNRE INTEGER,
    ECHAVEEMP INTEGER,
    CHAVEGNRE INTEGER,
    PRODUTOCUSTOCHAVEEMP INTEGER,
    PRODUTOVENDACHAVEEMP INTEGER,
    PACHAVEEMPRESA INTEGER,
    CHAVEUSUARIO INTEGER)
AS
declare variable TOTALGNRE numeric(18,4);
declare variable TIPODOC integer;
declare variable CHAVEITEMPRODALT integer;
declare variable PRECOCUSTOITEMNF numeric(18,6);
declare variable VPORCPVMINIMO numeric(18,6);
declare variable NLNF double precision;
declare variable NUMEROGNRE varchar(9);
declare variable DESCRICAO varchar(30);
declare variable VENCIMENTO date;
declare variable CHAVEPLANOCONTA integer;
declare variable CHAVEEMPRESA integer;
declare variable UPRECOCUSTO numeric(18,4);
declare variable UPRECOVENDA numeric(18,4);
declare variable UPRECOMEDIO numeric(18,4);
declare variable PRECOVENDA numeric(18,4);
declare variable PRECOCUSTO numeric(18,6);
declare variable CUSTOMEDIOFINAL numeric(18,4);
declare variable ANTSALDO numeric(18,4);
declare variable TOTALITENS numeric(18,4);
declare variable SALDOMULTIPLICADOR numeric(18,4);
declare variable TOTALNF numeric(18,6);
declare variable CHAVEPRODUTO integer;
declare variable QTDEITENS numeric(7,2);
declare variable VLRRATEIO numeric(18,6);
declare variable CUSTOUNITARIO numeric(18,6);
declare variable ALTERAPRODUTODIRETO varchar(2);
declare variable NL double precision;
declare variable ATUALIZAPRECOVENDA char(1);
declare variable FORMULACALCULOPROD integer;
declare variable NOVOCUSTOPROD numeric(18,6);
declare variable CHAVENF integer;
declare variable CONVERSAO decimal(15,2);
declare variable ANTPRECOVENDA numeric(18,6);
declare variable AUX numeric(18,6);
declare variable CHAVEITEM integer;
declare variable CUSTOMEDIOANT numeric(18,6);
declare variable MARGEMVLR numeric(18,6);
declare variable MARGEMPORC numeric(7,2);
declare variable CHAVECLIFOR integer;
declare variable GERARPAGAR char(10);
declare variable RATEIACUSTOPROD char(1);
declare variable VMODOPVMINIMO integer;
declare variable VCUSTO numeric(18,6);
declare variable VCUSTOANT numeric(18,6);
declare variable VMEDIO numeric(18,6);
declare variable VCHAVEEMPPAGAR integer;
declare variable VVENDA numeric(18,6);
declare variable VCHAVETABELAPRECO integer;
BEGIN
    VLRRATEIO=0;
    SELECT C.ALTERAPRODUTODIRETO, C.FORMULACALCMARGLUCPROD,
           C.GNRERATEIANOCUSTOPROD, C.GNREGERAPAGAR
    FROM CONFIG C
    WHERE C.CHAVE = :ECHAVEEMP
    INTO :ALTERAPRODUTODIRETO, :FORMULACALCULOPROD,
         :RATEIACUSTOPROD, :GERARPAGAR;
    SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=184 AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
    INTO :VMODOPVMINIMO;
    SELECT VALOR FROM CONFIGCAMPOS
    WHERE INDICE=303 AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
    INTO :ATUALIZAPRECOVENDA;
    SELECT G.CHAVENF,  G.CHAVEEMPRESA, G.VALOR, G.DATAVENC, G.NL, G.CHAVECLIFOR, G.TIPODOC
    FROM GNRE G
    INNER JOIN NFENTRADA NF ON NF.CHAVE= G.CHAVENF
    WHERE G.CHAVE=:CHAVEGNRE AND G.TIPO=1
    INTO :CHAVENF, :CHAVEEMPRESA, :TOTALGNRE, :VENCIMENTO, :NL, :CHAVECLIFOR, :TIPODOC;
      SELECT CHAVEEMPRESAREF FROM CONFIGCOMPART
      WHERE CHAVEEMPRESA=:CHAVEEMPRESA AND TABELA = 'PAGAR'
      INTO :VCHAVEEMPPAGAR;
    FOR SELECT CHAVEITEM, TOTALITENS, QTDEITENS, CONVERSAO, TOTALNF,
    ANTPRECOVENDA, CUSTOUNITARIO, CUSTOMEDIOANT,
    CHAVEPRODUTO, NUMEROGNRE, NL,
    CHAVEPRODALT, CUSTOITEMNF, SCHAVETABELAPRECO
    FROM RETORNARITENSGNRE(:CHAVEGNRE,:PRODUTOCUSTOCHAVEEMP,
    :PRODUTOVENDACHAVEEMP, :QTDEITENSGNRE)
    INTO :CHAVEITEM, :TOTALITENS, :QTDEITENS, :CONVERSAO, :TOTALNF,
    :ANTPRECOVENDA, :CUSTOUNITARIO, :CUSTOMEDIOANT,
    :CHAVEPRODUTO, :NUMEROGNRE,:NLNF,
    :CHAVEITEMPRODALT, :PRECOCUSTOITEMNF, :VCHAVETABELAPRECO
    DO BEGIN
       MARGEMVLR  = :ANTPRECOVENDA - :CUSTOUNITARIO;
       IF (:FORMULACALCULOPROD = 0) THEN BEGIN
          AUX = :MARGEMVLR / :CUSTOUNITARIO;
          MARGEMPORC = :AUX * 100;
       END ELSE BEGIN
          AUX = :CUSTOUNITARIO / :ANTPRECOVENDA;
          AUX = :AUX * 100;
          MARGEMPORC = 100 - :AUX;
       END
       IF (QTDEITENSGNRE > 0) THEN BEGIN
            IF (:CONVERSAO > 0) THEN
                QTDEITENS = :QTDEITENS * CONVERSAO;
            VLRRATEIO = :TOTALITENS/:QTDEITENS;
       END ELSE BEGIN
          IF (:CONVERSAO > 0) THEN
             QTDEITENS = :QTDEITENS * CONVERSAO;
          AUX = :TOTALITENS*100/:TOTALNF;
          VLRRATEIO = (:AUX*:TOTALGNRE)/100;
          VLRRATEIO = :VLRRATEIO/:QTDEITENS;
       END
       NOVOCUSTOPROD = :CUSTOUNITARIO+:VLRRATEIO;
       SELECT COALESCE(SALDO,1) FROM PRODUTOESTOQUE
       WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:ECHAVEEMP
       INTO :ANTSALDO ;
       SELECT
        CASE WHEN :VMODOPVMINIMO = 0 THEN
            CASE WHEN PV.PRECOVENDAMINIMO > 0 THEN CAST(PV.PRECOVENDAMINIMO * 100 / PC.PRECOCUSTO AS NUMERIC(18,4)) ELSE 0 END
        ELSE
            CASE WHEN PV.PRECOVENDAMINIMO > 0 THEN CAST(PV.PRECOVENDAMINIMO * 100 / PV.PRECOVENDA AS NUMERIC(18,4)) ELSE 0 END
       END
       FROM PRODUTOVENDA PV
       INNER JOIN PRODUTOCUSTO PC ON (PV.CHAVEPRODUTO=PC.CHAVEPRODUTO) AND (PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP) AND (PC.ATIVO=1)
       WHERE (PV.ATIVO=1) AND (PV.CHAVEPRODUTO=:CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP)
       AND (PV.CHAVETABELAPRECO=:VCHAVETABELAPRECO)
       INTO :VPORCPVMINIMO;
       IF (:ANTSALDO < 1) THEN
          ANTSALDO= 1;
       SALDOMULTIPLICADOR = :ANTSALDO-:QTDEITENS;
       IF (:SALDOMULTIPLICADOR <= 0) THEN
         SALDOMULTIPLICADOR = 0;
       AUX = :CUSTOUNITARIO * :QTDEITENS;
       AUX = :AUX + (:SALDOMULTIPLICADOR * :CUSTOMEDIOANT);
       IF ((:ANTSALDO - :QTDEITENS) < 0) THEN BEGIN
         CUSTOMEDIOFINAL = :AUX / :QTDEITENS;
       END ELSE BEGIN
         CUSTOMEDIOFINAL = :AUX / :ANTSALDO;
       END
       CUSTOMEDIOFINAL = :CUSTOMEDIOFINAL+:VLRRATEIO;
       IF (ALTERAPRODUTODIRETO = 'S') THEN BEGIN
            UPDATE PRODUTOCUSTO SET
                PRECOCUSTO = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :NOVOCUSTOPROD ELSE PRECOCUSTO END ,
                PRECOMEDIO = :CUSTOMEDIOFINAL,
                CHAVEUSUARIOALT=:CHAVEUSUARIO
            WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP;
          IF (:ATUALIZAPRECOVENDA='S') THEN BEGIN
             IF (:FORMULACALCULOPROD = 0) THEN BEGIN
                UPDATE PRODUTOVENDA SET
                PRECOVENDA= :NOVOCUSTOPROD + (((:NOVOCUSTOPROD)/100)*:MARGEMPORC),
                PRECOVENDAMINIMO = CASE WHEN :VPORCPVMINIMO > 0 THEN
                                        CASE WHEN :VMODOPVMINIMO = 0 THEN
                                            (:NOVOCUSTOPROD*:VPORCPVMINIMO)/100
                                        ELSE
                                            ((:NOVOCUSTOPROD + (((:NOVOCUSTOPROD)/100)*:MARGEMPORC))*:VPORCPVMINIMO)/100
                                        END
                                    ELSE PRECOVENDAMINIMO END
                WHERE (CHAVEPRODUTO=:CHAVEPRODUTO)
                AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP)
                AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO);
             END ELSE BEGIN
                UPDATE PRODUTOVENDA SET
                PRECOVENDA= :NOVOCUSTOPROD/(1-(:MARGEMPORC/100)),
                PRECOVENDAMINIMO = CASE WHEN :VPORCPVMINIMO > 0 THEN
                                        CASE WHEN :VMODOPVMINIMO = 0 THEN
                                            (:NOVOCUSTOPROD*:VPORCPVMINIMO)/100
                                        ELSE
                                            ((:NOVOCUSTOPROD/(1-(:MARGEMPORC/100)))*:VPORCPVMINIMO)/100
                                        END
                                    ELSE PRECOVENDAMINIMO END
                WHERE (CHAVEPRODUTO=:CHAVEPRODUTO)
                AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP)
                AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO);
             END
          END
         /* -- ATUALIZA OS CAMPOS NO ITENSNFENTRADA
          SELECT PRECOCUSTO FROM PRODUTOCUSTO
          WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
          INTO :PRECOCUSTO;  */
          SELECT PRECOVENDA FROM PRODUTOVENDA
          WHERE (CHAVEPRODUTO=:CHAVEPRODUTO)
          AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP)
          AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO)
          INTO :PRECOVENDA;
          PRECOCUSTO =:NOVOCUSTOPROD;
       END ELSE BEGIN
          UPRECOMEDIO = :CUSTOMEDIOFINAL;
          UPRECOCUSTO = :NOVOCUSTOPROD;
          IF (:ATUALIZAPRECOVENDA = 'N') THEN
            UPRECOVENDA = :ANTPRECOVENDA;
          ELSE BEGIN
             IF (:FORMULACALCULOPROD = 0) THEN
                UPRECOVENDA = :UPRECOCUSTO + (:UPRECOCUSTO*:MARGEMPORC/100);
             ELSE BEGIN
                AUX = 1 - (:MARGEMPORC / 100);
                UPRECOVENDA = :UPRECOCUSTO / :AUX;
             END
          END
          UPDATE PRODUTOCUSTO SET
            PRECOMEDIO= :UPRECOMEDIO,
            PRECOCUSTO = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :UPRECOCUSTO ELSE PRECOCUSTO END,
            CHAVEUSUARIOALT=:CHAVEUSUARIO
          WHERE CHAVEPRODUTO=:CHAVEPRODUTO AND CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP;
          IF ((:VMODOPVMINIMO=0) AND (:VPORCPVMINIMO>0)) THEN BEGIN
             UPDATE PRODUTOVENDA SET
                 PRECOVENDAMINIMO = (:UPRECOCUSTO*:VPORCPVMINIMO)/100,
                 CHAVEUSUARIOALT=:CHAVEUSUARIO
             WHERE (CHAVEPRODUTO=:CHAVEPRODUTO)
             AND (CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP)
             AND (CHAVETABELAPRECO=:VCHAVETABELAPRECO);
          END
          IF (:CHAVEITEMPRODALT > 0) THEN BEGIN
            UPDATE PRODUTOSALTERADOS SET
            PRECOCUSTO = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :UPRECOCUSTO ELSE PRECOCUSTO END,
            PRECOCUSTOMEDIO = :UPRECOMEDIO,
            PRECOVENDA      = :UPRECOVENDA,
            PRECOVENDAMINIMO = CASE WHEN :VPORCPVMINIMO > 0 THEN
                                    CASE WHEN :VMODOPVMINIMO = 0 THEN
                                        (CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :UPRECOCUSTO ELSE PRECOCUSTO END *:VPORCPVMINIMO)/100
                                    ELSE
                                        ((:NOVOCUSTOPROD + (((:NOVOCUSTOPROD)/100)*:MARGEMPORC))*:VPORCPVMINIMO)/100
                                    END
                                ELSE PRECOVENDAMINIMO END
            WHERE CHAVE= :CHAVEITEMPRODALT;
          END ELSE BEGIN
             SELECT
             CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :UPRECOCUSTO ELSE PC.PRECOCUSTO END,
             PC.PRECOCUSTO,
             PC.PRECOMEDIO,
             PV.PRECOVENDA
             FROM PRODUTO P
             INNER JOIN PRODUTOCUSTO PC ON P.CHAVE=PC.CHAVEPRODUTO AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
             INNER JOIN PRODUTOVENDA PV ON (P.CHAVE=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP)
             AND (PV.CHAVETABELAPRECO=:VCHAVETABELAPRECO)
             WHERE P.CHAVE=:CHAVEPRODUTO
             INTO :VCUSTO, :VCUSTOANT, :VMEDIO, :VVENDA;
             EXECUTE PROCEDURE INSERIRREGPRODALTERADOS(:PACHAVEEMPRESA, :CHAVEPRODUTO, 1, :CHAVENF, :NL, CURRENT_DATE,
                 :VCUSTO, :VCUSTOANT,:UPRECOMEDIO, :VMEDIO, :UPRECOVENDA, :VVENDA, NULL, :CHAVEITEM,
                 NULL, NULL, :VCHAVETABELAPRECO);
          END
          PRECOCUSTO = :UPRECOCUSTO;
          PRECOVENDA = :UPRECOVENDA;
       END
       IF (RATEIACUSTOPROD='S') THEN BEGIN
          UPDATE ESTOQUE
          SET PRECOCUSTO = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :PRECOCUSTO ELSE PRECOCUSTO END
          WHERE (ORIGEM=2) AND (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP)
          AND (CHAVEDOC=:CHAVENF) AND (NL=:NLNF) AND (CHAVEITEM=:CHAVEITEM);
       END
       UPDATE ITENSNFENTRADAPROD SET
       PRECOCUSTO = CASE WHEN :PRECOCUSTOITEMNF > 0 THEN :PRECOCUSTO ELSE PRECOCUSTO END,
       PRECOVENDA =:PRECOVENDA,
       CUSTOGNRE  =COALESCE(CUSTOGNRE,0)+:VLRRATEIO
       WHERE CHAVE = :CHAVEITEM;
    END
    IF (GERARPAGAR = 'S') THEN BEGIN
        IF (TIPODOC = 0) THEN
          DESCRICAO = 'REF GNRE NUMERO ';
        ELSE
          DESCRICAO = 'REF DARE NUMERO ';
       DESCRICAO = DESCRICAO||:NUMEROGNRE;
            
       SELECT CHAVEPLANOCONTA FROM CONFIGCAIXA
       WHERE CHAVE=25
       INTO :CHAVEPLANOCONTA;
       IF (CHAVEPLANOCONTA IS NULL ) THEN
          CHAVEPLANOCONTA = 2;
       INSERT INTO PAGAR
       (CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
       DATACONTA, DATAENTRADA, DESCRICAO, DOCUMENTO, OBS,
       PARCELA, TIPO, TOTPARC, VALOR, VENCIMENTO, COMPETENCIA, STATUS, NL, ORIGEM,
       CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
       VALUES
       (:VCHAVEEMPPAGAR, 2, :CHAVECLIFOR, :CHAVEPLANOCONTA,
       current_date , current_date, :DESCRICAO, :NUMEROGNRE, '',
       1, 1, 1, :TOTALGNRE, :VENCIMENTO, SUBSTRING(CAST(:VENCIMENTO AS VARCHAR(10)) FROM 6 FOR 2)||'/'|| SUBSTRING(CAST(:VENCIMENTO AS VARCHAR(10)) FROM 1 FOR 4),
       1, :NL, 2, :CHAVEUSUARIO, :CHAVEUSUARIO);
   END
   /*
   CHAMADAS :
   FrmGNRE : Calcular custos do produto
             gerar financeiro do documento
   */
END^


ALTER PROCEDURE RATEIOITENSPEDSAIDA (
    CHAVEPEDIDO INTEGER)
AS
declare variable ALIQUOTAISS numeric(18,6);
declare variable DIFERENCA double precision;
declare variable BASEISSPED numeric(18,6);
declare variable VLRSUBTRAIR numeric(18,6);
declare variable VLRISSCALC numeric(18,6);
declare variable VLRISS numeric(18,6);
declare variable TOTALISS numeric(18,6);
declare variable CHAVEITENSPS integer;
BEGIN
    SELECT COALESCE(TOTALISS,0), COALESCE(BASEISS,0), COALESCE(ALIQUOTAISS,0)
    FROM PEDIDOSAIDA PS
    WHERE PS.CHAVE=:CHAVEPEDIDO
    INTO :TOTALISS, :BASEISSPED, :ALIQUOTAISS;
    IF (:TOTALISS > 0) THEN BEGIN
        VLRISSCALC = CAST(((:BASEISSPED*:ALIQUOTAISS)/100) AS NUMERIC(18,2));
        IF (:TOTALISS>:VLRISSCALC) THEN BEGIN
           DIFERENCA   = (:TOTALISS - :VLRISSCALC);
           VLRSUBTRAIR = 0.01;
           FOR SELECT I.CHAVE, I.VLRISS
           FROM ITENSPEDSAIDASERV I
           WHERE (I.ATIVO=1) AND (I.CHAVEPEDIDO=:CHAVEPEDIDO) AND COALESCE(I.BASEISS,0)>0 AND COALESCE(I.ISS,0)>0
           AND ((I.VLRISS > ABS((I.BASEISS*I.ISS)/100)))
           INTO :CHAVEITENSPS, :VLRISS
           DO BEGIN
              IF ((:DIFERENCA>=:VLRSUBTRAIR) AND (:VLRISS > 0)) THEN BEGIN
                UPDATE ITENSPEDSAIDASERV SET VLRISS = VLRISS - 0.01
                WHERE CHAVE= :CHAVEITENSPS;
              END
              VLRSUBTRAIR = :VLRSUBTRAIR + 0.01;
           END
           UPDATE PEDIDOSAIDA SET
           TOTALISS = :VLRISSCALC
           WHERE CHAVE=:CHAVEPEDIDO;
        END
    END
    /*
        CHAMADAS :
        FRMPEDIDOSAIDA - USADA PARA REFAZER OS VALORES DE ISS CASO O VALOR DA BASE * ALIQUOTA SEJA DIFERENTE DO TOTAL ISS DISCRIMINADO NO PEDIDO (USADA SOMENTE PARA O LAYOUT SYSTEMPRO)
    */
END^


ALTER PROCEDURE RATEIONFCONSUMIDOR (
    CHAVENF INTEGER,
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER,
    CHAVEUSUARIO INTEGER)
AS
declare variable VALORCOFINS numeric(18,6);
declare variable VALORTOTBCPISCOFINS numeric(18,6);
declare variable PERCREDST numeric(18,6);
declare variable CONVUNMEDIDA numeric(18,6);
declare variable VLRCOFINSTRIB numeric(18,6);
declare variable VLRPISTRIB numeric(18,6);
declare variable PRECOCUSTO numeric(18,6);
declare variable BASECALCCOFINS integer;
declare variable REGIMETRIBUT smallint;
declare variable VALORTOTCOFINS numeric(18,6);
declare variable VALORTOTPIS numeric(18,6);
declare variable VALORPIS numeric(18,6);
declare variable CSTCOFINS integer;
declare variable CSTPIS integer;
declare variable CONVERSAO numeric(18,6);
declare variable ITENSTOTAL numeric(18,4);
declare variable MVAORIG numeric(7,2);
declare variable QTDEEST numeric(18,4);
declare variable CHAVEITENSNF integer;
declare variable ALIQICMS numeric(7,2);
declare variable VLRICMS numeric(18,4);
declare variable CST varchar(6);
declare variable BASEICMS numeric(18,4);
declare variable SOMABASEICMS numeric(18,4);
declare variable SOMAVLRICMS numeric(18,4);
declare variable CST2 varchar(2);
declare variable AUX numeric(18,6);
declare variable PERCREDICMS numeric(18,6);
declare variable VLRUNITCOMDESC numeric(18,6);
declare variable MVA numeric(7,2);
declare variable BASEICMSSUBSTTRIB numeric(18,6);
declare variable VLRICMSSUBSTTRIB numeric(18,6);
declare variable BASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable AUX2 numeric(18,6);
declare variable SOMABASESUBSTTRIB numeric(18,6);
declare variable SOMABASESUBSTTRIBDEST numeric(18,6);
declare variable SOMAVLRSUBSTTRIB numeric(18,6);
declare variable SOMAVLRSUBSTTRIBDEST numeric(18,6);
declare variable QTDE numeric(15,3);
declare variable UFEMP char(2);
declare variable DOCUMENTO varchar(9);
declare variable CHAVECFOP integer;
declare variable CHAVECFOPOPERFISCAIS integer;
declare variable CHAVETRIBUTACAO integer;
declare variable CODTABPISCOFINS varchar(10);
declare variable ALIQPIS numeric(7,2);
declare variable ALIQCOFINS numeric(7,2);
BEGIN
    SOMAVLRICMS=0;SOMABASEICMS=0;
    SOMABASESUBSTTRIB=0;SOMABASESUBSTTRIBDEST=0; SOMAVLRSUBSTTRIB=0;
    SOMAVLRSUBSTTRIBDEST=0;
    VALORTOTCOFINS=0; VALORTOTPIS=0; VALORCOFINS=0; VALORPIS=0;
    BASECALCCOFINS=0; VALORTOTBCPISCOFINS=0;

    SELECT CID.UF, E.REGIMETRIBUT FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE E.CHAVE= :CHAVEEMPESTOQUE
    INTO :UFEMP, :REGIMETRIBUT;

    FOR SELECT I.CHAVE, I.VLRTOTAL, I.VLRUNITCOMDESC, I.QTDE, U.CONVERSAO,
    T.CODIGO AS CST, T.ALIQUOTADE, T.PERCRED, P.MVA,
    GP.CSTPIS, GP.CSTCOFINS, SUBSTRING(T.CODIGO FROM 2 FOR 2), CF.CHAVECFOPPRODDE,
    CF.CHAVE, GP.CHAVETRIBUTACAO, COALESCE(I.PRECOCUSTO,0),
    (SELECT CODIGO FROM TABELAPISCOFINS WHERE CHAVE = GP.CHAVETABELAPISCOFINS), COALESCE(U.CONVUNMEDIDA,0),
    T.PERCREDST
    FROM ITENSNFSAIDA I
    INNER JOIN NFSAIDA NF ON (NF.CHAVE=I.CHAVENFSAIDA)
    INNER JOIN PRODUTO P ON (I.CHAVEPRODUTO=P.CHAVE)
    INNER JOIN GRUPOFISCAL GP ON (P.CHAVEGRUPOFISCALPF=GP.CHAVE)
    INNER JOIN TRIBUTACAO T ON (T.CHAVE=GP.CHAVETRIBUTACAO)
    INNER JOIN CFOPOPERFISCAIS CF ON (GP.CHAVECFOPOPERFISCAIS=CF.CHAVE)
    INNER JOIN UNIDADE U ON (I.CHAVEUNIDADE=U.CHAVE)
    LEFT JOIN CLIFOR C ON (C.CHAVE=NF.CHAVECLIFOR)
    WHERE (I.ATIVO=1) AND (I.CHAVENFSAIDA=:CHAVENF)
    INTO :CHAVEITENSNF, :ITENSTOTAL, :VLRUNITCOMDESC, :QTDE, :CONVERSAO,
    :CST, :ALIQICMS, :PERCREDICMS, :MVA,
    :CSTPIS, :CSTCOFINS, :CST2, :CHAVECFOP, :CHAVECFOPOPERFISCAIS, :CHAVETRIBUTACAO, :PRECOCUSTO,
    :CODTABPISCOFINS, :CONVUNMEDIDA, :PERCREDST
    DO BEGIN
        -- CALCULAR QTDE ESTOQUE COM CONVERSAO
        IF (CONVERSAO > 0) THEN
            QTDEEST = :QTDE*:CONVERSAO;
        ELSE
            QTDEEST = :QTDE;
        BASEICMS = :ITENSTOTAL;
        MVAORIG = MVA;

        IF (:CST2 IN ('00','10')) THEN BEGIN
            VLRICMS      = CAST(:BASEICMS * :ALIQICMS / 100 AS NUMERIC(18,2));
        END
        IF (:CST2 IN ('20','70')) THEN BEGIN
            AUX = 0;
            AUX = :BASEICMS;
            AUX = AUX * (100 - :PERCREDICMS) / 100;
            BASEICMS = CAST(:AUX AS NUMERIC(18,2));
            AUX = 0;
            AUX = (:BASEICMS/100)*:ALIQICMS;
            VLRICMS = CAST(:AUX AS NUMERIC(18,2));
        END
        IF (:CST2 IN ('51','90')) THEN BEGIN
            IF (:ALIQICMS > 0) THEN BEGIN
                VLRICMS      = CAST(:BASEICMS * :ALIQICMS / 100 AS NUMERIC(18,2));
            END ELSE BEGIN
                BASEICMS = 0;
                VLRICMS  = 0;
            END
        END
        IF (:CST2 IN ('30','40','41','50','60')) THEN BEGIN
            BASEICMS = 0;
            VLRICMS  = 0;
        END
        -- RATEIA DESCONTO NOS ITENS PROD
        /*IF (:DESCONTO <> 0) THEN BEGIN
            AUX = 0;
            AUX = :VLRUNITCOMDESC * 100 / :TOTALPRODUTO;
            AUX = :AUX * :DESCONTO / 100;
            VLRUNITCOMDESC = :VLRUNITCOMDESC - :AUX;
        END*/
        -- RECALCULA SUBSTITUICAO TRIBUTARIA
        IF ((:MVA<>0) AND (:CST2 IN ('10','30','60','70'))) THEN BEGIN
            AUX  = 0;
            AUX2 = 0;
            IF (:CST2='60') THEN BEGIN
               SELECT BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, MVAAJUSTADO FROM
               CALCULARMVA(:MVAORIG, :CST, :ALIQICMS,
               :PRECOCUSTO, :QTDE, 0, 0, :UFEMP, :UFEMP, 0, 0,:REGIMETRIBUT,0,0, 0, 0)
               INTO :AUX, :AUX2, :MVA;
            END ELSE BEGIN
               SELECT BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, MVAAJUSTADO FROM
               CALCULARMVA(:MVAORIG, :CST, :ALIQICMS,
               :VLRUNITCOMDESC, :QTDE,
               :PERCREDICMS, :PERCREDST, :UFEMP, :UFEMP, 0, 0, :REGIMETRIBUT,0,0,0,0)
               INTO :AUX, :AUX2, :MVA;
            END
            IF (:CST2 IN ('10','30','70')) THEN BEGIN
                BASEICMSSUBSTTRIB = CAST(:AUX AS NUMERIC(18,2));
                VLRICMSSUBSTTRIB  = CAST(:AUX2 AS NUMERIC(18,2));
                SOMABASESUBSTTRIB = :SOMABASESUBSTTRIB + :BASEICMSSUBSTTRIB;
                SOMAVLRSUBSTTRIB = :SOMAVLRSUBSTTRIB + :VLRICMSSUBSTTRIB;
            END ELSE BEGIN
                BASEICMSSUBSTTRIBDESTAC = CAST(:AUX AS NUMERIC(18,2));
                VLRICMSSUBSTTRIBDESTAC  = CAST(:AUX2 AS NUMERIC(18,2));
                SOMABASESUBSTTRIBDEST = :SOMABASESUBSTTRIBDEST + :BASEICMSSUBSTTRIBDESTAC;
                SOMAVLRSUBSTTRIBDEST = :SOMAVLRSUBSTTRIBDEST + :VLRICMSSUBSTTRIBDESTAC;
            END
            IF (:CST2 = '60') THEN BEGIN
                UPDATE ITENSNFSAIDA SET ICMS = 0
                WHERE CHAVE=:CHAVEITENSNF;
            END
            IF (:CST2 IN ('10','30','70')) THEN BEGIN
                UPDATE ITENSNFSAIDA SET MVACALC = :MVA
                WHERE CHAVE=:CHAVEITENSNF;
            END
        END ELSE BEGIN
            BASEICMSSUBSTTRIB       = 0;
            VLRICMSSUBSTTRIB        = 0;
            BASEICMSSUBSTTRIBDESTAC = 0;
            VLRICMSSUBSTTRIBDESTAC  = 0;
        END

        SOMABASEICMS = :SOMABASEICMS + :BASEICMS;
        SOMAVLRICMS = :SOMAVLRICMS + :VLRICMS;
        -- PIS/COFINS
        SELECT BASE, VALORPIS, VALORCOFINS, ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB FROM CALCULARPISCOFINS(:CSTCOFINS, :ITENSTOTAL, :CODTABPISCOFINS, :QTDE, :CONVUNMEDIDA)
        INTO :BASECALCCOFINS, :VALORPIS, :VALORCOFINS, :ALIQPIS, :ALIQCOFINS, :VLRPISTRIB, :VLRCOFINSTRIB;

        VALORTOTPIS = :VALORTOTPIS + :VALORPIS;
        VALORTOTCOFINS = :VALORTOTCOFINS + :VALORCOFINS;
        VALORTOTBCPISCOFINS = :VALORTOTBCPISCOFINS + :BASECALCCOFINS;

        UPDATE ITENSNFSAIDA SET
            CHAVETRIBUTACAO=:CHAVETRIBUTACAO,
            CHAVECFOP=:CHAVECFOP,
            CHAVECFOPOPERFISCAIS=:CHAVECFOPOPERFISCAIS,
            MOVESTOQUE=1,
            COMPORTOTALNF = 0,
            CST=:CST, CSTPIS=:CSTPIS, CSTCOFINS=:CSTCOFINS,
            BASEICMS=:BASEICMS, VLRICMS=:VLRICMS, ICMS=:ALIQICMS,
            BASECALCIPI=0, VLRIPI=0, IPI=0,
            BASEICMSSUBSTTRIB = :BASEICMSSUBSTTRIB, VLRICMSSUBSTTRIB = :VLRICMSSUBSTTRIB,
            BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC,
            VLRICMSSUBSTTRIBDESTAC = :VLRICMSSUBSTTRIBDESTAC,
            VLRUNITCOMDESC = :VLRUNITCOMDESC ,
            VLRFRETE = 0, VLRSEGURO = 0, VLRDESPACESSORIA = 0,
            QTDEESTOQUE = :QTDEEST,
            VLRICMSSIMPLESNACIONAL = 0,
            BCPIS = :BASECALCCOFINS, BCCOFINS = :BASECALCCOFINS,
            VLRPIS= :VALORPIS, VLRCOFINS = :VALORCOFINS,
            ALIQCOFINS=:ALIQCOFINS, ALIQPIS=:ALIQPIS,
            VLRPISTRIB=:VLRPISTRIB, VLRCOFINSTRIB=:VLRCOFINSTRIB
        WHERE CHAVE=:CHAVEITENSNF;
    END

    -- ATUALIZA A BASE DE CALCULO ICMS, O VLR DO ICMS E O TOTAL DO PEDIDO
    UPDATE NFSAIDA SET
        ORIGEMNF                = 0,
        STATUS                  = 1,
        CHAVECFOPPROD           = :CHAVECFOP,
        CHAVECFOPOPERFISCAIS    = :CHAVECFOPOPERFISCAIS,
        FRETEPORCONTA           = 3,
        TOTALSERVICO            = 0,
        TOTALIPI                = 0,
        BCIPI                   = 0,
        BASECALCULOICMS         = :SOMABASEICMS,
        VLRICMS                 = :SOMAVLRICMS,
        BASEICMSSIMPLESNACIONAL = 0,
        VLRICMSSIMPLESNACIONAL  = 0,
        ALIQICMSSIMPLESNACIONAL = 0,
        BASECALCICMSSUBST       = :SOMABASESUBSTTRIB,
        VLRICMSSUBST            = :SOMAVLRSUBSTTRIB,
        BASECALCICMSSUBSTDESTAC = :SOMABASESUBSTTRIBDEST,
        VLRICMSSUBSTDESTAC      = :SOMAVLRSUBSTTRIBDEST,
        VLRPIS = :VALORTOTPIS , VLRCOFINS=:VALORTOTCOFINS,
        BCPISCOFINS = :VALORTOTBCPISCOFINS
    WHERE (ATIVO=1) AND (CHAVE=:CHAVENF);

    SELECT NUMERONF FROM NFSAIDA
    WHERE CHAVE=:CHAVENF
    INTO :DOCUMENTO;

    EXECUTE PROCEDURE BAIXAESTOQUENF(:CHAVENF, :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO, :CHAVEUSUARIO, :DOCUMENTO);

    /*
        CHAMADAS :
        CHPDV - Usada para atualizar os valores da nf de consumidor pelo CHPDV

    */
END^


