DECLARE VARIABLE SOMAVLRICMS NUMERIC(18,6);
DECLARE VARIABLE CST2 VARCHAR(2);
DECLARE VARIABLE TOTALSERV NUMERIC(18,6);
DECLARE VARIABLE DESCVLRSERV NUMERIC(18,6);
DECLARE VARIABLE VLRSEGURO NUMERIC(18,6);
DECLARE VARIABLE SUBSTMANUAL CHAR(1);
DECLARE VARIABLE PERCREDICMS NUMERIC(18,6);
DECLARE VARIABLE AUX NUMERIC(18,6);
DECLARE VARIABLE AUX2 NUMERIC(18,6);
DECLARE VARIABLE BASEICMSSUBSTTRIB NUMERIC(18,6);
DECLARE VARIABLE VLRICMSSUBSTTRIB NUMERIC(18,6);
DECLARE VARIABLE BASEICMSSUBSTTRIBDESTAC NUMERIC(18,6);
DECLARE VARIABLE VLRICMSSUBSTTRIBDESTAC NUMERIC(18,6);
DECLARE VARIABLE VLRIPI NUMERIC(18,6);
DECLARE VARIABLE IPI NUMERIC(7,2);
DECLARE VARIABLE SOMAIPI NUMERIC(18,6);
DECLARE VARIABLE VLRRATEIOITEM NUMERIC(18,6);
DECLARE VARIABLE MVA NUMERIC(18,6);
DECLARE VARIABLE SOMABASESUBSTTRIB NUMERIC(18,6);
DECLARE VARIABLE SOMAVLRSUBSTTRIB NUMERIC(18,6);
DECLARE VARIABLE SOMABASESUBSTTRIBDEST NUMERIC(18,6);
DECLARE VARIABLE SOMAVLRSUBSTTRIBDEST NUMERIC(18,6);
DECLARE VARIABLE VLRUNITCOMDESC NUMERIC(18,6);
DECLARE VARIABLE QTDE NUMERIC(18,6);
DECLARE VARIABLE UFEMP CHAR(2);
DECLARE VARIABLE UFFORNECEDOR CHAR(2);
DECLARE VARIABLE MVAAJUSTADO NUMERIC(7,2);
DECLARE VARIABLE TIPOPROD INTEGER;
DECLARE VARIABLE MODELONF VARCHAR(2);
DECLARE VARIABLE BASECALCIPI NUMERIC(18,6);
DECLARE VARIABLE MVAORIG NUMERIC(7,2);
DECLARE VARIABLE BASEICMSSERV NUMERIC(18,6);
DECLARE VARIABLE VLRICMSSERV NUMERIC(18,6);
DECLARE VARIABLE VLRPAGOTERCEIROS NUMERIC(18,6);
DECLARE VARIABLE REDUCAOMVA NUMERIC(7,2);
DECLARE VARIABLE VLRDESPACESSACUMULADO NUMERIC(18,6);
DECLARE VARIABLE VLRFRETEACUMULADO NUMERIC(18,6);
DECLARE VARIABLE VLRSEGUROACUMULADO NUMERIC(18,6);
DECLARE VARIABLE VTOTALBASEISS NUMERIC(18,6);
DECLARE VARIABLE VMACROALTERARBASEISS VARCHAR(1);
DECLARE VARIABLE VALIQISSITEM NUMERIC(7,4);
DECLARE VARIABLE VTOTALISS NUMERIC(18,6);
DECLARE VARIABLE VBASEISSITEM NUMERIC(18,6);
DECLARE VARIABLE VLRDESCGLOBALACUMULADO NUMERIC(18,6);
DECLARE VARIABLE VSOMAVLRICMSFCPST NUMERIC(18,6);
DECLARE VARIABLE VVLRICMSFCPST NUMERIC(18,6);
DECLARE VARIABLE VLRIPIXML NUMERIC(18,6);
DECLARE VARIABLE VVLRICMSDESONERADO NUMERIC(18,6);
DECLARE VARIABLE VSOMAVLRICMSDESONERADO NUMERIC(18,6);
DECLARE VARIABLE VAUX NUMERIC(18,6);
DECLARE VARIABLE VI INTEGER;
DECLARE VARIABLE VVLRICMSDIFAL NUMERIC(18,6);
DECLARE VARIABLE VBASECALCDIFAL NUMERIC(18,6);
DECLARE VARIABLE VALIQINTERNA NUMERIC(18,2);
DECLARE VARIABLE VBASEIVA NUMERIC(18,6);
DECLARE VARIABLE BASEIVAUNIT NUMERIC(18,6);
DECLARE VARIABLE VCALCREFTRIB CHAR(1);
DECLARE VARIABLE VBCIVAAUX NUMERIC(18,6);
DECLARE VARIABLE VCHAVECLASSTRIB INTEGER;
DECLARE VARIABLE VCHAVECIDADE INTEGER;
DECLARE VARIABLE VVLRIBSDIFMUN NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSMUN NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSDIFUF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSUF NUMERIC(18,6);
DECLARE VARIABLE VVLRCBSDIF NUMERIC(18,6);
DECLARE VARIABLE VVLRCBS NUMERIC(18,6);
DECLARE VARIABLE VALIQIBSMUN NUMERIC(7,2);
DECLARE VARIABLE VALIQIBSUF NUMERIC(7,2);
DECLARE VARIABLE VALIQCBS NUMERIC(7,2);
DECLARE VARIABLE VPERCREDGOV NUMERIC(18,6);
DECLARE VARIABLE VCHAVECREDPRES INTEGER;
DECLARE VARIABLE VBCCREDPRES NUMERIC(18,6);
DECLARE VARIABLE VVLRCREDPRESIBS NUMERIC(18,6);
DECLARE VARIABLE VVLRCREDPRESCBS NUMERIC(18,6);
DECLARE VARIABLE VPERCCREDPRES NUMERIC(18,6);
DECLARE VARIABLE VBASEIVANF NUMERIC(18,6);
DECLARE VARIABLE VVLRCBSNF NUMERIC(18,6);
DECLARE VARIABLE VVLRCBSDIFNF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSUFNF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSDIFUFNF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSMUNNF NUMERIC(18,6);
DECLARE VARIABLE VVLRIBSDIFMUNNF NUMERIC(18,6);
DECLARE VARIABLE VVLRCREDPRESCBSNF NUMERIC(18,6);
DECLARE VARIABLE VVLRCREDPRESIBSNF NUMERIC(18,6);
DECLARE VARIABLE NAOCALCICMSSOBFRETE CHAR(1);
DECLARE VARIABLE NAOCALCIPISOBVLRADIC CHAR(1);
DECLARE VARIABLE VSOMARIMPIMPORTBCICMS CHAR(1);
DECLARE VARIABLE VLRRATEIOFRETEITEM NUMERIC(18,6);
DECLARE VARIABLE VLRRATEIOSEGDESPACESSITEM NUMERIC(18,6);
DECLARE VARIABLE VLRSEGDESPACESS NUMERIC(18,6);
DECLARE VARIABLE ICMSDESONDEDUZTOTNF SMALLINT;
DECLARE VARIABLE VVLRTOTICMSDESONERADO NUMERIC(18,6);
BEGIN
    PORC=0; SOMABASEICMS=0; VLRRATEIO=0; SOMAVLRICMS=0; SOMARBCIPI=0; SOMAIPI=0;
    SOMABASESUBSTTRIB=0;SOMABASESUBSTTRIBDEST=0;SOMAVLRSUBSTTRIB=0;
    SOMAVLRSUBSTTRIBDEST=0;DESPACESS=0;VLRSEGURO=0;VLRFRETE=0;
    BASEICMSSUBSTTRIB=0;VLRICMSSUBSTTRIB=0;TOTALPROD=0;TOTALSERV=0;VTOTALBASEISS=0;VTOTALISS=0;
    BASEICMSSUBSTTRIBDESTAC=0;VLRICMSSUBSTTRIBDESTAC=0;
    VLRTOTPIS=0; VLRTOTCOFINS=0; VALORPIS=0; VALORCOFINS=0;
    BASECALCCOFINS=0;VLRPAGOTERCEIROS=0;
    DESCVLRPROD=0;DESCVLRSERV=0;REDUCAOMVA=0;BASEICMSSERV=0;
    SOMARPISSERV=0; SOMARCOFINSSERV=0;TOTALBCPISCOFINS=0;
    SOMARBCPISCOFINSSERV =0; VLRIMPIMPORTITEM =0; VLRIOFITEM=0; VLRDESCPADUAITEM = 0;
    SOMAVLRICMSNFIMP=0; SOMABASEICMSNFIMP = 0; OBSNFIMP = ''; DESTACARICMSNFIMP = 'N';
    VLRFRETEACUMULADO=0; VLRSEGUROACUMULADO=0; VLRDESPACESSACUMULADO=0;
    VLRDESCGLOBALACUMULADO = 0; VSOMAVLRICMSFCPST = 0; VVLRICMSFCPST = 0; VVLRICMSDESONERADO = 0; VSOMAVLRICMSDESONERADO = 0;
    VAUX = 0; VLRIPIXML = 0; VSOMARIPIBCICMS = 'N'; VVLRICMSDIFAL = 0; VALIQINTERNA =0; VBASECALCDIFAL =0; VVLRCBSNF = 0;
    VVLRCBSDIFNF = 0; VVLRIBSUFNF = 0; VVLRIBSDIFUFNF = 0; VVLRIBSMUNNF = 0; VVLRIBSDIFMUNNF = 0; VBASEIVANF = 0;
    VVLRCREDPRESCBSNF = 0; VVLRCREDPRESIBSNF = 0; VLRSEGDESPACESS = 0; SOMARVLRIPIDEVOLV = 0; VVLRTOTICMSDESONERADO = 0; VSOMARIMPIMPORTBCICMS = 'N';
    SELECT VALOR
    FROM CONFIGCAMPOS
    WHERE CHAVEEMPRESA = :CHAVEEMPESTOQUE AND INDICE = 239
    INTO :INTEGRARIPIPISCOFINS;
    SELECT VALOR
    FROM CONFIGCAMPOS
    WHERE CHAVEEMPRESA = :CHAVEEMPESTOQUE AND INDICE = 240
    INTO :INTEGRARSTPISCOFINS;
    SELECT VALOR
    FROM CONFIGCAMPOS
    WHERE CHAVEEMPRESA = :CHAVEEMPESTOQUE AND INDICE = 289
    INTO :CASADECIMALVLRUNITNFENT;
    SELECT CID.UF, E.REGIMETRIBUT, E.CHAVECIDADE, CASE WHEN COALESCE(CALCREFTRIB,0) = 0 THEN 'S' ELSE 'N' END
    FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE E.CHAVE= :CHAVEEMPNFENTRADA
    INTO :UFEMP, :REGIMETRIB, :VCHAVECIDADE, :VCALCREFTRIB;
    SELECT CID.UF, C.REDUCAOMVA FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN NFENTRADA NF ON C.CHAVE=NF.CHAVECLIFOR
    WHERE NF.CHAVE=:CHAVENF
    INTO :UFFORNECEDOR, :REDUCAOMVA;
    SELECT COALESCE(SUM(I.VLRTOTAL),0), CASE WHEN COALESCE(SUM(I.CUSTOFRETEXML),0)> 0 THEN 'S' ELSE 'N' END,
    CASE WHEN COALESCE(SUM(I.CUSTOSEGUROXML),0) > 0 THEN 'S' ELSE 'N' END,
    CASE WHEN COALESCE(SUM(I.CUSTODESPACESSXML),0) > 0 THEN 'S' ELSE 'N' END
    FROM ITENSNFENTRADAPROD I
    INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS AND CF.COMPORTOTALNF = 0
    WHERE I.CHAVENFENTRADA=:CHAVENF AND I.ATIVO=1
    INTO :TOTALPROD, :TEMCUSTOFRETEXML, :TEMCUSTOSEGUROXML, TEMCUSTODESPACESSXML;
    SELECT COALESCE(SUM(VLRTOTAL),0), COALESCE(SUM(COALESCE(BASEICMS,0)),0), COALESCE(SUM(COALESCE(VLRICMS,0)),0)
    FROM ITENSNFENTRADASERV
    WHERE CHAVENFENTRADA=:CHAVENF AND ATIVO=1
    INTO :TOTALSERV, :BASEICMSSERV, :VLRICMSSERV;
    SELECT SUM(COALESCE(VLRII,0)), SUM(COALESCE(VLRDESPADU,0)), SUM(COALESCE(VLRIOF,0)) FROM IMPOSTOSIMPORTACAO
    WHERE ATIVO=1 AND CHAVENF=:CHAVENF
    INTO :VLRII, :VLRDESPADUA, :VLRIOF;
    SELECT COALESCE(N.FRETE,0), COALESCE(N.DESCONTOVLR,0), COALESCE(N.DESPACESSORIA,0),
    COALESCE(N.VLRSEGURO,0), COALESCE(N.DESCONTOPORC,0), N.MODELONF,
    COALESCE(N.DESCVLRSERVICO,0), COALESCE(N.TOTALIPI,0),
    COALESCE(N.BASECALCICMSSUBSTDESTAC,0), COALESCE(N.VLRCALCICMSSUBSTDESTAC,0),
    COALESCE(N.VLRPAGOTERCEIROS,0), SUBSTRING(C.CODIGO FROM 1 FOR 1),
    M.INTEGRARIPIBCPISCOFINS, M.INTEGRARSTBCPISCOFINS, COALESCE(M.CHAVE,0), COALESCE(M.NAOSOMARICMSTOTALNF,'N'),
    COALESCE(M.ALTERARBASEISS,'N'), COALESCE(M.NAOABATERDESCIPI,'N'), COALESCE(M.NAOCALCIPISOBREFRETE,'N'), COALESCE(M.NAOCALCICMSSOBFRETE,'N'), COALESCE(M.ABATERICMSBASEPISCOFINS, 'N'),
    N.FRETEPORCONTA, COALESCE(M.SOMARSTIPIDESPACESSNFSAIDA, 'N'), N.OBS,
    COALESCE(M.NAOABATERDESCICMS, 'N'), COALESCE(M.NAOCALCICMSVLRADIC, 'N'), COALESCE(M.NAOCALCIPISOBVLRADIC, 'N'), N.NL,
    COALESCE(M.SOMARIMPIMPORTBCICMS, 'N')
    FROM NFENTRADA N
    LEFT JOIN CFOP C ON (C.CHAVE=N.CHAVECFOPPROD)
    LEFT JOIN MACROES M ON (M.CHAVE=N.CHAVEMACROES)
    WHERE N.CHAVE=:CHAVENF
    INTO :VLRFRETE, :DESCVLRPROD, :DESPACESS,
    :VLRSEGURO, :DESCPORCPROD, :MODELONF,
    :DESCVLRSERV, :SOMAIPI,
    :SOMABASESUBSTTRIBDEST, :SOMAVLRSUBSTTRIBDEST,
    :VLRPAGOTERCEIROS, :CFOPNF,
    :INTEGRARIPIPISCOFINSMACRO, :INTEGRARSTPISCOFINSMACRO, :CHAVEMACRO, :VNAOSOMARICMSTOTALNF,
    :VMACROALTERARBASEISS, :NAOABATERDESCIPI, :NAOCALCIPISOBREFRETE, :NAOCALCICMSSOBFRETE, :ABATERICMSBASEPISCOFINS,
    :VFRETEPORCONTA, :VSOMARSTIPIDESPACESS, :OBS, :VNAOABATERDESCICMS, :VNAOCALCICMSVLRADIC, :NAOCALCIPISOBVLRADIC, :VNL,
    :VSOMARIMPIMPORTBCICMS;
    SELECT
         CASE
            WHEN COUNT(OLF.CHAVE) > 0 THEN 'S'
            ELSE 'N'
         END TEMCOMPLEANULACAO
    FROM OBSLIVROFISCCOMPLDOCFISC OLF
    INNER JOIN OBSCOMPLDOCFISCAL O ON (O.CHAVE=OLF.CHAVEOBSCOMPLFISCAL)
    WHERE (OLF.ATIVO=1) AND (OLF.NL=:VNL) AND (OLF.TIPO=1) AND
    (OLF.CHAVEDOCFISCAL=:CHAVENF) AND (OLF.TIPODOCFISCAL=0)
    AND O.CHAVE=27
    INTO :TEMCOMPLANULACAO;
    IF (:MODELONF IN ('06','28','29')) THEN BEGIN 
        VLRRATEIO = 0;
        VLRSEGDESPACESS = 0;
    END ELSE BEGIN 
        VLRRATEIO = :DESPACESS + :VLRFRETE + :VLRSEGURO;
        VLRSEGDESPACESS = :DESPACESS + :VLRSEGURO;
    END
    FOR SELECT I.CHAVE, I.VLRUNITCOMDESC, I.VLRTOTAL, I.ICMS,
    case UN.CONVERSAO
         when 0 then I.QTDE
         else case
                when UN.TIPOCONV=0 then cast(I.QTDE * UN.CONVERSAO as numeric(18,6))
                else cast(I.QTDE / UN.CONVERSAO as numeric(18,6))
              end
       end,
    I.BASEICMS, I.IPI, I.BASECALCIPI, I.VLRIPI, I.VLRIPIXML, P.TIPO,
    I.CST, SUBSTRING(I.CST FROM 2 FOR 2), T.PERCRED, COALESCE(I.MVA,0),
    COALESCE(BASEICMSSUBSTTRIB,0), COALESCE(VLRICMSSUBSTTRIB,0),
    COALESCE(BASEICMSSUBSTTRIBDESTAC,0), COALESCE(VLRICMSSUBSTTRIBDESTAC,0),
    I.SUBSTMANUAL, I.CSTCOFINS, I.ALIQPIS, I.ALIQCOFINS,
    SUBSTRING(C.CODIGO FROM 1 FOR 1), CL.REGIMETRIBUTARIO,
    COALESCE(I.VLRIPITRIB,0), UN.CONVUNMEDIDA,
    I.VLRPISTRIB,  I.VLRCOFINSTRIB, C.CLASSIFICACAO, I.COMPORTOTALNF, T.PERCREDST,
    COALESCE(CUSTOFRETEXML,0), COALESCE(CUSTOSEGUROXML,0), COALESCE(CUSTODESPACESSXML,0), T.CSTSUBSTTRIB, COALESCE(I.DESCVLR,0), I.VLRUNIT,
    COALESCE(COF.OPERCONSUMIDORFINAL,'N'), T.CODIGOSOSN, COALESCE(NF.CHAVESERIENF,0), COALESCE(I.VLRICMSFCPST, 0),
    COALESCE(I.VLRICMSDESONERADO, 0), COALESCE(I.PERCREDIPI, 0), COALESCE(I.BCPIS, 0), COALESCE(I.SOMARIPIBCICMS, 'N'),
    COALESCE(T.ICMSDESON,1), COALESCE(T.PERCDIF,0), I.BASEIVA, I.CHAVECLASSTRIB, COALESCE(I.ALIQCBS, 0), COALESCE(I.ALIQIBSUF, 0),
    COALESCE(I.ALIQIBSMUN, 0), COALESCE(COF.PERCREDOPGOV,0), COALESCE(I.PERCCREDPRES,0), COALESCE(I.CHAVECREDPRES,0),
    COALESCE(I.VLRIPIDEVOLV, 0), COALESCE(I.ICMSDESONDEDUZTOTNF, 0)
    FROM ITENSNFENTRADAPROD I
    INNER JOIN NFENTRADA NF ON NF.CHAVE = I.CHAVENFENTRADA
    INNER JOIN CLIFOR CL ON CL.CHAVE = NF.CHAVECLIFOR
    INNER JOIN PRODUTO P ON P.CHAVE = I.CHAVEPRODUTO
    INNER JOIN TRIBUTACAO T ON T.CHAVE = I.CHAVETRIBUTACAO
    INNER JOIN CFOP C ON C.CHAVE = I.CHAVECFOP
    INNER JOIN CFOPOPERFISCAIS COF ON COF.CHAVE = I.CHAVECFOPOPERFISCAIS
    INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
    WHERE I.CHAVENFENTRADA=:CHAVENF AND I.ATIVO=1
    INTO :CHAVEITENSNF, :VLRUNITCOMDESC, :VLRITENSTOTAL, :ALIQICMS,
    :QTDE, :BASEICMS, :IPI, :BASECALCIPI, :VLRIPI,:VLRIPIXML, :TIPOPROD,
    :CST, :CST2, :PERCREDICMS, :MVA,
    :BASEICMSSUBSTTRIB, :VLRICMSSUBSTTRIB,
    :BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC, :SUBSTMANUAL,
    :CSTCOFINS, :ALIQPIS, :ALIQCOFINS, :CFOPITEM, :REGIMETRIBUT,
    :VLRIPITRIB, :CONVUNMEDIDA,
    :VLRPISTRIB, :VLRCOFINSTRIB, :CLASSIFICACAOCFOP, :COMPORTOTALNF, :PERCREDST,
    :CUSTOFRETE, :CUSTOSEGURO, :CUSTODESPACESS, :CSTSUBSTTRIB, :DESCVLR, :VLRUNIT,
    :OPERACAOCONSFINAL, :CODSIMPLESNAC, :CHAVESERIENF, :VVLRICMSFCPST, :VVLRICMSDESONERADO,
    :PERCREDIPI, :VBCPIS, :VSOMARIPIBCICMS, :VICMSDESON, :VPERCDIF, :VBASEIVA, :VCHAVECLASSTRIB,
    :VALIQCBS, :VALIQIBSUF, :VALIQIBSMUN, :VPERCREDGOV, :VPERCCREDPRES, :VCHAVECREDPRES,
    :VVALORIPIDEVOLV, :ICMSDESONDEDUZTOTNF
    DO BEGIN
        ITEMDESPACESSORIA = 0;
        SELECT COALESCE(CHAVEOBSCOMPLFISCAL, 0) FROM OBSLIVROFISCCOMPLDOCFISC
        WHERE (ATIVO=1) AND (TIPODOCFISCAL=0) AND (CHAVEOBSCOMPLFISCAL=27) AND (CHAVEDOCFISCAL=:CHAVENF)
        INTO :CHAVEOBSCOMPLFISCAL;
        IF (COALESCE(CHAVEOBSCOMPLFISCAL, 0) > 0) THEN
            CLASSIFICACAOCFOP = 3;
        VAUX = 0;
        MVAORIG = :MVA;
        IF ((:CHAVESERIENF > 0) OR (:VBASEIVA = 0)) THEN
            VBASEIVA = :VLRITENSTOTAL;
        IF ((BASEICMS = 0) OR (NOT ((:CFOPITEM = '3') AND (:CHAVESERIENF > 0) AND (:MODELONF = '55')))) THEN
            BASEICMS = :VLRITENSTOTAL;
        IF (:DESCPORCPROD > 0) THEN
            BASEICMS= :BASEICMS - ((:BASEICMS/100)*:DESCPORCPROD);
        PORC = (:VLRITENSTOTAL*100) / :TOTALPROD;
        IF ((:TEMCUSTOFRETEXML='S') OR (:TEMCUSTOSEGUROXML='S') OR (:TEMCUSTODESPACESSXML='S')) THEN BEGIN 
            VLRRATEIOITEM = CAST((:CUSTOFRETE + :CUSTOSEGURO + :CUSTODESPACESS) AS NUMERIC(18,2));
            VLRRATEIOFRETEITEM = CAST((:CUSTOFRETE) AS NUMERIC(18,2));
            VLRRATEIOSEGDESPACESSITEM = CAST((:CUSTOSEGURO + :CUSTODESPACESS) AS NUMERIC(18,2));
        END ELSE BEGIN
            VLRRATEIOITEM = 0;
            VLRRATEIOFRETEITEM = 0;
            VLRRATEIOSEGDESPACESSITEM = 0;
            IF (:VLRRATEIO > 80000) THEN BEGIN
                VAUX = :VLRRATEIO/10;
                VI = 1;
                WHILE (VI <= 10) DO BEGIN
                    VLRRATEIOITEM = :VLRRATEIOITEM + CAST(CAST(:VAUX AS NUMERIC(18,6)) * CAST(PORC AS NUMERIC(18,6))/100 AS NUMERIC(18,6));
                    VI = :VI+1;
                END
                VLRRATEIOITEM = :VLRRATEIOITEM;
            END ELSE
                VLRRATEIOITEM = CAST((:VLRRATEIO * PORC) / 100 AS NUMERIC(18,6));
            VLRRATEIOFRETEITEM = CAST((:VLRFRETE * PORC) / 100 AS NUMERIC(18,6));
            VLRRATEIOSEGDESPACESSITEM = CAST((:VLRSEGDESPACESS * PORC) / 100 AS NUMERIC(18,6));
        END
        IF ((:CLASSIFICACAOCFOP = 3) AND (:VVALORIPIDEVOLV > 0)) THEN
            SOMARVLRIPIDEVOLV = SOMARVLRIPIDEVOLV + VVALORIPIDEVOLV;
        VLRIPI = CAST(:VLRIPI AS NUMERIC(18,2));
        IF ((:IPI+:VLRIPITRIB) > 0)  THEN BEGIN
            SOMAIPI = SOMAIPI - VLRIPI;
            IF (IPI > 0 ) THEN BEGIN
                IF ((BASECALCIPI = 0) OR (NOT ((:CFOPITEM = '3') AND (:CHAVESERIENF > 0) AND (:MODELONF = '55')))) THEN BEGIN
                    BASECALCIPI = 0;
                    BASECALCIPI = :VLRITENSTOTAL + :VLRRATEIOITEM;
                END
                IF (:NAOABATERDESCIPI = 'S') THEN    /* NAO AGREGAR O VALOR DO DESCONTO NO ITEM AO UTILIZAR A MACRO */
                    BASECALCIPI = :BASECALCIPI + :DESCVLR;
                IF (:NAOABATERDESCIPI = 'N') THEN
                    BASECALCIPI= :BASECALCIPI - ((:VLRITENSTOTAL/100)*:DESCPORCPROD);
                IF (:NAOCALCIPISOBREFRETE = 'S') THEN
                    BASECALCIPI = :BASECALCIPI - :VLRRATEIOFRETEITEM;
                IF (:NAOCALCIPISOBVLRADIC = 'S') THEN
                    BASECALCIPI = :BASECALCIPI - :VLRRATEIOSEGDESPACESSITEM;
                IF(:PERCREDIPI > 0) THEN BEGIN
                    IF (:CFOPITEM = '3') THEN
                        BASECALCIPI = :VLRITENSTOTAL - ((:VLRITENSTOTAL * :PERCREDIPI) / 100);        
                    ELSE
                        BASECALCIPI = (:VLRITENSTOTAL + :VLRRATEIOITEM) - (((:VLRITENSTOTAL + :VLRRATEIOITEM) * :PERCREDIPI) / 100);    
                END
                VLRIPI  = CAST(:BASECALCIPI * IPI/100 AS NUMERIC(18,2));
            END ELSE BEGIN
                VLRIPI =  CAST(((:CONVUNMEDIDA  * :QTDE) * :VLRIPITRIB) + CAST(((:VLRRATEIOITEM*VLRIPI)/(CASE WHEN :NAOABATERDESCIPI = 'S' THEN :VLRITENSTOTAL+:DESCVLR ELSE :VLRITENSTOTAL END)) AS NUMERIC(18,2))AS NUMERIC(18,2));
                IF (:NAOABATERDESCIPI = 'N') THEN
                    VLRIPI = VLRIPI - ((VLRIPI *:DESCPORCPROD)/100);
                IF (:NAOCALCIPISOBREFRETE = 'S') THEN
                    VLRIPI = VLRIPI - CAST(((:VLRRATEIOFRETEITEM*VLRIPI)/:VLRITENSTOTAL) AS NUMERIC(18,2));
                IF (:NAOCALCIPISOBVLRADIC = 'S') THEN
                    VLRIPI = VLRIPI - CAST(((:VLRRATEIOSEGDESPACESSITEM*VLRIPI)/:VLRITENSTOTAL) AS NUMERIC(18,2));
            END
            SOMARBCIPI= SOMARBCIPI+ BASECALCIPI;
            IF (:VLRIPIXML > 0) THEN
                VLRIPI = VLRIPIXML;
            SOMAIPI = :SOMAIPI + :VLRIPI;
        END
        IF (:CSTCOFINS IN ('01','02','05','50','51','52','53','54','55','56','60','61','62','63','64','65','66','67','98')) THEN BEGIN
            /* TRIBUTADO POR UNIDADE DE MEDIDA E DEVOLUCAO */
            IF ((VLRPISTRIB+VLRCOFINSTRIB > 0) AND (:CLASSIFICACAOCFOP = 3) AND (CONVUNMEDIDA > 0))  THEN BEGIN
               BASECALCCOFINS= 0;
               VALORPIS= CAST(((:CONVUNMEDIDA *:QTDE) * :VLRPISTRIB) AS NUMERIC(14,2));
               VALORCOFINS= CAST(((:CONVUNMEDIDA *:QTDE)* :VLRCOFINSTRIB) AS NUMERIC(14,2));
            END ELSE BEGIN
                IF ((:VBCPIS <= 0) OR (NOT (((:CFOPITEM = '3') AND (:CHAVESERIENF > 0) AND (:MODELONF = '55')))) AND (not (:TEMCOMPLANULACAO = 'S')) AND (:MODELONF <> '06')) THEN BEGIN
                    if ((:CSTCOFINS = '98') AND (:ALIQPIS=0)) then
                       BASECALCCOFINS = 0;
                    ELSE BEGIN
                       IF (VNAOABATERDESCICMS = 'S') THEN
                          BASECALCCOFINS = (:VLRITENSTOTAL +:VLRRATEIOITEM);
                       ELSE
                          BASECALCCOFINS = ((:VLRITENSTOTAL - ((:VLRITENSTOTAL/100)*:DESCPORCPROD))+:VLRRATEIOITEM);
                    END
                END ELSE BEGIN
                    IF ((:INTEGRARIPIPISCOFINS = 'S') AND (COALESCE(:VLRIPI,0) > 0)) THEN
                        VBCPIS= :VBCPIS - COALESCE(:VLRIPI,0);
                    BASECALCCOFINS = :VBCPIS;
                END
                IF (:CHAVEMACRO=0) THEN BEGIN
                    IF (:INTEGRARIPIPISCOFINS='S') THEN
                        BASECALCCOFINS= :BASECALCCOFINS + COALESCE(:VLRIPI,0);
                    IF (:INTEGRARSTPISCOFINS='S') THEN
                        BASECALCCOFINS= :BASECALCCOFINS + COALESCE(:VLRICMSSUBSTTRIB,0);
                END ELSE BEGIN
                    IF (:INTEGRARIPIPISCOFINSMACRO IN (0,1)) THEN BEGIN
                        IF (:INTEGRARIPIPISCOFINSMACRO=0) THEN BEGIN
                            IF (:INTEGRARIPIPISCOFINS = 'S') THEN
                                BASECALCCOFINS= :BASECALCCOFINS + COALESCE(:VLRIPI,0);
                        END ELSE
                            BASECALCCOFINS= :BASECALCCOFINS + COALESCE(:VLRIPI,0);
                    END
                    IF (:INTEGRARSTPISCOFINSMACRO IN (0,1)) THEN BEGIN
                        IF (:INTEGRARSTPISCOFINSMACRO=0) THEN BEGIN
                            IF (:INTEGRARSTPISCOFINS = 'S') THEN
                                BASECALCCOFINS= :BASECALCCOFINS + COALESCE(:VLRICMSSUBSTTRIB,0);
                        END ELSE
                            BASECALCCOFINS= :BASECALCCOFINS + COALESCE(:VLRICMSSUBSTTRIB,0);
                    END
                END
                VALORPIS= CAST((:BASECALCCOFINS *:ALIQPIS)/100 AS NUMERIC(14,2));
                VALORCOFINS= CAST((:BASECALCCOFINS *:ALIQCOFINS)/100 AS NUMERIC(14,2));
            END
        END ELSE BEGIN
            BASECALCCOFINS= 0;
            VALORPIS= 0;
            VALORCOFINS= 0;
            VLRPISTRIB = 0;
            VLRCOFINSTRIB=0;
        END
        IF (:CFOPITEM = '3') THEN BEGIN
            PARAMNFIMP    = :ALIQICMS/100;
            PORCIMP = (VLRITENSTOTAL*100)/:TOTALPROD;
            VLRIMPIMPORTITEM = (:VLRII * :PORCIMP) / 100;
            VLRIMPIMPORTITEM = CAST(:VLRIMPIMPORTITEM AS NUMERIC(18,2));
            VLRIOFITEM  = (:VLRIOF*:PORCIMP)/100;
            AUX = 0;
            AUX2 = VLRDESPADUA;
            IF (:AUX2 > 50000) THEN BEGIN
                WHILE(:AUX2 > 0) DO BEGIN
                    IF (:AUX2 >50000) THEN BEGIN
                        AUX = 50000;
                    END ELSE BEGIN
                        AUX = :AUX2;
                    END
                    AUX2 = :AUX2 - AUX;
                    VLRDESCPADUAITEM = :VLRDESCPADUAITEM + ((:AUX*:PORCIMP)/100);
                END
            END
            VLRDESCPADUAITEM = CAST(:VLRDESCPADUAITEM AS NUMERIC(18,2));
            VLRRATEIOITEM = :VLRRATEIOITEM + :VLRIPI + :VALORPIS + :VALORCOFINS;
            IF (:VSOMARIMPIMPORTBCICMS = 'S') THEN
                VLRRATEIOITEM = :VLRRATEIOITEM + :VLRIMPIMPORTITEM;
        END ELSE
            PARAMNFIMP = 0;
        IF (((:TIPOPROD IN (7,8)) AND (:CFOPITEM<>'3')) OR (:OPERACAOCONSFINAL='S'))   THEN BEGIN
            BASEICMS = :BASEICMS + :VLRIPI;
            VSOMARIPIBCICMS = 'S';
        END ELSE
            VSOMARIPIBCICMS = 'N';
            
        IF ((:CST2 IN ('00','10')) OR ((:CST2 = '90') AND (:PERCREDICMS=0) AND (:ALIQICMS>0)))   THEN BEGIN
            BASEICMS = (:BASEICMS + :VLRRATEIOITEM) / (1-:PARAMNFIMP);
            VLRICMS  = :BASEICMS * :ALIQICMS / 100;
        END
         VLRUNITCOMDESC  = (:VLRUNIT - (:DESCVLR / :QTDE));
        IF (:DESCVLRPROD <> 0) THEN BEGIN
            AUX = 0;
            VLRDESCGLOBAL = 0;
            IF (COMPORTOTALNF = 0) THEN BEGIN
                AUX = :VLRUNITCOMDESC * 100 / :TOTALPROD;
                AUX = :AUX * :DESCVLRPROD / 100;
                VLRUNITCOMDESC = :VLRUNITCOMDESC - :AUX;
                VLRDESCGLOBAL = CAST(:PORC AS NUMERIC(7,4)) * CAST(:DESCVLRPROD AS NUMERIC(18,2));
                VLRDESCGLOBAL = CAST((:VLRDESCGLOBAL/100) AS NUMERIC(18,2));
                VLRDESCGLOBALACUMULADO = VLRDESCGLOBALACUMULADO + :VLRDESCGLOBAL;
                BASEIVAUNIT = (:VBASEIVA - :VLRDESCGLOBAL) / :QTDE;
                VBASEIVA = CAST(:BASEIVAUNIT * :QTDE AS NUMERIC(18,2));
           END ELSE BEGIN
                BASEIVAUNIT = :VBASEIVA / :QTDE;
                BASEIVAUNIT = :BASEIVAUNIT - CAST(((:BASEIVAUNIT/100)*:DESCPORCPROD) AS NUMERIC(18,4));
                VBASEIVA = CAST(:BASEIVAUNIT * :QTDE AS NUMERIC(18,2));
           END
        END
        IF (:VNAOABATERDESCICMS = 'S') THEN BEGIN
            BASEICMS = BASEICMS  + VLRDESCGLOBAL + :DESCVLR;
            VLRICMS = :BASEICMS * :ALIQICMS / 100;
        END
        IF ((:CST2 IN ('20','51','70')) OR ((:CST2 = '90') AND (:PERCREDICMS>0) AND (:ALIQICMS>0)) OR ((:CST2 = '10') AND (:PERCREDICMS>0) AND (:ALIQICMS>0))) THEN BEGIN
            AUX2 = 0;
            AUX2 = (:BASEICMS+:VLRRATEIOITEM);
            AUX2 = AUX2 * ((100 - :PERCREDICMS) / 100);
            IF (:CST2 = '51') THEN BEGIN
               BASEICMS = CAST(:AUX2 AS NUMERIC(18,2));
               AUX2 = 0;
               AUX2 = :BASEICMS;
               AUX2 = AUX2 * ((100 - :VPERCDIF) / 100);
               VLRICMS = CAST(((:AUX2/100)*:ALIQICMS) AS NUMERIC(18,2));
            END ELSE BEGIN
               BASEICMS = :AUX2/ (1-:PARAMNFIMP);
               VLRICMS = :BASEICMS * :ALIQICMS / 100;
            END
        END
       /*  --RATEIA O DESCONTO FINAL ENTRE OS ITENS
        IF (:DESCVLRPROD <> 0) THEN BEGIN
            AUX = 0;
            AUX = :VLRITENSTOTAL * 100 / (:TOTALPRODUTO + :DESCVLRPROD) / 100;
            AUX = :DESCVLRPROD * AUX / :QTDE;
            DESCVLRPROD = :AUX;
        END    */
        VLRUNITCOMDESC = CASE :CASADECIMALVLRUNITNFENT
        WHEN 2 THEN CAST(:VLRUNITCOMDESC AS NUMERIC(18,2))
        WHEN 3 THEN CAST(:VLRUNITCOMDESC AS NUMERIC(18,3))
        WHEN 4 THEN CAST(:VLRUNITCOMDESC AS NUMERIC(18,4))
        WHEN 5 THEN CAST(:VLRUNITCOMDESC AS NUMERIC(18,5))
        WHEN 6 THEN CAST(:VLRUNITCOMDESC AS NUMERIC(18,6)) END;
        ITEMFRETE =0;
        IF (:VLRFRETE > 0) THEN BEGIN
            AUX = 0;
            AUX2= 0;
            IF (COMPORTOTALNF = 0) THEN BEGIN
                IF (:TEMCUSTOFRETEXML='S') THEN BEGIN
                    ITEMFRETE =:CUSTOFRETE;
                    /* frete por conta, diferente de CIF nao pode somar na base de ICMS */
                    IF ((VFRETEPORCONTA <> 0) AND (:BASEICMS > 0) AND (:CUSTOFRETE>0)) THEN BEGIN
                        BASEICMS = (:BASEICMS - :CUSTOFRETE);
                        VLRICMS  = :BASEICMS * :ALIQICMS / 100;
                    END
                END ELSE BEGIN
                    AUX2= (:VLRITENSTOTAL/:TOTALPROD);
                    AUX = CAST(:VLRFRETE*AUX2 AS NUMERIC(18,2));
                    ITEMFRETE =:AUX;
                END
                VLRFRETEACUMULADO = :VLRFRETEACUMULADO + :ITEMFRETE;
            END
        END
        ITEMSEGURO =0;
        IF (:VLRSEGURO > 0 ) THEN BEGIN
            AUX= 0;
            AUX2= 0;
            IF (COMPORTOTALNF = 0) THEN BEGIN
                IF (:TEMCUSTOSEGUROXML='S') THEN BEGIN
                    ITEMSEGURO =:CUSTOSEGURO;
                END ELSE BEGIN
                    AUX2= (:VLRITENSTOTAL/:TOTALPROD);
                    AUX= CAST(:VLRSEGURO*AUX2 AS NUMERIC(18,2));
                    ITEMSEGURO =:AUX;
                END
                VLRSEGUROACUMULADO = :VLRSEGUROACUMULADO + :ITEMSEGURO;
            END
        END
        ITEMDESPACESSORIA = 0;
        IF (:DESPACESS > 0 ) THEN  BEGIN
            AUX=0;
            AUX2=0;
            IF (COMPORTOTALNF = 0) THEN BEGIN
                IF (:TEMCUSTODESPACESSXML='S') THEN BEGIN
                    ITEMDESPACESSORIA= :CUSTODESPACESS;
                END ELSE BEGIN
                    AUX2 = (:VLRITENSTOTAL/:TOTALPROD);
                    AUX = CAST(:DESPACESS*AUX2 AS NUMERIC(18,2));
                    ITEMDESPACESSORIA = :AUX;
                END
                VLRDESPACESSACUMULADO = :VLRDESPACESSACUMULADO + :ITEMDESPACESSORIA;
            END
        END
        IF ((:VNAOCALCICMSVLRADIC = 'S') AND (BASEICMS>0)) THEN BEGIN
            BASEICMS = BASEICMS  - (:VLRRATEIOSEGDESPACESSITEM);
            VLRICMS = :BASEICMS * :ALIQICMS / 100;
        END
        IF ((:NAOCALCICMSSOBFRETE = 'S') AND (BASEICMS>0)) THEN BEGIN
            BASEICMS = BASEICMS  - (:VLRRATEIOFRETEITEM);
            VLRICMS = :BASEICMS * :ALIQICMS / 100;
        END
        IF (:VALORPIS+:VALORCOFINS > 0) THEN BEGIN
            AUX=0;
            AUX = AUX + (:VALORPIS / :QTDE);
            AUX = AUX + (:VALORCOFINS / :QTDE);
            ITEMPISCOFINS = :AUX;
        END ELSE
            ITEMPISCOFINS = 0;
        IF ((:CST2 IN ('10','30','60','70')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S'))) THEN BEGIN
            AUX  = 0;
            AUX2 = 0;
            IF (:CST2='60') THEN BEGIN
              IF (:MVAORIG>0) THEN BEGIN
                  SELECT BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, MVAAJUSTADO FROM
                  CALCULARMVA(:MVAORIG, :CST, :ALIQICMS,
                  :VLRUNITCOMDESC, :QTDE, 0, 0, :UFEMP, :UFFORNECEDOR, :IPI, :REDUCAOMVA, :REGIMETRIBUT,0,0, 0,0)
                  INTO :AUX, :AUX2, :MVAAJUSTADO;
              END ELSE BEGIN
                AUX  = :BASEICMSSUBSTTRIBDESTAC;
                AUX2 = :VLRICMSSUBSTTRIBDESTAC;
              END
            END ELSE BEGIN
              IF ((SUBSTMANUAL='N') AND (:MVAORIG>0))  THEN BEGIN
                SELECT BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, MVAAJUSTADO FROM
                CALCULARMVA(:MVAORIG,  :CST, :ALIQICMS,
                :VLRUNITCOMDESC + ((:VLRRATEIOITEM)/:QTDE), :QTDE,
                :PERCREDICMS, :PERCREDST, :UFEMP, :UFFORNECEDOR, :IPI, :REDUCAOMVA, :REGIMETRIBUT,0,0, 0,0)
                INTO :AUX, :AUX2, :MVAAJUSTADO;
              END ELSE BEGIN
                AUX  = :BASEICMSSUBSTTRIB;
                AUX2 = :VLRICMSSUBSTTRIB;
              END
            END
            IF (:MVAAJUSTADO > 0) THEN
               MVA= :MVAAJUSTADO;
            IF ((:CST2 IN ('10','30','70')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S'))) THEN BEGIN
                BASEICMSSUBSTTRIB = CAST(:AUX AS NUMERIC(18,2));
                VLRICMSSUBSTTRIB  = CAST(:AUX2 AS NUMERIC(18,2));
                BASEICMSSUBSTTRIBDESTAC = 0;
                VLRICMSSUBSTTRIBDESTAC  = 0;
                IF ((:CST2 = '30') AND (:VICMSDESON=0) AND (:VVLRICMSDESONERADO > 0)) THEN BEGIN
                    VLRICMSSUBSTTRIB = :VLRICMSSUBSTTRIB - :VVLRICMSDESONERADO;
                END
                SOMABASESUBSTTRIB     = :SOMABASESUBSTTRIB + :BASEICMSSUBSTTRIB;
                SOMAVLRSUBSTTRIB      = :SOMAVLRSUBSTTRIB + :VLRICMSSUBSTTRIB;
            END ELSE BEGIN
                SOMABASESUBSTTRIBDEST = :SOMABASESUBSTTRIBDEST - :BASEICMSSUBSTTRIBDESTAC;
                SOMAVLRSUBSTTRIBDEST = :SOMAVLRSUBSTTRIBDEST - :VLRICMSSUBSTTRIBDESTAC;
                BASEICMSSUBSTTRIBDESTAC = :AUX;
                VLRICMSSUBSTTRIBDESTAC  = :AUX2;
                BASEICMSSUBSTTRIB = 0;
                VLRICMSSUBSTTRIB  = 0;
                SOMABASESUBSTTRIBDEST = :SOMABASESUBSTTRIBDEST + :AUX;
                SOMAVLRSUBSTTRIBDEST = :SOMAVLRSUBSTTRIBDEST + :AUX2;
            END
        END
        IF  ((:CST2 IN ('30','40','41','50','60')) OR ((:CST2 IN ('90','51','61')) AND (:ALIQICMS=0))) THEN BEGIN
           BASEICMS = 0;
           VLRICMS  = 0;
        END
        BASEICMS = CAST(:BASEICMS AS NUMERIC(18,2));
        VLRICMS  = CAST(:VLRICMS AS NUMERIC(18,2));
        SOMAVLRICMSNFIMP = SOMAVLRICMSNFIMP + VLRICMS; -- ARMAZENAR A BASE/VALOR DE ICMS PARA DESTACAR/SOMAR NAS NOTAS DE IMPORTACAO
        SOMABASEICMSNFIMP = SOMABASEICMSNFIMP + BASEICMS;
        IF ((:REGIMETRIB IN (0, 3, 4)) AND (:CHAVESERIENF > 0)) THEN BEGIN
            IF (NOT (:CODSIMPLESNAC = '900')) THEN BEGIN
               ALIQICMS    = 0;
               BASEICMS    = 0;
               VLRICMS     = 0;
                IF (CFOPNF='3') THEN
                    DESTACARICMSNFIMP = 'S';
            END
        END
        IF ((:ABATERICMSBASEPISCOFINS = 'S') AND (:BASECALCCOFINS > 0) AND (:VLRICMS>0)) THEN BEGIN
            BASECALCCOFINS = :BASECALCCOFINS - :VLRICMS;
            VALORPIS= CAST((:BASECALCCOFINS *:ALIQPIS)/100 AS NUMERIC(14,2));
            VALORCOFINS= CAST((:BASECALCCOFINS *:ALIQCOFINS)/100 AS NUMERIC(14,2));
            AUX=0;
            AUX = AUX + (:VALORPIS / :QTDE);
            AUX = AUX + (:VALORCOFINS / :QTDE);
            ITEMPISCOFINS = :AUX;
        END
        VLRTOTPIS = :VLRTOTPIS + :VALORPIS;
        VLRTOTCOFINS = :VLRTOTCOFINS + :VALORCOFINS;
        TOTALBCPISCOFINS = :TOTALBCPISCOFINS+:BASECALCCOFINS;
        SOMABASEICMS = :SOMABASEICMS + :BASEICMS;
        SOMAVLRICMS  = :SOMAVLRICMS + :VLRICMS;
        VSOMAVLRICMSFCPST = :VSOMAVLRICMSFCPST + :VVLRICMSFCPST;
        IF (:ICMSDESONDEDUZTOTNF = 1) THEN
            VSOMAVLRICMSDESONERADO = :VSOMAVLRICMSDESONERADO + : VVLRICMSDESONERADO;
        VVLRTOTICMSDESONERADO = : VVLRTOTICMSDESONERADO + : VVLRICMSDESONERADO;
        VVLRICMSDIFAL  = 0;
        VBASECALCDIFAL = 0;
        IF ((:REGIMETRIB = 0) AND (:ALIQICMS = 4) AND (:UFFORNECEDOR <> :UFEMP) AND (SUBSTRING(:CST FROM 1 FOR 1) IN (1,2,6,7)) and (:UFEMP = 'SC')) THEN BEGIN
            SELECT TU.ALIQUOTA FROM TRIBUTACAOPORUF TU
            WHERE TU.ORIGEM=:UFEMP AND TU.DESTINO=:UFEMP
            INTO:VALIQINTERNA;
            IF (:VALIQINTERNA > 0) THEN BEGIN
                if (:VALIQINTERNA > 12) THEN
                    VALIQINTERNA = 12;
                VBASECALCDIFAL = CAST((:VLRITENSTOTAL - :VLRICMS)/(1 - (VALIQINTERNA/100)) AS NUMERIC (18,6));
                VVLRICMSDIFAL = ((:VBASECALCDIFAL * (VALIQINTERNA/100)) - :VLRICMS);
            END
        END
        IF (:VSOMARSTIPIDESPACESS = 'S') THEN BEGIN
            ITEMDESPACESSORIA = COALESCE(:ITEMDESPACESSORIA, 0);
            VLRIPI = COALESCE(:VLRIPI, 0);
            VLRIPITRIB = COALESCE(:VLRIPITRIB, 0);
            VLRICMSSUBSTTRIB = COALESCE(:VLRICMSSUBSTTRIB, 0);
            ITEMDESPACESSORIA = :ITEMDESPACESSORIA + CAST((:VLRIPI + :VLRIPITRIB + :VLRICMSSUBSTTRIB) AS NUMERIC(18,2));
        END
        IF ((VCALCREFTRIB = 'S') OR ((:CHAVESERIENF <= 0) AND (:VCHAVECLASSTRIB > 0))) THEN BEGIN
            IF (:CHAVESERIENF > 0) THEN
                VBASEIVA = CAST(:VBASEIVA + :VLRRATEIOITEM - (:VLRICMS + :VALORPIS + :VALORCOFINS) AS NUMERIC(18,2));
            VBCIVAAUX = :VBASEIVA;
            SELECT SALIQUOTA, SBASEIVA, SVALOR, SVALORDIF, SBCCREDPRES, SVALORCREDPRES FROM CALCTRIBCBSIBS('CBS', :VCHAVECLASSTRIB, :UFEMP, :CHAVEEMPNFENTRADA, :VCHAVECIDADE, :VBASEIVA, :VALIQCBS, :VPERCREDGOV, :VPERCCREDPRES, :VCHAVECREDPRES)
            INTO :VALIQCBS, :VBASEIVA, :VVLRCBS, :VVLRCBSDIF, :VBCCREDPRES, :VVLRCREDPRESCBS;
    
            VVLRCBSNF = VVLRCBSNF + :VVLRCBS;
            VVLRCBSDIFNF =  VVLRCBSDIFNF + :VVLRCBSDIF;
            VVLRCREDPRESCBSNF =  VVLRCREDPRESCBSNF + :VVLRCREDPRESCBS;
            IF ((:VPERCCREDPRES > 0) AND (VVLRCREDPRESCBS > 0) AND (VBASEIVA = 0) AND (:VBCIVAAUX > 0)) THEN
                VBASEIVA = :VBCIVAAUX;
            SELECT SALIQUOTA, SBASEIVA, SVALOR, SVALORDIF, SVALORCREDPRES FROM CALCTRIBCBSIBS('IBSUF', :VCHAVECLASSTRIB, :UFEMP, :CHAVEEMPNFENTRADA, :VCHAVECIDADE, :VBASEIVA, :VALIQIBSUF, :VPERCREDGOV, :VPERCCREDPRES, :VCHAVECREDPRES)
            INTO :VALIQIBSUF, :VBASEIVA, :VVLRIBSUF, :VVLRIBSDIFUF, :VVLRCREDPRESIBS;
    
            VVLRIBSUFNF = VVLRIBSUFNF + :VVLRIBSUF;
            VVLRIBSDIFUFNF =  VVLRIBSDIFUFNF + :VVLRIBSDIFUF;
            VVLRCREDPRESIBSNF =  VVLRCREDPRESIBSNF + :VVLRCREDPRESIBS;
    
            SELECT SALIQUOTA, SVALOR, SVALORDIF FROM CALCTRIBCBSIBS('IBSMUN', :VCHAVECLASSTRIB, :UFEMP, :CHAVEEMPNFENTRADA, :VCHAVECIDADE, :VBASEIVA, :VALIQIBSMUN, :VPERCREDGOV, 0, 0)
            INTO :VALIQIBSMUN, :VVLRIBSMUN, :VVLRIBSDIFMUN;
    
            VVLRIBSMUNNF = VVLRIBSMUNNF + :VVLRIBSMUN;
            VVLRIBSDIFMUNNF =  VVLRIBSDIFMUNNF + :VVLRIBSDIFMUN;
    
            VBASEIVANF = VBASEIVANF + :VBASEIVA;
        END ELSE BEGIN
           :VBASEIVA = 0;
           :VALIQCBS = 0;
           :VVLRCBS = 0;
           :VVLRCBSDIF = 0;
           :VALIQIBSUF = 0;
           :VVLRIBSUF = 0;
           :VVLRIBSDIFUF = 0;
           :VALIQIBSMUN = 0;
           :VVLRIBSMUN = 0;
           :VVLRIBSDIFMUN = 0;
           :VVLRCREDPRESIBS = 0;
           :VVLRCREDPRESCBS = 0;
           :VBCCREDPRES = 0;
        END
        UPDATE ITENSNFENTRADAPROD I SET
        BASEICMS=:BASEICMS, VLRICMS=:VLRICMS,
        BASEIVA = :VBASEIVA,
        ALIQCBS = :VALIQCBS,
        ALIQIBSUF = :VALIQIBSUF,
        ALIQIBSMUN = :VALIQIBSMUN,
        VLRCBS = :VVLRCBS,
        VLRCBSDIF = :VVLRCBSDIF,
        VLRIBSUF = :VVLRIBSUF,
        VLRIBSDIFUF = :VVLRIBSDIFUF,
        VLRIBSMUN = :VVLRIBSMUN,
        VLRIBSDIFMUN = :VVLRIBSDIFMUN,
        BCCREDPRES = :VBCCREDPRES,
        VLRCREDPRESCBS = :VVLRCREDPRESCBS,
        VLRCREDPRESIBS = :VVLRCREDPRESIBS,
        VLRIPI=CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN :VLRIPI ELSE 0 END,
        BASECALCIPI = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN :BASECALCIPI ELSE 0 END,
        IPI = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN :IPI ELSE 0 END,
        I.IPITRIB = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN I.IPITRIB ELSE '' END,
        VLRIPITRIB = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN :VLRIPITRIB ELSE 0 END,
        BASEICMSSUBSTTRIB = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN :BASEICMSSUBSTTRIB ELSE 0 END,
        VLRICMSSUBSTTRIB = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN :VLRICMSSUBSTTRIB ELSE 0 END,
        BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC,
        VLRICMSSUBSTTRIBDESTAC = :VLRICMSSUBSTTRIBDESTAC,
        VLRICMSDIFAL = :VVLRICMSDIFAL,
        MVACALC = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN :MVA ELSE 0 END,
        MVA = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') THEN I.MVA ELSE 0 END,
        VLRDESCGLOBAL= :VLRDESCGLOBAL,
        CSTIPI = CASE WHEN (:VSOMARSTIPIDESPACESS<>'S') OR (I.CSTIPI<>'00') THEN I.CSTIPI ELSE '49' END,
        BCPIS=:BASECALCCOFINS, BCCOFINS= :BASECALCCOFINS,
        VLRPIS=:VALORPIS, VLRCOFINS=:VALORCOFINS,
        CUSTODESPACESSORIAS =:ITEMDESPACESSORIA,
        CUSTOFRETE=:ITEMFRETE, CUSTOSEGURO =:ITEMSEGURO, QTDEESTOQUE =:QTDE,
        CUSTOPISCOFINS      = :ITEMPISCOFINS,
        ALIQUOTAPISCOFINS   = :ALIQPIS + :ALIQCOFINS,
        VLRUNITCOMDESC      = :VLRUNITCOMDESC,
        VLRII = :VLRIMPIMPORTITEM,
        VLRIOF = :VLRIOFITEM,
        VLRDESPADU = :VLRDESCPADUAITEM,
        SOMARIPIBCICMS = :VSOMARIPIBCICMS
        WHERE CHAVE=:CHAVEITENSNF;
    END
    WHILE ((:VLRFRETEACUMULADO > :VLRFRETE) OR (:VLRFRETEACUMULADO < :VLRFRETE)) DO BEGIN
        FOR SELECT I.CHAVE FROM ITENSNFENTRADAPROD I
        INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS
        WHERE I.ATIVO=1 AND I.CHAVENFENTRADA=:CHAVENF AND COALESCE(CF.COMPORTOTALNF,0) = 0
        ORDER BY I.VLRTOTAL-I.CUSTOFRETE DESC
        INTO :CHAVEITENSNF
        DO BEGIN
            IF (:VLRFRETEACUMULADO > :VLRFRETE) THEN BEGIN
                UPDATE ITENSNFENTRADAPROD I SET
                I.CUSTOFRETE = I.CUSTOFRETE - 0.01
                WHERE CHAVE=:CHAVEITENSNF;
                VLRFRETEACUMULADO = :VLRFRETEACUMULADO - 0.01;
                IF (:VLRFRETEACUMULADO <= :VLRFRETE) THEN
                    BREAK;
            END ELSE BEGIN
                UPDATE ITENSNFENTRADAPROD I SET
                I.CUSTOFRETE = I.CUSTOFRETE + 0.01
                WHERE CHAVE=:CHAVEITENSNF;
                VLRFRETEACUMULADO = :VLRFRETEACUMULADO + 0.01;
                IF (:VLRFRETEACUMULADO >= :VLRFRETE) THEN
                    BREAK;
            END
        END
    END
    WHILE ((:VLRSEGUROACUMULADO > :VLRSEGURO) OR (:VLRSEGUROACUMULADO < :VLRSEGURO)) DO BEGIN
        FOR SELECT I.CHAVE FROM ITENSNFENTRADAPROD I
        INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS
        WHERE I.ATIVO=1 AND I.CHAVENFENTRADA=:CHAVENF AND COALESCE(CF.COMPORTOTALNF,0) = 0
        ORDER BY I.VLRTOTAL-I.CUSTOSEGURO DESC
        INTO :CHAVEITENSNF
        DO BEGIN
            IF (:VLRSEGUROACUMULADO > :VLRSEGURO) THEN BEGIN
                UPDATE ITENSNFENTRADAPROD I SET
                I.CUSTOSEGURO = I.CUSTOSEGURO - 0.01
                WHERE CHAVE=:CHAVEITENSNF;
                VLRSEGUROACUMULADO = :VLRSEGUROACUMULADO - 0.01;
                IF (:VLRSEGUROACUMULADO <= :VLRSEGURO) THEN
                    BREAK;
            END ELSE BEGIN
                UPDATE ITENSNFENTRADAPROD I SET
                I.CUSTOSEGURO = I.CUSTOSEGURO + 0.01
                WHERE CHAVE=:CHAVEITENSNF;
                VLRSEGUROACUMULADO = :VLRSEGUROACUMULADO + 0.01;
                IF (:VLRSEGUROACUMULADO >= :VLRSEGURO) THEN
                    BREAK;
            END
        END
    END
    WHILE ((:VLRDESPACESSACUMULADO > :DESPACESS) OR (:VLRDESPACESSACUMULADO < :DESPACESS)) DO BEGIN
        FOR SELECT I.CHAVE FROM ITENSNFENTRADAPROD I
        INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS
        WHERE I.ATIVO=1 AND I.CHAVENFENTRADA=:CHAVENF AND COALESCE(CF.COMPORTOTALNF,0) = 0
        ORDER BY I.VLRTOTAL-I.CUSTODESPACESSORIAS DESC
        INTO :CHAVEITENSNF
        DO BEGIN
            IF (:VLRDESPACESSACUMULADO > :DESPACESS) THEN BEGIN
                UPDATE ITENSNFENTRADAPROD I SET
                I.CUSTODESPACESSORIAS = I.CUSTODESPACESSORIAS - 0.01
                WHERE CHAVE=:CHAVEITENSNF;
                VLRDESPACESSACUMULADO = :VLRDESPACESSACUMULADO - 0.01;
                IF (:VLRDESPACESSACUMULADO <= :DESPACESS) THEN
                    BREAK;
            END ELSE BEGIN
                UPDATE ITENSNFENTRADAPROD I SET
                I.CUSTODESPACESSORIAS = I.CUSTODESPACESSORIAS + 0.01
                WHERE CHAVE=:CHAVEITENSNF;
                VLRDESPACESSACUMULADO = :VLRDESPACESSACUMULADO + 0.01;
                IF (:VLRDESPACESSACUMULADO >= :DESPACESS) THEN
                    BREAK;
            END
        END
    END
    IF (:VMACROALTERARBASEISS IS NULL) THEN
        VMACROALTERARBASEISS = 'N';
    IF (:TOTALSERV > 0) THEN BEGIN
       FOR SELECT I.CHAVE, I.VLRTOTAL, I.ISS, I.BASEISS
       FROM ITENSNFENTRADASERV I
       WHERE I.CHAVENFENTRADA=:CHAVENF AND I.ATIVO=1
       INTO :CHAVEITENSNF, :TOTALITEMSERV, :VALIQISSITEM, :VBASEISSITEM DO BEGIN
          IF (:DESCVLRSERV <> 0) THEN BEGIN
            VLRDESCGLOBAL= (:TOTALITEMSERV*100)/(:TOTALSERV);
            VLRDESCGLOBAL = CAST(:VLRDESCGLOBAL AS NUMERIC(7,2));
            VLRDESCGLOBAL = :VLRDESCGLOBAL * :DESCVLRSERV/100;
            TOTALITEMSERV = :TOTALITEMSERV - :VLRDESCGLOBAL;
          END ELSE
            VLRDESCGLOBAL = 0;
          IF (:VMACROALTERARBASEISS <> 'S') THEN
            VBASEISSITEM = :TOTALITEMSERV;
          IF (:VALIQISSITEM > 0) THEN BEGIN
            AUX = :VBASEISSITEM * :VALIQISSITEM / 100;
            AUX = CAST(:AUX AS NUMERIC(18,2));
          END ELSE
            VBASEISSITEM = 0;
          UPDATE ITENSNFENTRADASERV SET
          VLRDESCGLOBAL=:VLRDESCGLOBAL,
          BASEISS = :VBASEISSITEM,
          VLRISS = :AUX
          WHERE (CHAVE=:CHAVEITENSNF);
          VTOTALBASEISS = :VTOTALBASEISS + :VBASEISSITEM;
          VTOTALISS = :VTOTALISS + :AUX;
       END
    END
    IF (:VSOMARSTIPIDESPACESS = 'S') THEN BEGIN
        IF (:SOMAIPI > 0) THEN
            OBS = SUBSTRING('BASE IPI: ' || FORMAT_VALOR(',#0.00', :SOMARBCIPI, '') || ' VALOR IPI: ' || FORMAT_VALOR(',#0.00', :SOMAIPI, '') || ASCII_CHAR(13) || ASCII_CHAR(10) || :OBS FROM 1 FOR 5000);
        IF (:SOMAVLRSUBSTTRIB > 0) THEN
            OBS = SUBSTRING('BASE ICMS ST: ' || FORMAT_VALOR(',#0.00', :SOMABASESUBSTTRIB, '') || ' VALOR ICMS ST: ' || FORMAT_VALOR(',#0.00', :SOMAVLRSUBSTTRIB, '') || ASCII_CHAR(13) || ASCII_CHAR(10) || :OBS FROM 1 FOR 5000);
        DESPACESS = :SOMAVLRSUBSTTRIB + :SOMAIPI;
        SOMARBCIPI = 0;
        SOMAIPI = 0;
        SOMABASESUBSTTRIB = 0;
        SOMAVLRSUBSTTRIB = 0;
    END ELSE
        DESPACESS = 0;
    IF (CFOPNF='3') THEN BEGIN
        VLRTOTALNF = :TOTALPROD + :TOTALSERV + :VLRPAGOTERCEIROS +
                     :VLRRATEIO + :DESPACESS + :SOMAIPI + :SOMARVLRIPIDEVOLV + :VLRTOTPIS + :VLRTOTCOFINS -
                     :DESCVLRPROD - :DESCVLRSERV + :SOMAVLRSUBSTTRIB +
                     :VSOMAVLRICMSFCPST - :VSOMAVLRICMSDESONERADO;
        IF (:VSOMARIMPIMPORTBCICMS = 'S') THEN
            VLRTOTALNF = :VLRTOTALNF + COALESCE(:VLRII, 0);
        IF (:VNAOSOMARICMSTOTALNF = 'N') THEN
            VLRTOTALNF = :VLRTOTALNF + :SOMAVLRICMSNFIMP;
    END ELSE BEGIN
        VLRTOTALNF = :TOTALPROD + :TOTALSERV + :VLRPAGOTERCEIROS +
                     :VLRRATEIO + + :DESPACESS + :SOMAIPI + :SOMARVLRIPIDEVOLV - :DESCVLRPROD -
                     :DESCVLRSERV + :VSOMAVLRICMSFCPST - :VSOMAVLRICMSDESONERADO;
        IF (:VNAOSOMARICMSTOTALNF = 'N') THEN
            VLRTOTALNF = :VLRTOTALNF + :SOMAVLRSUBSTTRIB;
    END
    FOR SELECT I.BASEPISCOFINS,
    I.VLRPIS, I.VLRCOFINS FROM ITENSNFENTRADASERV I
    INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
    WHERE I.ATIVO=1 AND I.CHAVENFENTRADA=:CHAVENF
    INTO BASEPISCOFINSSERV, :VLRPISSERV, :VLRCOFINSSERV
    DO BEGIN
        SOMARPISSERV = :SOMARPISSERV + :VLRPISSERV;
        SOMARCOFINSSERV = :SOMARCOFINSSERV + :VLRCOFINSSERV;
        SOMARBCPISCOFINSSERV = :SOMARBCPISCOFINSSERV + :BASEPISCOFINSSERV;
    END
    TOTALSERV = :TOTALSERV - :DESCVLRSERV;
     IF ((:REGIMETRIB IN (0,4)) AND (SOMABASEICMSNFIMP > 0) AND (DESTACARICMSNFIMP = 'S')) THEN BEGIN
        OBSNFIMP = TRIM(' BASE ICMS: ' || FORMAT_VALOR(',#0.00', :SOMABASEICMSNFIMP, '') || ' VALOR ICMS:' || FORMAT_VALOR(',#0.00', :SOMAVLRICMSNFIMP, '')||' ');
        OBS = REPLACE(:OBS, ASCII_CHAR(13) || ASCII_CHAR(10) ||:OBSNFIMP , '');
        OBS = SUBSTRING(:OBS||ASCII_CHAR(13) || ASCII_CHAR(10) ||:OBSNFIMP FROM 1 FOR 5000);
     END
    WHILE (:VLRDESCGLOBALACUMULADO > :DESCVLRPROD) DO BEGIN
        FOR SELECT I.CHAVE, I.BASEICMS FROM ITENSNFENTRADAPROD I
       INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS
       WHERE I.ATIVO=1 AND I.CHAVENFENTRADA=:CHAVENF AND COALESCE(CF.COMPORTOTALNF,0) = 0
        ORDER BY I.VLRTOTAL-I.VLRDESCGLOBAL DESC
        INTO :CHAVEITENSNF, :BASEICMS
       DO BEGIN
             UPDATE ITENSNFENTRADAPROD I SET
                 I.VLRDESCGLOBAL = I.VLRDESCGLOBAL - 0.01,
                 I.VLRUNITCOMDESC = (I.VLRUNITCOMDESC + (0.01 / I.QTDEESTOQUE)),
                 I.VLRICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN CAST((I.BASEICMS + 0.01) * (I.ICMS/100) AS NUMERIC(18,2)) ELSE I.VLRICMS END,
                 I.BASEICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN I.BASEICMS + 0.01 ELSE I.BASEICMS END
             WHERE CHAVE=:CHAVEITENSNF;
            VLRDESCGLOBALACUMULADO = :VLRDESCGLOBALACUMULADO - 0.01;
            IF ((:CST2 IN ('00','10')) AND (:BASEICMS > 0)) THEN
                SOMABASEICMS = :SOMABASEICMS + 0.01;
            IF (:VLRDESCGLOBALACUMULADO <= :DESCVLRPROD) THEN BEGIN
             BREAK;
          END
       END
    END
    WHILE (:VLRDESCGLOBALACUMULADO < :DESCVLRPROD) DO BEGIN
        FOR SELECT I.CHAVE, I.BASEICMS FROM ITENSNFENTRADAPROD I
           INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS
           WHERE I.ATIVO=1 AND I.CHAVENFENTRADA=:CHAVENF AND COALESCE(CF.COMPORTOTALNF,0) = 0
        ORDER BY I.VLRTOTAL-I.VLRDESCGLOBAL DESC
        INTO :CHAVEITENSNF, :BASEICMS
           DO BEGIN
            UPDATE ITENSNFENTRADAPROD I SET
                I.VLRDESCGLOBAL = I.VLRDESCGLOBAL + 0.01,
                I.VLRUNITCOMDESC = (I.VLRUNITCOMDESC - (0.01 / I.QTDEESTOQUE)),
                I.VLRICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN CAST((I.BASEICMS - 0.01) * (I.ICMS/100) AS NUMERIC(18,2)) ELSE I.VLRICMS END,
                I.BASEICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN I.BASEICMS - 0.01 ELSE I.BASEICMS END
            WHERE CHAVE=:CHAVEITENSNF;
            VLRDESCGLOBALACUMULADO = :VLRDESCGLOBALACUMULADO + 0.01;
            IF ((:CST2 IN ('00','10')) AND (:BASEICMS > 0)) THEN
                SOMABASEICMS = :SOMABASEICMS - 0.01;
            IF (:VLRDESCGLOBALACUMULADO >= :DESCVLRPROD) THEN BEGIN
                 BREAK;
            END
        END
    END
    UPDATE NFENTRADA SET
        TOTALNF = :VLRTOTALNF,
        TOTALPRODUTO = :TOTALPROD - :DESCVLRPROD,
        TOTALSERVICO = :TOTALSERV,
        TOTALIPI = :SOMAIPI,
        BCIPI = :SOMARBCIPI,
        BASECALCULOICMS = :SOMABASEICMS+:BASEICMSSERV,
        VLRICMS = :SOMAVLRICMS+:VLRICMSSERV,
        BASECALCICMSSUBST = :SOMABASESUBSTTRIB,
        BASEIVA = :VBASEIVANF,
        VLRCBS = :VVLRCBSNF,
        VLRCBSDIF = :VVLRCBSDIFNF,
        VLRIBSUF = :VVLRIBSUFNF,
        VLRIBSDIFUF = :VVLRIBSDIFUFNF,
        VLRIBSMUN = :VVLRIBSMUNNF,
        VLRIBSDIFMUN = :VVLRIBSDIFMUNNF,
        VLRCREDPRESCBS = :VVLRCREDPRESCBSNF,
        VLRCREDPRESIBS = :VVLRCREDPRESIBSNF,
        BASEISS = :VTOTALBASEISS,
        TOTALISS = :VTOTALISS,
        VLRICMSSUBST = :SOMAVLRSUBSTTRIB,
        BASECALCICMSSUBSTDESTAC = :SOMABASESUBSTTRIBDEST,
        VLRCALCICMSSUBSTDESTAC = :SOMAVLRSUBSTTRIBDEST,
        DESCONTOVLR= :DESCVLRPROD,
        DESCVLRSERVICO= :DESCVLRSERV,
        VLRPIS= :VLRTOTPIS, VLRCOFINS =:VLRTOTCOFINS,
        BCPISCOFINS = :TOTALBCPISCOFINS,
        VLRPISSERV = :SOMARPISSERV,
        VLRCOFINSSERV = :SOMARCOFINSSERV,
        BCPISCOFINSSERV = :SOMARBCPISCOFINSSERV,
        OBS =  :OBS,
        VLRICMSFCPST = :VSOMAVLRICMSFCPST,
        VLRICMSDESONERADO = :VVLRTOTICMSDESONERADO,
        DESPACESSORIA = COALESCE(DESPACESSORIA,0) + :DESPACESS
    WHERE (ATIVO=1) AND (CHAVE=:CHAVENF);
    /*
    CHAMADAS :
    FRMNFENTRADA - USADA PARA REFAZER VALORES DA NF ENTRADA
    */
END^


ALTER PROCEDURE RATEIONFSAIDA (
    CHAVENFSAIDA INTEGER,
    NLATUAL DOUBLE PRECISION,
    EMPRESALOG INTEGER,
