declare variable VLRSEGDESPACESSITEM numeric(18,6);
BEGIN
    PORC=0;
    SOMAVLRICMS=0;SOMABASEICMS=0;BASEICMSSIMPLESNACIONAL=0;VLRICMSSIMPLESNACIONAL=0;
    SOMABASESUBSTTRIB=0;SOMABASESUBSTTRIBDEST=0;SOMAVLRSUBSTTRIB=0;
    SOMAVLRSUBSTTRIBDEST=0;VLRICMSSIMPLESNACITEN=0; AUXSIMPLESNAC=0;
    VALORTOTCOFINS=0; VALORTOTPIS=0; VALORCOFINS=0; VALORPIS=0;
    BASECALCCOFINS=0; REDUCAOMVA=0; SOMARBCIPI = 0; VLRACRESGLOBALACUM = 0;
    SOMARPISSERV=0; SOMARCOFINSSERV=0; BASETOTALPISCOFINS=0;
    SOMARBCPISCOFINSSERV=0; VLRDESCGLOBALACUMULADO = 0;
    TOTBASEICMSDEVOL = 0; TOTVLRICMSDEVOL=0; VLRPISTRIB=0; VLRCOFINSTRIB=0;
    VLRPISTRIBSERV=0;VLRCOFINSTRIBSERV=0; SOMARVLRAPROXIMPPROD=0;SOMARVLRAPROXIMPSERV=0;
    VLRAPROXTRIBFEDPROD=0; VLRAPROXTRIBESTPROD=0;
    VLRAPROXTRIBMUNICPROD=0; VLRAPROXTRIBFEDSERV=0; VLRAPROXTRIBESTSERV=0; VLRAPROXTRIBMUNICSERV=0;
    NROITENS=0;TOTVLRICMSPARTDEST = 0; TOTVLRICMSPARTREMET=0; TOTVLRICMSFCP=0; TOTALICMSFCPST=0; TOTALICMSFCPSTDEST=0;
    VLRACUMULADOFRETE = 0; VVLRACUMSEGURO = 0; VVLRACUMDESPACES = 0;
    VVLRCBS = 0; VVLRCBSDIF = 0; VVLRIBSUF = 0; VVLRIBSDIFUF = 0; VVLRIBSMUN = 0; VVLRIBSDIFMUN = 0;
    VVLRCBSPED = 0; VVLRCBSDIFPED = 0; VVLRIBSUFPED = 0; VVLRIBSDIFUFPED = 0; VVLRIBSMUNPED = 0; VVLRIBSDIFMUNPED = 0;
    VBASEIVAPED = 0; VVLRCREDPRESCBSPED = 0; VVLRCREDPRESIBSPED = 0;
    TOTBASEICMSSTEFET=0; TOTVLRICMSSTEFET=0;
    SOMARSTIPIDESPACESS = 'N'; VMACRONAOGERARDIFAL = 'N';
    VSOMAVLRICMSDESON=0;
    VTOTALICMSDESON  =0;
    VDATAEMISSAO = NULL;
    PERCICMSPART = 0;
    SOMARVLRIPIDEVOLV = 0;
    SELECT CID.UF, CASE WHEN E.REGIMETRIBUT = 3 THEN 0 ELSE E.REGIMETRIBUT END, NAOGERARDIFAL,
    COALESCE(ALIQISSSIMPLESNACIONAL,0), COALESCE(ALIQICMSSIMPLESNACIONAL,0), CASE WHEN COALESCE(CALCREFTRIB,0) = 0 THEN 'S' ELSE 'N' END
    FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    WHERE E.CHAVE= :EMPRESALOG
    INTO :UFEMP, :REGIMETRIB, :NAOGERARDIFAL,
    :ALIQISSSIMPLESNACIONAL, :ALIQICMSSIMPLESNACIONAL, :VCALCREFTRIB;
    ALIQICMSSIMPLESNACIONAL= CAST(:ALIQICMSSIMPLESNACIONAL AS NUMERIC(7,2));
    SELECT CID.UF, C.REDUCAOMVA, C.CHAVECIDADE
    FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN PEDIDOSAIDA PS ON C.CHAVE=PS.CHAVECLIFOR
    WHERE PS.CHAVE=:CHAVEPEDIDO
    INTO :UFCLI, :REDUCAOMVA, :VCHAVECIDADE;
    SELECT COALESCE((SELECT CAST(VALOR AS INTEGER) FROM CONFIGCAMPOS WHERE (CHAVEEMPRESA=:EMPRESALOG) AND (CAMPO='SEGMENTO')),0), COALESCE((SELECT CAST(VALOR AS INTEGER) FROM CONFIGCAMPOS WHERE (CHAVEEMPRESA=:EMPRESALOG) AND (CAMPO='TIPOEMISSAONFSE')),0)
    FROM CONFIG C
    WHERE CHAVE=:EMPRESALOG
    INTO :VSEGMENTO, :TIPOEMISSAONFSE;
    SELECT COALESCE(COALESCE(SUM(I.VLRTOTAL),0) - SUM(COALESCE(I.VLRACRESCGLOBAL, 0)),0), COUNT(I.CHAVE)
    FROM ITENSPEDSAIDA I
    INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS AND CF.COMPORTOTALNF = 0
    WHERE I.CHAVEPEDIDO=:CHAVEPEDIDO AND I.ATIVO=1
    INTO :TOTALPRODUTO, :NROITENS;
    SELECT COALESCE(SUM(VLRTOTAL),0) FROM ITENSPEDSAIDASERV
    WHERE CHAVEPEDIDO=:CHAVEPEDIDO AND ATIVO=1
    INTO :TOTALSERVICO;
    SELECT COALESCE(FRETE,0), COALESCE(DESCVLRPROD,0), COALESCE(DESPACESSORIA,0),
    COALESCE(DESCVLRSERVICO,0), COALESCE(DESCPORCPROD,0), COALESCE(VLRSEGURO,0),
    COALESCE(TOTALIPI,0), PS.OBS, COALESCE(M.OPERACAOISS,0),
    COALESCE(M.ORIGEMALIQISS,0), C.PESSOA, C.IERG,
    COALESCE(PS.ACRESCVLRPROD,0), COALESCE(PS.ACRESCPORCPROD,0), COALESCE(M.SOMARSTIPIDESPACESSNFSAIDA, 'N'),
    COALESCE(M.ALTERARBASEISS, 'N'), COALESCE(M.PORCISS, 0), C.REGIMETRIBUTARIO,
    COALESCE(M.NAOABATERDESCICMS, 'N'), COALESCE(M.NAOATUALIZACADPRODUTO, 'N'), COALESCE(M.ABATERICMSBASEPISCOFINS, 'N'),
    COALESCE(M.NAOGERARDIFAL, 'N'), COALESCE(M.NAOCALCICMSVLRADIC, 'N'),  COALESCE(M.NAOCALCIPISOBVLRADIC, 'N')
    FROM PEDIDOSAIDA PS
    LEFT JOIN CFOP CF ON PS.CHAVECFOPPROD = CF.CHAVE
    LEFT JOIN MACROES M ON M.CHAVE = PS.CHAVEMACROES
    INNER JOIN CLIFOR C ON C.CHAVE=PS.CHAVECLIFOR
    WHERE PS.CHAVE=:CHAVEPEDIDO
    INTO :VLRFRETE, :DESCONTO, :DESPACESS,
    :DESCONTOSERVICO, :DESCPORCPROD, :VLRSEGURO,
    :SOMAIPI, :OBS, :OPERACAOISS, :ORIGEMALIQISS,
    :PESSOA , :INSCRICAOEST,
    :ACRESCVLRPROD, :ACRESCPORCPROD, :SOMARSTIPIDESPACESS,
    :ALTERARBASEISS, :VPORCISS, :REGIMETRIBCLIFOR,
    :VNAOABATERDESCICMS, :VALTERARSTDESTMANUAL, :ABATERICMSBASEPISCOFINS, :VMACRONAOGERARDIFAL, :NAOCALCICMSVLRADIC, :NAOCALCIPISOBVLRADIC;
    VLRRATEIO = :DESPACESS + :VLRFRETE + :VLRSEGURO;
    ITEMATUAL = 0;
    IF ((:ACRESCVLRPROD > 0) AND (:DESCONTO > 0)) THEN BEGIN
        AUX = :DESCONTO * 100;
        AUX = :AUX / (:TOTALPRODUTO + :ACRESCVLRPROD);
        AUX = CAST(AUX AS NUMERIC(18,4));
        DESCPORCPROD = :AUX;
    END
    FOR SELECT DISTINCT I.CHAVE, I.VLRUNIT, I.VLRTOTAL, I.ICMS, I.BASEICMS, I.DESCVLR,
    I.CST, SUBSTRING(I.CST FROM 2 FOR 2), T.PERCRED, T.PERCREDST, I.IPI, I.VLRIPI, I.QTDE,
    COALESCE(I.MVA,0), COALESCE(BASEICMSSUBSTTRIB,0), COALESCE(VLRICMSSUBSTTRIB,0),
    COALESCE(BASEICMSSUBSTTRIBDESTAC,0), COALESCE(VLRICMSSUBSTTRIBDESTAC,0),
    COALESCE(BASECALCIPI,0), CASE WHEN ((:UFEMP <> :UFCLI) AND ((C.PESSOA=1) OR ((C.PESSOA=0) AND (C.IERG IN ('ISENTO','')))))
    THEN  (SELECT TUF.ALIQUOTA FROM TRIBUTACAOPORUF TUF
    WHERE TUF.ORIGEM=:UFEMP AND TUF.DESTINO=:UFCLI) ELSE CASE WHEN (:UFEMP = :UFCLI) OR (C.PESSOA=1)
    OR ((C.PESSOA=0) AND (C.IERG IN ('ISENTO',''))) THEN T.ALIQUOTADE
    ELSE (SELECT TUF.ALIQUOTA FROM TRIBUTACAOPORUF TUF
    WHERE TUF.ORIGEM=:UFEMP AND TUF.DESTINO=:UFCLI) END END,
    UN.CONVERSAO, I.CSTCOFINS, COALESCE(I.VLRACRESCGLOBAL,0),
    I.ALIQPIS, I.ALIQCOFINS, I.CSOSN, CASE WHEN COALESCE(PC.BCSTMEDIADEST,0) > 0 THEN COALESCE(PC.BCSTMEDIADEST,0) ELSE COALESCE(I.PRECOCUSTO,0) END,
    COALESCE(M.NAOABATERDESCIPI,'N'), COALESCE(M.NAOCALCIPISOBREFRETE,'N'), COALESCE(M.NAOCALCICMSSOBFRETE,'N'),
    COALESCE(TC.CODIGO,'99'), COALESCE(CF.CLASSIFICACAO,0), COALESCE(I.VLRIPITRIB,0), COALESCE(UN.CONVUNMEDIDA,0),
    I.COMPORTOTALNF, COALESCE(IBPT.ALIQNAC,0), COALESCE(IBPT.ALIQIMP,0), COALESCE(IBPT.ALIQEST,0), COALESCE(IBPT.ALIQMUNIC,0),
    COALESCE(M.USARDIVISORICMS, 'N'), COALESCE(M.USARDIVISORIPI, 'N'), T.CSTSUBSTTRIB, I.VLRPAUTA, I.CHAVEUNIDADE, I.ALIQICMSINTRA,
    COALESCE(COF.OPERCONSUMIDORFINAL,'N'), COALESCE(P.CODANP,''), T.TIPOCALCST, SUBSTRING(CF.CODIGO FROM 1 FOR 1), COALESCE(T.MOSTRARBASESTRED,'N'),
    I.BCPIS, PC.PRECOCUSTO, PC.ALIQICMSPROPRIOCOMPRA, P.TIPO, COALESCE(M.SOMARIPIBASEICMS, 'N'),
    COALESCE(T.ICMSDESON,1), COALESCE(PC.VMEDIAICMSSUBST,0), C.IEPRODUTORRURAL,
    COALESCE(PC.BCSTMEDIADEST,0), COALESCE(PC.VMEDIAICMSSTDEST,0), COALESCE(T.PERCDIF,0), COALESCE(T.ICMSDESONDEDUZTOTNF,0),
    COALESCE(I.VLRIPIDEVOLV, 0), I.BASEIVA, I.CHAVECLASSTRIB, COALESCE(I.ALIQCBS, 0), COALESCE(I.ALIQIBSUF, 0), COALESCE(I.ALIQIBSMUN, 0),
    COALESCE(COF.PERCREDOPGOV,0), COALESCE(I.PERCCREDPRES,0), COALESCE(I.CHAVECREDPRES,0)
    FROM ITENSPEDSAIDA I
    INNER JOIN PEDIDOSAIDA PS ON PS.CHAVE=I.CHAVEPEDIDO
    INNER JOIN TRIBUTACAO T ON T.CHAVE = I.CHAVETRIBUTACAO
    INNER JOIN PRODUTO P ON I.CHAVEPRODUTO = P.CHAVE
    INNER JOIN PRODUTOCUSTO PC ON (P.CHAVE=PC.CHAVEPRODUTO) AND (PC.CHAVEEMPRESA=:ECHAVEEMPCUSTO)
    INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
    INNER JOIN CLIFOR C ON C.CHAVE=PS.CHAVECLIFOR
    INNER JOIN CFOPOPERFISCAIS COF ON COF.CHAVE = I.CHAVECFOPOPERFISCAIS
    LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = I.CHAVETABPISCOFINS
    LEFT JOIN CFOP CF ON I.CHAVECFOP = CF.CHAVE
    LEFT JOIN MACROES M ON M.CHAVE = PS.CHAVEMACROES
    LEFT JOIN CLASSFISCAL NCM ON NCM.CHAVE = I.CHAVECLASSFISCAL
    LEFT JOIN TABELAALIQIMPIBPT IBPT ON IBPT.CHAVECLASSFISCAL = NCM.CHAVE AND IBPT.UF = :UFEMP AND IBPT.ATIVO=1
    WHERE I.CHAVEPEDIDO=:CHAVEPEDIDO AND I.ATIVO=1
    INTO :CHAVEITENSPS, :VVLRUNIT, :ITENSTOTAL, :ALIQICMS, :BASEICMS, :VDESCVLRITEM,
    :CST, :CST2, :PERCREDICMS, :PERCREDST, :IPI, :VLRIPI, :QTDE,
    :MVA, :BASEICMSSUBSTTRIB, :VLRICMSSUBSTTRIB,
    :BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC,
    :BASECALCIPI, :ALIQTRIB, :CONVERSAO, :CSTCOFINS, :VLRACRESCGLOBAL,
    :ALIQPIS , :ALIQCOFINS, :CODSIMPLESNAC, :BASESTCST60,
    :NAOABATERDESCIPI, :NAOCALCIPISOBREFRETE, :NAOCALCICMSSOBFRETE,
    :CODTABPISCOFINS, :CLASSIFICACAOCFOP, :VLRIPITRIB, :CONVUNMEDIDA,
    :COMPORTOTALNF, :ALIQNACIMPOSTO, :ALIQIMPIMPOSTO, :ALIQESTIMPOSTOPROD, :ALIQMUNICIMPOSTOPROD,
    :USARDIVISORICMS, :USARDIVISORIPI, :CSTSUBSTTRIB, :VLRPAUTA, :CHAVEUNIDADE, :ALIQINTERNADEST,
    :OPERCONSFINAL, :CODANP, :TIPOCALCST, :CFOP, :MOSTRARBASESTRED,
    :VBCPIS, :VPRECOCUSTOREAL, :VALIQICMSPROPRIOCOMPRA, :TIPOPROD, :SOMARIPIBASEICMS,
    :VICMSDESON, :VVMEDIAICMSSUBST, :VIEPRODUTORRURAL,
    :VBCSTMEDIADEST, :VMEDIAICMSSTDEST, :VPERCDIF, :VICMSDESONDEDUZTOTNF, :VVALORIPIDEVOLV,
    :VBASEIVA, :VCHAVECLASSTRIB, :VALIQCBS, :VALIQIBSUF, :VALIQIBSMUN, :VPERCREDGOV, :VPERCCREDPRES, :VCHAVECREDPRES
    DO BEGIN
        ITEMATUAL = :ITEMATUAL + 1;
        VLRDESCGLOBAL = 0;
        VLRAPROXTRIBFEDPROD=0;
        VLRAPROXTRIBESTPROD=0;
        VLRAPROXTRIBMUNICPROD=0;
        VLRICMSPARTDEST = 0;
        VLRICMSPARTREMET = 0;
        VLRICMSFCPDE = 0;
        VLRICMSFCPST = 0;
        VLRICMSFCPSTDEST = 0;
        CONSUMIDORFINAL = 'N';
        VPARTICMSDIFAL = 'N';
        BASEICMSSTEFET = 0;
        VLRICMSSTEFET = 0;
        VVLRICMSDESON = 0;
        VBASEICMSSEMRED  = 0;
        VVALORUNITCALCST = 0;
        IF ((:VSEGMENTO <> 1) OR  (:VBCPIS = :ITENSTOTAL)) THEN
            VBCPIS = 0;
        IF (((PESSOA=1) AND (VIEPRODUTORRURAL = '')) OR ((PESSOA =0) AND (INSCRICAOEST = 'ISENTO')) OR (:OPERCONSFINAL='S')) THEN
            CONSUMIDORFINAL = 'S';
        QTDEEST = :QTDE*:CONVERSAO;
        IF (:ACRESCVLRPROD <> 0) THEN BEGIN
            IF (:ITEMATUAL < :NROITENS) THEN BEGIN
                AUX = :ITENSTOTAL - :VLRACRESCGLOBAL;
                AUX = ((:AUX/100) * :ACRESCPORCPROD);
                AUX = CAST(:AUX AS NUMERIC(18,2));
                AUX = CAST(AUX / :QTDE AS NUMERIC(18,2));
                AUX = AUX * :QTDE;
                AUX = CAST(:AUX AS NUMERIC(18,2));
            END ELSE
                AUX = :ACRESCVLRPROD - :VLRACRESGLOBALACUM;
            VLRACRESGLOBALACUM = :VLRACRESGLOBALACUM + :AUX;
            VLRACRESCGLOBAL = :AUX - :VLRACRESCGLOBAL;
            ITENSTOTAL = :ITENSTOTAL + :VLRACRESCGLOBAL; --ACRESCIMO AUMENTA O TOTAL DO ITEM
        END ELSE
            VLRACRESCGLOBAL = :VLRACRESCGLOBAL * (-1); --ABATER VALOR SE JA FOI RATEADO NOS ITENS
        VLRUNITCOMDESC = :ITENSTOTAL / :QTDEEST;
        IF ((:VDESCVLRITEM = 0) AND (ABS((:VLRUNITCOMDESC * :QTDEEST) - :ITENSTOTAL) < 0.01)) THEN
            VLRUNITCOMDESC = :VVLRUNIT;
        BASEICMS = :ITENSTOTAL;
        VBASEIVA =  :ITENSTOTAL;
        IF (:VNAOABATERDESCICMS = 'S') THEN
            BASEICMS = :BASEICMS + :VDESCVLRITEM;
        IF ((SUBSTRING(:CST FROM 1 FOR 1) IN (1,2,6,7)) AND (:USARDIVISORICMS = 'S')) THEN
            BASEICMS = :BASEICMS/((100-(:ALIQICMS))/100);
        MVAORIG = MVA;
        IF (:DESCPORCPROD > 0) THEN BEGIN
            VLRDESCGLOBAL = 0;
            IF (COMPORTOTALNF = 0) THEN BEGIN
                VLRDESCGLOBAL = CAST(((:ITENSTOTAL/100)*:DESCPORCPROD) AS NUMERIC(18,2));
                VLRDESCGLOBALACUMULADO = VLRDESCGLOBALACUMULADO + :VLRDESCGLOBAL;
                IF (:VNAOABATERDESCICMS <> 'S') THEN BEGIN
                    BASEICMSUNIT = (:BASEICMS - :VLRDESCGLOBAL) / :QTDEEST;
                    BASEICMS = CAST(:BASEICMSUNIT * :QTDEEST AS NUMERIC(18,2));
                END
                BASEIVAUNIT = (:VBASEIVA - :VLRDESCGLOBAL) / :QTDEEST;
                VBASEIVA = CAST(:BASEIVAUNIT * :QTDEEST AS NUMERIC(18,2));
            END ELSE BEGIN
                IF (:VNAOABATERDESCICMS <> 'S') THEN BEGIN
                    BASEICMSUNIT = :BASEICMS / :QTDEEST;
                    BASEICMSUNIT = :BASEICMSUNIT - CAST(((:BASEICMSUNIT/100)*:DESCPORCPROD) AS NUMERIC(18,4));
                    BASEICMS = CAST(:BASEICMSUNIT * :QTDEEST AS NUMERIC(18,2));
                END
                BASEIVAUNIT = :VBASEIVA / :QTDEEST;
                BASEIVAUNIT = :BASEIVAUNIT - CAST(((:BASEIVAUNIT/100)*:DESCPORCPROD) AS NUMERIC(18,4));
                VBASEIVA = CAST(:BASEIVAUNIT * :QTDEEST AS NUMERIC(18,2));
            END
        END
        PORC = ((:BASEICMS+COALESCE(VLRDESCGLOBAL,0))*100)/:TOTALPRODUTO;
        PORC = CAST(:PORC AS NUMERIC(7,4));
        VLRFRETEITEM = 0;
        IF (:VLRFRETE > 0) THEN BEGIN
            IF (COMPORTOTALNF = 0) THEN BEGIN
                IF (:ITEMATUAL = :NROITENS) THEN
                    VLRFRETEITEM = :VLRFRETE - :VLRACUMULADOFRETE;
                ELSE BEGIN
                    VLRFRETEITEM = CAST(((:VLRFRETE/100)*:PORC) AS NUMERIC(18,2));
                    IF (:VLRACUMULADOFRETE + :VLRFRETEITEM > :VLRFRETE) THEN
                        VLRFRETEITEM = :VLRFRETE - :VLRACUMULADOFRETE;    
                END
                VLRACUMULADOFRETE = :VLRACUMULADOFRETE + VLRFRETEITEM;
            END
        END
        VLRSEGUROITEM = 0;
        IF (:VLRSEGURO > 0) THEN BEGIN
            IF (COMPORTOTALNF = 0) THEN BEGIN
                IF (:ITEMATUAL = :NROITENS) THEN
                    VLRSEGUROITEM = :VLRSEGURO - :VVLRACUMSEGURO;
                ELSE BEGIN
                    VLRSEGUROITEM = CAST(((:VLRSEGURO/100)*:PORC) AS NUMERIC(18,2));
                    IF (:VVLRACUMSEGURO + :VLRSEGUROITEM > :VLRSEGURO) THEN
                        VLRSEGUROITEM = :VLRSEGURO - :VVLRACUMSEGURO;    
                END
                VVLRACUMSEGURO=:VVLRACUMSEGURO + VLRSEGUROITEM;
            END
        END
        VLRACESSITEM = 0;
        IF (:DESPACESS > 0) THEN BEGIN
            IF (COMPORTOTALNF = 0) THEN BEGIN
                IF (:ITEMATUAL = :NROITENS) THEN
                    VLRACESSITEM = :DESPACESS - :VVLRACUMDESPACES;
                ELSE BEGIN
                    VLRACESSITEM = CAST(((:DESPACESS/100)*:PORC) AS NUMERIC(18,2));
                    IF (:VVLRACUMDESPACES + :VLRACESSITEM > :DESPACESS) THEN
                        VLRACESSITEM = :DESPACESS - :VVLRACUMDESPACES;
                END
                VVLRACUMDESPACES=:VVLRACUMDESPACES + VLRACESSITEM;
            END
        END
        VLRRATEIOITEM = VLRFRETEITEM + VLRSEGUROITEM + VLRACESSITEM;
        VLRSEGDESPACESSITEM = VLRSEGUROITEM + VLRACESSITEM;
        IF ((:CLASSIFICACAOCFOP = 3) AND (:VVALORIPIDEVOLV > 0)) THEN
            SOMARVLRIPIDEVOLV = SOMARVLRIPIDEVOLV + VVALORIPIDEVOLV;
        IF ((:IPI+:VLRIPITRIB) > 0)  THEN BEGIN
            SOMAIPI = SOMAIPI - VLRIPI;
            IF (IPI > 0) THEN BEGIN
                IF ((SUBSTRING(:CST FROM 1 FOR 1) IN (1,2,6,7)) AND (:USARDIVISORIPI = 'S')) THEN
                    BASECALCIPI = (:ITENSTOTAL/((100-(:IPI))/100));
                ELSE
                    BASECALCIPI = :ITENSTOTAL;
                IF (:NAOABATERDESCIPI = 'S') THEN
                    BASECALCIPI = BASECALCIPI + :VDESCVLRITEM;
                IF (:NAOABATERDESCIPI = 'N') THEN
                    BASECALCIPI = :BASECALCIPI - ((:ITENSTOTAL/100)*:DESCPORCPROD);
                IF (:NAOCALCIPISOBREFRETE <> 'S') THEN
                    BASECALCIPI = :BASECALCIPI + :VLRFRETEITEM;
                VLRIPI  = CAST(:BASECALCIPI * :IPI / 100 AS NUMERIC(18,2));
                IF (:NAOCALCIPISOBVLRADIC <> 'S') THEN
                    BASECALCIPI = :BASECALCIPI + :VLRSEGDESPACESSITEM;
                VLRIPI  = CAST(:BASECALCIPI * :IPI / 100 AS NUMERIC(18,2));
            END ELSE BEGIN
                BASECALCIPI = 0;
                VLRIPI = ((:CONVUNMEDIDA  * :QTDE) * :VLRIPITRIB);
                IF (:NAOABATERDESCIPI = 'N') THEN
                    VLRIPI = VLRIPI - ((VLRIPI *:DESCPORCPROD)/100);
                IF (:NAOCALCIPISOBREFRETE <> 'S') THEN
                    VLRIPI = VLRIPI + CAST(((:VLRFRETEITEM*VLRIPI)/:ITENSTOTAL) AS NUMERIC(18,2));
                    VLRIPI = CAST(:VLRIPI AS NUMERIC(18,2));
                IF (:NAOCALCIPISOBVLRADIC <> 'S') THEN
                    VLRIPI = VLRIPI + CAST(((:VLRSEGDESPACESSITEM*VLRIPI)/:ITENSTOTAL) AS NUMERIC(18,2));
                    VLRIPI = CAST(:VLRIPI AS NUMERIC(18,2));
            END
            SOMARBCIPI = SOMARBCIPI + BASECALCIPI;
            SOMAIPI = :SOMAIPI + :VLRIPI;
            IF ( (:TIPOPROD IN (7,8)) OR (:CONSUMIDORFINAL='S') OR (:SOMARIPIBASEICMS='S') ) THEN BEGIN
                BASEICMS = :BASEICMS + :VLRIPI;
            END
        END
        IF (CONSUMIDORFINAL = 'S') THEN BEGIN
            IF ((:CLASSIFICACAOCFOP=1) AND (:CFOP <> '7')) THEN BEGIN
               IF (SUBSTRING(:CST FROM 1 FOR 1) IN ('0','3','4','5')) THEN BEGIN
                   IF (:ALIQNACIMPOSTO > 0) THEN
                       VLRAPROXTRIBFEDPROD = CAST(((:ITENSTOTAL-:VLRDESCGLOBAL) * :ALIQNACIMPOSTO)/100 AS NUMERIC(18,2));
               END ELSE BEGIN
                   IF (:ALIQIMPIMPOSTO > 0) THEN
                       VLRAPROXTRIBFEDPROD = CAST(((:ITENSTOTAL-:VLRDESCGLOBAL) * :ALIQIMPIMPOSTO)/100 AS NUMERIC(18,2));
               END
               VLRAPROXTRIBESTPROD = CAST(((:ITENSTOTAL-:VLRDESCGLOBAL) * :ALIQESTIMPOSTOPROD)/100 AS NUMERIC(18,2));
               VLRAPROXTRIBMUNICPROD = CAST(((:ITENSTOTAL-:VLRDESCGLOBAL) * :ALIQMUNICIMPOSTOPROD)/100 AS NUMERIC(18,2));
            END
        END
        SOMARVLRAPROXIMPPROD = SOMARVLRAPROXIMPPROD + :VLRAPROXTRIBFEDPROD + VLRAPROXTRIBESTPROD + VLRAPROXTRIBMUNICPROD;
        IF (:DESCPORCPROD > 0) THEN
            ITENSTOTAL = :ITENSTOTAL - ((:ITENSTOTAL/100)*:DESCPORCPROD);
        IF ((REGIMETRIB = 0) AND (ALIQICMS = 0) AND (:CST2 <> '90'))  THEN
            ALIQICMS = :ALIQTRIB;
        IF (:CST2 IN ('00','10')) THEN BEGIN
            BASEICMS     = :BASEICMS + :VLRRATEIOITEM;
            VLRICMS      = CAST(:BASEICMS * :ALIQICMS / 100 AS NUMERIC(18,2));
        END
        IF (((:CST2 IN ('20','51','70'))) OR ((:CST2 = '90') AND (:ALIQICMS>0))) THEN BEGIN
            AUX = 0;
            AUX = :BASEICMS + :VLRRATEIOITEM;
            VBASEICMSSEMRED = CAST(:AUX AS NUMERIC(18,2));
            AUX = AUX * ((100 - :PERCREDICMS) / 100);
            IF ((:CST2 = '51') OR ((:CST2 = '90') AND (:VPERCDIF>0))) THEN BEGIN
                BASEICMS = CAST(:AUX AS NUMERIC(18,2));
                AUX = 0;
                AUX = :BASEICMS;
                AUX = AUX * ((100 - :VPERCDIF) / 100);
                VLRICMS = CAST(((:AUX/100)*:ALIQICMS) AS NUMERIC(18,2));
            END ELSE BEGIN
                BASEICMS = CAST(:AUX AS NUMERIC(18,2));
                AUX = 0;
                AUX = (:BASEICMS/100)*:ALIQICMS;
                VLRICMS = CAST(:AUX AS NUMERIC(18,2));
                IF (:VICMSDESON = 0) THEN BEGIN
                    IF ((:PERCREDICMS > 0) AND (:ALIQICMS>0)) THEN BEGIN
                     AUX = 0;
                     AUX = CAST(VBASEICMSSEMRED - VLRICMS AS NUMERIC(18,2));
                     AUX = CAST(:AUX / (1 - (:ALIQICMS / 100)) AS NUMERIC(18,2));
                     AUX = CAST(((:AUX/100)*:ALIQICMS) AS NUMERIC(18,2));
                     VVLRICMSDESON = CAST((:AUX - VLRICMS)  AS NUMERIC(18,2));
                    END ELSE BEGIN
                        AUX = 0;
                        AUX = CAST((:VBASEICMSSEMRED/100)*:ALIQICMS AS NUMERIC(18,2));
                        VVLRICMSDESON = CAST((:AUX - VLRICMS)  AS NUMERIC(18,2));
                    END
                END
            END
        END
        IF ((:VICMSDESON = 0) AND (:CST2 IN ('30','40','41','50')) AND (:ALIQINTERNADEST>0)) THEN BEGIN
            AUX = 0;
            IF ((:CST2 = '30') AND (:ALIQICMS > 0)) THEN
                AUX = CAST((:ITENSTOTAL*(:ALIQICMS/100)) AS NUMERIC(18,2));
            ELSE
                AUX = CAST((:ITENSTOTAL*(:ALIQINTERNADEST/100)) AS NUMERIC(18,2));
            VVLRICMSDESON = CAST(:AUX  AS NUMERIC(18,2));
        END
        IF (:VICMSDESONDEDUZTOTNF = 0) THEN
            VSOMAVLRICMSDESON = VSOMAVLRICMSDESON + VVLRICMSDESON;
        VTOTALICMSDESON = VTOTALICMSDESON + VVLRICMSDESON;
        BCICMSDEST = 0;
        SELECT EMISSAO FROM NFENTRADA
        WHERE (CHAVE = (SELECT FIRST 1 I.CHAVENF FROM OBSLIVROFISCCOMPLDOCFISC O
            INNER JOIN ITENSCOMPLDOCFISCAL I ON (O.CHAVE=I.CHAVECOMPLDOCFISCAL) AND (I.ATIVO=1) AND (I.ORIGEMDOCFISCAL=0)
            WHERE (O.ATIVO=1) AND (O.TIPODOCFISCAL=1) AND (O.TIPO=1) AND (O.CHAVEDOCFISCAL=:CHAVEPEDIDO)
            ORDER BY I.CHAVENF DESC))
        INTO :VDATAEMISSAO;
        IF (:VDATAEMISSAO IS NOT NULL) THEN BEGIN
            PERCICMSPART = CASE EXTRACT(YEAR FROM :VDATAEMISSAO)
            WHEN 2015 THEN 40
            WHEN 2016 THEN 40
            WHEN 2017 THEN 60
            WHEN 2018 THEN 80
            ELSE 100 END;
        END ELSE BEGIN
            PERCICMSPART = CASE EXTRACT(YEAR FROM CURRENT_DATE)
            WHEN 2015 THEN 40
            WHEN 2016 THEN 40
            WHEN 2017 THEN 60
            WHEN 2018 THEN 80
            ELSE 100 END;
        END
        IF ((:NAOCALCICMSSOBFRETE = 'S') AND (BASEICMS>0) AND (VLRFRETEITEM>0)) THEN BEGIN
            BASEICMS = BASEICMS  - :VLRFRETEITEM;
            VLRICMS = CAST(:BASEICMS * :ALIQICMS / 100 AS NUMERIC(18,2));
        END
        IF ((:NAOCALCICMSVLRADIC = 'S') AND (BASEICMS>0) AND (VLRSEGDESPACESSITEM>0)) THEN BEGIN
            BASEICMS = BASEICMS  - :VLRSEGDESPACESSITEM;
            VLRICMS = CAST(:BASEICMS * :ALIQICMS / 100 AS NUMERIC(18,2));
        END
        IF (((:CODANP = '') OR ((:CODANP <> '') AND (CODANP IN ('820101001', '820101010', '810102001', '810102004', '810102002', '810102003', '810101002', '810101001',
                '810101003', '220101003', '220101004', '220101002', '220101001', '220101005', '220101006')))) AND (
                (((CONSUMIDORFINAL = 'S') AND (ALIQINTERNADEST > 0) AND (:UFCLI <> :UFEMP)) AND (:NAOGERARDIFAL = 'N') AND (VMACRONAOGERARDIFAL = 'N')
                AND (:CFOP <> '5')))) THEN
            VPARTICMSDIFAL = 'S';
        IF (VPARTICMSDIFAL = 'S') THEN BEGIN
            SELECT CASE WHEN PERCPROD >= 0 THEN PERCPROD ELSE CASE WHEN PERCNCM >= 0 THEN PERCNCM ELSE PERCUF END END FROM (
            SELECT
            COALESCE((SELECT FIRST 1 T1.PERCENTUAL FROM TRIBUTACAOFCP T1
            WHERE T1.ATIVO=1 AND T1.CHAVEPRODUTO = I.CHAVEPRODUTO AND T1.UF = :UFCLI
            ),-1) AS PERCPROD, COALESCE((SELECT FIRST 1 T2.PERCENTUAL FROM TRIBUTACAOFCP T2
            WHERE T2.ATIVO=1 AND T2.CHAVECLASSFISCAL = I.CHAVECLASSFISCAL AND T2.UF = :UFCLI
            ),-1) AS PERCNCM, COALESCE((SELECT FIRST 1  T3.PERCENTUAL FROM TRIBUTACAOFCP T3
            WHERE T3.ATIVO=1 AND T3.UF = :UFCLI AND (COALESCE(T3.CHAVEPRODUTO,0)=0) AND (COALESCE(T3.CHAVECLASSFISCAL,0)=0)
            ),-1) AS PERCUF
            FROM ITENSPEDSAIDA I
            WHERE I.CHAVE = :CHAVEITENSPS)
            INTO :PERCICMSFCP;
            IF (PERCICMSFCP = -1) THEN
                PERCICMSFCP = 0;
            BCICMSDEST = :BASEICMS;
            IF (BCICMSDEST=0) THEN
                BCICMSDEST = CAST((:ITENSTOTAL + :VLRRATEIOITEM + :VLRIPI) AS NUMERIC (18,2));
            SELECT DESCRICAO FROM TABELAS
            WHERE (ATIVO=1) AND (CHAVETABELA=76) AND (TIPO=1) AND (DESCRICAO=:UFCLI)
            INTO :CALCDIFALDUPLO;
            IF ((:CALCDIFALDUPLO <> '') AND (:ALIQINTERNADEST <> :ALIQICMS)) THEN BEGIN
                VLRICMSPARTDEST = CAST(((:BCICMSDEST / (1 - (:ALIQINTERNADEST / 100))) * (:ALIQINTERNADEST / 100)) - ((:BCICMSDEST / (1 - (:ALIQINTERNADEST / 100))) * (:ALIQICMS / 100)) AS NUMERIC(18,2));
                BCICMSDEST = :BASEICMS + :VLRICMSPARTDEST;
            END ELSE BEGIN
                VLRICMSPARTDEST = CAST(((:BCICMSDEST*(:ALIQINTERNADEST - :ALIQICMS)/100) * ((:PERCICMSPART)/100)) AS NUMERIC (18,2));
            END
            VLRICMSPARTREMET = CAST(((:BCICMSDEST*(:ALIQINTERNADEST - :ALIQICMS)/100) * (((100-:PERCICMSPART))/100)) AS NUMERIC (18,2));
            IF (PERCICMSFCP>0) THEN
                VLRICMSFCPDE = CAST((:BCICMSDEST * PERCICMSFCP)/100 AS NUMERIC (18,2));
            IF (VLRICMSPARTDEST<=0) THEN
                VLRICMSPARTDEST = 0;
            IF (VLRICMSPARTREMET<=0) THEN
                VLRICMSPARTREMET = 0;
        END ELSE BEGIN
            SELECT CASE WHEN PERCPROD >= 0 THEN PERCPROD ELSE CASE WHEN PERCNCM >= 0 THEN PERCNCM ELSE PERCUF END END FROM (
            SELECT
            COALESCE((SELECT FIRST 1 T1.PERCENTUAL FROM TRIBUTACAOFCP T1
            WHERE T1.ATIVO=1 AND T1.CHAVEPRODUTO = I.CHAVEPRODUTO AND T1.UF = :UFEMP
            ),-1) AS PERCPROD, COALESCE((SELECT FIRST 1 T2.PERCENTUAL FROM TRIBUTACAOFCP T2
            WHERE T2.ATIVO=1 AND T2.CHAVECLASSFISCAL = I.CHAVECLASSFISCAL AND T2.UF = :UFEMP
            ),-1) AS PERCNCM, COALESCE((SELECT FIRST 1  T3.PERCENTUAL FROM TRIBUTACAOFCP T3
            WHERE T3.ATIVO=1 AND T3.UF = :UFEMP AND (COALESCE(T3.CHAVEPRODUTO,0)=0) AND (COALESCE(T3.CHAVECLASSFISCAL,0)=0)
            ),-1) AS PERCUF
            FROM ITENSPEDSAIDA I
            WHERE I.CHAVE = :CHAVEITENSPS)
            INTO :PERCICMSFCP;
            IF (PERCICMSFCP = -1) THEN
                PERCICMSFCP = 0;
        END
        IF ((:CST2 IN ('30','40','41','50','60','61')) OR ((:CST2 IN ('90', '51')) AND (:ALIQICMS = 0)))  THEN BEGIN
            BASEICMS = 0;
            VLRICMS  = 0;
        END
        IF ((:DESCONTO <> 0) AND (COMPORTOTALNF = 0)) THEN BEGIN
            VLRUNITCOMDESC = :VLRUNITCOMDESC - (:VLRDESCGLOBAL / :QTDEEST);
        END
        IF ((((:CST2 IN ('10','30','60','70')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S')))) AND
        (NOT ((:CLASSIFICACAOCFOP IN (2,3)) AND (:MVA=0) AND (:BASEICMSSUBSTTRIB>0) AND (:VLRICMSSUBSTTRIB>0)))) THEN BEGIN
            AUX  = 0;
            AUX2 = 0;
            VUFCLIST = :UFCLI;
            VUFEMPST = :UFEMP;
            IF ((:CLASSIFICACAOCFOP = 3) AND (:CONSUMIDORFINAL = 'N')) THEN BEGIN
                VUFCLIST = :UFEMP;
                VUFEMPST = :UFCLI;
            END
            IF (:CST2='60') THEN BEGIN
               IF ((:CONSUMIDORFINAL = 'S') AND (:ALIQICMS>0)) THEN BEGIN
                  BASEICMSSTEFET = :ITENSTOTAL - ((:ITENSTOTAL * :PERCREDST) / 100);
                  VLRICMSSTEFET = (BASEICMSSTEFET * ALIQICMS) / 100;
                  TOTBASEICMSSTEFET = :TOTBASEICMSSTEFET + :BASEICMSSTEFET;
                  TOTVLRICMSSTEFET = :TOTVLRICMSSTEFET + :VLRICMSSTEFET;
               END ELSE BEGIN
                   IF ((ALIQICMS>0) AND (:VALTERARSTDESTMANUAL <> 'S'))  THEN BEGIN
                       SELECT BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, MVAAJUSTADO FROM
                       CALCULARMVA(:MVAORIG, :CST, :ALIQICMS,
                       :BASESTCST60, :QTDE, 0, 0, :VUFCLIST, :VUFEMPST, :IPI, :REDUCAOMVA, CASE WHEN :CLASSIFICACAOCFOP IN (2,3) THEN :REGIMETRIBCLIFOR ELSE :REGIMETRIB END, 0, :VLRIPI, 0, 0)
                       INTO :AUX, :AUX2, :MVA;
                   END
               END
            END ELSE BEGIN
               VVALORUNITCALCST = VLRUNITCOMDESC;
               IF (:VVLRICMSDESON > 0) THEN BEGIN
                  VVALORUNITCALCST = :VLRUNITCOMDESC - (:VVLRICMSDESON/:QTDE);
               END
               SELECT BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, MVAAJUSTADO FROM
               CALCULARMVA(:MVAORIG, :CST, :ALIQICMS,
               :VVALORUNITCALCST + (:VLRRATEIOITEM/:QTDE), :QTDE,
               :PERCREDICMS, :PERCREDST, :VUFCLIST, :VUFEMPST, :IPI, :REDUCAOMVA, CASE WHEN :CLASSIFICACAOCFOP IN (2,3) THEN :REGIMETRIBCLIFOR ELSE :REGIMETRIB END, 0, :VLRIPI, :VLRPAUTA, :CHAVEUNIDADE)
               INTO :AUX, :AUX2, :MVA;
            END
            IF ((:CST2 IN ('10','30','70')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S') AND (:ALIQICMS>0))) THEN BEGIN
                IF (CAST(:AUX2 AS NUMERIC(18,2)) <= 0) THEN BEGIN
                    BASEICMSSUBSTTRIB = 0;
                    VLRICMSSUBSTTRIB  = 0;
                END ELSE BEGIN
                    BASEICMSSUBSTTRIB = CAST(:AUX AS NUMERIC(18,2));
                    VLRICMSSUBSTTRIB  = CAST(:AUX2 AS NUMERIC(18,2));
                END
                IF ((:CST2 = '30') AND (:VICMSDESON=0) AND (:VVLRICMSDESON > 0)) THEN BEGIN
                    VLRICMSSUBSTTRIB = :VLRICMSSUBSTTRIB - :VVLRICMSDESON;
                END
                SOMABASESUBSTTRIB = :SOMABASESUBSTTRIB + :BASEICMSSUBSTTRIB;
                SOMAVLRSUBSTTRIB = :SOMAVLRSUBSTTRIB + :VLRICMSSUBSTTRIB;
            END ELSE BEGIN
                IF (CAST(:AUX2 AS NUMERIC(18,2)) > 0) THEN BEGIN
                    BASEICMSSUBSTTRIBDESTAC = CAST(:AUX AS NUMERIC(18,2));
                    VLRICMSSUBSTTRIBDESTAC  = CAST(:AUX2 AS NUMERIC(18,2));
                END
                IF (:VALTERARSTDESTMANUAL <> 'S') THEN BEGIN
                    IF ((:CST2='60') AND (:VBCSTMEDIADEST > 0) AND (:MVA = 0) AND (:VMEDIAICMSSTDEST > 0)) THEN BEGIN
                      BASEICMSSUBSTTRIBDESTAC = :VBCSTMEDIADEST * :QTDE;
                      VLRICMSSUBSTTRIBDESTAC = :VMEDIAICMSSTDEST * :QTDE;
                    END
                END
                SOMABASESUBSTTRIBDEST = :SOMABASESUBSTTRIBDEST + :BASEICMSSUBSTTRIBDESTAC;
                SOMAVLRSUBSTTRIBDEST = :SOMAVLRSUBSTTRIBDEST + :VLRICMSSUBSTTRIBDESTAC;
            END
            /* CALCULO DIFAL ST COM ARITMETICA SIMPLES ALIQ COM CALCULO DE ST CONVENIO.*/
            IF ((:MVA=0) AND (TIPOCALCST=1) AND (:VLRICMSSUBSTTRIB>0) AND (:CST2 = '10') AND (:UFCLI <> :UFEMP)) THEN BEGIN
                SOMABASESUBSTTRIB = :SOMABASESUBSTTRIB - :BASEICMSSUBSTTRIB;
                SOMAVLRSUBSTTRIB  =  :SOMAVLRSUBSTTRIB - :VLRICMSSUBSTTRIB;
                IF ((:UFCLI = 'PR') OR (:UFCLI = 'GO'))  THEN BEGIN
                    BASEICMSSUBSTTRIB = CAST(((:ITENSTOTAL + :VLRRATEIOITEM + :VLRIPI)/(1-(:ALIQINTERNADEST/100))) AS NUMERIC(18,2));
                    AUX = CAST(:BASEICMSSUBSTTRIB * (:ALIQICMS / 100) AS NUMERIC(18,2));
                    VLRICMSSUBSTTRIB = CAST(:BASEICMSSUBSTTRIB * (:ALIQINTERNADEST/100) - :AUX AS NUMERIC(18,2));
                END ELSE BEGIN
                    BASEICMSSUBSTTRIB = CAST((((:ITENSTOTAL + :VLRRATEIOITEM + :VLRIPI) - :VLRICMS)/ (1-(:ALIQINTERNADEST/100))) AS NUMERIC(18,2));
                    VLRICMSSUBSTTRIB = CAST(:BASEICMSSUBSTTRIB * (:ALIQINTERNADEST/100) - :VLRICMS AS NUMERIC(18,2));
                END
                IF (:MOSTRARBASESTRED = 'S') THEN
                    BASEICMSSUBSTTRIB = CAST((:ITENSTOTAL + :VLRRATEIOITEM + :VLRIPI) AS NUMERIC(18,2));
                SOMABASESUBSTTRIB = :SOMABASESUBSTTRIB + :BASEICMSSUBSTTRIB;
                SOMAVLRSUBSTTRIB  = :SOMAVLRSUBSTTRIB + :VLRICMSSUBSTTRIB;
            END
            IF (:CST2 = '60') THEN BEGIN
                UPDATE ITENSPEDSAIDA SET ICMS = 0
                WHERE CHAVE=:CHAVEITENSPS;
            END
            IF ((:CST2 IN ('10','30','70')) OR ((:CST2 = '90') AND (:CSTSUBSTTRIB='S') AND (:ALIQICMS>0))) THEN BEGIN
                UPDATE ITENSPEDSAIDA SET MVACALC = :MVA
                WHERE CHAVE=:CHAVEITENSPS;
            END
        END ELSE BEGIN
            IF ((:MVA=0) AND ((:CST2 NOT IN ('10','30','70')))) THEN BEGIN
                IF (NOT (((:CST2 = '90') AND (:CSTSUBSTTRIB='S')))) THEN BEGIN
                    BASEICMSSUBSTTRIB   = 0;
                    VLRICMSSUBSTTRIB    = 0;
                END
            END
            BASEICMSSUBSTTRIBDESTAC = 0;
            VLRICMSSUBSTTRIBDESTAC  = 0;
            SOMABASESUBSTTRIB = :SOMABASESUBSTTRIB + :BASEICMSSUBSTTRIB;
            SOMAVLRSUBSTTRIB = :SOMAVLRSUBSTTRIB + :VLRICMSSUBSTTRIB;
        END
        IF ((:REGIMETRIB = 0) AND (:CLASSIFICACAOCFOP IN (1,6)) AND
            (:ALIQICMSSIMPLESNACIONAL > 0) AND (:CODSIMPLESNAC IN ('101','201','900'))) THEN BEGIN
            IF (CONSUMIDORFINAL = 'S') THEN BEGIN
                IF (CODSIMPLESNAC = '101') THEN
                    CODSIMPLESNAC = '102';
                VLRICMSSIMPLESNACITEN = 0;
            END ELSE BEGIN
                AUXSIMPLESNAC = ((:ITENSTOTAL + COALESCE(:VLRFRETEITEM,0) + COALESCE(:VLRSEGUROITEM,0)+COALESCE(:VLRACESSITEM,0)));
                VLRICMSSIMPLESNACITEN = (:AUXSIMPLESNAC/100)*:ALIQICMSSIMPLESNACIONAL;
                BASEICMSSIMPLESNACIONAL = :BASEICMSSIMPLESNACIONAL + :AUXSIMPLESNAC;
            END
        END ELSE BEGIN
            VLRICMSSIMPLESNACITEN = 0;
        END
        ALIQUOTAINTER = :ALIQICMS;
        IF ((:REGIMETRIB = 0) AND (:CST2 <> '61')) THEN BEGIN
            IF (NOT ((:CODSIMPLESNAC = '900') AND (:ALIQICMS>0))) THEN BEGIN
               IF (CLASSIFICACAOCFOP=3) THEN BEGIN
                  TOTBASEICMSDEVOL = :TOTBASEICMSDEVOL + :BASEICMS;
                  TOTVLRICMSDEVOL  = :TOTVLRICMSDEVOL + :VLRICMS;
               END
               ALIQICMS    = 0;
               BASEICMS    = 0;
               VLRICMS     = 0;
               VLRICMSPARTREMET = 0;
               VLRICMSPARTDEST = 0;
               VLRICMSFCPDE = 0;
               PERCICMSFCP = 0;
               BCICMSDEST = 0;
            END
        END
        IF ((:BASEICMS > 0) AND (:PERCICMSFCP > 0) AND (:VPARTICMSDIFAL = 'N'))  THEN
           VLRICMSFCPDE = CAST((BASEICMS * PERCICMSFCP)/100 AS NUMERIC (18,2));
        TOTVLRICMSPARTDEST = :TOTVLRICMSPARTDEST + :VLRICMSPARTDEST;
        TOTVLRICMSPARTREMET = :TOTVLRICMSPARTREMET + :VLRICMSPARTREMET;
        IF (((:UFCLI = :UFEMP) OR ((:UFCLI <> :UFEMP) AND (:BASEICMSSUBSTTRIB>0))) AND (:VPARTICMSDIFAL = 'N')) THEN BEGIN
            SELECT CASE WHEN PERCPROD >= 0 THEN PERCPROD ELSE CASE WHEN PERCNCM >= 0 THEN PERCNCM ELSE PERCUF END END FROM (
            SELECT
            COALESCE((SELECT FIRST 1  T1.PERCENTUAL FROM TRIBUTACAOFCP T1
            WHERE T1.ATIVO=1 AND T1.CHAVEPRODUTO = I.CHAVEPRODUTO AND T1.UF = CASE WHEN :CLASSIFICACAOCFOP = 3 THEN :UFEMP ELSE :UFCLI END
            ),-1) AS PERCPROD, COALESCE((SELECT FIRST 1  T2.PERCENTUAL FROM TRIBUTACAOFCP T2
            WHERE T2.ATIVO=1 AND T2.CHAVECLASSFISCAL = I.CHAVECLASSFISCAL AND T2.UF = CASE WHEN :CLASSIFICACAOCFOP = 3 THEN :UFEMP ELSE :UFCLI END
            ),-1) AS PERCNCM, COALESCE((SELECT FIRST 1  T3.PERCENTUAL FROM TRIBUTACAOFCP T3
            WHERE T3.ATIVO=1 AND T3.UF = CASE WHEN :CLASSIFICACAOCFOP = 3 THEN :UFEMP ELSE :UFCLI END AND (COALESCE(T3.CHAVEPRODUTO,0)=0) AND (COALESCE(T3.CHAVECLASSFISCAL,0)=0)
            ),-1) AS PERCUF
            FROM ITENSPEDSAIDA I
            WHERE I.CHAVE = :CHAVEITENSPS)
            INTO :PERCICMSFCPST;
            IF (PERCICMSFCPST = -1) THEN
                PERCICMSFCPST = 0;
            IF (:PERCICMSFCPST>0) THEN BEGIN
                IF ((:SOMARSTIPIDESPACESS<>'S') AND (:BASEICMSSUBSTTRIB > 0)) THEN BEGIN
                    VLRICMSFCPST = CAST((((BASEICMSSUBSTTRIB * PERCICMSFCPST)/100))  AS NUMERIC (18,2));
                END ELSE BEGIN
                    IF (:BASEICMSSUBSTTRIBDESTAC > 0) THEN
                        VLRICMSFCPSTDEST = CAST((BASEICMSSUBSTTRIBDESTAC * PERCICMSFCPST)/100 AS NUMERIC (18,2));
                END
            END
        END
        TOTALICMSFCPSTDEST = :TOTALICMSFCPSTDEST + :VLRICMSFCPSTDEST;
        TOTALICMSFCPST = :TOTALICMSFCPST + :VLRICMSFCPST;
        TOTVLRICMSFCP = :TOTVLRICMSFCP + :VLRICMSFCPDE;
        SOMABASEICMS = :SOMABASEICMS + :BASEICMS;
        SOMAVLRICMS = :SOMAVLRICMS + :VLRICMS;
        IF ((:VBCPIS <= 0) OR (:VSEGMENTO <> 1)) THEN
            VBCPIS = :ITENSTOTAL + :VLRRATEIOITEM;
         IF (:ABATERICMSBASEPISCOFINS = 'S') THEN BEGIN
            IF(:VBCPIS > 0) THEN BEGIN
                VBCPIS = :VBCPIS - :VLRICMS;
            END
        END
        SELECT BASE, VALORPIS, VALORCOFINS, ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB
        FROM CALCULARPISCOFINS(:CSTCOFINS, :VBCPIS, :CODTABPISCOFINS, :QTDE, :CONVUNMEDIDA)
        INTO :BASECALCCOFINS, :VALORPIS, :VALORCOFINS, :ALIQPIS, :ALIQCOFINS, :VLRPISTRIB, :VLRCOFINSTRIB;
        VALORTOTPIS = :VALORTOTPIS + :VALORPIS;
        VALORTOTCOFINS = :VALORTOTCOFINS + :VALORCOFINS;
        BASETOTALPISCOFINS = :BASETOTALPISCOFINS + BASECALCCOFINS;
        IF (:SOMARSTIPIDESPACESS = 'S') THEN BEGIN
            VLRACESSITEM = COALESCE(:VLRACESSITEM, 0);
            VLRIPI = COALESCE(:VLRIPI, 0);
            VLRIPITRIB = COALESCE(:VLRIPITRIB, 0);
            VLRICMSSUBSTTRIB = COALESCE(:VLRICMSSUBSTTRIB, 0);
            VLRACESSITEM = :VLRACESSITEM + CAST((:VLRIPI + :VLRIPITRIB + :VLRICMSSUBSTTRIB) AS NUMERIC(18,2));
        END
        IF (VCALCREFTRIB = 'S') THEN BEGIN
            VBASEIVA = :VBASEIVA + :VLRRATEIOITEM - (:VLRICMS + :VALORPIS + :VALORCOFINS + :VLRICMSFCPDE + :VLRICMSPARTDEST);
            VBCIVAAUX = :VBASEIVA;
            SELECT SALIQUOTA, SBASEIVA, SVALOR, SVALORDIF, SBCCREDPRES, SVALORCREDPRES FROM CALCTRIBCBSIBS('CBS', :VCHAVECLASSTRIB, :UFCLI, :EMPRESALOG, :VCHAVECIDADE, :VBASEIVA, :VALIQCBS, :VPERCREDGOV, :VPERCCREDPRES, :VCHAVECREDPRES)
            INTO :VALIQCBS, :VBASEIVA, :VVLRCBS, :VVLRCBSDIF, :VBCCREDPRES, :VVLRCREDPRESCBS;
    
            VVLRCBSPED = VVLRCBSPED + :VVLRCBS;
            VVLRCBSDIFPED = VVLRCBSDIFPED + :VVLRCBSDIF;
            VVLRCREDPRESCBSPED =  VVLRCREDPRESCBSPED + :VVLRCREDPRESCBS;
            IF ((:VPERCCREDPRES > 0) AND (VVLRCREDPRESCBS > 0) AND (VBASEIVA = 0) AND (:VBCIVAAUX > 0)) THEN
                VBASEIVA = :VBCIVAAUX;
            SELECT SALIQUOTA, SBASEIVA, SVALOR, SVALORDIF, SVALORCREDPRES FROM CALCTRIBCBSIBS('IBSUF', :VCHAVECLASSTRIB, :UFCLI, :EMPRESALOG, :VCHAVECIDADE, :VBASEIVA, :VALIQIBSUF, :VPERCREDGOV, :VPERCCREDPRES, :VCHAVECREDPRES)
            INTO :VALIQIBSUF, :VBASEIVA, :VVLRIBSUF, :VVLRIBSDIFUF, :VVLRCREDPRESIBS;
    
            VVLRIBSUFPED = VVLRIBSUFPED + :VVLRIBSUF;
            VVLRIBSDIFUFPED =  VVLRIBSDIFUFPED + :VVLRIBSDIFUF;
            VVLRCREDPRESIBSPED =  VVLRCREDPRESIBSPED + :VVLRCREDPRESIBS;
    
            SELECT SALIQUOTA, SVALOR, SVALORDIF FROM CALCTRIBCBSIBS('IBSMUN', :VCHAVECLASSTRIB, :UFCLI, :EMPRESALOG, :VCHAVECIDADE, :VBASEIVA, :VALIQIBSMUN, :VPERCREDGOV, 0, 0)
            INTO :VALIQIBSMUN, :VVLRIBSMUN, :VVLRIBSDIFMUN;
    
            VVLRIBSMUNPED = VVLRIBSMUNPED + :VVLRIBSMUN;
            VVLRIBSDIFMUNPED =  VVLRIBSDIFMUNPED + :VVLRIBSDIFMUN;
    
            VBASEIVAPED = VBASEIVAPED + :VBASEIVA;
        END ELSE BEGIN
           :VBASEIVA = 0;
           :VALIQCBS = 0;
           :VVLRCBS = 0;
           :VVLRCBSDIF = 0;
           :VALIQIBSUF = 0;
           :VVLRIBSUF = 0;
           :VVLRIBSDIFUF = 0;
           :VALIQIBSMUN = 0;
           :VVLRIBSMUN = 0;
           :VVLRIBSDIFMUN = 0;
           :VVLRCREDPRESIBS = 0;
           :VVLRCREDPRESCBS = 0;
           :VBCCREDPRES = 0;
        END
        UPDATE ITENSPEDSAIDA I SET
        BASEICMS = :BASEICMS, VLRICMS = :VLRICMS, ICMS = :ALIQICMS, VLRICMSDESON = :VVLRICMSDESON,
        BASEIVA = :VBASEIVA,
        ALIQCBS = :VALIQCBS,
        ALIQIBSUF = :VALIQIBSUF,
        ALIQIBSMUN = :VALIQIBSMUN,
        VLRCBS = :VVLRCBS,
        VLRCBSDIF = :VVLRCBSDIF,
        VLRIBSUF = :VVLRIBSUF,
        VLRIBSDIFUF = :VVLRIBSDIFUF,
        VLRIBSMUN = :VVLRIBSMUN,
        VLRIBSDIFMUN = :VVLRIBSDIFMUN,
        BCCREDPRES = :VBCCREDPRES,
        VLRCREDPRESCBS = :VVLRCREDPRESCBS,
        VLRCREDPRESIBS = :VVLRCREDPRESIBS,
        BASECALCIPI = CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN :BASECALCIPI ELSE 0 END,
        VLRIPI= CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN :VLRIPI ELSE 0 END,
        IPI= CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN :IPI ELSE 0 END,
        VLRIPITRIB= CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN :VLRIPITRIB ELSE 0 END,
        BASEICMSSUBSTTRIB = CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN :BASEICMSSUBSTTRIB ELSE 0 END,
        VLRICMSSUBSTTRIB = CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN :VLRICMSSUBSTTRIB ELSE 0 END,
        I.CSTIPI = CASE WHEN (:SOMARSTIPIDESPACESS<>'S') OR (I.CSTIPI<>'50') THEN I.CSTIPI ELSE '99' END,
        I.IPITRIB = CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN I.IPITRIB ELSE '' END,
        I.MVA = CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN I.MVA ELSE 0 END, 
        I.MVACALC = CASE WHEN (:SOMARSTIPIDESPACESS<>'S') THEN I.MVACALC ELSE 0 END,
        BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC = :VLRICMSSUBSTTRIBDESTAC,
        VLRUNITCOMDESC = :VLRUNITCOMDESC,
        VLRDESCGLOBAL = :VLRDESCGLOBAL,
        DESCPORC = CASE WHEN (:VLRACRESCGLOBAL = 0) THEN DESCPORC ELSE CAST((DESCVLR * 100) / (VLRSUBTOTAL + :VLRACRESCGLOBAL) AS NUMERIC(18,4)) END,
        VLRACRESCGLOBAL = COALESCE(VLRACRESCGLOBAL,0) + :VLRACRESCGLOBAL,
        VLRUNIT = VLRUNIT + (:VLRACRESCGLOBAL / :QTDE),
        VLRSUBTOTAL = VLRSUBTOTAL + :VLRACRESCGLOBAL,
        VLRTOTAL = VLRTOTAL + :VLRACRESCGLOBAL,
        VLRUNITTABELA = VLRUNITTABELA + (:VLRACRESCGLOBAL / :QTDE),
        VLRFRETE = :VLRFRETEITEM,
        VLRSEGURO = :VLRSEGUROITEM,
        VLRDESPACESSORIA = :VLRACESSITEM,
        QTDEESTOQUE = :QTDEEST,
        VLRICMSSIMPLESNACIONAL = :VLRICMSSIMPLESNACITEN,
        BCPIS = :BASECALCCOFINS, BCCOFINS=:BASECALCCOFINS,
        VLRPIS = :VALORPIS, VLRCOFINS = :VALORCOFINS,
        ALIQPIS = :ALIQPIS, ALIQCOFINS = :ALIQCOFINS,
        CSOSN = :CODSIMPLESNAC, VLRPISTRIB = :VLRPISTRIB, VLRCOFINSTRIB=:VLRCOFINSTRIB,
        VLRTOTTRIB = :VLRAPROXTRIBFEDPROD,
        VLRTOTTRIBEST = :VLRAPROXTRIBESTPROD,
        VLRTOTTRIBMUNIC = :VLRAPROXTRIBMUNICPROD,
        VLRICMSPARTDEST = :VLRICMSPARTDEST,
        VLRICMSPARTREMET = :VLRICMSPARTREMET,
        BCICMSUFDEST = :BCICMSDEST,
        ALIQICMSINTER = :ALIQUOTAINTER,
        VLRICMSFCP = :VLRICMSFCPDE,
        PERCICMSPART = :PERCICMSPART,
        PERCICMSFCP = :PERCICMSFCP,
        PERCICMSFCPST = :PERCICMSFCPST,
        VLRICMSFCPST = :VLRICMSFCPST,
        VLRICMSFCPSTDEST = :VLRICMSFCPSTDEST,
        BASEICMSSTEFET = :BASEICMSSTEFET,
        VLRICMSSTEFET = :VLRICMSSTEFET,
        ALIQICMSPROPRIOCOMPRA = :VALIQICMSPROPRIOCOMPRA,
        VLRICMSPROPRIOCOMPRA = CASE WHEN COALESCE(VLRICMSPROPRIOCOMPRA,0) > 0 THEN VLRICMSPROPRIOCOMPRA ELSE  CASE WHEN :VVMEDIAICMSSUBST > 0 THEN :VVMEDIAICMSSUBST ELSE :VPRECOCUSTOREAL * (:VALIQICMSPROPRIOCOMPRA/100) END END,
        PCVENDA = :VPRECOCUSTOREAL
        WHERE (CHAVE=:CHAVEITENSPS);
    END
    WHILE (:VLRDESCGLOBALACUMULADO > :DESCONTO) DO BEGIN
        FOR SELECT I.CHAVE, SUBSTRING(I.CST FROM 2 FOR 2), I.BASEICMS FROM ITENSPEDSAIDA I
        INNER JOIN CFOPOPERFISCAIS CF ON (CF.CHAVE = I.CHAVECFOPOPERFISCAIS)
        WHERE (I.ATIVO=1) AND (I.CHAVEPEDIDO=:CHAVEPEDIDO) AND (COALESCE(CF.COMPORTOTALNF,0) = 0)
        ORDER BY I.VLRTOTAL-I.VLRDESCGLOBAL DESC
        INTO :CHAVEITENSPS, :VCST2, :BASEICMS
        DO BEGIN
            IF (:VNAOABATERDESCICMS <> 'S') THEN BEGIN
                UPDATE ITENSPEDSAIDA I SET
                VLRDESCGLOBAL = VLRDESCGLOBAL - 0.01,
                VLRUNITCOMDESC = (VLRUNITCOMDESC + (0.01 / QTDEESTOQUE)),
                I.VLRICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN CAST((((I.BASEICMS + 0.01) * I.ICMS)/100) AS NUMERIC(18,2)) ELSE I.VLRICMS END,
                I.BASEICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN I.BASEICMS + 0.01 ELSE I.BASEICMS END
                WHERE CHAVE=:CHAVEITENSPS;
                IF ((:VCST2 IN ('00','10')) AND (:BASEICMS > 0)) THEN
                    SOMABASEICMS = :SOMABASEICMS + 0.01;
            END ELSE BEGIN
                UPDATE ITENSPEDSAIDA I SET
                VLRDESCGLOBAL = VLRDESCGLOBAL - 0.01,
                VLRUNITCOMDESC = (VLRUNITCOMDESC + (0.01 / QTDEESTOQUE))
                WHERE CHAVE=:CHAVEITENSPS;
            END
            VLRDESCGLOBALACUMULADO = :VLRDESCGLOBALACUMULADO - 0.01;
            IF (:VLRDESCGLOBALACUMULADO <= :DESCONTO) THEN BEGIN
                IF (:VNAOABATERDESCICMS <> 'S') THEN BEGIN
                    SELECT SUM(VLRICMS) FROM ITENSPEDSAIDA
                    WHERE (ATIVO=1) AND (CHAVEPEDIDO=:CHAVEPEDIDO)
                    INTO :SOMAVLRICMS;
                END
                BREAK;
            END
        END
    END
    WHILE (:VLRDESCGLOBALACUMULADO < :DESCONTO) DO BEGIN
        FOR SELECT I.CHAVE, SUBSTRING(I.CST FROM 2 FOR 2), I.BASEICMS FROM ITENSPEDSAIDA I
        INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS
        WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDIDO AND COALESCE(CF.COMPORTOTALNF,0) = 0
        ORDER BY I.VLRTOTAL-I.VLRDESCGLOBAL DESC
        INTO :CHAVEITENSPS, :VCST2, :BASEICMS
        DO BEGIN
            IF (:VNAOABATERDESCICMS <> 'S') THEN BEGIN
                UPDATE ITENSPEDSAIDA I SET
                I.VLRDESCGLOBAL = VLRDESCGLOBAL + 0.01,
                I.VLRUNITCOMDESC = (VLRUNITCOMDESC - (0.01 / QTDEESTOQUE)),
                I.VLRICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN CAST((((I.BASEICMS - 0.01) * I.ICMS)/100) AS NUMERIC(18,2)) ELSE I.VLRICMS END,
                I.BASEICMS = CASE WHEN SUBSTRING(I.CST FROM 2 FOR 2) IN ('00','10') AND (I.BASEICMS>0) THEN I.BASEICMS - 0.01 ELSE I.BASEICMS END
                WHERE CHAVE=:CHAVEITENSPS;
                IF ((:VCST2 IN ('00','10')) AND (:BASEICMS > 0)) THEN
                    SOMABASEICMS = :SOMABASEICMS - 0.01;
            END ELSE BEGIN
                UPDATE ITENSPEDSAIDA I SET
                I.VLRDESCGLOBAL = VLRDESCGLOBAL + 0.01,
                I.VLRUNITCOMDESC = (VLRUNITCOMDESC - (0.01 / QTDEESTOQUE))
                WHERE CHAVE=:CHAVEITENSPS;
            END
            VLRDESCGLOBALACUMULADO = :VLRDESCGLOBALACUMULADO + 0.01;
            IF (:VLRDESCGLOBALACUMULADO >= :DESCONTO) THEN BEGIN
                IF (:VNAOABATERDESCICMS <> 'S') THEN BEGIN
                    SELECT SUM(VLRICMS) FROM ITENSPEDSAIDA
                    WHERE (ATIVO=1) AND (CHAVEPEDIDO=:CHAVEPEDIDO)
                    INTO :SOMAVLRICMS;
                END
                BREAK;
            END
        END
    END
    IF (:TOTALSERVICO <> 0) THEN BEGIN
        VCOUNTITEMSERV = (SELECT COUNT(CHAVE) FROM ITENSPEDSAIDASERV WHERE (ATIVO=1) AND (CHAVEPEDIDO=:CHAVEPEDIDO));
        VDESCACUMULADOSERV = 0;
        FOR SELECT DISTINCT I.CHAVE, I.VLRTOTAL/I.QTDE, I.VLRTOTAL, PS.ALIQUOTAISS,
        COALESCE(COALESCE(IBPT.ALIQNAC, IBPTPROD.ALIQNAC), 0), COALESCE(COALESCE(IBPT.ALIQIMP, IBPTPROD.ALIQIMP), 0), COALESCE(COALESCE(IBPT.ALIQEST, IBPTPROD.ALIQEST), 0),
        COALESCE(COALESCE(IBPT.ALIQMUNIC, IBPTPROD.ALIQMUNIC), 0), COALESCE(CF.CLASSIFICACAO,0), COALESCE(T.CODIGO,''), M.RETERISSTOTALNF,
        SUBSTRING(CF.CODIGO FROM 1 FOR 1), COALESCE(COF.OPERCONSUMIDORFINAL,'N'), I.BASEIVA, I.VLRCBS, I.VLRIBSUF,
        I.VLRIBSMUN, COALESCE(I.ALIQCBS, 0), COALESCE(I.ALIQIBSUF, 0), COALESCE(I.ALIQIBSMUN, 0), I.CHAVECLASSTRIB,
        I.BASEISS, COALESCE(COF.PERCREDOPGOV,0), I.QTDE
        FROM ITENSPEDSAIDASERV I
        INNER JOIN PEDIDOSAIDA PS ON PS.CHAVE=I.CHAVEPEDIDO
        INNER JOIN PRODUTO P ON P.CHAVE  = I.CHAVEPRODUTO
        INNER JOIN CFOPOPERFISCAIS COF ON COF.CHAVE = I.CHAVECFOPOPERFISCAIS
        LEFT JOIN CLASSFISCAL NCM ON NCM.CHAVE = I.CHAVECLASSFISCAL
        LEFT JOIN TABELAALIQIMPIBPT IBPT ON IBPT.CHAVECLASSFISCAL = NCM.CHAVE AND IBPT.UF = :UFEMP AND IBPT.ATIVO=1
        LEFT JOIN CLASSFISCAL NCMPROD ON NCMPROD.CHAVE = P.CHAVECLASSFISCAL
        LEFT JOIN TABELAALIQIMPIBPT IBPTPROD ON IBPTPROD.CHAVECLASSFISCAL = NCMPROD.CHAVE AND IBPTPROD.UF = :UFEMP AND IBPTPROD.ATIVO=1
        LEFT JOIN CFOP CF ON I.CHAVECFOP = CF.CHAVE
        LEFT JOIN GRUPOFISCAL GP ON P.CHAVEGRUPOFISCAL = GP.CHAVE
        LEFT JOIN TRIBUTACAO T ON T.CHAVE = GP.CHAVETRIBUTACAO
        LEFT JOIN MACROES M ON M.CHAVE = PS.CHAVEMACROES
        LEFT JOIN PRODTIPOSERV PT ON PT.CHAVE=P.CHAVETIPOSERV
        WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDIDO
        INTO :CHAVEITENSPS, :VLRUNITCOMDESCSERV, :ITENSTOTALSERV, :ALIQISS,
        :ALIQNACIMPOSTOSERV, :ALIQIMPIMPOSTOSERV, :ALIQESTIMPOSTOSERV, :ALIQMUNICIMPOSTOSERV,
        :CLASSIFICACAOCFOP, :CST, :RETERISSTOTALNF, :CFOP, :OPERCONSFINAL, :VBASEIVASERV,
        :VVLRCBSSERV, :VVLRIBSUFSERV, :VVLRIBSMUNSERV, :VALIQCBS, :VALIQIBSUF, :VALIQIBSMUN, :VCHAVECLASSTRIB,
        :VBASEISS, :VPERCREDGOV, :VQTDESERV
        DO BEGIN
            VCOUNTITEMSERV = :VCOUNTITEMSERV-1;
            VLRAPROXTRIBFEDSERV=0;
            VLRAPROXTRIBESTSERV=0;
            CONSUMIDORFINAL = 'N';
            VLRAPROXTRIBMUNICSERV=0;
            AUX = 0;
            VLRDESCGLOBAL =0;
            AUX = :VLRUNITCOMDESCSERV * 100 / :TOTALSERVICO;
            AUX = :AUX * :DESCONTOSERVICO / 100;
            VLRUNITCOMDESCSERV = :VLRUNITCOMDESCSERV - :AUX;
            VLRDESCGLOBAL= (:ITENSTOTALSERV*100)/(:TOTALSERVICO);
            VLRDESCGLOBAL = CAST(:VLRDESCGLOBAL * :DESCONTOSERVICO/100  AS NUMERIC(7,2));
            IF ((PESSOA=1) OR ((PESSOA =0) AND (INSCRICAOEST = 'ISENTO')) OR (:OPERCONSFINAL='S')) THEN
                CONSUMIDORFINAL = 'S';
            IF (CONSUMIDORFINAL = 'S') THEN BEGIN
                IF ((:CLASSIFICACAOCFOP = 1) AND (:CFOP <> '7')) THEN BEGIN
                   IF (SUBSTRING(:CST FROM 1 FOR 1) IN ('','0','3','4','5')) THEN BEGIN
                       IF (:ALIQNACIMPOSTOSERV > 0) THEN
                           VLRAPROXTRIBFEDSERV = CAST(((:ITENSTOTALSERV-:VLRDESCGLOBAL) * :ALIQNACIMPOSTOSERV)/100  AS NUMERIC(18,2));
                   END ELSE BEGIN
                       IF (:ALIQIMPIMPOSTOSERV > 0) THEN
                           VLRAPROXTRIBFEDSERV = CAST(((:ITENSTOTALSERV-:VLRDESCGLOBAL) * :ALIQIMPIMPOSTOSERV)/100  AS NUMERIC(18,2));
                   END
                   VLRAPROXTRIBESTSERV = CAST(((:ITENSTOTALSERV-:VLRDESCGLOBAL) * :ALIQESTIMPOSTOSERV)/100  AS NUMERIC(18,2));
                   VLRAPROXTRIBMUNICSERV = CAST(((:ITENSTOTALSERV-:VLRDESCGLOBAL) * :ALIQMUNICIMPOSTOSERV)/100  AS NUMERIC(18,2));
                END
            END
            VBASEISS = CASE WHEN :ALIQISS = 0 THEN 0 ELSE CASE WHEN :ALTERARBASEISS = 'N' THEN CASE WHEN :RETERISSTOTALNF = 'S' THEN ((:TOTALPRODUTO + :VLRRATEIO  + :TOTALSERVICO + :SOMAIPI + :SOMAVLRSUBSTTRIB)-(:DESCONTO + :DESCONTOSERVICO)) ELSE CAST(:VLRUNITCOMDESCSERV*:VQTDESERV AS NUMERIC(18,2)) END ELSE (:VBASEISS - :VLRDESCGLOBAL) END END;
            VVALORISS  = CASE WHEN :ALTERARBASEISS = 'N' THEN CASE WHEN :RETERISSTOTALNF = 'S' THEN ((:TOTALPRODUTO + :VLRRATEIO  + :TOTALSERVICO + :SOMAIPI + :SOMAVLRSUBSTTRIB)-(:DESCONTO + :DESCONTOSERVICO))*:ALIQISS/100 ELSE CAST(CAST((:VLRUNITCOMDESCSERV*:VQTDESERV) AS NUMERIC(18,6))*:ALIQISS/100 AS NUMERIC(18,2)) END ELSE ((:VBASEISS - :VLRDESCGLOBAL)*:ALIQISS)/100 END;
            VBASEIVASERV = :ITENSTOTALSERV;
            VBASEIVASERV = VBASEIVASERV - (:VLRDESCGLOBAL + :VVALORISS);
            SOMARVLRAPROXIMPSERV = SOMARVLRAPROXIMPSERV + :VLRAPROXTRIBFEDSERV + VLRAPROXTRIBESTSERV + VLRAPROXTRIBMUNICSERV;
            IF (VCALCREFTRIB = 'S') THEN BEGIN
                SELECT SALIQUOTA, SBASEIVA, SVALOR, SVALORDIF FROM CALCTRIBCBSIBS('CBS', :VCHAVECLASSTRIB, :UFCLI, :EMPRESALOG, :VCHAVECIDADE, :VBASEIVASERV, :VALIQCBS, :VPERCREDGOV, 0, 0)
                INTO :VALIQCBS, :VBASEIVASERV, :VVLRCBSSERV, :VVLRCBSDIF;
        
                VVLRCBSPED = VVLRCBSPED + :VVLRCBSSERV;
                VVLRCBSDIFPED = VVLRCBSDIFPED + :VVLRCBSDIF;
        
                SELECT SALIQUOTA, SVALOR, SVALORDIF FROM CALCTRIBCBSIBS('IBSUF', :VCHAVECLASSTRIB, :UFCLI, :EMPRESALOG, :VCHAVECIDADE, :VBASEIVASERV, :VALIQIBSUF, :VPERCREDGOV, 0, 0)
                INTO :VALIQIBSUF, :VVLRIBSUFSERV, :VVLRIBSDIFUF;
        
                VVLRIBSUFPED = VVLRIBSUFPED + :VVLRIBSUFSERV;
                VVLRIBSDIFUFPED =  VVLRIBSDIFUFPED + :VVLRIBSDIFUF;
        
                SELECT SALIQUOTA, SVALOR, SVALORDIF FROM CALCTRIBCBSIBS('IBSMUN', :VCHAVECLASSTRIB, :UFCLI, :EMPRESALOG, :VCHAVECIDADE, :VBASEIVASERV, :VALIQIBSMUN, :VPERCREDGOV, 0, 0)
                INTO :VALIQIBSMUN, :VVLRIBSMUNSERV, :VVLRIBSDIFMUN;
        
                VVLRIBSMUNPED = VVLRIBSMUNPED + :VVLRIBSMUNSERV;
                VVLRIBSDIFMUNPED =  VVLRIBSDIFMUNPED + :VVLRIBSDIFMUN;
        
                VBASEIVAPED = VBASEIVAPED + :VBASEIVASERV;
            END ELSE BEGIN
                :VBASEIVASERV = 0;
                :VALIQCBS = 0;
                :VVLRCBSSERV = 0;
                :VVLRCBSDIF = 0;
                :VALIQIBSUF = 0;
                :VVLRIBSUFSERV = 0;
                :VVLRIBSDIFUF = 0;
                :VALIQIBSMUN = 0;
                :VVLRIBSMUNSERV = 0;
                :VVLRIBSDIFMUN = 0;
            END
            UPDATE ITENSPEDSAIDASERV SET
            VLRUNITCOMDESCSERVICO = :VLRUNITCOMDESCSERV,
            ISS= :ALIQISS,
            BASEISS= :VBASEISS,
            VLRISS = :VVALORISS,
            BASEIVA = :VBASEIVASERV,
            ALIQCBS = :VALIQCBS,
            ALIQIBSUF = :VALIQIBSUF,
            ALIQIBSMUN = :VALIQIBSMUN,
            VLRCBS = :VVLRCBSSERV,
            VLRIBSUF = :VVLRIBSUFSERV,
            VLRIBSMUN = :VVLRIBSMUNSERV,
            VLRCBSDIF = :VVLRCBSDIF,
            VLRIBSDIFUF = :VVLRIBSDIFUF,
            VLRIBSDIFMUN = :VVLRIBSDIFMUN,
            VLRDESCGLOBAL = :VLRDESCGLOBAL,
            VLRTOTTRIB = :VLRAPROXTRIBFEDSERV,
            VLRTOTTRIBEST = :VLRAPROXTRIBESTSERV,
            VLRTOTTRIBMUNIC = :VLRAPROXTRIBMUNICSERV
            WHERE CHAVE=:CHAVEITENSPS;
            VDESCACUMULADOSERV = :VDESCACUMULADOSERV + :VLRDESCGLOBAL;
            IF ((:VCOUNTITEMSERV = 0) AND (:ALTERARBASEISS = 'S') AND ((:VDESCACUMULADOSERV-:DESCONTOSERVICO) <> 0)) THEN BEGIN
                UPDATE ITENSPEDSAIDASERV SET
                BASEISS= BASEISS - (:VDESCACUMULADOSERV-:DESCONTOSERVICO),
                VLRISS = VLRISS - (:VDESCACUMULADOSERV-:DESCONTOSERVICO)
                WHERE CHAVE=:CHAVEITENSPS;
            END
        END
    END
    SELECT COALESCE(SUM(I.BASEISS),0), COALESCE(SUM(I.VLRISS),0) FROM ITENSPEDSAIDASERV I
    WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDIDO
    INTO :SOMABASEISS, :SOMAVLRISS;
    IF ((ALTERARBASEISS = 'N') AND ((:SOMABASEISS <> (:TOTALSERVICO-:DESCONTOSERVICO)) AND (:RETERISSTOTALNF <> 'S')) AND (:ALIQISS>0)) THEN BEGIN
        DIFERENCAISS = (:TOTALSERVICO-:DESCONTOSERVICO) - :SOMABASEISS;
        UPDATE ITENSPEDSAIDASERV SET
        BASEISS = BASEISS + :DIFERENCAISS
        WHERE CHAVE = (SELECT MAX(CHAVE) FROM ITENSPEDSAIDASERV WHERE ATIVO=1 AND CHAVEPEDIDO=:CHAVEPEDIDO);
        SOMABASEISS = :SOMABASEISS+(:DIFERENCAISS);
    END
    IF (BASEICMSSIMPLESNACIONAL > 0) THEN
        VLRICMSSIMPLESNACIONAL = (:BASEICMSSIMPLESNACIONAL/100)*:ALIQICMSSIMPLESNACIONAL;
    ELSE
        ALIQICMSSIMPLESNACIONAL= 0;
     IF ((:REGIMETRIB = 0) AND (TOTBASEICMSDEVOL > 0)) THEN
        OBS = :OBS||' '||'BASE ICMS: '||CAST(:TOTBASEICMSDEVOL AS NUMERIC(18,2))||' VALOR ICMS:'||CAST(:TOTVLRICMSDEVOL AS NUMERIC(18,2))||' ';
    FOR SELECT I.CHAVE, I.ALIQPIS, I.ALIQCOFINS, I.CSTPISCOFINS, I.VLRTOTAL-COALESCE(I.VLRDESCGLOBAL,0),
    TC.CODIGO, I.QTDE, COALESCE(UN.CONVUNMEDIDA,0)  FROM ITENSPEDSAIDASERV I
    INNER JOIN UNIDADE UN ON UN.CHAVE = I.CHAVEUNIDADE
    INNER JOIN TABELAPISCOFINS TC ON TC.CHAVE = I.CHAVETABPISCOFINS
    WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVEPEDIDO
    INTO :CHAVEITEMSERV, :ALIQPISSERV, :ALIQCOFINSSERV, :CSTPISCOFINS, :VLRTOTSERV,
    :CODTABPISCOFINS, :QTDESERV, :CONVUNMEDSERV
    DO BEGIN
        SELECT BASE, VALORPIS, VALORCOFINS, ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB FROM CALCULARPISCOFINS(:CSTPISCOFINS,:VLRTOTSERV,:CODTABPISCOFINS, :QTDESERV, :CONVUNMEDSERV)
        INTO :BASEPISCOFINSSERV, :VLRPISSERV, :VLRCOFINSSERV, :ALIQPISSERV, :ALIQCOFINSSERV, :VLRPISTRIBSERV, :VLRCOFINSTRIBSERV;
        UPDATE ITENSPEDSAIDASERV SET
        ISS=:ALIQISS,
        ALIQPIS=:ALIQPISSERV,
        ALIQCOFINS=:ALIQCOFINSSERV,
        VLRPIS=:VLRPISSERV,
        VLRCOFINS=:VLRCOFINSSERV,
        BASEPISCOFINS = :BASEPISCOFINSSERV,
        VLRPISTRIB=:VLRPISTRIBSERV, VLRCOFINSTRIB=:VLRCOFINSTRIBSERV
        WHERE ATIVO=1 AND CHAVE =:CHAVEITEMSERV;
        SOMARPISSERV = :SOMARPISSERV + :VLRPISSERV;
        SOMARCOFINSSERV = :SOMARCOFINSSERV + :VLRCOFINSSERV;
        SOMARBCPISCOFINSSERV = :SOMARBCPISCOFINSSERV + BASEPISCOFINSSERV;
    END
    IF (:SOMARSTIPIDESPACESS = 'S') THEN BEGIN
        IF (:SOMAIPI > 0) THEN
            OBS = SUBSTRING('BASE IPI: ' || FORMAT_VALOR(',#0.00', :SOMARBCIPI, '') || ' VALOR IPI: ' || FORMAT_VALOR(',#0.00', :SOMAIPI, '') || ASCII_CHAR(13) || ASCII_CHAR(10) || :OBS FROM 1 FOR 5000);
        IF (:SOMAVLRSUBSTTRIB > 0) THEN
            OBS = SUBSTRING('BASE ICMS ST: ' || FORMAT_VALOR(',#0.00', :SOMABASESUBSTTRIB, '') || ' VALOR ICMS ST: ' || FORMAT_VALOR(',#0.00', :SOMAVLRSUBSTTRIB, '') || ASCII_CHAR(13) || ASCII_CHAR(10) || :OBS FROM 1 FOR 5000);
        DESPACESS = :SOMAVLRSUBSTTRIB + :SOMAIPI;
        SOMARBCIPI = 0;
        SOMAIPI = 0;
        SOMABASESUBSTTRIB = 0;
        SOMAVLRSUBSTTRIB = 0;
    END ELSE
        DESPACESS = 0;
    UPDATE PEDIDOSAIDA SET
        TOTALPEDIDO = (:TOTALPRODUTO + :VLRRATEIO  + :TOTALSERVICO + :SOMAIPI + :SOMARVLRIPIDEVOLV + :SOMAVLRSUBSTTRIB + :VLRACRESGLOBALACUM + :DESPACESS + :TOTALICMSFCPST)-(:DESCONTO + :DESCONTOSERVICO + :VSOMAVLRICMSDESON),
        TOTALPRODUTO= :TOTALPRODUTO - :DESCONTO + :VLRACRESGLOBALACUM,
        TOTALSERVICO= :TOTALSERVICO - :DESCONTOSERVICO,
        TOTALIPI = :SOMAIPI,
        BCIPI = :SOMARBCIPI,
        BASECALCULOICMS  = :SOMABASEICMS,
        VLRICMS = :SOMAVLRICMS,
        VLRICMSDESON = :VTOTALICMSDESON,
        BASEIVA = :VBASEIVAPED,
        VLRCBS = :VVLRCBSPED,
        VLRCBSDIF = :VVLRCBSDIFPED,
        VLRIBSUF = :VVLRIBSUFPED,
        VLRIBSDIFUF = :VVLRIBSDIFUFPED,
        VLRIBSMUN = :VVLRIBSMUNPED,
        VLRIBSDIFMUN = :VVLRIBSDIFMUNPED,
        VLRCREDPRESCBS = :VVLRCREDPRESCBSPED,
        VLRCREDPRESIBS = :VVLRCREDPRESIBSPED,
        BASEICMSSIMPLESNACIONAL= :BASEICMSSIMPLESNACIONAL,
        VLRICMSSIMPLESNACIONAL = :VLRICMSSIMPLESNACIONAL,
        ALIQICMSSIMPLESNACIONAL= :ALIQICMSSIMPLESNACIONAL,
        BASECALCICMSSUBST = :SOMABASESUBSTTRIB,
        VLRICMSSUBST = :SOMAVLRSUBSTTRIB,
        BASECALCICMSSUBSTDESTAC = :SOMABASESUBSTTRIBDEST,
        VLRICMSSUBSTDESTAC = :SOMAVLRSUBSTTRIBDEST,
        VLRPIS =:VALORTOTPIS , VLRCOFINS=:VALORTOTCOFINS,
        BCPISCOFINS = :BASETOTALPISCOFINS,
        DESPACESSORIA = COALESCE(DESPACESSORIA,0) + :DESPACESS,
        BASEISS=:SOMABASEISS,
        TOTALISS=:SOMAVLRISS,
        OBS = :OBS,
        VLRPISSERV = :SOMARPISSERV,
        VLRCOFINSSERV = :SOMARCOFINSSERV,
        BCPISCOFINSSERV = :SOMARBCPISCOFINSSERV,
        VLRTOTTRIB = :SOMARVLRAPROXIMPPROD + :SOMARVLRAPROXIMPSERV,
        DESCPORCPROD = :DESCPORCPROD,
        VLRICMSPARTDEST = :TOTVLRICMSPARTDEST,
        VLRICMSPARTREMET = :TOTVLRICMSPARTREMET,
        VLRICMSFCP = :TOTVLRICMSFCP,
        VLRICMSFCPST = :TOTALICMSFCPST,
        VLRICMSFCPSTDEST = :TOTALICMSFCPSTDEST,
        BASEICMSSTEFET = :TOTBASEICMSSTEFET,
        VLRICMSSTEFET = :TOTVLRICMSSTEFET
        WHERE (ATIVO=1) AND (CHAVE=:CHAVEPEDIDO);
    UPDATE ITENSPEDSAIDA SET NL=:NLATUAL
    WHERE CHAVEPEDIDO=:CHAVEPEDIDO;
    UPDATE ITENSPEDSAIDASERV SET NL=:NLATUAL
    WHERE CHAVEPEDIDO=:CHAVEPEDIDO;
    IF (TIPOEMISSAONFSE = 0) THEN BEGIN
        IF (((:REGIMETRIB=0) AND (:ALIQISSSIMPLESNACIONAL=0) AND (:OPERACAOISS = 0)) OR ((:OPERACAOISS = 2) AND (:ORIGEMALIQISS = 2) AND (:VPORCISS=0))) THEN BEGIN
           UPDATE ITENSPEDSAIDASERV SET
           BASEISS=0,
           ISS=0,
           VLRISS=0
           WHERE CHAVEPEDIDO=:CHAVEPEDIDO;
    
           UPDATE PEDIDOSAIDA SET
           BASEISS=0,
           TOTALISS=0,
           ALIQUOTAISS=0
           WHERE CHAVE=:CHAVEPEDIDO;
        END
    END ELSE BEGIN
       IF (:REGIMETRIB=0) THEN BEGIN
          IF (:OPERACAOISS=0) THEN BEGIN
          UPDATE ITENSPEDSAIDASERV SET
          VLRISS=0,
          ISS = 0,
          BASEISS=0
          WHERE CHAVEPEDIDO=:CHAVEPEDIDO;
          UPDATE PEDIDOSAIDA SET
          TOTALISS=0,
          ALIQUOTAISS=0,
          BASEISS = 0
          WHERE CHAVE=:CHAVEPEDIDO;
       END
         IF ((:OPERACAOISS IN(1,2)) AND (:ORIGEMALIQISS=1)) THEN BEGIN
            UPDATE ITENSPEDSAIDASERV SET
            VLRISS=0,
            BASEISS=0
            WHERE CHAVEPEDIDO=:CHAVEPEDIDO;
            UPDATE PEDIDOSAIDA SET
            TOTALISS=0,
            BASEISS = 0
            WHERE CHAVE=:CHAVEPEDIDO;
    END
       END
    END
    /*
        CHAMADAS :
        FRMPEDIDOSAIDA - USADA PARA REFAZER VALORES DO PEDIDO DE SAIDA
    */
END^


ALTER PROCEDURE RECALCULARCUSTOMEDIO (
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER,
    CHAVENF INTEGER)
AS
DECLARE VARIABLE SALDOEST      NUMERIC(14,3);
DECLARE VARIABLE CUSTOMEDIO    NUMERIC(18,6);
DECLARE VARIABLE VLRTOTAL      NUMERIC(18,6);
DECLARE VARIABLE SOMACUSTO     NUMERIC(18,6);
DECLARE VARIABLE CHAVEPRODUTO  INTEGER;
DECLARE VARIABLE VLRLANCADO    NUMERIC(18,6);
DECLARE VARIABLE PRECOCUSTOANT NUMERIC(18,6);
BEGIN
    FOR SELECT DISTINCT CHAVEPRODUTO FROM ITENSNFENTRADAPROD
    WHERE (ATIVO=1) AND (CHAVENFENTRADA=:CHAVENF)
    INTO :CHAVEPRODUTO
    DO BEGIN
        SELECT FIRST 1 COALESCE(I.VLRUNITCOMDESC,0) FROM NFENTRADA NF
        INNER JOIN ITENSNFENTRADAPROD I ON (NF.CHAVE=I.CHAVENFENTRADA) AND (I.ATIVO=1)  AND (I.CHAVEPRODUTO=:CHAVEPRODUTO)
        WHERE (NF.ATIVO=1) AND (NF.CHAVEEMPRESA=:CHAVEEMPESTOQUE) AND (NF.STATUS=1)
        ORDER by NF.ENTRADA DESC
        INTO :VLRLANCADO;
        IF (:VLRLANCADO IS NULL) THEN
            VLRLANCADO = 0;
        IF (:VLRLANCADO = 0) then begin
            SELECT PRECOCUSTO FROM PRODUTOCUSTO
            WHERE (ATIVO=1) AND (CHAVEEMPRESA=:CHAVEEMPCUSTO) AND (CHAVEPRODUTO=:CHAVEPRODUTO)
            INTO :VLRLANCADO;
        end
        SELECT SALDO FROM PRODUTOESTOQUE
        WHERE (ATIVO=1) AND (CHAVEEMPRESA=:CHAVEEMPESTOQUE) AND (CHAVEPRODUTO=:CHAVEPRODUTO)
        INTO :SALDOEST;
        IF (SALDOEST > 0) THEN BEGIN
            SOMACUSTO = 0;
            FOR SELECT CAST(CAST(PRECOCUSTO AS DOUBLE PRECISION) * CAST(SALDO AS DOUBLE PRECISION) AS NUMERIC(18,6))
            FROM ESTOQUE
            WHERE (ATIVO=1) AND (CHAVEEMPRESA=:CHAVEEMPESTOQUE) AND (CHAVEPRODUTO=:CHAVEPRODUTO) AND (SALDO <> 0)
            INTO :VLRTOTAL
            DO BEGIN
                SOMACUSTO = SOMACUSTO + VLRTOTAL;
            END
            CUSTOMEDIO = SOMACUSTO/:SALDOEST;
            IF (CUSTOMEDIO < 0.01) THEN BEGIN
                SELECT PRECOCUSTOANT
                FROM PRODUTOCUSTO
                WHERE (ATIVO=1) AND (CHAVEEMPRESA=:CHAVEEMPCUSTO) AND (CHAVEPRODUTO=:CHAVEPRODUTO)
                INTO :PRECOCUSTOANT;
                    if (PRECOCUSTOANT < 0.01) then
                        CUSTOMEDIO = VLRLANCADO;
                    else
                        CUSTOMEDIO = PRECOCUSTOANT;
            END
            UPDATE PRODUTOCUSTO SET
            PRECOMEDIO = :CUSTOMEDIO,
            PRECOCUSTONFLANC = :VLRLANCADO
            WHERE (ATIVO=1) AND (CHAVEEMPRESA=:CHAVEEMPCUSTO) AND (CHAVEPRODUTO=:CHAVEPRODUTO);
        END ELSE BEGIN
            UPDATE PRODUTOCUSTO SET
            PRECOMEDIO = PRECOCUSTO,
            PRECOCUSTONFLANC = :VLRLANCADO
            WHERE (ATIVO=1) AND (CHAVEEMPRESA=:CHAVEEMPCUSTO) AND (CHAVEPRODUTO=:CHAVEPRODUTO);
        END
    END
END^


ALTER PROCEDURE RECALCULARTABDESCCOND (
    CHAVETABELA INTEGER,
    CHAVETABDESC INTEGER,
    CHAVEEMPPRODUTOVENDA INTEGER,
    VLRVENDAORIGEM VARCHAR(5),
    VPERCENT01 NUMERIC(18,6),
    VPERCENT02 NUMERIC(18,6),
    VPERCENT03 NUMERIC(18,6),
    VPERCENT04 NUMERIC(18,6),
    CASADECIMALVLRUNIT NUMERIC(18,6),
    APLICARPROD CHAR(1),
    APLICARSERV CHAR(1))
AS
declare variable CHAVEPRODUTO integer;
declare variable ALTERARPRECOMINIMO char(1);
declare variable CHAVEITEM integer;
declare variable CHAVETABELADESCONTO integer;
declare variable VSOMABASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VSOMAVLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VSOMABASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VSOMABASEICMS numeric(18,6);
declare variable VSOMARBCIPI numeric(18,6);
declare variable VSOMATOTALIPI numeric(18,6);
declare variable VVLRIPI numeric(18,6);
declare variable VBASECALCIPI numeric(18,6);
declare variable VMVACALC numeric(18,6);
declare variable VVLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VBASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VVLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VBASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VVLRICMSITEM numeric(18,6);
declare variable VBASEICMSITEM numeric(18,6);
declare variable VCHAVEUNIDADE integer;
declare variable VVLRIPITRIB numeric(18,6);
declare variable VPERCREDST numeric(18,6);
declare variable VMVA numeric(18,6);
declare variable VREGIMETRIB integer;
declare variable VIPI numeric(7,2);
declare variable VUFEMP varchar(10);
declare variable VREDUCAOMVA numeric(18,6);
declare variable VUFCLI varchar(10);
declare variable VICMSITEM numeric(18,6);
declare variable VPERCRED numeric(18,6);
declare variable VICMSTRIB numeric(18,6);
declare variable VCST varchar(10);
declare variable VPERC01 numeric(18,6);
declare variable VPERC02 numeric(18,6);
declare variable VPERC03 numeric(18,6);
declare variable VPERC04 numeric(15,2);
declare variable VLRTOTALITEM numeric(18,6);
declare variable TOTALSERVICOS numeric(18,6);
declare variable TOTALPRODUTOS numeric(18,6);
declare variable VLRVENDAITEM numeric(18,6);
declare variable VLRVENDAPROD numeric(18,6);
declare variable PRECOVENDAORIGINAL numeric(18,6);
declare variable PRECOVENDAMINIMO numeric(18,6);
declare variable QTDE numeric(15,3);
declare variable VSOMAVLRICMS numeric(18,6);
declare variable VSOMAVLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VTIPO integer;
BEGIN
    VSOMATOTALIPI = 0;
    VSOMARBCIPI = 0;
    VSOMABASEICMS = 0;
    VSOMAVLRICMS = 0;
    VSOMABASEICMSSUBSTTRIBRETIDO = 0;
    VSOMAVLRICMSSUBSTTRIBRETIDO  = 0;
    VSOMABASEICMSSUBSTTRIBDESTAC = 0;
    VSOMAVLRICMSSUBSTTRIBDESTAC = 0;
    SELECT CID.UF, C.REDUCAOMVA, CIDE.UF FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN CONDICIONAL COT ON C.CHAVE=COT.CHAVECLIFOR
    INNER JOIN EMPRESA E ON E.CHAVE = CID.CHAVEEMPRESA
    INNER JOIN CIDADE CIDE ON E.CHAVECIDADE=CIDE.CHAVE
    WHERE COT.CHAVE=:CHAVETABELA
    INTO :VUFCLI, :VREDUCAOMVA, :VUFEMP;

    UPDATE CONDICIONAL SET TOTALPRODUTO = 0, TOTALSERVICO = 0, TOTALCONDICIONAL = 0 WHERE CHAVE=:CHAVETABELA;
    IF ((:CHAVETABDESC = 0) OR (:APLICARPROD='S')) THEN BEGIN
        FOR SELECT ICP.CHAVE, ICP.CHAVEPRODUTO, ICP.VLRUNITTABELA,
        PV.PRECOVENDA, PV.PRECOVENDAMINIMO, ICP.QTDE, T.CODIGO, T.ALIQUOTADE, T.PERCRED, ICP.ICMS,
        ICP.IPI, C.REGIMETRIBUTARIO, ICP.MVA, T.PERCREDST, ICP.VLRIPITRIB, ICP.CHAVEUNIDADE
        FROM ITENSCONDICIONALPROD ICP
        INNER JOIN CONDICIONAL COND ON COND.CHAVE = ICP.CHAVECONDICIONAL
        INNER JOIN TRIBUTACAO T ON ICP.CHAVETRIBUTACAO=T.CHAVE
        INNER JOIN PRODUTO P ON ICP.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (ICP.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=ICP.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        LEFT JOIN CLIFOR C ON C.CHAVE = COND.CHAVECLIFOR
        WHERE ICP.ATIVO=1 AND ICP.CHAVECONDICIONAL=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :VLRVENDAITEM,
        :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE, :VCST, :VICMSTRIB, :VPERCRED, :VICMSITEM,
        :VIPI, :VREGIMETRIB, :VMVA, :VPERCREDST, :VVLRIPITRIB, :VCHAVEUNIDADE
        DO BEGIN
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- Aplica os descontos/acrescimos da tabela principal
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            -- Se for desconto
            SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
            INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            -- Agora verifica se o produto tem desconto/acrescimo por grupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por grupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Se for desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- Verifica se o produto tem desconto/acrescimo por subgrupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por subgrupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Se for desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- VERIFICAR CASAS DECIMAIS VLRUNIT Q O SISTEMA ESTA TRABALHANDO
            PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
            WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
            WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END;
            VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            UPDATE ITENSCONDICIONALPROD SET VLRUNIT = :PRECOVENDAORIGINAL, VLRVENDAMINIMO = :PRECOVENDAMINIMO,
            DESCVLR = 0, DESCPORC = 0, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL = :VLRTOTALITEM
            WHERE CHAVE=:CHAVEITEM;

            SELECT BASEICMSITEM, VLRICMSITEM, BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, MVAAJUSTADO
            FROM CALCULARICMS(:VCST, :VLRTOTALITEM, :VICMSTRIB, :VPERCRED, :PRECOVENDAORIGINAL, :QTDE, :VICMSITEM, :VUFCLI, :VUFEMP, :VIPI, :VREDUCAOMVA, :VREGIMETRIB, :VMVA, :VPERCREDST, :VVLRIPITRIB, 0, :VCHAVEUNIDADE)
            INTO :VBASEICMSITEM, :VVLRICMSITEM, :VBASEICMSSUBSTTRIBRETIDO, :VVLRICMSSUBSTTRIBRETIDO, :VBASEICMSSUBSTTRIBDESTAC, :VVLRICMSSUBSTTRIBDESTAC, :VMVACALC;
            VBASECALCIPI = :VLRTOTALITEM;
            VVLRIPI = (:VBASECALCIPI * :VIPI / 100);
            if (VVLRIPI = 0) then
                VBASECALCIPI = 0;
            VSOMATOTALIPI = :VSOMATOTALIPI + :VVLRIPI;
            VSOMARBCIPI = VSOMARBCIPI + VBASECALCIPI;
            -- ACUMULA TOTAIS
            VSOMABASEICMS = :VSOMABASEICMS + :VBASEICMSITEM;
            VSOMAVLRICMS  = :VSOMAVLRICMS  + :VVLRICMSITEM;
            VSOMABASEICMSSUBSTTRIBRETIDO = :VSOMABASEICMSSUBSTTRIBRETIDO + :VBASEICMSSUBSTTRIBRETIDO;
            VSOMAVLRICMSSUBSTTRIBRETIDO  = :VSOMAVLRICMSSUBSTTRIBRETIDO + :VVLRICMSSUBSTTRIBRETIDO;
            VSOMABASEICMSSUBSTTRIBDESTAC = :VSOMABASEICMSSUBSTTRIBDESTAC + :VBASEICMSSUBSTTRIBDESTAC;
            VSOMAVLRICMSSUBSTTRIBDESTAC  = :VSOMAVLRICMSSUBSTTRIBDESTAC + :VVLRICMSSUBSTTRIBDESTAC;

            UPDATE ITENSCONDICIONALPROD SET BASECALCIPI = :VBASECALCIPI, VLRIPI = :VVLRIPI, BASEICMS = :VBASEICMSITEM, VLRICMS  = :VVLRICMSITEM,
            BASEICMSSUBSTTRIB = :VBASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIB  = :VVLRICMSSUBSTTRIBRETIDO, MVACALC = :VMVACALC,
            BASEICMSSUBSTTRIBDESTAC = :VBASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC  = :VVLRICMSSUBSTTRIBDESTAC, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL = :VLRTOTALITEM
            WHERE CHAVE=:CHAVEITEM;

        END
    END
    IF ((:CHAVETABDESC = 0) OR (:APLICARSERV='S')) THEN BEGIN
        FOR SELECT ICS.CHAVE, ICS.CHAVEPRODUTO, ICS.VLRUNITTABELA, PV.PRECOVENDA, PV.PRECOVENDAMINIMO, ICS.QTDE FROM ITENSCONDICIONALSERV ICS
        INNER JOIN PRODUTO P ON ICS.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (ICS.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=ICS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        WHERE ICS.ATIVO=1 AND ICS.CHAVECONDICIONAL=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :VLRVENDAITEM, :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE
        DO BEGIN
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- Aplica os descontos/acrescimos da tabela principal
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
    
            SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
            INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            -- Agora verifica se o produto tem desconto/acrescimo por grupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por grupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Se for desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- Verifica se o produto tem desconto/acrescimo por subgrupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por subgrupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Se for desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- VERIFICAR CASAS DECIMAIS VLRUNIT Q O SISTEMA ESTA TRABALHANDO
            PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
            WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
            WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END;
            VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            UPDATE ITENSCONDICIONALSERV SET VLRUNIT = :PRECOVENDAORIGINAL, DESCVLR = 0, DESCPORC = 0, VLRSUBTOTAL = :VLRTOTALITEM, TOTALSERVICO = :VLRTOTALITEM
            WHERE CHAVE=:CHAVEITEM;
        END
    END
    SELECT SUM(CAST(VLRTOTAL AS NUMERIC(18,2))) FROM ITENSCONDICIONALPROD WHERE ATIVO=1 AND CHAVECONDICIONAL=:CHAVETABELA
    INTO :TOTALPRODUTOS;
    SELECT SUM(CAST(TOTALSERVICO AS NUMERIC(18,2))) FROM ITENSCONDICIONALSERV WHERE ATIVO=1 AND CHAVECONDICIONAL=:CHAVETABELA
    INTO :TOTALSERVICOS;

    UPDATE CONDICIONAL SET
    TOTALPRODUTO = :TOTALPRODUTOS,
    TOTALSERVICO=:TOTALSERVICOS,
    BASECALCULOICMS   = CAST(:VSOMABASEICMS AS NUMERIC(18,2)),
    VLRICMS           = CAST(:VSOMAVLRICMS AS NUMERIC(18,2)),
    BASECALCICMSSUBST = CAST(:VSOMABASEICMSSUBSTTRIBRETIDO AS NUMERIC(18,2)),
    VLRICMSSUBST      = CAST(:VSOMAVLRICMSSUBSTTRIBRETIDO AS NUMERIC(18,2)),
    BASECALCICMSSUBSTDESTAC = CAST(:VSOMABASEICMSSUBSTTRIBDESTAC AS NUMERIC(18,2)),
    VLRICMSSUBSTDESTAC      = CAST(:VSOMAVLRICMSSUBSTTRIBDESTAC AS NUMERIC(18,2)),
    TOTALIPI          = CAST(:VSOMATOTALIPI AS NUMERIC(18,2)),
    BCIPI             = CAST(:VSOMARBCIPI AS NUMERIC(18,2)),
    TOTALCONDICIONAL  = :TOTALPRODUTOS + :TOTALSERVICOS + :VSOMABASEICMSSUBSTTRIBRETIDO + :VSOMATOTALIPI
    WHERE CHAVE=:CHAVETABELA;
END^


ALTER PROCEDURE RECALCULARTABDESCCOT (
    CHAVETABELA INTEGER,
    CHAVETABDESC INTEGER,
    CHAVEEMPPRODUTOVENDA INTEGER,
    VLRVENDAORIGEM VARCHAR(5),
    VPERCENT01 NUMERIC(18,6),
    VPERCENT02 NUMERIC(18,6),
    VPERCENT03 NUMERIC(18,6),
    VPERCENT04 NUMERIC(18,6),
    REGIMETRIB SMALLINT,
    CASADECIMALVLRUNIT NUMERIC(18,6),
    UFEMP CHAR(2),
    APLICARPROD CHAR(1),
    APLICARSERV CHAR(1),
    PERCREDST NUMERIC(18,6),
    VLRIPITRIB NUMERIC(18,6),
    VLRPAUTA NUMERIC(18,6),
    CHAVEUNIDADE INTEGER)
AS
declare variable CHAVEPRODUTO integer;
declare variable CODTABPISCOFINS varchar(10);
declare variable SOMARVLRCOFINS numeric(18,6);
declare variable SOMARVLRPIS numeric(18,6);
declare variable SOMARBCPISCOFINS numeric(18,6);
declare variable VLRPIS numeric(18,6);
declare variable VLRCOFINS numeric(18,6);
declare variable BASEPISCOFINS numeric(18,6);
declare variable VLRCOFINSTRIB numeric(18,6);
declare variable VLRPISTRIB numeric(18,6);
declare variable ALIQCOFINS numeric(18,6);
declare variable ALIQPIS numeric(18,6);
declare variable CONVUNMEDIDA numeric(18,6);
declare variable CSTPIS varchar(10);
declare variable ALTERARPRECOMINIMO char(1);
declare variable SOMARBCIPI numeric(18,6);
declare variable CHAVEITEM integer;
declare variable CHAVETABELADESCONTO integer;
declare variable VPERC01 numeric(18,6);
declare variable VPERC02 numeric(18,6);
declare variable VPERC03 numeric(18,6);
declare variable VPERC04 numeric(15,2);
declare variable CST varchar(6);
declare variable ICMSTRIB numeric(7,2);
declare variable ICMSITEM numeric(7,2);
declare variable SOMABASEICMS numeric(18,6);
declare variable SOMAVLRICMS numeric(18,6);
declare variable VLRICMSITEM numeric(18,6);
declare variable VLRTOTALITEM numeric(18,6);
declare variable BASEICMSITEM numeric(18,6);
declare variable PERCRED numeric(15,6);
declare variable TOTALSERVICOS numeric(18,6);
declare variable TOTALPRODUTOS numeric(18,6);
declare variable VLRVENDAITEM numeric(18,6);
declare variable VLRVENDAPROD numeric(18,6);
declare variable PRECOVENDAORIGINAL numeric(18,6);
declare variable PRECOVENDAMINIMO numeric(18,6);
declare variable QTDE numeric(15,3);
declare variable VTIPO integer;
declare variable BASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable BASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable UFCLI char(2);
declare variable IPI numeric(7,2);
declare variable VLRIPI numeric(18,6);
declare variable SOMATOTALIPI numeric(18,6);
declare variable BASECALCIPI numeric(18,6);
declare variable REDUCAOMVA numeric(7,2);
declare variable MVA numeric(7,2);
declare variable MVACALC numeric(7,2);
BEGIN
    SELECT CID.UF, C.REDUCAOMVA FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN COTACAO COT ON C.CHAVE=COT.CHAVECLIFOR
    WHERE COT.CHAVE=:CHAVETABELA
    INTO :UFCLI, :REDUCAOMVA;

    UPDATE COTACAO SET BASECALCULOICMS = 0, VLRICMS  = 0, TOTALIPI = 0, TOTALPRODUTO = 0, TOTALSERVICO=0, TOTALCOTACAO = 0 WHERE CHAVE=:CHAVETABELA;
    IF ((:CHAVETABDESC = 0) OR (:APLICARPROD='S')) THEN BEGIN
        FOR SELECT ICP.CHAVE, ICP.CHAVEPRODUTO, ICP.CST, T.PERCRED,
        T.ALIQUOTADE, ICP.ICMS, ICP.VLRUNITTABELA,
        PV.PRECOVENDA, PV.PRECOVENDAMINIMO, ICP.QTDE, ICP.IPI, ICP.BASECALCIPI, ICP.MVA,
        ICP.CSTPIS, TC.CODIGO, COALESCE(UN.CONVUNMEDIDA,0)
        FROM ITENSCOTACAOPROD ICP
        INNER JOIN TRIBUTACAO T ON ICP.CHAVETRIBUTACAO=T.CHAVE
        INNER JOIN PRODUTO P ON ICP.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (ICP.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=ICP.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = ICP.CHAVETABPISCOFINS
        INNER JOIN UNIDADE UN ON UN.CHAVE = ICP.CHAVEUNIDADE
        WHERE ICP.ATIVO=1 AND ICP.CHAVECOTACAO=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :CST, :PERCRED, :ICMSTRIB, :ICMSITEM, :VLRVENDAITEM,
        :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE, :IPI, :BASECALCIPI, :MVA, :CSTPIS, :CODTABPISCOFINS, :CONVUNMEDIDA
        DO BEGIN
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- APLICA OS DESCONTOS/ACRESCIMOS DA TABELA PRINCIPAL
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            -- SE FOR DESCONTO
            SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
            INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            -- VERIFICA SE O PRODUTO TEM DESC/ACRESC POR GRUPO
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- SE TEM DESCONTO POR GRUPO APLICA
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- SE FOR DESCONTO
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- VERIFICA SE O PRODUTO TEM DESCONTO/ACRESCIMO POR SUBGRUPO
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- SE TEM DESCONTO POR SUBGRUPO APLICA
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- SE FOR DESCONTO
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- VERIFICAR CASAS DECIMAIS VLRUNIT Q O SISTEMA ESTA TRABALHANDO
            PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
            WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
            WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END;
            VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            -- CALCULO DO ICMS
            SELECT BASEICMSITEM, VLRICMSITEM, BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC, MVAAJUSTADO
            FROM CALCULARICMS(:CST, :VLRTOTALITEM, :ICMSTRIB, :PERCRED, :PRECOVENDAORIGINAL, :QTDE, :ICMSITEM, :UFCLI, :UFEMP, :IPI, :REDUCAOMVA, :REGIMETRIB, :MVA, :PERCREDST, :VLRIPITRIB, :VLRPAUTA, :CHAVEUNIDADE)
            INTO :BASEICMSITEM, :VLRICMSITEM, :BASEICMSSUBSTTRIBRETIDO, :VLRICMSSUBSTTRIBRETIDO, :BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC, :MVACALC;
            BASECALCIPI = :VLRTOTALITEM;
            VLRIPI = (:BASECALCIPI * :IPI / 100);
            SOMATOTALIPI = :SOMATOTALIPI + :VLRIPI;
            SOMARBCIPI = SOMARBCIPI + BASECALCIPI;
            -- ACUMULA TOTAIS
            SOMABASEICMS = :SOMABASEICMS + :BASEICMSITEM;
            SOMAVLRICMS  = :SOMAVLRICMS  + :VLRICMSITEM;
            SOMABASEICMSSUBSTTRIBRETIDO = :SOMABASEICMSSUBSTTRIBRETIDO + :BASEICMSSUBSTTRIBRETIDO;
            SOMAVLRICMSSUBSTTRIBRETIDO  = :SOMAVLRICMSSUBSTTRIBRETIDO + :VLRICMSSUBSTTRIBRETIDO;
            SOMABASEICMSSUBSTTRIBDESTAC = :SOMABASEICMSSUBSTTRIBDESTAC + :BASEICMSSUBSTTRIBDESTAC;
            SOMAVLRICMSSUBSTTRIBDESTAC  = :SOMAVLRICMSSUBSTTRIBDESTAC + :VLRICMSSUBSTTRIBDESTAC;
            SELECT ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB, BASE, VALORPIS, VALORCOFINS FROM CALCULARPISCOFINS(:CSTPIS, :VLRTOTALITEM, :CODTABPISCOFINS, :QTDE, :CONVUNMEDIDA)
            INTO :ALIQPIS, :ALIQCOFINS, :VLRPISTRIB, :VLRCOFINSTRIB, :BASEPISCOFINS, :VLRPIS, :VLRCOFINS;
            SOMARVLRPIS = :SOMARVLRPIS + :VLRPIS;
            SOMARVLRCOFINS= :SOMARVLRCOFINS + :VLRCOFINS;
            SOMARBCPISCOFINS = :SOMARBCPISCOFINS + :BASEPISCOFINS;
            -- ATUALIZA OS VALORES DE ICMS
            UPDATE ITENSCOTACAOPROD SET VLRUNIT  = :PRECOVENDAORIGINAL, VLRVENDAMINIMO = :PRECOVENDAMINIMO,
            DESCVLR  = 0, DESCPORC = 0, BASECALCIPI = :BASECALCIPI, VLRIPI = :VLRIPI, BASEICMS = :BASEICMSITEM, VLRICMS  = :VLRICMSITEM,
            BASEICMSSUBSTTRIB = :BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIB  = :VLRICMSSUBSTTRIBRETIDO, MVACALC = :MVACALC,
            BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC  = :VLRICMSSUBSTTRIBDESTAC, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL    = :VLRTOTALITEM,
            ALIQPIS=:ALIQPIS, ALIQCOFINS=:ALIQCOFINS, VLRPISTRIB=:VLRPISTRIB, VLRCOFINSTRIB=:VLRCOFINSTRIB, BCPIS=:BASEPISCOFINS, BCCOFINS=:BASEPISCOFINS, VLRPIS=:VLRPIS, VLRCOFINS=:VLRCOFINS
            WHERE CHAVE=:CHAVEITEM;
        END
    END
    IF ((:CHAVETABDESC = 0) OR (:APLICARSERV='S')) THEN BEGIN
        FOR SELECT ICS.CHAVE, ICS.CHAVEPRODUTO, ICS.VLRUNITTABELA, PV.PRECOVENDA, PV.PRECOVENDAMINIMO, ICS.QTDE
        FROM ITENSCOTACAOSERV ICS
        INNER JOIN PRODUTO P ON ICS.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (ICS.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=ICS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        WHERE ICS.ATIVO=1 AND ICS.CHAVECOTACAO=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :VLRVENDAITEM, :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE
        DO BEGIN
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- APLICA OS DESCONTOS/ACRESCIMOS DA TABELA PRINCIPAL
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            -- SE FOR DESCONTO
            SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
            INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            -- VERIFICA SE O PRODUTO TEM DESC/ACRESC POR GRUPO
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- SE TEM DESCONTO POR GRUPO APLICA
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- SE FOR DESCONTO
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- VERIFICA SE O PRODUTO TEM DESCONTO/ACRESCIMO POR SUBGRUPO
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- SE TEM DESCONTO POR SUBGRUPO APLICA
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- SE FOR DESCONTO
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- VERIFICAR CASAS DECIMAIS VLRUNIT Q O SISTEMA ESTA TRABALHANDO
            PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
            WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
            WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END;
            VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            -- ATUALIZA OS VALORES DE ICMS
            UPDATE ITENSCOTACAOSERV SET VLRUNIT  = :PRECOVENDAORIGINAL, DESCVLR  = 0, DESCPORC = 0, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL = :VLRTOTALITEM WHERE CHAVE=:CHAVEITEM;
        END
    END
    SELECT SUM(VLRTOTAL) FROM ITENSCOTACAOPROD WHERE ATIVO=1 AND CHAVECOTACAO=:CHAVETABELA
    INTO :TOTALPRODUTOS;
    SELECT SUM(VLRTOTAL) FROM ITENSCOTACAOSERV WHERE ATIVO=1 AND CHAVECOTACAO=:CHAVETABELA
    INTO :TOTALSERVICOS;
    UPDATE COTACAO SET
        BASECALCULOICMS   = CAST(:SOMABASEICMS AS NUMERIC(18,2)), VLRICMS           = CAST(:SOMAVLRICMS AS NUMERIC(18,2)),
        BASECALCICMSSUBST = CAST(:SOMABASEICMSSUBSTTRIBRETIDO AS NUMERIC(18,2)), VLRICMSSUBST      = CAST(:SOMAVLRICMSSUBSTTRIBRETIDO AS NUMERIC(18,2)),
        BASECALCICMSSUBSTDESTAC = CAST(:SOMABASEICMSSUBSTTRIBDESTAC AS NUMERIC(18,2)), VLRICMSSUBSTDESTAC      = CAST(:SOMAVLRICMSSUBSTTRIBDESTAC AS NUMERIC(18,2)),
        TOTALIPI          = CAST(:SOMATOTALIPI AS NUMERIC(18,2)), BCIPI             = CAST(:SOMARBCIPI AS NUMERIC(18,2)), TOTALPRODUTO = :TOTALPRODUTOS, TOTALSERVICO=:TOTALSERVICOS,
        TOTALCOTACAO      = :TOTALPRODUTOS + :TOTALSERVICOS + :SOMAVLRICMSSUBSTTRIBRETIDO, BCPISCOFINS=:SOMARBCPISCOFINS, VLRPIS=:SOMARVLRPIS, VLRCOFINS=:SOMARVLRCOFINS
    WHERE CHAVE=:CHAVETABELA;
END^


ALTER PROCEDURE RECALCULARTABDESCOS (
    CHAVETABELA INTEGER,
    CHAVETABDESC INTEGER,
    CHAVEEMPPRODUTOVENDA INTEGER,
    VLRVENDAORIGEM VARCHAR(5),
    VPERCENT01 NUMERIC(18,6),
    VPERCENT02 NUMERIC(18,6),
    VPERCENT03 NUMERIC(18,6),
    VPERCENT04 NUMERIC(18,6),
    CASADECIMALVLRUNIT NUMERIC(18,6),
    APLICARPROD CHAR(1),
    APLICARSERV CHAR(1),
    CHOSTABDESCAPLICAR SMALLINT)
AS
declare variable CHAVEPRODUTO integer;
declare variable ALTERARPRECOMINIMO char(1);
declare variable CHAVEITEM integer;
declare variable CHAVETABELADESCONTO integer;
declare variable VPERC01 numeric(18,6);
declare variable VPERC02 numeric(18,6);
declare variable VPERC03 numeric(18,6);
declare variable VPERC04 numeric(15,2);
declare variable VLRTOTALITEM numeric(18,6);
declare variable TOTALSERVICOS numeric(18,6);
declare variable TOTALPRODUTOS numeric(18,6);
declare variable VLRVENDAITEM numeric(18,6);
declare variable VLRVENDAPROD numeric(18,6);
declare variable PRECOVENDAORIGINAL numeric(18,6);
declare variable PRECOVENDAMINIMO numeric(18,6);
declare variable QTDE numeric(15,3);
declare variable VTIPO integer;
declare variable PERCDESCTOTAL numeric(18,6);
declare variable DESCVLR numeric(18,6);
declare variable VLRTOTALCOMDESC numeric(18,6);
BEGIN
    UPDATE ORDEMSERVICO SET TOTALPRODUTO = 0, TOTALOS = 0, TOTALSERVICO = 0 WHERE CHAVE=:CHAVETABELA;
    IF ((:CHAVETABDESC = 0) OR (:APLICARPROD='S')) THEN BEGIN
        FOR SELECT IPO.CHAVE, IPO.CHAVEPRODUTO, IPO.VLRUNITTABELA, PV.PRECOVENDA, PV.PRECOVENDAMINIMO, IPO.QTDE
        FROM ITENSORDEMSERVICOPROD IPO
        INNER JOIN PRODUTO P ON IPO.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (IPO.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=IPO.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        WHERE IPO.ATIVO=1 AND IPO.CHAVEOS=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :VLRVENDAITEM, :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE
        DO BEGIN                          
            DESCVLR = 0;
            PERCDESCTOTAL = 0;
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- Aplica os desc/acresc da tabela principal
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            IF ((:CHOSTABDESCAPLICAR=1) and (:VTIPO=0)) THEN BEGIN
                PERCDESCTOTAL = 100;
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC01)/100));
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC02)/100));
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC03)/100));
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC04)/100));
            END ELSE BEGIN
                -- DESCONTO
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04,
                :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- Verifica se o produto tem desc/acresc por grupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1)
            AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por grupo aplica
            IF ((:CHAVETABELADESCONTO > 0) and (:VTIPO=0)) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Calcula perc desconto
                IF (:CHOSTABDESCAPLICAR=1) THEN BEGIN
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC01)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC02)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC03)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC04)/100));
                END ELSE BEGIN
                    -- DESCONTO
                    SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04,
                    :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                    INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
                END
            END
            -- Verifica se o produto tem desconto/acrescimo por subgrupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por subgrupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Calcula perc desconto
                IF ((:CHOSTABDESCAPLICAR = 1) and (:VTIPO=0)) THEN BEGIN      
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC01)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC02)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC03)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC04)/100));
                END ELSE BEGIN
                    -- DESCONTO
                    SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04,
                    :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                    INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
                END
            END
            IF ((:CHOSTABDESCAPLICAR = 1) and (:VTIPO=0)) THEN
                PERCDESCTOTAL = 100 - :PERCDESCTOTAL;
            -- CAPTURA VALOR TOTAL (CASO DESCONTO APLIQUE DIRETO NO VALOR UNIT ESSE CAMPO JA TEAR O VALOR DESCONTO/ ACRESCIMO EMBUTIDO)
            VLRTOTALITEM = :QTDE * (CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
                WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
                WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END);
            -- CALCULA O VALOR DE DESCONTO DE ACORDO COM O VALOR TOTAL DO PERCENTUAL DE DESCONTO OBTIDO NOS CALCULO ACIMA
            DESCVLR = :VLRTOTALITEM * (:PERCDESCTOTAL/100);
            VLRTOTALCOMDESC = :VLRTOTALITEM - COALESCE(:DESCVLR, 0);
            VLRTOTALCOMDESC = (CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,2)) WHEN 3 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,3))
                WHEN 4 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,4)) WHEN 5 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,5))
                WHEN 6 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,6))END);
            DESCVLR = CAST(:DESCVLR AS NUMERIC(18,2));
            -- UPDATE ITEM COM DESCS
            UPDATE ITENSORDEMSERVICOPROD SET VLRUNIT  = :PRECOVENDAORIGINAL, VLRVENDAMINIMO = :PRECOVENDAMINIMO, DESCVLR  = COALESCE(:DESCVLR,0),
                DESCPORC = COALESCE(:PERCDESCTOTAL,0), VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL = :VLRTOTALCOMDESC
                WHERE CHAVE=:CHAVEITEM;
        END
    END
    IF ((:CHAVETABDESC = 0) OR (:APLICARSERV='S')) THEN BEGIN
        FOR SELECT IOS.CHAVE, IOS.CHAVEPRODUTO, IOS.VLRUNITTABELA, PV.PRECOVENDA, PV.PRECOVENDAMINIMO, IOS.QTDE
        FROM ITENSORDEMSERVICOSERV IOS
        INNER JOIN PRODUTO P ON IOS.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (IOS.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=IOS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        WHERE IOS.ATIVO=1 AND IOS.CHAVEOS=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :VLRVENDAITEM, :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE
        DO BEGIN    
            DESCVLR = 0;
            PERCDESCTOTAL = 0;
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- Aplica os desc/acresc da tabela principal
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            -- Desconto Calcula perc desconto
            IF ((:CHOSTABDESCAPLICAR=1) and (:VTIPO=0)) THEN BEGIN
                PERCDESCTOTAL = 100;
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC01)/100));
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC02)/100));
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC03)/100));
                PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC04)/100));
            END ELSE BEGIN
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04,
                :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- Verifica se o produto tem desc/acresc por grupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por grupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Calcula perc desconto
                IF ((:CHOSTABDESCAPLICAR=1) and (:VTIPO=0)) THEN BEGIN
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC01)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC02)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC03)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC04)/100));
                END ELSE BEGIN
                    SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                    INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
                END 
            END
            -- Verifica se o produto tem desconto/acrescimo por subgrupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por subgrupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Calcula perc desconto
                IF ((:CHOSTABDESCAPLICAR=1) and (:VTIPO=0)) THEN BEGIN
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC01)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC02)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC03)/100));
                    PERCDESCTOTAL = :PERCDESCTOTAL-(:PERCDESCTOTAL*((:VPERC04)/100));
                END ELSE BEGIN
                    SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                    INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
                END
            END
            IF ((:CHOSTABDESCAPLICAR = 1) and (:VTIPO=0)) THEN
                PERCDESCTOTAL = 100 - :PERCDESCTOTAL;
            -- CAPTURA VALOR TOTAL (CASO DESCONTO APLIQUE DIRETO NO VALOR UNIT ESSE CAMPO JA TEAR O VALOR DESCONTO/ ACRESCIMO EMBUTIDO)
            VLRTOTALITEM = :QTDE * (CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
                WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
                WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END);
            -- CALCULA O VALOR DE DESCONTO DE ACORDO COM O VALOR TOTAL DO PERCENTUAL DE DESCONTO OBTIDO NOS CALCULO ACIMA
            DESCVLR = :VLRTOTALITEM * (:PERCDESCTOTAL/100);
            DESCVLR = CAST(:DESCVLR AS NUMERIC(18,2));
            VLRTOTALCOMDESC = :VLRTOTALITEM - COALESCE(:DESCVLR,0);
            VLRTOTALCOMDESC = (CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,2)) WHEN 3 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,3))
            WHEN 4 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,4)) WHEN 5 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,5))WHEN 6 THEN CAST(:VLRTOTALCOMDESC AS NUMERIC(18,6))END);
            -- Atualiza os valores de ICMS
            UPDATE ITENSORDEMSERVICOSERV SET VLRUNIT  = :PRECOVENDAORIGINAL, DESCVLR  = :DESCVLR, DESCPORC = :PERCDESCTOTAL, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL = :VLRTOTALCOMDESC WHERE CHAVE=:CHAVEITEM;
        END
    END
    SELECT SUM(CAST(VLRTOTAL AS NUMERIC(18,2))) FROM ITENSORDEMSERVICOPROD WHERE ATIVO=1 AND CHAVEOS=:CHAVETABELA INTO :TOTALPRODUTOS;
    SELECT SUM(CAST(VLRTOTAL AS NUMERIC(18,2))) FROM ITENSORDEMSERVICOSERV WHERE ATIVO=1 AND CHAVEOS=:CHAVETABELA INTO :TOTALSERVICOS;
    UPDATE ORDEMSERVICO SET TOTALPRODUTO = :TOTALPRODUTOS, TOTALOS = COALESCE(:TOTALPRODUTOS,0) + COALESCE(:TOTALSERVICOS,0) + COALESCE(FRETE,0) + COALESCE(TOTALIPI,0),
        TOTALSERVICO=:TOTALSERVICOS
    WHERE CHAVE=:CHAVETABELA;
END^


ALTER PROCEDURE RECALCULARTABDESCPREVENDA (
    CHAVETABELA INTEGER,
    CHAVETABDESC INTEGER,
    CHAVEEMPPRODUTOVENDA INTEGER,
    VLRVENDAORIGEM VARCHAR(5),
    VPERCENT01 NUMERIC(18,6),
    VPERCENT02 NUMERIC(18,6),
    VPERCENT03 NUMERIC(18,6),
    VPERCENT04 NUMERIC(18,6),
    APLICARPROD CHAR(1))
AS
declare variable CHAVEPRODUTO integer;
declare variable ALTERARPRECOMINIMO char(1);
declare variable CHAVEITEM integer;
declare variable CHAVETABELADESCONTO integer;
declare variable VPERC01 numeric(18,6);
declare variable VPERC02 numeric(18,6);
declare variable VPERC03 numeric(18,6);
declare variable VPERC04 numeric(15,2);
declare variable VLRTOTALITEM numeric(18,6);
declare variable TOTALPRODUTOS numeric(18,6);
declare variable VLRVENDAITEM numeric(18,6);
declare variable VLRVENDAPROD numeric(18,6);
declare variable PRECOVENDAORIGINAL numeric(18,6);
declare variable PRECOVENDAMINIMO numeric(18,6);
declare variable QTDE numeric(15,3);
declare variable VTIPO integer;
BEGIN
    UPDATE PREVENDA SET TOTALPRODUTO = 0, TOTALPV  = 0 WHERE CHAVE=:CHAVETABELA;
    IF ((:CHAVETABDESC = 0) OR (:APLICARPROD='S')) THEN BEGIN
        FOR SELECT IPV.CHAVE, IPV.CHAVEPRODUTO, IPV.VLRUNITTABELA, PV.PRECOVENDA, PV.PRECOVENDAMINIMO, IPV.QTDE
        FROM ITENSPREVENDA IPV
        INNER JOIN PRODUTO P ON IPV.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (IPV.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=IPV.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        WHERE IPV.ATIVO=1 AND IPV.CHAVEPREVENDA=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :VLRVENDAITEM, :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE
        DO BEGIN
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- Aplica os desc/acresc da tabela principal
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            -- Desconto
            SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
            INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            -- Verifica se o produto tem desc/acresc por grupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por grupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- descontos
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- Verifica se o produto tem desconto/acrescimo por subgrupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por subgrupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            VLRTOTALITEM = :QTDE * :PRECOVENDAORIGINAL;
            -- Atualiza os valores de ICMS
            UPDATE ITENSPREVENDA SET VLRUNIT = :PRECOVENDAORIGINAL, VLRVENDAMINIMO = :PRECOVENDAMINIMO, DESCVLR  = 0, DESCPORC = 0, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL    = :VLRTOTALITEM
            WHERE CHAVE=:CHAVEITEM;
        END
    END
    SELECT SUM(CAST(VLRTOTAL AS NUMERIC(18,2))) FROM ITENSPREVENDA WHERE ATIVO=1 AND CHAVEPREVENDA=:CHAVETABELA
    INTO :TOTALPRODUTOS;

    UPDATE PREVENDA SET
    TOTALPRODUTO = :TOTALPRODUTOS,
    TOTALPV = :TOTALPRODUTOS
    WHERE CHAVE=:CHAVETABELA;
END^


ALTER PROCEDURE RECALCULARTABDESCPS (
    CHAVETABELA INTEGER,
    CHAVETABDESC INTEGER,
    CHAVEEMPPRODUTOVENDA INTEGER,
    VLRVENDAORIGEM VARCHAR(5),
    VPERCENT01 NUMERIC(18,6),
    VPERCENT02 NUMERIC(18,6),
    VPERCENT03 NUMERIC(18,6),
    VPERCENT04 NUMERIC(18,6),
    REGIMETRIB SMALLINT,
    CASADECIMALVLRUNIT NUMERIC(18,6),
    UFEMP CHAR(2),
    APLICARPROD CHAR(1),
    APLICARSERV CHAR(1))
AS
declare variable CHAVEPRODUTO integer;
declare variable CODTABPISCOFINS varchar(10);
declare variable SOMARVLRCOFINS numeric(18,6);
declare variable SOMARVLRPIS numeric(18,6);
declare variable SOMARBCPISCOFINSSERV numeric(18,6);
declare variable SOMARVLRCOFINSSERV numeric(18,6);
declare variable SOMARVLRPISSERV numeric(18,6);
declare variable SOMARBCPISCOFINS numeric(18,6);
declare variable VLRPIS numeric(18,6);
declare variable VLRCOFINS numeric(18,6);
declare variable BASEPISCOFINS numeric(18,6);
declare variable VLRCOFINSTRIB numeric(18,6);
declare variable VLRPISTRIB numeric(18,6);
declare variable ALIQCOFINS numeric(18,6);
declare variable ALIQPIS numeric(18,6);
declare variable CONVUNMEDIDA numeric(18,6);
declare variable CSTPIS varchar(10);
declare variable ALTERARPRECOMINIMO char(1);
declare variable PERCREDST numeric(18,6);
declare variable SOMARBCIPI numeric(18,6);
declare variable CHAVEITEM integer;
declare variable CHAVETABELADESCONTO integer;
declare variable VPERC01 numeric(18,6);
declare variable VPERC02 numeric(18,6);
declare variable VPERC03 numeric(18,6);
declare variable VPERC04 numeric(15,2);
declare variable CST varchar(6);
declare variable ICMSTRIB numeric(7,2);
declare variable ICMSITEM numeric(7,2);
declare variable SOMABASEICMS numeric(18,6);
declare variable SOMAVLRICMS numeric(18,6);
declare variable VLRICMSITEM numeric(18,6);
declare variable VLRTOTALITEM numeric(18,6);
declare variable BASEICMSITEM numeric(18,6);
declare variable PERCRED numeric(15,6);
declare variable TOTALSERVICOS numeric(18,6);
declare variable TOTALPRODUTOS numeric(18,6);
declare variable VLRVENDAITEM numeric(18,6);
declare variable VLRVENDAPROD numeric(18,6);
declare variable PRECOVENDAORIGINAL numeric(18,6);
declare variable PRECOVENDAMINIMO numeric(18,6);
declare variable QTDE numeric(15,3);
declare variable VTIPO integer;
declare variable BASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable VLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBDESTAC numeric(18,6);
declare variable BASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable VLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMABASEICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable SOMAVLRICMSSUBSTTRIBRETIDO numeric(18,6);
declare variable UFCLI char(2);
declare variable IPI numeric(7,2);
declare variable VLRIPI numeric(18,6);
declare variable SOMATOTALIPI numeric(18,6);
declare variable BASECALCIPI numeric(18,6);
declare variable REDUCAOMVA numeric(7,2);
declare variable MVA numeric(7,2);
declare variable VLRIPITRIB numeric(18,6);
declare variable VLRPAUTA numeric(18,6);
declare variable CHAVEUNIDADE integer;
BEGIN
    SELECT CID.UF, C.REDUCAOMVA FROM CLIFOR C
    INNER JOIN CIDADE CID ON C.CHAVECIDADE=CID.CHAVE
    INNER JOIN PEDIDOSAIDA PS ON C.CHAVE=PS.CHAVECLIFOR
    WHERE PS.CHAVE=:CHAVETABELA
    INTO :UFCLI, :REDUCAOMVA;

    UPDATE PEDIDOSAIDA SET BASECALCULOICMS = 0, VLRICMS  = 0, TOTALIPI = 0, BCIPI = 0, TOTALPRODUTO = 0, TOTALSERVICO = 0, TOTALPEDIDO  = 0  WHERE CHAVE=:CHAVETABELA;

    IF ((:CHAVETABDESC = 0) OR (:APLICARPROD='S')) THEN BEGIN
        FOR SELECT IPS.CHAVE, IPS.CHAVEPRODUTO, IPS.CST, T.PERCRED, T.ALIQUOTADE, IPS.ICMS, IPS.VLRUNITTABELA, PV.PRECOVENDA, PV.PRECOVENDAMINIMO, IPS.QTDE, IPS.IPI,
        IPS.BASECALCIPI, IPS.MVA, T.PERCREDST, IPS.CSTPIS, TC.CODIGO, COALESCE(UN.CONVUNMEDIDA,0), IPS.VLRIPITRIB, IPS.VLRPAUTA, IPS.CHAVEUNIDADE
        FROM ITENSPEDSAIDA IPS
        INNER JOIN TRIBUTACAO T ON IPS.CHAVETRIBUTACAO=T.CHAVE
        INNER JOIN PRODUTO P ON IPS.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (IPS.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=IPS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = IPS.CHAVETABPISCOFINS
        INNER JOIN UNIDADE UN ON UN.CHAVE = IPS.CHAVEUNIDADE
        WHERE IPS.ATIVO=1 AND IPS.CHAVEPEDIDO=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :CST, :PERCRED, :ICMSTRIB, :ICMSITEM, :VLRVENDAITEM, :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE, :IPI,
        :BASECALCIPI, :MVA, :PERCREDST, :CSTPIS, :CODTABPISCOFINS, :CONVUNMEDIDA,  :VLRIPITRIB, :VLRPAUTA, :CHAVEUNIDADE
        DO BEGIN
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- Aplica os desc/acresc da tabela principal
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            -- Desconto
            SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
            INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            -- Verifica se o produto tem desc/acresc por grupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por grupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- Verifica se o produto tem desconto/acrescimo por subgrupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por subgrupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Se for desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- VERIFICAR CASAS DECIMAIS VLRUNIT Q O SISTEMA ESTA TRABALHANDO
            PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
            WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
            WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END;
            VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            -- Calculos de ICMS
            SELECT BASEICMSITEM, VLRICMSITEM, BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIBRETIDO, BASEICMSSUBSTTRIBDESTAC, VLRICMSSUBSTTRIBDESTAC
            FROM CALCULARICMS(:CST, :VLRTOTALITEM, :ICMSTRIB, :PERCRED, :PRECOVENDAORIGINAL, :QTDE, :ICMSITEM, :UFCLI, :UFEMP, :IPI, :REDUCAOMVA, :REGIMETRIB, :MVA, :PERCREDST,:VLRIPITRIB, :VLRPAUTA, :CHAVEUNIDADE)
            INTO :BASEICMSITEM, :VLRICMSITEM,:BASEICMSSUBSTTRIBRETIDO, :VLRICMSSUBSTTRIBRETIDO,:BASEICMSSUBSTTRIBDESTAC, :VLRICMSSUBSTTRIBDESTAC;
            BASECALCIPI = :VLRTOTALITEM;
            VLRIPI = (:BASECALCIPI * :IPI / 100);
            SOMATOTALIPI = :SOMATOTALIPI + :VLRIPI;
            SOMARBCIPI = SOMARBCIPI + BASECALCIPI;
            -- Acumula totais
            SOMABASEICMS = :SOMABASEICMS + :BASEICMSITEM;
            SOMAVLRICMS  = :SOMAVLRICMS + :VLRICMSITEM;
            SOMABASEICMSSUBSTTRIBRETIDO = :SOMABASEICMSSUBSTTRIBRETIDO + :BASEICMSSUBSTTRIBRETIDO;
            SOMAVLRICMSSUBSTTRIBRETIDO  = :SOMAVLRICMSSUBSTTRIBRETIDO + :VLRICMSSUBSTTRIBRETIDO;
            SOMABASEICMSSUBSTTRIBDESTAC = :SOMABASEICMSSUBSTTRIBDESTAC + :BASEICMSSUBSTTRIBDESTAC;
            SOMAVLRICMSSUBSTTRIBDESTAC  = :SOMAVLRICMSSUBSTTRIBDESTAC + :VLRICMSSUBSTTRIBDESTAC;
            SELECT ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB, BASE, VALORPIS, VALORCOFINS FROM CALCULARPISCOFINS(:CSTPIS, :VLRTOTALITEM, :CODTABPISCOFINS, :QTDE, :CONVUNMEDIDA)
            INTO :ALIQPIS, :ALIQCOFINS, :VLRPISTRIB, :VLRCOFINSTRIB, :BASEPISCOFINS, :VLRPIS, :VLRCOFINS;
            SOMARVLRPIS = :SOMARVLRPIS + :VLRPIS;
            SOMARVLRCOFINS= :SOMARVLRCOFINS + :VLRCOFINS;
            SOMARBCPISCOFINS = :SOMARBCPISCOFINS + :BASEPISCOFINS;
            -- Atualiza os valores de ICMS
            UPDATE ITENSPEDSAIDA SET VLRUNIT  = :PRECOVENDAORIGINAL, VLRVENDAMINIMO = :PRECOVENDAMINIMO,
            DESCVLR  = 0, DESCPORC = 0, BASECALCIPI = :BASECALCIPI, VLRIPI = :VLRIPI, BASEICMS = :BASEICMSITEM, VLRICMS  = :VLRICMSITEM,
            BASEICMSSUBSTTRIB = :BASEICMSSUBSTTRIBRETIDO, VLRICMSSUBSTTRIB  = :VLRICMSSUBSTTRIBRETIDO, BASEICMSSUBSTTRIBDESTAC = :BASEICMSSUBSTTRIBDESTAC,
            VLRICMSSUBSTTRIBDESTAC  = :VLRICMSSUBSTTRIBDESTAC, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL    = :VLRTOTALITEM, ALIQPIS=:ALIQPIS, ALIQCOFINS=:ALIQCOFINS,
            VLRPISTRIB=:VLRPISTRIB, VLRCOFINSTRIB=:VLRCOFINSTRIB, BCPIS=:BASEPISCOFINS, BCCOFINS=:BASEPISCOFINS, VLRPIS=:VLRPIS, VLRCOFINS=:VLRCOFINS
            WHERE CHAVE=:CHAVEITEM;
        END
    END
    IF ((:CHAVETABDESC = 0) OR (:APLICARSERV='S')) THEN BEGIN
        FOR SELECT ITS.CHAVE, ITS.CHAVEPRODUTO, ITS.VLRUNITTABELA, PV.PRECOVENDA, PV.PRECOVENDAMINIMO, ITS.QTDE, ITS.CSTPISCOFINS, TC.CODIGO, COALESCE(UN.CONVUNMEDIDA,0)
        FROM ITENSPEDSAIDASERV ITS
        INNER JOIN PRODUTO P ON ITS.CHAVEPRODUTO=P.CHAVE
        INNER JOIN PRODUTOVENDA PV ON (ITS.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:CHAVEEMPPRODUTOVENDA) AND (PV.CHAVETABELAPRECO=ITS.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        INNER JOIN UNIDADE UN ON UN.CHAVE = ITS.CHAVEUNIDADE
        LEFT JOIN TABELAPISCOFINS TC ON TC.CHAVE = ITS.CHAVETABPISCOFINS
        WHERE ITS.ATIVO=1 AND ITS.CHAVEPEDIDO=:CHAVETABELA
        INTO :CHAVEITEM, :CHAVEPRODUTO, :VLRVENDAITEM, :VLRVENDAPROD, :PRECOVENDAMINIMO, :QTDE, :CSTPIS, :CODTABPISCOFINS, :CONVUNMEDIDA
        DO BEGIN
            IF (:VLRVENDAORIGEM = 'ITEM') THEN
                PRECOVENDAORIGINAL =:VLRVENDAITEM;
            IF (:VLRVENDAORIGEM = 'PROD') THEN
                PRECOVENDAORIGINAL =:VLRVENDAPROD;
            -- Aplica os desc/acresc da tabela principal
            SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABDESC, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
            INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
            -- Desconto
            SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
            INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            -- Verifica se o produto tem desc/acresc por grupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN GRUPOPRODUTO GP ON GP.CHAVE=TDGP.CHAVEGRUPOPRODUTO
            INNER JOIN PRODUTO P ON GP.CHAVE=P.CHAVEGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (GP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por grupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            -- Verifica se o produto tem desconto/acrescimo por subgrupo
            CHAVETABELADESCONTO= 0;
            SELECT TDGP.CHAVETABELADESCONTOS FROM TABELADESCONTOS TD
            INNER JOIN TABELADESCGRUPOPROD TDGP ON TD.CHAVE=TDGP.CHAVETABELADESC
            INNER JOIN SUBGRUPOPRODUTO SGP ON SGP.CHAVE=TDGP.CHAVESUBGRUPOPRODUTO
            INNER JOIN PRODUTO P ON SGP.CHAVE=P.CHAVESUBGRUPO
            WHERE (TD.ATIVO=1) AND (TDGP.ATIVO=1) AND (SGP.ATIVO=1) AND (P.CHAVE=:CHAVEPRODUTO) AND (TD.CHAVE=:CHAVETABDESC)
            INTO :CHAVETABELADESCONTO;
            -- Se tem desconto por subgrupo aplica
            IF (:CHAVETABELADESCONTO > 0) THEN BEGIN
                SELECT VPERC01, VPERC02, VPERC03, VPERC04, VTIPO, ALTERARPRECOMINIMO FROM RETORNARPERCTABDESCONTOS(:CHAVETABELADESCONTO, :VPERCENT01, :VPERCENT02, :VPERCENT03,  :VPERCENT04)
                INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
                -- Se for desconto
                SELECT PRECOVENDA, PRECOMINIMO FROM RETORNARVALORESTABELADESCONTO(:VTIPO, :VPERC01, :VPERC02, :VPERC03, :VPERC04, :PRECOVENDAORIGINAL, :ALTERARPRECOMINIMO, :PRECOVENDAMINIMO)
                INTO :PRECOVENDAORIGINAL, :PRECOVENDAMINIMO;
            END
            PRECOVENDAORIGINAL = CASE :CASADECIMALVLRUNIT WHEN 2 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,2))
            WHEN 3 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,3)) WHEN 4 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,4))
            WHEN 5 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,5)) WHEN 6 THEN CAST(:PRECOVENDAORIGINAL AS NUMERIC(18,6))END;
            VLRTOTALITEM= :QTDE * :PRECOVENDAORIGINAL;
            SELECT ALIQPIS, ALIQCOFINS, VLRPISTRIB, VLRCOFINSTRIB, BASE, VALORPIS, VALORCOFINS FROM CALCULARPISCOFINS(:CSTPIS, :VLRTOTALITEM, :CODTABPISCOFINS, :QTDE, :convunmedida)
            INTO :ALIQPIS, :ALIQCOFINS, :VLRPISTRIB, :VLRCOFINSTRIB, :BASEPISCOFINS, :VLRPIS, :VLRCOFINS;
            SOMARVLRPISSERV = :SOMARVLRPISSERV + :VLRPIS;
            SOMARVLRCOFINSSERV= :SOMARVLRCOFINSSERV + :VLRCOFINS;
            SOMARBCPISCOFINSSERV = :SOMARBCPISCOFINSSERV + :BASEPISCOFINS;

            UPDATE ITENSPEDSAIDASERV SET VLRUNIT  = :PRECOVENDAORIGINAL, DESCVLR  = 0, DESCPORC = 0, VLRSUBTOTAL = :VLRTOTALITEM, VLRTOTAL    = :VLRTOTALITEM, ALIQPIS=:ALIQPIS,
            ALIQCOFINS=:ALIQCOFINS, VLRPISTRIB=:VLRPISTRIB, VLRCOFINSTRIB=:VLRCOFINSTRIB, BASEPISCOFINS=:BASEPISCOFINS, BASEISS=:VLRTOTALITEM, VLRISS=((:VLRTOTALITEM * COALESCE(ISS,0)) / 100)
            WHERE CHAVE=:CHAVEITEM;
        END
    END
    SELECT SUM(CAST(I.VLRTOTAL AS NUMERIC(18,2))) FROM ITENSPEDSAIDA I
    INNER JOIN CFOPOPERFISCAIS CF ON CF.CHAVE = I.CHAVECFOPOPERFISCAIS AND CF.COMPORTOTALNF = 0
    WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVETABELA
    INTO :TOTALPRODUTOS;
    SELECT SUM(CAST(I.VLRTOTAL AS NUMERIC(18,2))) FROM ITENSPEDSAIDASERV I WHERE I.ATIVO=1 AND I.CHAVEPEDIDO=:CHAVETABELA
    INTO :TOTALSERVICOS;
    UPDATE PEDIDOSAIDA SET
        BASECALCULOICMS   = CAST(:SOMABASEICMS AS NUMERIC(18,2)), VLRICMS  = CAST(:SOMAVLRICMS AS NUMERIC(18,2)),
        BASECALCICMSSUBST = CAST(:SOMABASEICMSSUBSTTRIBRETIDO AS NUMERIC(18,2)), VLRICMSSUBST = CAST(:SOMAVLRICMSSUBSTTRIBRETIDO AS NUMERIC(18,2)),
        BASECALCICMSSUBSTDESTAC = CAST(:SOMABASEICMSSUBSTTRIBDESTAC AS NUMERIC(18,2)), BCPISCOFINS=:SOMARBCPISCOFINS, VLRPIS=:SOMARVLRPIS, VLRCOFINS=:SOMARVLRCOFINS,
        VLRICMSSUBSTDESTAC      = CAST(:SOMAVLRICMSSUBSTTRIBDESTAC AS NUMERIC(18,2)), BCPISCOFINSSERV=:SOMARBCPISCOFINSSERV, VLRPISSERV=:SOMARVLRPISSERV, VLRCOFINSSERV=:SOMARVLRCOFINSSERV,
        TOTALIPI          = CAST(:SOMATOTALIPI AS NUMERIC(18,2)), BCIPI = CAST(:SOMARBCIPI AS NUMERIC(18,2)), TOTALPRODUTO      = :TOTALPRODUTOS, TOTALPEDIDO = :TOTALPRODUTOS + :TOTALSERVICOS + :SOMAVLRICMSSUBSTTRIBRETIDO,
        TOTALSERVICO=:TOTALSERVICOS, TOTALISS= CASE WHEN COALESCE(ALIQUOTAISS,0)>0 THEN ((:TOTALSERVICOS*COALESCE(ALIQUOTAISS,0))/100) ELSE TOTALISS END, BASEISS= CASE WHEN COALESCE(ALIQUOTAISS,0)>0 THEN :TOTALSERVICOS ELSE BASEISS END
    WHERE CHAVE=:CHAVETABELA;
END^


ALTER PROCEDURE RECALCULATABELADESCONTO (
    CHAVETABELA INTEGER,
    TABELA VARCHAR(50),
    CHAVETABDESC INTEGER,
    CHAVEEMPPRODUTOVENDA INTEGER,
    VLRVENDAORIGEM VARCHAR(5),
    CHAVEEMPLOGADA INTEGER,
    VPERCENT01 NUMERIC(18,6),
    VPERCENT02 NUMERIC(18,6),
    VPERCENT03 NUMERIC(18,6),
    VPERCENT04 NUMERIC(18,6))
AS
declare variable REGIMETRIB smallint;
declare variable PERCREDST numeric(18,6);
declare variable CASADECIMALVLRUNIT numeric(18,6);
declare variable UFEMP char(2);
declare variable CHOSTABDESCAPLICAR smallint;
declare variable APLICARPROD char(1);
declare variable APLICARSERV char(1);
declare variable VLRIPITRIB numeric(18,6);
declare variable VLRPAUTA numeric(18,2);
declare variable CHAVEUNIDADE integer;
BEGIN
    PERCREDST=0; VLRIPITRIB=0; VLRPAUTA=0; CHAVEUNIDADE=0;
    APLICARPROD='N';APLICARSERV='N';
    SELECT CID.UF, E.REGIMETRIBUT, C.CHOSTABDESCAPLICAR FROM EMPRESA E
    INNER JOIN CIDADE CID ON E.CHAVECIDADE=CID.CHAVE
    INNER JOIN CONFIG C ON C.CHAVEEMPRESA = E.CHAVE
    WHERE E.CHAVE=:CHAVEEMPLOGADA
    INTO :UFEMP, :REGIMETRIB, :CHOSTABDESCAPLICAR;

    SELECT VALOR
    FROM CONFIGCAMPOS
    WHERE CHAVEEMPRESA = :CHAVEEMPLOGADA AND INDICE = 288
    INTO :CASADECIMALVLRUNIT;

    IF (:CHAVETABDESC <> 0) THEN BEGIN
        SELECT APLICARPRODUTOS, APLICARSERVICOS FROM TABELADESCONTOS WHERE (CHAVE=:CHAVETABDESC)
        INTO :APLICARPROD, :APLICARSERV;
    END

    -- Pedido Saida
    IF (:TABELA = 'PEDIDOSAIDA') THEN BEGIN
        EXECUTE PROCEDURE RECALCULARTABDESCPS(:CHAVETABELA, :CHAVETABDESC, :CHAVEEMPPRODUTOVENDA, :VLRVENDAORIGEM, :VPERCENT01, :VPERCENT02, :VPERCENT03, :VPERCENT04,
            :REGIMETRIB, :CASADECIMALVLRUNIT, :UFEMP, :APLICARPROD, :APLICARSERV);
    END
    -- orcamento
    IF (:TABELA = 'COTACAO') THEN BEGIN
        EXECUTE PROCEDURE RECALCULARTABDESCCOT(:CHAVETABELA, :CHAVETABDESC, :CHAVEEMPPRODUTOVENDA, :VLRVENDAORIGEM, :VPERCENT01, :VPERCENT02, :VPERCENT03, :VPERCENT04,
            :REGIMETRIB, :CASADECIMALVLRUNIT, :UFEMP, :APLICARPROD, :APLICARSERV, :PERCREDST, :VLRIPITRIB, :VLRPAUTA, :CHAVEUNIDADE);
    END
    -- Condicional
    IF (:TABELA = 'CONDICIONAL') THEN BEGIN
        EXECUTE PROCEDURE RECALCULARTABDESCCOND(:CHAVETABELA, :CHAVETABDESC, :CHAVEEMPPRODUTOVENDA, :VLRVENDAORIGEM, :VPERCENT01, :VPERCENT02, :VPERCENT03, :VPERCENT04,
            :CASADECIMALVLRUNIT, :APLICARPROD, :APLICARSERV);
    END
    -- Pre - Venda
    IF (:TABELA = 'PREVENDA') THEN
        EXECUTE PROCEDURE RECALCULARTABDESCPREVENDA(:CHAVETABELA, :CHAVETABDESC, :CHAVEEMPPRODUTOVENDA, :VLRVENDAORIGEM, :VPERCENT01, :VPERCENT02, :VPERCENT03, :VPERCENT04, :APLICARPROD);
    -- Ordem Servico
    IF (:TABELA = 'ORDEMSERVICO') THEN BEGIN
        EXECUTE PROCEDURE RECALCULARTABDESCOS(:CHAVETABELA, :CHAVETABDESC, :CHAVEEMPPRODUTOVENDA, :VLRVENDAORIGEM, :VPERCENT01, :VPERCENT02, :VPERCENT03, :VPERCENT04,
        :CASADECIMALVLRUNIT, :APLICARPROD, :APLICARSERV, :CHOSTABDESCAPLICAR);
    END
    /*
       CHAMADAS:
            - FuncoesProc: Nesta unit tem a chamada da funcao que altera os valores ja cadastrados atualizando conforme o tipo da tabela de desconto
            (Desconto, Acrescimo, Preco Minimo), com base no preco do cadastro do produto ou do valor digitado, conforme parametrizacao.
           As telas que usam essa funcao sao:
            - PreVenda
            - PedidoSaida
            - Orcamento
            - Condicional
            - OrdemServico;
   */
END^


ALTER PROCEDURE REPLICARDADOS (
    CHAVEREG INTEGER,
    CHAVEEMPRESA INTEGER,
    ACAO SMALLINT,
    TABELA VARCHAR(30))
AS
BEGIN
    INSERT INTO REPLICADOR(ATIVO, CHAVEEMPRESA, ACAO, TABELA, CHAVEREG, DATAHORA)
    VALUES (1, :CHAVEEMPRESA, :ACAO, :TABELA, :CHAVEREG, CURRENT_TIMESTAMP);
END^


ALTER PROCEDURE RETORNARCUSTOCOTCOMPRA (
    PRECOCUSTO NUMERIC(18,6),
    PRECOCUSTONF NUMERIC(18,6),
    CONVERSAO NUMERIC(18,6),
    USARUNCOMPRA CHAR(1))
RETURNS (
    CUSTO NUMERIC(18,6))
AS
BEGIN
    -- alterado em 10/09/2013 -> Julio
    IF (PRECOCUSTONF>0) THEN BEGIN
        IF (USARUNCOMPRA = 'S') THEN
           CUSTO =:CONVERSAO * :PRECOCUSTONF;
        ELSE
           CUSTO =:PRECOCUSTONF;
    END ELSE BEGIN
        IF (USARUNCOMPRA = 'S') THEN
           CUSTO = :CONVERSAO * :PRECOCUSTO;
        ELSE
           CUSTO = :PRECOCUSTO;
    END
    /*
        CHAMADAS:
        DUPLICACOTACAOATUALIZAVALORES: USADA PARA RETORNAR O CUSTO DO PRODUTO MULTIPLICADO PELO CONVERSAO


    */
  SUSPEND;
END^


ALTER PROCEDURE RETORNARITENSGNRE (
    CHAVEGNRE INTEGER,
    PRODUTOCUSTOCHAVEEMP INTEGER,
    PRODUTOVENDACHAVEEMP INTEGER,
    QTDEITENSGNRE INTEGER)
RETURNS (
    CHAVEITEMGNRE INTEGER,
    TOTALITENS NUMERIC(18,6),
    CHAVEITEM INTEGER,
    CUSTOITEMNF NUMERIC(18,6),
    NL DOUBLE PRECISION,
    QTDEITENS NUMERIC(14,3),
    CUSTOMEDIOANT NUMERIC(18,4),
    CONVERSAO NUMERIC(18,6),
    TOTALNF NUMERIC(18,6),
    ANTPRECOVENDA NUMERIC(18,6),
    CUSTOUNITARIO NUMERIC(18,6),
    CHAVEPRODUTO INTEGER,
    CHAVEEMPALT INTEGER,
    CHAVEPRODALT INTEGER,
    NUMEROGNRE VARCHAR(9),
    SCHAVETABELAPRECO INTEGER)
AS
declare variable CUSTOUNIT numeric(18,4);
declare variable CHAVEEMPRESAPRODALT integer;
declare variable CHAVEITEMPRODALT integer;
declare variable NLITEM double precision;
declare variable NUMGNRE varchar(9);
declare variable CUSTMEDANT numeric(18,4);
declare variable TOTITENS numeric(18,4);
declare variable TOTNF numeric(18,6);
declare variable CHAVEPROD integer;
declare variable QTDE numeric(7,2);
declare variable CONVER numeric(18,6);
declare variable ANTPREVENDA numeric(18,6);
declare variable CUSTOITEMNFENTRADA numeric(18,6);
declare variable ITEMCHAVE integer;
BEGIN
    IF (QTDEITENSGNRE > 0) THEN BEGIN
        FOR SELECT IT.CHAVE, I.VLRICMSST, I.QTDE,
        COALESCE(PALT.PRECOVENDA, PV.PRECOVENDA),
        CASE WHEN COALESCE(IT.PRECOCUSTO,0) = 0 THEN COALESCE(PC.PRECOCUSTO,0) ELSE COALESCE(IT.PRECOCUSTO,0) END,
        COALESCE(PALT.PRECOCUSTOMEDIOANT, PC.PRECOMEDIOANT),
        I.CHAVEPRODUTO, NF.NUMERONF, IT.NL, I.CHAVEITEMNF,
        PALT.CHAVEEMPRESA, PALT.CHAVE, COALESCE(IT.PRECOCUSTO,0),
        PALT.CHAVETABELAPRECO
        FROM ITENSGNRE I
        INNER JOIN GNRE G ON G.CHAVE=I.CHAVEGNRE
        INNER JOIN ITENSNFENTRADAPROD IT ON IT.CHAVE=I.CHAVEITEMNF AND I.ATIVO=1
        INNER JOIN NFENTRADA NF ON NF.CHAVE = G.CHAVENF
        INNER JOIN PRODUTOCUSTO PC ON I.CHAVEPRODUTO= PC.CHAVEPRODUTO AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
        LEFT JOIN PRODUTOSALTERADOS PALT ON NF.NL = PALT.NL AND I.CHAVEPRODUTO=PALT.CHAVEPRODUTO AND PALT.ATIVO=1
        INNER JOIN PRODUTOVENDA PV ON (I.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=PALT.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        WHERE I.ATIVO=1 AND G.CHAVE = :CHAVEGNRE AND G.TIPO=1
        INTO :ITEMCHAVE, :TOTITENS, :QTDE, :ANTPREVENDA,
        :CUSTOUNIT, :CUSTMEDANT,  :CHAVEPROD, :NUMGNRE,
        :NLITEM, :CHAVEITEMGNRE, :CHAVEEMPRESAPRODALT, :CHAVEITEMPRODALT, :CUSTOITEMNFENTRADA,
        :SCHAVETABELAPRECO
        DO BEGIN
            CHAVEITEMGNRE = :ITEMCHAVE;
            TOTALITENS = :TOTITENS;
            QTDEITENS = :QTDE;
            ANTPRECOVENDA = :ANTPREVENDA;
            CUSTOUNITARIO = :CUSTOUNIT;
            CHAVEPRODUTO = :CHAVEPROD;
            NUMEROGNRE = :NUMGNRE;
            CUSTOMEDIOANT = :CUSTMEDANT;
            NL = :NLITEM;
            CHAVEITEM = :CHAVEITEMGNRE;
            CHAVEEMPALT = :CHAVEEMPRESAPRODALT;
            CHAVEPRODALT = :CHAVEITEMPRODALT;
            CUSTOITEMNF  = :CUSTOITEMNFENTRADA;

            SUSPEND;
        END
    END ELSE BEGIN
        FOR SELECT I.CHAVE, I.VLRTOTAL,
        CAST(I.QTDE AS NUMERIC (14,3)), U.CONVERSAO, NF.TOTALPRODUTO,
        COALESCE(PALT.PRECOVENDA, PV.PRECOVENDA),
        CASE WHEN COALESCE(I.PRECOCUSTO,0) = 0 THEN COALESCE(PC.PRECOCUSTO,0) ELSE COALESCE(I.PRECOCUSTO,0) END,
        COALESCE(PALT.PRECOCUSTOMEDIOANT, PC.PRECOMEDIOANT),
        I.CHAVEPRODUTO, NF.NUMERONF, I.NL,
        PALT.CHAVEEMPRESA, PALT.CHAVE, COALESCE(I.PRECOCUSTO,0),
        PALT.CHAVETABELAPRECO
        FROM GNRE G
        INNER JOIN ITENSNFENTRADAPROD I ON I.CHAVENFENTRADA = G.CHAVENF
        INNER JOIN NFENTRADA NF ON NF.CHAVE=I.CHAVENFENTRADA
        INNER JOIN UNIDADE U ON U.CHAVE=I.CHAVEUNIDADE
        LEFT JOIN PRODUTOSALTERADOS PALT ON NF.NL = PALT.NL AND I.CHAVEPRODUTO=PALT.CHAVEPRODUTO AND PALT.ATIVO=1
        INNER JOIN PRODUTOCUSTO PC ON I.CHAVEPRODUTO= PC.CHAVEPRODUTO AND PC.CHAVEEMPRESA=:PRODUTOCUSTOCHAVEEMP
        INNER JOIN PRODUTOVENDA PV ON (I.CHAVEPRODUTO=PV.CHAVEPRODUTO) AND (PV.CHAVEEMPRESA=:PRODUTOVENDACHAVEEMP) AND (PV.CHAVETABELAPRECO=PALT.CHAVETABELAPRECO) AND (PV.ATIVO=1)
        WHERE G.CHAVE = :CHAVEGNRE AND G.ATIVO=1 AND G.TIPO=1
        INTO :ITEMCHAVE, :TOTITENS, :QTDE, :CONVER, :TOTNF,
        :ANTPREVENDA, :CUSTOUNIT, :CUSTMEDANT,  :CHAVEPROD,
        :NUMGNRE, :NLITEM, :CHAVEEMPRESAPRODALT, :CHAVEITEMPRODALT, :CUSTOITEMNFENTRADA,
        :SCHAVETABELAPRECO
        DO BEGIN
            CHAVEITEM = :ITEMCHAVE;
            QTDEITENS = :QTDE;
            ANTPRECOVENDA = :ANTPREVENDA;
            CUSTOUNITARIO = :CUSTOUNIT;
            CHAVEPRODUTO = :CHAVEPROD;
            NUMEROGNRE = :NUMGNRE;
            TOTALITENS = :TOTITENS;
            CONVERSAO = :CONVER;
            TOTALNF = :TOTNF;
            CUSTOMEDIOANT = :CUSTMEDANT;
            NL =:NLITEM;
            CHAVEEMPALT = :CHAVEEMPRESAPRODALT;
            CHAVEPRODALT = :CHAVEITEMPRODALT;
            CUSTOITEMNF  = :CUSTOITEMNFENTRADA;
            SUSPEND;
        END
    END
   /*
   CHAMADAS :

   RATEIOGNRE : para retornar itens da gnre/dare

   */
END^


ALTER PROCEDURE RETORNARPERCTABDESCONTOS (
    CHAVETABELA INTEGER,
    VPERCENT01 NUMERIC(18,6),
    VPERCENT02 NUMERIC(18,6),
    VPERCENT03 NUMERIC(18,6),
    VPERCENT04 NUMERIC(18,6))
RETURNS (
    VPERC01 NUMERIC(18,6),
    VPERC02 NUMERIC(18,6),
    ALTERARPRECOMINIMO CHAR(1),
    VPERC03 NUMERIC(18,6),
    VTIPO INTEGER,
    VPERC04 NUMERIC(18,6))
AS
BEGIN
    SELECT CASE WHEN COALESCE(:VPERCENT01,0) = 0 THEN COALESCE(PERC01,0) ELSE :VPERCENT01 END , CASE WHEN COALESCE(:VPERCENT02,0)=0 THEN COALESCE(PERC02,0) ELSE :VPERCENT02 END,
    CASE WHEN COALESCE(:VPERCENT03,0) =0 THEN COALESCE(PERC03,0) ELSE :VPERCENT03 END , CASE WHEN COALESCE(:VPERCENT04,0)=0 THEN COALESCE(PERC04,0) ELSE :VPERCENT04 END,
    TIPO, ALTERARPRECOMINIMO FROM TABELADESCONTOS
    WHERE (ATIVO=1) AND (CHAVE=:CHAVETABELA)
    INTO :VPERC01, :VPERC02, :VPERC03, :VPERC04, :VTIPO, :ALTERARPRECOMINIMO;
  SUSPEND;
END^


ALTER PROCEDURE RETORNARSALDOESTDPTO (
    ECHAVEPRODUTO INTEGER,
    ECHAVEDPTOESTOQUE INTEGER,
    ETIPOMOVIMENTACAO INTEGER)
RETURNS (
    SSALDOESTOQUE NUMERIC(14,3),
    SSALDODPTOEST NUMERIC(14,3),
    STEMREG CHAR(1))
AS
declare variable VCHAVEDPTOESTOQUEINT integer;
declare variable VSALDOEST numeric(14,3);
declare variable VSALDODPTO numeric(14,3);
BEGIN
   STEMREG = 'N';
   FOR SELECT
     PD.CHAVEDPTOESTOQUE,
     CASE WHEN :ETIPOMOVIMENTACAO IN (0,1) THEN COALESCE(PE.SALDOPOSSEPROPRIA,0)
        WHEN :ETIPOMOVIMENTACAO = 2 THEN (COALESCE(PE.SALDODETERCEIROS,0))
     END AS SALDOEST,
     PD.SALDO AS SALDODPTO
     FROM PRODUTODPTOESTOQUE PD
     INNER JOIN PRODUTOESTOQUE PE ON (PE.CHAVEPRODUTO=PD.CHAVEPRODUTO)
     INNER JOIN DPTOESTOQUE DE ON (DE.CHAVE=:ECHAVEDPTOESTOQUE)
     WHERE PD.CHAVEPRODUTO=:ECHAVEPRODUTO AND PD.CHAVEDPTOESTOQUE=:ECHAVEDPTOESTOQUE
     AND PD.CHAVEEMPRESA=DE.CHAVEEMPRESA AND PE.CHAVEEMPRESA=DE.CHAVEEMPRESA
   INTO :VCHAVEDPTOESTOQUEINT, :VSALDOEST, :VSALDODPTO DO BEGIN
       SSALDOESTOQUE = COALESCE(:SSALDOESTOQUE,0)+COALESCE(:VSALDOEST,0);
       IF (:VCHAVEDPTOESTOQUEINT = :ECHAVEDPTOESTOQUE) THEN
          SSALDODPTOEST = :VSALDODPTO;
       STEMREG = 'S';
   END
   SUSPEND;
END^


ALTER PROCEDURE RETORNARVALORESTABELADESCONTO (
    VTIPO INTEGER,
    VPERC01 NUMERIC(18,6),
    VPERC02 NUMERIC(18,6),
    VPERC03 NUMERIC(18,6),
    VPERC04 NUMERIC(18,6),
    PRECOVENDAORIGINAL NUMERIC(18,6),
    ALTERARPRECOMINIMO CHAR(1),
    PRECOVENDAMINIMO NUMERIC(18,6))
RETURNS (
    PRECOMINIMO NUMERIC(18,6),
    PRECOVENDA NUMERIC(18,6))
AS
BEGIN
    PRECOVENDA = 0; PRECOMINIMO=0;
    -- SE FOR DESCONTO
    IF (:VTIPO = 0) THEN BEGIN
        -- APLICA OS PERCENTUAIS DE DESCONTOS
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL - (PRECOVENDAORIGINAL/100)*:VPERC01;
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL - (PRECOVENDAORIGINAL/100)*:VPERC02;
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL - (PRECOVENDAORIGINAL/100)*:VPERC03;
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL - (PRECOVENDAORIGINAL/100)*:VPERC04;
        -- SE ALTERA O PRECO MINIMO JUNTO, APLICA OS DESCONTOS TAMBEM
        IF (:ALTERARPRECOMINIMO = 'S') THEN BEGIN
            PRECOVENDAMINIMO = PRECOVENDAMINIMO - (PRECOVENDAMINIMO/100)*:VPERC01;
            PRECOVENDAMINIMO = PRECOVENDAMINIMO - (PRECOVENDAMINIMO/100)*:VPERC02;
            PRECOVENDAMINIMO = PRECOVENDAMINIMO - (PRECOVENDAMINIMO/100)*:VPERC03;
            PRECOVENDAMINIMO = PRECOVENDAMINIMO - (PRECOVENDAMINIMO/100)*:VPERC04;
        END
    END
    IF (:VTIPO = 1) THEN BEGIN
        -- SENAO APLICA OS ACRESCIMOS
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL + (PRECOVENDAORIGINAL/100)*:VPERC01;
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL + (PRECOVENDAORIGINAL/100)*:VPERC02;
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL + (PRECOVENDAORIGINAL/100)*:VPERC03;
        PRECOVENDAORIGINAL = PRECOVENDAORIGINAL + (PRECOVENDAORIGINAL/100)*:VPERC04;
        -- SE ALTERA O PRECO MINIMO JUNTO, APLICA OS ACRESCIMOS TAMBEM
        IF (:ALTERARPRECOMINIMO = 'S') THEN BEGIN
            PRECOVENDAMINIMO = PRECOVENDAMINIMO + (PRECOVENDAMINIMO/100)*:VPERC01;
            PRECOVENDAMINIMO = PRECOVENDAMINIMO + (PRECOVENDAMINIMO/100)*:VPERC02;
            PRECOVENDAMINIMO = PRECOVENDAMINIMO + (PRECOVENDAMINIMO/100)*:VPERC03;
            PRECOVENDAMINIMO = PRECOVENDAMINIMO + (PRECOVENDAMINIMO/100)*:VPERC04;
        END
    END
    IF (:VTIPO = 2) THEN BEGIN
        -- PRECO MINIMO
        IF (:PRECOVENDAMINIMO > 0) THEN
            PRECOVENDAORIGINAL = :PRECOVENDAMINIMO;
    END
    PRECOVENDA  = :PRECOVENDAORIGINAL;
    PRECOMINIMO = :PRECOVENDAMINIMO;
  SUSPEND;
END^


ALTER PROCEDURE TMSDUPLICARFRETES (
    CHAVEFRETE INTEGER,
    CHAVEEMPRESA INTEGER,
    CHAVEUSUARIO INTEGER,
    ENLATUAL DOUBLE PRECISION)
RETURNS (
    CHAVEFINAL INTEGER)
AS
declare variable CHAVEGENFRETE integer;
declare variable CONHECIMENTO integer;
declare variable CHAVESERIE integer;
declare variable CHAVECTRC integer;
declare variable DATASAIDA date;
declare variable DATAENTREGA date;
declare variable HODOMETROSAIDA numeric(14,3);
declare variable HODOMETROENTREGA numeric(14,3);
declare variable CHAVEREMETENTE integer;
declare variable CHAVEDESTINATARIO integer;
declare variable SERIE varchar(3);
declare variable SUBSERIE varchar(3);
declare variable MODELO varchar(2);
declare variable NUMCTRC varchar(9);
declare variable EMISSAO date;
declare variable TOTALFRETE numeric(18,6);
declare variable BASECOMISSAO numeric(18,6);
declare variable ADIANTAMENTOMOTORISTA numeric(18,6);
declare variable SALDO numeric(18,6);
declare variable CHAVECIDCOLETA integer;
declare variable CHAVECIDENTREGA integer;
declare variable CHAVEADIDEV integer;
declare variable CHAVETRANSPORTADOR integer;
declare variable CHAVERECEBER integer;
declare variable CHAVEGENITEM integer;
declare variable CHAVEITEMANT integer;
BEGIN
    CHAVEGENFRETE = GEN_ID(GEN_TMSFRETES_ID,1);
    INSERT INTO TMSFRETES
        (CHAVE, ATIVO, CHAVEEMPRESA, CODIGO, SITUACAO, EMISSAO, HORAEMISSAO, DATASAIDA,
        HORASAIDA, DATACHEGADA, HORACHEGADA, CHAVEUSUARIO, CHAVEVEICULO, HODOMETROINICIAL,
        HODOMETROFINAL, CHAVEMOTORISTA, COMISSAOEXTRA, OBS, NL, TOTALCTRC, TOTALCOMISSAO,
        TOTALDESPESAS, TOTALFRETE, TOTALBASECOMISSAO, TOTALDEVOLUCAO, TOTALADIANTAMENTO,
        TOTALDESPPAGASMOTORISTA, ADIANTDEVOLVER, SALDOADIANTDEVOL, TOTALOUTRASRECEITAS,
        TOTALCONTRATOS, DESPCOMBPAGASMOTORISTA)
    SELECT :CHAVEGENFRETE, 1, :CHAVEEMPRESA, LPAD(:CHAVEGENFRETE, 6, 0), 0, 'NOW', CURRENT_TIMESTAMP, DATASAIDA,
        HORASAIDA, DATACHEGADA, HORACHEGADA, :CHAVEUSUARIO, CHAVEVEICULO, HODOMETROINICIAL,
        HODOMETROFINAL, CHAVEMOTORISTA, COMISSAOEXTRA, OBS, :ENLATUAL, TOTALCTRC, TOTALCOMISSAO,
        TOTALDESPESAS, TOTALFRETE, TOTALBASECOMISSAO, TOTALDEVOLUCAO, TOTALADIANTAMENTO,
        TOTALDESPPAGASMOTORISTA, ADIANTDEVOLVER, SALDOADIANTDEVOL, TOTALOUTRASRECEITAS,
        TOTALCONTRATOS, DESPCOMBPAGASMOTORISTA
    FROM TMSFRETES
    WHERE (CHAVE=:CHAVEFRETE);
    FOR SELECT CHAVE, CONHECIMENTO, CHAVESERIE, CHAVECTRC, DATASAIDA,
        DATAENTREGA, HODOMETROSAIDA, HODOMETROENTREGA, CHAVEREMETENTE, CHAVEDESTINATARIO,
        SERIE, SUBSERIE, MODELO, NUMCTRC, EMISSAO, TOTALFRETE, BASECOMISSAO,
        ADIANTAMENTOMOTORISTA, SALDO, CHAVECIDCOLETA, CHAVECIDENTREGA, CHAVEADIDEV,
        CHAVETRANSPORTADOR, CHAVERECEBER
    FROM TMSFRETESITENSCTRC
    WHERE (ATIVO=1) AND (CHAVEFRETE=:CHAVEFRETE)
    INTO :CHAVEITEMANT, :CONHECIMENTO, :CHAVESERIE, :CHAVECTRC, :DATASAIDA,
        :DATAENTREGA, :HODOMETROSAIDA, :HODOMETROENTREGA, :CHAVEREMETENTE, :CHAVEDESTINATARIO,
        :SERIE, :SUBSERIE, :MODELO, :NUMCTRC, :EMISSAO, :TOTALFRETE, :BASECOMISSAO,
        :ADIANTAMENTOMOTORISTA, :SALDO, :CHAVECIDCOLETA, :CHAVECIDENTREGA, :CHAVEADIDEV,
        :CHAVETRANSPORTADOR, :CHAVERECEBER
    DO BEGIN
        CHAVEGENITEM = GEN_ID(GEN_TMSFRETESITENSCTRC_ID,1);
        INSERT INTO TMSFRETESITENSCTRC
            (CHAVE, ATIVO, CHAVEEMPRESA, CHAVEFRETE, CONHECIMENTO, CHAVESERIE, CHAVECTRC, DATASAIDA,
            DATAENTREGA, HODOMETROSAIDA, HODOMETROENTREGA, CHAVEREMETENTE, CHAVEDESTINATARIO,
            SERIE, SUBSERIE, MODELO, NUMCTRC, EMISSAO, NL, TOTALFRETE, BASECOMISSAO,
            ADIANTAMENTOMOTORISTA, SALDO, CHAVECIDCOLETA, CHAVECIDENTREGA, CHAVEADIDEV,
            CHAVETRANSPORTADOR, CHAVERECEBER)
        SELECT :CHAVEGENITEM, 1, :CHAVEEMPRESA, :CHAVEGENFRETE, :CONHECIMENTO, :CHAVESERIE, :CHAVECTRC, :DATASAIDA,
            :DATAENTREGA, :HODOMETROSAIDA, :HODOMETROENTREGA, :CHAVEREMETENTE, :CHAVEDESTINATARIO,
            :SERIE, :SUBSERIE, :MODELO, :NUMCTRC, :EMISSAO, :ENLATUAL, :TOTALFRETE, :BASECOMISSAO,
            :ADIANTAMENTOMOTORISTA, :SALDO, :CHAVECIDCOLETA, :CHAVECIDENTREGA, :CHAVEADIDEV,
            :CHAVETRANSPORTADOR, 0
        FROM TMSFRETESITENSCTRC
        WHERE (ATIVO=1) AND (CHAVEFRETE=:CHAVEFRETE) AND (CHAVE=:CHAVEITEMANT);
        IF (:CHAVERECEBER > 0) THEN BEGIN
            UPDATE TMSFRETESITENSCTRC SET
            CHAVERECEBER = (SELECT CHAVERECFINAL FROM TMSGERARRECEBERFRETES(:CHAVEGENITEM, :CHAVEEMPRESA, 0, :CHAVEUSUARIO))
            WHERE (CHAVE=:CHAVEGENITEM);
        END
    END
    INSERT INTO TMSFRETESITENSCONTRATO
        (ATIVO, CHAVEEMPRESA, CHAVEFRETE, NROCONTRATO, CHAVECLIFOR,
        DATACONTRATO, CHAVECIDCOLETA, CHAVECIDENTREGA, TOTALFRETE, PEDAGIOREC,
        VLRADIANTAMENTO, OUTRASDESPESAS, SALDO, NL, GERARCOMISSAO, BASECOMISSAO)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENFRETE, NROCONTRATO, CHAVECLIFOR,
        DATACONTRATO, CHAVECIDCOLETA, CHAVECIDENTREGA, TOTALFRETE, PEDAGIOREC,
        VLRADIANTAMENTO, OUTRASDESPESAS, SALDO, :ENLATUAL, GERARCOMISSAO, BASECOMISSAO
    FROM TMSFRETESITENSCONTRATO
    WHERE (ATIVO=1) AND (CHAVEFRETE=:CHAVEFRETE);
    INSERT INTO TMSFRETESITENSDESP
        (ATIVO, CHAVEEMPRESA, CHAVEFRETE, CHAVEDESPESA, QTDE,
        VLRUNIT, TOTAL, PAGAMENTO, NL, HODOMETRODESP, DATADESP,
        DOCUMENTODESP, DESCPORC, DESCVLR, CHAVECLIFOR)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENFRETE, CHAVEDESPESA, QTDE,
        VLRUNIT, TOTAL, PAGAMENTO, :ENLATUAL, HODOMETRODESP, DATADESP,
        DOCUMENTODESP, DESCPORC, DESCVLR, CHAVECLIFOR
    FROM TMSFRETESITENSDESP
    WHERE (ATIVO=1) AND (CHAVEFRETE=:CHAVEFRETE);
    INSERT INTO TMSFRETESITENSADIDEV
        (ATIVO, CHAVEEMPRESA, CHAVEFRETE, CHAVEADIDEV, TIPO,
        NL, DATA, TOTAL, CHAVEITEMFRETE, OBS)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENFRETE, CHAVEADIDEV, TIPO,
        :ENLATUAL, DATA, TOTAL, CHAVEITEMFRETE, OBS
    FROM TMSFRETESITENSADIDEV
    WHERE (ATIVO=1) AND (CHAVEFRETE=:CHAVEFRETE);
    INSERT INTO TMSFRETESITENSOUTRREC
        (ATIVO, CHAVEEMPRESA, CHAVEFRETE, DESCRICAO, DATA,
        TOTAL, NL, GERARCOMISSAO, BASECOMISSAO)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENFRETE, DESCRICAO, DATA,
        TOTAL, :ENLATUAL, GERARCOMISSAO, BASECOMISSAO
    FROM TMSFRETESITENSOUTRREC
    WHERE (ATIVO=1) AND (CHAVEFRETE=:CHAVEFRETE);
    INSERT INTO TMSFRETESITENSTACOGRAFO
        (ATIVO, CHAVEEMPRESA, CHAVEFRETE, DATACOLOCACAO,
        CHAVECIDADEDEST, KMINICIAL, KMFINAL, DISTANCIA,
        VELOCIDADE, NL, OBS)
    SELECT 1, :CHAVEEMPRESA, :CHAVEGENFRETE, DATACOLOCACAO,
        CHAVECIDADEDEST, KMINICIAL, KMFINAL, DISTANCIA,
        VELOCIDADE, :ENLATUAL, OBS
    FROM TMSFRETESITENSTACOGRAFO
    WHERE (ATIVO=1) AND (CHAVEFRETE=:CHAVEFRETE);
    CHAVEFINAL = CHAVEGENFRETE;
    SUSPEND;
END^


ALTER PROCEDURE TMSDUPLICARMANIFESTO (
    CHAVEMANIFESTO INTEGER,
    CHAVEEMPRESA INTEGER,
    ENLATUAL DOUBLE PRECISION)
RETURNS (
    CHAVEFINAL INTEGER)
AS
declare variable CHAVEGENMANIFESTO integer;
BEGIN
    CHAVEGENMANIFESTO = GEN_ID(GEN_TMSMANIFESTO_ID,1);
    INSERT INTO TMSMANIFESTO
        (CHAVE, ATIVO, CHAVEEMPRESA, CHAVEACESSOMDFE, CHAVESERIE, SERIE, SUBSERIE, MODELO,
        NROMANIFESTO, EMISSAO, HORAEMISSAO, EMISSAOMDFE, SITUACAO, DATASAIDA, DATACHEGADA,
        CHAVEVEICULO, CHAVEVEICULOSVINC1, CHAVEVEICULOSVINC2, CHAVEVEICULOSVINC3,
        CHAVEMOTORISTA, CHAVEUFCARREGAMENTO, CHAVEUFDESCARREGAMENTO, NL, OBS, QTDECTE, QTDECTRC,
        PESOBRUTOTOTAL, TIPOEMISSAO, CNPJRESPPEDAGIO, CNPJFORNECPEDAGIO, NROCOMPPEDAGIO, CATEGCOMBVEIC,
        CHAVECIDENCERRAMENTO, QTDENFE, VLRTOTALMERC, TIPOEMITENTE, RESPONSAVELSEGURO, TPCARGA, PRODPRED, CODBARRAS, NCM,
        NOMERESPPAG, CNPJCPFRESPPAG, CNPJBANCOPAG, AGENCIABANCOPAG, CONTABANCOPAG, TIPOPAG, CHAVECONDPGTO)
    SELECT :CHAVEGENMANIFESTO, 1, :CHAVEEMPRESA, '', CHAVESERIE, SERIE, SUBSERIE, MODELO,
        NROMANIFESTO, NULL, NULL, NULL, 0, DATASAIDA, DATACHEGADA,
        CHAVEVEICULO, CHAVEVEICULOSVINC1, CHAVEVEICULOSVINC2, CHAVEVEICULOSVINC3,
        CHAVEMOTORISTA, CHAVEUFCARREGAMENTO, CHAVEUFDESCARREGAMENTO, :ENLATUAL, OBS, QTDECTE, QTDECTRC,
        PESOBRUTOTOTAL, TIPOEMISSAO, CNPJRESPPEDAGIO, CNPJFORNECPEDAGIO, NROCOMPPEDAGIO, CATEGCOMBVEIC,
        CHAVECIDENCERRAMENTO, QTDENFE, VLRTOTALMERC, TIPOEMITENTE, RESPONSAVELSEGURO, TPCARGA, PRODPRED, CODBARRAS, NCM,
        NOMERESPPAG, CNPJCPFRESPPAG, CNPJBANCOPAG, AGENCIABANCOPAG, CONTABANCOPAG, TIPOPAG, CHAVECONDPGTO
    FROM TMSMANIFESTO
    WHERE (CHAVE=:CHAVEMANIFESTO);
    INSERT INTO TMSMANIFESTOITENSCTRC
        (ATIVO, CHAVEEMPRESA, CHAVECTRC, CHAVEMANIFESTO, NL)
    SELECT 1, CHAVEEMPRESA, CHAVECTRC, :CHAVEGENMANIFESTO, :ENLATUAL
    FROM TMSMANIFESTOITENSCTRC
    WHERE (ATIVO=1) AND (CHAVEMANIFESTO=:CHAVEMANIFESTO);
    INSERT INTO TMSMANIFESTOITENSNF
        (ATIVO, CHAVEEMPRESA, CHAVENF, CHAVEMANIFESTO, NL, CHAVEACESSO, ORIGEMDOC, CHAVECLIFOR)
    SELECT 1, CHAVEEMPRESA, CHAVENF, :CHAVEGENMANIFESTO, :ENLATUAL, CHAVEACESSO, ORIGEMDOC, CHAVECLIFOR
    FROM TMSMANIFESTOITENSNF
    WHERE (ATIVO=1) AND (CHAVEMANIFESTO=:CHAVEMANIFESTO);
    INSERT INTO TMSMANIFESTOCIDCARDESC
    (ATIVO, CHAVEEMPRESA, CHAVECIDCARREG, CHAVECIDDESCARREG, CHAVEMANIFESTO, CEPCARREG, CEPDESCARREG)
    SELECT 1, CHAVEEMPRESA, CHAVECIDCARREG, CHAVECIDDESCARREG, :CHAVEGENMANIFESTO, CEPCARREG, CEPDESCARREG
    FROM TMSMANIFESTOCIDCARDESC
    WHERE (ATIVO=1) AND (CHAVEMANIFESTO=:CHAVEMANIFESTO);
    INSERT INTO TMSMANIFESTOSEGURO
    (ATIVO, CHAVEEMPRESA, CHAVEMANIFESTO, CNPJCPFRESPSEGURO, NOMESEGURADORA, CNPJSEGURADORA, NUMEROAPOLICE, NUMEROAVERBACAO)
    SELECT 1, CHAVEEMPRESA, :CHAVEGENMANIFESTO, CNPJCPFRESPSEGURO, NOMESEGURADORA, CNPJSEGURADORA, NUMEROAPOLICE, NUMEROAVERBACAO
    FROM TMSMANIFESTOSEGURO
    WHERE (ATIVO=1) AND (CHAVEMANIFESTO=:CHAVEMANIFESTO);
    INSERT INTO TMSMANIFESTOCIOT
    (ATIVO, CHAVEEMPRESA, CHAVEMANIFESTO, CNPJCPFRESPCIOT, CIOT)
    SELECT 1, CHAVEEMPRESA, :CHAVEGENMANIFESTO, CNPJCPFRESPCIOT, CIOT
    FROM TMSMANIFESTOCIOT
    WHERE (ATIVO=1) AND (CHAVEMANIFESTO=:CHAVEMANIFESTO);
    INSERT INTO TMSMANIFESTOPRODPERIG
    (ATIVO, CHAVEEMPRESA, CHAVEMANIFESTO, CHAVEPRODPERIG, CHAVENF, CHAVECTRC)
    SELECT 1, CHAVEEMPRESA, :CHAVEGENMANIFESTO, CHAVEPRODPERIG, CHAVENF, CHAVECTRC
    FROM TMSMANIFESTOPRODPERIG
    WHERE (ATIVO=1) AND (CHAVEMANIFESTO=:CHAVEMANIFESTO);
    
    INSERT INTO TMSMANIFESTOCOMPPAG
    (ATIVO, CHAVEEMPRESA, CHAVEMANIFESTO, TIPO, NOME, VALOR)
    SELECT 1, CHAVEEMPRESA, :CHAVEGENMANIFESTO, TIPO, NOME, VALOR
    FROM TMSMANIFESTOCOMPPAG
    WHERE (ATIVO=1) AND (CHAVEMANIFESTO=:CHAVEMANIFESTO);
    
    CHAVEFINAL = :CHAVEGENMANIFESTO;
    SUSPEND;
END^


ALTER PROCEDURE TMSGERARPAGARDESPESAS (
    ECHAVEDESPESA INTEGER,
    ECHAVEEMPPAGAR INTEGER,
    ENL DOUBLE PRECISION,
    ECHAVEUSUARIO INTEGER)
AS
declare variable VAUTOINC integer;
BEGIN
    VAUTOINC = GEN_ID(GEN_PAGAR_ID,1);
    INSERT INTO PAGAR(CHAVE, CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
        DATACONTA, DATAENTRADA, DESCRICAO, DOCUMENTO,
        PARCELA, TIPO, TOTPARC, VALOR, VENCIMENTO, COMPETENCIA,
        STATUS, NL, ORIGEM, CHAVEUSUARIOCAD, CHAVEUSUARIOALT, OBS)
    SELECT :VAUTOINC, :ECHAVEEMPPAGAR, 2, D.CHAVECLIFOR, 2,
        D.DATA, D.DATA, SUBSTRING('REF. DESPESA '||D.CODIGO||' DESCRICAO: '||D.DESCRICAO FROM 1 FOR 100), D.CODIGO,
        D.PARCELA, 0, D.TOTPARC, D.TOTAL, D.VENCIMENTO,
        SUBSTRING(CAST(D.VENCIMENTO AS VARCHAR(10)) FROM 6 FOR 2)||'/'|| SUBSTRING(CAST(D.VENCIMENTO AS VARCHAR(10)) FROM 1 FOR 4),
        1, :ENL, 6, :ECHAVEUSUARIO, :ECHAVEUSUARIO, D.OBS
    FROM TMSDESPESAS D
    WHERE D.CHAVE = :ECHAVEDESPESA;
    UPDATE TMSDESPESAS SET
    CHAVEPAGAR=:VAUTOINC
    WHERE CHAVE=:ECHAVEDESPESA;
END^


ALTER PROCEDURE TMSGERARRECEBERFRETES (
    CHAVEITEMFRETE INTEGER,
    CHAVEEMPRESA INTEGER,
    CHAVERECEBER INTEGER,
    CHAVEUSUARIO INTEGER)
RETURNS (
    CHAVERECFINAL INTEGER)
AS
declare variable CHAVECLIFOR integer;
declare variable EMISSAO date;
declare variable DESCRICAO varchar(100);
declare variable NUMCTRC varchar(9);
declare variable SALDO numeric(18,6);
declare variable NL double precision;
BEGIN
    SELECT FI.CHAVETRANSPORTADOR,FI.EMISSAO, 'FRETE PRESTADO A TERCEIROS N. '||FI.NUMCTRC AS DESCRICAO,
    FI.NUMCTRC, FI.SALDO, FI.NL
    FROM TMSFRETESITENSCTRC FI
    LEFT JOIN CLIFOR C ON C.CHAVE=FI.CHAVETRANSPORTADOR
    WHERE FI.CHAVE = :CHAVEITEMFRETE
    INTO :CHAVECLIFOR, :EMISSAO, :DESCRICAO, :NUMCTRC, :SALDO, :NL;
    IF (:CHAVERECEBER=0) THEN BEGIN
        -- GERAR NOVA CHAVE
        CHAVERECEBER = GEN_ID(GEN_RECEBER_ID,1);
        INSERT INTO RECEBER(CHAVE,CHAVEEMPRESA, CHAVECENTROCTO, CHAVECLIFOR, CHAVEPLANOCTO,
        DATACONTA, DESCRICAO, DOCUMENTO, PARCELA, TIPO, TOTPARC, VALOR,
        VENCIMENTO, STATUS, NL, ORIGEM, VALORPRODUTO, VALORSERVICO, CHAVEDOC,
        ACRESCIMORENEGOCIADO, VALORBAIXADO, CHAVEUSUARIOCAD, CHAVEUSUARIOALT)
        VALUES (:CHAVERECEBER, :CHAVEEMPRESA, 1, :CHAVECLIFOR, (SELECT COALESCE(CHAVEPLANOCONTA,1) FROM CONFIGCAIXA WHERE (CHAVE=24)),
        :EMISSAO, :DESCRICAO, :NUMCTRC, 1, 0, 1, :SALDO, :EMISSAO, 1, :NL, 12, 0, :SALDO, :CHAVEITEMFRETE,
        0, 0, :CHAVEUSUARIO, :CHAVEUSUARIO);
    END ELSE BEGIN
        UPDATE RECEBER R SET
        R.CHAVEEMPRESA=:CHAVEEMPRESA, R.CHAVECLIFOR=:CHAVECLIFOR,
        R.DATACONTA=:EMISSAO, R.DESCRICAO=:DESCRICAO,
        R.DOCUMENTO=:NUMCTRC, R.VALOR=:SALDO, R.VALORSERVICO=:SALDO, R.VENCIMENTO=:EMISSAO,
        CHAVEUSUARIOALT=:CHAVEUSUARIO
        WHERE R.CHAVE = :CHAVERECEBER;
    END
    CHAVERECFINAL = :CHAVERECEBER;
    /*
    CHAMADAS:
    FRMFRETES - GERAR RECEBER DO FRETE

    */
    SUSPEND;
END^


ALTER PROCEDURE TRANSFERIRITENSPV (
    CHAVEITEMORIG INTEGER,
    MESACOMANDADEST VARCHAR(10),
    ECHAVEDOCDEST INTEGER,
    CHAVEDOCORIG INTEGER,
    CHAVEEMPRESA INTEGER,
    TIPODOC INTEGER,
    PERMITIRZERADAS CHAR(1),
    QTDETRANSF NUMERIC(15,3),
    EXCLUIRPVORIGEM CHAR(1),
    CHAVEEMPRECOMPENSA INTEGER,
    EATLZPRECOITEM CHAR(1))
RETURNS (
    RESULTADO CHAR(1))
AS
declare variable CHAVEDOCDEST integer;
declare variable NLDEST double precision;
declare variable VLRTOTITEM numeric(18,6);
declare variable MESACOMANDAORIG varchar(20);
declare variable INDICE integer;
declare variable TOTALPV numeric(18,6);
declare variable DESCVLR numeric(18,2);
declare variable GORJETAPERCDOCORIG numeric(10,4);
declare variable DESCPERCDOCORIG numeric(10,4);
declare variable GORJETAVLR numeric(18,2);
declare variable GORJETAPERCDOCDEST numeric(10,4);
declare variable DESCPORCDOCDEST numeric(10,4);
declare variable TIPOPEDIDO smallint;
declare variable BRSTAXAENTREGA numeric(18,6);
declare variable BRSTAXAENTREGADOR numeric(18,6);
declare variable DATADEST date;
declare variable HORADEST time;
declare variable DATAORIG date;
declare variable HORAORIG time;
declare variable BRSTEMRECOMPENSA char(1);
declare variable CHAVEPRODUTOPROMOCAO integer;
declare variable QTDEPROMOCAO decimal(14,3);
declare variable BRSTAXACOUVERT numeric(18,6);
declare variable TIPODOCDESTINO integer;
BEGIN
    IF (CHAR_LENGTH(:MESACOMANDADEST) IN (1, 2, 3, 4, 5, 6)) THEN
        MESACOMANDADEST = '8888' || LPAD(MESACOMANDADEST, 6, 0);
    SELECT PV.CHAVE, PV.NL, PV.TOTALPV, PV.BRSGORJETAGARCOMPERC, PV.DESCPORCPROD, PV.BRSTIPOPEDIDO,
    PV.DATAPV, PV.HORA, PV.TIPODOCDESTINO
    FROM PREVENDA PV
    INNER JOIN PREVENDA PV1 ON (CASE WHEN (PV.TIPODOCDESTINO=0) THEN PV.CHAVE ELSE PV.CHAVEDOCDESTINO END=PV1.CHAVE)
    WHERE (PV.ATIVO=1) AND (PV.CHAVEEMPRESA=:CHAVEEMPRESA) AND (PV.TIPO=:TIPODOC)
    AND ((PV.TIPODOCDESTINO=0) OR ((PV.TIPODOCDESTINO=4) AND (PV1.TIPODOCDESTINO=0) AND (COALESCE(PV.TOTALPV,0) > 0)))
    AND CASE WHEN COALESCE(:ECHAVEDOCDEST,0) > 0 THEN (PV.CHAVE = :ECHAVEDOCDEST) ELSE (PV.CODIGOREST=:MESACOMANDADEST) END
    INTO :CHAVEDOCDEST, :NLDEST, :TOTALPV, :GORJETAPERCDOCDEST, :DESCPORCDOCDEST, :TIPOPEDIDO,
    :DATADEST, :HORADEST, :TIPODOCDESTINO;
    IF (COALESCE(:CHAVEDOCDEST,0) = 0) THEN BEGIN
        RESULTADO = 'N';
        SUSPEND;
        EXIT;
    END
    IF ((:EXCLUIRPVORIGEM='S') AND (:CHAVEDOCORIG = :CHAVEDOCDEST)) THEN BEGIN
        RESULTADO = '=';
        SUSPEND;
        EXIT;
    END
    IF (:TIPODOCDESTINO = 4) THEN BEGIN
        RESULTADO = 'A';
        SUSPEND;
        EXIT;
    END
    IF ((:TOTALPV = 0) AND (:PERMITIRZERADAS='N')) THEN BEGIN
        RESULTADO = '0';
        SUSPEND;
        EXIT;
    END
    IF ((:EXCLUIRPVORIGEM='S') AND (:TIPOPEDIDO = 1)) THEN BEGIN
        RESULTADO = 'T';
        SUSPEND;
        EXIT;
    END
    SELECT CASE WHEN TIPO=1 THEN NUMEROPV ELSE CODIGOREST END, BRSGORJETAGARCOMPERC, DESCPORCPROD, BRSTAXAENTREGA,
    BRSTAXACOUVERT, BRSTAXAENTREGADOR, DATAPV, HORA
    FROM PREVENDA
    WHERE (CHAVE=:CHAVEDOCORIG)
    INTO :MESACOMANDAORIG, :GORJETAPERCDOCORIG, :DESCPERCDOCORIG, :BRSTAXAENTREGA,
    :BRSTAXACOUVERT, :BRSTAXAENTREGADOR, :DATAORIG, :HORAORIG;
    SELECT COALESCE(MAX(INDICE)+1,1) FROM ITENSPREVENDA I
    WHERE (I.CHAVEPREVENDA=:CHAVEDOCDEST)
    INTO :INDICE;
    EXECUTE PROCEDURE DIVIDIRITEMPV(CHAVEDOCDEST, 'S', CHAVEITEMORIG, QTDETRANSF, NLDEST, MESACOMANDAORIG, EXCLUIRPVORIGEM, INDICE, CHAVEEMPRECOMPENSA, EATLZPRECOITEM);
    IF (:EXCLUIRPVORIGEM='S') THEN BEGIN
        VLRTOTITEM = 0;
        SELECT COALESCE(SUM(VLRTOTAL),0) FROM ITENSPREVENDA
        WHERE (ATIVO=1) AND (CHAVEPREVENDA=:CHAVEDOCORIG)
        INTO :VLRTOTITEM;
        BRSTEMRECOMPENSA = 'N';
        FOR SELECT CHAVEPRODUTOPROMOCAO, MIN(QTDEPROMOCAO) FROM BRSRECOMPENSA WHERE ATIVO=1 GROUP BY CHAVEPRODUTOPROMOCAO, QTDEPROMOCAO
        INTO :CHAVEPRODUTOPROMOCAO, :QTDEPROMOCAO DO BEGIN
            IF ((SELECT SUM(QTDE) FROM ITENSPREVENDA
                WHERE (ATIVO=1) AND (CHAVEPREVENDA=:CHAVEDOCORIG) AND (ATIVO=1) AND (CHAVEPRODUTO=:CHAVEPRODUTOPROMOCAO) AND (RECOMPENSA=1))>=:QTDEPROMOCAO) THEN BEGIN
                BRSTEMRECOMPENSA = 'S';
                BREAK;
            END
        END
        IF (:VLRTOTITEM=0) THEN BEGIN
            BRSTAXAENTREGA = 0;
            BRSTAXAENTREGADOR = 0;
            BRSTAXACOUVERT = 0;
        END
        DESCVLR = CAST((:VLRTOTITEM * :DESCPERCDOCORIG) / 100 AS NUMERIC(18,2));
        GORJETAVLR = CAST(((:VLRTOTITEM - :DESCVLR) * :GORJETAPERCDOCORIG) / 100 AS NUMERIC(18,2));
        UPDATE PREVENDA SET
        TOTALPRODUTO = :VLRTOTITEM,
        DESCVLRPROD = :DESCVLR,
        CHAVECONDPGTO = 0,
        FATURA = '',
        FORMAPGTO = 0,
        BRSGORJETAGARCOMVLR = :GORJETAVLR,
        BRSTAXAENTREGA = :BRSTAXAENTREGA,
        BRSTAXACOUVERT = :BRSTAXACOUVERT,
        BRSTAXAENTREGADOR = :BRSTAXAENTREGADOR,
        TOTALPV = :VLRTOTITEM - :DESCVLR + :GORJETAVLR + :BRSTAXAENTREGA + :BRSTAXACOUVERT,
        BRSTEMRECOMPENSA = :BRSTEMRECOMPENSA
        WHERE (CHAVE=:CHAVEDOCORIG);
    END
    VLRTOTITEM = 0;
    SELECT COALESCE(SUM(VLRTOTAL),0) FROM ITENSPREVENDA
    WHERE (ATIVO=1) AND (CHAVEPREVENDA = :CHAVEDOCDEST)
    INTO :VLRTOTITEM;
    
    
    BRSTEMRECOMPENSA = 'N';
    FOR SELECT CHAVEPRODUTOPROMOCAO, MIN(QTDEPROMOCAO) FROM BRSRECOMPENSA WHERE ATIVO=1 GROUP BY CHAVEPRODUTOPROMOCAO, QTDEPROMOCAO
    INTO :CHAVEPRODUTOPROMOCAO, :QTDEPROMOCAO DO BEGIN
        IF ((SELECT SUM(QTDE) FROM ITENSPREVENDA
            WHERE (ATIVO=1) AND (CHAVEPREVENDA=:CHAVEDOCDEST) AND (ATIVO=1) AND (CHAVEPRODUTO=:CHAVEPRODUTOPROMOCAO) AND (RECOMPENSA=1))>=:QTDEPROMOCAO) THEN BEGIN
            BRSTEMRECOMPENSA = 'S';
            BREAK;
        END
    END
    DESCVLR = CAST((:VLRTOTITEM * :DESCPORCDOCDEST) / 100 AS NUMERIC(18,2));
    GORJETAVLR = CAST((:VLRTOTITEM * :GORJETAPERCDOCDEST) / 100 AS NUMERIC(18,2));
    UPDATE PREVENDA SET
    TOTALPRODUTO = :VLRTOTITEM,
    DESCVLRPROD = :DESCVLR,
    BRSGORJETAGARCOMVLR = :GORJETAVLR,
    TOTALPV = :VLRTOTITEM - :DESCVLR + :GORJETAVLR + BRSTAXAENTREGA + BRSTAXACOUVERT,
    DATAPV = CASE WHEN :DATADEST > :DATAORIG THEN :DATAORIG ELSE DATAPV END,
    HORA = CASE WHEN :DATADEST > :DATAORIG THEN
              :HORAORIG
           ELSE
              CASE WHEN :DATADEST = :DATAORIG THEN
                  CASE WHEN :HORADEST > :HORAORIG THEN
                      :HORAORIG
                  ELSE
                      HORA
                  END
              ELSE
                  HORA
              END
           END,
    BRSTEMRECOMPENSA = :BRSTEMRECOMPENSA
    WHERE (CHAVE=:CHAVEDOCDEST);
    RESULTADO = 'S';
    SUSPEND;
    /*  CHAMADAS:
            - FRAMETOTAISBRS (CHBRS): USADA PARA TRANSFERIR ITENS ENTRE MESAS/CONTAS DE CLIENTES*/
END^


ALTER PROCEDURE UPDATESALDOESTOQUE (
    CHAVEPRODAJUSTE INTEGER)
AS
declare variable CHAVEPRODUTO integer;
declare variable SALDO numeric(18,6);
declare variable CHAVEPRODUTOCOMP integer;
declare variable CHAVEPRODUTOAGRUP integer;
declare variable CHAVEEMPRESA integer;
declare variable SOMASALDOGERAL numeric(18,6);
declare variable SOMASALDOEMTERCEIROS numeric(18,6);
declare variable SOMASALDODETERCEIROS numeric(18,6);
declare variable SOMASALDOPOSSEPROPRIA numeric(18,6);
declare variable CHAVEDPTOESTOQUE integer;
declare variable VSOMASALDORESERVADO numeric(18,6);
BEGIN
    IF (:CHAVEPRODAJUSTE = 0) THEN BEGIN
        UPDATE PRODUTO SET AGRUPADOCOMPOSTO=0
        WHERE ATIVO=1 AND COALESCE(AGRUPADOCOMPOSTO,-1) <> 0;

        -- UPDATE DOS PRODUTOS COMPOSTOS
        FOR SELECT CHAVEPRODUTO, CHAVEPRODUTOCOMP FROM BAIXAESTCOMPOSTO
        WHERE ATIVO=1 AND TIPO=0
        INTO :CHAVEPRODUTO, :CHAVEPRODUTOCOMP
        DO BEGIN
            UPDATE PRODUTO SET
            AGRUPADOCOMPOSTO = 4
            WHERE CHAVE = :CHAVEPRODUTO;
    
            UPDATE PRODUTO SET
            AGRUPADOCOMPOSTO = 2
            WHERE CHAVE=:CHAVEPRODUTOCOMP;
        END
        -- UPDATE DOS PRODUTOS AGRUPADOS
        FOR SELECT CHAVEPRODUTO, CHAVEPRODUTOAGRUP FROM BAIXAESTAGRUPADO
        WHERE ATIVO=1
        INTO :CHAVEPRODUTO, :CHAVEPRODUTOAGRUP
        DO BEGIN
            UPDATE PRODUTO SET
            AGRUPADOCOMPOSTO = 3
            WHERE CHAVE = :CHAVEPRODUTO;
    
            UPDATE PRODUTO SET
            AGRUPADOCOMPOSTO = 1
            WHERE CHAVE = :CHAVEPRODUTOAGRUP;
        END
    END


    -- FAZ A SOMA DO SALDO DAS EMPRESAS PARA SINCRONIZAR O SALDO POR EMPRESA
    IF (:CHAVEPRODAJUSTE > 0) THEN BEGIN
        FOR SELECT P.CHAVE, COALESCE(PE.CHAVEEMPRESA,0) AS CHAVEEMPRESA,
        SUM(COALESCE(E.SALDO,0)) AS SALDOGERALSUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 0 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOPOSSEPROPRIASUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 1 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOEMTERCEIROSSUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 2 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDODETERCEIROSSUM
        FROM PRODUTO P
        LEFT JOIN PRODUTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE  AND PE.ATIVO=1
        LEFT JOIN ESTOQUE E ON E.CHAVEPRODUTO = P.CHAVE AND E.ATIVO=1 AND PE.CHAVEEMPRESA = E.CHAVEEMPRESA
        WHERE P.ATIVO=1 AND
        P.CHAVE = :CHAVEPRODAJUSTE
        GROUP BY P.CHAVE, PE.CHAVEEMPRESA,
        COALESCE(PE.SALDO, 0), COALESCE(PE.SALDOEMTERCEIROS,0), COALESCE(PE.SALDODETERCEIROS,0), COALESCE(PE.SALDOPOSSEPROPRIA,0)
        INTO :CHAVEPRODUTO, :CHAVEEMPRESA,
        :SOMASALDOGERAL, :SOMASALDOPOSSEPROPRIA, :SOMASALDOEMTERCEIROS,
        :SOMASALDODETERCEIROS
        DO BEGIN

            UPDATE PRODUTOESTOQUE SET
                SALDO=:SOMASALDOGERAL,
                SALDOEMTERCEIROS=:SOMASALDOEMTERCEIROS,
                SALDODETERCEIROS=:SOMASALDODETERCEIROS,
                SALDOPOSSEPROPRIA=:SOMASALDOPOSSEPROPRIA,
                DATA=CURRENT_DATE
            WHERE CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA AND
            ((SALDO<>:SOMASALDOGERAL) or (SALDOEMTERCEIROS<>:SOMASALDOEMTERCEIROS) or (SALDODETERCEIROS<>:SOMASALDODETERCEIROS) or (SALDOPOSSEPROPRIA=:SOMASALDOPOSSEPROPRIA));
       END

        -- FAZ A SOMA DO SALDO RESERVADO DAS EMPRESAS PARA SINCRONIZAR O SALDOESTOQUE
        FOR SELECT DISTINCT
        P.CHAVE,
        ER.CHAVEEMPRESA,
        SUM(COALESCE(ER.QTDE,0)) AS QTDERESERVADO
        FROM PRODUTO P
        INNER JOIN ESTOQUERESERVADO ER ON (ER.CHAVEPRODUTO=P.CHAVE)
        LEFT JOIN PRODUTOESTOQUE PE ON (PE.CHAVEPRODUTO=P.CHAVE) AND (PE.CHAVEEMPRESA=ER.CHAVEEMPRESA)
        WHERE (P.ATIVO=1)  AND (COALESCE(P.CHAVE,0) = :CHAVEPRODAJUSTE)
        GROUP BY P.CHAVE, ER.CHAVEEMPRESA
        HAVING (SUM(COALESCE(ER.QTDE,0)) <> SUM(COALESCE(PE.SALDORESERVADO,0)))
        INTO :CHAVEPRODUTO, :CHAVEEMPRESA, :VSOMASALDORESERVADO
        DO BEGIN
            UPDATE PRODUTOESTOQUE SET
                SALDORESERVADO=:VSOMASALDORESERVADO
            WHERE CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;
        END

    END ELSE BEGIN
        FOR SELECT P.CHAVE, COALESCE(PE.CHAVEEMPRESA,0) AS CHAVEEMPRESA,
        SUM(COALESCE(E.SALDO,0)) AS SALDOGERALSUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 0 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOPOSSEPROPRIASUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 1 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOEMTERCEIROSSUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 2 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDODETERCEIROSSUM
        FROM PRODUTO P
        LEFT JOIN PRODUTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE  AND PE.ATIVO=1
        LEFT JOIN ESTOQUE E ON E.CHAVEPRODUTO = P.CHAVE AND E.ATIVO=1 AND PE.CHAVEEMPRESA = E.CHAVEEMPRESA
        WHERE P.ATIVO=1
        GROUP BY P.CHAVE, PE.CHAVEEMPRESA,
        COALESCE(PE.SALDO, 0), COALESCE(PE.SALDOEMTERCEIROS,0), COALESCE(PE.SALDODETERCEIROS,0), COALESCE(PE.SALDOPOSSEPROPRIA,0)
        HAVING (SUM(CASE E.TIPOMOVIMENTACAO WHEN 0 THEN COALESCE(E.SALDO,0) ELSE 0 END) <> COALESCE(PE.SALDOPOSSEPROPRIA,0)) OR
           (SUM(CASE E.TIPOMOVIMENTACAO WHEN 1 THEN COALESCE(E.SALDO,0) ELSE 0 END) <> COALESCE(PE.SALDOEMTERCEIROS,0)) OR
           (SUM(CASE E.TIPOMOVIMENTACAO WHEN 2 THEN COALESCE(E.SALDO,0) ELSE 0 END) <> COALESCE(PE.SALDODETERCEIROS,0)) OR
           (SUM(COALESCE(E.SALDO,0)) <> COALESCE(PE.SALDO,0))
        INTO :CHAVEPRODUTO, :CHAVEEMPRESA,
        :SOMASALDOGERAL, :SOMASALDOPOSSEPROPRIA, :SOMASALDOEMTERCEIROS,
        :SOMASALDODETERCEIROS
        DO BEGIN
            UPDATE PRODUTOESTOQUE SET
               SALDO=:SOMASALDOGERAL,
               SALDOEMTERCEIROS=:SOMASALDOEMTERCEIROS,
               SALDODETERCEIROS=:SOMASALDODETERCEIROS,
               SALDOPOSSEPROPRIA=:SOMASALDOPOSSEPROPRIA,
               DATA=CURRENT_DATE
            WHERE CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;
        END

        -- FAZ A SOMA DO SALDO RESERVADO DAS EMPRESAS PARA SINCRONIZAR O SALDOESTOQUE
        FOR SELECT DISTINCT
        P.CHAVE,
        ER.CHAVEEMPRESA,
        SUM(COALESCE(ER.QTDE,0)) AS QTDERESERVADO
        FROM PRODUTO P
        INNER JOIN ESTOQUERESERVADO ER ON (ER.CHAVEPRODUTO=P.CHAVE)
        LEFT JOIN PRODUTOESTOQUE PE ON (PE.CHAVEPRODUTO=P.CHAVE) AND (PE.CHAVEEMPRESA=ER.CHAVEEMPRESA)
        WHERE (P.ATIVO=1)
        AND (COALESCE(P.CHAVE,0) = CASE WHEN (:CHAVEPRODAJUSTE=0) THEN COALESCE(P.CHAVE,0) ELSE :CHAVEPRODAJUSTE END)
        GROUP BY P.CHAVE, ER.CHAVEEMPRESA
        HAVING (SUM(COALESCE(ER.QTDE,0)) <> SUM(COALESCE(PE.SALDORESERVADO,0)))
        INTO :CHAVEPRODUTO, :CHAVEEMPRESA, :VSOMASALDORESERVADO
        DO BEGIN
            UPDATE PRODUTOESTOQUE SET
                SALDORESERVADO=:VSOMASALDORESERVADO
            WHERE CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;
        END
    END


    -- FAZ A SOMA DO SALDO DAS EMPRESAS PARA SINCRONIZAR O SALDO POR DPTO ESTOQUE
    IF (:CHAVEPRODAJUSTE > 0) THEN BEGIN
        FOR SELECT P.CHAVE,
        COALESCE(E.CHAVEDPTOESTOQUE,0),
        SUM(COALESCE(E.SALDO,0)),
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 0 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOPOSSEPROPRIASUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 1 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOEMTERCEIROSSUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 2 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDODETERCEIROSSUM
        FROM PRODUTO P
        LEFT JOIN PRODUTODPTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE AND PE.ATIVO=1
        LEFT JOIN ESTOQUE E ON E.CHAVEPRODUTO=P.CHAVE AND E.ATIVO=1 AND PE.CHAVEDPTOESTOQUE=E.CHAVEDPTOESTOQUE AND PE.CHAVEEMPRESA=E.CHAVEEMPRESA
        WHERE P.ATIVO=1 AND
        P.CHAVE = :CHAVEPRODAJUSTE
        GROUP BY P.CHAVE, E.CHAVEDPTOESTOQUE, PE.CHAVEDPTOESTOQUE, COALESCE(PE.SALDO, 0),
        COALESCE(PE.SALDOEMTERCEIROS,0), COALESCE(PE.SALDODETERCEIROS,0), COALESCE(PE.SALDOPOSSEPROPRIA,0)
        INTO :CHAVEPRODUTO, :CHAVEDPTOESTOQUE, :SOMASALDOGERAL, :SOMASALDOPOSSEPROPRIA, :SOMASALDOEMTERCEIROS,
        :SOMASALDODETERCEIROS
        DO BEGIN
            UPDATE PRODUTODPTOESTOQUE SET
                SALDO=:SOMASALDOGERAL,
                SALDOEMTERCEIROS=:SOMASALDOEMTERCEIROS,
                SALDODETERCEIROS=:SOMASALDODETERCEIROS,
                SALDOPOSSEPROPRIA=:SOMASALDOPOSSEPROPRIA
            WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEDPTOESTOQUE=:CHAVEDPTOESTOQUE) AND
            ((SALDO<>:SOMASALDOGERAL) or (SALDOEMTERCEIROS<>:SOMASALDOEMTERCEIROS) or (SALDODETERCEIROS<>:SOMASALDODETERCEIROS) or (SALDOPOSSEPROPRIA<>:SOMASALDOPOSSEPROPRIA));
        END

        FOR SELECT DISTINCT
        P.CHAVE,
        ER.CHAVEDPTOESTOQUE,
        SUM(COALESCE(ER.QTDE,0)) AS QTDERESERVADO
        FROM PRODUTO P
        INNER JOIN ESTOQUERESERVADO ER ON (ER.CHAVEPRODUTO=P.CHAVE)
        LEFT JOIN PRODUTODPTOESTOQUE PE ON (PE.CHAVEPRODUTO=P.CHAVE) AND (PE.CHAVEEMPRESA=ER.CHAVEEMPRESA) AND (PE.CHAVEDPTOESTOQUE=ER.CHAVEDPTOESTOQUE)
        WHERE (P.ATIVO=1) AND (P.CHAVE=:CHAVEPRODAJUSTE)
        GROUP BY P.CHAVE, ER.CHAVEDPTOESTOQUE
        HAVING (SUM(COALESCE(ER.QTDE,0)) <> SUM(COALESCE(PE.SALDORESERVADO,0)))
        INTO :CHAVEPRODUTO, :CHAVEDPTOESTOQUE, :VSOMASALDORESERVADO
        DO BEGIN
            UPDATE PRODUTODPTOESTOQUE SET
                SALDORESERVADO=:VSOMASALDORESERVADO
            WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEDPTOESTOQUE=:CHAVEDPTOESTOQUE);
        END
    END ELSE BEGIN
        FOR SELECT P.CHAVE,
        COALESCE(E.CHAVEDPTOESTOQUE,0),
        SUM(COALESCE(E.SALDO,0)),
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 0 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOPOSSEPROPRIASUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 1 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDOEMTERCEIROSSUM,
        SUM(CASE E.TIPOMOVIMENTACAO WHEN 2 THEN COALESCE(E.SALDO,0) ELSE 0 END) AS SALDODETERCEIROSSUM
        FROM PRODUTO P
        LEFT JOIN PRODUTODPTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE AND PE.ATIVO=1
        LEFT JOIN ESTOQUE E ON E.CHAVEPRODUTO=P.CHAVE AND E.ATIVO=1 AND PE.CHAVEDPTOESTOQUE=E.CHAVEDPTOESTOQUE AND (PE.CHAVEEMPRESA=E.CHAVEEMPRESA)
        WHERE P.ATIVO=1 AND COALESCE(P.CHAVE,0) = CASE :CHAVEPRODAJUSTE WHEN 0 THEN
        COALESCE(P.CHAVE,0) ELSE :CHAVEPRODAJUSTE END
        GROUP BY P.CHAVE, E.CHAVEDPTOESTOQUE, PE.CHAVEDPTOESTOQUE, COALESCE(PE.SALDO, 0),
        COALESCE(PE.SALDOEMTERCEIROS,0), COALESCE(PE.SALDODETERCEIROS,0), COALESCE(PE.SALDOPOSSEPROPRIA,0)
        HAVING (SUM(CASE E.TIPOMOVIMENTACAO WHEN 0 THEN COALESCE(E.SALDO,0) ELSE 0 END) <> COALESCE(PE.SALDOPOSSEPROPRIA,0)) OR
               (SUM(CASE E.TIPOMOVIMENTACAO WHEN 1 THEN COALESCE(E.SALDO,0) ELSE 0 END) <> COALESCE(PE.SALDOEMTERCEIROS,0)) OR
               (SUM(CASE E.TIPOMOVIMENTACAO WHEN 2 THEN COALESCE(E.SALDO,0) ELSE 0 END) <> COALESCE(PE.SALDODETERCEIROS,0)) OR
               (SUM(COALESCE(E.SALDO,0)) <> SUM(COALESCE(PE.SALDO,0))/COUNT(PE.CHAVE))
        INTO :CHAVEPRODUTO, :CHAVEDPTOESTOQUE, :SOMASALDOGERAL, :SOMASALDOPOSSEPROPRIA, :SOMASALDOEMTERCEIROS,
        :SOMASALDODETERCEIROS
        DO BEGIN
            UPDATE PRODUTODPTOESTOQUE SET
                SALDO=:SOMASALDOGERAL,
                SALDOEMTERCEIROS=:SOMASALDOEMTERCEIROS,
                SALDODETERCEIROS=:SOMASALDODETERCEIROS,
                SALDOPOSSEPROPRIA=:SOMASALDOPOSSEPROPRIA
            WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEDPTOESTOQUE=:CHAVEDPTOESTOQUE);
        END

        FOR SELECT DISTINCT
        P.CHAVE,
        ER.CHAVEDPTOESTOQUE,
        SUM(COALESCE(ER.QTDE,0)) AS QTDERESERVADO
        FROM PRODUTO P
        INNER JOIN ESTOQUERESERVADO ER ON (ER.CHAVEPRODUTO=P.CHAVE)
        LEFT JOIN PRODUTODPTOESTOQUE PE ON (PE.CHAVEPRODUTO=P.CHAVE) AND (PE.CHAVEEMPRESA=ER.CHAVEEMPRESA) AND (PE.CHAVEDPTOESTOQUE=ER.CHAVEDPTOESTOQUE)
        WHERE (P.ATIVO=1)
        GROUP BY P.CHAVE, ER.CHAVEDPTOESTOQUE
        HAVING (SUM(COALESCE(ER.QTDE,0)) <> SUM(COALESCE(PE.SALDORESERVADO,0)))
        INTO :CHAVEPRODUTO, :CHAVEDPTOESTOQUE, :VSOMASALDORESERVADO
        DO BEGIN
            UPDATE PRODUTODPTOESTOQUE SET
                SALDORESERVADO=:VSOMASALDORESERVADO
            WHERE (CHAVEPRODUTO=:CHAVEPRODUTO) AND (CHAVEDPTOESTOQUE=:CHAVEDPTOESTOQUE);
        END
    END

    IF (:CHAVEPRODAJUSTE = 0) THEN BEGIN
    
        -- FAZ A SOMA DO SALDO DAS EMPRESAS DA CONDICIONAL
        FOR SELECT E.CHAVEPRODUTO, E.CHAVEEMPRESA, COALESCE(SUM(E.SALDO),0)
        FROM ESTOQUE E
        INNER JOIN PRODUTOESTOQUE PE ON PE.CHAVEPRODUTO=E.CHAVEPRODUTO AND PE.CHAVEEMPRESA = E.CHAVEEMPRESA
        WHERE E.ATIVO=1 AND E.ORIGEM=8 AND COALESCE(E.CHAVEPRODUTO,0) = CASE :CHAVEPRODAJUSTE WHEN 0 THEN
        COALESCE(E.CHAVEPRODUTO,0) ELSE :CHAVEPRODAJUSTE END
        GROUP BY E.CHAVEPRODUTO, E.CHAVEEMPRESA, PE.SALDOCONDICIONAL
        HAVING SUM(E.SALDO) <> PE.SALDOCONDICIONAL
        INTO :CHAVEPRODUTO, :CHAVEEMPRESA, :SALDO
        DO BEGIN
            UPDATE PRODUTOESTOQUE SET
            SALDOCONDICIONAL =:SALDO
            WHERE CHAVEPRODUTO = :CHAVEPRODUTO AND CHAVEEMPRESA=:CHAVEEMPRESA;
        END
    END
END^


ALTER PROCEDURE VERIFICAESTOQUE (
    ECHAVELOTEPROD INTEGER,
    CHAVEPRODUTO INTEGER,
    CHAVEEMPESTOQUE INTEGER,
    CHAVEEMPCUSTO INTEGER,
    QTDESAIDA NUMERIC(14,3),
    CHAVEUNIDADE INTEGER,
    TIPOMOVIMENTACAO INTEGER,
    CHAVECLIFOR INTEGER,
    ENTRADASAIDA CHAR(1),
    CHAVEDPTOESTOQUE INTEGER)
RETURNS (
    SRETORNOGRADE CHAR(1),
    RETORNO VARCHAR(2000),
    RETORNONODPTO CHAR(1))
AS
declare variable VSALDOGRADE numeric(14,3);
declare variable SALDOEST numeric(14,3);
declare variable CONVERSAO numeric(18,6);
declare variable CODIGOPROD varchar(6);
declare variable AGRUPADOCOMPOSTO integer;
declare variable QTDEBAIXARBEC numeric(14,3);
declare variable SALDOCLIFOR numeric(14,3);
declare variable SALDODPTOEST numeric(14,3);
declare variable STEMREGDPTO char(1);
BEGIN
    RETORNO = '';
    RETORNONODPTO = 'N';
    STEMREGDPTO = 'N';
    SRETORNOGRADE = 'N';
    CONVERSAO = 0;
    SELECT COALESCE(CONVERSAO,0) FROM UNIDADE
    WHERE CHAVE=:CHAVEUNIDADE
    INTO :CONVERSAO;
    IF (:CONVERSAO <> 1) THEN
        QTDESAIDA = :QTDESAIDA * CONVERSAO;
    IF ((:ENTRADASAIDA='S') AND (:ECHAVELOTEPROD > 0)) THEN BEGIN
        SELECT
        COALESCE(L.SALDO,0) AS SALDO
        FROM LOTEPRODUTOS L
        WHERE (L.ATIVO=1)
        AND (L.CHAVE=:ECHAVELOTEPROD)
        AND ((COALESCE(L.CHAVEGRADELINHA,0) <> 0)
        OR (COALESCE(L.CHAVEGRADECOLUNA,0) <> 0))
        INTO :VSALDOGRADE;
        IF ((:VSALDOGRADE-:QTDESAIDA) < 0) THEN BEGIN
            SRETORNOGRADE = 'S';
            RETORNO = RETORNO || 'GRADE';
        END
    END
    SELECT SSALDOESTOQUE, SSALDODPTOEST, STEMREG
    FROM RETORNARSALDOESTDPTO(:CHAVEPRODUTO, :CHAVEDPTOESTOQUE, :TIPOMOVIMENTACAO)
    INTO :SALDOEST, :SALDODPTOEST, :STEMREGDPTO;
    IF (:STEMREGDPTO = 'N') THEN
       EXCEPTION REGISTROS_PRODDPTOESTOQUE;
    SELECT AGRUPADOCOMPOSTO
    FROM PRODUTO P
    INNER JOIN PRODUTOESTOQUE PE ON PE.CHAVEPRODUTO = P.CHAVE AND PE.CHAVEEMPRESA = :CHAVEEMPESTOQUE
    WHERE PE.CHAVEPRODUTO=:CHAVEPRODUTO
    INTO :AGRUPADOCOMPOSTO;
    IF (AGRUPADOCOMPOSTO = 1) THEN BEGIN
        SELECT CHAVE, CODIGO, COALESCE(SALDO,0)
        FROM ESTRETORNARAGRUPADOPRINCIPAL(:CHAVEPRODUTO, :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO)
        INTO :CHAVEPRODUTO, :CODIGOPROD, :SALDOEST;
        SELECT SSALDOESTOQUE, SSALDODPTOEST, STEMREG
        FROM RETORNARSALDOESTDPTO(:CHAVEPRODUTO, :CHAVEDPTOESTOQUE, :TIPOMOVIMENTACAO)
        INTO :SALDOEST, :SALDODPTOEST, :STEMREGDPTO;
    
        IF (:SALDOEST < :QTDESAIDA) THEN
            RETORNO = RETORNO || ' ' || CAST(:CODIGOPROD AS INTEGER) || ' / ' || CAST(FORMAT_VALOR(',#0.000', :SALDOEST, '') AS VARCHAR(30));
        IF (RETORNO = '') THEN BEGIN
            IF (:SALDODPTOEST < :QTDESAIDA) THEN BEGIN
                RETORNO = CAST(:CODIGOPROD AS INTEGER) || ' / ' || CAST(FORMAT_VALOR(',#0.000', :SALDODPTOEST, '') AS VARCHAR(30));
                RETORNONODPTO = 'S';
            END
        END
        IF (:RETORNO = '') THEN
            RETORNO = 'OK';
        SUSPEND;
        EXIT;
    END
    IF (AGRUPADOCOMPOSTO = 4) THEN BEGIN
        FOR SELECT CHAVE, COALESCE(SALDO,0), CODIGO, QTDEBAIXAR
        FROM ESTRETORNARCOMPOSTOS(0, :CHAVEPRODUTO, :CHAVEEMPESTOQUE, :CHAVEEMPCUSTO, 0)
        INTO :CHAVEPRODUTO, :SALDOEST, :CODIGOPROD, :QTDEBAIXARBEC  DO BEGIN
            SELECT SSALDOESTOQUE, SSALDODPTOEST, STEMREG
            FROM RETORNARSALDOESTDPTO(:CHAVEPRODUTO, :CHAVEDPTOESTOQUE, :TIPOMOVIMENTACAO)
            INTO :SALDOEST, :SALDODPTOEST, :STEMREGDPTO;
            IF (:SALDOEST < (:QTDESAIDA*:QTDEBAIXARBEC)) THEN
                RETORNO = RETORNO  || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST(:CODIGOPROD AS INTEGER) || ' / ' || CAST(FORMAT_VALOR(',#0.000', :SALDOEST, '') AS VARCHAR(30));
            IF (:SALDOEST >= (:QTDESAIDA*:QTDEBAIXARBEC)) THEN BEGIN
                IF (:SALDODPTOEST < (:QTDESAIDA*:QTDEBAIXARBEC)) THEN BEGIN
                    RETORNO = RETORNO  || ASCII_CHAR(13) || ASCII_CHAR(10) || CAST(:CODIGOPROD AS INTEGER) || ' / ' || CAST(FORMAT_VALOR(',#0.000', :SALDOEST, '') AS VARCHAR(30));
                    RETORNONODPTO = 'S';
                END
            END
        END
        IF (:RETORNO = '') THEN
            RETORNO = 'OK';
        SUSPEND;
        EXIT;
    END
    IF ((:TIPOMOVIMENTACAO = 1) AND (:ENTRADASAIDA = 'E')) THEN BEGIN
    END ELSE BEGIN
       IF (:SALDOEST < :QTDESAIDA) THEN BEGIN
           RETORNO = CAST(:SALDOEST AS VARCHAR(30));
           SUSPEND;
           EXIT;
       END
       IF ((:TIPOMOVIMENTACAO<>1) AND (:SALDODPTOEST < :QTDESAIDA)) THEN BEGIN
           RETORNO = CAST(:SALDODPTOEST AS VARCHAR(30));
           RETORNONODPTO = 'S';
           SUSPEND;
           EXIT;
       END
    END
    IF (:TIPOMOVIMENTACAO = 0) THEN BEGIN
        IF (RETORNO = '') THEN
            RETORNO = 'OK';
    END
    IF (:TIPOMOVIMENTACAO = 1)  THEN BEGIN
        IF (:ENTRADASAIDA = 'E') THEN BEGIN
            SELECT COALESCE(SUM(SALDO),0) FROM ESTOQUE
            WHERE ATIVO=1 AND CHAVECLIFOR=:CHAVECLIFOR AND TIPOMOVIMENTACAO=1
            AND CHAVEEMPRESA=:CHAVEEMPESTOQUE AND CHAVEPRODUTO=:CHAVEPRODUTO
            INTO :SALDOCLIFOR;
            IF (:SALDOCLIFOR < :QTDESAIDA) THEN
                RETORNO = CAST(:SALDOCLIFOR AS VARCHAR(30));
            IF (RETORNO = '') THEN
                RETORNO = 'OK';
       END ELSE
           RETORNO = 'OK';
    END
    IF (:TIPOMOVIMENTACAO = 2) THEN BEGIN
        IF (:ENTRADASAIDA = 'S') THEN BEGIN
            SELECT COALESCE(SUM(SALDO),0) FROM ESTOQUE
            WHERE ATIVO=1 AND CHAVECLIFOR=:CHAVECLIFOR AND TIPOMOVIMENTACAO=2
            AND CHAVEEMPRESA=:CHAVEEMPESTOQUE AND CHAVEPRODUTO=:CHAVEPRODUTO
            INTO :SALDOCLIFOR;
            IF (:SALDOCLIFOR < :QTDESAIDA) THEN
                RETORNO = CAST(:SALDOCLIFOR AS VARCHAR(30));
            IF (RETORNO = '') THEN
                RETORNO = 'OK';
        END ELSE
            RETORNO = 'OK';
    END
    SUSPEND;
    /*
        CHAMADAS:
            - FRMAJUSTEESTOQUE: USADA PARA VALIDAR MOVIMENTACAO DE ESTOQUE DE/EM TERCEIROS
            - FUNCOESCHERP: NESTA UNIT TEM UMA FUNCAO VERIFICARSALDOESTOQUE
                QUE DENTRO DELA CHAMA ESTA PROCEDURE. ESSA FUNCAO DO DELPHI E CHAMADA
                EM ALGUMAS TELAS DE VENDA PARA VERIFICAR O SALDO ESTOQUE;
           AS TELAS  QUE FAZEM ESSA VALIDACAO SAO:
            - FRMCOTACAO;
            - FRMPEDIDOSAIDA;
            - FRMDLGFATURAMENTO;
   */
END^



