ALTER FUNCTION EXTENSO (
    VALOR NUMERIC(18,2),
    MOEDA VARCHAR(1))
RETURNS VARCHAR(1000)
AS
declare variable CENTAVOS varchar(255);
declare variable CENTENA varchar(255);
declare variable MILHAR varchar(255);
declare variable TEXTO varchar(20);
declare variable MSING varchar(20);
declare variable MPLURAL varchar(20);
declare variable RESULTADO varchar(1000);
declare variable PARTE_INTEIRA integer;
declare variable PARTE_DECIMAL integer;
BEGIN
    MSING = '';
    MPLURAL = '';
    RESULTADO = '';
    
    IF (MOEDA = 'S') THEN BEGIN
        MSING = ' Real';
        MPLURAL = ' Reais';
    END
    
    IF (VALOR > 999999.99 OR VALOR < 0) THEN
        RETURN '';
    
    IF (VALOR = 0) THEN
        RETURN '';
    
    PARTE_INTEIRA = CAST(FLOOR(VALOR) AS INTEGER);
    PARTE_DECIMAL = CAST(ROUND((VALOR - FLOOR(VALOR)) * 100) AS INTEGER);
    
    TEXTO = LPAD(CAST(PARTE_INTEIRA AS VARCHAR(6)), 6, '0') || 
            LPAD(CAST(PARTE_DECIMAL AS VARCHAR(2)), 2, '0');
    
    MILHAR = MINI_EXTENSO(SUBSTRING(TEXTO FROM 1 FOR 3));
    CENTENA = MINI_EXTENSO(SUBSTRING(TEXTO FROM 4 FOR 3));
    
    IF (PARTE_DECIMAL > 0) THEN
        CENTAVOS = MINI_EXTENSO('0' || SUBSTRING(TEXTO FROM 7 FOR 2));
    ELSE
        CENTAVOS = '';
    
    IF (MILHAR IS NOT NULL AND MILHAR <> '') THEN BEGIN
        RESULTADO = MILHAR;
        IF (SUBSTRING(TEXTO FROM 4 FOR 3) = '000') THEN
            RESULTADO = RESULTADO || ' Mil' || MPLURAL;
        ELSE
            RESULTADO = RESULTADO || ' Mil, ';
        
        IF ((((SUBSTRING(TEXTO FROM 4 FOR 2) = '00') AND (MILHAR <> '') AND (SUBSTRING(TEXTO FROM 6 FOR 1) <> '0'))) OR
             ((CENTAVOS = '') AND ((CENTENA IS NOT NULL) AND (CENTENA <> '')))) THEN
            RESULTADO = RESULTADO || ' e ';
    END
    
    IF ((MILHAR IS NOT NULL AND MILHAR <> '') OR (CENTENA IS NOT NULL AND CENTENA <> '')) THEN
        RESULTADO = RESULTADO || CENTENA;
    
    IF ((MILHAR IS NULL) OR (MILHAR = '') AND (SUBSTRING(TEXTO FROM 4 FOR 3) = '001')) THEN
        RESULTADO = RESULTADO || MSING;
    ELSE IF (SUBSTRING(TEXTO FROM 4 FOR 3) <> '000') THEN
        RESULTADO = RESULTADO || MPLURAL;
    
    IF (CENTAVOS <> '') THEN BEGIN
        IF (RESULTADO <> '') THEN
            RESULTADO = RESULTADO || ' e ' || CENTAVOS || ' Centavo' || CASE WHEN PARTE_DECIMAL <> 1 THEN 's' ELSE '' END;
        ELSE
            RESULTADO = CENTAVOS || ' Centavo' || CASE WHEN PARTE_DECIMAL <> 1 THEN 's' ELSE '' END;
    END
    
    RETURN RESULTADO;
END^


ALTER FUNCTION EXTRAIRNUMEROS (
    STR VARCHAR(255))
RETURNS VARCHAR(255)
AS
declare variable RESULT varchar(255);
declare variable I integer;
declare variable CH char(1);
BEGIN
  RESULT = '';
  I = 1;
  WHILE (I <= CHAR_LENGTH(STR)) DO BEGIN
    CH = SUBSTRING(STR FROM I FOR 1);
    IF (CH BETWEEN '0' AND '9') THEN
      RESULT = RESULT || CH;
    I = I + 1;
  END
  RETURN RESULT;
END^


ALTER FUNCTION FORMAT_VALOR (
    FORMATO VARCHAR(20),
    VALOR DOUBLE PRECISION,
    PALAVRA_CODIFICAR VARCHAR(10))
RETURNS VARCHAR(100)
AS
DECLARE VARIABLE I INTEGER;
DECLARE VARIABLE TEMP VARCHAR(100);
DECLARE VARIABLE SAIDA VARCHAR(1000);
DECLARE VARIABLE VALOR_CAMF VARCHAR(10);
DECLARE VARIABLE DIGITO CHAR(1);
DECLARE VARIABLE TAMANHO INTEGER;
DECLARE VARIABLE INTEIRO_PARTE VARCHAR(50);
DECLARE VARIABLE DECIMAL_PARTE VARCHAR(50);
DECLARE VARIABLE TEMP_VALOR VARCHAR(100);
DECLARE VARIABLE CASAS_DECIMAIS INTEGER;
DECLARE VARIABLE INTEIRO_FORMATADO VARCHAR(100);
DECLARE VARIABLE J INTEGER;
DECLARE VARIABLE CONTADOR INTEGER;
BEGIN
    SAIDA = '';
    
    IF (POSITION('.', :FORMATO) > 0) THEN
        CASAS_DECIMAIS = CHAR_LENGTH(SUBSTRING(:FORMATO FROM POSITION('.', :FORMATO)+1));
    ELSE
        CASAS_DECIMAIS = 2; -- DEFAULT
    
    TEMP_VALOR = CAST(CAST(ABS(:VALOR) AS DECIMAL(18,6)) AS VARCHAR(100));
    IF (POSITION('.', :TEMP_VALOR) > 0) THEN
    BEGIN
        INTEIRO_PARTE = SUBSTRING(:TEMP_VALOR FROM 1 FOR POSITION('.', :TEMP_VALOR)-1);
        DECIMAL_PARTE = SUBSTRING(:TEMP_VALOR FROM POSITION('.', :TEMP_VALOR)+1 FOR :CASAS_DECIMAIS);
    END ELSE BEGIN
        INTEIRO_PARTE = :TEMP_VALOR;
        DECIMAL_PARTE = LPAD('', :CASAS_DECIMAIS, '0');
    END
    
    INTEIRO_FORMATADO = '';
    J = CHAR_LENGTH(:INTEIRO_PARTE);
    CONTADOR = 0;
    
    WHILE (J > 0) DO BEGIN
        IF (CONTADOR = 3) THEN BEGIN
            INTEIRO_FORMATADO = '.' || :INTEIRO_FORMATADO;
            CONTADOR = 0;
        END
        INTEIRO_FORMATADO = SUBSTRING(:INTEIRO_PARTE FROM J FOR 1) || :INTEIRO_FORMATADO;
        J = J - 1;
        CONTADOR = CONTADOR + 1;
    END
    
    IF (CHAR_LENGTH(:DECIMAL_PARTE) < :CASAS_DECIMAIS) THEN
        DECIMAL_PARTE = RPAD(:DECIMAL_PARTE, :CASAS_DECIMAIS, '0');
    
    TEMP = INTEIRO_FORMATADO || ',' || DECIMAL_PARTE;
    
    IF (TRIM(:PALAVRA_CODIFICAR) = '') THEN
        RETURN :TEMP;
    
    TEMP = REPLACE(REPLACE(:TEMP, '.', ''), ',', '');
    
    VALOR_CAMF = SUBSTRING(:PALAVRA_CODIFICAR FROM 10 FOR 1);
    
    I = 1;
    WHILE (I <= 9) DO BEGIN
        VALOR_CAMF = VALOR_CAMF || SUBSTRING(:PALAVRA_CODIFICAR FROM I FOR 1);
        I = I + 1;
    END
    
    TAMANHO = CHAR_LENGTH(TRIM(:TEMP));
    I = 1;
    WHILE (I <= TAMANHO) DO BEGIN
        DIGITO = SUBSTRING(:TEMP FROM I FOR 1);
        IF (DIGITO BETWEEN '0' AND '9') THEN
            SAIDA = SAIDA || SUBSTRING(:VALOR_CAMF FROM CAST(:DIGITO AS INTEGER)+1 FOR 1);
        I = I + 1;
    END
    
    RETURN :SAIDA;
END^


ALTER FUNCTION FRAC (
    VALOR DOUBLE PRECISION)
RETURNS DOUBLE PRECISION
AS
BEGIN
  RETURN VALOR - FLOOR(VALOR);
END^


ALTER FUNCTION MESEXTENSO (
    DATA_ENTRADA TIMESTAMP)
RETURNS VARCHAR(20)
AS
BEGIN
  RETURN CASE EXTRACT(MONTH FROM :DATA_ENTRADA)
    WHEN 1 THEN 'Janeiro'
    WHEN 2 THEN 'Fevereiro'
    WHEN 3 THEN 'Marco'
    WHEN 4 THEN 'Abril'
    WHEN 5 THEN 'Maio'
    WHEN 6 THEN 'Junho'
    WHEN 7 THEN 'Julho'
    WHEN 8 THEN 'Agosto'
    WHEN 9 THEN 'Setembro'
    WHEN 10 THEN 'Outubro'
    WHEN 11 THEN 'Novembro'
    WHEN 12 THEN 'Dezembro'
  END;
END^


ALTER FUNCTION MINI_EXTENSO (
    TRIO VARCHAR(3))
RETURNS VARCHAR(255)
AS
declare variable UNIDADE varchar(20);
declare variable DEZENA varchar(20);
declare variable CENTENA varchar(20);
declare variable RESULTADO varchar(255);
BEGIN
    UNIDADE = '';
    DEZENA = '';
    CENTENA = '';
    
    IF (SUBSTRING(TRIO FROM 2 FOR 1) = '1' AND SUBSTRING(TRIO FROM 3 FOR 1) <> '0') THEN BEGIN
        UNIDADE = CASE SUBSTRING(TRIO FROM 3 FOR 1)
            WHEN '1' THEN 'Onze' WHEN '2' THEN 'Doze' WHEN '3' THEN 'Treze'
            WHEN '4' THEN 'Quatorze' WHEN '5' THEN 'Quinze' WHEN '6' THEN 'Dezesseis'
            WHEN '7' THEN 'Dezessete' WHEN '8' THEN 'Dezoito' WHEN '9' THEN 'Dezenove'
        END;
        DEZENA = '';
    END ELSE BEGIN
        IF (SUBSTRING(TRIO FROM 2 FOR 1) <> '0') THEN
            DEZENA = CASE SUBSTRING(TRIO FROM 2 FOR 1)
                WHEN '1' THEN 'Dez' WHEN '2' THEN 'Vinte' WHEN '3' THEN 'Trinta'
                WHEN '4' THEN 'Quarenta' WHEN '5' THEN 'Cinquenta' WHEN '6' THEN 'Sessenta'
                WHEN '7' THEN 'Setenta' WHEN '8' THEN 'Oitenta' WHEN '9' THEN 'Noventa'
            END;
        
        IF (SUBSTRING(TRIO FROM 3 FOR 1) <> '0') THEN
            UNIDADE = CASE SUBSTRING(TRIO FROM 3 FOR 1)
                WHEN '1' THEN 'Um' WHEN '2' THEN 'Dois' WHEN '3' THEN 'Tres'
                WHEN '4' THEN 'Quatro' WHEN '5' THEN 'Cinco' WHEN '6' THEN 'Seis'
                WHEN '7' THEN 'Sete' WHEN '8' THEN 'Oito' WHEN '9' THEN 'Nove'
            END;
    END
    
    IF (SUBSTRING(TRIO FROM 1 FOR 1) = '1' AND UNIDADE = '' AND DEZENA = '') THEN
        CENTENA = 'Cem';
    ELSE IF (SUBSTRING(TRIO FROM 1 FOR 1) <> '0') THEN
        CENTENA = CASE SUBSTRING(TRIO FROM 1 FOR 1)
            WHEN '1' THEN 'Cento' WHEN '2' THEN 'Duzentos' WHEN '3' THEN 'Trezentos'
            WHEN '4' THEN 'Quatrocentos' WHEN '5' THEN 'Quinhentos' WHEN '6' THEN 'Seiscentos'
            WHEN '7' THEN 'Setecentos' WHEN '8' THEN 'Oitocentos' WHEN '9' THEN 'Novecentos'
        END;
    
    RESULTADO = CENTENA;
    IF (CENTENA <> '' AND (DEZENA <> '' OR UNIDADE <> '')) THEN
        RESULTADO = RESULTADO || ' e ';
    
    RESULTADO = RESULTADO || DEZENA;
    
    IF (DEZENA <> '' AND UNIDADE <> '') THEN
        RESULTADO = RESULTADO || ' e ';
    
    RESULTADO = RESULTADO || UNIDADE;
    
    RETURN RESULTADO;
END^



